    /// <inheritdoc/>
    public Vector<T> GenerateDropoutMask<T>(int length, T dropoutRate, T scale, int? seed = null)
    {
        if (length < 0) throw new ArgumentException("Length must be non-negative.", nameof(length));
        var random = seed.HasValue ? RandomHelper.CreateSeededRandom(seed.Value) : RandomHelper.CreateSecureRandom();
        var numOps = MathHelper.GetNumericOperations<T>();
        double dropoutRateDouble = Convert.ToDouble(dropoutRate);
        var mask = new Vector<T>(length);
        for (int i = 0; i < length; i++)
        {
            mask[i] = random.NextDouble() > dropoutRateDouble ? scale : numOps.Zero;
        }
        return mask;
    }

    /// <inheritdoc/>
    public void CopyVectorToTensor<T>(Vector<T> source, Tensor<T> destination)
    {
        if (source == null) throw new ArgumentNullException(nameof(source));
        if (destination == null) throw new ArgumentNullException(nameof(destination));
        if (source.Length != destination.Length)
        {
            throw new ArgumentException(
                $"Vector length ({source.Length}) must equal tensor total elements ({destination.Length}).");
        }
        for (int i = 0; i < source.Length; i++)
        {
            destination[i] = source[i];
        }
    }
    /// <inheritdoc/>
    public Vector<T> GenerateGaussianNoise<T>(int length, T mean, T standardDeviation, int? seed = null)
    {
        if (length < 0) throw new ArgumentException("Length must be non-negative.", nameof(length));
        var random = seed.HasValue ? RandomHelper.CreateSeededRandom(seed.Value) : RandomHelper.CreateSecureRandom();
        var numOps = MathHelper.GetNumericOperations<T>();
        var noise = new Vector<T>(length);
        for (int i = 0; i < length; i++)
        {
            // Box-Muller transform to generate Gaussian random numbers
            T u1 = numOps.FromDouble(random.NextDouble());
            T u2 = numOps.FromDouble(random.NextDouble());
            T z = numOps.Multiply(
                numOps.Sqrt(numOps.Multiply(numOps.FromDouble(-2.0), numOps.Log(u1))),
                numOps.FromDouble(Math.Cos(2.0 * Math.PI * Convert.ToDouble(u2))));
            noise[i] = numOps.Add(mean, numOps.Multiply(standardDeviation, z));
        }
        return noise;
    }

    #endregion

    #region Matrix Operations (Phase B: Epic 2)

    /// <inheritdoc/>
    public Matrix<T> MatrixMultiply<T>(Matrix<T> a, Matrix<T> b)
    {
        if (a == null) throw new ArgumentNullException(nameof(a));
        if (b == null) throw new ArgumentNullException(nameof(b));
        if (a.Columns != b.Rows)
        {
            throw new ArgumentException(
                $"Matrix dimensions incompatible for multiplication. " +
                $"First matrix is {a.Rows}x{a.Columns}, second is {b.Rows}x{b.Columns}. " +
                $"First matrix columns ({a.Columns}) must equal second matrix rows ({b.Rows}).");
        }

        var numOps = MathHelper.GetNumericOperations<T>();
        int m = a.Rows;
        int k = a.Columns;
        int n = b.Columns;
        var result = new Matrix<T>(m, n);

        // Try BLAS/SimdGemm-accelerated path for float/double
        if (MatrixMultiplyHelper.TryGemm(a.AsMemory(), 0, b.AsMemory(), 0, result.AsWritableMemory(), 0, m, k, n))
        {
            return result;
        }

        // Fallback for non-float/double types: blocked multiplication using numOps
        MatrixMultiplyHelper.MultiplyBlocked(numOps, a.AsMemory(), b.AsMemory(), result.AsWritableMemory(), m, k, n, k, n, n);

        return result;
    }

    /// <inheritdoc/>
    public Vector<T> MatrixVectorMultiply<T>(Matrix<T> matrix, Vector<T> vector)
    {
        if (matrix == null) throw new ArgumentNullException(nameof(matrix));
        if (vector == null) throw new ArgumentNullException(nameof(vector));
        if (matrix.Columns != vector.Length)
        {
            throw new ArgumentException(
                $"Matrix-vector dimensions incompatible. " +
                $"Matrix is {matrix.Rows}x{matrix.Columns}, vector has {vector.Length} elements. " +
                $"Matrix columns ({matrix.Columns}) must equal vector length ({vector.Length}).");
        }

        var numOps = MathHelper.GetNumericOperations<T>();
        var result = new Vector<T>(matrix.Rows);

        for (int i = 0; i < matrix.Rows; i++)
        {
            T sum = numOps.Zero;
            for (int j = 0; j < matrix.Columns; j++)
            {
                sum = numOps.Add(sum, numOps.Multiply(matrix[i, j], vector[j]));
            }
            result[i] = sum;
        }

        return result;
    }

    /// <inheritdoc/>
    public Matrix<T> MatrixTranspose<T>(Matrix<T> matrix)
    {
        if (matrix == null) throw new ArgumentNullException(nameof(matrix));

        var result = new Matrix<T>(matrix.Columns, matrix.Rows);

        for (int i = 0; i < matrix.Rows; i++)
        {
            for (int j = 0; j < matrix.Columns; j++)
            {
                result[j, i] = matrix[i, j];
            }
        }

        return result;
    }

    /// <inheritdoc/>
    public Matrix<T> MatrixAdd<T>(Matrix<T> a, Matrix<T> b)
    {
        if (a == null) throw new ArgumentNullException(nameof(a));
        if (b == null) throw new ArgumentNullException(nameof(b));
        if (a.Rows != b.Rows || a.Columns != b.Columns)
        {
            throw new ArgumentException(
                $"Matrix dimensions must match for addition. " +
                $"First matrix is {a.Rows}x{a.Columns}, second is {b.Rows}x{b.Columns}.");
        }

        var numOps = MathHelper.GetNumericOperations<T>();
        var result = new Matrix<T>(a.Rows, a.Columns);

        for (int i = 0; i < a.Rows; i++)
        {
            for (int j = 0; j < a.Columns; j++)
            {
                result[i, j] = numOps.Add(a[i, j], b[i, j]);
            }
        }

        return result;
    }

    /// <inheritdoc/>
    public Matrix<T> MatrixMultiplyScalar<T>(Matrix<T> matrix, T scalar)
    {
        if (matrix == null) throw new ArgumentNullException(nameof(matrix));

        var numOps = MathHelper.GetNumericOperations<T>();
        var result = new Matrix<T>(matrix.Rows, matrix.Columns);

        for (int i = 0; i < matrix.Rows; i++)
        {
            for (int j = 0; j < matrix.Columns; j++)
            {
                result[i, j] = numOps.Multiply(matrix[i, j], scalar);
            }
        }

        return result;
    }

    public Matrix<T> MatrixSubtract<T>(Matrix<T> a, Matrix<T> b)
    {
        if (a == null) throw new ArgumentNullException(nameof(a));
        if (b == null) throw new ArgumentNullException(nameof(b));
        if (a.Rows != b.Rows || a.Columns != b.Columns)
            throw new ArgumentException("Matrix dimensions must match for subtraction");

        var result = new Matrix<T>(a.Rows, a.Columns);

        // VECTORIZED: Use existing Vector Subtract operation on each row
        for (int i = 0; i < a.Rows; i++)
        {
            var rowA = a.GetRow(i);
            var rowB = b.GetRow(i);
            var diffRow = Subtract(rowA, rowB); // Reuse vectorized Vector Subtract
            result.SetRow(i, diffRow);
        }

        return result;
    }

    public T MatrixSumOfSquares<T>(Matrix<T> matrix)
    {
        if (matrix == null) throw new ArgumentNullException(nameof(matrix));

        var numOps = MathHelper.GetNumericOperations<T>();
        T sum = numOps.Zero;

        // VECTORIZED: Use existing DotProduct operation on each row
        for (int i = 0; i < matrix.Rows; i++)
        {
            var row = matrix.GetRow(i);
            T rowSumSquares = DotProduct(row, row); // row ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â· row = sum of squares for row
            sum = numOps.Add(sum, rowSumSquares);
        }

        return sum;
    }

    public void SwapColumns<T>(Matrix<T> matrix, int col1, int col2)
    {
        if (matrix == null) throw new ArgumentNullException(nameof(matrix));

        // Direct element swap - no vectorization benefit for column swaps due to strided access
        for (int i = 0; i < matrix.Rows; i++)
        {
            T temp = matrix[i, col1];
            matrix[i, col1] = matrix[i, col2];
            matrix[i, col2] = temp;
        }
    }

    public void SwapRows<T>(Matrix<T> matrix, int row1, int row2)
    {
        if (matrix == null) throw new ArgumentNullException(nameof(matrix));

        // Use vectorized operations for row swapping
        var tempRow1 = GetRow(matrix, row1);
        var tempRow2 = GetRow(matrix, row2);

        SetRow(matrix, row1, tempRow2);
        SetRow(matrix, row2, tempRow1);
    }

    public Matrix<T> OuterProduct<T>(Vector<T> a, Vector<T> b)
    {
        if (a == null) throw new ArgumentNullException(nameof(a));
        if (b == null) throw new ArgumentNullException(nameof(b));

        var result = new Matrix<T>(a.Length, b.Length);
        var aArray = a.GetDataArray();
        var bArray = b.GetDataArray();

        // Use SIMD-optimized TensorPrimitives for float type
        if (typeof(T) == typeof(float) && bArray.Length >= 16)
        {
            var bFloat = (float[])(object)bArray;
            var aFloat = (float[])(object)aArray;

            for (int i = 0; i < aFloat.Length; i++)
            {
                var rowData = new float[bFloat.Length];
                // SIMD vectorized: multiply vector b by scalar a[i]
                Simd.SimdKernels.MultiplyScalar(bFloat.AsSpan(), aFloat[i], rowData.AsSpan());

                // Copy result to matrix
                for (int j = 0; j < bFloat.Length; j++)
                {
                    result[i, j] = (T)(object)rowData[j];
                }
            }
        }
        else
        {
            // Fallback using NumOps
            var numOps = MathHelper.GetNumericOperations<T>();
            for (int i = 0; i < aArray.Length; i++)
            {
                for (int j = 0; j < bArray.Length; j++)
                {
                    result[i, j] = numOps.Multiply(aArray[i], bArray[j]);
                }
            }
        }

        return result;
    }

    public Vector<T> GetColumn<T>(Matrix<T> matrix, int columnIndex)
    {
        if (matrix == null) throw new ArgumentNullException(nameof(matrix));
        if (columnIndex < 0 || columnIndex >= matrix.Columns)
            throw new ArgumentOutOfRangeException(nameof(columnIndex),
                $"Column index {columnIndex} is out of range. Valid range is 0 to {matrix.Columns - 1}.");

        // No vectorization benefit - column access is strided
        var result = new T[matrix.Rows];
        for (int i = 0; i < matrix.Rows; i++)
        {
            result[i] = matrix[i, columnIndex];
        }
        return new Vector<T>(result);
    }

    public Vector<T> GetRow<T>(Matrix<T> matrix, int rowIndex)
    {
        if (matrix == null) throw new ArgumentNullException(nameof(matrix));
        if (rowIndex < 0 || rowIndex >= matrix.Rows)
            throw new ArgumentOutOfRangeException(nameof(rowIndex),
                $"Row index {rowIndex} is out of range. Valid range is 0 to {matrix.Rows - 1}.");

        // Row access is contiguous - can use direct array copy
        var result = new T[matrix.Columns];
        for (int j = 0; j < matrix.Columns; j++)
        {
            result[j] = matrix[rowIndex, j];
        }
        return new Vector<T>(result);
    }

    public void SetColumn<T>(Matrix<T> matrix, int columnIndex, Vector<T> values)
    {
        if (matrix == null) throw new ArgumentNullException(nameof(matrix));
        if (values == null) throw new ArgumentNullException(nameof(values));
        if (columnIndex < 0 || columnIndex >= matrix.Columns)
            throw new ArgumentOutOfRangeException(nameof(columnIndex),
                $"Column index {columnIndex} is out of range. Valid range is 0 to {matrix.Columns - 1}.");
        if (values.Length != matrix.Rows)
            throw new ArgumentException(
                $"Values vector length ({values.Length}) must match matrix rows ({matrix.Rows}).",
                nameof(values));

        // No vectorization benefit - column access is strided
        var valuesArray = values.GetDataArray();
        for (int i = 0; i < matrix.Rows; i++)
        {
            matrix[i, columnIndex] = valuesArray[i];
        }
    }

    public void SetRow<T>(Matrix<T> matrix, int rowIndex, Vector<T> values)
    {
        if (matrix == null) throw new ArgumentNullException(nameof(matrix));
        if (values == null) throw new ArgumentNullException(nameof(values));
        if (rowIndex < 0 || rowIndex >= matrix.Rows)
            throw new ArgumentOutOfRangeException(nameof(rowIndex),
                $"Row index {rowIndex} is out of range. Valid range is 0 to {matrix.Rows - 1}.");
        if (values.Length != matrix.Columns)
            throw new ArgumentException(
                $"Values vector length ({values.Length}) must match matrix columns ({matrix.Columns}).",
                nameof(values));

        // Row access is contiguous - direct assignment
        var valuesArray = values.GetDataArray();
        for (int j = 0; j < matrix.Columns; j++)
        {
            matrix[rowIndex, j] = valuesArray[j];
        }
    }

    #endregion

    #region Tensor Operations (Phase B: Epic 3)

    /// <inheritdoc/>
    public virtual Tensor<T> TensorBroadcastTo<T>(Tensor<T> input, int[] targetShape)
    {
        if (input == null) throw new ArgumentNullException(nameof(input));
        if (targetShape == null) throw new ArgumentNullException(nameof(targetShape));

        // torch.broadcast_to requires target.Rank >= source.Rank — we can't
        // broadcast to fewer dimensions. Fail fast so the Tier-3 fallback
        // doesn't silently miscompute shapes.
        if (targetShape.Length < input.Rank)
            throw new ArgumentException(
                $"Broadcast target rank ({targetShape.Length}) must be >= source rank ({input.Rank}).",
                nameof(targetShape));

        // Tier 1: exact shape match → identity. Zero cost.
        if (ShapesEqual1D(input._shape, targetShape)) return input;

        // Tier 2: target only differs from source by PREPENDING size-1 axes
        // (source shape == target tail, all extra target leading axes == 1).
        // This is a pure reshape — no broadcasting actually happens, just
        // rank realignment. Dispatches to Reshape which is GraphMode-aware
        // and performs zero data copy.
        //
        // This path owns the BERT MatMul weight-broadcast cost: a 2-D weight
        // [K, N] becoming a batched [1, K, N] for rank-compatible matmul.
        int rankDiff = targetShape.Length - input.Rank;
        if (rankDiff >= 0)
        {
            bool leadingAllOne = true;
            for (int i = 0; i < rankDiff; i++)
                if (targetShape[i] != 1) { leadingAllOne = false; break; }
            if (leadingAllOne)
            {
                bool tailMatches = true;
                for (int i = 0; i < input.Rank; i++)
                    if (targetShape[rankDiff + i] != input._shape[i]) { tailMatches = false; break; }
                if (tailMatches) return Reshape(input, targetShape);
            }
        }

        // Validate broadcast compatibility before falling through — want a crisp
        // error with both shapes, not a confusing downstream failure.
        int maxRank = Math.Max(input.Rank, targetShape.Length);
        for (int i = 0; i < maxRank; i++)
        {
            int srcDim = (i < maxRank - input.Rank)         ? 1 : input._shape[i - (maxRank - input.Rank)];
            int tgtDim = (i < maxRank - targetShape.Length) ? 1 : targetShape[i - (maxRank - targetShape.Length)];
            if (srcDim != tgtDim && srcDim != 1)
                throw new ArgumentException(
                    $"BroadcastTo: cannot broadcast shape [{string.Join(",", input._shape)}] to " +
                    $"[{string.Join(",", targetShape)}] — source dim {srcDim} at axis {i} must equal target dim {tgtDim} or be 1.");
        }

        // Tier 3: general broadcast (genuine size-1 → size-N expansion at
        // some axis). Fall through to the existing broadcast kernel via a
        // zero-add. Equivalent cost to the old idiom; callers used to
        // allocate the zero tensor themselves which made Tier 1 / Tier 2
        // fast paths unreachable. Now the primitive handles Tier 1/2
        // correctly and only burns the full kernel when genuinely needed.
        return TensorBroadcastAdd(input, new Tensor<T>(targetShape));
    }

    private static bool ShapesEqual1D(int[] a, int[] b)
    {
        if (a.Length != b.Length) return false;
        for (int i = 0; i < a.Length; i++) if (a[i] != b[i]) return false;
        return true;
    }

    /// <inheritdoc/>
    public virtual Tensor<T> Reshape<T>(Tensor<T> tensor, int[] newShape)
    {
        if (tensor == null) throw new ArgumentNullException(nameof(tensor));
        if (newShape == null) throw new ArgumentNullException(nameof(newShape));

        if (GraphMode.IsActive)
        {
            var scope = GraphMode.Current;
            if (scope != null)
            {
                var captured = tensor;
                var capturedShape = newShape;
                var origShape = tensor.Shape.ToArray();
                return scope.RecordUnary(LazyNodeType.Reshape, "Reshape", tensor, newShape,
                    (eng, output) => { captured.AsSpan().CopyTo(output.AsWritableSpan()); },
                    BackwardFunctions<T>.ReshapeBackward, new object[] { origShape });
            }
        }

        { var ac = AutoTracer.TryGetCompiledPlan<T>("Reshape", tensor._shape); if (ac is not null) return ac.Execute(); }

        var originalShape = tensor.Shape.ToArray();
        var result = tensor.Reshape(newShape);
        DifferentiableOps.RecordUnary("Reshape", result, tensor, BackwardFunctions<T>.ReshapeBackward, new object[] { originalShape });
        AutoTracer.RecordOp("Reshape", result, eng => result);
        return result;
    }

    /// <inheritdoc/>
    public virtual Tensor<T> ReorderToNchwc<T>(Tensor<T> tensor, LinearAlgebra.TensorLayout targetLayout)
    {
        if (tensor == null) throw new ArgumentNullException(nameof(tensor));
        if (!targetLayout.IsChannelPacked())
            throw new ArgumentException($"Target layout {targetLayout} is not a channel-packed layout.", nameof(targetLayout));
        if (tensor.Layout == targetLayout) return tensor;
        if (tensor.Rank != 4)
            throw new ArgumentException($"NCHWc reorder requires rank-4 input, got rank {tensor.Rank}.");
        int cBlock = targetLayout.CBlock();
        int n = tensor._shape[0], c = tensor._shape[1], h = tensor._shape[2], w = tensor._shape[3];
        if (c % cBlock != 0)
            throw new ArgumentException($"NCHWc reorder requires C ({c}) divisible by cBlock ({cBlock}).");

        if (GraphMode.IsActive)
        {
            var scope = GraphMode.Current;
            if (scope != null)
            {
                var captured = tensor;
                var capturedLayout = targetLayout;
                var capturedCBlock = cBlock;
                var capturedShape = (int[])tensor._shape.Clone();
                var lazy = scope.RecordUnary(LazyNodeType.Custom, "ReorderToNchwc", tensor, capturedShape,
                    (eng, output) =>
                    {
                        var eager = eng.ReorderToNchwc(captured, capturedLayout);
                        eager.AsSpan().CopyTo(output.AsWritableSpan());
                        output.Layout = capturedLayout;
                    });
                // Mirror the layout on the placeholder at RECORD time. A later
                // layout-sensitive op in the same scope (e.g. ReorderToNchw
                // below) inspects Layout during recording and would otherwise
                // observe the default Nchw — short-circuiting a required reorder.
                lazy.Layout = capturedLayout;
                return lazy;
            }
        }

        // Eager path. Shape stays the same flat-length; we just rearrange.
        var result = new Tensor<T>(tensor._shape) { Layout = targetLayout };
        if (typeof(T) == typeof(float))
        {
            var srcF = (Tensor<float>)(object)tensor;
            var dstF = (Tensor<float>)(object)result;
            Simd.NchwcReorder.ToNchwc(srcF.AsSpan(), dstF.AsWritableSpan(), n, c, h, w, cBlock);
        }
        else
        {
            // Generic scalar reorder — same index math as the float path.
            var src = tensor.AsSpan();
            var dst = result.AsWritableSpan();
            int hw = h * w;
            int outerC = c / cBlock;
            for (int ni = 0; ni < n; ni++)
            {
                int srcN = ni * c * hw;
                int dstN = ni * c * hw;
                for (int oc = 0; oc < outerC; oc++)
                {
                    int srcOc = srcN + oc * cBlock * hw;
                    int dstOc = dstN + oc * hw * cBlock;
                    for (int p = 0; p < hw; p++)
                    {
                        int dstBase = dstOc + p * cBlock;
                        for (int cb = 0; cb < cBlock; cb++)
                            dst[dstBase + cb] = src[srcOc + cb * hw + p];
                    }
                }
            }
        }
        return result;
    }

    /// <inheritdoc/>
    public virtual Tensor<T> ReorderToNchw<T>(Tensor<T> tensor)
    {
        if (tensor == null) throw new ArgumentNullException(nameof(tensor));
        if (tensor.Layout == LinearAlgebra.TensorLayout.Nchw) return tensor;
        if (tensor.Rank != 4)
            throw new ArgumentException($"NCHWc → NCHW reorder requires rank-4 input, got rank {tensor.Rank}.");
        int cBlock = tensor.Layout.CBlock();
        int n = tensor._shape[0], c = tensor._shape[1], h = tensor._shape[2], w = tensor._shape[3];
        if (c % cBlock != 0)
            throw new ArgumentException($"NCHWc → NCHW reorder requires C ({c}) divisible by cBlock ({cBlock}).");

        if (GraphMode.IsActive)
        {
            var scope = GraphMode.Current;
            if (scope != null)
            {
                var captured = tensor;
                var capturedShape = (int[])tensor._shape.Clone();
                var lazy = scope.RecordUnary(LazyNodeType.Custom, "ReorderToNchw", tensor, capturedShape,
                    (eng, output) =>
                    {
                        var eager = eng.ReorderToNchw(captured);
                        eager.AsSpan().CopyTo(output.AsWritableSpan());
                        output.Layout = LinearAlgebra.TensorLayout.Nchw;
                    });
                // Propagate Layout at record time (see matching comment in
                // ReorderToNchwc above) so downstream layout-sensitive ops
                // within the same scope see Nchw and don't short-circuit.
                lazy.Layout = LinearAlgebra.TensorLayout.Nchw;
                return lazy;
            }
        }

        var result = new Tensor<T>(tensor._shape) { Layout = LinearAlgebra.TensorLayout.Nchw };
        if (typeof(T) == typeof(float))
        {
            var srcF = (Tensor<float>)(object)tensor;
            var dstF = (Tensor<float>)(object)result;
            Simd.NchwcReorder.ToNchw(srcF.AsSpan(), dstF.AsWritableSpan(), n, c, h, w, cBlock);
        }
        else
        {
            var src = tensor.AsSpan();
            var dst = result.AsWritableSpan();
            int hw = h * w;
            int outerC = c / cBlock;
            for (int ni = 0; ni < n; ni++)
            {
                int srcN = ni * c * hw;
                int dstN = ni * c * hw;
                for (int oc = 0; oc < outerC; oc++)
                {
                    int srcOc = srcN + oc * hw * cBlock;
                    int dstOc = dstN + oc * cBlock * hw;
                    for (int p = 0; p < hw; p++)
                    {
                        int srcBase = srcOc + p * cBlock;
                        for (int cb = 0; cb < cBlock; cb++)
                            dst[dstOc + cb * hw + p] = src[srcBase + cb];
                    }
                }
            }
        }
        return result;
    }

    /// <summary>
    /// Write-through BatchNormInference. Mirrors the dispatch in
    /// <see cref="BatchNormInference{T}"/> but writes into the provided
    /// output tensor and propagates layout. Used by the GraphMode lambda
    /// to skip the intermediate-result alloc + CopyTo in CV inference,
    /// which calls BN once per Conv block (e.g., 50× per ResNet-50).
    /// </summary>
    public void BatchNormInferenceInto<T>(Tensor<T> output, Tensor<T> x, Tensor<T> gamma, Tensor<T> beta, Tensor<T> mean, Tensor<T> variance, double epsilon)
    {
        if (output == null) throw new ArgumentNullException(nameof(output));
        if (x == null) throw new ArgumentNullException(nameof(x));
        if (gamma == null) throw new ArgumentNullException(nameof(gamma));
        if (beta == null) throw new ArgumentNullException(nameof(beta));
        if (mean == null) throw new ArgumentNullException(nameof(mean));
        if (variance == null) throw new ArgumentNullException(nameof(variance));
        if (x.Rank != 4)
            throw new ArgumentException($"BatchNormInferenceInto requires rank-4 input, got rank {x.Rank}.");

        if (typeof(T) == typeof(float))
        {
            int C = x._shape[1], H = x._shape[2], W = x._shape[3], N = x._shape[0];
            var xf = (Tensor<float>)(object)x;
            var gammaF = (Tensor<float>)(object)gamma;
            var betaF  = (Tensor<float>)(object)beta;
            var meanF  = (Tensor<float>)(object)mean;
            var varF   = (Tensor<float>)(object)variance;
            var dstF   = (Tensor<float>)(object)output;
            dstF.Layout = x.Layout;
            if (x.Layout == LinearAlgebra.TensorLayout.Nchwc8 && C % Simd.NchwcBatchNorm.CBlock == 0)
            {
                Simd.NchwcBatchNorm.RunNchwc8(
                    xf.AsSpan(), gammaF.AsSpan(), betaF.AsSpan(),
                    meanF.AsSpan(), varF.AsSpan(), (float)epsilon,
                    dstF.AsWritableSpan(), N, C, H, W);
            }
            else
            {
                Simd.NchwcBatchNorm.RunNchw(
                    xf.AsSpan(), gammaF.AsSpan(), betaF.AsSpan(),
                    meanF.AsSpan(), varF.AsSpan(), (float)epsilon,
                    dstF.AsWritableSpan(), N, C, H, W);
            }
            return;
        }

        // Generic scalar fallback. Pre-combine scale/bias per channel, then FMA.
        var numOps = MathHelper.GetNumericOperations<T>();
        T eps = numOps.FromDouble(epsilon);
        int cc = x._shape[1], hh = x._shape[2], ww = x._shape[3], nn = x._shape[0];
        int spatial = hh * ww;
        var gData = gamma.GetDataArray();
        var bData = beta.GetDataArray();
        var mData = mean.GetDataArray();
        var vData = variance.GetDataArray();
        var scaleArr = new T[cc];
        var biasArr = new T[cc];
        for (int c = 0; c < cc; c++)
        {
            T s = numOps.Divide(gData[c], numOps.Sqrt(numOps.Add(vData[c], eps)));
            scaleArr[c] = s;
            biasArr[c] = numOps.Subtract(bData[c], numOps.Multiply(s, mData[c]));
        }
        output.Layout = x.Layout;
        var inSpan = x.AsSpan();
        var outSpan = output.AsWritableSpan();
        for (int ni = 0; ni < nn; ni++)
        {
            for (int c = 0; c < cc; c++)
            {
                int baseIdx = (ni * cc + c) * spatial;
                T s = scaleArr[c], b2 = biasArr[c];
                for (int sp = 0; sp < spatial; sp++)
                    outSpan[baseIdx + sp] = numOps.Add(numOps.Multiply(inSpan[baseIdx + sp], s), b2);
            }
        }
    }


    /// <inheritdoc/>
    public virtual Tensor<T> BatchNormInference<T>(Tensor<T> x, Tensor<T> gamma, Tensor<T> beta, Tensor<T> mean, Tensor<T> variance, double epsilon)
    {
        if (x == null) throw new ArgumentNullException(nameof(x));
        if (gamma == null) throw new ArgumentNullException(nameof(gamma));
        if (beta == null) throw new ArgumentNullException(nameof(beta));
        if (mean == null) throw new ArgumentNullException(nameof(mean));
        if (variance == null) throw new ArgumentNullException(nameof(variance));
        if (x.Rank != 4)
            throw new ArgumentException($"BatchNormInference requires rank-4 input, got rank {x.Rank}.");

        // GraphMode: record lazy node — never execute eagerly, or the plan
        // would bake placeholder data into the frozen BN output.
        if (GraphMode.IsActive)
        {
            var scope = GraphMode.Current;
            if (scope != null)
            {
                var capX = x; var capG = gamma; var capB = beta; var capM = mean; var capV = variance;
                double capE = epsilon;
                return scope.RecordVariadic(LazyNodeType.Custom, "BatchNormInference",
                    new[] { x, gamma, beta, mean, variance }, x._shape,
                    (eng, output) =>
                    {
                        if (eng is CpuEngine cpuEng)
                        {
                            cpuEng.BatchNormInferenceInto(output, capX, capG, capB, capM, capV, capE);
                        }
                        else
                        {
                            var r = eng.BatchNormInference(capX, capG, capB, capM, capV, capE);
                            r.AsSpan().CopyTo(output.AsWritableSpan());
                            output.Layout = r.Layout;
                        }
                    },
                    savedState: new object[] { epsilon });
            }
        }

        // Float fast paths — the common case for ONNX vision models.
        if (typeof(T) == typeof(float))
        {
            int C = x._shape[1];
            int H = x._shape[2];
            int W = x._shape[3];
            int N = x._shape[0];
            var xf = (Tensor<float>)(object)x;
            var gammaF = (Tensor<float>)(object)gamma;
            var betaF  = (Tensor<float>)(object)beta;
            var meanF  = (Tensor<float>)(object)mean;
            var varF   = (Tensor<float>)(object)variance;
            var result = new Tensor<float>(x._shape) { Layout = x.Layout };
            if (x.Layout == LinearAlgebra.TensorLayout.Nchwc8 && C % Simd.NchwcBatchNorm.CBlock == 0)
            {
                Simd.NchwcBatchNorm.RunNchwc8(
                    xf.AsSpan(), gammaF.AsSpan(), betaF.AsSpan(),
                    meanF.AsSpan(), varF.AsSpan(), (float)epsilon,
                    result.AsWritableSpan(), N, C, H, W);
            }
            else if (x.Layout == LinearAlgebra.TensorLayout.Nchw)
            {
                Simd.NchwcBatchNorm.RunNchw(
                    xf.AsSpan(), gammaF.AsSpan(), betaF.AsSpan(),
                    meanF.AsSpan(), varF.AsSpan(), (float)epsilon,
                    result.AsWritableSpan(), N, C, H, W);
            }
            else
            {
                // Any other packed layout (e.g. Nchwc16 that didn't hit the
                // Nchwc8 branch above) isn't safe to interpret as plain NCHW
                // — RunNchw would index into the buffer with the wrong stride
                // and produce garbage. Unpack to plain NCHW first, then run
                // the generic NCHW kernel, and mark the result as Nchw.
                var unpackedT = new Tensor<float>(new[] { N, C, H, W }) { Layout = LinearAlgebra.TensorLayout.Nchw };
                Simd.NchwcReorder.ToNchw(xf.AsSpan(), unpackedT.AsWritableSpan(), N, C, H, W, Simd.NchwcConv2D.CBlock);
                Simd.NchwcBatchNorm.RunNchw(
                    unpackedT.AsSpan(), gammaF.AsSpan(), betaF.AsSpan(),
                    meanF.AsSpan(), varF.AsSpan(), (float)epsilon,
                    result.AsWritableSpan(), N, C, H, W);
                result.Layout = LinearAlgebra.TensorLayout.Nchw;
            }
            return (Tensor<T>)(object)result;
        }

        // Generic scalar fallback for non-float T. Pre-combine scale/bias, then FMA.
        var numOps = MathHelper.GetNumericOperations<T>();
        T eps = numOps.FromDouble(epsilon);
        int cc = x._shape[1], hh = x._shape[2], ww = x._shape[3], nn = x._shape[0];
        int spatial = hh * ww;
        var gData = gamma.GetDataArray();
        var bData = beta.GetDataArray();
        var mData = mean.GetDataArray();
        var vData = variance.GetDataArray();
        var scaleArr = new T[cc];
        var biasArr = new T[cc];
        for (int c = 0; c < cc; c++)
        {
            T s = numOps.Divide(gData[c], numOps.Sqrt(numOps.Add(vData[c], eps)));
            scaleArr[c] = s;
            biasArr[c] = numOps.Subtract(bData[c], numOps.Multiply(s, mData[c]));
        }
        var outT = new Tensor<T>(x._shape) { Layout = x.Layout };
        var inSpan = x.AsSpan();
        var outSpan = outT.AsWritableSpan();
        for (int ni = 0; ni < nn; ni++)
        {
            for (int c = 0; c < cc; c++)
            {
                int baseIdx = (ni * cc + c) * spatial;
                T s = scaleArr[c], b2 = biasArr[c];
                for (int sp = 0; sp < spatial; sp++)
                    outSpan[baseIdx + sp] = numOps.Add(numOps.Multiply(inSpan[baseIdx + sp], s), b2);
            }
        }
        return outT;
    }

    /// <inheritdoc/>
    public virtual Tensor<T> BatchMatMul<T>(Tensor<T> a, Tensor<T> b)
    {
        using var _opScope = AiDotNet.Tensors.Engines.Profiling.Profiler.OpScope("BatchMatMul");
        if (a == null) throw new ArgumentNullException(nameof(a));
        if (b == null) throw new ArgumentNullException(nameof(b));

        // Lazy graph mode: record and return placeholder
        if (GraphMode.IsActive)
        { var ac = AutoTracer.TryGetCompiledPlan<T>("BatchMatMul", a._shape); if (ac is not null) return ac.Execute(); }

        {
            var scope = GraphMode.Current;
            if (scope != null && a.Rank >= 2 && b.Rank >= 2 && a.Rank == b.Rank)
            {
                var outShape = ComputeMatMulOutputShape(a._shape, b._shape);
                var capturedA = a;
                var capturedB = b;
                return scope.RecordBinary(LazyNodeType.BatchMatMul, "BatchMatMul", a, b, outShape,
                    // Path C write-through: BERT attention hits BatchMatMul
                    // 24× per inference (12 heads × 2 matmuls). Skipping the
                    // intermediate-tensor allocation + 3 MB CopyTo saves
                    // ~50 µs per call = ~1.2 ms aggregate per BERT inference.
                    (eng, output) =>
                    {
                        if (typeof(T) == typeof(float) && eng is CpuEngine cpuEng)
                        {
                            cpuEng.BatchMatMulFloatInto(
                                (Tensor<float>)(object)capturedA,
                                (Tensor<float>)(object)capturedB,
                                (Tensor<float>)(object)output);
                        }
                        else
                        {
                            var eager = eng.BatchMatMul(capturedA, capturedB);
                            eager.AsSpan().CopyTo(output.AsWritableSpan());
                        }
                    },
                    BackwardFunctions<T>.BatchMatMulBackward);
            }
        }

        // Preserve original references for tape recording (#257). The
        // .Contiguous() rebind below would otherwise replace the user's
        // GradFn-bearing view with a fresh tensor, breaking the topo-walk
        // chain back to the upstream parameter — same defect as the
        // TensorMatMul fix above.
        var aOrig = a;
        var bOrig = b;
        // For ND (N>=3) batch matmul, materialize non-contiguous views.
        // 2D stride-aware GEMM is handled below with transA/transB flags.
        if (a.Rank >= 3 && !a.IsContiguous) a = a.Contiguous();
        if (b.Rank >= 3 && !b.IsContiguous) b = b.Contiguous();

        // Industry-standard BatchMatMul supports any-rank tensors (2D, 3D, 4D, 5D, ...)
        // For ND tensors where N >= 2:
        // - First N-2 dimensions are batch dimensions (must match)
        // - Last 2 dimensions are matrix dimensions: [..., M, K] @ [..., K, N] = [..., M, N]
        if (a.Rank < 2 || b.Rank < 2)
        {
            throw new ArgumentException(
                $"BatchMatMul requires tensors with at least 2 dimensions. Got ranks {a.Rank} and {b.Rank}.");
        }

        if (a.Rank != b.Rank)
        {
            throw new ArgumentException(
                $"BatchMatMul requires tensors with matching ranks. Got ranks {a.Rank} and {b.Rank}.");
        }

        int rank = a.Rank;
        int m = a._shape[rank - 2];  // Second-to-last dimension
        int k = a._shape[rank - 1];  // Last dimension of a
        int k2 = b._shape[rank - 2]; // Second-to-last dimension of b
        int n = b._shape[rank - 1];  // Last dimension of b

        // Verify inner dimensions match for matrix multiplication
        if (k != k2)
        {
            throw new ArgumentException(
                $"Matrix dimensions incompatible for multiplication. " +
                $"First tensor's last dimension is {k}, " +
                $"second tensor's second-to-last dimension is {k2}. " +
                $"Inner dimensions must match.");
        }

        // Verify batch dimensions match
        for (int i = 0; i < rank - 2; i++)
        {
            if (a._shape[i] != b._shape[i])
            {
                throw new ArgumentException(
                    $"Batch dimensions must match. Got {a._shape[i]} vs {b._shape[i]} at dimension {i}.");
            }
        }

        // Calculate total batch size (product of all batch dimensions)
        int batchSize = 1;
        for (int i = 0; i < rank - 2; i++)
        {
            batchSize *= a._shape[i];
        }

        // Build output shape: [...batch dims..., m, n]
        var outputShape = new int[rank];
        for (int i = 0; i < rank - 2; i++)
        {
            outputShape[i] = a._shape[i];
        }
        outputShape[rank - 2] = m;
        outputShape[rank - 1] = n;

        var numOps = MathHelper.GetNumericOperations<T>();
        var result = AutoTensorCache.RentOrAllocate<T>(outputShape);

        // Handle 2D case (no batch dimensions)
        if (rank == 2)
        {
            // Stride-aware GEMM for float: detect transposed views and pass flags
            // SIMD GEMM: only for contiguous or simple-transpose operands
            if (typeof(T) == typeof(float) &&
                (a.IsContiguous || a.IsSimpleTranspose) &&
                (b.IsContiguous || b.IsSimpleTranspose))
            {
                bool transA = a.IsSimpleTranspose;
                bool transB = b.IsSimpleTranspose;
                int lda = transA ? a._strides[a.Rank - 1] : k;
                int ldb = transB ? b._strides[b.Rank - 1] : n;

                // Get raw storage arrays (NOT GetDataArray which copies for views)
                var aArr = a._storage.GetDataArray();
                var bArr = b._storage.GetDataArray();
                var rArr = result.GetDataArray();
                var aFloat = new ReadOnlySpan<float>((float[])(object)aArr).Slice(a._storageOffset);
                var bFloat = new ReadOnlySpan<float>((float[])(object)bArr).Slice(b._storageOffset);
                var cFloat = new Span<float>((float[])(object)rArr);

                Simd.SimdGemm.Sgemm(aFloat, lda, transA, bFloat, ldb, transB, cFloat, m, k, n);
                DifferentiableOps.RecordBinary("BatchMatMul", result, aOrig, bOrig, BackwardFunctions<T>.BatchMatMulBackward);
                { var ca = a; var cb = b; AutoTracer.RecordOp("BatchMatMul", result, eng => eng.BatchMatMul(ca, cb)); }
                return result;
            }

            // Try OneDNN/MKL BLAS for contiguous non-transposed
            if (a.IsContiguous && b.IsContiguous)
            {
                if (MatrixMultiplyHelper.TryGemm(a.Data, 0, b.Data, 0, result.Data, 0, m, k, n))
                {
                    DifferentiableOps.RecordBinary("BatchMatMul", result, aOrig, bOrig, BackwardFunctions<T>.BatchMatMulBackward);
                    { var ca = a; var cb = b; AutoTracer.RecordOp("BatchMatMul", result, eng => eng.BatchMatMul(ca, cb)); }
                    return result;
                }
            }

            // Generic fallback: stride-aware scalar matmul (raw storage for stride access)
            var aDataArr = a._storage.GetDataArray();
            var bDataArr = b._storage.GetDataArray();
            var rDataArr = result.GetDataArray();
            int aOff = a._storageOffset, bOff = b._storageOffset;
            int aStride0 = a._strides[0], aStride1 = a._strides[1];
            int bStride0 = b._strides[0], bStride1 = b._strides[1];

            Parallel.For(0, m, i =>
            {
                for (int j = 0; j < n; j++)
                {
                    T sum = numOps.Zero;
                    for (int p = 0; p < k; p++)
                    {
                        T aVal = aDataArr[aOff + i * aStride0 + p * aStride1];
                        T bVal = bDataArr[bOff + p * bStride0 + j * bStride1];
                        sum = numOps.Add(sum, numOps.Multiply(aVal, bVal));
                    }
                    rDataArr[i * n + j] = sum;
                }
            });
            DifferentiableOps.RecordBinary("BatchMatMul", result, aOrig, bOrig,
                BackwardFunctions<T>.BatchMatMulBackward);
            { var ca = a; var cb = b; AutoTracer.RecordOp("BatchMatMul", result, eng => eng.BatchMatMul(ca, cb)); }
            return result;
        }

        var aData = a.GetDataArray();
        var bData = b.GetDataArray();
        var rData = result.GetDataArray();

        // Handle ND case with batch dimensions (N >= 3)
        int matrixSizeA = m * k;
        int matrixSizeB = k * n;
        int matrixSizeResult = m * n;

        // Fast path: for float, choose the right parallelism axis based on
        // batch size.
        //
        // batchSize == 1: call Sgemm directly — it has internal Parallel.For
        //   across the m dimension, so a single large slice still utilises
        //   all cores. Outer Parallel.For(0, 1) would run serial anyway.
        //
        // batchSize >= 2: outer Parallel.For over the batch with
        //   SgemmSequential per slice. Outer parallelism hides SGEMM dispatch
        //   overhead and each worker can saturate a core on one slice.
        //   Using Sgemm here would NEST parallel loops (one Parallel.For per
        //   worker), which contends for the shared thread pool.
        //
        // BatchMatMulRootCauseDiag validated these tiers: batch=12 BERT
        // attention slices are 3× faster with outer Parallel.For +
        // SgemmSequential vs MatrixMultiplyHelper sequential; batch=1 FFN
        // weight broadcasts use Sgemm's internal parallelism at ~100 GFLOP/s.
        if (typeof(T) == typeof(float))
        {
            var aF = (float[])(object)aData;
            var bF = (float[])(object)bData;
            var rF = (float[])(object)rData;
            if (batchSize == 1)
            {
                Simd.SimdGemm.Sgemm(
                    aF.AsSpan(0, matrixSizeA),
                    bF.AsSpan(0, matrixSizeB),
                    rF.AsSpan(0, matrixSizeResult),
                    m, k, n);
            }
            else
            {
                Parallel.For(0, batchSize, batch =>
                {
                    int aOffset = batch * matrixSizeA;
                    int bOffset = batch * matrixSizeB;
                    int resultOffset = batch * matrixSizeResult;
                    Simd.SimdGemm.SgemmSequential(
                        aF.AsSpan(aOffset, matrixSizeA),
                        bF.AsSpan(bOffset, matrixSizeB),
                        rF.AsSpan(resultOffset, matrixSizeResult),
                        m, k, n);
                });
            }
            goto batchDone;
        }

        Parallel.For(0, batchSize, batch =>
        {
            int aOffset = batch * matrixSizeA;
            int bOffset = batch * matrixSizeB;
            int resultOffset = batch * matrixSizeResult;

            if (MatrixMultiplyHelper.TryGemm(a.Data, aOffset, b.Data, bOffset, result.Data, resultOffset, m, k, n))
            {
                return;
            }

            // Scalar fallback with direct array access
            for (int i = 0; i < m; i++)
            {
                for (int j = 0; j < n; j++)
                {
                    T sum = numOps.Zero;
                    for (int p = 0; p < k; p++)
                    {
                        sum = numOps.Add(sum, numOps.Multiply(aData[aOffset + i * k + p], bData[bOffset + p * n + j]));
                    }
                    rData[resultOffset + i * n + j] = sum;
                }
            }
        });

        batchDone:

        DifferentiableOps.RecordBinary("BatchMatMul", result, aOrig, bOrig,
            BackwardFunctions<T>.BatchMatMulBackward);
        { var ca = a; var cb = b; AutoTracer.RecordOp("BatchMatMul", result, eng => eng.BatchMatMul(ca, cb)); }
        return result;
    }

    /// <inheritdoc/>
    #if !NETFRAMEWORK
    [MethodImpl(MethodImplOptions.AggressiveOptimization)]
#endif
    public virtual unsafe Tensor<T> TensorAdd<T>(Tensor<T> a, Tensor<T> b)
    {
        if (a == null) throw new ArgumentNullException(nameof(a));
        if (b == null) throw new ArgumentNullException(nameof(b));
        if (!ShapesMatch(a._shape, b._shape))
        {
            throw new ArgumentException(
                $"Tensor shapes must match. Got {FormatShape(a._shape)} and {FormatShape(b._shape)}.");
        }

        // Lazy graph mode: record and return placeholder
        if (GraphMode.IsActive)
        {
            var scope = GraphMode.Current;
            if (scope != null)
            {
                var capturedA = a;
                var capturedB = b;
                return scope.RecordBinary(LazyNodeType.Add, "TensorAdd", a, b, a._shape,
                    (eng, output) => eng.TensorAddInto(output, capturedA, capturedB),
                    BackwardFunctions<T>.AddBackward);
            }
        }

        // Auto-tracer: check if a compiled plan exists for this op pattern
        var autoCompiled = AutoTracer.TryGetCompiledPlan<T>("TensorAdd", a._shape);
        if (autoCompiled is not null) return autoCompiled.Execute();

        // RentUninitialized: kernel writes every element, no need to zero
        var result = AutoTensorCache.RentOrAllocate<T>(a._shape);
        int length = a.Length;

        // Stride-aware: if either operand is non-contiguous, use strided iteration (zero-copy)
        // IMPORTANT: use _storage.GetDataArray() (raw backing array) not tensor.GetDataArray() (which copies for views)
        if (!a.IsContiguous || !b.IsContiguous)
        {
            var aRaw = a._storage.GetDataArray(); var bRaw = b._storage.GetDataArray(); var rArr = result.GetDataArray();
            var ops = MathHelper.GetNumericOperations<T>();
            if (a.IsContiguous) { int aOff = a._storageOffset; for (int i = 0; i < length; i++) rArr[i] = ops.Add(aRaw[aOff + i], bRaw[b.LogicalToStorageIndex(i)]); }
            else if (b.IsContiguous) { int bOff = b._storageOffset; for (int i = 0; i < length; i++) rArr[i] = ops.Add(aRaw[a.LogicalToStorageIndex(i)], bRaw[bOff + i]); }
            else { for (int i = 0; i < length; i++) rArr[i] = ops.Add(aRaw[a.LogicalToStorageIndex(i)], bRaw[b.LogicalToStorageIndex(i)]); }
        }
        else if (typeof(T) == typeof(float))
        {
            // In-house path: pin the raw storage + storageOffset and call
            // SimdKernels.VectorAddUnsafe (4× unrolled AVX2/AVX-512 with
            // FMA on net8+). Beats TensorPrimitives by 1.0-1.04× on every
            // tracked DiT-XL shape — same kernel family that beat MKL on
            // the iter18c sweep.
            var aRaw = (float[])(object)a._storage.GetDataArray();
            var bRaw = (float[])(object)b._storage.GetDataArray();
            var rRaw = (float[])(object)result._storage.GetDataArray();
            int aOff = a._storageOffset, bOff = b._storageOffset, rOff = result._storageOffset;
            fixed (float* pAFix = aRaw, pBFix = bRaw, pRFix = rRaw)
            {
                float* pA = pAFix + aOff;
                float* pB = pBFix + bOff;
                float* pR = pRFix + rOff;

            // JIT-compiled kernels: size-specialized, 4x unrolled, NT stores
            if (CpuJitSelfTest.IsVerified && length >= 64)
            {
                JitBinaryDispatch(pA, pB, pR, length, JitBinaryOp.Add);
            }
            else
            {
                // Fallback: SimdKernels with parallel chunking for large arrays.
                // Bandwidth-bound threshold: one core hits ~4 GB/s on a bulk
                // add of non-L2-resident data, DRAM delivers 50+ GB/s across
                // channels. AddRootCauseDiag measured 3.25× speedup moving
                // from 1 → 4 chunks at length=196608 (BERT residual add).
                // Old threshold length/500_000 required a 3 MB add before
                // splitting — far past the point where parallelism helps.
                // Target ~64 KB per chunk (fits in L1) with a cap at the
                // thread-pool size.
                const int kElemsPerChunk = 16 * 1024; // 64 KB at float32
                int addChunks = Math.Min(
                    CpuParallelSettings.MaxDegreeOfParallelism,
                    Math.Max(1, length / kElemsPerChunk));
                if (addChunks >= 2)
                {
                    int chunkSize = (length + addChunks - 1) / addChunks;
                    chunkSize = (chunkSize + 31) & ~31;
                    var pACap = pA; var pBCap = pB; var pRCap = pR;
                    int lenCap = length;

                    PersistentParallelExecutor.Instance.Execute(addChunks, chunk =>
                    {
                        int start = chunk * chunkSize;
                        int count = Math.Min(chunkSize, lenCap - start);
                        if (count > 0)
                        {
                            SimdKernels.VectorAddUnsafe(pACap + start, pBCap + start, pRCap + start, count);
                        }
                    });
                }
                else
                {
                    SimdKernels.VectorAddUnsafe(pA, pB, pR, length);
                }
            }
            }
        }
        else if (typeof(T) == typeof(double))
        {
            // In-house: pin raw storage + offset, call SimdKernels.VectorAddUnsafe(double*).
            var aRaw = (double[])(object)a._storage.GetDataArray();
            var bRaw = (double[])(object)b._storage.GetDataArray();
            var rRaw = (double[])(object)result._storage.GetDataArray();
            int aOff = a._storageOffset, bOff = b._storageOffset, rOff = result._storageOffset;
            fixed (double* pAFix = aRaw, pBFix = bRaw, pRFix = rRaw)
            {
                double* pA = pAFix + aOff;
                double* pB = pBFix + bOff;
                double* pR = pRFix + rOff;
                int subChunks = Math.Min(CpuParallelSettings.MaxDegreeOfParallelism, Math.Max(1, length / 250_000));
                if (subChunks >= 2)
                {
                    int chunkSize = (length + subChunks - 1) / subChunks;
                    chunkSize = (chunkSize + 15) & ~15;
                    IntPtr ipA = (IntPtr)pA, ipB = (IntPtr)pB, ipR = (IntPtr)pR;
                    int totalLength = length;
                    Parallel.For(0, subChunks, chunk =>
                    {
                        int start = chunk * chunkSize;
                        int count = Math.Min(chunkSize, totalLength - start);
                        if (count > 0)
                            SimdKernels.VectorAddUnsafe((double*)ipA + start, (double*)ipB + start, (double*)ipR + start, count);
                    });
                }
                else
                {
                    SimdKernels.VectorAddUnsafe(pA, pB, pR, length);
                }
            }
        }
        else
        {
            var numOps = MathHelper.GetNumericOperations<T>();
            numOps.Add(a.AsSpan(), b.AsSpan(), result.AsWritableSpan());
        }

        DifferentiableOps.RecordBinary("TensorAdd", result, a, b, BackwardFunctions<T>.AddBackward);

        // Auto-tracer: record this op for future compilation
        { var ca = a; var cb = b; AutoTracer.RecordOp("TensorAdd", result, eng => eng.TensorAdd(ca, cb)); }

        return result;
    }

    /// <summary>
    /// Adds tensor b to tensor a in-place (a += b). Zero allocation.
    /// Uses parallel SIMD for large float tensors.
    /// </summary>
    #if !NETFRAMEWORK
    [MethodImpl(MethodImplOptions.AggressiveOptimization)]
#endif
    public virtual unsafe void TensorAddInPlace<T>(Tensor<T> a, Tensor<T> b)
    {
        if (a == null) throw new ArgumentNullException(nameof(a));
        if (b == null) throw new ArgumentNullException(nameof(b));
        if (!ShapesMatch(a._shape, b._shape))
        {
            throw new ArgumentException(
                $"Tensor shapes must match. Got {FormatShape(a._shape)} and {FormatShape(b._shape)}.");
        }

        // Save input before mutation when tape is active (for backward pass)
        Tensor<T>? savedA = null;
        var tape = GradientTape<T>.Current;
        if (tape is not null && tape.Options.RecordInPlace)
            savedA = a.Clone();

        // Increment version BEFORE mutation so prior tape entries detect the change
        a.IncrementVersion();

        // Stride-aware: in-place requires contiguous target; materialize source if needed
        if (!a.IsContiguous) throw new InvalidOperationException("In-place add requires contiguous target tensor.");
        var bOrig = b;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!b.IsContiguous) b = b.Contiguous();

        int length = a.Length;

        // Fast path for float tensors: bypass generic dispatch + Span bounds-checking
        // Use Memory<T>.Pin() directly — avoids GetDataArray() which can copy (breaking in-place writes)
        if (typeof(T) == typeof(float))
        {
            var aMem = AsFloatMemory(a.Data);
            var bMem = AsFloatMemory(b.Data);
            using var pinA = aMem.Pin();
            using var pinB = bMem.Pin();
            float* pA = (float*)pinA.Pointer;
            float* pB = (float*)pinB.Pointer;

#if !NET471
            // Strategy 1: Try oneDNN for best performance (uses JIT-compiled native kernels)
            if (OneDnnProvider.IsAvailable)
            {
                if (OneDnnProvider.TryAdd(pB, pA, pA, length))
                {
                    if (savedA is not null) DifferentiableOps.RecordBinary("TensorAddInPlace", a, savedA, bOrig, BackwardFunctions<T>.AddBackward);
                    return;
                }
            }
#endif

            // Strategy 2: JIT-compiled kernel (size-specialized, 4x unrolled, parallel for large)
            if (CpuJitSelfTest.IsVerified && length >= 64)
            {
                JitBinaryDispatch(pA, pB, pA, length, JitBinaryOp.Add);
                if (savedA is not null) DifferentiableOps.RecordBinary("TensorAddInPlace", a, savedA, bOrig, BackwardFunctions<T>.AddBackward);
                return;
            }

            // Fallback: SimdKernels with parallel chunking for large arrays
            int numChunks = Math.Min(CpuParallelSettings.MaxDegreeOfParallelism, Math.Max(1, length / 2_000_000));
            if (numChunks >= 2)
            {
                int chunkSize = (length + numChunks - 1) / numChunks;
                chunkSize = (chunkSize + 31) & ~31;

                Parallel.For(0, numChunks, chunk =>
                {
                    int start = chunk * chunkSize;
                    int count = Math.Min(chunkSize, length - start);
                    if (count > 0)
                    {
                        SimdKernels.VectorAddUnsafe(pB + start, pA + start, pA + start, count);
                    }
                });
            }
            else
            {
                SimdKernels.VectorAddUnsafe(pB, pA, pA, length);
            }
            if (savedA is not null) DifferentiableOps.RecordBinary("TensorAddInPlace", a, savedA, bOrig, BackwardFunctions<T>.AddBackward);
            return;
        }

        var numOps = MathHelper.GetNumericOperations<T>();
        numOps.Add(a.AsSpan(), b.AsSpan(), a.AsWritableSpan());
        if (savedA is not null)
            DifferentiableOps.RecordBinary("TensorAddInPlace", a, savedA, bOrig, BackwardFunctions<T>.AddBackward);
    }

    /// <summary>
    /// Adds tensors a and b, storing result in destination. Zero allocation.
    /// </summary>
    #if !NETFRAMEWORK
    [MethodImpl(MethodImplOptions.AggressiveOptimization)]
#endif
    public unsafe void TensorAddInto<T>(Tensor<T> destination, Tensor<T> a, Tensor<T> b)
    {
        if (destination == null) throw new ArgumentNullException(nameof(destination));
        if (a == null) throw new ArgumentNullException(nameof(a));
        if (b == null) throw new ArgumentNullException(nameof(b));
        var bOrig = b;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!b.IsContiguous) b = b.Contiguous();
        var aOrig = a;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!a.IsContiguous) a = a.Contiguous();
        if (!destination.IsContiguous) throw new InvalidOperationException("Output tensor must be contiguous.");
        if (!ShapesMatch(a._shape, b._shape) || !ShapesMatch(a._shape, destination._shape))
        {
            throw new ArgumentException("All tensor shapes must match.");
        }

        int length = a.Length;
        if (typeof(T) == typeof(float))
        {
            var aMem = AsFloatMemory(a.Data);
            var bMem = AsFloatMemory(b.Data);
            var rMem = AsFloatMemory(destination.Data);
            using var pinA = aMem.Pin();
            using var pinB = bMem.Pin();
            using var pinR = rMem.Pin();
            float* pA = (float*)pinA.Pointer;
            float* pB = (float*)pinB.Pointer;
            float* pR = (float*)pinR.Pointer;
            if (CpuJitSelfTest.IsVerified && length >= 64)
                JitBinaryDispatch(pA, pB, pR, length, JitBinaryOp.Add);
            else
                Simd.SimdKernels.VectorAddUnsafe(pA, pB, pR, length);
        }
        else
        {
            var numOps = MathHelper.GetNumericOperations<T>();
            numOps.Add(a.AsSpan(), b.AsSpan(), destination.AsWritableSpan());
        }
    }

    /// <inheritdoc/>
    public virtual Tensor<T> TensorBroadcastAdd<T>(Tensor<T> a, Tensor<T> b)
    {
        using var _opScope = AiDotNet.Tensors.Engines.Profiling.Profiler.OpScope("TensorBroadcastAdd");
        if (a == null) throw new ArgumentNullException(nameof(a));
        if (b == null) throw new ArgumentNullException(nameof(b));

        // Lazy graph mode: record and return placeholder
        if (GraphMode.IsActive)
        { var ac = AutoTracer.TryGetCompiledPlan<T>("TensorBroadcastAdd", a._shape); if (ac is not null) return ac.Execute(); }

        {
            var scope = GraphMode.Current;
            if (scope != null)
            {
                var capturedA = a;
                var capturedB = b;
                var broadcastShape = ComputeBroadcastShape(a._shape, b._shape);
                return scope.RecordBinary(LazyNodeType.BroadcastAdd, "TensorBroadcastAdd", a, b, broadcastShape,
                    (eng, output) => { var eager = eng.TensorBroadcastAdd(capturedA, capturedB); eager.AsSpan().CopyTo(output.AsWritableSpan()); },
                    BackwardFunctions<T>.BroadcastAddBackward);
            }
        }

        // Preserve original references for tape recording (#257) — the
        // .Contiguous() rebind below would otherwise replace a user's
        // GradFn-bearing strided view with a fresh tensor, breaking the
        // topo-walk back to upstream parameters. Math kernels still consume
        // the contiguous copies for performance.
        var aOrig = a;
        var bOrig = b;
        if (!a.IsContiguous) a = a.Contiguous();
        if (!b.IsContiguous) b = b.Contiguous();

        // Generic trailing-repeat fast path — same rationale as
        // TensorBroadcastMultiply. The DiT AdaLN shift path hits this every
        // block × every inference step × every Predict, so the prior indexer-
        // per-element fallback was a major transformer perf bug.
        if (TryBroadcastTrailingRepeat(a, b, out int bTileSize))
        {
            var res = AutoTensorCache.RentOrAllocate<T>(a._shape);
            var numOps = MathHelper.GetNumericOperations<T>();
            var aSpan = a.AsSpan();
            var bSpan = b.AsSpan();
            var rSpan = res.AsWritableSpan();
            int numTiles = a.Length / bTileSize;
            for (int t = 0; t < numTiles; t++)
            {
                int off = t * bTileSize;
                numOps.Add(aSpan.Slice(off, bTileSize), bSpan, rSpan.Slice(off, bTileSize));
            }
            DifferentiableOps.RecordBinary("TensorBroadcastAdd", res, aOrig, bOrig, BackwardFunctions<T>.BroadcastAddBackward);
            { var ca = a; var cb = b; AutoTracer.RecordOp("TensorBroadcastAdd", res, eng => eng.TensorBroadcastAdd(ca, cb)); }
            return res;
        }

        // Use optimized Tensor.BroadcastAdd which handles broadcasting logic
        var result = a.BroadcastAdd(b);
        DifferentiableOps.RecordBinary("TensorBroadcastAdd", result, aOrig, bOrig, BackwardFunctions<T>.BroadcastAddBackward);
        { var ca = a; var cb = b; AutoTracer.RecordOp("TensorBroadcastAdd", result, eng => eng.TensorBroadcastAdd(ca, cb)); }
        return result;
    }

    /// <inheritdoc/>
    public virtual Tensor<T> TensorBroadcastSubtract<T>(Tensor<T> a, Tensor<T> b)
    {
        if (a == null) throw new ArgumentNullException(nameof(a));
        if (b == null) throw new ArgumentNullException(nameof(b));

        if (GraphMode.IsActive)
        { var ac = AutoTracer.TryGetCompiledPlan<T>("TensorBroadcastSubtract", a._shape); if (ac is not null) return ac.Execute(); }

        {
            var scope = GraphMode.Current;
            if (scope != null)
            {
                var capturedA = a;
                var capturedB = b;
                // Same broadcast-shape fix as TensorBroadcastMultiply —
                // a._shape is not always the final broadcast shape.
                var broadcastShape = ComputeBroadcastShape(a._shape, b._shape);
                return scope.RecordBinary(LazyNodeType.BroadcastSubtract, "TensorBroadcastSubtract", a, b, broadcastShape,
                    (eng, output) => { var r = eng.TensorBroadcastSubtract(capturedA, capturedB); r.AsSpan().CopyTo(output.AsWritableSpan()); },
                    BackwardFunctions<T>.BroadcastSubtractBackward);
            }
        }

        // Preserve original references for tape recording (#257) — see
        // TensorBroadcastAdd for the rationale.
        var aOrig = a;
        var bOrig = b;
        if (!a.IsContiguous) a = a.Contiguous();
        if (!b.IsContiguous) b = b.Contiguous();

        // Fast path for [N,M] - [M] or [N,M] - [1,M] bias subtract pattern
        if (typeof(T) == typeof(float) && a.Rank == 2 && (b.Rank == 1 || (b.Rank == 2 && b._shape[0] == 1)))
        {
            int rows = a._shape[0], cols = a._shape[1];
            int bCols = b.Rank == 1 ? b._shape[0] : b._shape[1];
            if (cols == bCols)
            {
                var res = AutoTensorCache.RentOrAllocate<T>(a._shape);
                var af = (float[])(object)a.GetDataArray();
                var bf = (float[])(object)b.GetDataArray();
                var rf = (float[])(object)res.GetDataArray();
                for (int r = 0; r < rows; r++)
                {
                    int off = r * cols;
                    for (int c = 0; c < cols; c++)
                        rf[off + c] = af[off + c] - bf[c];
                }
                DifferentiableOps.RecordBinary("TensorBroadcastSubtract", res, aOrig, bOrig, BackwardFunctions<T>.BroadcastSubtractBackward);
                { var ca = a; var cb = b; AutoTracer.RecordOp("TensorBroadcastSubtract", res, eng => eng.TensorBroadcastSubtract(ca, cb)); }
                return res;
            }
        }

        var result = a.BroadcastSubtract(b);
        DifferentiableOps.RecordBinary("TensorBroadcastSubtract", result, aOrig, bOrig, BackwardFunctions<T>.BroadcastSubtractBackward);
        { var ca = a; var cb = b; AutoTracer.RecordOp("TensorBroadcastSubtract", result, eng => eng.TensorBroadcastSubtract(ca, cb)); }
        return result;
    }

    /// <inheritdoc/>
    public virtual Tensor<T> TensorBroadcastDivide<T>(Tensor<T> a, Tensor<T> b)
    {
        if (a == null) throw new ArgumentNullException(nameof(a));
        if (b == null) throw new ArgumentNullException(nameof(b));

        if (GraphMode.IsActive)
        { var ac = AutoTracer.TryGetCompiledPlan<T>("TensorBroadcastDivide", a._shape); if (ac is not null) return ac.Execute(); }

        {
            var scope = GraphMode.Current;
