                    (eng, output) => { var r = eng.TensorBroadcastDivide(capturedA, capturedB); r.AsSpan().CopyTo(output.AsWritableSpan()); },
                    BackwardFunctions<T>.BroadcastDivideBackward);
            }
        }

        // Preserve original references for tape recording (#257).
        var aOrig = a;
        var bOrig = b;
        if (!a.IsContiguous) a = a.Contiguous();
        if (!b.IsContiguous) b = b.Contiguous();

        var result = a.BroadcastDivide(b);
        DifferentiableOps.RecordBinary("TensorBroadcastDivide", result, aOrig, bOrig, BackwardFunctions<T>.BroadcastDivideBackward);
        { var ca = a; var cb = b; AutoTracer.RecordOp("TensorBroadcastDivide", result, eng => eng.TensorBroadcastDivide(ca, cb)); }
        return result;
    }

    /// <inheritdoc/>
    public virtual Tensor<T> TensorBroadcastMultiply<T>(Tensor<T> a, Tensor<T> b)
    {
        if (a == null) throw new ArgumentNullException(nameof(a));
        if (b == null) throw new ArgumentNullException(nameof(b));

        if (GraphMode.IsActive)
        { var ac = AutoTracer.TryGetCompiledPlan<T>("TensorBroadcastMultiply", a._shape); if (ac is not null) return ac.Execute(); }

        {
            var scope = GraphMode.Current;
            if (scope != null)
            {
                var capturedA = a;
                var capturedB = b;
                // Broadcast output shape follows NumPy rules — must be computed
                // from both operands, not just a._shape. The previous `a._shape`
                // assumption held only when a was the "larger" operand; when
                // b is broader (e.g. scalar * [B, H, S, D]), the recorded
                // output buffer was too small and the eager TensorBroadcastMultiply
                // inside the closure overran it with "Destination is too short".
                var broadcastShape = ComputeBroadcastShape(a._shape, b._shape);
                return scope.RecordBinary(LazyNodeType.BroadcastMultiply, "TensorBroadcastMultiply", a, b, broadcastShape,
                    (eng, output) => { var r = eng.TensorBroadcastMultiply(capturedA, capturedB); r.AsSpan().CopyTo(output.AsWritableSpan()); },
                    BackwardFunctions<T>.BroadcastMultiplyBackward);
            }
        }

        // Preserve original references for tape recording (#257).
        var aOrig = a;
        var bOrig = b;
        if (!a.IsContiguous) a = a.Contiguous();
        if (!b.IsContiguous) b = b.Contiguous();

        // Generic trailing-repeat fast path (float + double + any T with SIMD numOps).
        // Covers the AdaLN / transformer-bias shape pattern where b's shape is a
        // trailing suffix of a's shape with leading dims all 1 — e.g.
        //   [B, S, H] * [1, 1, H]   (DiT AdaLN)
        //   [N, M]    * [1, M]      (dense bias)
        //   [N, M]    * [M]         (dense bias, rank-dropped)
        // For these, broadcasting is just repeating b across a.Length / b.Length
        // tiles, each an elementwise multiply — a perfect fit for the SIMD
        // numOps.Multiply(Span,Span,Span) kernel (Vector256<double> AVX2/FMA).
        // Without this, the generic Tensor<T>.BroadcastMultiply at rank > 2
        // falls back to an indexer-per-element loop that dominates transformer
        // wall clock at ~100x slower than SIMD.
        if (TryBroadcastTrailingRepeat(a, b, out int bTileSize))
        {
            var res = AutoTensorCache.RentOrAllocate<T>(a._shape);
            var numOps = MathHelper.GetNumericOperations<T>();
            var aSpan = a.AsSpan();
            var bSpan = b.AsSpan();
            var rSpan = res.AsWritableSpan();
            int numTiles = a.Length / bTileSize;
            for (int t = 0; t < numTiles; t++)
            {
                int off = t * bTileSize;
                numOps.Multiply(aSpan.Slice(off, bTileSize), bSpan, rSpan.Slice(off, bTileSize));
            }
            DifferentiableOps.RecordBinary("TensorBroadcastMultiply", res, aOrig, bOrig, BackwardFunctions<T>.BroadcastMultiplyBackward);
            { var ca = a; var cb = b; AutoTracer.RecordOp("TensorBroadcastMultiply", res, eng => eng.TensorBroadcastMultiply(ca, cb)); }
            return res;
        }

        var result = a.BroadcastMultiply(b);
        DifferentiableOps.RecordBinary("TensorBroadcastMultiply", result, aOrig, bOrig, BackwardFunctions<T>.BroadcastMultiplyBackward);
        { var ca = a; var cb = b; AutoTracer.RecordOp("TensorBroadcastMultiply", result, eng => eng.TensorBroadcastMultiply(ca, cb)); }
        return result;
    }

    /// <summary>
    /// Detects the "trailing-repeat" broadcast pattern where <paramref name="b"/>
    /// broadcasts over <paramref name="a"/> by matching a trailing suffix of
    /// <paramref name="a"/>'s shape, with any preceding dimensions all equal to 1.
    /// The caller can then treat the broadcast as <c>a.Length / b.Length</c>
    /// tiles of <c>b.Length</c> elementwise ops — the dominant shape pattern for
    /// transformer AdaLN / dense-bias and the fundamental reason we don't want
    /// to route these through the generic indexer-based fallback.
    /// </summary>
    /// <remarks>
    /// Returns false for the Conv2D bias pattern <c>[B, C, H, W] op [1, C, 1, 1]</c>
    /// because the broadcast is across the middle of the shape, not the trailing
    /// suffix — that case has its own dedicated fast path elsewhere.
    /// </remarks>
    private static bool TryBroadcastTrailingRepeat<T>(Tensor<T> a, Tensor<T> b, out int tileSize)
    {
        tileSize = 0;
        if (!a.IsContiguous || !b.IsContiguous) return false;
        if (b.Rank == 0 || a.Rank < b.Rank) return false;
        if (b.Length == 0 || a.Length % b.Length != 0) return false;

        // Determine the longest trailing suffix of b whose dims are all > 1 and
        // exactly match a's corresponding trailing dims — this is the "inner"
        // tile that gets repeated across the outer dims. All b dims to the left
        // of that suffix must be 1 (those are the broadcast axes). Any a dim on
        // the left is arbitrary — it contributes to the tile count.
        //
        // Example shapes that succeed:
        //   a=[B, S, H], b=[1, 1, H]          → tile = H        (DiT AdaLN)
        //   a=[B, S, H], b=[H]                → tile = H        (rank-dropped bias)
        //   a=[N, M],    b=[1, M]             → tile = M        (dense bias)
        //   a=[B, H, W], b=[1, H, W]          → tile = H*W      (per-sample feature)
        // Rejected (needs a different fast path or the general fallback):
        //   a=[B, C, H, W], b=[1, C, 1, 1]    (broadcast in middle — Conv bias)
        int aRank = a.Rank;
        int bRank = b.Rank;
        int offset = aRank - bRank;

        // Walk b's dims right-to-left, find where the trailing "all-matching"
        // suffix ends (i.e. first index from the left where b dim != a dim).
        int splitPoint = bRank;
        for (int i = bRank - 1; i >= 0; i--)
        {
            if (b._shape[i] == a._shape[offset + i])
            {
                splitPoint = i;
            }
            else
            {
                break;
            }
        }

        // All dims in b to the left of splitPoint must be 1 (broadcast axes).
        for (int i = 0; i < splitPoint; i++)
        {
            if (b._shape[i] != 1) return false;
        }

        // Compute tile size = product of trailing matching dims.
        int ts = 1;
        for (int i = splitPoint; i < bRank; i++) ts *= b._shape[i];
        if (ts == 0 || ts != b.Length) return false;

        // Tile must tile a.Length evenly (should follow from the structural
        // check, but guard anyway against zero-dim edge cases).
        if (a.Length % ts != 0) return false;

        tileSize = ts;
        return true;
    }

    /// <inheritdoc/>
    public void TensorBroadcastAddInPlace<T>(Tensor<T> a, Tensor<T> b)
    {
        if (a == null) throw new ArgumentNullException(nameof(a));
        if (b == null) throw new ArgumentNullException(nameof(b));
        var aOrig = a;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!a.IsContiguous) a = a.Contiguous();
        var bOrig = b;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!b.IsContiguous) b = b.Contiguous();

        var numOps = MathHelper.GetNumericOperations<T>();
        var aSpan = a.Data.Span;
        var bSpan = b.Data.Span;

        // Fast path: same shape — no broadcasting needed
        if (ShapesMatch(a._shape, b._shape))
        {
            for (int i = 0; i < aSpan.Length; i++)
                aSpan[i] = numOps.Add(aSpan[i], bSpan[i]);
            return;
        }

        // Conv bias pattern: a=[B,C,H,W], b=[1,C,1,1] — most common case
        if (a.Rank == 4 && b.Rank == 4 &&
            b._shape[0] == 1 && b._shape[2] == 1 && b._shape[3] == 1 &&
            a._shape[1] == b._shape[1])
        {
            int batch = a._shape[0];
            int channels = a._shape[1];
            int spatial = a._shape[2] * a._shape[3];

            for (int n = 0; n < batch; n++)
            {
                for (int c = 0; c < channels; c++)
                {
                    T biasVal = bSpan[c];
                    int offset = (n * channels + c) * spatial;
                    for (int s = 0; s < spatial; s++)
                    {
                        aSpan[offset + s] = numOps.Add(aSpan[offset + s], biasVal);
                    }
                }
            }
            return;
        }

        // Scalar broadcast: b has 1 element
        if (b.Length == 1)
        {
            T scalar = bSpan[0];
            for (int i = 0; i < aSpan.Length; i++)
                aSpan[i] = numOps.Add(aSpan[i], scalar);
            return;
        }

        // 1D bias along last dimension: a=[..., N], b=[N]
        if (b.Rank == 1 && a._shape[^1] == b._shape[0])
        {
            int lastDim = b._shape[0];
            int outerSize = a.Length / lastDim;
            for (int outer = 0; outer < outerSize; outer++)
            {
                int offset = outer * lastDim;
                for (int i = 0; i < lastDim; i++)
                    aSpan[offset + i] = numOps.Add(aSpan[offset + i], bSpan[i]);
            }
            return;
        }

        // General fallback: compute broadcast result and copy back.
        // This allocates a temporary — acceptable for rare arbitrary broadcast shapes.
        var result = TensorBroadcastAdd(a, b);
        result.Data.Span.CopyTo(aSpan);
    }

    /// <inheritdoc/>
    public void GroupNormInto<T>(Tensor<T> output, Tensor<T> input, int numGroups, Tensor<T> gamma, Tensor<T> beta, double epsilon, out Tensor<T> mean, out Tensor<T> variance)
    {
        if (!output.IsContiguous) throw new InvalidOperationException("Output tensor must be contiguous.");
        var inputOrig = input;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!input.IsContiguous) input = input.Contiguous();
        var gammaOrig = gamma;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!gamma.IsContiguous) gamma = gamma.Contiguous();
        var betaOrig = beta;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!beta.IsContiguous) beta = beta.Contiguous();
        // GroupNorm writes normalized values into pre-allocated output.
        // The mean/variance stats are small tensors [batch, numGroups] that the callee allocates.
        // The main output tensor avoids allocation since it's pre-allocated by the caller.
        var result = GroupNorm(input, numGroups, gamma, beta, epsilon, out mean, out variance);
        result.Data.Span.CopyTo(output.Data.Span);
    }

    /// <inheritdoc/>
    public void GroupNormSwishInto<T>(Tensor<T> output, Tensor<T> input, int numGroups, Tensor<T> gamma, Tensor<T> beta, double epsilon)
    {
        if (!output.IsContiguous) throw new InvalidOperationException("Output tensor must be contiguous.");
        var inputOrig = input;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!input.IsContiguous) input = input.Contiguous();
        var gammaOrig = gamma;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!gamma.IsContiguous) gamma = gamma.Contiguous();
        var betaOrig = beta;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!beta.IsContiguous) beta = beta.Contiguous();
        // Step 1: GroupNorm into output (single computation)
        GroupNormInto(output, input, numGroups, gamma, beta, epsilon, out _, out _);

        // Step 2: Swish in-place on the normalized output
        // swish(x) = x * sigmoid(x) — needs a temp buffer for sigmoid values
        SwishInPlace(output);
    }

    /// <inheritdoc/>
    public void AddGroupNormInto<T>(Tensor<T> output, Tensor<T> a, Tensor<T> b, int numGroups, Tensor<T> gamma, Tensor<T> beta, double epsilon)
    {
        if (!output.IsContiguous) throw new InvalidOperationException("Output tensor must be contiguous.");
        var aOrig = a;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!a.IsContiguous) a = a.Contiguous();
        var bOrig = b;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!b.IsContiguous) b = b.Contiguous();
        var gammaOrig = gamma;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!gamma.IsContiguous) gamma = gamma.Contiguous();
        var betaOrig = beta;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!beta.IsContiguous) beta = beta.Contiguous();
        // output = GroupNorm(a + b)
        // Step 1: Add a + b directly into output (zero alloc)
        var numOps = MathHelper.GetNumericOperations<T>();
        numOps.Add(a.AsSpan(), b.AsSpan(), output.AsWritableSpan());
        // Step 2: GroupNorm in-place on output via GroupNormInto
        GroupNormInto(output, output, numGroups, gamma, beta, epsilon, out _, out _);
    }

    /// <inheritdoc/>
    public void SwishInPlace<T>(Tensor<T> tensor)
    {
        var tensorOrig = tensor;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!tensor.IsContiguous) tensor = tensor.Contiguous();
