                var src = tensor._storage.GetDataArray(); var dst = r.GetDataArray();
                var idx = new int[tensor.Length]; tensor.FillStorageIndices(idx);
                for (int i = 0; i < tensor.Length; i++) { T v = src[idx[i]]; T negV = ops2.Negate(v); T sig = ops2.Divide(ops2.One, ops2.Add(ops2.One, ops2.Exp(negV))); dst[i] = ops2.Multiply(v, sig); }
                DifferentiableOps.RecordUnary("Swish", r, tensor, BackwardFunctions<T>.SwishBackward);
                { var c = tensor; AutoTracer.RecordOp("Swish", r, eng => eng.Swish(c)); }
                return r;
            }
            tensor = tensor.Contiguous();
        }

        var result = AutoTensorCache.RentOrAllocate<T>(tensor._shape);

        if (typeof(T) == typeof(float))
        {
            var srcMem = AsFloatMemory(tensor.Data);
            var dstMem = AsFloatMemory(result.Data);
            using var pinSrc = srcMem.Pin();
            using var pinDst = dstMem.Pin();
            unsafe
            {
                float* pSrc = (float*)pinSrc.Pointer;
                float* pDst = (float*)pinDst.Pointer;
                // Fused swish: sigmoid(x) * x in two SIMD passes
                SimdKernels.SigmoidUnsafe(pSrc, pDst, tensor.Length);
                SimdKernels.VectorMultiplyUnsafe(pSrc, pDst, pDst, tensor.Length);
            }
        }
        else
        {
            var numOps = MathHelper.GetNumericOperations<T>();
            numOps.Swish(tensor.AsSpan(), result.AsWritableSpan());
        }

        DifferentiableOps.RecordUnary("Swish", result, tensor, BackwardFunctions<T>.SwishBackward);
        { var c = tensor; AutoTracer.RecordOp("Swish", result, eng => eng.Swish(c)); }
        return result;
    }

    public virtual Tensor<T> ELU<T>(Tensor<T> tensor, double alpha = 1.0)
    {
        if (GraphMode.IsActive)
        { var ac = AutoTracer.TryGetCompiledPlan<T>("ELU", tensor._shape, paramHash: alpha.GetHashCode()); if (ac is not null) return ac.Execute(); }

        {
            var scope = GraphMode.Current;
            if (scope != null)
            {
                var captured = tensor;
                double capturedAlpha = alpha;
                return scope.RecordUnary(LazyNodeType.ELU, "ELU", tensor, tensor._shape,
                    (eng, output) =>
                    {
                        if (eng is CpuEngine cpuEng) cpuEng.ELUInto(output, captured, capturedAlpha);
                        else { var r = eng.ELU(captured, capturedAlpha); r.AsSpan().CopyTo(output.AsWritableSpan()); }
                    },
                    BackwardFunctions<T>.ELUBackward, new object[] { alpha });
            }
        }

        if (!tensor.IsContiguous)
        {
            if (tensor.Length <= 4096)
            {
                var ops2 = MathHelper.GetNumericOperations<T>();
                var r = AutoTensorCache.RentOrAllocate<T>(tensor._shape);
                var src = tensor._storage.GetDataArray(); var dst = r.GetDataArray();
                var idx = new int[tensor.Length]; tensor.FillStorageIndices(idx);
                T alphaT = ops2.FromDouble(alpha);
                for (int i = 0; i < tensor.Length; i++)
                {
                    T v = src[idx[i]];
                    dst[i] = ops2.GreaterThan(v, ops2.Zero) ? v : ops2.Multiply(alphaT, ops2.Subtract(ops2.Exp(v), ops2.One));
                }
                DifferentiableOps.RecordUnary("ELU", r, tensor, BackwardFunctions<T>.ELUBackward, new object[] { alpha });
                { var c = tensor; double al = alpha; AutoTracer.RecordOp("ELU", r, eng => eng.ELU(c, al), paramHash: al.GetHashCode()); }
                return r;
            }
            tensor = tensor.Contiguous();
        }
        if (tensor == null)
            throw new ArgumentNullException(nameof(tensor));

        var result = AutoTensorCache.RentOrAllocate<T>(tensor._shape);

        if (typeof(T) == typeof(float))
        {
            unsafe
            {
                var srcMem = AsFloatMemory(tensor.Data);
                var dstMem = AsFloatMemory(result.Data);
                using var pinSrc = srcMem.Pin();
                using var pinDst = dstMem.Pin();
                SimdKernels.ELUUnsafe((float*)pinSrc.Pointer, (float*)pinDst.Pointer, tensor.Length, (float)alpha);
            }
        }
        else
        {
            var numOps = MathHelper.GetNumericOperations<T>();
            numOps.ELU(tensor.AsSpan(), numOps.FromDouble(alpha), result.AsWritableSpan());
        }

        DifferentiableOps.RecordUnary("ELU", result, tensor, BackwardFunctions<T>.ELUBackward, new object[] { alpha });
        { var c = tensor; double al = alpha; AutoTracer.RecordOp("ELU", result, eng => eng.ELU(c, al), paramHash: al.GetHashCode()); }
        return result;
    }

    /// <summary>ELU into pre-allocated destination. Uses AVX SIMD for float.</summary>
    public unsafe void ELUInto<T>(Tensor<T> destination, Tensor<T> input, double alpha = 1.0)
    {
        if (!destination.IsContiguous) throw new InvalidOperationException("Output tensor must be contiguous.");
        var inputOrig = input;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!input.IsContiguous) input = input.Contiguous();
        if (typeof(T) == typeof(float))
        {
            var srcMem = AsFloatMemory(input.Data);
            var dstMem = AsFloatMemory(destination.Data);
            using var pinSrc = srcMem.Pin();
            using var pinDst = dstMem.Pin();
            SimdKernels.ELUUnsafe((float*)pinSrc.Pointer, (float*)pinDst.Pointer, input.Length, (float)alpha);
            return;
        }
        var numOps = MathHelper.GetNumericOperations<T>();
        numOps.ELU(input.AsSpan(), numOps.FromDouble(alpha), destination.AsWritableSpan());
    }

    /// <inheritdoc/>
    public virtual unsafe Tensor<T> LeakyReLU<T>(Tensor<T> tensor, T alpha)
    {
        if (GraphMode.IsActive)
        {
            var scope = GraphMode.Current;
            if (scope != null)
            {
                var captured = tensor;
                var capturedAlpha = alpha;
                return scope.RecordUnary(LazyNodeType.LeakyReLU, "LeakyReLU", tensor, tensor._shape,
                    (eng, output) => eng.LeakyReLUInto(output, captured, capturedAlpha),
                    BackwardFunctions<T>.LeakyReLUBackward, new object[] { MathHelper.GetNumericOperations<T>().ToDouble(alpha) });
            }
        }

        { long ph = alpha is null ? 0L : alpha.GetHashCode(); var ac = AutoTracer.TryGetCompiledPlan<T>("LeakyReLU", tensor._shape, paramHash: ph); if (ac is not null) return ac.Execute(); }

        if (!tensor.IsContiguous)
        {
            if (tensor.Length <= 4096)
            {
                var ops2 = MathHelper.GetNumericOperations<T>();
                var r = AutoTensorCache.RentOrAllocate<T>(tensor._shape);
                var src = tensor._storage.GetDataArray(); var dst = r.GetDataArray();
                var idx = new int[tensor.Length]; tensor.FillStorageIndices(idx);
                for (int i = 0; i < tensor.Length; i++)
                {
                    T v = src[idx[i]];
                    dst[i] = ops2.GreaterThan(v, ops2.Zero) ? v : ops2.Multiply(alpha, v);
                }
                DifferentiableOps.RecordUnary("LeakyReLU", r, tensor, BackwardFunctions<T>.LeakyReLUBackward, new object[] { MathHelper.GetNumericOperations<T>().ToDouble(alpha) });
                { var c = tensor; var a = alpha; AutoTracer.RecordOp("LeakyReLU", r, eng => eng.LeakyReLU(c, a), paramHash: a is null ? 0L : a.GetHashCode()); }
                return r;
            }
            tensor = tensor.Contiguous();
        }
        if (tensor == null)
            throw new ArgumentNullException(nameof(tensor));

        var result = AutoTensorCache.RentOrAllocate<T>(tensor._shape);
        var negSlope = MathHelper.GetNumericOperations<T>().ToDouble(alpha);

        if (typeof(T) == typeof(float))
        {
            float alphaF = System.Runtime.CompilerServices.Unsafe.As<T, float>(ref alpha);
            var srcMem = AsFloatMemory(tensor.Data);
            var dstMem = AsFloatMemory(result.Data);
            using var pinSrc = srcMem.Pin();
            using var pinDst = dstMem.Pin();
            float* pSrc = (float*)pinSrc.Pointer;
            float* pDst = (float*)pinDst.Pointer;
            int len = tensor.Length;
            const int parallelThreshold = 256 * 1024;
            int maxThreads = CpuParallelSettings.MaxDegreeOfParallelism;
            int chunks = Math.Min(maxThreads, Math.Max(1, len / parallelThreshold));
            if (chunks >= 2)
            {
                int chunkSize = (len + chunks - 1) / chunks;
                chunkSize = (chunkSize + 31) & ~31;
                IntPtr pIn = (IntPtr)pSrc;
                IntPtr pOut = (IntPtr)pDst;
                Parallel.For(0, chunks, chunk =>
                {
                    int start = chunk * chunkSize;
                    int count = Math.Min(chunkSize, len - start);
                    if (count > 0)
                        SimdKernels.LeakyReLUUnsafe((float*)pIn + start, (float*)pOut + start, count, alphaF);
                });
            }
            else
            {
                SimdKernels.LeakyReLUUnsafe(pSrc, pDst, len, alphaF);
            }
        }
        else
        {
            var numOps = MathHelper.GetNumericOperations<T>();
            numOps.LeakyReLU(tensor.AsSpan(), alpha, result.AsWritableSpan());
        }

        DifferentiableOps.RecordUnary("LeakyReLU", result, tensor, BackwardFunctions<T>.LeakyReLUBackward, new object[] { negSlope });
        { var c = tensor; var a = alpha; AutoTracer.RecordOp("LeakyReLU", result, eng => eng.LeakyReLU(c, a), paramHash: a is null ? 0L : a.GetHashCode()); }
        return result;
    }

    /// <summary>
    /// Gated Linear Unit: GLU(a, b) = a * sigmoid(b)
    /// Splits input in half along specified dimension and applies sigmoid gating.
    /// From "Language Modeling with Gated Convolutional Networks" (Dauphin et al., 2017)
    /// </summary>
    public Tensor<T> GLU<T>(Tensor<T> input, int dim = -1)
    {
        if (input == null)
            throw new ArgumentNullException(nameof(input));

        var numOps = MathHelper.GetNumericOperations<T>();

        // Handle negative dimension
        int actualDim = dim < 0 ? input.Rank + dim : dim;
        if (actualDim < 0 || actualDim >= input.Rank)
            throw new ArgumentException($"Invalid dimension {dim} for tensor with rank {input.Rank}");

        if (GraphMode.IsActive)
        {
            var scope = GraphMode.Current;
            if (scope != null)
            {
                var captured = input;
                int capDim = dim;
                var outShape = input.Shape.ToArray();
                outShape[actualDim] = input._shape[actualDim] / 2;
                return scope.RecordUnary(LazyNodeType.Custom, "GLU", input, outShape,
                    (eng, output) => { var r = eng.GLU(captured, capDim); r.AsSpan().CopyTo(output.AsWritableSpan()); },
                    BackwardFunctions<T>.GLUBackward, new object[] { actualDim });
            }
        }

        { var ac = AutoTracer.TryGetCompiledPlan<T>("GLU", input._shape); if (ac is not null) return ac.Execute(); }

        int dimSize = input._shape[actualDim];
        if (dimSize % 2 != 0)
            throw new ArgumentException($"Dimension {actualDim} must have even size for GLU, got {dimSize}");

        int halfSize = dimSize / 2;

        // Calculate output shape
        var outputShape = input.Shape.ToArray();
        outputShape[actualDim] = halfSize;

        var inputData = input.GetFlattenedData();
        var outputData = new T[input.Length / 2];

        // Calculate strides for the dimension
        int innerSize = 1;
        for (int i = actualDim + 1; i < input.Rank; i++)
            innerSize *= input._shape[i];

        int outerSize = 1;
        for (int i = 0; i < actualDim; i++)
            outerSize *= input._shape[i];

        // Apply GLU: output = a * sigmoid(b)
        Parallel.For(0, outerSize, outer =>
        {
            for (int h = 0; h < halfSize; h++)
            {
                for (int inner = 0; inner < innerSize; inner++)
                {
                    int aIdx = outer * dimSize * innerSize + h * innerSize + inner;
                    int bIdx = outer * dimSize * innerSize + (h + halfSize) * innerSize + inner;
                    int outIdx = outer * halfSize * innerSize + h * innerSize + inner;

                    T a = inputData[aIdx];
                    T b = inputData[bIdx];
                    T sigmoid_b = numOps.Divide(numOps.One, numOps.Add(numOps.One, numOps.Exp(numOps.Negate(b))));
                    outputData[outIdx] = numOps.Multiply(a, sigmoid_b);
                }
            }
        });

        var result = TensorAllocator.Rent<T>(outputShape, new Vector<T>(outputData));
        DifferentiableOps.RecordUnary("GLU", result, input, BackwardFunctions<T>.GLUBackward, new object[] { actualDim });
        AutoTracer.RecordOp("GLU", result, eng => result);
        return result;
    }

    /// <summary>
    /// GLU backward pass.
    /// </summary>
    public Tensor<T> GLUBackward<T>(Tensor<T> gradOutput, Tensor<T> input, int dim = -1)
    {
        if (gradOutput == null)
            throw new ArgumentNullException(nameof(gradOutput));
        if (input == null)
            throw new ArgumentNullException(nameof(input));
        var inputOrig = input;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!input.IsContiguous) input = input.Contiguous();

        var numOps = MathHelper.GetNumericOperations<T>();

        int actualDim = dim < 0 ? input.Rank + dim : dim;
        int dimSize = input._shape[actualDim];
        int halfSize = dimSize / 2;

        var inputData = input.GetFlattenedData();
        var gradOutData = gradOutput.GetFlattenedData();
        var gradInputData = new T[input.Length];

        int innerSize = 1;
        for (int i = actualDim + 1; i < input.Rank; i++)
            innerSize *= input._shape[i];

        int outerSize = 1;
        for (int i = 0; i < actualDim; i++)
            outerSize *= input._shape[i];

        // Gradient: d/da = sigmoid(b) * gradOut, d/db = a * sigmoid(b) * (1 - sigmoid(b)) * gradOut
        Parallel.For(0, outerSize, outer =>
        {
            for (int h = 0; h < halfSize; h++)
            {
                for (int inner = 0; inner < innerSize; inner++)
                {
                    int aIdx = outer * dimSize * innerSize + h * innerSize + inner;
                    int bIdx = outer * dimSize * innerSize + (h + halfSize) * innerSize + inner;
                    int outIdx = outer * halfSize * innerSize + h * innerSize + inner;

                    T a = inputData[aIdx];
                    T b = inputData[bIdx];
                    T gradOut = gradOutData[outIdx];

                    T sigmoid_b = numOps.Divide(numOps.One, numOps.Add(numOps.One, numOps.Exp(numOps.Negate(b))));
                    T one_minus_sigmoid = numOps.Subtract(numOps.One, sigmoid_b);

                    gradInputData[aIdx] = numOps.Multiply(sigmoid_b, gradOut);
                    gradInputData[bIdx] = numOps.Multiply(numOps.Multiply(numOps.Multiply(a, sigmoid_b), one_minus_sigmoid), gradOut);
                }
            }
        });

        return TensorAllocator.Rent<T>(input._shape, new Vector<T>(gradInputData));
    }

    /// <summary>
    /// GeGLU: Gaussian Error Gated Linear Unit.
    /// GeGLU(a, b) = a * GELU(b)
    /// From "GLU Variants Improve Transformer" (Shazeer, 2020)
    /// </summary>
    public Tensor<T> GeGLU<T>(Tensor<T> input, int dim = -1)
    {
        if (input == null)
            throw new ArgumentNullException(nameof(input));

        var numOps = MathHelper.GetNumericOperations<T>();

        int actualDim = dim < 0 ? input.Rank + dim : dim;
        if (actualDim < 0 || actualDim >= input.Rank)
            throw new ArgumentException($"Invalid dimension {dim} for tensor with rank {input.Rank}");

        int dimSize = input._shape[actualDim];
        if (dimSize % 2 != 0)
            throw new ArgumentException($"Dimension {actualDim} must have even size for GeGLU, got {dimSize}");

        int halfSize = dimSize / 2;

        var outputShape = input.Shape.ToArray();
        outputShape[actualDim] = halfSize;

        var inputData = input.GetFlattenedData();
        var outputData = new T[input.Length / 2];

        int innerSize = 1;
        for (int i = actualDim + 1; i < input.Rank; i++)
            innerSize *= input._shape[i];

        int outerSize = 1;
        for (int i = 0; i < actualDim; i++)
            outerSize *= input._shape[i];

        // GELU approximation: 0.5 * x * (1 + tanh(sqrt(2/pi) * (x + 0.044715 * x^3)))
        double sqrtTwoOverPi = Math.Sqrt(2.0 / Math.PI);

        Parallel.For(0, outerSize, outer =>
        {
            for (int h = 0; h < halfSize; h++)
            {
                for (int inner = 0; inner < innerSize; inner++)
                {
                    int aIdx = outer * dimSize * innerSize + h * innerSize + inner;
                    int bIdx = outer * dimSize * innerSize + (h + halfSize) * innerSize + inner;
                    int outIdx = outer * halfSize * innerSize + h * innerSize + inner;

                    T a = inputData[aIdx];
                    T b = inputData[bIdx];

                    // GELU(b)
                    double bVal = numOps.ToDouble(b);
                    double gelu = 0.5 * bVal * (1.0 + Math.Tanh(sqrtTwoOverPi * (bVal + 0.044715 * bVal * bVal * bVal)));
                    outputData[outIdx] = numOps.Multiply(a, numOps.FromDouble(gelu));
                }
            }
        });

        var result = TensorAllocator.Rent<T>(outputShape, new Vector<T>(outputData));
        DifferentiableOps.RecordUnary("GeGLU", result, input, BackwardFunctions<T>.GeGLUBackward,
            new object[] { actualDim });
        return result;
    }

    /// <summary>
    /// GeGLU backward pass.
    /// </summary>
    public Tensor<T> GeGLUBackward<T>(Tensor<T> gradOutput, Tensor<T> input, int dim = -1)
    {
        if (gradOutput == null)
            throw new ArgumentNullException(nameof(gradOutput));
        if (input == null)
            throw new ArgumentNullException(nameof(input));
        var inputOrig = input;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!input.IsContiguous) input = input.Contiguous();

        var numOps = MathHelper.GetNumericOperations<T>();

        int actualDim = dim < 0 ? input.Rank + dim : dim;
        int dimSize = input._shape[actualDim];
        int halfSize = dimSize / 2;

        var inputData = input.GetFlattenedData();
        var gradOutData = gradOutput.GetFlattenedData();
        var gradInputData = new T[input.Length];

        int innerSize = 1;
        for (int i = actualDim + 1; i < input.Rank; i++)
            innerSize *= input._shape[i];

        int outerSize = 1;
        for (int i = 0; i < actualDim; i++)
            outerSize *= input._shape[i];

        double sqrtTwoOverPi = Math.Sqrt(2.0 / Math.PI);

        Parallel.For(0, outerSize, outer =>
        {
            for (int h = 0; h < halfSize; h++)
            {
                for (int inner = 0; inner < innerSize; inner++)
                {
                    int aIdx = outer * dimSize * innerSize + h * innerSize + inner;
                    int bIdx = outer * dimSize * innerSize + (h + halfSize) * innerSize + inner;
                    int outIdx = outer * halfSize * innerSize + h * innerSize + inner;

                    T a = inputData[aIdx];
                    T b = inputData[bIdx];
                    T gradOut = gradOutData[outIdx];

                    double bVal = numOps.ToDouble(b);
                    double aVal = numOps.ToDouble(a);
                    double gradOutVal = numOps.ToDouble(gradOut);

                    // GELU and its derivative
                    double inner_val = sqrtTwoOverPi * (bVal + 0.044715 * bVal * bVal * bVal);
                    double tanh_val = Math.Tanh(inner_val);
                    double gelu = 0.5 * bVal * (1.0 + tanh_val);
                    double sech2 = 1.0 - tanh_val * tanh_val;
                    double gelu_deriv = 0.5 * (1.0 + tanh_val) + 0.5 * bVal * sech2 * sqrtTwoOverPi * (1.0 + 3.0 * 0.044715 * bVal * bVal);

                    gradInputData[aIdx] = numOps.FromDouble(gelu * gradOutVal);
                    gradInputData[bIdx] = numOps.FromDouble(aVal * gelu_deriv * gradOutVal);
                }
            }
        });

        return TensorAllocator.Rent<T>(input._shape, new Vector<T>(gradInputData));
    }

    /// <summary>
    /// SwiGLU: Swish-Gated Linear Unit.
    /// SwiGLU(a, b) = a * Swish(b) where Swish(x) = x * sigmoid(x)
    /// From "GLU Variants Improve Transformer" (Shazeer, 2020)
    /// Used in LLaMA, PaLM, and other modern transformers.
    /// </summary>
    public Tensor<T> SwiGLU<T>(Tensor<T> input, int dim = -1)
    {
        if (input == null)
            throw new ArgumentNullException(nameof(input));

        var numOps = MathHelper.GetNumericOperations<T>();

        int actualDim = dim < 0 ? input.Rank + dim : dim;
        if (actualDim < 0 || actualDim >= input.Rank)
            throw new ArgumentException($"Invalid dimension {dim} for tensor with rank {input.Rank}");

        int dimSize = input._shape[actualDim];
        if (dimSize % 2 != 0)
            throw new ArgumentException($"Dimension {actualDim} must have even size for SwiGLU, got {dimSize}");

        int halfSize = dimSize / 2;

        var outputShape = input.Shape.ToArray();
        outputShape[actualDim] = halfSize;

        var inputData = input.GetFlattenedData();
        var outputData = new T[input.Length / 2];

        int innerSize = 1;
        for (int i = actualDim + 1; i < input.Rank; i++)
            innerSize *= input._shape[i];

        int outerSize = 1;
        for (int i = 0; i < actualDim; i++)
            outerSize *= input._shape[i];

        // SwiGLU: a * (b * sigmoid(b))
        Parallel.For(0, outerSize, outer =>
        {
            for (int h = 0; h < halfSize; h++)
            {
                for (int inner = 0; inner < innerSize; inner++)
                {
                    int aIdx = outer * dimSize * innerSize + h * innerSize + inner;
                    int bIdx = outer * dimSize * innerSize + (h + halfSize) * innerSize + inner;
                    int outIdx = outer * halfSize * innerSize + h * innerSize + inner;

                    T a = inputData[aIdx];
                    T b = inputData[bIdx];

                    // Swish(b) = b * sigmoid(b)
                    T sigmoid_b = numOps.Divide(numOps.One, numOps.Add(numOps.One, numOps.Exp(numOps.Negate(b))));
                    T swish_b = numOps.Multiply(b, sigmoid_b);
                    outputData[outIdx] = numOps.Multiply(a, swish_b);
                }
            }
        });

        var result = TensorAllocator.Rent<T>(outputShape, new Vector<T>(outputData));
        DifferentiableOps.RecordUnary("SwiGLU", result, input, BackwardFunctions<T>.SwiGLUBackward,
            new object[] { actualDim });
        return result;
    }

    /// <summary>
    /// SwiGLU backward pass.
    /// </summary>
    public Tensor<T> SwiGLUBackward<T>(Tensor<T> gradOutput, Tensor<T> input, int dim = -1)
    {
        if (gradOutput == null)
            throw new ArgumentNullException(nameof(gradOutput));
        if (input == null)
            throw new ArgumentNullException(nameof(input));
        var inputOrig = input;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!input.IsContiguous) input = input.Contiguous();

        var numOps = MathHelper.GetNumericOperations<T>();

        int actualDim = dim < 0 ? input.Rank + dim : dim;
        int dimSize = input._shape[actualDim];
        int halfSize = dimSize / 2;

        var inputData = input.GetFlattenedData();
        var gradOutData = gradOutput.GetFlattenedData();
        var gradInputData = new T[input.Length];

        int innerSize = 1;
        for (int i = actualDim + 1; i < input.Rank; i++)
            innerSize *= input._shape[i];

        int outerSize = 1;
        for (int i = 0; i < actualDim; i++)
            outerSize *= input._shape[i];

        // d/da = Swish(b) * gradOut
        // d/db = a * d_Swish(b) * gradOut where d_Swish(b) = sigmoid(b) + b * sigmoid(b) * (1 - sigmoid(b))
        Parallel.For(0, outerSize, outer =>
        {
            for (int h = 0; h < halfSize; h++)
            {
                for (int inner = 0; inner < innerSize; inner++)
                {
                    int aIdx = outer * dimSize * innerSize + h * innerSize + inner;
                    int bIdx = outer * dimSize * innerSize + (h + halfSize) * innerSize + inner;
                    int outIdx = outer * halfSize * innerSize + h * innerSize + inner;

                    T a = inputData[aIdx];
                    T b = inputData[bIdx];
                    T gradOut = gradOutData[outIdx];

                    T sigmoid_b = numOps.Divide(numOps.One, numOps.Add(numOps.One, numOps.Exp(numOps.Negate(b))));
                    T swish_b = numOps.Multiply(b, sigmoid_b);
                    T one_minus_sigmoid = numOps.Subtract(numOps.One, sigmoid_b);
                    T swish_deriv = numOps.Add(sigmoid_b, numOps.Multiply(numOps.Multiply(b, sigmoid_b), one_minus_sigmoid));

                    gradInputData[aIdx] = numOps.Multiply(swish_b, gradOut);
                    gradInputData[bIdx] = numOps.Multiply(numOps.Multiply(a, swish_deriv), gradOut);
                }
            }
        });

        return TensorAllocator.Rent<T>(input._shape, new Vector<T>(gradInputData));
    }

    /// <summary>
    /// ReGLU: ReLU-Gated Linear Unit.
    /// ReGLU(a, b) = a * ReLU(b)
    /// From "GLU Variants Improve Transformer" (Shazeer, 2020)
    /// </summary>
    public Tensor<T> ReGLU<T>(Tensor<T> input, int dim = -1)
    {
        if (input == null)
            throw new ArgumentNullException(nameof(input));

        var numOps = MathHelper.GetNumericOperations<T>();

        int actualDim = dim < 0 ? input.Rank + dim : dim;
        if (actualDim < 0 || actualDim >= input.Rank)
            throw new ArgumentException($"Invalid dimension {dim} for tensor with rank {input.Rank}");

        int dimSize = input._shape[actualDim];
        if (dimSize % 2 != 0)
            throw new ArgumentException($"Dimension {actualDim} must have even size for ReGLU, got {dimSize}");

        int halfSize = dimSize / 2;

        var outputShape = input.Shape.ToArray();
        outputShape[actualDim] = halfSize;

        var inputData = input.GetFlattenedData();
        var outputData = new T[input.Length / 2];

        int innerSize = 1;
        for (int i = actualDim + 1; i < input.Rank; i++)
            innerSize *= input._shape[i];

        int outerSize = 1;
        for (int i = 0; i < actualDim; i++)
            outerSize *= input._shape[i];

        // ReGLU: a * ReLU(b) = a * max(0, b)
        Parallel.For(0, outerSize, outer =>
        {
            for (int h = 0; h < halfSize; h++)
            {
                for (int inner = 0; inner < innerSize; inner++)
                {
                    int aIdx = outer * dimSize * innerSize + h * innerSize + inner;
                    int bIdx = outer * dimSize * innerSize + (h + halfSize) * innerSize + inner;
                    int outIdx = outer * halfSize * innerSize + h * innerSize + inner;

                    T a = inputData[aIdx];
                    T b = inputData[bIdx];

                    // ReLU(b) = max(0, b)
                    T relu_b = numOps.GreaterThan(b, numOps.Zero) ? b : numOps.Zero;
                    outputData[outIdx] = numOps.Multiply(a, relu_b);
                }
            }
        });

        var result = TensorAllocator.Rent<T>(outputShape, new Vector<T>(outputData));
        DifferentiableOps.RecordUnary("ReGLU", result, input, BackwardFunctions<T>.ReGLUBackward,
            new object[] { actualDim });
        return result;
    }

    /// <summary>
    /// ReGLU backward pass.
    /// </summary>
    public Tensor<T> ReGLUBackward<T>(Tensor<T> gradOutput, Tensor<T> input, int dim = -1)
    {
        if (gradOutput == null)
            throw new ArgumentNullException(nameof(gradOutput));
        if (input == null)
            throw new ArgumentNullException(nameof(input));
        var inputOrig = input;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!input.IsContiguous) input = input.Contiguous();

        var numOps = MathHelper.GetNumericOperations<T>();

        int actualDim = dim < 0 ? input.Rank + dim : dim;
        int dimSize = input._shape[actualDim];
        int halfSize = dimSize / 2;

        var inputData = input.GetFlattenedData();
        var gradOutData = gradOutput.GetFlattenedData();
        var gradInputData = new T[input.Length];

        int innerSize = 1;
        for (int i = actualDim + 1; i < input.Rank; i++)
            innerSize *= input._shape[i];

        int outerSize = 1;
        for (int i = 0; i < actualDim; i++)
            outerSize *= input._shape[i];

        // d/da = ReLU(b) * gradOut
        // d/db = a * (b > 0 ? 1 : 0) * gradOut
        Parallel.For(0, outerSize, outer =>
        {
            for (int h = 0; h < halfSize; h++)
            {
                for (int inner = 0; inner < innerSize; inner++)
                {
                    int aIdx = outer * dimSize * innerSize + h * innerSize + inner;
                    int bIdx = outer * dimSize * innerSize + (h + halfSize) * innerSize + inner;
                    int outIdx = outer * halfSize * innerSize + h * innerSize + inner;

                    T a = inputData[aIdx];
                    T b = inputData[bIdx];
                    T gradOut = gradOutData[outIdx];

                    T relu_b = numOps.GreaterThan(b, numOps.Zero) ? b : numOps.Zero;
                    T relu_deriv = numOps.GreaterThan(b, numOps.Zero) ? numOps.One : numOps.Zero;

                    gradInputData[aIdx] = numOps.Multiply(relu_b, gradOut);
                    gradInputData[bIdx] = numOps.Multiply(numOps.Multiply(a, relu_deriv), gradOut);
                }
            }
        });

        return TensorAllocator.Rent<T>(input._shape, new Vector<T>(gradInputData));
    }


    #endregion

    #region Extended Tensor Operations

    /// <inheritdoc/>
    public virtual Tensor<T> TensorTranspose<T>(Tensor<T> tensor)
    {
        if (tensor == null) throw new ArgumentNullException(nameof(tensor));
        if (tensor.Rank != 2)
            throw new ArgumentException($"TensorTranspose requires a 2D tensor. Got rank {tensor.Rank}.");

        // Lazy graph mode: record and return placeholder
        if (GraphMode.IsActive)
        { var ac = AutoTracer.TryGetCompiledPlan<T>("TensorTranspose", tensor._shape); if (ac is not null) return ac.Execute(); }

        {
            var scope = GraphMode.Current;
            if (scope != null)
            {
                int rows0 = tensor._shape[0];
                int cols0 = tensor._shape[1];
                var captured = tensor;
                return scope.RecordUnary(LazyNodeType.Transpose, "TensorTranspose", tensor, new[] { cols0, rows0 },
                    (eng, output) =>
                    {
                        // TensorTranspose returns a view — need to materialize contiguous data into the output buffer
                        var transposed = eng.TensorTranspose(captured);
                        var data = transposed.ToArray();
                        data.AsSpan().CopyTo(output.AsWritableSpan());
                    },
                    BackwardFunctions<T>.TransposeBackward);
            }
        }

        // Return a contiguous transposed copy for API compatibility.
        // The lazy graph path uses a more efficient execute delegate.
        var view = tensor.Transpose();
        var result = view.Contiguous();
        DifferentiableOps.RecordUnary("TensorTranspose", result, tensor, BackwardFunctions<T>.TransposeBackward);
        { var c = tensor; AutoTracer.RecordOp("TensorTranspose", result, eng => eng.TensorTranspose(c)); }
        return result;
    }

    /// <inheritdoc/>
    public virtual Tensor<T> TensorMatMulTransposed<T>(Tensor<T> a, Tensor<T> b)
    {
        if (a is null) throw new ArgumentNullException(nameof(a));
        if (b is null) throw new ArgumentNullException(nameof(b));
        if (a.Rank < 2 || b.Rank < 2)
            throw new ArgumentException("TensorMatMulTransposed requires rank >= 2 for both operands.");
        // a: [..., M, K], b stored as [..., N, K] (rows are the K dim).
        int M = a._shape[a.Rank - 2];
        int K = a._shape[a.Rank - 1];
        int N = b._shape[b.Rank - 2];
        int Kb = b._shape[b.Rank - 1];
        if (K != Kb)
            throw new ArgumentException(
                $"TensorMatMulTransposed K mismatch: a's trailing dim {K} != b's trailing dim {Kb}.");

        // Output shape mirrors TensorMatMul(a, b^T): [..., M, N].
        var outShape = new int[a.Rank];
        for (int d = 0; d < a.Rank - 2; d++) outShape[d] = a._shape[d];
        outShape[a.Rank - 2] = M;
        outShape[a.Rank - 1] = N;

        // Float fast path via SimdGemm.Sgemm with transB=true. Skips the
        // ~70%-of-the-time-spent-on-the-transpose materialization that the
        // user-pattern Transpose(B) + MatMul(A, B^T) was hitting.
        if (typeof(T) == typeof(float) && a.Rank == 2 && b.Rank == 2 && a.IsContiguous && b.IsContiguous)
        {
            var result = AutoTensorCache.RentOrAllocate<T>(outShape);
            // Use the storage + storageOffset directly. AutoTensorCache /
            // pooled tensors back themselves with arrays that may be larger
            // than Length (capacity headroom from ArrayPool buckets), so
            // GetDataArray() returns the BUCKET-sized array — slicing with
            // (0, M*K) on a contiguous-but-offset tensor would index wrong.
            // The _storageOffset is 0 for non-view tensors but the explicit
            // pin keeps the contract clean for any future view caller.
            var aRaw = (float[])(object)a._storage.GetDataArray();
            var bRaw = (float[])(object)b._storage.GetDataArray();
            var rRaw = (float[])(object)result._storage.GetDataArray();
            int aOff = a._storageOffset, bOff = b._storageOffset, rOff = result._storageOffset;
            // Sgemm(a, lda, transA, b, ldb, transB, c, m, k, n).
            // a is [M,K] row-major (lda=K, transA=false). b is stored
            // [N,K] row-major (lda for b = K, transB=true so the kernel
            // treats it as Kᵀ-major and contracts over K).
            AiDotNet.Tensors.Engines.Simd.SimdGemm.Sgemm(
                new ReadOnlySpan<float>(aRaw, aOff, M * K),
                lda: K, transA: false,
                new ReadOnlySpan<float>(bRaw, bOff, N * K),
                ldb: K, transB: true,
                new Span<float>(rRaw, rOff, M * N),
                M, K, N);
            // Register the transpose-aware backward — the standard
            // MatMulBackward assumes C = A·B and emits wrong gradients
            // for the C = A·Bᵀ contract this method computes.
            DifferentiableOps.RecordBinary("TensorMatMulTransposed", result, a, b, BackwardFunctions<T>.MatMulTransposedBackward);
            return result;
        }

        // Generic fallback: materialize the transpose and call TensorMatMul.
        // Slower than the fast path but correct for all dtypes / non-2D shapes.
        var bT = TensorTranspose(b);
        return TensorMatMul(a, bT);
    }

    /// <inheritdoc/>
    #if !NETFRAMEWORK
    [MethodImpl(MethodImplOptions.AggressiveOptimization)]
#endif
    public virtual Tensor<T> TensorMatMul<T>(Tensor<T> a, Tensor<T> b)
    {
        // OpScope is no-op + zero-alloc when no profiler is active (#220).
        using var _opScope = AiDotNet.Tensors.Engines.Profiling.Profiler.OpScope("TensorMatMul");
        if (a == null) throw new ArgumentNullException(nameof(a));
        if (b == null) throw new ArgumentNullException(nameof(b));
        if (a.Rank < 2) throw new ArgumentException($"TensorMatMul requires tensors of rank >= 2. Got rank {a.Rank} for first tensor.");
        if (b.Rank < 2) throw new ArgumentException($"TensorMatMul requires tensors of rank >= 2. Got rank {b.Rank} for second tensor.");

        // Lazy graph mode: record and return placeholder
        if (GraphMode.IsActive)
        {
            var outShape = ComputeMatMulOutputShape(a._shape, b._shape);
            var scope = GraphMode.Current;
            if (scope != null)
            {
                var capturedA = a;
                var capturedB = b;
                return scope.RecordBinary(LazyNodeType.MatMul, "TensorMatMul", a, b, outShape,
                    // Path C: write-through. BERT has 72 MatMul calls per
                    // layer, each allocating + copying its output (786 KB
                    // to 9 MB depending on shape). Eliminating the CopyTo
                    // saves ~12 ms of aggregate redundant memory traffic
                    // per BERT inference. TensorMatMulInto dispatches the
                    // 2D/ND×2D/ND×ND cases to write-through kernels.
                    (eng, output) =>
                    {
                        if (typeof(T) == typeof(float) && eng is CpuEngine cpuEng)
                        {
                            cpuEng.TensorMatMulFloatInto(
                                (Tensor<float>)(object)capturedA,
                                (Tensor<float>)(object)capturedB,
                                (Tensor<float>)(object)output);
                        }
                        else
                        {
                            var eager = eng.TensorMatMul(capturedA, capturedB);
                            eager.AsSpan().CopyTo(output.AsWritableSpan());
                        }
                    },
                    BackwardFunctions<T>.MatMulBackward);
            }
        }

        // Auto-tracer: check if a compiled plan exists for this op pattern
        { var matMulOutShape = ComputeMatMulOutputShape(a._shape, b._shape);
          var autoCompiled = AutoTracer.TryGetCompiledPlan<T>("TensorMatMul", matMulOutShape);
          if (autoCompiled is not null) return autoCompiled.Execute(); }

        // Preserve the caller's original tensor references for tape recording.
        // Permute returns a strided view; the .Contiguous() rebind below would
        // otherwise replace the user's GradFn-bearing reference with a fresh
        // tensor that has no GradFn — breaking the topo-walk chain back to the
        // upstream parameter (#257). Math kernels still consume the contiguous
        // copies; only the recorded inputs change.
        var aOrig = a;
        var bOrig = b;
        if (!a.IsContiguous) a = a.Contiguous();
        if (!b.IsContiguous) b = b.Contiguous();

        var numOps = MathHelper.GetNumericOperations<T>();

        Tensor<T> result;

        // Standard 2D x 2D case
        if (a.Rank == 2 && b.Rank == 2)
        {
            result = TensorMatMul2D(a, b, numOps);
        }
        // ND x 2D case: broadcast 2D weights over batch dimensions
        // This is the common transformer pattern: [batch, seq, features] @ [features, output]
        else if (b.Rank == 2)
        {
            result = TensorMatMulBatched(a, b, numOps);
        }
        // 3D x 3D or ND x ND: full batched matmul (batch dimensions must match)
        else if (a.Rank == b.Rank)
        {
            result = TensorMatMulFullBatched(a, b, numOps);
        }
        else
        {
            throw new ArgumentException($"Unsupported TensorMatMul combination: ranks {a.Rank} and {b.Rank}. Supported: 2Dx2D, NDx2D, NDxND (same rank).");
        }

        DifferentiableOps.RecordBinary("TensorMatMul", result, aOrig, bOrig, BackwardFunctions<T>.MatMulBackward);

        // Auto-tracer: record this op for future compilation
        { var ca = a; var cb = b; AutoTracer.RecordOp("TensorMatMul", result, eng => eng.TensorMatMul(ca, cb)); }

        return result;
    }

    /// <summary>
    /// Write-through TensorMatMul for float: writes directly into the provided
    /// <paramref name="output"/> tensor, skipping the intermediate allocation
    /// + <c>CopyTo</c> that the public <see cref="TensorMatMul{T}"/> routes
    /// through when called from a compiled plan step. Used by the Path C
    /// plan-step lambda (captured in GraphMode-active LazyGraph recording).
    ///
    /// <para>Dispatch mirrors <see cref="TensorMatMul{T}"/>:</para>
    /// <list type="bullet">
    ///   <item>2D×2D: SGEMM directly into output (uses MatMulInto semantics)</item>
    ///   <item>ND×2D: collapse to 2D GEMM [batch*m, k]×[k,n], single SGEMM</item>
    ///   <item>ND×ND (same rank): parallel loop over batches, Sgemm/SgemmSequential</item>
    /// </list>
    /// </summary>
    /// <summary>
    /// Write-through BatchMatMul for float. BERT attention's
    /// (Q @ K^T) and (attn @ V) go through this 24× per inference.
    /// Same dispatch semantics as TensorMatMulFloatInto — in fact for
    /// rank-3+ same-rank inputs the two are behaviourally identical,
    /// so we just delegate.
    /// </summary>
    internal void BatchMatMulFloatInto(Tensor<float> a, Tensor<float> b, Tensor<float> output)
    {
        TensorMatMulFloatInto(a, b, output);
    }

    internal void TensorMatMulFloatInto(Tensor<float> a, Tensor<float> b, Tensor<float> output)
    {
        var aOrig = a;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!a.IsContiguous) a = a.Contiguous();
        var bOrig = b;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!b.IsContiguous) b = b.Contiguous();

        var aArr = a.GetDataArray();
        var bArr = b.GetDataArray();
        var oArr = output.GetDataArray();

        // 2D × 2D — route through cached-B path (Path A: pre-pack weights)
        if (a.Rank == 2 && b.Rank == 2)
        {
            int m = a._shape[0], k = a._shape[1], n = b._shape[1];
            Simd.SimdGemm.SgemmWithCachedB(
                new System.ReadOnlySpan<float>(aArr, 0, m * k),
                bArr,
                new System.Span<float>(oArr, 0, m * n),
                m, k, n);
            return;
        }

        // ND × 2D: collapse batch dims into m (mirrors TensorMatMulBatched fast path)
        // Also routes through cached-B — B is the constant weight across all
        // batch items and across all forward calls.
        if (b.Rank == 2)
        {
            int aRank = a.Rank;
            int m = a._shape[aRank - 2];
            int k = a._shape[aRank - 1];
            int n = b._shape[1];
            int batchSize = 1;
            for (int i = 0; i < aRank - 2; i++) batchSize *= a._shape[i];
            Simd.SimdGemm.SgemmWithCachedB(
                new System.ReadOnlySpan<float>(aArr, 0, batchSize * m * k),
                bArr,
                new System.Span<float>(oArr, 0, batchSize * m * n),
                batchSize * m, k, n);
            return;
        }

        // ND × ND (same rank): parallel per-batch SGEMM (mirrors
        // TensorMatMulFullBatched's float fast path + BatchMatMul's
        // batchSize-aware dispatch: batch=1 → Sgemm, batch≥2 → Parallel+Sequential)
        if (a.Rank == b.Rank)
        {
            int rank = a.Rank;
            int m = a._shape[rank - 2];
            int k = a._shape[rank - 1];
            int n = b._shape[rank - 1];
            int batchSize = 1;
            for (int i = 0; i < rank - 2; i++) batchSize *= a._shape[i];
            int sliceA = m * k, sliceB = k * n, sliceC = m * n;
            if (batchSize == 1)
            {
                Simd.SimdGemm.Sgemm(
                    new System.ReadOnlySpan<float>(aArr, 0, sliceA),
                    new System.ReadOnlySpan<float>(bArr, 0, sliceB),
                    new System.Span<float>(oArr, 0, sliceC),
                    m, k, n);
            }
            else
            {
                Parallel.For(0, batchSize, batch =>
                {
                    Simd.SimdGemm.SgemmSequential(
                        new System.ReadOnlySpan<float>(aArr, batch * sliceA, sliceA),
                        new System.ReadOnlySpan<float>(bArr, batch * sliceB, sliceB),
                        new System.Span<float>(oArr, batch * sliceC, sliceC),
                        m, k, n);
                });
            }
            return;
        }

        throw new ArgumentException(
            $"TensorMatMulFloatInto: unsupported rank combination {a.Rank} and {b.Rank}");
    }

    private static int[] ComputeBroadcastShape(int[] shape1, int[] shape2)
    {
        int maxRank = Math.Max(shape1.Length, shape2.Length);
        var result = new int[maxRank];
        for (int i = 0; i < maxRank; i++)
        {
            int dim1 = i < shape1.Length ? shape1[shape1.Length - 1 - i] : 1;
            int dim2 = i < shape2.Length ? shape2[shape2.Length - 1 - i] : 1;
            if (dim1 != dim2 && dim1 != 1 && dim2 != 1)
                throw new ArgumentException($"Shapes are not broadcast-compatible at dimension {maxRank - 1 - i}: {dim1} vs {dim2}");
            result[maxRank - 1 - i] = Math.Max(dim1, dim2);
        }
        return result;
    }

    /// <summary>Eagerly computes the output shape of a matmul without executing it.</summary>
    private static int[] ComputeMatMulOutputShape(int[] aShape, int[] bShape)
    {
        int aRank = aShape.Length;
        int bRank = bShape.Length;
        if (aRank == 2 && bRank == 2)
            return new[] { aShape[0], bShape[1] };
        if (bRank == 2)
        {
            // ND x 2D: batch dims from a, last dim from b
            var shape = new int[aRank];
            Array.Copy(aShape, shape, aRank - 1);
            shape[aRank - 1] = bShape[1];
            return shape;
        }
        // ND x ND: same batch dims, matmul last two
        var outShape = new int[aRank];
        Array.Copy(aShape, outShape, aRank - 2);
        outShape[aRank - 2] = aShape[aRank - 2];
        outShape[aRank - 1] = bShape[bRank - 1];
        return outShape;
    }

    /// <summary>
    /// Standard 2D matrix multiplication: [M, N] @ [N, P] = [M, P]
    /// Uses BLAS when available for float/double, falls back to parallel loops otherwise.
    /// </summary>
    #if !NETFRAMEWORK
    [MethodImpl(MethodImplOptions.AggressiveOptimization)]
#endif
    private Tensor<T> TensorMatMul2D<T>(Tensor<T> a, Tensor<T> b, INumericOperations<T> numOps)
    {
        int m = a._shape[0];
        int n = a._shape[1];
        int p = b._shape[1];

        if (n != b._shape[0])
            throw new ArgumentException($"Matrix dimensions incompatible: [{m},{n}] x [{b._shape[0]},{p}]");

        // RentUninitialized: BLAS GEMM with beta=0 overwrites every element
        var result = AutoTensorCache.RentOrAllocate<T>(new[] { m, p });

        // Try BLAS-accelerated path for float/double tensors
        if (MatrixMultiplyHelper.TryGemm(a.Data, 0, b.Data, 0, result.Data, 0, m, n, p))
        {
            return result;
        }

        // Fallback when TryGemm declines (non-float/double, below BLAS threshold,
        // or — critically — Tensor<double> on every shape because BlasProvider is
        // disabled and SimdGemm only ships an Sgemm path). Route through
        // MatrixMultiplyHelper.MultiplyBlocked, which uses numOps.MultiplyAdd as
        // its inner kernel. For Tensor<double>, that dispatches to
        // SimdKernels.ScalarMultiplyAdd's AVX2/FMA Vector256<double> kernel —
        // 50–100× faster than the naive Parallel.For triple-loop on AVX2 hosts.
        // For other T, MultiplyBlocked still beats the naive loop via cache
        // tiling + the numOps.MultiplyAdd virtual call's per-span amortization.
        // MatrixMultiplyHelper.MultiplyBlocked accumulates (c += a·b) and does
        // NOT clear the destination. Pre-clear result here so the accumulation
        // starts from zero and we get matmul (c = a·b), not c += a·b.
        result.AsWritableSpan().Clear();
        MatrixMultiplyHelper.MultiplyBlocked(numOps, a.Data, b.Data, result.Data, m, n, p, n, p, p);

        return result;
    }

    /// <summary>
    /// Batched matmul: [..., M, N] @ [N, P] = [..., M, P]
    /// Weights (b) are broadcasted over all batch dimensions of a.
    /// </summary>
    #if !NETFRAMEWORK
    [MethodImpl(MethodImplOptions.AggressiveOptimization)]
#endif
    private Tensor<T> TensorMatMulBatched<T>(Tensor<T> a, Tensor<T> b, INumericOperations<T> numOps)
    {
        int aRank = a.Rank;
        int m = a._shape[aRank - 2];  // Second to last dim
        int n = a._shape[aRank - 1];  // Last dim
        int p = b._shape[1];          // Output features

        if (n != b._shape[0])
            throw new ArgumentException($"Matrix dimensions incompatible for batched matmul: last dim of a is {n}, first dim of b is {b._shape[0]}");

        // Calculate batch size (product of all dimensions except last 2)
        int batchSize = 1;
        var batchShape = new int[aRank - 2];
        for (int i = 0; i < aRank - 2; i++)
        {
            batchSize *= a._shape[i];
            batchShape[i] = a._shape[i];
        }

        // Output shape: [...batch dims..., m, p]
        var outputShape = new int[aRank];
        for (int i = 0; i < aRank - 2; i++)
        {
            outputShape[i] = a._shape[i];
        }
        outputShape[aRank - 2] = m;
        outputShape[aRank - 1] = p;

        var result = AutoTensorCache.RentOrAllocate<T>(outputShape);

        int matrixSizeA = m * n;
        int matrixSizeResult = m * p;

        var aData = a.GetDataArray();
        var bData = b.GetDataArray();
        var rData = result.GetDataArray();

        // Iter 24 (batched-GEMM consolidation): for the ND×2D broadcast pattern, B is
        // SHARED across all batch slices and A is stored row-major contiguous, so the
        // whole batched matmul collapses to a single 2D GEMM of shape
        // [batchSize*m, n] × [n, p] = [batchSize*m, p]. This eliminates the per-slice
        // BLAS dispatch overhead (2-3 µs per call × batchSize) and lets MKL pack B
        // once instead of N times. The Phase 0 baseline measured the per-slice
        // dispatch cost via Batched 3D [4,256,1152]×[1152,4608] which was 1.75× slower
        // than MKL's equivalent 2D matmul — this consolidation should close most of
        // that gap.
        //
        // Requires BOTH A and B to be contiguous (tightly packed row-major).
        // MatrixMultiplyHelper.TryGemm assumes row-major with leading dims k
        // and n respectively; a transposed or sliced B would be read with the
        // wrong stride and produce silently incorrect results. The caller in
        // TensorMatMul ensures A is contiguous via a.Contiguous(); we guard
        // B here since it may be a shared weight matrix passed directly.
        if (a.IsContiguous && b.IsContiguous && MatrixMultiplyHelper.TryGemm(
            a.Data, 0, b.Data, 0, result.Data, 0,
            batchSize * m, n, p))
        {
            return result;
        }

        // Fallback: per-slice dispatch (preserves behavior for non-contiguous A or
        // when the big GEMM declines — e.g. non-float/double T, or work below the
        // BLAS threshold where per-slice dispatch can actually win).
        Parallel.For(0, batchSize, batch =>
        {
            int aOffset = batch * matrixSizeA;
            int resultOffset = batch * matrixSizeResult;

            // Try BLAS for each batch slice
            if (MatrixMultiplyHelper.TryGemm(a.Data, aOffset, b.Data, 0, result.Data, resultOffset, m, n, p))
            {
                return;
            }

            // SIMD-blocked fallback (see TensorMatMul2D for rationale). Pre-zero
            // the slice since MultiplyBlocked accumulates. allowParallel:false
            // because we're already inside a Parallel.For over batch — letting
            // MultiplyBlocked spawn a second tier would oversubscribe.
            result.Data.Span.Slice(resultOffset, matrixSizeResult).Clear();
            MatrixMultiplyHelper.MultiplyBlocked(
                numOps, a.Data, b.Data, result.Data,
                m, n, p, n, p, p,
                aOffset: aOffset, bOffset: 0, cOffset: resultOffset,
                allowParallel: false);
        });

        return result;
    }

    /// <summary>
    /// Full batched matmul: [..., M, N] @ [..., N, P] = [..., M, P]
    /// Batch dimensions must match.
    /// </summary>
    #if !NETFRAMEWORK
    [MethodImpl(MethodImplOptions.AggressiveOptimization)]
#endif
    private Tensor<T> TensorMatMulFullBatched<T>(Tensor<T> a, Tensor<T> b, INumericOperations<T> numOps)
    {
        int rank = a.Rank;
        int m = a._shape[rank - 2];
        int n = a._shape[rank - 1];
        int p = b._shape[rank - 1];

        if (n != b._shape[rank - 2])
            throw new ArgumentException($"Matrix dimensions incompatible for batched matmul: [{m},{n}] x [{b._shape[rank - 2]},{p}]");

        // Verify batch dimensions match
        for (int i = 0; i < rank - 2; i++)
        {
            if (a._shape[i] != b._shape[i])
                throw new ArgumentException($"Batch dimensions must match. Got {a._shape[i]} vs {b._shape[i]} at dimension {i}");
        }

        // Calculate batch size
        int batchSize = 1;
        for (int i = 0; i < rank - 2; i++)
        {
            batchSize *= a._shape[i];
        }

        // Output shape
        var outputShape = new int[rank];
        for (int i = 0; i < rank - 2; i++)
        {
            outputShape[i] = a._shape[i];
        }
        outputShape[rank - 2] = m;
        outputShape[rank - 1] = p;

        var result = AutoTensorCache.RentOrAllocate<T>(outputShape);

        int matrixSizeA = m * n;
        int matrixSizeB = n * p;
        int matrixSizeResult = m * p;

        var aData = a.GetDataArray();
        var bData = b.GetDataArray();
        var rData = result.GetDataArray();

        // Phase 2D BERT-attention fix: for float, bypass
        // MatrixMultiplyHelper.TryGemm's per-slice validation + memory
        // conversion overhead and call SimdGemm.SgemmSequential directly.
        //
        // BatchMatMulRootCauseDiag showed this saves ~40 µs per slice
        // (×12 slices on BERT attention = ~480 µs total), taking the
        // attn-scores [12,256,64]×[12,64,256] call from 920 µs → 441 µs
        // and attn×V [12,256,256]×[12,256,64] from 588 µs → 474 µs.
        // SgemmSequential (not Sgemm) is the right SGEMM variant here —
        // we're already inside Parallel.For, so letting the inner SGEMM
        // also spawn a Parallel.For would nest workers over the thread
        // pool. In practice the nested case measured equivalent for
        // BERT-scale slices (SGEMM's internal work threshold isn't hit),
        // but SgemmSequential is the documented correct pattern.
        if (typeof(T) == typeof(float))
        {
            var aF = (float[])(object)aData;
            var bF = (float[])(object)bData;
            var rF = (float[])(object)rData;

            Parallel.For(0, batchSize, batch =>
            {
                int aOffset = batch * matrixSizeA;
                int bOffset = batch * matrixSizeB;
                int resultOffset = batch * matrixSizeResult;

                Simd.SimdGemm.SgemmSequential(
                    aF.AsSpan(aOffset, matrixSizeA),
                    bF.AsSpan(bOffset, matrixSizeB),
                    rF.AsSpan(resultOffset, matrixSizeResult),
                    m, n, p);
            });

            return result;
        }

        Parallel.For(0, batchSize, batch =>
        {
            int aOffset = batch * matrixSizeA;
            int bOffset = batch * matrixSizeB;
            int resultOffset = batch * matrixSizeResult;

            // Try BLAS for each batch slice
            if (MatrixMultiplyHelper.TryGemm(a.Data, aOffset, b.Data, bOffset, result.Data, resultOffset, m, n, p))
            {
                return;
            }

            // SIMD-blocked fallback (see TensorMatMul2D for rationale). Pre-zero
            // the slice since MultiplyBlocked accumulates. allowParallel:false
            // because we're already inside a Parallel.For over batch.
            result.Data.Span.Slice(resultOffset, matrixSizeResult).Clear();
            MatrixMultiplyHelper.MultiplyBlocked(
                numOps, a.Data, b.Data, result.Data,
                m, n, p, n, p, p,
                aOffset: aOffset, bOffset: bOffset, cOffset: resultOffset,
                allowParallel: false);
        });

        return result;
    }

    /// <summary>
    /// Write-through Conv2D (int[] overload): runs the same dispatch as the
    /// public <see cref="Conv2D{T}(Tensor{T}, Tensor{T}, int[], int[], int[])"/>
    /// but writes directly into a pre-allocated <paramref name="output"/>
    /// tensor instead of renting a fresh one. Used by compiled plan steps to
    /// skip the intermediate allocation + CopyTo that would otherwise burn
    /// ~50 µs per call on ResNet conv shapes.
    /// </summary>
    public void Conv2DInto<T>(Tensor<T> output, Tensor<T> input, Tensor<T> kernel, int[] stride, int[] padding, int[] dilation)
    {
        if (output == null) throw new ArgumentNullException(nameof(output));
        Conv2DIntoImpl(input, kernel, stride, padding, dilation, output);
    }

    /// <inheritdoc/>
    public Tensor<T> Conv2D<T>(Tensor<T> input, Tensor<T> kernel, int[] stride, int[] padding, int[] dilation)
    {
        using var _opScope = AiDotNet.Tensors.Engines.Profiling.Profiler.OpScope("Conv2D");
        return Conv2DIntoImpl<T>(input, kernel, stride, padding, dilation, preAllocatedOutput: null);
    }

    /// <summary>
    /// Shared implementation. When <paramref name="preAllocatedOutput"/> is
    /// null, allocates a fresh result via TensorAllocator.Rent. Otherwise
    /// writes into the provided tensor (path used by Conv2DInto).
    /// </summary>
    private Tensor<T> Conv2DIntoImpl<T>(Tensor<T> input, Tensor<T> kernel, int[] stride, int[] padding, int[] dilation, Tensor<T>? preAllocatedOutput)
    {
        if (input == null) throw new ArgumentNullException(nameof(input));
        if (kernel == null) throw new ArgumentNullException(nameof(kernel));
        // Preserve original input ref for tape recording (#257) — see TensorMatMul.
        var inputOrig = input;
        if (!input.IsContiguous) input = input.Contiguous();
        if (input.Rank != 4) throw new ArgumentException($"Conv2D requires 4D input tensor. Got rank {input.Rank}.", nameof(input));
        if (kernel.Rank != 4) throw new ArgumentException($"Conv2D requires 4D kernel tensor. Got rank {kernel.Rank}.", nameof(kernel));
        if (stride == null || stride.Length != 2) throw new ArgumentException("Stride must be array of 2 elements", nameof(stride));
        if (stride[0] <= 0 || stride[1] <= 0) throw new ArgumentException("Stride elements must be positive", nameof(stride));
        if (padding == null || padding.Length != 2) throw new ArgumentException("Padding must be array of 2 elements", nameof(padding));
        if (dilation == null || dilation.Length != 2) throw new ArgumentException("Dilation must be array of 2 elements", nameof(dilation));
        if (dilation[0] <= 0 || dilation[1] <= 0) throw new ArgumentException("Dilation elements must be positive", nameof(dilation));
        if (input._shape[1] != kernel._shape[1]) throw new ArgumentException($"Input channels ({input._shape[1]}) must match kernel in_channels ({kernel._shape[1]})");

        int strideH = stride[0], strideW = stride[1];
        int padH = padding[0], padW = padding[1];
        int dilationH = dilation[0], dilationW = dilation[1];

        var numOps = MathHelper.GetNumericOperations<T>();

        int batch = input._shape[0];
        int inChannels = input._shape[1];
        int height = input._shape[2];
        int width = input._shape[3];

        int outChannels = kernel._shape[0];
        int kernelHeight = kernel._shape[2];
        int kernelWidth = kernel._shape[3];

        int effectiveKernelH = dilationH * (kernelHeight - 1) + 1;
        int effectiveKernelW = dilationW * (kernelWidth - 1) + 1;

        int outputHeight = (height + 2 * padH - effectiveKernelH) / strideH + 1;
        int outputWidth = (width + 2 * padW - effectiveKernelW) / strideW + 1;

        if (outputHeight <= 0 || outputWidth <= 0)
            throw new ArgumentException($"Invalid output dimensions ({outputHeight}x{outputWidth}). Check kernel size, stride, padding, and dilation parameters.");

        // Lazy graph mode: record and return placeholder. Only when invoked
        // as the allocating Conv2D — write-through Conv2DInto skips this
        // because it already has the output to write into.
        if (preAllocatedOutput is null && GraphMode.IsActive)
        {
            var scope = GraphMode.Current;
            if (scope != null)
            {
                var outShape = new[] { batch, outChannels, outputHeight, outputWidth };
                var capturedInput = input;
                var capturedKernel = kernel;
                var capturedStride = stride;
                var capturedPad = padding;
                var capturedDil = dilation;
                return scope.RecordBinary(LazyNodeType.Conv2D, "Conv2D", input, kernel, outShape,
                    (eng, output) =>
                    {
                        // Path C write-through for Conv2D via the int[] overload.
                        // Routes through Conv2DInto(int[]) so the dispatch stays
                        // on the fast int[] NCHWc / im2col+Sgemm path without
                        // allocating an intermediate tensor.
                        if (eng is CpuEngine cpuEng)
                            cpuEng.Conv2DInto(output, capturedInput, capturedKernel, capturedStride, capturedPad, capturedDil);
                        else { var eager = eng.Conv2D(capturedInput, capturedKernel, capturedStride, capturedPad, capturedDil); eager.AsSpan().CopyTo(output.AsWritableSpan()); }
                    },
                    BackwardFunctions<T>.Conv2DBackward, new object[] { stride, padding, dilation });
            }
        }

        var result = preAllocatedOutput ?? TensorAllocator.Rent<T>([batch, outChannels, outputHeight, outputWidth]);
        var inputData = input.GetDataArray();
        var kernelData = kernel.GetDataArray();
        var outputData = result.GetDataArray();

        // NCHWc fast path: when the caller pre-reordered input + kernel into
        // channel-packed layout (input.Layout == Nchwc8 and kernel's
        // first-axis group is divisible by 8), route through the direct
        // NCHWc conv kernel. Each lane broadcasts one input channel and
        // FMAs against the matching 8-wide kernel row — this is the path
        // ORT/oneDNN use to get close to peak FMA throughput on AVX2.
        // NCHWc16 (AVX-512) fast path — preferred when the runtime has
        // Avx512F and the shapes are aligned to cBlock=16. Double the FMA
        // throughput per cycle vs the cb=8 Vector256 kernel.
        if (typeof(T) == typeof(float) &&
            input.Layout == LinearAlgebra.TensorLayout.Nchwc16 &&
            inChannels % Simd.NchwcConv2D16.CBlock == 0 &&
            outChannels % Simd.NchwcConv2D16.CBlock == 0)
        {
            int kernelLen16 = outChannels * inChannels * kernelHeight * kernelWidth;
            var packedKernel16 = new float[kernelLen16];
            Simd.NchwcReorder.KernelToOihwIo(
                (float[])(object)kernelData,
                packedKernel16,
                outChannels, inChannels, kernelHeight, kernelWidth,
                Simd.NchwcConv2D16.CBlock);
            Simd.NchwcConv2D16.Run(
                (float[])(object)inputData,
                packedKernel16,
                (float[])(object)outputData,
                batch, inChannels, height, width,
                outChannels, kernelHeight, kernelWidth,
                outputHeight, outputWidth,
                strideH, strideW, padH, padW, dilationH, dilationW);
            result.Layout = LinearAlgebra.TensorLayout.Nchwc16;
            DifferentiableOps.RecordBinary("Conv2D", result, inputOrig, kernel, BackwardFunctions<T>.Conv2DBackward,
                new object[] { stride, padding, dilation });
            AutoTracer.RecordOp("Conv2D", result, eng => result);
            return result;
        }

        if (typeof(T) == typeof(float) &&
            input.Layout == LinearAlgebra.TensorLayout.Nchwc8 &&
            inChannels % Simd.NchwcConv2D.CBlock == 0 &&
            outChannels % Simd.NchwcConv2D.CBlock == 0)
        {
            // Kernel must be in OIHWio packed form. Detect via a conservative
            // shape check: if it's stored flat with length outC * inC * kH * kW
            // we reorder on-the-fly. The proper ConvBn-NCHWc fusion path
            // will pre-reorder the kernel into a constant initializer.
            int kernelLen = outChannels * inChannels * kernelHeight * kernelWidth;
            var packedKernel = new float[kernelLen];
            Simd.NchwcReorder.KernelToOihwIo(
                (float[])(object)kernelData,
                packedKernel,
                outChannels, inChannels, kernelHeight, kernelWidth,
                Simd.NchwcConv2D.CBlock);
            Simd.NchwcConv2D.Run(
                (float[])(object)inputData,
                packedKernel,
                (float[])(object)outputData,
                batch, inChannels, height, width,
                outChannels, kernelHeight, kernelWidth,
                outputHeight, outputWidth,
                strideH, strideW, padH, padW, dilationH, dilationW);
            result.Layout = LinearAlgebra.TensorLayout.Nchwc8;
            DifferentiableOps.RecordBinary("Conv2D", result, inputOrig, kernel, BackwardFunctions<T>.Conv2DBackward,
                new object[] { stride, padding, dilation });
            AutoTracer.RecordOp("Conv2D", result, eng => result);
            return result;
        }

        // Fast path: im2col + SimdGemm for float tensors. The naive nested-
        // loop kernel below is O(batch × outC × outH × outW × inC × kH × kW)
        // of scalar multiplies — NO vectorization, NO cache blocking. Real
        // conv runtimes (ORT/MKL/cuDNN) lower to GEMM-on-lowered-input for
        // exactly this reason: once the image is unfolded, the heavy compute
        // is a single [outC × K] @ [K × (oH·oW)] matmul that hits the tuned
        // BLAS path. This closes ~95% of the ResNet-50 gap vs ORT.
        if (typeof(T) == typeof(float))
        {
            // Packed layouts (Nchwc8 / Nchwc16) that fell through to this
            // fallback must be unpacked first — Conv2DIm2colGemm reads the
            // buffer assuming plain NCHW row-major indexing, so reading a
            // packed buffer would silently produce wrong outputs.
            if (input.Layout == LinearAlgebra.TensorLayout.Nchwc8 ||
                input.Layout == LinearAlgebra.TensorLayout.Nchwc16)
            {
                int cBlock = input.Layout == LinearAlgebra.TensorLayout.Nchwc16 ? 16 : 8;
                if (inChannels % cBlock != 0)
                    throw new NotSupportedException(
                        $"Conv2D fallback: packed {input.Layout} input with inChannels={inChannels} " +
                        $"not divisible by cBlock={cBlock} cannot be unpacked safely.");
                var unpackedData = new float[batch * inChannels * height * width];
                Simd.NchwcReorder.ToNchw(
                    ((float[])(object)inputData).AsSpan(), unpackedData.AsSpan(),
                    batch, inChannels, height, width, cBlock);
                inputData = (T[])(object)unpackedData;
            }
            Conv2DIm2colGemm(
                (float[])(object)inputData,
                (float[])(object)kernelData,
                (float[])(object)outputData,
                batch, inChannels, height, width,
                outChannels, kernelHeight, kernelWidth,
                outputHeight, outputWidth,
                strideH, strideW, padH, padW, dilationH, dilationW);
        }
        else
        {
            Parallel.For(0, batch * outChannels, idx =>
            {
                int b = idx / outChannels;
                int oc = idx % outChannels;

                for (int oh = 0; oh < outputHeight; oh++)
                {
                    for (int ow = 0; ow < outputWidth; ow++)
                    {
                        T sum = numOps.Zero;

                        for (int ic = 0; ic < inChannels; ic++)
                        {
                            for (int kh = 0; kh < kernelHeight; kh++)
                            {
                                for (int kw = 0; kw < kernelWidth; kw++)
                                {
                                    int ih = oh * strideH + kh * dilationH - padH;
                                    int iw = ow * strideW + kw * dilationW - padW;

                                    if (ih >= 0 && ih < height && iw >= 0 && iw < width)
                                    {
                                        int inputIdx = ((b * inChannels + ic) * height + ih) * width + iw;
                                        int kernelIdx = ((oc * inChannels + ic) * kernelHeight + kh) * kernelWidth + kw;
                                        sum = numOps.Add(sum, numOps.Multiply(inputData[inputIdx], kernelData[kernelIdx]));
                                    }
                                }
                            }
                        }

                        int outputIdx = ((b * outChannels + oc) * outputHeight + oh) * outputWidth + ow;
                        outputData[outputIdx] = sum;
                    }
                }
            });
        }

        DifferentiableOps.RecordBinary("Conv2D", result, inputOrig, kernel, BackwardFunctions<T>.Conv2DBackward,
            new object[] { stride, padding, dilation });
        AutoTracer.RecordOp("Conv2D", result, eng => result);
        return result;
    }

    // Per-kernel pre-transposed array cache for the small-N Conv fast path.
    // ConditionalWeakTable holds entries weakly by the kernel float[] reference
    // — they survive exactly as long as the kernel does. For inference on a
    // fixed ONNX model every Conv layer's kernel is stable, so the first call
    // populates the cache and every subsequent call reuses the transposed
    // buffer for ~0 µs. Multi-threaded callers are handled inside
    // ConditionalWeakTable.GetValue which is documented thread-safe.
    private static readonly System.Runtime.CompilerServices.ConditionalWeakTable<float[], float[]>
        _kernelTransposeCache = new();

    /// <summary>
    /// im2col + SGEMM float conv. Unfolds the input tensor into a matrix
    /// where each row is one receptive field's flattened patch, then runs a
    /// single blocked GEMM against the kernel-as-matrix layout. Closes the
    /// gap vs tuned conv runtimes that rely on the same lowering.
    /// </summary>
    private static void Conv2DIm2colGemm(
        float[] input, float[] kernel, float[] output,
        int batch, int inC, int H, int W,
        int outC, int kH, int kW,
        int oH, int oW,
        int sH, int sW, int padH, int padW, int dH, int dW)
    {
        int K = inC * kH * kW;         // im2col row length (kernel @ one patch).
        int N = oH * oW;               // patches per image.
        int kernelRowsPerPatch = K;
        // Kernel is already in [outC, inC, kH, kW] = [outC, K] row-major;
        // this IS the GEMM's A matrix layout (M=outC, K=K).
        // im2col builds B as [K, N] per-image so GEMM produces [outC, N].
        // We allocate one col buffer per image and reuse via a thread-local
        // pool to avoid per-batch allocations hot-path.
        //
        // Parallel-batch policy: we ONLY parallelize across the batch axis
        // for small per-image GEMMs. When the per-image GEMM is large enough
        // (>= 50M FLOPs per image), the inner SgemmBlocked already
        // parallelizes across K and saturates cores — adding an outer
        // Parallel.For would double-dip and waste threads. For small
        // per-image work, the inner GEMM can't usefully parallelize, so
        // batch-level parallelism is how we get thread-scaling.
        long perImageCost = (long)outC * K * N;
        bool parallelBatch = batch > 1 && perImageCost < 50_000_000L;

        void ProcessImage(int b)
        {
            // Rent a scratch col buffer of size [K, N] = K*N floats.
            var col = System.Buffers.ArrayPool<float>.Shared.Rent(K * N);
            try
            {
                // im2col: for each output position (oh, ow) and each kernel
                // cell (ic, kh, kw), write input[b, ic, ih, iw] (or 0 on
                // padding) to col[(ic*kH*kW + kh*kW + kw), oh*oW + ow].
                //
                // The outer ic loop is embarrassingly parallel — different
                // input channels write to disjoint col rows. For ResNet
                // stage1 (inC=64, col buffer 7.2 MB) the serial im2col was
                // ~3 ms = 2.4 GB/s, ~10× below RAM peak on a 16-core box.
                // Parallelising the ic loop distributes the memory-bound
                // copy across cores. Gate at inC × K × N ≥ 1 M to avoid
                // paying task-pool dispatch on small shapes (stage3/stage4
                // im2col is already sub-millisecond).
                long im2colOps = (long)inC * kH * kW * oH * oW;
                void CopyChannel(int ic)
                {
                    for (int kh = 0; kh < kH; kh++)
                    {
                        for (int kw = 0; kw < kW; kw++)
                        {
                            int rowBase = (ic * kH + kh) * kW + kw;
                            int rowOff = rowBase * N;
                            for (int oh = 0; oh < oH; oh++)
                            {
                                int ih = oh * sH + kh * dH - padH;
                                if ((uint)ih >= (uint)H)
                                {
                                    // Whole row padded — zero the block.
                                    int zeroStart = rowOff + oh * oW;
                                    Array.Clear(col, zeroStart, oW);
                                    continue;
                                }
                                int inputRowBase = ((b * inC + ic) * H + ih) * W;
                                int colRowStart = rowOff + oh * oW;
                                for (int ow = 0; ow < oW; ow++)
                                {
                                    int iw = ow * sW + kw * dW - padW;
                                    col[colRowStart + ow] = (uint)iw < (uint)W ? input[inputRowBase + iw] : 0f;
                                }
                            }
                        }
                    }
                }

                if (im2colOps >= 1_000_000L)
                {
                    Parallel.For(0, inC, CopyChannel);
                }
                else
                {
                    for (int ic = 0; ic < inC; ic++) CopyChannel(ic);
                }

                // Output slice for this image: [outC, oH*oW] starting at
                // (b * outC * N) in the packed NCHW output.
                int outOff = b * outC * N;
                var outSpan = output.AsSpan(outOff, outC * N);
                outSpan.Clear();

                // Phase 2C small-N fast path: when N (output patches)
                // is small and M (outC) is large, SimdGemm's standard
                // blocked kernel underperforms (stage4 1×512×7×7 3×3
                // conv = SGEMM[M=512, K=4608, N=49] hits only 18 GFLOPS
                // vs 100+ on balanced shapes). Diagnostic data from
                // Conv2DKernelSplitDiag showed the SAME FLOPs with
                // M↔N swapped runs at 116 GFLOPS — 6.4× faster.
                //
                // Fix: when the gate fires, explicitly transpose col and
                // kernel into the fast-shape layout, run SGEMM on
                // [N, K] × [K, M] → [N, M], then transpose back to
                // [M, N]. Rent transposed buffers from ArrayPool so we
                // don't churn the GC.
                //
                // Gate tuning: fires when N ≤ 128 AND M ≥ 128. Empirically
                // stage4 (N=49, M=512) hits the gate; stages 1-3 all have
                // N > 128 so they skip it (their direct SGEMM is fast).
                // The 1×1 ResNet bottleneck and BERT shapes all have
                // either N > 128 or M < 128, so they also skip.
                if (N <= 128 && outC >= 128)
                {
                    // col stored [K, N] → colT [N, K]
                    var colT = System.Buffers.ArrayPool<float>.Shared.Rent(N * K);
                    // output computed as [N, M], then transposed to [M, N]
                    var outT = System.Buffers.ArrayPool<float>.Shared.Rent(N * outC);
                    // Kernel pre-transpose cache: for a given input kernel
                    // float[] reference, keep a pre-transposed [K, M] copy.
                    // This is the "fast-forward transform" — moves the 2.4 MB
                    // kernel transpose (~1 ms even parallelised) out of the
                    // hot path. Kernel arrays are stable across Conv2D calls
                    // for the same model, so the cache hits for every call
                    // after the first. ConditionalWeakTable uses reference
                    // equality and collects entries when the kernel is GC'd.
                    float[] kernelT = GetOrBuildTransposedKernel(kernel, outC, K);
                    try
                    {
                        TransposeFloatSerial(col, 0, colT, 0, K, N);

                        int outOffInArray = outOff;
                        AiDotNet.Tensors.Engines.Simd.SimdGemm.Sgemm(
                            colT.AsSpan(0, N * K),
                            kernelT.AsSpan(0, K * outC),
                            outT.AsSpan(0, N * outC),
                            N, K, outC);

                        TransposeFloatSerial(outT, 0, output, outOffInArray, N, outC);
                    }
                    finally
                    {
                        System.Buffers.ArrayPool<float>.Shared.Return(outT);
                        System.Buffers.ArrayPool<float>.Shared.Return(colT);
                        // NOTE: kernelT is NOT returned to ArrayPool — it's
                        // owned by the cache and lives as long as the kernel.
                    }
                }
                else
                {
                    // Sgemm (vs SgemmSequential) lets SimdGemm spawn its own
                    // Parallel.For when the workload crosses ParallelWorkThreshold.
                    // For batch=1 inference the outer per-image loop has no
                    // parallelism to offer, so the SGEMM-internal one is the
                    // only source of multi-core throughput.
                    AiDotNet.Tensors.Engines.Simd.SimdGemm.Sgemm(
                        kernel.AsSpan(0, outC * K),
                        col.AsSpan(0, K * N),
                        outSpan,
                        outC, K, N);
                }
            }
            finally
            {
                System.Buffers.ArrayPool<float>.Shared.Return(col);
            }
        }

        /// <summary>
        /// Blocked row/col transpose for the small-N SGEMM fast path above.
        /// src is [rows, cols] row-major; dst is [cols, rows] row-major.
        /// Uses a 32×32 blocked traversal with the INNER loop over <c>r</c>
        /// so dst writes within a block are contiguous (stride 1 in <c>r</c>
        /// maps to stride 1 in <c>dst[c*rows + r]</c>). This is the
        /// "transpose by contiguous writes" layout — SIMD-friendly and
        /// cache-line-aligned. Uses <c>Unsafe.Add</c> on raw refs to skip
        /// per-element Span bounds checks.
        /// </summary>
        // Persistent cache of pre-transposed kernel arrays for the small-N
        // fast path. Keyed by the caller's kernel float[] reference via
        // ConditionalWeakTable — the cache entry stays alive exactly as
        // long as the kernel itself, so folding inference on a fixed
        // model gets amortised kernel-transpose cost of zero after the
        // first call per Conv layer, and transient kernels (training
        // loops, ad-hoc computations) drop from the cache when the
        // kernel array is GC'd.
        static float[] GetOrBuildTransposedKernel(float[] kernel, int rows, int cols)
        {
            return _kernelTransposeCache.GetValue(kernel, k =>
            {
                var kernelT = new float[cols * rows];
                TransposeFloatParallel(k, 0, kernelT, 0, rows, cols);
                return kernelT;
            });
        }

        /// <summary>
        /// Serial blocked transpose on raw arrays. Takes arrays + offsets
        /// so callers can work with ArrayPool-rented buffers without span
        /// juggling. Inner loop order: outer c (block-contiguous dst rows),
        /// inner r (stride-1 dst writes). Uses <c>Unsafe.Add</c> on array
        /// refs to elide bounds checks.
        /// </summary>
        static void TransposeFloatSerial(float[] src, int srcOff, float[] dst, int dstOff, int rows, int cols)
        {
            const int BLK = 32;
            ref float srcRef = ref src[srcOff];
            ref float dstRef = ref dst[dstOff];
            for (int cb = 0; cb < cols; cb += BLK)
            {
                int cEnd = Math.Min(cb + BLK, cols);
                for (int rb = 0; rb < rows; rb += BLK)
                {
                    int rEnd = Math.Min(rb + BLK, rows);
                    for (int c = cb; c < cEnd; c++)
                    {
                        int dstRowBase = c * rows;
                        for (int r = rb; r < rEnd; r++)
                        {
                            System.Runtime.CompilerServices.Unsafe.Add(ref dstRef, dstRowBase + r) =
                                System.Runtime.CompilerServices.Unsafe.Add(ref srcRef, r * cols + c);
                        }
                    }
                }
            }
        }

        /// <summary>
        /// Parallel variant that distributes the outer col-block iteration
        /// across cores. For the ResNet stage4 kernel (2.4 MB, 144 col
        /// blocks) → ~9 blocks per core on a 16-core box ≈ 36 KB working
        /// set per core (fits in L1). Uses raw array refs to bypass
        /// per-element Span bounds checks inside the parallel closure.
        /// </summary>
        static void TransposeFloatParallel(float[] src, int srcOff, float[] dst, int dstOff, int rows, int cols)
        {
            const int BLK = 32;
            int numColBlocks = (cols + BLK - 1) / BLK;
            System.Threading.Tasks.Parallel.For(0, numColBlocks, colBlockIdx =>
            {
                int cb = colBlockIdx * BLK;
                int cEnd = Math.Min(cb + BLK, cols);
                ref float srcRef = ref src[srcOff];
                ref float dstRef = ref dst[dstOff];
                for (int rb = 0; rb < rows; rb += BLK)
                {
                    int rEnd = Math.Min(rb + BLK, rows);
                    for (int c = cb; c < cEnd; c++)
                    {
                        int dstRowBase = c * rows;
                        for (int r = rb; r < rEnd; r++)
                        {
                            System.Runtime.CompilerServices.Unsafe.Add(ref dstRef, dstRowBase + r) =
                                System.Runtime.CompilerServices.Unsafe.Add(ref srcRef, r * cols + c);
                        }
                    }
                }
            });
        }

        if (parallelBatch)
        {
            Parallel.For(0, batch, ProcessImage);
        }
        else
        {
            for (int b = 0; b < batch; b++) ProcessImage(b);
        }
    }

    /// <inheritdoc/>
    public Tensor<T> Conv2DBackwardInput<T>(Tensor<T> gradOutput, Tensor<T> kernel, int[] inputShape, int[] stride, int[] padding, int[] dilation)
    {
        if (gradOutput == null) throw new ArgumentNullException(nameof(gradOutput));
        if (kernel == null) throw new ArgumentNullException(nameof(kernel));
        var gradOutputOrig = gradOutput;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!gradOutput.IsContiguous) gradOutput = gradOutput.Contiguous();
        var kernelOrig = kernel;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!kernel.IsContiguous) kernel = kernel.Contiguous();
        if (inputShape == null || inputShape.Length != 4) throw new ArgumentException("inputShape must be array of 4 elements [batch, inChannels, height, width]", nameof(inputShape));
        if (gradOutput.Rank != 4) throw new ArgumentException($"Conv2DBackwardInput requires 4D gradOutput tensor. Got rank {gradOutput.Rank}.", nameof(gradOutput));
        if (kernel.Rank != 4) throw new ArgumentException($"Conv2DBackwardInput requires 4D kernel tensor. Got rank {kernel.Rank}.", nameof(kernel));
        if (stride == null || stride.Length != 2) throw new ArgumentException("Stride must be array of 2 elements", nameof(stride));
        if (stride[0] <= 0 || stride[1] <= 0) throw new ArgumentException("Stride elements must be positive", nameof(stride));
        if (padding == null || padding.Length != 2) throw new ArgumentException("Padding must be array of 2 elements", nameof(padding));
        if (dilation == null || dilation.Length != 2) throw new ArgumentException("Dilation must be array of 2 elements", nameof(dilation));
        if (dilation[0] <= 0 || dilation[1] <= 0) throw new ArgumentException("Dilation elements must be positive", nameof(dilation));
        if (gradOutput._shape[0] != inputShape[0]) throw new ArgumentException($"gradOutput batch size ({gradOutput._shape[0]}) must match inputShape batch size ({inputShape[0]})");
        if (gradOutput._shape[1] != kernel._shape[0]) throw new ArgumentException($"gradOutput outChannels ({gradOutput._shape[1]}) must match kernel outChannels ({kernel._shape[0]})");
        if (inputShape[1] != kernel._shape[1]) throw new ArgumentException($"inputShape inChannels ({inputShape[1]}) must match kernel inChannels ({kernel._shape[1]})");

        var numOps = MathHelper.GetNumericOperations<T>();
        int batch = inputShape[0];
        int inChannels = inputShape[1];
        int height = inputShape[2];
        int width = inputShape[3];

        int outChannels = kernel._shape[0];
        int kernelHeight = kernel._shape[2];
        int kernelWidth = kernel._shape[3];

        int strideH = stride[0], strideW = stride[1];
        int padH = padding[0], padW = padding[1];
        int dilationH = dilation[0], dilationW = dilation[1];

        int outputHeight = gradOutput._shape[2];
        int outputWidth = gradOutput._shape[3];

        // im2col + GEMM fast path for float: kernel^T × gradOutput → col, then col2im
        if (typeof(T) == typeof(float))
        {
            int colH = inChannels * kernelHeight * kernelWidth;
            int colW = outputHeight * outputWidth;
            var gradInputF = new float[batch * inChannels * height * width];
            var gradOutputF = (float[])(object)gradOutput.GetFlattenedData();
            var kernelF = (float[])(object)kernel.GetFlattenedData();

            // Reshape kernel from [outC, inC, kH, kW] to [outC, colH] — already contiguous in memory
            // We need kernel^T which is [colH, outC]
            var kernelT = new float[colH * outChannels];
            for (int r = 0; r < outChannels; r++)
                for (int c = 0; c < colH; c++)
                    kernelT[c * outChannels + r] = kernelF[r * colH + c];

            // Parallel across batches — each batch rents a colBuffer from the pool
            var pool = System.Buffers.ArrayPool<float>.Shared;
            Parallel.For(0, batch, b =>
            {
                var colBuf = pool.Rent(colW * colH);
                try
                {
                    int gradOutOff = b * outChannels * colW;

                    // BLAS GEMM: col = kernel^T × gradOutput → [colH, colW]
                    if (!Helpers.BlasProvider.TryGemm(colH, colW, outChannels,
                        kernelT, 0, outChannels,
                        gradOutputF, gradOutOff, colW,
                        colBuf, 0, colW))
                    {
                        // SimdGemm fallback when BLAS unavailable
                        Simd.SimdGemm.Sgemm(
                            new ReadOnlySpan<float>(kernelT),
                            new ReadOnlySpan<float>(gradOutputF, gradOutOff, outChannels * colW),
                            new Span<float>(colBuf, 0, colH * colW),
                            colH, outChannels, colW);
                    }

                    int imgOff = b * inChannels * height * width;
                    Im2ColHelper.Col2ImAccumulate(
                        new ReadOnlySpan<float>(colBuf, 0, colW * colH),
                        new Span<float>(gradInputF, imgOff, inChannels * height * width),
                        inChannels, height, width,
                        kernelHeight, kernelWidth, strideH, strideW, padH, padW, dilationH, dilationW,
                        outputHeight, outputWidth);
                }
                finally { pool.Return(colBuf); }
            });

            var ops2 = MathHelper.GetNumericOperations<T>();
            var resultArr = new T[gradInputF.Length];
            ops2.FromFloatSpan(new ReadOnlySpan<float>(gradInputF), new Span<T>(resultArr));
            return TensorAllocator.Rent<T>(inputShape, new Vector<T>(resultArr));
        }

        // Generic fallback for non-float types
        var gradInput = new T[batch * inChannels * height * width];
        var gradOutputData = gradOutput.GetDataArray();
        var kernelData = kernel.GetDataArray();

        Parallel.For(0, batch * inChannels, idx =>
        {
            int b = idx / inChannels;
            int ic = idx % inChannels;

            for (int oh = 0; oh < outputHeight; oh++)
            {
                for (int ow = 0; ow < outputWidth; ow++)
                {
                    for (int oc = 0; oc < outChannels; oc++)
                    {
                        int gradOutIdx = ((b * outChannels + oc) * outputHeight + oh) * outputWidth + ow;
                        T gradVal = gradOutputData[gradOutIdx];

                        for (int kh = 0; kh < kernelHeight; kh++)
                        {
                            for (int kw = 0; kw < kernelWidth; kw++)
                            {
                                int ih = oh * strideH + kh * dilationH - padH;
                                int iw = ow * strideW + kw * dilationW - padW;

                                if (ih >= 0 && ih < height && iw >= 0 && iw < width)
                                {
                                    int gradInputIdx = ((b * inChannels + ic) * height + ih) * width + iw;
                                    int kernelIdx = ((oc * inChannels + ic) * kernelHeight + kh) * kernelWidth + kw;
                                    gradInput[gradInputIdx] = numOps.Add(gradInput[gradInputIdx], numOps.Multiply(gradVal, kernelData[kernelIdx]));
                                }
                            }
                        }
                    }
                }
            }
        });

        return TensorAllocator.Rent<T>(inputShape, new Vector<T>(gradInput));
    }

    /// <inheritdoc/>
    public Tensor<T> Conv2DBackwardKernel<T>(Tensor<T> gradOutput, Tensor<T> input, int[] kernelShape, int[] stride, int[] padding, int[] dilation)
    {
        if (gradOutput == null) throw new ArgumentNullException(nameof(gradOutput));
        if (input == null) throw new ArgumentNullException(nameof(input));
        var gradOutputOrig = gradOutput;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!gradOutput.IsContiguous) gradOutput = gradOutput.Contiguous();
        var inputOrig = input;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!input.IsContiguous) input = input.Contiguous();
        if (kernelShape == null || kernelShape.Length != 4) throw new ArgumentException("kernelShape must be array of 4 elements [outChannels, inChannels, kernelHeight, kernelWidth]", nameof(kernelShape));
        if (gradOutput.Rank != 4) throw new ArgumentException($"Conv2DBackwardKernel requires 4D gradOutput tensor. Got rank {gradOutput.Rank}.", nameof(gradOutput));
        if (input.Rank != 4) throw new ArgumentException($"Conv2DBackwardKernel requires 4D input tensor. Got rank {input.Rank}.", nameof(input));
        if (stride == null || stride.Length != 2) throw new ArgumentException("Stride must be array of 2 elements", nameof(stride));
        if (stride[0] <= 0 || stride[1] <= 0) throw new ArgumentException("Stride elements must be positive", nameof(stride));
        if (padding == null || padding.Length != 2) throw new ArgumentException("Padding must be array of 2 elements", nameof(padding));
        if (dilation == null || dilation.Length != 2) throw new ArgumentException("Dilation must be array of 2 elements", nameof(dilation));
        if (dilation[0] <= 0 || dilation[1] <= 0) throw new ArgumentException("Dilation elements must be positive", nameof(dilation));
        if (gradOutput._shape[0] != input._shape[0]) throw new ArgumentException($"gradOutput batch size ({gradOutput._shape[0]}) must match input batch size ({input._shape[0]})");
        if (gradOutput._shape[1] != kernelShape[0]) throw new ArgumentException($"gradOutput outChannels ({gradOutput._shape[1]}) must match kernelShape outChannels ({kernelShape[0]})");
        if (input._shape[1] != kernelShape[1]) throw new ArgumentException($"input inChannels ({input._shape[1]}) must match kernelShape inChannels ({kernelShape[1]})");

        var numOps = MathHelper.GetNumericOperations<T>();

        int batch = input._shape[0];
        int inChannels = input._shape[1];
        int height = input._shape[2];
        int width = input._shape[3];

        int outChannels = kernelShape[0];
        int kernelHeight = kernelShape[2];
        int kernelWidth = kernelShape[3];

        int strideH = stride[0], strideW = stride[1];
        int padH = padding[0], padW = padding[1];
        int dilationH = dilation[0], dilationW = dilation[1];

        int outputHeight = gradOutput._shape[2];
        int outputWidth = gradOutput._shape[3];

        // im2col + GEMM fast path for float: gradKernel += gradOutput × im2col^T
        if (typeof(T) == typeof(float))
        {
            int colH = inChannels * kernelHeight * kernelWidth;
            int colW = outputHeight * outputWidth;
            var gradKernelF = new float[outChannels * colH];
            var gradOutputF = (float[])(object)gradOutput.GetFlattenedData();
            var inputF = (float[])(object)input.GetFlattenedData();
            int inputSliceSize = inChannels * height * width;

            // Parallel across batches — each batch accumulates into a local gradKernel,
            // merged after. This avoids lock contention on the shared accumulator.
            var perBatchGrads = new float[batch][];
            var kPool = System.Buffers.ArrayPool<float>.Shared;
            Parallel.For(0, batch, b =>
            {
                var im2colBuf = kPool.Rent(colH * colW);
                var localGrad = kPool.Rent(outChannels * colH);
                try
                {
                    Array.Clear(localGrad, 0, outChannels * colH);

                    Im2ColHelper.Im2Col(
                        new ReadOnlySpan<float>(inputF, b * inputSliceSize, inputSliceSize),
                        new Span<float>(im2colBuf),
                        1, inChannels, height, width,
                        kernelHeight, kernelWidth, strideH, strideW, padH, padW, dilationH, dilationW);

                    int gradOutOff = b * outChannels * colW;

                    // BLAS GEMM with transpose: localGrad = gradOutput × im2col^T
                    if (!Helpers.BlasProvider.TryGemmEx(
                        outChannels, colH, colW,
                        gradOutputF, gradOutOff, colW, false,
                        im2colBuf, 0, colW, true,
                        localGrad, 0, colH))
                    {
                        // SimdGemm fallback with transpose
                        Simd.SimdGemm.Sgemm(
                            new ReadOnlySpan<float>(gradOutputF, gradOutOff, outChannels * colW), colW, false,
                            new ReadOnlySpan<float>(im2colBuf, 0, colH * colW), colW, true,
                            new Span<float>(localGrad, 0, outChannels * colH),
                            outChannels, colW, colH);
                    }

                    var gradCopy = new float[outChannels * colH];
                    Array.Copy(localGrad, gradCopy, outChannels * colH);
                    perBatchGrads[b] = gradCopy;
                }
                finally
                {
                    kPool.Return(im2colBuf);
                    kPool.Return(localGrad);
                }
            });

            // Merge per-batch gradients
            for (int b = 0; b < batch; b++)
            {
                var lg = perBatchGrads[b];
                for (int i = 0; i < gradKernelF.Length; i++)
                    gradKernelF[i] += lg[i];
            }

            var ops2 = MathHelper.GetNumericOperations<T>();
            var resultArr = new T[gradKernelF.Length];
            ops2.FromFloatSpan(new ReadOnlySpan<float>(gradKernelF), new Span<T>(resultArr));
            return TensorAllocator.Rent<T>(kernelShape, new Vector<T>(resultArr));
        }

        // Generic fallback for non-float types
        var gradKernel = new T[outChannels * inChannels * kernelHeight * kernelWidth];
        var gradOutputData = gradOutput.GetDataArray();
        var inputData = input.GetDataArray();

        Parallel.For(0, outChannels * inChannels, idx =>
        {
            int oc = idx / inChannels;
            int ic = idx % inChannels;

            for (int kh = 0; kh < kernelHeight; kh++)
            {
                for (int kw = 0; kw < kernelWidth; kw++)
                {
                    T sum = numOps.Zero;

                    for (int b = 0; b < batch; b++)
                    {
                        for (int oh = 0; oh < outputHeight; oh++)
                        {
                            for (int ow = 0; ow < outputWidth; ow++)
                            {
                                int ih = oh * strideH + kh * dilationH - padH;
                                int iw = ow * strideW + kw * dilationW - padW;

                                if (ih >= 0 && ih < height && iw >= 0 && iw < width)
                                {
                                    int gradOutIdx = ((b * outChannels + oc) * outputHeight + oh) * outputWidth + ow;
                                    int inputIdx = ((b * inChannels + ic) * height + ih) * width + iw;
                                    sum = numOps.Add(sum, numOps.Multiply(gradOutputData[gradOutIdx], inputData[inputIdx]));
                                }
                            }
                        }
                    }

                    int kernelIdx = ((oc * inChannels + ic) * kernelHeight + kh) * kernelWidth + kw;
                    gradKernel[kernelIdx] = sum;
                }
            }
        });

        return TensorAllocator.Rent<T>(kernelShape, new Vector<T>(gradKernel));
    }

    /// <inheritdoc/>
    public Tensor<T> MaxPool2DWithIndices<T>(Tensor<T> input, int[] poolSize, int[] stride, out int[,,,,] maxIndices)
    {
        if (input == null) throw new ArgumentNullException(nameof(input));

        var numOps = MathHelper.GetNumericOperations<T>();

        int batch = input._shape[0];
        int channels = input._shape[1];
        int height = input._shape[2];
        int width = input._shape[3];

        int poolH = poolSize[0], poolW = poolSize[1];
        int strideH = stride[0], strideW = stride[1];

        if (poolH > height || poolW > width)
            throw new ArgumentException($"Pool size ({poolH}x{poolW}) cannot exceed input spatial dimensions ({height}x{width})");

        int outputHeight = (height - poolH) / strideH + 1;
        int outputWidth = (width - poolW) / strideW + 1;

        if (outputHeight <= 0 || outputWidth <= 0)
            throw new ArgumentException($"Invalid output dimensions ({outputHeight}x{outputWidth}). Check pool size and stride.");

        var result = TensorAllocator.Rent<T>([batch, channels, outputHeight, outputWidth]);
        // Use local variable to avoid capturing out parameter in lambda
        var indices = new int[batch, channels, outputHeight, outputWidth, 2];

        var inputData = input.GetFlattenedData();
        var outputData = result.GetDataArray();

        Parallel.For(0, batch * channels, idx =>
        {
            int b = idx / channels;
            int c = idx % channels;

            for (int oh = 0; oh < outputHeight; oh++)
            {
                for (int ow = 0; ow < outputWidth; ow++)
                {
                    T maxVal = numOps.MinValue;
                    int maxH = 0, maxW = 0;

                    for (int kh = 0; kh < poolH; kh++)
                    {
                        for (int kw = 0; kw < poolW; kw++)
                        {
                            int ih = oh * strideH + kh;
                            int iw = ow * strideW + kw;

                            int inputIdx = ((b * channels + c) * height + ih) * width + iw;
                            T val = inputData[inputIdx];

                            if (numOps.GreaterThan(val, maxVal))
                            {
                                maxVal = val;
                                maxH = ih;
                                maxW = iw;
                            }
                        }
                    }

                    int outputIdx = ((b * channels + c) * outputHeight + oh) * outputWidth + ow;
                    outputData[outputIdx] = maxVal;
                    indices[b, c, oh, ow, 0] = maxH;
                    indices[b, c, oh, ow, 1] = maxW;
                }
            }
        });

        // Assign local variable to out parameter after parallel section
        maxIndices = indices;
        DifferentiableOps.RecordUnary("MaxPool2DWithIndices", result, input, BackwardFunctions<T>.MaxPool2DWithIndicesBackward, new object[] { maxIndices, poolSize, stride });
        { var ci = input; var cp = poolSize; var cs = stride; AutoTracer.RecordOp("MaxPool2DWithIndices", result, eng => { eng.MaxPool2DWithIndices(ci, cp, cs, out _); return result; }); }
        return result;
    }

    /// <inheritdoc/>
    public Tensor<T> MaxPool2DBackward<T>(Tensor<T> gradOutput, int[,,,,] maxIndices, int[] inputShape, int[] poolSize, int[] stride)
    {
        if (gradOutput == null) throw new ArgumentNullException(nameof(gradOutput));

        var numOps = MathHelper.GetNumericOperations<T>();

        int batch = inputShape[0];
        int channels = inputShape[1];
        int height = inputShape[2];
        int width = inputShape[3];

        int outputHeight = gradOutput._shape[2];
        int outputWidth = gradOutput._shape[3];

        var result = AutoTensorCache.RentOrAllocate<T>(inputShape);
        var gradInputData = result.GetDataArray();
        var gradOutputData = gradOutput.GetFlattenedData();

        // Cannot parallelize across (batch, channel) pairs because for MaxPool with
        // overlapping windows, multiple output positions may scatter to the same
        // input index within a channel. Parallel over batches is safe.
        if (typeof(T) == typeof(float))
        {
            var fGradIn = (float[])(object)gradInputData;
            var fGradOut = (float[])(object)gradOutputData;
            Array.Clear(fGradIn, 0, fGradIn.Length);
            Parallel.For(0, batch, b =>
            {
                for (int c = 0; c < channels; c++)
                    for (int oh = 0; oh < outputHeight; oh++)
                        for (int ow = 0; ow < outputWidth; ow++)
                        {
                            int maxH = maxIndices[b, c, oh, ow, 0];
                            int maxW = maxIndices[b, c, oh, ow, 1];
                            int gradOutIdx = ((b * channels + c) * outputHeight + oh) * outputWidth + ow;
                            int gradInIdx = ((b * channels + c) * height + maxH) * width + maxW;
                            fGradIn[gradInIdx] += fGradOut[gradOutIdx];
                        }
            });
        }
        else if (typeof(T) == typeof(double))
        {
            var dGradIn = (double[])(object)gradInputData;
            var dGradOut = (double[])(object)gradOutputData;
            Array.Clear(dGradIn, 0, dGradIn.Length);
            Parallel.For(0, batch, b =>
            {
                for (int c = 0; c < channels; c++)
                    for (int oh = 0; oh < outputHeight; oh++)
                        for (int ow = 0; ow < outputWidth; ow++)
                        {
                            int maxH = maxIndices[b, c, oh, ow, 0];
                            int maxW = maxIndices[b, c, oh, ow, 1];
                            int gradOutIdx = ((b * channels + c) * outputHeight + oh) * outputWidth + ow;
                            int gradInIdx = ((b * channels + c) * height + maxH) * width + maxW;
                            dGradIn[gradInIdx] += dGradOut[gradOutIdx];
                        }
            });
        }
        else
        {
            // Initialize to zero
            for (int i = 0; i < gradInputData.Length; i++)
                gradInputData[i] = numOps.Zero;

            Parallel.For(0, batch, b =>
            {
                for (int c = 0; c < channels; c++)
                {
                    for (int oh = 0; oh < outputHeight; oh++)
                    {
                        for (int ow = 0; ow < outputWidth; ow++)
                        {
                            int maxH = maxIndices[b, c, oh, ow, 0];
                            int maxW = maxIndices[b, c, oh, ow, 1];

                            int gradOutIdx = ((b * channels + c) * outputHeight + oh) * outputWidth + ow;
                            int gradInIdx = ((b * channels + c) * height + maxH) * width + maxW;

                            gradInputData[gradInIdx] = numOps.Add(gradInputData[gradInIdx], gradOutputData[gradOutIdx]);
                        }
                    }
                }
            });
        }

        return result;
    }

    /// <inheritdoc/>
    public Tensor<T> AvgPool2D<T>(Tensor<T> input, int[] poolSize, int[] stride)
    {
        if (input == null) throw new ArgumentNullException(nameof(input));

        var numOps = MathHelper.GetNumericOperations<T>();

        int batch = input._shape[0];
        int channels = input._shape[1];
        int height = input._shape[2];
        int width = input._shape[3];

        int poolH = poolSize[0], poolW = poolSize[1];
        int strideH = stride[0], strideW = stride[1];

        if (poolH > height || poolW > width)
            throw new ArgumentException($"Pool size ({poolH}x{poolW}) cannot exceed input spatial dimensions ({height}x{width})");

        int outputHeight = (height - poolH) / strideH + 1;
        int outputWidth = (width - poolW) / strideW + 1;

        if (outputHeight <= 0 || outputWidth <= 0)
            throw new ArgumentException($"Invalid output dimensions ({outputHeight}x{outputWidth}). Check pool size and stride.");

        var inputData = input.GetFlattenedData();
        var outputData = new T[batch * channels * outputHeight * outputWidth];
        T poolArea = numOps.FromDouble(poolH * poolW);

        Parallel.For(0, batch * channels, idx =>
        {
            int b = idx / channels;
            int c = idx % channels;

            for (int oh = 0; oh < outputHeight; oh++)
            {
                for (int ow = 0; ow < outputWidth; ow++)
                {
                    T sum = numOps.Zero;

                    for (int kh = 0; kh < poolH; kh++)
                    {
                        for (int kw = 0; kw < poolW; kw++)
                        {
                            int ih = oh * strideH + kh;
                            int iw = ow * strideW + kw;
                            int inputIdx = ((b * channels + c) * height + ih) * width + iw;
                            sum = numOps.Add(sum, inputData[inputIdx]);
                        }
                    }

                    int outputIdx = ((b * channels + c) * outputHeight + oh) * outputWidth + ow;
                    outputData[outputIdx] = numOps.Divide(sum, poolArea);
                }
            }
        });

        var result = TensorAllocator.Rent<T>([batch, channels, outputHeight, outputWidth], new Vector<T>(outputData));
        // Tape registration — without it, dL/dInput silently dropped on this overload (#255 audit).
        // Snapshot poolSize/stride: callers can reuse + mutate the int[] they passed in, which would
        // make backward replay with parameters that no longer match the forward result.
        DifferentiableOps.RecordUnary("AvgPool2D", result, input, BackwardFunctions<T>.AvgPool2DBackward,
            new object[] { (int[])poolSize.Clone(), (int[])stride.Clone() });
        return result;
    }

    /// <inheritdoc/>
    public Tensor<T> AvgPool2DBackward<T>(Tensor<T> gradOutput, int[] inputShape, int[] poolSize, int[] stride)
    {
        if (gradOutput == null) throw new ArgumentNullException(nameof(gradOutput));

        var numOps = MathHelper.GetNumericOperations<T>();

        int batch = inputShape[0];
        int channels = inputShape[1];
        int height = inputShape[2];
        int width = inputShape[3];

        int poolH = poolSize[0], poolW = poolSize[1];
        int strideH = stride[0], strideW = stride[1];

        int outputHeight = gradOutput._shape[2];
        int outputWidth = gradOutput._shape[3];

        var result = AutoTensorCache.RentOrAllocate<T>(inputShape);
        var gradInputData = result.GetDataArray();
        var gradOutputData = gradOutput.GetFlattenedData();

        if (typeof(T) == typeof(float))
        {
            var fGradIn = (float[])(object)gradInputData;
            var fGradOut = (float[])(object)gradOutputData;
            float invPoolArea = 1f / (poolH * poolW);
            Array.Clear(fGradIn, 0, fGradIn.Length);
            Parallel.For(0, batch, b =>
            {
                for (int c = 0; c < channels; c++)
                {
                    int inputBaseOffset = (b * channels + c) * height * width;
                    int outputBaseOffset = (b * channels + c) * outputHeight * outputWidth;
                    for (int oh = 0; oh < outputHeight; oh++)
                    {
                        for (int ow = 0; ow < outputWidth; ow++)
                        {
                            float grad = fGradOut[outputBaseOffset + oh * outputWidth + ow] * invPoolArea;
                            for (int kh = 0; kh < poolH; kh++)
                            {
                                int ih = oh * strideH + kh;
                                for (int kw = 0; kw < poolW; kw++)
                                {
                                    int iw = ow * strideW + kw;
                                    fGradIn[inputBaseOffset + ih * width + iw] += grad;
                                }
                            }
                        }
                    }
                }
            });
        }
        else if (typeof(T) == typeof(double))
        {
            var dGradIn = (double[])(object)gradInputData;
            var dGradOut = (double[])(object)gradOutputData;
            double invPoolArea = 1.0 / (poolH * poolW);
            Array.Clear(dGradIn, 0, dGradIn.Length);
            Parallel.For(0, batch, b =>
            {
                for (int c = 0; c < channels; c++)
                {
                    int inputBaseOffset = (b * channels + c) * height * width;
                    int outputBaseOffset = (b * channels + c) * outputHeight * outputWidth;
                    for (int oh = 0; oh < outputHeight; oh++)
                    {
                        for (int ow = 0; ow < outputWidth; ow++)
                        {
                            double grad = dGradOut[outputBaseOffset + oh * outputWidth + ow] * invPoolArea;
                            for (int kh = 0; kh < poolH; kh++)
                            {
                                int ih = oh * strideH + kh;
                                for (int kw = 0; kw < poolW; kw++)
                                {
                                    int iw = ow * strideW + kw;
                                    dGradIn[inputBaseOffset + ih * width + iw] += grad;
                                }
                            }
                        }
                    }
                }
            });
        }
        else
        {
            T poolArea = numOps.FromDouble(poolH * poolW);

            // Initialize to zero
            for (int i = 0; i < gradInputData.Length; i++)
                gradInputData[i] = numOps.Zero;

            // Parallelize across batches (within a batch*channel, output positions scatter to overlapping input regions)
            Parallel.For(0, batch, b =>
            {
                for (int c = 0; c < channels; c++)
                {
                    int inputBaseOffset = (b * channels + c) * height * width;
                    int outputBaseOffset = (b * channels + c) * outputHeight * outputWidth;

                    for (int oh = 0; oh < outputHeight; oh++)
                    {
                        for (int ow = 0; ow < outputWidth; ow++)
                        {
                            T grad = numOps.Divide(gradOutputData[outputBaseOffset + oh * outputWidth + ow], poolArea);

                            for (int kh = 0; kh < poolH; kh++)
                            {
                                int ih = oh * strideH + kh;
                                for (int kw = 0; kw < poolW; kw++)
                                {
                                    int iw = ow * strideW + kw;
                                    int gradInIdx = inputBaseOffset + ih * width + iw;
                                    gradInputData[gradInIdx] = numOps.Add(gradInputData[gradInIdx], grad);
                                }
                            }
                        }
                    }
                }
            });
        }

        return result;
    }

    /// <summary>
    /// Write-through DepthwiseConv2D for MobileNet / EfficientNet inference.
    /// Computes directly into the provided output buffer, skipping the
    /// intermediate tensor allocation + CopyTo (~100 µs saved per call on
    /// mid-sized depthwise layers).
    /// </summary>
    public void DepthwiseConv2DInto<T>(Tensor<T> output, Tensor<T> input, Tensor<T> kernel, int[] stride, int[] padding)
    {
        if (output == null) throw new ArgumentNullException(nameof(output));
        if (input == null) throw new ArgumentNullException(nameof(input));
        if (kernel == null) throw new ArgumentNullException(nameof(kernel));
        DepthwiseConv2DComputeIntoOutput(input, kernel, stride, padding, output.GetDataArray());
    }

    /// <inheritdoc/>
    public Tensor<T> DepthwiseConv2D<T>(Tensor<T> input, Tensor<T> kernel, int[] stride, int[] padding)
    {
        if (input == null) throw new ArgumentNullException(nameof(input));
        if (kernel == null) throw new ArgumentNullException(nameof(kernel));

        if (GraphMode.IsActive)
        {
            var scope = GraphMode.Current;
            if (scope != null)
            {
                int oH = (input._shape[2] + 2 * padding[0] - kernel._shape[2]) / stride[0] + 1;
                int oW = (input._shape[3] + 2 * padding[1] - kernel._shape[3]) / stride[1] + 1;
                int outCh = input._shape[1] * kernel._shape[1];
                var outShape = new[] { input._shape[0], outCh, oH, oW };
                var capturedInput = input;
                var capturedKernel = kernel;
                var capturedStride = stride;
                var capturedPadding = padding;
                return scope.RecordBinary(LazyNodeType.DepthwiseConv2D, "DepthwiseConv2D", input, kernel, outShape,
                    (eng, output) =>
                    {
                        if (eng is CpuEngine cpuEng) cpuEng.DepthwiseConv2DInto(output, capturedInput, capturedKernel, capturedStride, capturedPadding);
                        else { var r = eng.DepthwiseConv2D(capturedInput, capturedKernel, capturedStride, capturedPadding); r.AsSpan().CopyTo(output.AsWritableSpan()); }
                    },
                    BackwardFunctions<T>.DepthwiseConv2DBackward, new object[] { stride, padding });
            }
        }

        { var ac = AutoTracer.TryGetCompiledPlan<T>("DepthwiseConv2D", input._shape); if (ac is not null) return ac.Execute(); }

        int batch0 = input._shape[0];
        int inChannels0 = input._shape[1];
        int multiplier0 = kernel._shape[1];
        int kernelHeight0 = kernel._shape[2];
        int kernelWidth0 = kernel._shape[3];
        int outputHeight0 = (input._shape[2] + 2 * padding[0] - kernelHeight0) / stride[0] + 1;
        int outputWidth0 = (input._shape[3] + 2 * padding[1] - kernelWidth0) / stride[1] + 1;
        int outChannels0 = inChannels0 * multiplier0;

        var outputData = new T[batch0 * outChannels0 * outputHeight0 * outputWidth0];
        DepthwiseConv2DComputeIntoOutput(input, kernel, stride, padding, outputData);

        var dwConvResult = TensorAllocator.Rent<T>([batch0, outChannels0, outputHeight0, outputWidth0], new Vector<T>(outputData));
        DifferentiableOps.RecordBinary("DepthwiseConv2D", dwConvResult, input, kernel, BackwardFunctions<T>.DepthwiseConv2DBackward, new object[] { stride, padding });
        AutoTracer.RecordOp("DepthwiseConv2D", dwConvResult, eng => dwConvResult);
        return dwConvResult;
    }

    /// <summary>
    /// Shared depthwise conv compute: Parallel.For over (batch × out-channels)
    /// with a 4-level spatial inner loop. Writes results directly into
    /// <paramref name="outputData"/> which must be sized for the output
    /// tensor's total element count. Used by both DepthwiseConv2D (rents
    /// a fresh output) and DepthwiseConv2DInto (reuses caller's buffer).
    /// </summary>
    private void DepthwiseConv2DComputeIntoOutput<T>(
        Tensor<T> input, Tensor<T> kernel, int[] stride, int[] padding, T[] outputData)
    {
        var numOps = MathHelper.GetNumericOperations<T>();

        int batch = input._shape[0];
        int inChannels = input._shape[1];
        int height = input._shape[2];
        int width = input._shape[3];

        int multiplier = kernel._shape[1];
        int kernelHeight = kernel._shape[2];
        int kernelWidth = kernel._shape[3];

        int strideH = stride[0], strideW = stride[1];
        int padH = padding[0], padW = padding[1];

        int outputHeight = (height + 2 * padH - kernelHeight) / strideH + 1;
        int outputWidth = (width + 2 * padW - kernelWidth) / strideW + 1;
        int outChannels = inChannels * multiplier;

        var inputData = input.GetFlattenedData();
        var kernelData = kernel.GetFlattenedData();

        Parallel.For(0, batch * outChannels, idx =>
        {
            int b = idx / outChannels;
            int oc = idx % outChannels;
            int ic = oc / multiplier;
            int m = oc % multiplier;

            for (int oh = 0; oh < outputHeight; oh++)
            {
                for (int ow = 0; ow < outputWidth; ow++)
                {
                    T sum = numOps.Zero;

                    for (int kh = 0; kh < kernelHeight; kh++)
                    {
                        for (int kw = 0; kw < kernelWidth; kw++)
                        {
                            int ih = oh * strideH + kh - padH;
                            int iw = ow * strideW + kw - padW;

                            if (ih >= 0 && ih < height && iw >= 0 && iw < width)
                            {
                                int inputIdx = ((b * inChannels + ic) * height + ih) * width + iw;
                                int kernelIdx = ((ic * multiplier + m) * kernelHeight + kh) * kernelWidth + kw;
                                sum = numOps.Add(sum, numOps.Multiply(inputData[inputIdx], kernelData[kernelIdx]));
                            }
                        }
                    }

                    int outputIdx = ((b * outChannels + oc) * outputHeight + oh) * outputWidth + ow;
                    outputData[outputIdx] = sum;
                }
            }
        });
    }

    /// <inheritdoc/>
    public Tensor<T> DepthwiseConv2DBackwardInput<T>(Tensor<T> gradOutput, Tensor<T> kernel, int[] inputShape, int[] stride, int[] padding)
    {
        if (gradOutput == null) throw new ArgumentNullException(nameof(gradOutput));
        if (kernel == null) throw new ArgumentNullException(nameof(kernel));
        var kernelOrig = kernel;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!kernel.IsContiguous) kernel = kernel.Contiguous();

        var numOps = MathHelper.GetNumericOperations<T>();

        int batch = inputShape[0];
        int inChannels = inputShape[1];
        int height = inputShape[2];
        int width = inputShape[3];

        int multiplier = kernel._shape[1];
        int kernelHeight = kernel._shape[2];
        int kernelWidth = kernel._shape[3];

        int strideH = stride[0], strideW = stride[1];
        int padH = padding[0], padW = padding[1];

        int outputHeight = gradOutput._shape[2];
        int outputWidth = gradOutput._shape[3];
        int outChannels = inChannels * multiplier;

        var gradInput = new T[batch * inChannels * height * width];
        var gradOutputData = gradOutput.GetFlattenedData();
        var kernelData = kernel.GetFlattenedData();

        for (int i = 0; i < gradInput.Length; i++)
            gradInput[i] = numOps.Zero;

        for (int b = 0; b < batch; b++)
        {
            for (int oc = 0; oc < outChannels; oc++)
            {
                int ic = oc / multiplier;
                int m = oc % multiplier;

                for (int oh = 0; oh < outputHeight; oh++)
                {
                    for (int ow = 0; ow < outputWidth; ow++)
                    {
                        int gradOutIdx = ((b * outChannels + oc) * outputHeight + oh) * outputWidth + ow;
                        T gradVal = gradOutputData[gradOutIdx];

                        for (int kh = 0; kh < kernelHeight; kh++)
                        {
                            for (int kw = 0; kw < kernelWidth; kw++)
                            {
                                int ih = oh * strideH + kh - padH;
                                int iw = ow * strideW + kw - padW;

                                if (ih >= 0 && ih < height && iw >= 0 && iw < width)
                                {
                                    int gradInIdx = ((b * inChannels + ic) * height + ih) * width + iw;
                                    int kernelIdx = ((ic * multiplier + m) * kernelHeight + kh) * kernelWidth + kw;
                                    gradInput[gradInIdx] = numOps.Add(gradInput[gradInIdx], numOps.Multiply(gradVal, kernelData[kernelIdx]));
                                }
                            }
                        }
                    }
                }
            }
        }

        return TensorAllocator.Rent<T>(inputShape, new Vector<T>(gradInput));
    }

    /// <inheritdoc/>
    public Tensor<T> DepthwiseConv2DBackwardKernel<T>(Tensor<T> gradOutput, Tensor<T> input, int[] kernelShape, int[] stride, int[] padding)
    {
        if (gradOutput == null) throw new ArgumentNullException(nameof(gradOutput));
        if (input == null) throw new ArgumentNullException(nameof(input));
        var gradOutputOrig = gradOutput;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!gradOutput.IsContiguous) gradOutput = gradOutput.Contiguous();

        var numOps = MathHelper.GetNumericOperations<T>();

        int batch = input._shape[0];
        int inChannels = input._shape[1];
        int height = input._shape[2];
        int width = input._shape[3];

        int multiplier = kernelShape[1];
        int kernelHeight = kernelShape[2];
        int kernelWidth = kernelShape[3];

        int strideH = stride[0], strideW = stride[1];
        int padH = padding[0], padW = padding[1];

        int outputHeight = gradOutput._shape[2];
        int outputWidth = gradOutput._shape[3];

        var gradKernel = new T[inChannels * multiplier * kernelHeight * kernelWidth];
        var gradOutputData = gradOutput.GetFlattenedData();
        var inputData = input.GetFlattenedData();

        for (int i = 0; i < gradKernel.Length; i++)
            gradKernel[i] = numOps.Zero;

        for (int ic = 0; ic < inChannels; ic++)
        {
            for (int m = 0; m < multiplier; m++)
            {
                int oc = ic * multiplier + m;

                for (int kh = 0; kh < kernelHeight; kh++)
                {
                    for (int kw = 0; kw < kernelWidth; kw++)
                    {
                        T sum = numOps.Zero;

                        for (int b = 0; b < batch; b++)
                        {
                            for (int oh = 0; oh < outputHeight; oh++)
                            {
                                for (int ow = 0; ow < outputWidth; ow++)
                                {
                                    int ih = oh * strideH + kh - padH;
                                    int iw = ow * strideW + kw - padW;

                                    if (ih >= 0 && ih < height && iw >= 0 && iw < width)
                                    {
                                        int gradOutIdx = ((b * (inChannels * multiplier) + oc) * outputHeight + oh) * outputWidth + ow;
                                        int inputIdx = ((b * inChannels + ic) * height + ih) * width + iw;
                                        sum = numOps.Add(sum, numOps.Multiply(gradOutputData[gradOutIdx], inputData[inputIdx]));
                                    }
                                }
                            }
                        }

                        int kernelIdx = ((ic * multiplier + m) * kernelHeight + kh) * kernelWidth + kw;
                        gradKernel[kernelIdx] = sum;
                    }
                }
            }
        }

        return TensorAllocator.Rent<T>(kernelShape, new Vector<T>(gradKernel));
    }

    /// <inheritdoc/>
    public virtual Tensor<T> ConvTranspose2D<T>(Tensor<T> input, Tensor<T> kernel, int[] stride, int[] padding, int[] outputPadding)
    {
        if (input == null) throw new ArgumentNullException(nameof(input));
        if (kernel == null) throw new ArgumentNullException(nameof(kernel));
        var inputOrig = input;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!input.IsContiguous) input = input.Contiguous();
        var kernelOrig = kernel;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!kernel.IsContiguous) kernel = kernel.Contiguous();
        if (input.Rank != 4) throw new ArgumentException($"ConvTranspose2D requires 4D input tensor. Got rank {input.Rank}.", nameof(input));
        if (kernel.Rank != 4) throw new ArgumentException($"ConvTranspose2D requires 4D kernel tensor. Got rank {kernel.Rank}.", nameof(kernel));
        if (stride == null || stride.Length != 2) throw new ArgumentException("Stride must be array of 2 elements", nameof(stride));
        if (stride[0] <= 0 || stride[1] <= 0) throw new ArgumentException("Stride elements must be positive", nameof(stride));
        if (padding == null || padding.Length != 2) throw new ArgumentException("Padding must be array of 2 elements", nameof(padding));
        if (padding[0] < 0 || padding[1] < 0) throw new ArgumentException("Padding elements must be non-negative", nameof(padding));
        if (outputPadding == null || outputPadding.Length != 2) throw new ArgumentException("OutputPadding must be array of 2 elements", nameof(outputPadding));
        if (outputPadding[0] < 0 || outputPadding[1] < 0) throw new ArgumentException("OutputPadding elements must be non-negative", nameof(outputPadding));
        if (input._shape[1] != kernel._shape[0]) throw new ArgumentException($"Input inChannels ({input._shape[1]}) must match kernel inChannels ({kernel._shape[0]})");

        if (GraphMode.IsActive)
        {
            var scope = GraphMode.Current;
            if (scope != null)
            {
                int oH = (input._shape[2] - 1) * stride[0] - 2 * padding[0] + kernel._shape[2] + outputPadding[0];
                int oW = (input._shape[3] - 1) * stride[1] - 2 * padding[1] + kernel._shape[3] + outputPadding[1];
                var outShape = new[] { input._shape[0], kernel._shape[1], oH, oW };
                var capturedInput = input;
                var capturedKernel = kernel;
                var capturedStride = (int[])stride.Clone();
                var capturedPadding = (int[])padding.Clone();
                var capturedOutputPadding = (int[])outputPadding.Clone();
                return scope.RecordBinary(LazyNodeType.Custom, "ConvTranspose2D", input, kernel, outShape,
                    (eng, output) => { var r = eng.ConvTranspose2D(capturedInput, capturedKernel, capturedStride, capturedPadding, capturedOutputPadding); r.AsSpan().CopyTo(output.AsWritableSpan()); },
                    BackwardFunctions<T>.ConvTranspose2DBackward, new object[] { (int[])stride.Clone(), (int[])padding.Clone() });
            }
        }

        { var ac = AutoTracer.TryGetCompiledPlan<T>("ConvTranspose2D", input._shape); if (ac is not null) return ac.Execute(); }

        var numOps = MathHelper.GetNumericOperations<T>();

        int batch = input._shape[0];
        int inChannels = input._shape[1];
        int height = input._shape[2];
        int width = input._shape[3];

        int outChannels = kernel._shape[1];
        int kernelHeight = kernel._shape[2];
        int kernelWidth = kernel._shape[3];

        int strideH = stride[0], strideW = stride[1];
        int padH = padding[0], padW = padding[1];
        int outPadH = outputPadding[0], outPadW = outputPadding[1];

        int outputHeight = (height - 1) * strideH - 2 * padH + kernelHeight + outPadH;
        int outputWidth = (width - 1) * strideW - 2 * padW + kernelWidth + outPadW;

        var inputData = input.GetDataArray();
        var kernelData = kernel.GetDataArray();
        var outputData = new T[batch * outChannels * outputHeight * outputWidth];

        // ────────────────────────────────────────────────────────────────────
        // Primitive fast paths: direct float/double arithmetic, no virtual
        // dispatch. Gather form parallelized over (batch, outChannels) — each
        // worker owns a disjoint output slice [b, oc, :, :], eliminating
        // thread-local full-size buffers and the merge lock. Memory usage
        // stays O(outLen) instead of O(threads × outLen).
        //
        // VAE decoder — directly in the #162 timing-out list — plus diffusion
        // UNet upsample decoder blocks hit this op in every forward pass.
        // ────────────────────────────────────────────────────────────────────
        if (typeof(T) == typeof(float))
        {
            var fInput = (float[])(object)inputData;
            var fKernel = (float[])(object)kernelData;
            var fOutput = (float[])(object)outputData;

            Parallel.For(0, batch * outChannels, idx =>
            {
                int b = idx / outChannels;
                int oc = idx % outChannels;
                for (int oh = 0; oh < outputHeight; oh++)
                {
                    for (int ow = 0; ow < outputWidth; ow++)
                    {
                        float sum = 0f;
                        for (int kh = 0; kh < kernelHeight; kh++)
                        {
                            int numerH = oh + padH - kh;
                            if (numerH < 0 || numerH % strideH != 0) continue;
                            int ih = numerH / strideH;
                            if (ih >= height) continue;
                            for (int kw = 0; kw < kernelWidth; kw++)
                            {
                                int numerW = ow + padW - kw;
                                if (numerW < 0 || numerW % strideW != 0) continue;
                                int iw = numerW / strideW;
                                if (iw >= width) continue;
                                for (int ic = 0; ic < inChannels; ic++)
                                {
                                    int inputIdx = ((b * inChannels + ic) * height + ih) * width + iw;
                                    int kernelIdx = ((ic * outChannels + oc) * kernelHeight + kh) * kernelWidth + kw;
                                    sum += fInput[inputIdx] * fKernel[kernelIdx];
                                }
                            }
                        }
                        int outputIdx = ((b * outChannels + oc) * outputHeight + oh) * outputWidth + ow;
                        fOutput[outputIdx] = sum;
                    }
                }
            });
        }
        else if (typeof(T) == typeof(double))
        {
            var dInput = (double[])(object)inputData;
            var dKernel = (double[])(object)kernelData;
            var dOutput = (double[])(object)outputData;

            Parallel.For(0, batch * outChannels, idx =>
            {
                int b = idx / outChannels;
                int oc = idx % outChannels;
                for (int oh = 0; oh < outputHeight; oh++)
                {
                    for (int ow = 0; ow < outputWidth; ow++)
                    {
                        double sum = 0d;
                        for (int kh = 0; kh < kernelHeight; kh++)
                        {
                            int numerH = oh + padH - kh;
                            if (numerH < 0 || numerH % strideH != 0) continue;
                            int ih = numerH / strideH;
                            if (ih >= height) continue;
                            for (int kw = 0; kw < kernelWidth; kw++)
                            {
                                int numerW = ow + padW - kw;
                                if (numerW < 0 || numerW % strideW != 0) continue;
                                int iw = numerW / strideW;
                                if (iw >= width) continue;
                                for (int ic = 0; ic < inChannels; ic++)
                                {
                                    int inputIdx = ((b * inChannels + ic) * height + ih) * width + iw;
                                    int kernelIdx = ((ic * outChannels + oc) * kernelHeight + kh) * kernelWidth + kw;
                                    sum += dInput[inputIdx] * dKernel[kernelIdx];
                                }
                            }
                        }
                        int outputIdx = ((b * outChannels + oc) * outputHeight + oh) * outputWidth + ow;
                        dOutput[outputIdx] = sum;
                    }
                }
            });
        }
        else
        {
            for (int i = 0; i < outputData.Length; i++)
                outputData[i] = numOps.Zero;

            // Use thread-local accumulation to avoid lock contention
            var lockObj = new object();
            Parallel.For(0, batch * inChannels,
                // Initialize thread-local storage
                () => new T[batch * outChannels * outputHeight * outputWidth],
                // Body
                (idx, state, localOutput) =>
                {
                    int b = idx / inChannels;
                    int ic = idx % inChannels;

                    for (int ih = 0; ih < height; ih++)
                    {
                        for (int iw = 0; iw < width; iw++)
                        {
                            int inputIdx = ((b * inChannels + ic) * height + ih) * width + iw;
                            T inputVal = inputData[inputIdx];

                            for (int oc = 0; oc < outChannels; oc++)
                            {
                                for (int kh = 0; kh < kernelHeight; kh++)
                                {
                                    for (int kw = 0; kw < kernelWidth; kw++)
                                    {
                                        int oh = ih * strideH - padH + kh;
                                        int ow = iw * strideW - padW + kw;

                                        if (oh >= 0 && oh < outputHeight && ow >= 0 && ow < outputWidth)
                                        {
                                            int outputIdx = ((b * outChannels + oc) * outputHeight + oh) * outputWidth + ow;
                                            int kernelIdx = ((ic * outChannels + oc) * kernelHeight + kh) * kernelWidth + kw;
                                            localOutput[outputIdx] = numOps.Add(localOutput[outputIdx], numOps.Multiply(inputVal, kernelData[kernelIdx]));
                                        }
                                    }
                                }
                            }
                        }
                    }
                    return localOutput;
                },
                // Merge thread-local results
                (localOutput) =>
                {
                    lock (lockObj)
                    {
                        for (int i = 0; i < outputData.Length; i++)
                        {
                            outputData[i] = numOps.Add(outputData[i], localOutput[i]);
                        }
                    }
                });
        }

        var convTransResult = TensorAllocator.Rent<T>([batch, outChannels, outputHeight, outputWidth], new Vector<T>(outputData));
        DifferentiableOps.RecordBinary("ConvTranspose2D", convTransResult, inputOrig, kernelOrig,
            BackwardFunctions<T>.ConvTranspose2DBackward,
            savedState: new object[] { (int[])stride.Clone(), (int[])padding.Clone() });
        AutoTracer.RecordOp("ConvTranspose2D", convTransResult, eng => convTransResult);
        return convTransResult;
    }

    /// <inheritdoc/>
    public Tensor<T> ConvTranspose2DBackwardInput<T>(Tensor<T> gradOutput, Tensor<T> kernel, int[] inputShape, int[] stride, int[] padding)
    {
        // ConvTranspose2D backward w.r.t. input is equivalent to Conv2D forward
        // Note: This implementation assumes unit dilation. For non-unit dilation, the gradient requires
        // more complex handling (e.g., dilated convolution with flipped kernel).
        var result = Conv2D(gradOutput, kernel, stride, padding, [1, 1]);

        // Validate that the result matches expected input shape
        if (result._shape[0] != inputShape[0] || result._shape[1] != inputShape[1] ||
            result._shape[2] != inputShape[2] || result._shape[3] != inputShape[3])
        {
            throw new InvalidOperationException(
                $"ConvTranspose2DBackwardInput result shape [{string.Join(",", result._shape)}] " +
                $"does not match expected inputShape [{string.Join(",", inputShape)}]. " +
                "This may occur with non-standard stride/padding configurations.");
        }

        return result;
    }

    /// <inheritdoc/>
    public Tensor<T> ConvTranspose2DBackwardKernel<T>(Tensor<T> gradOutput, Tensor<T> input, int[] kernelShape, int[] stride, int[] padding)
    {
        if (gradOutput == null) throw new ArgumentNullException(nameof(gradOutput));
        if (input == null) throw new ArgumentNullException(nameof(input));

        var numOps = MathHelper.GetNumericOperations<T>();

        int batch = input._shape[0];
        int inChannels = input._shape[1];
        int height = input._shape[2];
        int width = input._shape[3];

        int outChannels = kernelShape[1];
        int kernelHeight = kernelShape[2];
        int kernelWidth = kernelShape[3];

        int strideH = stride[0], strideW = stride[1];
        int padH = padding[0], padW = padding[1];

        int outputHeight = gradOutput._shape[2];
        int outputWidth = gradOutput._shape[3];

        var gradKernel = new T[inChannels * outChannels * kernelHeight * kernelWidth];
        var gradOutputData = gradOutput.GetFlattenedData();
        var inputData = input.GetFlattenedData();

        // Parallelize over inChannels*outChannels since each (ic, oc) pair writes
        // a disjoint [kernelHeight × kernelWidth] kernel slice. Primitive fast
        // paths skip virtual dispatch for float/double.
        int pairs = inChannels * outChannels;

        if (typeof(T) == typeof(float))
        {
            var fGradOut = (float[])(object)gradOutputData;
            var fInput = (float[])(object)inputData;
            var fGradKernel = (float[])(object)gradKernel;
            Parallel.For(0, pairs, pair =>
            {
                int ic = pair / outChannels;
                int oc = pair % outChannels;
                for (int kh = 0; kh < kernelHeight; kh++)
                {
                    for (int kw = 0; kw < kernelWidth; kw++)
                    {
                        float sum = 0f;
                        for (int b = 0; b < batch; b++)
                        {
                            for (int ih = 0; ih < height; ih++)
                            {
                                int oh = ih * strideH - padH + kh;
                                if (oh < 0 || oh >= outputHeight) continue;
                                for (int iw = 0; iw < width; iw++)
                                {
                                    int ow = iw * strideW - padW + kw;
                                    if (ow < 0 || ow >= outputWidth) continue;
                                    int gradOutIdx = ((b * outChannels + oc) * outputHeight + oh) * outputWidth + ow;
                                    int inputIdx = ((b * inChannels + ic) * height + ih) * width + iw;
                                    sum += fGradOut[gradOutIdx] * fInput[inputIdx];
                                }
                            }
                        }
                        int kernelIdx = ((ic * outChannels + oc) * kernelHeight + kh) * kernelWidth + kw;
                        fGradKernel[kernelIdx] = sum;
                    }
                }
            });
        }
        else if (typeof(T) == typeof(double))
        {
            var dGradOut = (double[])(object)gradOutputData;
            var dInput = (double[])(object)inputData;
            var dGradKernel = (double[])(object)gradKernel;
            Parallel.For(0, pairs, pair =>
            {
                int ic = pair / outChannels;
                int oc = pair % outChannels;
                for (int kh = 0; kh < kernelHeight; kh++)
                {
                    for (int kw = 0; kw < kernelWidth; kw++)
                    {
                        double sum = 0.0;
                        for (int b = 0; b < batch; b++)
                        {
                            for (int ih = 0; ih < height; ih++)
                            {
                                int oh = ih * strideH - padH + kh;
                                if (oh < 0 || oh >= outputHeight) continue;
                                for (int iw = 0; iw < width; iw++)
                                {
                                    int ow = iw * strideW - padW + kw;
                                    if (ow < 0 || ow >= outputWidth) continue;
                                    int gradOutIdx = ((b * outChannels + oc) * outputHeight + oh) * outputWidth + ow;
                                    int inputIdx = ((b * inChannels + ic) * height + ih) * width + iw;
                                    sum += dGradOut[gradOutIdx] * dInput[inputIdx];
                                }
                            }
                        }
                        int kernelIdx = ((ic * outChannels + oc) * kernelHeight + kh) * kernelWidth + kw;
                        dGradKernel[kernelIdx] = sum;
                    }
                }
            });
        }
        else
        {
            for (int i = 0; i < gradKernel.Length; i++)
                gradKernel[i] = numOps.Zero;

            for (int ic = 0; ic < inChannels; ic++)
            {
                for (int oc = 0; oc < outChannels; oc++)
                {
                    for (int kh = 0; kh < kernelHeight; kh++)
                    {
                        for (int kw = 0; kw < kernelWidth; kw++)
                        {
                            T sum = numOps.Zero;

                            for (int b = 0; b < batch; b++)
                            {
                                for (int ih = 0; ih < height; ih++)
                                {
                                    for (int iw = 0; iw < width; iw++)
                                    {
                                        int oh = ih * strideH - padH + kh;
                                        int ow = iw * strideW - padW + kw;

                                        if (oh >= 0 && oh < outputHeight && ow >= 0 && ow < outputWidth)
                                        {
                                            int gradOutIdx = ((b * outChannels + oc) * outputHeight + oh) * outputWidth + ow;
                                            int inputIdx = ((b * inChannels + ic) * height + ih) * width + iw;
                                            sum = numOps.Add(sum, numOps.Multiply(gradOutputData[gradOutIdx], inputData[inputIdx]));
                                        }
                                    }
                                }
                            }

                            int kernelIdx = ((ic * outChannels + oc) * kernelHeight + kh) * kernelWidth + kw;
                            gradKernel[kernelIdx] = sum;
                        }
                    }
                }
            }
        }

        return TensorAllocator.Rent<T>(kernelShape, new Vector<T>(gradKernel));
    }

    #region Deformable Convolution Operations

    /// <inheritdoc/>
    public Tensor<T> DeformableConv2D<T>(
        Tensor<T> input,
        Tensor<T> kernel,
        Tensor<T> offset,
        Tensor<T>? mask,
        int[] stride,
        int[] padding,
        int[] dilation)
    {
        if (input == null) throw new ArgumentNullException(nameof(input));
        if (kernel == null) throw new ArgumentNullException(nameof(kernel));
        if (offset == null) throw new ArgumentNullException(nameof(offset));
        if (input.Rank != 4) throw new ArgumentException($"DeformableConv2D requires 4D input tensor. Got rank {input.Rank}.", nameof(input));
        if (kernel.Rank != 4) throw new ArgumentException($"DeformableConv2D requires 4D kernel tensor. Got rank {kernel.Rank}.", nameof(kernel));
        if (stride == null || stride.Length != 2) throw new ArgumentException("Stride must be array of 2 elements.", nameof(stride));
        if (padding == null || padding.Length != 2) throw new ArgumentException("Padding must be array of 2 elements.", nameof(padding));
        if (dilation == null || dilation.Length != 2) throw new ArgumentException("Dilation must be array of 2 elements.", nameof(dilation));

        var numOps = MathHelper.GetNumericOperations<T>();

        int batch = input._shape[0];
        int inChannels = input._shape[1];
        int height = input._shape[2];
        int width = input._shape[3];

        int outChannels = kernel._shape[0];
        int kernelInChannels = kernel._shape[1];
        int kernelHeight = kernel._shape[2];
        int kernelWidth = kernel._shape[3];

        // Validate input/kernel channel compatibility
        if (inChannels != kernelInChannels)
            throw new ArgumentException($"Input channels ({inChannels}) must match kernel in_channels ({kernelInChannels}).", nameof(kernel));

        int strideH = stride[0], strideW = stride[1];
        int padH = padding[0], padW = padding[1];
        int dilationH = dilation[0], dilationW = dilation[1];

        // Validate stride and dilation are positive
        if (strideH <= 0 || strideW <= 0)
            throw new ArgumentException("Stride elements must be positive.", nameof(stride));
        if (dilationH <= 0 || dilationW <= 0)
            throw new ArgumentException("Dilation elements must be positive.", nameof(dilation));

        int effectiveKernelH = dilationH * (kernelHeight - 1) + 1;
        int effectiveKernelW = dilationW * (kernelWidth - 1) + 1;

        int outputHeight = (height + 2 * padH - effectiveKernelH) / strideH + 1;
        int outputWidth = (width + 2 * padW - effectiveKernelW) / strideW + 1;

        // Validate output dimensions are positive
        if (outputHeight <= 0 || outputWidth <= 0)
            throw new ArgumentException(
                $"Invalid deformable conv parameters: output size would be {outputHeight}x{outputWidth} " +
                $"for input {height}x{width}, kernel {kernelHeight}x{kernelWidth}, " +
                $"stride=({strideH},{strideW}), padding=({padH},{padW}), dilation=({dilationH},{dilationW}).");

        int numKernelPositions = kernelHeight * kernelWidth;

        // Validate offset shape: [batch, 2*kernel_h*kernel_w, out_h, out_w]
        if (offset.Rank != 4)
            throw new ArgumentException($"Offset tensor must be 4D. Got rank {offset.Rank}.", nameof(offset));
        if (offset._shape[0] != batch || offset._shape[1] != 2 * numKernelPositions ||
            offset._shape[2] != outputHeight || offset._shape[3] != outputWidth)
            throw new ArgumentException(
                $"Offset tensor must have shape [{batch}, {2 * numKernelPositions}, {outputHeight}, {outputWidth}]. " +
                $"Got [{string.Join(",", offset._shape)}].", nameof(offset));

        // Validate mask shape if provided: [batch, kernel_h*kernel_w, out_h, out_w]
        if (mask != null)
        {
            if (mask.Rank != 4)
                throw new ArgumentException($"Mask tensor must be 4D. Got rank {mask.Rank}.", nameof(mask));
            if (mask._shape[0] != batch || mask._shape[1] != numKernelPositions ||
                mask._shape[2] != outputHeight || mask._shape[3] != outputWidth)
                throw new ArgumentException(
                    $"Mask tensor must have shape [{batch}, {numKernelPositions}, {outputHeight}, {outputWidth}]. " +
                    $"Got [{string.Join(",", mask._shape)}].", nameof(mask));
        }

        var result = TensorAllocator.Rent<T>([batch, outChannels, outputHeight, outputWidth]);
        var inputData = input.GetDataArray();
        var kernelData = kernel.GetDataArray();
        var offsetData = offset.GetDataArray();
        var maskData = mask?.GetDataArray();
        var outputData = result.GetDataArray();

        // Parallel over batch * outChannels for maximum parallelism
        Parallel.For(0, batch * outChannels, idx =>
        {
            int b = idx / outChannels;
            int oc = idx % outChannels;

            for (int oh = 0; oh < outputHeight; oh++)
            {
                for (int ow = 0; ow < outputWidth; ow++)
                {
                    T sum = numOps.Zero;

                    for (int ic = 0; ic < inChannels; ic++)
                    {
                        for (int kh = 0; kh < kernelHeight; kh++)
                        {
                            for (int kw = 0; kw < kernelWidth; kw++)
                            {
                                int kernelPosIdx = kh * kernelWidth + kw;

                                // Get offsets for this kernel position
                                int offsetYIdx = ((b * (2 * numKernelPositions) + kernelPosIdx) * outputHeight + oh) * outputWidth + ow;
                                int offsetXIdx = ((b * (2 * numKernelPositions) + numKernelPositions + kernelPosIdx) * outputHeight + oh) * outputWidth + ow;

                                double offsetY = numOps.ToDouble(offsetData[offsetYIdx]);
                                double offsetX = numOps.ToDouble(offsetData[offsetXIdx]);

                                // Base sampling position + learned offset
                                double sampledH = oh * strideH - padH + kh * dilationH + offsetY;
                                double sampledW = ow * strideW - padW + kw * dilationW + offsetX;

                                // Bilinear interpolation
                                T sampledValue = BilinearSample(inputData, b, ic, inChannels, height, width, sampledH, sampledW, numOps);

                                // Apply modulation mask (DCNv2)
                                if (maskData != null)
                                {
                                    int maskIdx = ((b * numKernelPositions + kernelPosIdx) * outputHeight + oh) * outputWidth + ow;
                                    sampledValue = numOps.Multiply(sampledValue, maskData[maskIdx]);
                                }

                                // Multiply by kernel weight
                                int kernelIdx = ((oc * inChannels + ic) * kernelHeight + kh) * kernelWidth + kw;
                                sum = numOps.Add(sum, numOps.Multiply(sampledValue, kernelData[kernelIdx]));
                            }
                        }
                    }

                    int outputIdx = ((b * outChannels + oc) * outputHeight + oh) * outputWidth + ow;
                    outputData[outputIdx] = sum;
                }
            }
        });

        // Tape registration — only DCN v1 (mask null) for now. DCN v2 with
        // modulation mask isn't yet wired; rather than silently drop dL on
        // training paths that pass a mask, fail fast so the caller knows to
        // either disable autograd for this op or wait for v2 wiring.
        if (mask is null)
        {
            DifferentiableOps.RecordIfActive("DeformableConv2D", result,
                new[] { input, kernel, offset },
                BackwardFunctions<T>.DeformableConv2DBackward,
                new object[] { (int[])stride.Clone(), (int[])padding.Clone(), (int[])dilation.Clone() });
        }
        else if (DifferentiableOps.IsTapeActiveForThread<T>())
        {
            throw new NotSupportedException(
                "DeformableConv2D autograd with a modulation mask (DCN v2) is not yet wired. " +
                "Either pass mask=null (DCN v1) or wrap the call in a NoGradScope<T>() to opt out " +
                "of autograd for this op.");
        }
        return result;
    }

    /// <summary>
    /// Performs bilinear sampling at a fractional position.
    /// </summary>
    private static T BilinearSample<T>(
        T[] data,
        int batch,
        int channel,
        int totalChannels,
        int height,
        int width,
        double h,
        double w,
        INumericOperations<T> numOps)
    {
        // Out of bounds check
        if (h < -1 || h > height || w < -1 || w > width)
            return numOps.Zero;

        int h0 = (int)Math.Floor(h);
        int h1 = h0 + 1;
        int w0 = (int)Math.Floor(w);
        int w1 = w0 + 1;

        double lh = h - h0; // Lerp factor for height
        double lw = w - w0; // Lerp factor for width

        T v00 = GetPixelValue(data, batch, channel, totalChannels, height, width, h0, w0, numOps);
        T v01 = GetPixelValue(data, batch, channel, totalChannels, height, width, h0, w1, numOps);
        T v10 = GetPixelValue(data, batch, channel, totalChannels, height, width, h1, w0, numOps);
        T v11 = GetPixelValue(data, batch, channel, totalChannels, height, width, h1, w1, numOps);

        // Bilinear interpolation: (1-lh)*(1-lw)*v00 + (1-lh)*lw*v01 + lh*(1-lw)*v10 + lh*lw*v11
        double w00 = (1 - lh) * (1 - lw);
        double w01 = (1 - lh) * lw;
        double w10 = lh * (1 - lw);
        double w11 = lh * lw;

        T result = numOps.Multiply(v00, numOps.FromDouble(w00));
        result = numOps.Add(result, numOps.Multiply(v01, numOps.FromDouble(w01)));
        result = numOps.Add(result, numOps.Multiply(v10, numOps.FromDouble(w10)));
        result = numOps.Add(result, numOps.Multiply(v11, numOps.FromDouble(w11)));

        return result;
    }

    /// <summary>
    /// Gets a pixel value with boundary checking (returns zero for out-of-bounds).
    /// </summary>
    private static T GetPixelValue<T>(
        T[] data,
        int batch,
        int channel,
        int totalChannels,
        int height,
        int width,
        int h,
        int w,
        INumericOperations<T> numOps)
    {
        if (h < 0 || h >= height || w < 0 || w >= width)
            return numOps.Zero;

        int idx = ((batch * totalChannels + channel) * height + h) * width + w;
        return data[idx];
    }

    /// <inheritdoc/>
    public Tensor<T> DeformableConv2DBackwardInput<T>(
        Tensor<T> gradOutput,
        Tensor<T> input,
        Tensor<T> kernel,
        Tensor<T> offset,
        Tensor<T>? mask,
        int[] inputShape,
        int[] stride,
        int[] padding,
        int[] dilation)
    {
        if (gradOutput == null) throw new ArgumentNullException(nameof(gradOutput));
        if (input == null) throw new ArgumentNullException(nameof(input));
        if (kernel == null) throw new ArgumentNullException(nameof(kernel));
        if (offset == null) throw new ArgumentNullException(nameof(offset));

        var numOps = MathHelper.GetNumericOperations<T>();

        int batch = inputShape[0];
        int inChannels = inputShape[1];
        int height = inputShape[2];
        int width = inputShape[3];

        int outChannels = kernel._shape[0];
        int kernelHeight = kernel._shape[2];
        int kernelWidth = kernel._shape[3];

        int strideH = stride[0], strideW = stride[1];
        int padH = padding[0], padW = padding[1];
        int dilationH = dilation[0], dilationW = dilation[1];

        int outputHeight = gradOutput._shape[2];
        int outputWidth = gradOutput._shape[3];
        int numKernelPositions = kernelHeight * kernelWidth;

        var gradInput = AutoTensorCache.RentOrAllocate<T>(inputShape);
        var gradInputData = gradInput.GetDataArray();
        var gradOutputData = gradOutput.GetDataArray();
        var kernelData = kernel.GetDataArray();
        var offsetData = offset.GetDataArray();
        var maskData = mask?.GetDataArray();

        // Use a lock array to avoid race conditions during atomic adds
        var locks = new object[batch * inChannels * height * width];
        for (int i = 0; i < locks.Length; i++) locks[i] = new object();

        Parallel.For(0, batch * outChannels, idx =>
        {
            int b = idx / outChannels;
            int oc = idx % outChannels;

            for (int oh = 0; oh < outputHeight; oh++)
            {
                for (int ow = 0; ow < outputWidth; ow++)
                {
                    int gradOutIdx = ((b * outChannels + oc) * outputHeight + oh) * outputWidth + ow;
                    T gradOutVal = gradOutputData[gradOutIdx];

                    for (int ic = 0; ic < inChannels; ic++)
                    {
                        for (int kh = 0; kh < kernelHeight; kh++)
                        {
                            for (int kw = 0; kw < kernelWidth; kw++)
                            {
                                int kernelPosIdx = kh * kernelWidth + kw;
                                int kernelIdx = ((oc * inChannels + ic) * kernelHeight + kh) * kernelWidth + kw;

                                // Get offsets
                                int offsetYIdx = ((b * (2 * numKernelPositions) + kernelPosIdx) * outputHeight + oh) * outputWidth + ow;
                                int offsetXIdx = ((b * (2 * numKernelPositions) + numKernelPositions + kernelPosIdx) * outputHeight + oh) * outputWidth + ow;

                                double offsetY = numOps.ToDouble(offsetData[offsetYIdx]);
                                double offsetX = numOps.ToDouble(offsetData[offsetXIdx]);

                                double sampledH = oh * strideH - padH + kh * dilationH + offsetY;
                                double sampledW = ow * strideW - padW + kw * dilationW + offsetX;

                                // Get modulation mask
                                T modulation = numOps.One;
                                if (maskData != null)
                                {
                                    int maskIdx = ((b * numKernelPositions + kernelPosIdx) * outputHeight + oh) * outputWidth + ow;
                                    modulation = maskData[maskIdx];
                                }

                                // Gradient multiplied by kernel weight and modulation
                                T gradVal = numOps.Multiply(numOps.Multiply(gradOutVal, kernelData[kernelIdx]), modulation);

                                // Distribute gradient to the 4 neighboring pixels using bilinear weights
                                BilinearBackwardInput(gradInputData, gradVal, b, ic, inChannels, height, width, sampledH, sampledW, numOps, locks);
                            }
                        }
                    }
                }
            }
        });

        return gradInput;
    }

    /// <summary>
    /// Distributes gradient to input using bilinear interpolation weights.
    /// </summary>
    private static void BilinearBackwardInput<T>(
        T[] gradData,
        T gradVal,
        int batch,
        int channel,
        int totalChannels,
        int height,
        int width,
        double h,
        double w,
        INumericOperations<T> numOps,
        object[] locks)
    {
        if (h <= -1 || h >= height || w <= -1 || w >= width)
            return;

        int h0 = (int)Math.Floor(h);
        int h1 = h0 + 1;
        int w0 = (int)Math.Floor(w);
        int w1 = w0 + 1;

        double lh = h - h0;
        double lw = w - w0;

        double w00 = (1 - lh) * (1 - lw);
        double w01 = (1 - lh) * lw;
        double w10 = lh * (1 - lw);
        double w11 = lh * lw;

        // Add gradient contributions to each of the 4 corners
        AddGradientToPixel(gradData, gradVal, batch, channel, totalChannels, height, width, h0, w0, w00, numOps, locks);
        AddGradientToPixel(gradData, gradVal, batch, channel, totalChannels, height, width, h0, w1, w01, numOps, locks);
        AddGradientToPixel(gradData, gradVal, batch, channel, totalChannels, height, width, h1, w0, w10, numOps, locks);
        AddGradientToPixel(gradData, gradVal, batch, channel, totalChannels, height, width, h1, w1, w11, numOps, locks);
    }

    /// <summary>
    /// Atomically adds gradient to a pixel position with boundary checking.
    /// </summary>
    private static void AddGradientToPixel<T>(
        T[] gradData,
        T gradVal,
        int batch,
        int channel,
        int totalChannels,
        int height,
        int width,
        int h,
        int w,
        double weight,
        INumericOperations<T> numOps,
        object[] locks)
    {
        if (h < 0 || h >= height || w < 0 || w >= width || Math.Abs(weight) < 1e-10)
            return;

        int idx = ((batch * totalChannels + channel) * height + h) * width + w;
        T contrib = numOps.Multiply(gradVal, numOps.FromDouble(weight));

        lock (locks[idx])
        {
            gradData[idx] = numOps.Add(gradData[idx], contrib);
        }
    }

    /// <inheritdoc/>
    public Tensor<T> DeformableConv2DBackwardKernel<T>(
        Tensor<T> gradOutput,
        Tensor<T> input,
        Tensor<T> offset,
        Tensor<T>? mask,
        int[] kernelShape,
        int[] stride,
        int[] padding,
        int[] dilation)
    {
        if (gradOutput == null) throw new ArgumentNullException(nameof(gradOutput));
        if (input == null) throw new ArgumentNullException(nameof(input));
        if (offset == null) throw new ArgumentNullException(nameof(offset));

        var numOps = MathHelper.GetNumericOperations<T>();

        int batch = input._shape[0];
        int inChannels = input._shape[1];
        int height = input._shape[2];
        int width = input._shape[3];

        int outChannels = kernelShape[0];
        int kernelHeight = kernelShape[2];
        int kernelWidth = kernelShape[3];

        int strideH = stride[0], strideW = stride[1];
        int padH = padding[0], padW = padding[1];
        int dilationH = dilation[0], dilationW = dilation[1];

        int outputHeight = gradOutput._shape[2];
        int outputWidth = gradOutput._shape[3];
        int numKernelPositions = kernelHeight * kernelWidth;

        var gradKernel = AutoTensorCache.RentOrAllocate<T>(kernelShape);
        var gradKernelData = gradKernel.GetDataArray();
        var gradOutputData = gradOutput.GetDataArray();
        var inputData = input.GetDataArray();
        var offsetData = offset.GetDataArray();
        var maskData = mask?.GetDataArray();

        // Use locks for atomic operations on kernel gradients
        var locks = new object[outChannels * inChannels * kernelHeight * kernelWidth];
        for (int i = 0; i < locks.Length; i++) locks[i] = new object();

        Parallel.For(0, batch, b =>
        {
            for (int oc = 0; oc < outChannels; oc++)
            {
                for (int oh = 0; oh < outputHeight; oh++)
                {
                    for (int ow = 0; ow < outputWidth; ow++)
                    {
                        int gradOutIdx = ((b * outChannels + oc) * outputHeight + oh) * outputWidth + ow;
                        T gradOutVal = gradOutputData[gradOutIdx];

                        for (int ic = 0; ic < inChannels; ic++)
                        {
                            for (int kh = 0; kh < kernelHeight; kh++)
                            {
                                for (int kw = 0; kw < kernelWidth; kw++)
                                {
                                    int kernelPosIdx = kh * kernelWidth + kw;
                                    int kernelIdx = ((oc * inChannels + ic) * kernelHeight + kh) * kernelWidth + kw;

                                    // Get offsets
                                    int offsetYIdx = ((b * (2 * numKernelPositions) + kernelPosIdx) * outputHeight + oh) * outputWidth + ow;
                                    int offsetXIdx = ((b * (2 * numKernelPositions) + numKernelPositions + kernelPosIdx) * outputHeight + oh) * outputWidth + ow;

                                    double offsetY = numOps.ToDouble(offsetData[offsetYIdx]);
                                    double offsetX = numOps.ToDouble(offsetData[offsetXIdx]);

                                    double sampledH = oh * strideH - padH + kh * dilationH + offsetY;
                                    double sampledW = ow * strideW - padW + kw * dilationW + offsetX;

                                    // Sample input with bilinear interpolation
                                    T sampledValue = BilinearSample(inputData, b, ic, inChannels, height, width, sampledH, sampledW, numOps);

                                    // Apply modulation mask
                                    if (maskData != null)
                                    {
                                        int maskIdx = ((b * numKernelPositions + kernelPosIdx) * outputHeight + oh) * outputWidth + ow;
                                        sampledValue = numOps.Multiply(sampledValue, maskData[maskIdx]);
                                    }

                                    // gradKernel[oc, ic, kh, kw] += gradOutput * sampledValue
                                    T contrib = numOps.Multiply(gradOutVal, sampledValue);

                                    lock (locks[kernelIdx])
                                    {
                                        gradKernelData[kernelIdx] = numOps.Add(gradKernelData[kernelIdx], contrib);
                                    }
                                }
                            }
                        }
                    }
                }
            }
        });

        return gradKernel;
    }

    /// <inheritdoc/>
    public Tensor<T> DeformableConv2DBackwardOffset<T>(
        Tensor<T> gradOutput,
        Tensor<T> input,
        Tensor<T> kernel,
        Tensor<T> offset,
        Tensor<T>? mask,
        int[] stride,
        int[] padding,
        int[] dilation)
    {
        if (gradOutput == null) throw new ArgumentNullException(nameof(gradOutput));
        if (input == null) throw new ArgumentNullException(nameof(input));
        if (kernel == null) throw new ArgumentNullException(nameof(kernel));
        if (offset == null) throw new ArgumentNullException(nameof(offset));

        // Validate tensor ranks (must be 4D for deformable conv)
        if (gradOutput.Rank != 4) throw new ArgumentException($"DeformableConv2DBackwardOffset requires 4D gradOutput tensor. Got rank {gradOutput.Rank}.", nameof(gradOutput));
        if (input.Rank != 4) throw new ArgumentException($"DeformableConv2DBackwardOffset requires 4D input tensor. Got rank {input.Rank}.", nameof(input));
        if (kernel.Rank != 4) throw new ArgumentException($"DeformableConv2DBackwardOffset requires 4D kernel tensor. Got rank {kernel.Rank}.", nameof(kernel));
        if (offset.Rank != 4) throw new ArgumentException($"DeformableConv2DBackwardOffset requires 4D offset tensor. Got rank {offset.Rank}.", nameof(offset));
        if (mask != null && mask.Rank != 4) throw new ArgumentException($"DeformableConv2DBackwardOffset requires 4D mask tensor. Got rank {mask.Rank}.", nameof(mask));

        // Validate parameter arrays
        if (stride == null || stride.Length != 2) throw new ArgumentException("Stride must be array of 2 elements.", nameof(stride));
        if (padding == null || padding.Length != 2) throw new ArgumentException("Padding must be array of 2 elements.", nameof(padding));
        if (dilation == null || dilation.Length != 2) throw new ArgumentException("Dilation must be array of 2 elements.", nameof(dilation));

        var numOps = MathHelper.GetNumericOperations<T>();

        int batch = input._shape[0];
        int inChannels = input._shape[1];
        int height = input._shape[2];
        int width = input._shape[3];

        // Validate batch consistency
        if (gradOutput._shape[0] != batch) throw new ArgumentException($"Batch size mismatch: input has {batch}, gradOutput has {gradOutput._shape[0]}.", nameof(gradOutput));
        if (offset._shape[0] != batch) throw new ArgumentException($"Batch size mismatch: input has {batch}, offset has {offset._shape[0]}.", nameof(offset));
        if (mask != null && mask._shape[0] != batch) throw new ArgumentException($"Batch size mismatch: input has {batch}, mask has {mask._shape[0]}.", nameof(mask));

        int outChannels = kernel._shape[0];
        int kernelHeight = kernel._shape[2];
        int kernelWidth = kernel._shape[3];

        int strideH = stride[0], strideW = stride[1];
        int padH = padding[0], padW = padding[1];
        int dilationH = dilation[0], dilationW = dilation[1];

        int outputHeight = gradOutput._shape[2];
        int outputWidth = gradOutput._shape[3];
        int numKernelPositions = kernelHeight * kernelWidth;

        var gradOffset = AutoTensorCache.RentOrAllocate<T>(offset._shape);
        var gradOffsetData = gradOffset.GetDataArray();
        var gradOutputData = gradOutput.GetDataArray();
        var inputData = input.GetDataArray();
        var kernelData = kernel.GetDataArray();
        var offsetData = offset.GetDataArray();
        var maskData = mask?.GetDataArray();

        Parallel.For(0, batch, b =>
        {
            for (int oh = 0; oh < outputHeight; oh++)
            {
                for (int ow = 0; ow < outputWidth; ow++)
                {
                    for (int kh = 0; kh < kernelHeight; kh++)
                    {
                        for (int kw = 0; kw < kernelWidth; kw++)
                        {
                            int kernelPosIdx = kh * kernelWidth + kw;

                            // Get current offsets
                            int offsetYIdx = ((b * (2 * numKernelPositions) + kernelPosIdx) * outputHeight + oh) * outputWidth + ow;
                            int offsetXIdx = ((b * (2 * numKernelPositions) + numKernelPositions + kernelPosIdx) * outputHeight + oh) * outputWidth + ow;

                            double offsetY = numOps.ToDouble(offsetData[offsetYIdx]);
                            double offsetX = numOps.ToDouble(offsetData[offsetXIdx]);

                            double sampledH = oh * strideH - padH + kh * dilationH + offsetY;
                            double sampledW = ow * strideW - padW + kw * dilationW + offsetX;

                            // Get modulation mask
                            T modulation = numOps.One;
                            if (maskData != null)
                            {
                                int maskIdx = ((b * numKernelPositions + kernelPosIdx) * outputHeight + oh) * outputWidth + ow;
                                modulation = maskData[maskIdx];
                            }

                            // Compute gradient w.r.t. offset by chain rule through bilinear interpolation
                            // d(output)/d(offsetY) = sum over (oc, ic) of gradOutput * kernel * d(bilinear)/d(h)
                            // d(output)/d(offsetX) = sum over (oc, ic) of gradOutput * kernel * d(bilinear)/d(w)

                            T gradOffsetY = numOps.Zero;
                            T gradOffsetX = numOps.Zero;

                            for (int oc = 0; oc < outChannels; oc++)
                            {
                                int gradOutIdx = ((b * outChannels + oc) * outputHeight + oh) * outputWidth + ow;
                                T gradOutVal = gradOutputData[gradOutIdx];

                                for (int ic = 0; ic < inChannels; ic++)
                                {
                                    int kernelIdx = ((oc * inChannels + ic) * kernelHeight + kh) * kernelWidth + kw;
                                    T kernelWeight = kernelData[kernelIdx];

                                    // Compute d(bilinear)/d(h) and d(bilinear)/d(w)
                                    var (dH, dW) = BilinearGradient(inputData, b, ic, inChannels, height, width, sampledH, sampledW, numOps);

                                    // Chain rule: gradOutput * kernel * modulation * d(bilinear)/d(offset)
                                    T factor = numOps.Multiply(numOps.Multiply(gradOutVal, kernelWeight), modulation);
                                    gradOffsetY = numOps.Add(gradOffsetY, numOps.Multiply(factor, dH));
                                    gradOffsetX = numOps.Add(gradOffsetX, numOps.Multiply(factor, dW));
                                }
                            }

                            gradOffsetData[offsetYIdx] = gradOffsetY;
                            gradOffsetData[offsetXIdx] = gradOffsetX;
                        }
                    }
                }
            }
        });

        return gradOffset;
    }

    /// <summary>
    /// Computes the gradient of bilinear interpolation w.r.t. sampling position.
    /// </summary>
    private static (T gradH, T gradW) BilinearGradient<T>(
        T[] data,
        int batch,
        int channel,
        int totalChannels,
        int height,
        int width,
        double h,
        double w,
        INumericOperations<T> numOps)
    {
        // Out of bounds - no gradient
        if (h <= -1 || h >= height || w <= -1 || w >= width)
            return (numOps.Zero, numOps.Zero);

        int h0 = (int)Math.Floor(h);
        int h1 = h0 + 1;
        int w0 = (int)Math.Floor(w);
        int w1 = w0 + 1;

        double lh = h - h0;
        double lw = w - w0;

        T v00 = GetPixelValue(data, batch, channel, totalChannels, height, width, h0, w0, numOps);
        T v01 = GetPixelValue(data, batch, channel, totalChannels, height, width, h0, w1, numOps);
        T v10 = GetPixelValue(data, batch, channel, totalChannels, height, width, h1, w0, numOps);
        T v11 = GetPixelValue(data, batch, channel, totalChannels, height, width, h1, w1, numOps);

        // d/dh: derivative of bilinear w.r.t. h
        // output = (1-lh)*(1-lw)*v00 + (1-lh)*lw*v01 + lh*(1-lw)*v10 + lh*lw*v11
        // d/dlh = -(1-lw)*v00 - lw*v01 + (1-lw)*v10 + lw*v11
        //       = (1-lw)*(v10 - v00) + lw*(v11 - v01)
        T dH = numOps.Add(
            numOps.Multiply(numOps.FromDouble(1 - lw), numOps.Subtract(v10, v00)),
            numOps.Multiply(numOps.FromDouble(lw), numOps.Subtract(v11, v01)));

        // d/dw: derivative of bilinear w.r.t. w
        // d/dlw = -(1-lh)*v00 + (1-lh)*v01 - lh*v10 + lh*v11
        //       = (1-lh)*(v01 - v00) + lh*(v11 - v10)
        T dW = numOps.Add(
            numOps.Multiply(numOps.FromDouble(1 - lh), numOps.Subtract(v01, v00)),
            numOps.Multiply(numOps.FromDouble(lh), numOps.Subtract(v11, v10)));

        return (dH, dW);
    }

    /// <summary>
    /// Distributes gradient to input using bilinear interpolation weights (NHWC layout).
    /// </summary>
    private static void BilinearBackwardInputNHWC<T>(
        T[] gradData,
        T gradVal,
        int batch,
        int channel,
        int height,
        int width,
        int channels,
        double h,
        double w,
        INumericOperations<T> numOps,
        object[] locks)
    {
        if (h <= -1 || h >= height || w <= -1 || w >= width)
            return;

        int h0 = (int)Math.Floor(h);
        int h1 = h0 + 1;
        int w0 = (int)Math.Floor(w);
        int w1 = w0 + 1;

        double lh = h - h0;
        double lw = w - w0;

        double w00 = (1 - lh) * (1 - lw);
        double w01 = (1 - lh) * lw;
        double w10 = lh * (1 - lw);
        double w11 = lh * lw;

        // Add gradient contributions to each of the 4 corners (NHWC layout)
        AddGradientToPixelNHWC(gradData, gradVal, batch, channel, height, width, channels, h0, w0, w00, numOps, locks);
        AddGradientToPixelNHWC(gradData, gradVal, batch, channel, height, width, channels, h0, w1, w01, numOps, locks);
        AddGradientToPixelNHWC(gradData, gradVal, batch, channel, height, width, channels, h1, w0, w10, numOps, locks);
        AddGradientToPixelNHWC(gradData, gradVal, batch, channel, height, width, channels, h1, w1, w11, numOps, locks);
    }

    /// <summary>
    /// Atomically adds gradient to a pixel position with boundary checking (NHWC layout).
    /// </summary>
    private static void AddGradientToPixelNHWC<T>(
        T[] gradData,
        T gradVal,
        int batch,
        int channel,
        int height,
        int width,
        int channels,
        int h,
        int w,
        double weight,
        INumericOperations<T> numOps,
        object[] locks)
    {
        if (h < 0 || h >= height || w < 0 || w >= width || Math.Abs(weight) < 1e-10)
            return;

        // NHWC index: [batch, h, w, channel]
        int idx = ((batch * height + h) * width + w) * channels + channel;
        T contrib = numOps.Multiply(gradVal, numOps.FromDouble(weight));

        lock (locks[idx])
        {
            gradData[idx] = numOps.Add(gradData[idx], contrib);
        }
    }

    /// <summary>
    /// Gets a pixel value with boundary checking for NHWC layout (returns zero for out-of-bounds).
    /// </summary>
    private static T GetPixelValueNHWC<T>(
        T[] data,
        int batch,
        int channel,
        int height,
        int width,
        int channels,
        int h,
        int w,
        INumericOperations<T> numOps)
    {
        if (h < 0 || h >= height || w < 0 || w >= width)
            return numOps.Zero;

        // NHWC index: [batch, h, w, channel]
        int idx = ((batch * height + h) * width + w) * channels + channel;
        return data[idx];
    }

    /// <summary>
    /// Computes the gradient of bilinear interpolation w.r.t. sampling position (NHWC layout).
    /// </summary>
    private static (T gradH, T gradW) BilinearGradientNHWC<T>(
        T[] data,
        int batch,
        int channel,
        int height,
        int width,
        int channels,
        double h,
        double w,
        INumericOperations<T> numOps)
    {
        // Out of bounds - no gradient
        if (h <= -1 || h >= height || w <= -1 || w >= width)
            return (numOps.Zero, numOps.Zero);

        int h0 = (int)Math.Floor(h);
        int h1 = h0 + 1;
        int w0 = (int)Math.Floor(w);
        int w1 = w0 + 1;

        double lh = h - h0;
        double lw = w - w0;

        T v00 = GetPixelValueNHWC(data, batch, channel, height, width, channels, h0, w0, numOps);
        T v01 = GetPixelValueNHWC(data, batch, channel, height, width, channels, h0, w1, numOps);
        T v10 = GetPixelValueNHWC(data, batch, channel, height, width, channels, h1, w0, numOps);
        T v11 = GetPixelValueNHWC(data, batch, channel, height, width, channels, h1, w1, numOps);

        // d/dh: derivative of bilinear w.r.t. h
        T dH = numOps.Add(
            numOps.Multiply(numOps.FromDouble(1 - lw), numOps.Subtract(v10, v00)),
            numOps.Multiply(numOps.FromDouble(lw), numOps.Subtract(v11, v01)));

        // d/dw: derivative of bilinear w.r.t. w
        T dW = numOps.Add(
            numOps.Multiply(numOps.FromDouble(1 - lh), numOps.Subtract(v01, v00)),
            numOps.Multiply(numOps.FromDouble(lh), numOps.Subtract(v11, v10)));

        return (dH, dW);
    }

    /// <inheritdoc/>
    public Tensor<T> DeformableConv2DBackwardMask<T>(
        Tensor<T> gradOutput,
        Tensor<T> input,
        Tensor<T> kernel,
        Tensor<T> offset,
        Tensor<T>? mask,
        int[] stride,
        int[] padding,
        int[] dilation)
    {
        if (gradOutput == null) throw new ArgumentNullException(nameof(gradOutput));
        if (input == null) throw new ArgumentNullException(nameof(input));
        if (kernel == null) throw new ArgumentNullException(nameof(kernel));
        if (offset == null) throw new ArgumentNullException(nameof(offset));

        // Validate tensor ranks (must be 4D for deformable conv)
        if (gradOutput.Rank != 4) throw new ArgumentException($"DeformableConv2DBackwardMask requires 4D gradOutput tensor. Got rank {gradOutput.Rank}.", nameof(gradOutput));
        if (input.Rank != 4) throw new ArgumentException($"DeformableConv2DBackwardMask requires 4D input tensor. Got rank {input.Rank}.", nameof(input));
        if (kernel.Rank != 4) throw new ArgumentException($"DeformableConv2DBackwardMask requires 4D kernel tensor. Got rank {kernel.Rank}.", nameof(kernel));
        if (offset.Rank != 4) throw new ArgumentException($"DeformableConv2DBackwardMask requires 4D offset tensor. Got rank {offset.Rank}.", nameof(offset));
        if (mask != null && mask.Rank != 4) throw new ArgumentException($"DeformableConv2DBackwardMask requires 4D mask tensor. Got rank {mask.Rank}.", nameof(mask));

        // Validate parameter arrays
        if (stride == null || stride.Length != 2) throw new ArgumentException("Stride must be array of 2 elements.", nameof(stride));
        if (padding == null || padding.Length != 2) throw new ArgumentException("Padding must be array of 2 elements.", nameof(padding));
        if (dilation == null || dilation.Length != 2) throw new ArgumentException("Dilation must be array of 2 elements.", nameof(dilation));

        var numOps = MathHelper.GetNumericOperations<T>();

        int batch = input._shape[0];
        int inChannels = input._shape[1];
        int height = input._shape[2];
        int width = input._shape[3];

        // Validate batch consistency
        if (gradOutput._shape[0] != batch) throw new ArgumentException($"Batch size mismatch: input has {batch}, gradOutput has {gradOutput._shape[0]}.", nameof(gradOutput));
        if (offset._shape[0] != batch) throw new ArgumentException($"Batch size mismatch: input has {batch}, offset has {offset._shape[0]}.", nameof(offset));
        if (mask != null && mask._shape[0] != batch) throw new ArgumentException($"Batch size mismatch: input has {batch}, mask has {mask._shape[0]}.", nameof(mask));

        int outChannels = kernel._shape[0];
        int kernelHeight = kernel._shape[2];
        int kernelWidth = kernel._shape[3];

        int strideH = stride[0], strideW = stride[1];
        int padH = padding[0], padW = padding[1];
        int dilationH = dilation[0], dilationW = dilation[1];

        int outputHeight = gradOutput._shape[2];
        int outputWidth = gradOutput._shape[3];
        int numKernelPositions = kernelHeight * kernelWidth;

        // Mask shape: [batch, kernel_h*kernel_w, out_h, out_w]
        var gradMask = TensorAllocator.Rent<T>([batch, numKernelPositions, outputHeight, outputWidth]);
        var gradMaskData = gradMask.GetDataArray();
        var gradOutputData = gradOutput.GetDataArray();
        var inputData = input.GetDataArray();
        var kernelData = kernel.GetDataArray();
        var offsetData = offset.GetDataArray();

        Parallel.For(0, batch, b =>
        {
            for (int oh = 0; oh < outputHeight; oh++)
            {
                for (int ow = 0; ow < outputWidth; ow++)
                {
                    for (int kh = 0; kh < kernelHeight; kh++)
                    {
                        for (int kw = 0; kw < kernelWidth; kw++)
                        {
                            int kernelPosIdx = kh * kernelWidth + kw;
                            int maskIdx = ((b * numKernelPositions + kernelPosIdx) * outputHeight + oh) * outputWidth + ow;

                            // Get offsets
                            int offsetYIdx = ((b * (2 * numKernelPositions) + kernelPosIdx) * outputHeight + oh) * outputWidth + ow;
                            int offsetXIdx = ((b * (2 * numKernelPositions) + numKernelPositions + kernelPosIdx) * outputHeight + oh) * outputWidth + ow;

                            double offsetY = numOps.ToDouble(offsetData[offsetYIdx]);
                            double offsetX = numOps.ToDouble(offsetData[offsetXIdx]);

                            double sampledH = oh * strideH - padH + kh * dilationH + offsetY;
                            double sampledW = ow * strideW - padW + kw * dilationW + offsetX;

                            // d(output)/d(mask[b,k,oh,ow]) = sum over (oc, ic) of gradOutput * kernel * sampledValue
                            T gradMaskVal = numOps.Zero;

                            for (int oc = 0; oc < outChannels; oc++)
                            {
                                int gradOutIdx = ((b * outChannels + oc) * outputHeight + oh) * outputWidth + ow;
                                T gradOutVal = gradOutputData[gradOutIdx];

                                for (int ic = 0; ic < inChannels; ic++)
                                {
                                    int kernelIdx = ((oc * inChannels + ic) * kernelHeight + kh) * kernelWidth + kw;
                                    T kernelWeight = kernelData[kernelIdx];

                                    // Sample input
                                    T sampledValue = BilinearSample(inputData, b, ic, inChannels, height, width, sampledH, sampledW, numOps);

                                    gradMaskVal = numOps.Add(gradMaskVal, numOps.Multiply(numOps.Multiply(gradOutVal, kernelWeight), sampledValue));
                                }
                            }

                            gradMaskData[maskIdx] = gradMaskVal;
                        }
                    }
                }
            }
        });

        return gradMask;
    }

    #endregion

    #region Grid Sample Backward Operations

    /// <inheritdoc/>
    public Tensor<T> GridSampleBackwardInput<T>(Tensor<T> gradOutput, Tensor<T> grid, int[] inputShape)
    {
        if (gradOutput == null) throw new ArgumentNullException(nameof(gradOutput));
        if (grid == null) throw new ArgumentNullException(nameof(grid));
        var gradOutputOrig = gradOutput;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!gradOutput.IsContiguous) gradOutput = gradOutput.Contiguous();
        var gridOrig = grid;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!grid.IsContiguous) grid = grid.Contiguous();
        if (inputShape == null || inputShape.Length != 4) throw new ArgumentException("inputShape must be array of 4 elements [batch, height, width, channels].", nameof(inputShape));

        // Validate tensor ranks for NHWC layout
        if (gradOutput.Rank != 4) throw new ArgumentException($"GridSampleBackwardInput requires 4D gradOutput tensor (NHWC). Got rank {gradOutput.Rank}.", nameof(gradOutput));
        if (grid.Rank != 4) throw new ArgumentException($"GridSampleBackwardInput requires 4D grid tensor [batch, outH, outW, 2]. Got rank {grid.Rank}.", nameof(grid));

        var numOps = MathHelper.GetNumericOperations<T>();

        // NHWC layout: [batch, height, width, channels]
        int batch = inputShape[0];
        int height = inputShape[1];
        int width = inputShape[2];
        int channels = inputShape[3];

        int outHeight = grid._shape[1];
        int outWidth = grid._shape[2];

        // Validate shape consistency
        if (grid._shape[0] != batch) throw new ArgumentException($"Batch size mismatch: inputShape has {batch}, grid has {grid._shape[0]}.", nameof(grid));
        if (grid._shape[3] != 2) throw new ArgumentException($"Grid last dimension must be 2 (x,y coordinates). Got {grid._shape[3]}.", nameof(grid));
        if (gradOutput._shape[0] != batch) throw new ArgumentException($"Batch size mismatch: inputShape has {batch}, gradOutput has {gradOutput._shape[0]}.", nameof(gradOutput));
        if (gradOutput._shape[1] != outHeight || gradOutput._shape[2] != outWidth)
            throw new ArgumentException($"gradOutput spatial dims [{gradOutput._shape[1]},{gradOutput._shape[2]}] must match grid spatial dims [{outHeight},{outWidth}].", nameof(gradOutput));
        if (gradOutput._shape[3] != channels) throw new ArgumentException($"Channel mismatch: inputShape has {channels}, gradOutput has {gradOutput._shape[3]}.", nameof(gradOutput));

        var gradInput = AutoTensorCache.RentOrAllocate<T>(inputShape);
        var gradInputData = gradInput.GetDataArray();
        var gradOutputData = gradOutput.GetDataArray();
        var gridData = grid.GetDataArray();

        // Use locks for atomic addition - NHWC layout
        var locks = new object[batch * height * width * channels];
        for (int i = 0; i < locks.Length; i++) locks[i] = new object();

        Parallel.For(0, batch, b =>
        {
            for (int oh = 0; oh < outHeight; oh++)
            {
                for (int ow = 0; ow < outWidth; ow++)
                {
                    // Get normalized grid coordinates
                    int gridBaseIdx = ((b * outHeight + oh) * outWidth + ow) * 2;
                    double gx = numOps.ToDouble(gridData[gridBaseIdx]);
                    double gy = numOps.ToDouble(gridData[gridBaseIdx + 1]);

                    // Convert to pixel coordinates
                    double srcH = (gy + 1) / 2 * (height - 1);
                    double srcW = (gx + 1) / 2 * (width - 1);

                    // Distribute gradient for all channels using NHWC bilinear weights
                    for (int c = 0; c < channels; c++)
                    {
                        // NHWC gradOutput index: [b, oh, ow, c]
                        int gradOutIdx = ((b * outHeight + oh) * outWidth + ow) * channels + c;
                        T gradVal = gradOutputData[gradOutIdx];

                        BilinearBackwardInputNHWC(gradInputData, gradVal, b, c, height, width, channels, srcH, srcW, numOps, locks);
                    }
                }
            }
        });

        return gradInput;
    }

    /// <inheritdoc/>
    public Tensor<T> GridSampleBackwardGrid<T>(Tensor<T> gradOutput, Tensor<T> input, Tensor<T> grid)
    {
        if (gradOutput == null) throw new ArgumentNullException(nameof(gradOutput));
        if (input == null) throw new ArgumentNullException(nameof(input));
        if (grid == null) throw new ArgumentNullException(nameof(grid));
        var gridOrig = grid;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!grid.IsContiguous) grid = grid.Contiguous();
        var inputOrig = input;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!input.IsContiguous) input = input.Contiguous();
        var gradOutputOrig = gradOutput;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!gradOutput.IsContiguous) gradOutput = gradOutput.Contiguous();

        // Validate tensor ranks for NHWC layout
        if (gradOutput.Rank != 4) throw new ArgumentException($"GridSampleBackwardGrid requires 4D gradOutput tensor (NHWC). Got rank {gradOutput.Rank}.", nameof(gradOutput));
        if (input.Rank != 4) throw new ArgumentException($"GridSampleBackwardGrid requires 4D input tensor (NHWC). Got rank {input.Rank}.", nameof(input));
        if (grid.Rank != 4) throw new ArgumentException($"GridSampleBackwardGrid requires 4D grid tensor [batch, outH, outW, 2]. Got rank {grid.Rank}.", nameof(grid));

        var numOps = MathHelper.GetNumericOperations<T>();

        // NHWC layout: [batch, height, width, channels]
        int batch = input._shape[0];
        int height = input._shape[1];
        int width = input._shape[2];
        int channels = input._shape[3];

        int outHeight = grid._shape[1];
        int outWidth = grid._shape[2];

        // Validate shape consistency
        if (grid._shape[0] != batch) throw new ArgumentException($"Batch size mismatch: input has {batch}, grid has {grid._shape[0]}.", nameof(grid));
        if (grid._shape[3] != 2) throw new ArgumentException($"Grid last dimension must be 2 (x,y coordinates). Got {grid._shape[3]}.", nameof(grid));
        if (gradOutput._shape[0] != batch) throw new ArgumentException($"Batch size mismatch: input has {batch}, gradOutput has {gradOutput._shape[0]}.", nameof(gradOutput));
        if (gradOutput._shape[1] != outHeight || gradOutput._shape[2] != outWidth)
            throw new ArgumentException($"gradOutput spatial dims [{gradOutput._shape[1]},{gradOutput._shape[2]}] must match grid spatial dims [{outHeight},{outWidth}].", nameof(gradOutput));
        if (gradOutput._shape[3] != channels) throw new ArgumentException($"Channel mismatch: input has {channels}, gradOutput has {gradOutput._shape[3]}.", nameof(gradOutput));

        var gradGrid = AutoTensorCache.RentOrAllocate<T>(grid._shape);
        var gradGridData = gradGrid.GetDataArray();
        var gradOutputData = gradOutput.GetDataArray();
        var inputData = input.GetDataArray();
        var gridData = grid.GetDataArray();

        Parallel.For(0, batch, b =>
        {
            for (int oh = 0; oh < outHeight; oh++)
            {
                for (int ow = 0; ow < outWidth; ow++)
                {
                    int gridBaseIdx = ((b * outHeight + oh) * outWidth + ow) * 2;
                    double gx = numOps.ToDouble(gridData[gridBaseIdx]);
                    double gy = numOps.ToDouble(gridData[gridBaseIdx + 1]);

                    // Convert to pixel coordinates
                    double srcH = (gy + 1) / 2 * (height - 1);
                    double srcW = (gx + 1) / 2 * (width - 1);

                    // Compute d(output)/d(gx) and d(output)/d(gy) by summing over all channels
                    T gradGx = numOps.Zero;
                    T gradGy = numOps.Zero;

                    for (int c = 0; c < channels; c++)
                    {
                        // NHWC gradOutput index: [b, oh, ow, c]
                        int gradOutIdx = ((b * outHeight + oh) * outWidth + ow) * channels + c;
                        T gradOutVal = gradOutputData[gradOutIdx];

                        // Get gradient of bilinear sampling w.r.t. h and w using NHWC layout
                        var (dH, dW) = BilinearGradientNHWC(inputData, b, c, height, width, channels, srcH, srcW, numOps);

                        // Chain rule: d/dgx = d/dw * dw/dgx where dw/dgx = (width-1)/2
                        // Chain rule: d/dgy = d/dh * dh/dgy where dh/dgy = (height-1)/2
                        T scaledDW = numOps.Multiply(dW, numOps.FromDouble((width - 1) / 2.0));
                        T scaledDH = numOps.Multiply(dH, numOps.FromDouble((height - 1) / 2.0));

                        gradGx = numOps.Add(gradGx, numOps.Multiply(gradOutVal, scaledDW));
                        gradGy = numOps.Add(gradGy, numOps.Multiply(gradOutVal, scaledDH));
                    }

                    gradGridData[gridBaseIdx] = gradGx;
                    gradGridData[gridBaseIdx + 1] = gradGy;
                }
            }
        });

        return gradGrid;
    }

    #endregion

    #region 3D Convolution and Pooling Operations

    /// <inheritdoc/>
    public virtual Tensor<T> Conv3D<T>(Tensor<T> input, Tensor<T> kernel, int stride = 1, int padding = 0, int dilation = 1)
    {
        return Conv3D(input, kernel, [stride, stride, stride], [padding, padding, padding], [dilation, dilation, dilation]);
    }

    /// <inheritdoc/>
    public Tensor<T> Conv3D<T>(Tensor<T> input, Tensor<T> kernel, int[] stride, int[] padding, int[] dilation)
    {
        if (input == null) throw new ArgumentNullException(nameof(input));
        if (kernel == null) throw new ArgumentNullException(nameof(kernel));
        if (input.Rank != 5) throw new ArgumentException($"Conv3D requires 5D input tensor [batch, in_channels, depth, height, width]. Got rank {input.Rank}.", nameof(input));
        if (kernel.Rank != 5) throw new ArgumentException($"Conv3D requires 5D kernel tensor [out_channels, in_channels, kernel_depth, kernel_height, kernel_width]. Got rank {kernel.Rank}.", nameof(kernel));
        if (stride == null || stride.Length != 3) throw new ArgumentException("Stride must be array of 3 elements [strideD, strideH, strideW].", nameof(stride));
        if (stride[0] <= 0 || stride[1] <= 0 || stride[2] <= 0) throw new ArgumentException("Stride elements must be positive.", nameof(stride));
        if (padding == null || padding.Length != 3) throw new ArgumentException("Padding must be array of 3 elements [padD, padH, padW].", nameof(padding));
        if (dilation == null || dilation.Length != 3) throw new ArgumentException("Dilation must be array of 3 elements [dilationD, dilationH, dilationW].", nameof(dilation));
        if (dilation[0] <= 0 || dilation[1] <= 0 || dilation[2] <= 0) throw new ArgumentException("Dilation elements must be positive.", nameof(dilation));
        if (input._shape[1] != kernel._shape[1]) throw new ArgumentException($"Input channels ({input._shape[1]}) must match kernel in_channels ({kernel._shape[1]}).");

        if (GraphMode.IsActive)
        {
            var scope = GraphMode.Current;
            if (scope != null)
            {
                int effKD = dilation[0] * (kernel._shape[2] - 1) + 1;
                int effKH = dilation[1] * (kernel._shape[3] - 1) + 1;
                int effKW = dilation[2] * (kernel._shape[4] - 1) + 1;
                int oD = (input._shape[2] + 2 * padding[0] - effKD) / stride[0] + 1;
                int oH = (input._shape[3] + 2 * padding[1] - effKH) / stride[1] + 1;
                int oW = (input._shape[4] + 2 * padding[2] - effKW) / stride[2] + 1;
                var outShape = new[] { input._shape[0], kernel._shape[0], oD, oH, oW };
                var capturedInput = input;
                var capturedKernel = kernel;
                var capturedStride = stride;
                var capturedPadding = padding;
                var capturedDilation = dilation;
                return scope.RecordBinary(LazyNodeType.Custom, "Conv3D", input, kernel, outShape,
                    (eng, output) => { var r = eng.Conv3D(capturedInput, capturedKernel, capturedStride, capturedPadding, capturedDilation); r.AsSpan().CopyTo(output.AsWritableSpan()); },
                    BackwardFunctions<T>.Conv3DBackward, new object[] { stride, padding, dilation });
            }
        }

        { var ac = AutoTracer.TryGetCompiledPlan<T>("Conv3D", input._shape); if (ac is not null) return ac.Execute(); }

        int strideD = stride[0], strideH = stride[1], strideW = stride[2];
        int padD = padding[0], padH = padding[1], padW = padding[2];
        int dilationD = dilation[0], dilationH = dilation[1], dilationW = dilation[2];

        var numOps = MathHelper.GetNumericOperations<T>();

        int batch = input._shape[0];
        int inChannels = input._shape[1];
        int depth = input._shape[2];
        int height = input._shape[3];
        int width = input._shape[4];

        int outChannels = kernel._shape[0];
        int kernelDepth = kernel._shape[2];
        int kernelHeight = kernel._shape[3];
        int kernelWidth = kernel._shape[4];

        int effectiveKernelD = dilationD * (kernelDepth - 1) + 1;
        int effectiveKernelH = dilationH * (kernelHeight - 1) + 1;
        int effectiveKernelW = dilationW * (kernelWidth - 1) + 1;

        int outputDepth = (depth + 2 * padD - effectiveKernelD) / strideD + 1;
        int outputHeight = (height + 2 * padH - effectiveKernelH) / strideH + 1;
        int outputWidth = (width + 2 * padW - effectiveKernelW) / strideW + 1;

        if (outputDepth <= 0 || outputHeight <= 0 || outputWidth <= 0)
        {
            throw new ArgumentException(
                $"Invalid output dimensions ({outputDepth}x{outputHeight}x{outputWidth}). " +
                $"Check kernel size, stride, padding, and dilation parameters for input size {depth}x{height}x{width}.");
        }

        var result = TensorAllocator.Rent<T>([batch, outChannels, outputDepth, outputHeight, outputWidth]);
        var inputData = input.GetDataArray();
        var kernelData = kernel.GetDataArray();
        var outputData = result.GetDataArray();

        // Parallel over batch * outChannels for maximum parallelism
        Parallel.For(0, batch * outChannels, idx =>
        {
            int b = idx / outChannels;
            int oc = idx % outChannels;

            for (int od = 0; od < outputDepth; od++)
            {
                for (int oh = 0; oh < outputHeight; oh++)
                {
                    for (int ow = 0; ow < outputWidth; ow++)
                    {
                        T sum = numOps.Zero;

                        for (int ic = 0; ic < inChannels; ic++)
                        {
                            for (int kd = 0; kd < kernelDepth; kd++)
                            {
                                int id = od * strideD + kd * dilationD - padD;
                                if (id < 0 || id >= depth) continue;

                                for (int kh = 0; kh < kernelHeight; kh++)
                                {
                                    int ih = oh * strideH + kh * dilationH - padH;
                                    if (ih < 0 || ih >= height) continue;

                                    for (int kw = 0; kw < kernelWidth; kw++)
                                    {
                                        int iw = ow * strideW + kw * dilationW - padW;
                                        if (iw < 0 || iw >= width) continue;

                                        int inputIdx = (((b * inChannels + ic) * depth + id) * height + ih) * width + iw;
                                        int kernelIdx = (((oc * inChannels + ic) * kernelDepth + kd) * kernelHeight + kh) * kernelWidth + kw;
                                        sum = numOps.Add(sum, numOps.Multiply(inputData[inputIdx], kernelData[kernelIdx]));
                                    }
                                }
                            }
                        }

                        int outputIdx = (((b * outChannels + oc) * outputDepth + od) * outputHeight + oh) * outputWidth + ow;
                        outputData[outputIdx] = sum;
                    }
                }
            }
        });

        DifferentiableOps.RecordBinary("Conv3D", result, input, kernel, BackwardFunctions<T>.Conv3DBackward,
            new object[] { stride, padding, dilation });
        AutoTracer.RecordOp("Conv3D", result, eng => result);
        return result;
    }

    /// <inheritdoc/>
    public Tensor<T> Conv3DBackwardInput<T>(Tensor<T> gradOutput, Tensor<T> kernel, int[] inputShape, int[] stride, int[] padding, int[] dilation)
    {
        if (gradOutput == null) throw new ArgumentNullException(nameof(gradOutput));
        if (kernel == null) throw new ArgumentNullException(nameof(kernel));
        if (inputShape == null || inputShape.Length != 5) throw new ArgumentException("Input shape must be array of 5 elements [batch, in_channels, depth, height, width].", nameof(inputShape));
        if (stride == null || stride.Length != 3) throw new ArgumentException("Stride must be array of 3 elements.", nameof(stride));
        if (padding == null || padding.Length != 3) throw new ArgumentException("Padding must be array of 3 elements.", nameof(padding));
        if (dilation == null || dilation.Length != 3) throw new ArgumentException("Dilation must be array of 3 elements.", nameof(dilation));

        // Rank and shape validation
        if (gradOutput.Rank != 5) throw new ArgumentException($"Conv3DBackwardInput requires 5D gradOutput tensor. Got rank {gradOutput.Rank}.", nameof(gradOutput));
        if (kernel.Rank != 5) throw new ArgumentException($"Conv3DBackwardInput requires 5D kernel tensor. Got rank {kernel.Rank}.", nameof(kernel));

        var numOps = MathHelper.GetNumericOperations<T>();

        int batch = inputShape[0];
        int inChannels = inputShape[1];
        int depth = inputShape[2];
        int height = inputShape[3];
        int width = inputShape[4];

        int outChannels = kernel._shape[0];
        int kernelDepth = kernel._shape[2];
        int kernelHeight = kernel._shape[3];
        int kernelWidth = kernel._shape[4];

        // Validate shape consistency
        if (gradOutput._shape[0] != batch)
            throw new ArgumentException($"gradOutput batch size ({gradOutput._shape[0]}) must match inputShape batch size ({batch}).", nameof(gradOutput));
        if (gradOutput._shape[1] != outChannels)
            throw new ArgumentException($"gradOutput outChannels ({gradOutput._shape[1]}) must match kernel out_channels ({outChannels}).", nameof(gradOutput));
        if (inputShape[1] != kernel._shape[1])
            throw new ArgumentException($"inputShape in_channels ({inputShape[1]}) must match kernel in_channels ({kernel._shape[1]}).", nameof(inputShape));

        int strideD = stride[0], strideH = stride[1], strideW = stride[2];
        int padD = padding[0], padH = padding[1], padW = padding[2];
        int dilationD = dilation[0], dilationH = dilation[1], dilationW = dilation[2];

        int outputDepth = gradOutput._shape[2];
        int outputHeight = gradOutput._shape[3];
        int outputWidth = gradOutput._shape[4];

        var gradInputData = new T[batch * inChannels * depth * height * width];
        var gradOutputData = gradOutput.GetDataArray();
        var kernelData = kernel.GetDataArray();

        // Primitive fast paths for float/double. Parallel over (batch, inChannels)
        // pairs — each pair owns a disjoint gradInput slice, so direct writes
        // are race-free without thread-local buffers. Explicit Array.Clear keeps
        // intent clear and stays correct if the buffer source ever switches from
        // `new T[]` to TensorAllocator.RentUninitialized.
        if (typeof(T) == typeof(float))
        {
            var fGradOut = (float[])(object)gradOutputData;
            var fKernel = (float[])(object)kernelData;
            var fGradInput = (float[])(object)gradInputData;
            Array.Clear(fGradInput, 0, fGradInput.Length);
            Parallel.For(0, batch * inChannels, idx =>
            {
                int b = idx / inChannels;
                int ic = idx % inChannels;
                for (int oc = 0; oc < outChannels; oc++)
                {
                    for (int od = 0; od < outputDepth; od++)
                    {
                        for (int oh = 0; oh < outputHeight; oh++)
                        {
                            for (int ow = 0; ow < outputWidth; ow++)
                            {
                                int gradOutIdx = (((b * outChannels + oc) * outputDepth + od) * outputHeight + oh) * outputWidth + ow;
                                float gradVal = fGradOut[gradOutIdx];
                                for (int kd = 0; kd < kernelDepth; kd++)
                                {
                                    int id = od * strideD + kd * dilationD - padD;
                                    if (id < 0 || id >= depth) continue;
                                    for (int kh = 0; kh < kernelHeight; kh++)
                                    {
                                        int ih = oh * strideH + kh * dilationH - padH;
                                        if (ih < 0 || ih >= height) continue;
                                        for (int kw = 0; kw < kernelWidth; kw++)
                                        {
                                            int iw = ow * strideW + kw * dilationW - padW;
                                            if (iw < 0 || iw >= width) continue;
                                            int inputIdx = (((b * inChannels + ic) * depth + id) * height + ih) * width + iw;
                                            int kernelIdx = (((oc * inChannels + ic) * kernelDepth + kd) * kernelHeight + kh) * kernelWidth + kw;
                                            fGradInput[inputIdx] += gradVal * fKernel[kernelIdx];
                                        }
                                    }
                                }
                            }
                        }
                    }
                }
            });
        }
        else if (typeof(T) == typeof(double))
        {
            var dGradOut = (double[])(object)gradOutputData;
            var dKernel = (double[])(object)kernelData;
            var dGradInput = (double[])(object)gradInputData;
            Array.Clear(dGradInput, 0, dGradInput.Length);
            Parallel.For(0, batch * inChannels, idx =>
            {
                int b = idx / inChannels;
                int ic = idx % inChannels;
                for (int oc = 0; oc < outChannels; oc++)
                {
                    for (int od = 0; od < outputDepth; od++)
                    {
                        for (int oh = 0; oh < outputHeight; oh++)
                        {
                            for (int ow = 0; ow < outputWidth; ow++)
                            {
                                int gradOutIdx = (((b * outChannels + oc) * outputDepth + od) * outputHeight + oh) * outputWidth + ow;
                                double gradVal = dGradOut[gradOutIdx];
                                for (int kd = 0; kd < kernelDepth; kd++)
                                {
                                    int id = od * strideD + kd * dilationD - padD;
                                    if (id < 0 || id >= depth) continue;
                                    for (int kh = 0; kh < kernelHeight; kh++)
                                    {
                                        int ih = oh * strideH + kh * dilationH - padH;
                                        if (ih < 0 || ih >= height) continue;
                                        for (int kw = 0; kw < kernelWidth; kw++)
                                        {
                                            int iw = ow * strideW + kw * dilationW - padW;
                                            if (iw < 0 || iw >= width) continue;
                                            int inputIdx = (((b * inChannels + ic) * depth + id) * height + ih) * width + iw;
                                            int kernelIdx = (((oc * inChannels + ic) * kernelDepth + kd) * kernelHeight + kh) * kernelWidth + kw;
                                            dGradInput[inputIdx] += gradVal * dKernel[kernelIdx];
                                        }
                                    }
                                }
                            }
                        }
                    }
                }
            });
        }
        else
        {
            for (int i = 0; i < gradInputData.Length; i++)
                gradInputData[i] = numOps.Zero;

            Parallel.For(0, batch * inChannels, idx =>
            {
                int b = idx / inChannels;
                int ic = idx % inChannels;

                for (int oc = 0; oc < outChannels; oc++)
                {
                    for (int od = 0; od < outputDepth; od++)
                    {
                        for (int oh = 0; oh < outputHeight; oh++)
                        {
                            for (int ow = 0; ow < outputWidth; ow++)
                            {
                                int gradOutIdx = (((b * outChannels + oc) * outputDepth + od) * outputHeight + oh) * outputWidth + ow;
                                T gradVal = gradOutputData[gradOutIdx];

                                for (int kd = 0; kd < kernelDepth; kd++)
                                {
                                    int id = od * strideD + kd * dilationD - padD;
                                    if (id < 0 || id >= depth) continue;

                                    for (int kh = 0; kh < kernelHeight; kh++)
                                    {
                                        int ih = oh * strideH + kh * dilationH - padH;
                                        if (ih < 0 || ih >= height) continue;

                                        for (int kw = 0; kw < kernelWidth; kw++)
                                        {
                                            int iw = ow * strideW + kw * dilationW - padW;
                                            if (iw < 0 || iw >= width) continue;

                                            int inputIdx = (((b * inChannels + ic) * depth + id) * height + ih) * width + iw;
                                            int kernelIdx = (((oc * inChannels + ic) * kernelDepth + kd) * kernelHeight + kh) * kernelWidth + kw;
                                            gradInputData[inputIdx] = numOps.Add(gradInputData[inputIdx], numOps.Multiply(gradVal, kernelData[kernelIdx]));
                                        }
                                    }
                                }
                            }
                        }
                    }
                }
            });
        }

        return TensorAllocator.Rent<T>(inputShape, new Vector<T>(gradInputData));
    }

    /// <inheritdoc/>
    public Tensor<T> Conv3DBackwardKernel<T>(Tensor<T> gradOutput, Tensor<T> input, int[] kernelShape, int[] stride, int[] padding, int[] dilation)
    {
        if (gradOutput == null) throw new ArgumentNullException(nameof(gradOutput));
        if (input == null) throw new ArgumentNullException(nameof(input));
        if (kernelShape == null || kernelShape.Length != 5) throw new ArgumentException("Kernel shape must be array of 5 elements [out_channels, in_channels, kernel_depth, kernel_height, kernel_width].", nameof(kernelShape));
        if (stride == null || stride.Length != 3) throw new ArgumentException("Stride must be array of 3 elements.", nameof(stride));
        if (padding == null || padding.Length != 3) throw new ArgumentException("Padding must be array of 3 elements.", nameof(padding));
        if (dilation == null || dilation.Length != 3) throw new ArgumentException("Dilation must be array of 3 elements.", nameof(dilation));

        // Rank and shape validation
        if (gradOutput.Rank != 5) throw new ArgumentException($"Conv3DBackwardKernel requires 5D gradOutput tensor. Got rank {gradOutput.Rank}.", nameof(gradOutput));
        if (input.Rank != 5) throw new ArgumentException($"Conv3DBackwardKernel requires 5D input tensor. Got rank {input.Rank}.", nameof(input));

        var numOps = MathHelper.GetNumericOperations<T>();

        int batch = input._shape[0];
        int inChannels = input._shape[1];
        int depth = input._shape[2];
        int height = input._shape[3];
        int width = input._shape[4];

        int outChannels = kernelShape[0];
        int kernelDepth = kernelShape[2];
        int kernelHeight = kernelShape[3];
        int kernelWidth = kernelShape[4];

        // Validate shape consistency
        if (gradOutput._shape[0] != batch)
            throw new ArgumentException($"gradOutput batch size ({gradOutput._shape[0]}) must match input batch size ({batch}).", nameof(gradOutput));
        if (gradOutput._shape[1] != outChannels)
            throw new ArgumentException($"gradOutput outChannels ({gradOutput._shape[1]}) must match kernelShape out_channels ({outChannels}).", nameof(gradOutput));
        if (input._shape[1] != kernelShape[1])
            throw new ArgumentException($"input in_channels ({input._shape[1]}) must match kernelShape in_channels ({kernelShape[1]}).", nameof(input));

        int strideD = stride[0], strideH = stride[1], strideW = stride[2];
        int padD = padding[0], padH = padding[1], padW = padding[2];
        int dilationD = dilation[0], dilationH = dilation[1], dilationW = dilation[2];

        int outputDepth = gradOutput._shape[2];
        int outputHeight = gradOutput._shape[3];
        int outputWidth = gradOutput._shape[4];

        var gradKernelData = new T[outChannels * inChannels * kernelDepth * kernelHeight * kernelWidth];
        var gradOutputData = gradOutput.GetDataArray();
        var inputData = input.GetDataArray();

        // Primitive fast paths — each (oc, ic) pair owns a disjoint kernel slice.
        if (typeof(T) == typeof(float))
        {
            var fGradOut = (float[])(object)gradOutputData;
            var fInput = (float[])(object)inputData;
            var fGradKernel = (float[])(object)gradKernelData;
            Parallel.For(0, outChannels * inChannels, idx =>
            {
                int oc = idx / inChannels;
                int ic = idx % inChannels;
                for (int kd = 0; kd < kernelDepth; kd++)
                {
                    for (int kh = 0; kh < kernelHeight; kh++)
                    {
                        for (int kw = 0; kw < kernelWidth; kw++)
                        {
                            float sum = 0f;
                            for (int b = 0; b < batch; b++)
                            {
                                for (int od = 0; od < outputDepth; od++)
                                {
                                    int id = od * strideD + kd * dilationD - padD;
                                    if (id < 0 || id >= depth) continue;
                                    for (int oh = 0; oh < outputHeight; oh++)
                                    {
                                        int ih = oh * strideH + kh * dilationH - padH;
                                        if (ih < 0 || ih >= height) continue;
                                        for (int ow = 0; ow < outputWidth; ow++)
                                        {
                                            int iw = ow * strideW + kw * dilationW - padW;
                                            if (iw < 0 || iw >= width) continue;
                                            int gradOutIdx = (((b * outChannels + oc) * outputDepth + od) * outputHeight + oh) * outputWidth + ow;
                                            int inputIdx = (((b * inChannels + ic) * depth + id) * height + ih) * width + iw;
                                            sum += fGradOut[gradOutIdx] * fInput[inputIdx];
                                        }
                                    }
                                }
                            }
                            int kernelIdx = (((oc * inChannels + ic) * kernelDepth + kd) * kernelHeight + kh) * kernelWidth + kw;
                            fGradKernel[kernelIdx] = sum;
                        }
                    }
                }
            });
        }
        else if (typeof(T) == typeof(double))
        {
            var dGradOut = (double[])(object)gradOutputData;
            var dInput = (double[])(object)inputData;
            var dGradKernel = (double[])(object)gradKernelData;
            Parallel.For(0, outChannels * inChannels, idx =>
            {
                int oc = idx / inChannels;
                int ic = idx % inChannels;
                for (int kd = 0; kd < kernelDepth; kd++)
                {
                    for (int kh = 0; kh < kernelHeight; kh++)
                    {
                        for (int kw = 0; kw < kernelWidth; kw++)
                        {
                            double sum = 0.0;
                            for (int b = 0; b < batch; b++)
                            {
                                for (int od = 0; od < outputDepth; od++)
                                {
                                    int id = od * strideD + kd * dilationD - padD;
                                    if (id < 0 || id >= depth) continue;
                                    for (int oh = 0; oh < outputHeight; oh++)
                                    {
                                        int ih = oh * strideH + kh * dilationH - padH;
                                        if (ih < 0 || ih >= height) continue;
                                        for (int ow = 0; ow < outputWidth; ow++)
                                        {
                                            int iw = ow * strideW + kw * dilationW - padW;
                                            if (iw < 0 || iw >= width) continue;
                                            int gradOutIdx = (((b * outChannels + oc) * outputDepth + od) * outputHeight + oh) * outputWidth + ow;
                                            int inputIdx = (((b * inChannels + ic) * depth + id) * height + ih) * width + iw;
                                            sum += dGradOut[gradOutIdx] * dInput[inputIdx];
                                        }
                                    }
                                }
                            }
                            int kernelIdx = (((oc * inChannels + ic) * kernelDepth + kd) * kernelHeight + kh) * kernelWidth + kw;
                            dGradKernel[kernelIdx] = sum;
                        }
                    }
                }
            });
        }
        else
        {
            for (int i = 0; i < gradKernelData.Length; i++)
                gradKernelData[i] = numOps.Zero;

            Parallel.For(0, outChannels * inChannels, idx =>
            {
                int oc = idx / inChannels;
                int ic = idx % inChannels;

                for (int kd = 0; kd < kernelDepth; kd++)
                {
                    for (int kh = 0; kh < kernelHeight; kh++)
                    {
                        for (int kw = 0; kw < kernelWidth; kw++)
                        {
                            T sum = numOps.Zero;

                            for (int b = 0; b < batch; b++)
                            {
                                for (int od = 0; od < outputDepth; od++)
                                {
                                    int id = od * strideD + kd * dilationD - padD;
                                    if (id < 0 || id >= depth) continue;

                                    for (int oh = 0; oh < outputHeight; oh++)
                                    {
                                        int ih = oh * strideH + kh * dilationH - padH;
                                        if (ih < 0 || ih >= height) continue;

                                        for (int ow = 0; ow < outputWidth; ow++)
                                        {
                                            int iw = ow * strideW + kw * dilationW - padW;
                                            if (iw < 0 || iw >= width) continue;

                                            int gradOutIdx = (((b * outChannels + oc) * outputDepth + od) * outputHeight + oh) * outputWidth + ow;
                                            int inputIdx = (((b * inChannels + ic) * depth + id) * height + ih) * width + iw;
                                            sum = numOps.Add(sum, numOps.Multiply(gradOutputData[gradOutIdx], inputData[inputIdx]));
                                        }
                                    }
                                }
                            }

                            int kernelIdx = (((oc * inChannels + ic) * kernelDepth + kd) * kernelHeight + kh) * kernelWidth + kw;
                            gradKernelData[kernelIdx] = sum;
                        }
                    }
                }
            });
        }

        return TensorAllocator.Rent<T>(kernelShape, new Vector<T>(gradKernelData));
    }

    /// <inheritdoc/>
    public Tensor<T> MaxPool3D<T>(Tensor<T> input, int poolSize, int stride = 0, int padding = 0)
    {
        if (stride == 0) stride = poolSize;
        return MaxPool3D(input, [poolSize, poolSize, poolSize], [stride, stride, stride], [padding, padding, padding]);
    }

    /// <inheritdoc/>
    public Tensor<T> MaxPool3D<T>(Tensor<T> input, int[] poolSize, int[] stride, int[] padding)
    {
        if (input == null) throw new ArgumentNullException(nameof(input));

        // GraphMode recording was missing here — without it, MaxPool3D runs
        // eagerly under a GraphMode scope and its output never makes it into
        // the compiled plan. ONNX-imported 3D MaxPool plans had the final
        // tensor buffer always zero because no step produced it.
        if (GraphMode.IsActive)
        {
            var scope = GraphMode.Current;
            if (scope != null)
            {
                if (input.Rank != 5) throw new ArgumentException($"MaxPool3D requires 5D input; got rank {input.Rank}.", nameof(input));
                if (poolSize == null || poolSize.Length != 3) throw new ArgumentException("Pool size must have 3 elements.", nameof(poolSize));
                if (stride == null || stride.Length != 3) throw new ArgumentException("Stride must have 3 elements.", nameof(stride));
                if (padding == null || padding.Length != 3) throw new ArgumentException("Padding must have 3 elements.", nameof(padding));

                int outD = (input._shape[2] + 2 * padding[0] - poolSize[0]) / stride[0] + 1;
                int outH = (input._shape[3] + 2 * padding[1] - poolSize[1]) / stride[1] + 1;
                int outW = (input._shape[4] + 2 * padding[2] - poolSize[2]) / stride[2] + 1;
                var outShape = new[] { input._shape[0], input._shape[1], outD, outH, outW };
                var capturedInput = input;
                var capturedPool = poolSize;
                var capturedStride = stride;
                var capturedPadding = padding;
                return scope.RecordUnary(LazyNodeType.Custom, "MaxPool3D", input, outShape,
                    (eng, output) => { var r = eng.MaxPool3D(capturedInput, capturedPool, capturedStride, capturedPadding); r.AsSpan().CopyTo(output.AsWritableSpan()); },
                    backwardFn: null, savedState: new object[] { capturedPool, capturedStride, capturedPadding });
            }
        }

        // Tape-aware path: dispatch through MaxPool3DWithIndices, which
        // already records on the tape with MaxPool3DBackward. Costs an
        // int[,,,,,] index array (one int per output element) but unlocks
        // gradient flow through 3D max-pool — without this, dL/dInput was
        // silently zero after MaxPool3D in any tape-tracked model.
        if (DifferentiableOps.IsTapeActiveForThread<T>())
        {
            return MaxPool3DWithIndices(input, poolSize, stride, out _);
        }

        return MaxPool3DCore(input, poolSize, stride, padding);
    }

    /// <summary>
    /// Core implementation of MaxPool3D without index tracking for simple forward pass.
    /// </summary>
    private Tensor<T> MaxPool3DCore<T>(Tensor<T> input, int[] poolSize, int[] stride, int[] padding)
    {
        if (input == null) throw new ArgumentNullException(nameof(input));
        if (input.Rank != 5) throw new ArgumentException($"MaxPool3D requires 5D input tensor [batch, channels, depth, height, width]. Got rank {input.Rank}.", nameof(input));
        if (poolSize == null || poolSize.Length != 3) throw new ArgumentException("Pool size must be array of 3 elements [poolD, poolH, poolW].", nameof(poolSize));
        if (stride == null || stride.Length != 3) throw new ArgumentException("Stride must be array of 3 elements [strideD, strideH, strideW].", nameof(stride));
        if (padding == null || padding.Length != 3) throw new ArgumentException("Padding must be array of 3 elements [padD, padH, padW].", nameof(padding));

        var numOps = MathHelper.GetNumericOperations<T>();

        int batch = input._shape[0];
        int channels = input._shape[1];
        int depth = input._shape[2];
        int height = input._shape[3];
        int width = input._shape[4];

        int poolD = poolSize[0], poolH = poolSize[1], poolW = poolSize[2];
        int strideD = stride[0], strideH = stride[1], strideW = stride[2];
        int padD = padding[0], padH = padding[1], padW = padding[2];

        int outputDepth = (depth + 2 * padD - poolD) / strideD + 1;
        int outputHeight = (height + 2 * padH - poolH) / strideH + 1;
        int outputWidth = (width + 2 * padW - poolW) / strideW + 1;

        if (outputDepth <= 0 || outputHeight <= 0 || outputWidth <= 0)
        {
            throw new ArgumentException(
                $"Invalid output dimensions ({outputDepth}x{outputHeight}x{outputWidth}). " +
                $"Check pool size, stride, and padding parameters for input size {depth}x{height}x{width}.");
        }

        var result = TensorAllocator.Rent<T>([batch, channels, outputDepth, outputHeight, outputWidth]);
        var inputData = input.GetDataArray();
        var outputData = result.GetDataArray();

        // Parallel over batch * channels
        Parallel.For(0, batch * channels, idx =>
        {
            int b = idx / channels;
            int c = idx % channels;

            for (int od = 0; od < outputDepth; od++)
            {
                for (int oh = 0; oh < outputHeight; oh++)
                {
                    for (int ow = 0; ow < outputWidth; ow++)
                    {
                        T maxVal = numOps.MinValue;
                        bool foundValid = false;

                        for (int pd = 0; pd < poolD; pd++)
                        {
                            int id = od * strideD + pd - padD;
                            if (id < 0 || id >= depth) continue;

                            for (int ph = 0; ph < poolH; ph++)
                            {
                                int ih = oh * strideH + ph - padH;
                                if (ih < 0 || ih >= height) continue;

                                for (int pw = 0; pw < poolW; pw++)
                                {
                                    int iw = ow * strideW + pw - padW;
                                    if (iw < 0 || iw >= width) continue;

                                    int inputIdx = (((b * channels + c) * depth + id) * height + ih) * width + iw;
                                    T val = inputData[inputIdx];
                                    if (!foundValid || numOps.GreaterThan(val, maxVal))
                                    {
                                        maxVal = val;
                                        foundValid = true;
                                    }
                                }
                            }
                        }

                        int outputIdx = (((b * channels + c) * outputDepth + od) * outputHeight + oh) * outputWidth + ow;
                        outputData[outputIdx] = foundValid ? maxVal : numOps.Zero;
                    }
                }
            }
        });

        return result;
    }

    /// <inheritdoc/>
    public Tensor<T> MaxPool3DWithIndices<T>(Tensor<T> input, int[] poolSize, int[] stride, out int[,,,,,] maxIndices)
    {
        if (input == null) throw new ArgumentNullException(nameof(input));
        if (input.Rank != 5) throw new ArgumentException($"MaxPool3D requires 5D input tensor [batch, channels, depth, height, width]. Got rank {input.Rank}.", nameof(input));
        if (poolSize == null || poolSize.Length != 3) throw new ArgumentException("Pool size must be array of 3 elements [poolD, poolH, poolW].", nameof(poolSize));
        if (stride == null || stride.Length != 3) throw new ArgumentException("Stride must be array of 3 elements [strideD, strideH, strideW].", nameof(stride));

        var numOps = MathHelper.GetNumericOperations<T>();

        int batch = input._shape[0];
        int channels = input._shape[1];
        int depth = input._shape[2];
        int height = input._shape[3];
        int width = input._shape[4];

        int poolD = poolSize[0], poolH = poolSize[1], poolW = poolSize[2];
        int strideD = stride[0], strideH = stride[1], strideW = stride[2];

        int outputDepth = (depth - poolD) / strideD + 1;
        int outputHeight = (height - poolH) / strideH + 1;
        int outputWidth = (width - poolW) / strideW + 1;

        if (outputDepth <= 0 || outputHeight <= 0 || outputWidth <= 0)
        {
            throw new ArgumentException(
                $"Invalid output dimensions ({outputDepth}x{outputHeight}x{outputWidth}). " +
                $"Check pool size and stride parameters for input size {depth}x{height}x{width}.");
        }

        var result = TensorAllocator.Rent<T>([batch, channels, outputDepth, outputHeight, outputWidth]);
        var inputData = input.GetFlattenedData();
        var outputData = result.GetDataArray();
        var localMaxIndices = new int[batch, channels, outputDepth, outputHeight, outputWidth, 3];

        // Parallel over batch * channels
        Parallel.For(0, batch * channels, idx =>
        {
            int b = idx / channels;
            int c = idx % channels;

            for (int od = 0; od < outputDepth; od++)
            {
                for (int oh = 0; oh < outputHeight; oh++)
                {
                    for (int ow = 0; ow < outputWidth; ow++)
                    {
                        T maxVal = numOps.MinValue;
                        int maxId = 0, maxIh = 0, maxIw = 0;
                        bool foundValid = false;

                        for (int pd = 0; pd < poolD; pd++)
                        {
                            int id = od * strideD + pd;
                            if (id >= depth) continue;

                            for (int ph = 0; ph < poolH; ph++)
                            {
                                int ih = oh * strideH + ph;
                                if (ih >= height) continue;

                                for (int pw = 0; pw < poolW; pw++)
                                {
                                    int iw = ow * strideW + pw;
                                    if (iw >= width) continue;

                                    int inputIdx = (((b * channels + c) * depth + id) * height + ih) * width + iw;
                                    T val = inputData[inputIdx];
                                    if (!foundValid || numOps.GreaterThan(val, maxVal))
                                    {
                                        maxVal = val;
                                        maxId = id;
                                        maxIh = ih;
                                        maxIw = iw;
                                        foundValid = true;
                                    }
                                }
                            }
                        }

                        int outputIdx = (((b * channels + c) * outputDepth + od) * outputHeight + oh) * outputWidth + ow;
                        outputData[outputIdx] = foundValid ? maxVal : numOps.Zero;
                        localMaxIndices[b, c, od, oh, ow, 0] = maxId;
                        localMaxIndices[b, c, od, oh, ow, 1] = maxIh;
                        localMaxIndices[b, c, od, oh, ow, 2] = maxIw;
                    }
                }
            }
        });

        maxIndices = localMaxIndices;
        DifferentiableOps.RecordUnary("MaxPool3DWithIndices", result, input, BackwardFunctions<T>.MaxPool3DBackward, new object[] { maxIndices, poolSize, stride });
        { var ci = input; var cp = poolSize; var cs = stride; AutoTracer.RecordOp("MaxPool3DWithIndices", result, eng => { eng.MaxPool3DWithIndices(ci, cp, cs, out _); return result; }); }
        return result;
    }

    /// <inheritdoc/>
    public Tensor<T> MaxPool3DBackward<T>(Tensor<T> gradOutput, int[,,,,,] maxIndices, int[] inputShape, int[] poolSize, int[] stride)
    {
        if (gradOutput == null) throw new ArgumentNullException(nameof(gradOutput));
        if (maxIndices == null) throw new ArgumentNullException(nameof(maxIndices));
        if (inputShape == null || inputShape.Length != 5) throw new ArgumentException("Input shape must be array of 5 elements [batch, channels, depth, height, width].", nameof(inputShape));

        var numOps = MathHelper.GetNumericOperations<T>();

        int batch = inputShape[0];
        int channels = inputShape[1];
        int depth = inputShape[2];
        int height = inputShape[3];
        int width = inputShape[4];

        int outputDepth = gradOutput._shape[2];
        int outputHeight = gradOutput._shape[3];
        int outputWidth = gradOutput._shape[4];

        var gradInputData = new T[batch * channels * depth * height * width];
        var gradOutputData = gradOutput.GetFlattenedData();

        // Initialize to zero
        for (int i = 0; i < gradInputData.Length; i++)
            gradInputData[i] = numOps.Zero;

        // Parallel over batch * channels - each (b, c) pair writes to a unique slice of gradInputData
        // so no thread-local buffers are needed (avoiding racy thread-ID based indexing)
        Parallel.For(0, batch * channels, idx =>
        {
            int b = idx / channels;
            int c = idx % channels;

            for (int od = 0; od < outputDepth; od++)
            {
                for (int oh = 0; oh < outputHeight; oh++)
                {
                    for (int ow = 0; ow < outputWidth; ow++)
                    {
                        int gradOutIdx = (((b * channels + c) * outputDepth + od) * outputHeight + oh) * outputWidth + ow;
                        T gradVal = gradOutputData[gradOutIdx];

                        int id = maxIndices[b, c, od, oh, ow, 0];
                        int ih = maxIndices[b, c, od, oh, ow, 1];
                        int iw = maxIndices[b, c, od, oh, ow, 2];

                        int inputIdx = (((b * channels + c) * depth + id) * height + ih) * width + iw;
                        gradInputData[inputIdx] = numOps.Add(gradInputData[inputIdx], gradVal);
                    }
                }
            }
        });

        return TensorAllocator.Rent<T>(inputShape, new Vector<T>(gradInputData));
    }

    /// <inheritdoc/>
    public Tensor<T> AvgPool3D<T>(Tensor<T> input, int poolSize, int stride = 0, int padding = 0)
    {
        var inputOrig = input;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!input.IsContiguous) input = input.Contiguous();
        if (stride == 0) stride = poolSize;
        return AvgPool3D(input, [poolSize, poolSize, poolSize], [stride, stride, stride], [padding, padding, padding]);
    }

    /// <inheritdoc/>
    public Tensor<T> AvgPool3D<T>(Tensor<T> input, int[] poolSize, int[] stride, int[] padding)
    {
        if (input == null) throw new ArgumentNullException(nameof(input));

        // Mirror the MaxPool3D GraphMode-recording fix — without this, 3D
        // avg-pool outputs are zero in a compiled plan.
        if (GraphMode.IsActive)
        {
            var scope = GraphMode.Current;
            if (scope != null)
            {
                // Validate parameters BEFORE indexing into them to avoid
                // IndexOutOfRange on malformed inputs. Mirrors the eager-path
                // validation below.
                if (input.Rank != 5) throw new ArgumentException($"AvgPool3D requires 5D input; got rank {input.Rank}.", nameof(input));
                if (poolSize == null || poolSize.Length != 3) throw new ArgumentException("Pool size must be array of 3 elements [poolD, poolH, poolW].", nameof(poolSize));
                if (stride == null || stride.Length != 3) throw new ArgumentException("Stride must be array of 3 elements [strideD, strideH, strideW].", nameof(stride));
                if (padding == null || padding.Length != 3) throw new ArgumentException("Padding must be array of 3 elements [padD, padH, padW].", nameof(padding));
                int outD = (input._shape[2] + 2 * padding[0] - poolSize[0]) / stride[0] + 1;
                int outH = (input._shape[3] + 2 * padding[1] - poolSize[1]) / stride[1] + 1;
                int outW = (input._shape[4] + 2 * padding[2] - poolSize[2]) / stride[2] + 1;
                var outShape = new[] { input._shape[0], input._shape[1], outD, outH, outW };
                var capturedInput = input;
                var capturedPool = poolSize;
                var capturedStride = stride;
                var capturedPadding = padding;
                return scope.RecordUnary(LazyNodeType.Custom, "AvgPool3D", input, outShape,
                    (eng, output) => { var r = eng.AvgPool3D(capturedInput, capturedPool, capturedStride, capturedPadding); r.AsSpan().CopyTo(output.AsWritableSpan()); },
                    backwardFn: null, savedState: new object[] { capturedPool, capturedStride, capturedPadding });
            }
        }
        var inputOrig = input;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!input.IsContiguous) input = input.Contiguous();
        if (input.Rank != 5) throw new ArgumentException($"AvgPool3D requires 5D input tensor [batch, channels, depth, height, width]. Got rank {input.Rank}.", nameof(input));
        if (poolSize == null || poolSize.Length != 3) throw new ArgumentException("Pool size must be array of 3 elements [poolD, poolH, poolW].", nameof(poolSize));
        if (stride == null || stride.Length != 3) throw new ArgumentException("Stride must be array of 3 elements [strideD, strideH, strideW].", nameof(stride));
        if (padding == null || padding.Length != 3) throw new ArgumentException("Padding must be array of 3 elements [padD, padH, padW].", nameof(padding));

        if (GraphMode.IsActive)
        {
            var scope = GraphMode.Current;
            if (scope != null)
            {
                int oD = (input._shape[2] + 2 * padding[0] - poolSize[0]) / stride[0] + 1;
                int oH = (input._shape[3] + 2 * padding[1] - poolSize[1]) / stride[1] + 1;
                int oW = (input._shape[4] + 2 * padding[2] - poolSize[2]) / stride[2] + 1;
                var outShape = new[] { input._shape[0], input._shape[1], oD, oH, oW };
                var captured = input;
                var capturedPool = poolSize;
                var capturedStride = stride;
                var capturedPadding = padding;
                return scope.RecordUnary(LazyNodeType.Custom, "AvgPool3D", input, outShape,
                    (eng, output) => { var r = eng.AvgPool3D(captured, capturedPool, capturedStride, capturedPadding); r.AsSpan().CopyTo(output.AsWritableSpan()); },
                    BackwardFunctions<T>.AvgPool3DBackward, new object[] { poolSize, stride, padding });
            }
        }

        { var ac = AutoTracer.TryGetCompiledPlan<T>("AvgPool3D", input._shape); if (ac is not null) return ac.Execute(); }

        var numOps = MathHelper.GetNumericOperations<T>();

        int batch = input._shape[0];
        int channels = input._shape[1];
        int depth = input._shape[2];
        int height = input._shape[3];
        int width = input._shape[4];

        int poolD = poolSize[0], poolH = poolSize[1], poolW = poolSize[2];
        int strideD = stride[0], strideH = stride[1], strideW = stride[2];
        int padD = padding[0], padH = padding[1], padW = padding[2];

        int outputDepth = (depth + 2 * padD - poolD) / strideD + 1;
        int outputHeight = (height + 2 * padH - poolH) / strideH + 1;
        int outputWidth = (width + 2 * padW - poolW) / strideW + 1;

        if (outputDepth <= 0 || outputHeight <= 0 || outputWidth <= 0)
        {
            throw new ArgumentException(
                $"Invalid output dimensions ({outputDepth}x{outputHeight}x{outputWidth}). " +
                $"Check pool size, stride, and padding parameters for input size {depth}x{height}x{width}.");
        }

        var result = TensorAllocator.Rent<T>([batch, channels, outputDepth, outputHeight, outputWidth]);
        var inputData = input.GetDataArray();
        var outputData = result.GetDataArray();

        // Parallel over batch * channels
        Parallel.For(0, batch * channels, idx =>
        {
            int b = idx / channels;
            int c = idx % channels;

            for (int od = 0; od < outputDepth; od++)
            {
                for (int oh = 0; oh < outputHeight; oh++)
                {
                    for (int ow = 0; ow < outputWidth; ow++)
                    {
                        T sum = numOps.Zero;
                        int count = 0;

                        for (int pd = 0; pd < poolD; pd++)
                        {
                            int id = od * strideD + pd - padD;
                            if (id < 0 || id >= depth) continue;

                            for (int ph = 0; ph < poolH; ph++)
                            {
                                int ih = oh * strideH + ph - padH;
                                if (ih < 0 || ih >= height) continue;

                                for (int pw = 0; pw < poolW; pw++)
                                {
                                    int iw = ow * strideW + pw - padW;
                                    if (iw < 0 || iw >= width) continue;

                                    int inputIdx = (((b * channels + c) * depth + id) * height + ih) * width + iw;
                                    sum = numOps.Add(sum, inputData[inputIdx]);
                                    count++;
                                }
                            }
                        }

                        int outputIdx = (((b * channels + c) * outputDepth + od) * outputHeight + oh) * outputWidth + ow;
                        outputData[outputIdx] = count > 0 ? numOps.Divide(sum, numOps.FromDouble(count)) : numOps.Zero;
                    }
                }
            }
        });

        DifferentiableOps.RecordUnary("AvgPool3D", result, inputOrig, BackwardFunctions<T>.AvgPool3DBackward, new object[] { poolSize, stride, padding });
        AutoTracer.RecordOp("AvgPool3D", result, eng => result);
        return result;
    }

    /// <inheritdoc/>
    public Tensor<T> AvgPool3DBackward<T>(Tensor<T> gradOutput, int[] inputShape, int[] poolSize, int[] stride, int[] padding)
    {
        if (gradOutput == null) throw new ArgumentNullException(nameof(gradOutput));
        if (inputShape == null || inputShape.Length != 5) throw new ArgumentException("Input shape must be array of 5 elements [batch, channels, depth, height, width].", nameof(inputShape));
        if (poolSize == null || poolSize.Length != 3) throw new ArgumentException("Pool size must be array of 3 elements.", nameof(poolSize));
        if (stride == null || stride.Length != 3) throw new ArgumentException("Stride must be array of 3 elements.", nameof(stride));
        if (padding == null || padding.Length != 3) throw new ArgumentException("Padding must be array of 3 elements.", nameof(padding));

        var numOps = MathHelper.GetNumericOperations<T>();

        int batch = inputShape[0];
        int channels = inputShape[1];
        int depth = inputShape[2];
        int height = inputShape[3];
        int width = inputShape[4];

        int poolD = poolSize[0], poolH = poolSize[1], poolW = poolSize[2];
        int strideD = stride[0], strideH = stride[1], strideW = stride[2];
        int padD = padding[0], padH = padding[1], padW = padding[2];

        int outputDepth = gradOutput._shape[2];
        int outputHeight = gradOutput._shape[3];
        int outputWidth = gradOutput._shape[4];

        var gradInputData = new T[batch * channels * depth * height * width];
        var gradOutputData = gradOutput.GetFlattenedData();

        // Initialize to zero
        for (int i = 0; i < gradInputData.Length; i++)
            gradInputData[i] = numOps.Zero;

        // Parallel over batch * channels - each (b, c) pair writes to a unique slice of gradInputData
        // so no thread-local buffers are needed (avoiding racy thread-ID based indexing)
        Parallel.For(0, batch * channels, idx =>
        {
            int b = idx / channels;
            int c = idx % channels;

            for (int od = 0; od < outputDepth; od++)
            {
                for (int oh = 0; oh < outputHeight; oh++)
                {
                    for (int ow = 0; ow < outputWidth; ow++)
                    {
                        // Count valid positions in this pool window
                        int count = 0;
                        for (int pd = 0; pd < poolD; pd++)
                        {
                            int id = od * strideD + pd - padD;
                            if (id < 0 || id >= depth) continue;
                            for (int ph = 0; ph < poolH; ph++)
                            {
                                int ih = oh * strideH + ph - padH;
                                if (ih < 0 || ih >= height) continue;
                                for (int pw = 0; pw < poolW; pw++)
                                {
                                    int iw = ow * strideW + pw - padW;
                                    if (iw < 0 || iw >= width) continue;
                                    count++;
                                }
                            }
                        }

                        if (count == 0) continue;

                        int gradOutIdx = (((b * channels + c) * outputDepth + od) * outputHeight + oh) * outputWidth + ow;
                        T gradVal = numOps.Divide(gradOutputData[gradOutIdx], numOps.FromDouble(count));

                        // Distribute gradient equally to all contributing positions
                        for (int pd = 0; pd < poolD; pd++)
                        {
                            int id = od * strideD + pd - padD;
                            if (id < 0 || id >= depth) continue;

                            for (int ph = 0; ph < poolH; ph++)
                            {
                                int ih = oh * strideH + ph - padH;
                                if (ih < 0 || ih >= height) continue;

                                for (int pw = 0; pw < poolW; pw++)
                                {
                                    int iw = ow * strideW + pw - padW;
                                    if (iw < 0 || iw >= width) continue;

                                    int inputIdx = (((b * channels + c) * depth + id) * height + ih) * width + iw;
                                    gradInputData[inputIdx] = numOps.Add(gradInputData[inputIdx], gradVal);
                                }
                            }
                        }
                    }
                }
            }
        });

        return TensorAllocator.Rent<T>(inputShape, new Vector<T>(gradInputData));
    }

    /// <inheritdoc/>
    public Tensor<T> Upsample3D<T>(Tensor<T> input, int scaleD, int scaleH, int scaleW)
    {
        if (input == null) throw new ArgumentNullException(nameof(input));
        if (input.Rank != 5) throw new ArgumentException($"Upsample3D requires 5D input tensor [batch, channels, depth, height, width]. Got rank {input.Rank}.", nameof(input));
        if (scaleD <= 0 || scaleH <= 0 || scaleW <= 0) throw new ArgumentException("Scale factors must be positive.");

        if (GraphMode.IsActive)
        { var ac = AutoTracer.TryGetCompiledPlan<T>("Upsample3D", input._shape); if (ac is not null) return ac.Execute(); }

        {
            var scope = GraphMode.Current;
            if (scope != null)
            {
                var captured = input;
                int capD = scaleD, capH = scaleH, capW = scaleW;
                var outShape = new[] { input._shape[0], input._shape[1],
                    input._shape[2] * scaleD, input._shape[3] * scaleH, input._shape[4] * scaleW };
                return scope.RecordUnary(LazyNodeType.Custom, "Upsample3D", input, outShape,
                    (eng, output) => { var r = eng.Upsample3D(captured, capD, capH, capW); r.AsSpan().CopyTo(output.AsWritableSpan()); },
                    BackwardFunctions<T>.Upsample3DBackward, new object[] { capD, capH, capW });
            }
        }

        int batch = input._shape[0];
        int channels = input._shape[1];
        int depth = input._shape[2];
        int height = input._shape[3];
        int width = input._shape[4];

        int outDepth = depth * scaleD;
        int outHeight = height * scaleH;
        int outWidth = width * scaleW;

        var outputData = new T[batch * channels * outDepth * outHeight * outWidth];
        var inputData = input.GetFlattenedData();

        // Use parallel processing over batch and channels
        Parallel.For(0, batch * channels, bc =>
        {
            int b = bc / channels;
            int c = bc % channels;

            for (int od = 0; od < outDepth; od++)
            {
                int id = od / scaleD;
                for (int oh = 0; oh < outHeight; oh++)
                {
                    int ih = oh / scaleH;
                    for (int ow = 0; ow < outWidth; ow++)
                    {
                        int iw = ow / scaleW;

                        int inputIdx = (((b * channels + c) * depth + id) * height + ih) * width + iw;
                        int outputIdx = (((b * channels + c) * outDepth + od) * outHeight + oh) * outWidth + ow;
                        outputData[outputIdx] = inputData[inputIdx];
                    }
                }
            }
        });

        var up3dResult = TensorAllocator.Rent<T>([batch, channels, outDepth, outHeight, outWidth], new Vector<T>(outputData));
        DifferentiableOps.RecordUnary("Upsample3D", up3dResult, input, BackwardFunctions<T>.Upsample3DBackward, new object[] { scaleD, scaleH, scaleW });
        AutoTracer.RecordOp("Upsample3D", up3dResult, eng => up3dResult);
        return up3dResult;
    }

    /// <inheritdoc/>
    public Tensor<T> Upsample3DBackward<T>(Tensor<T> gradOutput, int[] inputShape, int scaleD, int scaleH, int scaleW)
    {
        if (gradOutput == null) throw new ArgumentNullException(nameof(gradOutput));
        if (inputShape == null || inputShape.Length != 5) throw new ArgumentException("Input shape must be array of 5 elements [batch, channels, depth, height, width].", nameof(inputShape));
        if (scaleD <= 0 || scaleH <= 0 || scaleW <= 0) throw new ArgumentException("Scale factors must be positive.");

        var numOps = MathHelper.GetNumericOperations<T>();

        int batch = inputShape[0];
        int channels = inputShape[1];
        int depth = inputShape[2];
        int height = inputShape[3];
        int width = inputShape[4];

        int outDepth = depth * scaleD;
        int outHeight = height * scaleH;
        int outWidth = width * scaleW;

        var gradInputData = new T[batch * channels * depth * height * width];
        var gradOutputData = gradOutput.GetFlattenedData();

        // Initialize gradient input to zero
        for (int i = 0; i < gradInputData.Length; i++)
        {
            gradInputData[i] = numOps.Zero;
        }

        // Each (b, c) iteration writes to a disjoint slice of gradInputData,
        // so no synchronization is needed - direct writes are thread-safe
        Parallel.For(0, batch * channels, bc =>
        {
            int b = bc / channels;
            int c = bc % channels;

            // Base offset for this (b, c) slice in gradInputData
            int inputBaseOffset = (b * channels + c) * depth * height * width;
            int outputBaseOffset = (b * channels + c) * outDepth * outHeight * outWidth;

            for (int od = 0; od < outDepth; od++)
            {
                int id = od / scaleD;
                for (int oh = 0; oh < outHeight; oh++)
                {
                    int ih = oh / scaleH;
                    for (int ow = 0; ow < outWidth; ow++)
                    {
                        int iw = ow / scaleW;

                        int inputIdx = inputBaseOffset + (id * height + ih) * width + iw;
                        int outputIdx = outputBaseOffset + (od * outHeight + oh) * outWidth + ow;
                        gradInputData[inputIdx] = numOps.Add(gradInputData[inputIdx], gradOutputData[outputIdx]);
                    }
                }
            }
        });

        return TensorAllocator.Rent<T>(inputShape, new Vector<T>(gradInputData));
    }

    /// <inheritdoc/>
    public Tensor<T> ConvTranspose3D<T>(Tensor<T> input, Tensor<T> kernel, int[] stride, int[] padding, int[] outputPadding)
    {
        if (input == null) throw new ArgumentNullException(nameof(input));
        if (kernel == null) throw new ArgumentNullException(nameof(kernel));
        var inputOrig = input;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!input.IsContiguous) input = input.Contiguous();
        var kernelOrig = kernel;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!kernel.IsContiguous) kernel = kernel.Contiguous();
        if (input.Rank != 5) throw new ArgumentException($"ConvTranspose3D input requires 5D tensor [batch, in_channels, depth, height, width]. Got rank {input.Rank}.", nameof(input));
        if (kernel.Rank != 5) throw new ArgumentException($"ConvTranspose3D kernel requires 5D tensor [in_channels, out_channels, kD, kH, kW]. Got rank {kernel.Rank}.", nameof(kernel));
        if (stride == null || stride.Length != 3) throw new ArgumentException("Stride must be array of 3 elements.", nameof(stride));
        if (padding == null || padding.Length != 3) throw new ArgumentException("Padding must be array of 3 elements.", nameof(padding));
        if (outputPadding == null || outputPadding.Length != 3) throw new ArgumentException("Output padding must be array of 3 elements.", nameof(outputPadding));

        var numOps = MathHelper.GetNumericOperations<T>();

        int batch = input._shape[0];
        int inChannels = input._shape[1];
        int inDepth = input._shape[2];
        int inHeight = input._shape[3];
        int inWidth = input._shape[4];

        int kernelInChannels = kernel._shape[0];
        int outChannels = kernel._shape[1];
        int kD = kernel._shape[2];
        int kH = kernel._shape[3];
        int kW = kernel._shape[4];

        if (inChannels != kernelInChannels)
            throw new ArgumentException($"Kernel's input channels ({kernelInChannels}) must match input tensor's channels ({inChannels}).");

        if (GraphMode.IsActive)
        {
            var scope = GraphMode.Current;
            if (scope is not null)
            {
                int oD = (inDepth - 1) * stride[0] - 2 * padding[0] + kD + outputPadding[0];
                int oH = (inHeight - 1) * stride[1] - 2 * padding[1] + kH + outputPadding[1];
                int oW = (inWidth - 1) * stride[2] - 2 * padding[2] + kW + outputPadding[2];
                var outShape = new[] { batch, outChannels, oD, oH, oW };
                var ci = input; var ck = kernel;
                var cs = (int[])stride.Clone(); var cp = (int[])padding.Clone(); var cop = (int[])outputPadding.Clone();
                return scope.RecordBinary(LazyNodeType.Custom, "ConvTranspose3D", input, kernel, outShape,
                    (eng, output) => { var r = eng.ConvTranspose3D(ci, ck, cs, cp, cop); r.AsSpan().CopyTo(output.AsWritableSpan()); },
                    BackwardFunctions<T>.ConvTranspose3DBackward, new object[] { (int[])stride.Clone(), (int[])padding.Clone() });
            }
        }

        { var ac = AutoTracer.TryGetCompiledPlan<T>("ConvTranspose3D", input._shape); if (ac is not null) return ac.Execute(); }

        int strideD = stride[0], strideH = stride[1], strideW = stride[2];
        int padD = padding[0], padH = padding[1], padW = padding[2];
        int outPadD = outputPadding[0], outPadH = outputPadding[1], outPadW = outputPadding[2];

        // Calculate output dimensions for transposed convolution
        int outDepth = (inDepth - 1) * strideD - 2 * padD + kD + outPadD;
        int outHeight = (inHeight - 1) * strideH - 2 * padH + kH + outPadH;
        int outWidth = (inWidth - 1) * strideW - 2 * padW + kW + outPadW;

        var outputData = new T[batch * outChannels * outDepth * outHeight * outWidth];
        var inputData = input.GetDataArray();
        var kernelData = kernel.GetDataArray();
        var mergeLock = new object();

        // Use Parallel.For with true per-task local accumulators to avoid race conditions
        Parallel.For(
            0, batch * inChannels,
            () => new T[outputData.Length], // localInit: create per-task buffer
            (bic, state, localOutput) =>
            {
                int b = bic / inChannels;
                int ic = bic % inChannels;

                for (int id = 0; id < inDepth; id++)
                {
                    for (int ih = 0; ih < inHeight; ih++)
                    {
                        for (int iw = 0; iw < inWidth; iw++)
                        {
                            int inputIdx = (((b * inChannels + ic) * inDepth + id) * inHeight + ih) * inWidth + iw;
                            T inputVal = inputData[inputIdx];

                            for (int oc = 0; oc < outChannels; oc++)
                            {
                                for (int kd = 0; kd < kD; kd++)
                                {
                                    int od = id * strideD - padD + kd;
                                    if (od < 0 || od >= outDepth) continue;

                                    for (int kh = 0; kh < kH; kh++)
                                    {
                                        int oh = ih * strideH - padH + kh;
                                        if (oh < 0 || oh >= outHeight) continue;

                                        for (int kw = 0; kw < kW; kw++)
                                        {
                                            int ow = iw * strideW - padW + kw;
                                            if (ow < 0 || ow >= outWidth) continue;

                                            int kernelIdx = (((ic * outChannels + oc) * kD + kd) * kH + kh) * kW + kw;
                                            int outputIdx = (((b * outChannels + oc) * outDepth + od) * outHeight + oh) * outWidth + ow;

                                            localOutput[outputIdx] = numOps.Add(localOutput[outputIdx],
                                                numOps.Multiply(inputVal, kernelData[kernelIdx]));
                                        }
                                    }
                                }
                            }
                        }
                    }
                }
                return localOutput;
            },
            localOutput =>
            {
                // localFinally: merge per-task results under lock
                lock (mergeLock)
                {
                    for (int i = 0; i < outputData.Length; i++)
                    {
                        outputData[i] = numOps.Add(outputData[i], localOutput[i]);
                    }
                }
            });

        var ct3dResult = TensorAllocator.Rent<T>([batch, outChannels, outDepth, outHeight, outWidth], new Vector<T>(outputData));
        DifferentiableOps.RecordBinary("ConvTranspose3D", ct3dResult, inputOrig, kernelOrig, BackwardFunctions<T>.ConvTranspose3DBackward, new object[] { stride, padding });
        { var ca = input; var cb = kernel; var cs2 = stride; var cp2 = padding; var cop2 = outputPadding; AutoTracer.RecordOp("ConvTranspose3D", ct3dResult, eng => eng.ConvTranspose3D(ca, cb, cs2, cp2, cop2)); }
        return ct3dResult;
    }

    /// <inheritdoc/>
    public Tensor<T> ConvTranspose3DBackwardInput<T>(Tensor<T> gradOutput, Tensor<T> kernel, int[] inputShape, int[] stride, int[] padding)
    {
        if (gradOutput == null) throw new ArgumentNullException(nameof(gradOutput));
        if (kernel == null) throw new ArgumentNullException(nameof(kernel));
        var gradOutputOrig = gradOutput;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!gradOutput.IsContiguous) gradOutput = gradOutput.Contiguous();
        var kernelOrig = kernel;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!kernel.IsContiguous) kernel = kernel.Contiguous();
        if (inputShape == null || inputShape.Length != 5) throw new ArgumentException("Input shape must be array of 5 elements.", nameof(inputShape));

        // The backward pass for transposed convolution input is equivalent to a regular Conv3D
        // with the kernel applied in the normal direction
        return Conv3D(gradOutput, kernel, stride, padding, [1, 1, 1]);
    }

    /// <inheritdoc/>
    public Tensor<T> ConvTranspose3DBackwardKernel<T>(Tensor<T> gradOutput, Tensor<T> input, int[] kernelShape, int[] stride, int[] padding)
    {
        if (gradOutput == null) throw new ArgumentNullException(nameof(gradOutput));
        if (input == null) throw new ArgumentNullException(nameof(input));
        if (kernelShape == null || kernelShape.Length != 5) throw new ArgumentException("Kernel shape must be array of 5 elements.", nameof(kernelShape));

        var numOps = MathHelper.GetNumericOperations<T>();

        int batch = input._shape[0];
        int inChannels = input._shape[1];
        int inDepth = input._shape[2];
        int inHeight = input._shape[3];
        int inWidth = input._shape[4];

        int outChannels = gradOutput._shape[1];
        int outDepth = gradOutput._shape[2];
        int outHeight = gradOutput._shape[3];
        int outWidth = gradOutput._shape[4];

        int kD = kernelShape[2], kH = kernelShape[3], kW = kernelShape[4];
        int strideD = stride[0], strideH = stride[1], strideW = stride[2];
        int padD = padding[0], padH = padding[1], padW = padding[2];

        var gradKernelData = new T[inChannels * outChannels * kD * kH * kW];
        var inputData = input.GetFlattenedData();
        var gradOutputData = gradOutput.GetFlattenedData();

        // Use Parallel.For with localInit/localFinally for thread-safe accumulation
        var mergeLock = new object();

        Parallel.For(
            0, batch * inChannels,
            () => new T[gradKernelData.Length], // localInit: create per-task buffer
            (bic, state, localGradKernel) =>
            {
                int b = bic / inChannels;
                int ic = bic % inChannels;

                for (int id = 0; id < inDepth; id++)
                {
                    for (int ih = 0; ih < inHeight; ih++)
                    {
                        for (int iw = 0; iw < inWidth; iw++)
                        {
                            int inputIdx = (((b * inChannels + ic) * inDepth + id) * inHeight + ih) * inWidth + iw;
                            T inputVal = inputData[inputIdx];

                            for (int oc = 0; oc < outChannels; oc++)
                            {
                                for (int kd = 0; kd < kD; kd++)
                                {
                                    int od = id * strideD - padD + kd;
                                    if (od < 0 || od >= outDepth) continue;

                                    for (int kh = 0; kh < kH; kh++)
                                    {
                                        int oh = ih * strideH - padH + kh;
                                        if (oh < 0 || oh >= outHeight) continue;

                                        for (int kw = 0; kw < kW; kw++)
                                        {
                                            int ow = iw * strideW - padW + kw;
                                            if (ow < 0 || ow >= outWidth) continue;

                                            int gradOutputIdx = (((b * outChannels + oc) * outDepth + od) * outHeight + oh) * outWidth + ow;
                                            int kernelIdx = (((ic * outChannels + oc) * kD + kd) * kH + kh) * kW + kw;

                                            localGradKernel[kernelIdx] = numOps.Add(localGradKernel[kernelIdx],
                                                numOps.Multiply(inputVal, gradOutputData[gradOutputIdx]));
                                        }
                                    }
                                }
                            }
                        }
                    }
                }

                return localGradKernel;
            },
            localGradKernel =>
            {
                // localFinally: merge per-task results under lock
                lock (mergeLock)
                {
                    for (int i = 0; i < gradKernelData.Length; i++)
                    {
                        gradKernelData[i] = numOps.Add(gradKernelData[i], localGradKernel[i]);
                    }
                }
            });

        return TensorAllocator.Rent<T>(kernelShape, new Vector<T>(gradKernelData));
    }

    #endregion

    /// <inheritdoc/>
    public Tensor<T> LocallyConnectedConv2D<T>(Tensor<T> input, Tensor<T> weights, Tensor<T>? bias, int[] stride)
    {
        if (input == null) throw new ArgumentNullException(nameof(input));
        if (weights == null) throw new ArgumentNullException(nameof(weights));
        var inputOrig = input;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!input.IsContiguous) input = input.Contiguous();
        var weightsOrig = weights;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!weights.IsContiguous) weights = weights.Contiguous();
        if (input.Rank != 4) throw new ArgumentException($"LocallyConnectedConv2D input requires a 4D tensor [batch, in_channels, height, width]. Got rank {input.Rank}.");
        // weights shape: [output_height, output_width, out_channels, in_channels, kernel_height, kernel_width]
        if (weights.Rank != 6) throw new ArgumentException($"LocallyConnectedConv2D weights require a 6D tensor. Got rank {weights.Rank}.");
        if (stride == null || stride.Length != 2) throw new ArgumentException("Stride must be an array of 2 elements", nameof(stride));
        if (stride[0] <= 0 || stride[1] <= 0) throw new ArgumentException("Stride elements must be positive", nameof(stride));

        var numOps = MathHelper.GetNumericOperations<T>();

        int batch = input._shape[0];
        int inChannels = input._shape[1];
        int inputHeight = input._shape[2];
        int inputWidth = input._shape[3];

        int outputHeight = weights._shape[0];
        int outputWidth = weights._shape[1];
        int outChannels = weights._shape[2];
        int kernelInChannels = weights._shape[3]; // in_channels in the weights tensor definition
        int kernelHeight = weights._shape[4];
        int kernelWidth = weights._shape[5];

        int strideH = stride[0], strideW = stride[1];

        // Validate kernel in_channels matches input in_channels
        if (kernelInChannels != inChannels)
            throw new ArgumentException($"Weight's input channels ({kernelInChannels}) must match input tensor's in_channels ({inChannels}).");

        // Ensure output shape derived from input/kernel/stride matches weights
        int expectedOutputH = (inputHeight - kernelHeight) / strideH + 1;
        int expectedOutputW = (inputWidth - kernelWidth) / strideW + 1;

        if (outputHeight != expectedOutputH || outputWidth != expectedOutputW)
            throw new ArgumentException($"Calculated output dimensions ({expectedOutputH}x{expectedOutputW}) do not match weights dimensions ({outputHeight}x{outputWidth}). Check input, kernel, and stride parameters.");

        if (GraphMode.IsActive)
        {
            var scope = GraphMode.Current;
            if (scope is not null)
            {
                var outShape = new[] { batch, outChannels, outputHeight, outputWidth };
                var ci = input; var cw = weights; var cb = bias; var cs = (int[])stride.Clone();
                var inputs = bias is not null ? new[] { input, weights, bias } : new[] { input, weights };
                return scope.RecordVariadic(LazyNodeType.Custom, "LocallyConnectedConv2D", inputs, outShape,
                    (eng, output) => { var r = eng.LocallyConnectedConv2D(ci, cw, cb, cs); r.AsSpan().CopyTo(output.AsWritableSpan()); },
                    BackwardFunctions<T>.LocallyConnectedConv2DBackward, new object[] { (int[])stride.Clone() });
            }
        }

        { var ac = AutoTracer.TryGetCompiledPlan<T>("LocallyConnectedConv2D", input._shape); if (ac is not null) return ac.Execute(); }

        var result = TensorAllocator.Rent<T>(new[] { batch, outChannels, outputHeight, outputWidth });
        var inputData = input.GetDataArray();
        var weightsData = weights.GetDataArray();
        var biasData = bias?.GetDataArray();

        Parallel.For(0, batch, b => // Process each batch independently
        {
            for (int oc = 0; oc < outChannels; oc++)
            {
                for (int oh = 0; oh < outputHeight; oh++)
                {
                    for (int ow = 0; ow < outputWidth; ow++)
                    {
                        T sum = numOps.Zero;

                        for (int ic = 0; ic < inChannels; ic++)
                        {
                            for (int kh = 0; kh < kernelHeight; kh++)
                            {
                                for (int kw = 0; kw < kernelWidth; kw++)
                                {
                                    int ih = oh * strideH + kh;
                                    int iw = ow * strideW + kw;

                                    // Check bounds (LocallyConnected typically doesn't use padding in direct impl, but can be added)
                                    if (ih >= 0 && ih < inputHeight && iw >= 0 && iw < inputWidth)
                                    {
                                        T inputVal = inputData[((b * inChannels + ic) * inputHeight + ih) * inputWidth + iw];
                                        // weightsData index: [oh, ow, oc, ic, kh, kw]
                                        T weightVal = weightsData[((((oh * outputWidth + ow) * outChannels + oc) * kernelInChannels + ic) * kernelHeight + kh) * kernelWidth + kw];
                                        sum = numOps.Add(sum, numOps.Multiply(inputVal, weightVal));
                                    }
                                }
                            }
                        }

                        // Add bias if provided
                        if (biasData != null)
                        {
                            sum = numOps.Add(sum, biasData[oc]);
                        }

                        result[b, oc, oh, ow] = sum;
                    }
                }
            }
        });

        DifferentiableOps.RecordBinary("LocallyConnectedConv2D", result, inputOrig, weightsOrig, BackwardFunctions<T>.LocallyConnectedConv2DBackward, new object[] { stride });
        { var ca = input; var cb = weights; var cc = bias; var cs = stride; AutoTracer.RecordOp("LocallyConnectedConv2D", result, eng => eng.LocallyConnectedConv2D(ca, cb, cc, cs)); }
        return result;
    }

    /// <inheritdoc/>
    public Tensor<T> LocallyConnectedConv2DBackwardInput<T>(Tensor<T> gradOutput, Tensor<T> weights, int[] inputShape, int[] stride)
    {
        if (gradOutput == null) throw new ArgumentNullException(nameof(gradOutput));
        if (weights == null) throw new ArgumentNullException(nameof(weights));
        if (inputShape == null || inputShape.Length != 4) throw new ArgumentException("inputShape must be array of 4 elements [batch, inChannels, height, width]", nameof(inputShape));
        if (gradOutput.Rank != 4) throw new ArgumentException($"LocallyConnectedConv2DBackwardInput gradOutput requires 4D tensor. Got rank {gradOutput.Rank}.");
        if (weights.Rank != 6) throw new ArgumentException($"LocallyConnectedConv2DBackwardInput weights require a 6D tensor. Got rank {weights.Rank}.");
        if (stride == null || stride.Length != 2) throw new ArgumentException("Stride must be an array of 2 elements", nameof(stride));

        var numOps = MathHelper.GetNumericOperations<T>();

        int batch = inputShape[0];
        int inChannels = inputShape[1];
        int inputHeight = inputShape[2];
        int inputWidth = inputShape[3];

        int outputHeight = weights._shape[0];
        int outputWidth = weights._shape[1];
        int outChannels = weights._shape[2];
        int kernelInChannels = weights._shape[3];
        int kernelHeight = weights._shape[4];
        int kernelWidth = weights._shape[5];

        int strideH = stride[0], strideW = stride[1];

        var finalGradInput = new T[batch * inChannels * inputHeight * inputWidth];
        var gradOutputData = gradOutput.GetFlattenedData();
        var weightsData = weights.GetFlattenedData();

        Parallel.For(0, batch * inChannels * inputHeight * inputWidth, idx =>
        {
            int b = idx / (inChannels * inputHeight * inputWidth);
            int ic = (idx / (inputHeight * inputWidth)) % inChannels;
            int ih = (idx / inputWidth) % inputHeight;
            int iw = idx % inputWidth;

            T sumGrad = numOps.Zero;
            // Iterate over all possible output positions this input pixel contributes to
            for (int oh_candidate = 0; oh_candidate < outputHeight; oh_candidate++)
            {
                for (int ow_candidate = 0; ow_candidate < outputWidth; ow_candidate++)
                {
                    // Check if input pixel (ih, iw) is covered by kernel at (oh_candidate, ow_candidate)
                    // (ih, iw) should be in the kernel window
                    int kh_relative = ih - oh_candidate * strideH;
                    int kw_relative = iw - ow_candidate * strideW;

                    if (kh_relative >= 0 && kh_relative < kernelHeight && kw_relative >= 0 && kw_relative < kernelWidth)
                    {
                        for (int oc = 0; oc < outChannels; oc++)
                        {
                            T gradOutVal = gradOutputData[((b * outChannels + oc) * outputHeight + oh_candidate) * outputWidth + ow_candidate];
                            T weightVal = weightsData[((((oh_candidate * outputWidth + ow_candidate) * outChannels + oc) * kernelInChannels + ic) * kernelHeight + kh_relative) * kernelWidth + kw_relative];
                            sumGrad = numOps.Add(sumGrad, numOps.Multiply(gradOutVal, weightVal));
                        }
                    }
                }
            }
            finalGradInput[idx] = sumGrad;
        });

        return TensorAllocator.Rent<T>(inputShape, new Vector<T>(finalGradInput));
    }

    /// <inheritdoc/>
    public Tensor<T> LocallyConnectedConv2DBackwardWeights<T>(Tensor<T> gradOutput, Tensor<T> input, int[] weightsShape, int[] stride)
    {
        if (gradOutput == null) throw new ArgumentNullException(nameof(gradOutput));
        if (input == null) throw new ArgumentNullException(nameof(input));
        var gradOutputOrig = gradOutput;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!gradOutput.IsContiguous) gradOutput = gradOutput.Contiguous();
        if (weightsShape == null || weightsShape.Length != 6) throw new ArgumentException("weightsShape must be array of 6 elements", nameof(weightsShape));
        if (gradOutput.Rank != 4) throw new ArgumentException($"LocallyConnectedConv2DBackwardWeights gradOutput requires 4D tensor. Got rank {gradOutput.Rank}.");
        if (input.Rank != 4) throw new ArgumentException($"LocallyConnectedConv2DBackwardWeights input requires 4D tensor. Got rank {input.Rank}.");
        if (stride == null || stride.Length != 2) throw new ArgumentException("Stride must be array of 2 elements", nameof(stride));

        var numOps = MathHelper.GetNumericOperations<T>();

        int batch = input._shape[0];
        int inChannels = input._shape[1];
        int inputHeight = input._shape[2];
        int inputWidth = input._shape[3];

        int outputHeight = weightsShape[0];
        int outputWidth = weightsShape[1];
        int outChannels = weightsShape[2];
        int kernelInChannels = weightsShape[3];
        int kernelHeight = weightsShape[4];
        int kernelWidth = weightsShape[5];

        int strideH = stride[0], strideW = stride[1];

        var gradWeights = new T[weightsShape.Aggregate(1, (acc, val) => acc * val)];
        var gradOutputData = gradOutput.GetFlattenedData();
        var inputData = input.GetFlattenedData();

        for (int i = 0; i < gradWeights.Length; i++)
            gradWeights[i] = numOps.Zero;

        Parallel.For(0, weightsShape.Aggregate(1, (acc, val) => acc * val), idx => // Iterate over all weight elements
        {
            // Deconstruct idx to weights indices (oh, ow, oc, ic, kh, kw)
            int flatIdx = idx;
            int kw_w = kernelWidth;
            int kh_w = kernelHeight;
            int ic_w = kernelInChannels; // This is the 3rd dim in weights (index 3)
            int oc_w = outChannels;
            int ow_w = outputWidth;

            int kw = flatIdx % kw_w; flatIdx /= kw_w;
            int kh = flatIdx % kh_w; flatIdx /= kh_w;
            int ic = flatIdx % ic_w; flatIdx /= ic_w;
            int oc = flatIdx % oc_w; flatIdx /= oc_w;
            int ow = flatIdx % ow_w; flatIdx /= ow_w;
            int oh = flatIdx;

            T sum = numOps.Zero;
            for (int b = 0; b < batch; b++)
            {
                int ih = oh * strideH + kh;
                int iw = ow * strideW + kw;

                // Check bounds for input
                if (ih >= 0 && ih < inputHeight && iw >= 0 && iw < inputWidth)
                {
                    T gradOutVal = gradOutputData[((b * outChannels + oc) * outputHeight + oh) * outputWidth + ow];
                    T inputVal = inputData[((b * inChannels + ic) * inputHeight + ih) * inputWidth + iw];
                    sum = numOps.Add(sum, numOps.Multiply(gradOutVal, inputVal));
                }
            }
            gradWeights[idx] = sum;
        });

        return TensorAllocator.Rent<T>(weightsShape, new Vector<T>(gradWeights));
    }

    /// <inheritdoc/>
    public Tensor<T> LocallyConnectedConv2DBackwardBias<T>(Tensor<T> gradOutput)
    {
        if (gradOutput == null) throw new ArgumentNullException(nameof(gradOutput));
        if (gradOutput.Rank != 4) throw new ArgumentException($"LocallyConnectedConv2DBackwardBias gradOutput requires 4D tensor. Got rank {gradOutput.Rank}.");

        var numOps = MathHelper.GetNumericOperations<T>();

        int batch = gradOutput._shape[0];
        int outChannels = gradOutput._shape[1];
        int outputHeight = gradOutput._shape[2];
        int outputWidth = gradOutput._shape[3];

        var gradBias = new T[outChannels]; // Bias gradient is 1D [outChannels]
        var gradOutputData = gradOutput.GetFlattenedData();

        for (int i = 0; i < gradBias.Length; i++)
            gradBias[i] = numOps.Zero;

        Parallel.For(0, outChannels, oc => // Iterate over output channels
        {
            T sum = numOps.Zero;
            for (int b = 0; b < batch; b++)
            {
                for (int oh = 0; oh < outputHeight; oh++)
                {
                    for (int ow = 0; ow < outputWidth; ow++)
                    {
                        sum = numOps.Add(sum, gradOutputData[((b * outChannels + oc) * outputHeight + oh) * outputWidth + ow]);
                    }
                }
            }
            gradBias[oc] = sum;
        });

        return TensorAllocator.Rent<T>(new[] { outChannels }, new Vector<T>(gradBias));
    }

    #endregion

    #region Normalization and Activation Operations

    /// <inheritdoc/>
    public virtual Tensor<T> Softmax<T>(Tensor<T> input, int axis = -1)
    {
        using var _opScope = AiDotNet.Tensors.Engines.Profiling.Profiler.OpScope("Softmax");
        if (input == null) throw new ArgumentNullException(nameof(input));

        int rank = input.Rank;
        if (axis < 0) axis = rank + axis;
        if (axis < 0 || axis >= rank)
            throw new ArgumentException($"Invalid axis {axis} for tensor with {rank} dimensions");

        // Lazy graph mode: record and return placeholder
        if (GraphMode.IsActive)
        {
            var scope = GraphMode.Current;
            if (scope != null)
            {
                var captured = input;
                int capturedAxis = axis;
                return scope.RecordUnary(LazyNodeType.Softmax, "Softmax", input, input._shape,
                    // Path C: write-through via SoftmaxInto when possible.
                    // Skips the alloc-copy round-trip through Softmax's
                    // public API (~100 µs saved on BERT [1,12,256,256]).
                    (eng, output) => eng.SoftmaxInto(output, captured, capturedAxis),
                    BackwardFunctions<T>.SoftmaxBackward, new object[] { axis });
            }
        }

        // Auto-tracer: check if a compiled plan exists for this op pattern
        { var autoCompiled = AutoTracer.TryGetCompiledPlan<T>("Softmax", input._shape, paramHash: axis);
          if (autoCompiled is not null) return autoCompiled.Execute(); }

        // Compute outer and inner sizes
        int outerSize = 1, axisSize = input._shape[axis], innerSize = 1;
        for (int i = 0; i < axis; i++) outerSize *= input._shape[i];
        for (int i = axis + 1; i < rank; i++) innerSize *= input._shape[i];

        // Fast SIMD path for float when softmax is on the last axis (innerSize==1)
        if (typeof(T) == typeof(float) && innerSize == 1)
        {
            // Use Pin() for NativeMemory compatibility (no GetDataArray copy)
            var result = AutoTensorCache.RentOrAllocate<T>(input._shape);
            using var pinIn = input.Data.Pin();
            using var pinOut = result.Data.Pin();
            unsafe
            {
                SoftmaxFloatFastPtr((float*)pinIn.Pointer, (float*)pinOut.Pointer, outerSize, axisSize);
            }
            DifferentiableOps.RecordUnary("Softmax", result, input, BackwardFunctions<T>.SoftmaxBackward, new object[] { axis });
            { var c = input; int ax = axis; AutoTracer.RecordOp("Softmax", result, eng => eng.Softmax(c, ax), paramHash: ax); }
            return result;
        }

        // Double SIMD fast path for last-axis softmax — parallel + Vector256<double>
        // via FastExpDouble256. Mirrors the float path's structure: PersistentParallelExecutor
        // chunks rows across cores, each row uses SoftmaxRowDoubleUnsafe.
        if (typeof(T) == typeof(double) && innerSize == 1)
        {
            var result = AutoTensorCache.RentOrAllocate<T>(input._shape);
            using var pinIn = input.Data.Pin();
            using var pinOut = result.Data.Pin();
            unsafe
            {
                double* pIn = (double*)pinIn.Pointer;
                double* pOut = (double*)pinOut.Pointer;
                int maxThreads = CpuParallelSettings.MaxDegreeOfParallelism;
                bool useParallel = outerSize >= 4 && outerSize * axisSize >= 16384;
                if (useParallel)
                {
                    int numChunks = Math.Min(maxThreads, outerSize);
                    int rowsPerChunk = (outerSize + numChunks - 1) / numChunks;
                    IntPtr ipIn = (IntPtr)pIn;
                    IntPtr ipOut = (IntPtr)pOut;
                    int axisSz = axisSize;
                    int outerSz = outerSize;
                    Helpers.PersistentParallelExecutor.Instance.Execute(numChunks, chunk =>
                    {
                        int startRow = chunk * rowsPerChunk;
                        int endRow = Math.Min(startRow + rowsPerChunk, outerSz);
                        for (int row = startRow; row < endRow; row++)
                            SimdKernels.SoftmaxRowDoubleUnsafe(
                                (double*)ipIn + row * axisSz,
                                (double*)ipOut + row * axisSz,
                                axisSz);
                    });
                }
                else
                {
                    for (int row = 0; row < outerSize; row++)
                        SimdKernels.SoftmaxRowDoubleUnsafe(
                            pIn + row * axisSize,
                            pOut + row * axisSize,
                            axisSize);
                }
            }
            DifferentiableOps.RecordUnary("Softmax", result, input, BackwardFunctions<T>.SoftmaxBackward, new object[] { axis });
            { var c = input; int ax = axis; AutoTracer.RecordOp("Softmax", result, eng => eng.Softmax(c, ax), paramHash: ax); }
            return result;
        }

        // Generic scalar fallback for non-float types or non-last-axis
        var numOps = MathHelper.GetNumericOperations<T>();
        var inputData = input.GetFlattenedData();
        var result2 = AutoTensorCache.RentOrAllocate<T>(input._shape);
        var outputDataGeneric = result2.GetDataArray();

        Parallel.For(0, outerSize * innerSize, idx =>
        {
            int outer = idx / innerSize;
            int inner = idx % innerSize;

            T maxVal = numOps.MinValue;
            for (int i = 0; i < axisSize; i++)
            {
                int flatIdx = (outer * axisSize + i) * innerSize + inner;
                if (numOps.GreaterThan(inputData[flatIdx], maxVal))
                    maxVal = inputData[flatIdx];
            }

            T sumExp = numOps.Zero;
            var expVals = new T[axisSize];
            for (int i = 0; i < axisSize; i++)
            {
                int flatIdx = (outer * axisSize + i) * innerSize + inner;
                expVals[i] = numOps.Exp(numOps.Subtract(inputData[flatIdx], maxVal));
                sumExp = numOps.Add(sumExp, expVals[i]);
            }

            for (int i = 0; i < axisSize; i++)
            {
                int flatIdx = (outer * axisSize + i) * innerSize + inner;
                outputDataGeneric[flatIdx] = numOps.Divide(expVals[i], sumExp);
            }
        });

        DifferentiableOps.RecordUnary("Softmax", result2, input, BackwardFunctions<T>.SoftmaxBackward, new object[] { axis });
        { var c = input; int ax = axis; AutoTracer.RecordOp("Softmax", result2, eng => eng.Softmax(c, ax), paramHash: ax); }
        return result2;
    }

    /// <summary>
    /// Fast SIMD softmax for float arrays with parallel row processing.
    /// Each row is independent: max → subtract → exp → sum → divide.
    /// Parallelized across rows for large tensors.
    /// </summary>
    /// <summary>
    /// SIMD-optimized GroupNorm for float. Fuses mean+variance computation
    /// and parallelizes across batch*groups using PersistentParallelExecutor.
    /// </summary>
    private unsafe void GroupNormFloatPtr(
        float* inputData, float* outputData,
        float* gammaData, float* betaData,
        int batch, int channels, int spatialSize, int numGroups, int channelsPerGroup,
        float eps, out float[] meanArr, out float[] varArr)
    {
        // Use arrays directly (Span can't be captured in lambdas)

        int groupSize = channelsPerGroup * spatialSize;
        meanArr = new float[batch * numGroups];
        varArr = new float[batch * numGroups];

        int totalGroups = batch * numGroups;
        var meanLocal = meanArr;
        var varLocal = varArr;

        // Parallelize across batch*groups — each group is independent
        PersistentParallelExecutor.Instance.Execute(
            Math.Min(totalGroups, CpuParallelSettings.MaxDegreeOfParallelism),
            chunk =>
            {
                int chunkSize = (totalGroups + Math.Min(totalGroups, CpuParallelSettings.MaxDegreeOfParallelism) - 1)
                    / Math.Min(totalGroups, CpuParallelSettings.MaxDegreeOfParallelism);
                int startIdx = chunk * chunkSize;
                int endIdx = Math.Min(startIdx + chunkSize, totalGroups);

                for (int idx = startIdx; idx < endIdx; idx++)
                {
                    int b = idx / numGroups;
                    int g = idx % numGroups;
                    int startChannel = g * channelsPerGroup;
                    int batchOffset = b * channels * spatialSize;

                    // Mean computation — use SIMD SumUnsafe per channel
                    float sum = 0f;
                    for (int c = 0; c < channelsPerGroup; c++)
                    {
                        int chanOff = batchOffset + (startChannel + c) * spatialSize;
                        sum += SimdKernels.SumUnsafe(inputData + chanOff, spatialSize);
                    }
                    float groupMean = sum / groupSize;
                    meanLocal[idx] = groupMean;

                    // Fused variance computation per channel — SIMD accelerated
                    float sumSq = 0f;
                    for (int c = 0; c < channelsPerGroup; c++)
                    {
                        int chanOff = batchOffset + (startChannel + c) * spatialSize;
                        sumSq += SimdKernels.SumSquaredDiffUnsafe(inputData + chanOff, groupMean, spatialSize);
                    }
                    float groupVar = sumSq / groupSize;
                    varLocal[idx] = groupVar;

                    // Normalize and apply scale/shift — fused per channel
                    float invStd = 1f / MathF.Sqrt(groupVar + eps);
                    for (int c = 0; c < channelsPerGroup; c++)
                    {
                        int channel = startChannel + c;
                        int chanOff = batchOffset + channel * spatialSize;
                        float scale = gammaData[channel] * invStd;
                        float bias = betaData[channel] - groupMean * scale;
                        // Fused: output = input * scale + bias (single pass, JIT auto-vectorizes)
                        for (int s = 0; s < spatialSize; s++)
                            outputData[chanOff + s] = inputData[chanOff + s] * scale + bias;
                    }
                }
            });
    }

    /// <summary>SIMD-accelerated sum of float array segment.</summary>
    [MethodImpl(MethodImplOptions.AggressiveInlining)]
    private static float SimdSumFloat(float[] data, int offset, int count)
    {
        float sum = 0f;
        int i = 0;
#if NET5_0_OR_GREATER
        if (System.Runtime.Intrinsics.X86.Avx.IsSupported && count >= 32)
        {
            var vsum0 = System.Runtime.Intrinsics.Vector256<float>.Zero;
            var vsum1 = vsum0; var vsum2 = vsum0; var vsum3 = vsum0;
            int simdLen = count & ~31;
            for (; i < simdLen; i += 32)
            {
                vsum0 = System.Runtime.Intrinsics.X86.Avx.Add(vsum0, SimdKernels.ReadVector256(data.AsSpan(), offset + i));
                vsum1 = System.Runtime.Intrinsics.X86.Avx.Add(vsum1, SimdKernels.ReadVector256(data.AsSpan(), offset + i + 8));
                vsum2 = System.Runtime.Intrinsics.X86.Avx.Add(vsum2, SimdKernels.ReadVector256(data.AsSpan(), offset + i + 16));
                vsum3 = System.Runtime.Intrinsics.X86.Avx.Add(vsum3, SimdKernels.ReadVector256(data.AsSpan(), offset + i + 24));
            }
            vsum0 = System.Runtime.Intrinsics.X86.Avx.Add(
                System.Runtime.Intrinsics.X86.Avx.Add(vsum0, vsum1),
                System.Runtime.Intrinsics.X86.Avx.Add(vsum2, vsum3));
            sum = SimdKernels.HorizontalSum(vsum0);
        }
#endif
        for (; i < count; i++)
            sum += data[offset + i];
        return sum;
    }

    /// <summary>SIMD-accelerated sum of squared differences: sum((x-mean)^2).</summary>
    [MethodImpl(MethodImplOptions.AggressiveInlining)]
    private static float SimdSumSquaredDiffFloat(float[] data, int offset, int count, float mean)
    {
        float sumSq = 0f;
        int i = 0;
#if NET5_0_OR_GREATER
        if (System.Runtime.Intrinsics.X86.Avx.IsSupported && System.Runtime.Intrinsics.X86.Fma.IsSupported && count >= 32)
        {
            var vmean = System.Runtime.Intrinsics.Vector256.Create(mean);
            var vsum0 = System.Runtime.Intrinsics.Vector256<float>.Zero;
            var vsum1 = vsum0; var vsum2 = vsum0; var vsum3 = vsum0;
            int simdLen = count & ~31;
            for (; i < simdLen; i += 32)
            {
                var d0 = System.Runtime.Intrinsics.X86.Avx.Subtract(SimdKernels.ReadVector256(data.AsSpan(), offset + i), vmean);
                var d1 = System.Runtime.Intrinsics.X86.Avx.Subtract(SimdKernels.ReadVector256(data.AsSpan(), offset + i + 8), vmean);
                var d2 = System.Runtime.Intrinsics.X86.Avx.Subtract(SimdKernels.ReadVector256(data.AsSpan(), offset + i + 16), vmean);
                var d3 = System.Runtime.Intrinsics.X86.Avx.Subtract(SimdKernels.ReadVector256(data.AsSpan(), offset + i + 24), vmean);
                vsum0 = System.Runtime.Intrinsics.X86.Fma.MultiplyAdd(d0, d0, vsum0);
                vsum1 = System.Runtime.Intrinsics.X86.Fma.MultiplyAdd(d1, d1, vsum1);
                vsum2 = System.Runtime.Intrinsics.X86.Fma.MultiplyAdd(d2, d2, vsum2);
                vsum3 = System.Runtime.Intrinsics.X86.Fma.MultiplyAdd(d3, d3, vsum3);
            }
            vsum0 = System.Runtime.Intrinsics.X86.Avx.Add(
                System.Runtime.Intrinsics.X86.Avx.Add(vsum0, vsum1),
                System.Runtime.Intrinsics.X86.Avx.Add(vsum2, vsum3));
            sumSq = SimdKernels.HorizontalSum(vsum0);
        }
#endif
        for (; i < count; i++)
        {
            float diff = data[offset + i] - mean;
            sumSq += diff * diff;
        }
        return sumSq;
    }

    /// <summary>Pointer-based softmax — works with both managed arrays and NativeMemory.</summary>
    private static unsafe void SoftmaxFloatFastPtr(float* pIn, float* pOut, int outerSize, int axisSize)
    {
        {
#if NET5_0_OR_GREATER
            // oneDNN path: fused SVML-accelerated softmax — processes all rows in one call.
            // This matches TorchSharp's libtorch which uses the same MKLDNN backend.
            if (OneDnnProvider.TrySoftmax(pIn, pOut, outerSize, axisSize))
                return;
#endif

            int maxThreads = CpuParallelSettings.MaxDegreeOfParallelism;
            bool useParallel = outerSize >= 4 && outerSize * axisSize >= 32768;

            if (useParallel)
            {
                // Use PersistentParallelExecutor for near-zero dispatch overhead
                // Each worker processes a chunk of consecutive rows for cache locality
                int numChunks = Math.Min(maxThreads, outerSize);
                int rowsPerChunk = (outerSize + numChunks - 1) / numChunks;
                float* pInCap = pIn;
                float* pOutCap = pOut;
                int axisSz = axisSize;
                int outerSz = outerSize;

                PersistentParallelExecutor.Instance.Execute(numChunks, chunk =>
                {
                    int startRow = chunk * rowsPerChunk;
                    int endRow = Math.Min(startRow + rowsPerChunk, outerSz);
                    for (int row = startRow; row < endRow; row++)
                    {
                        SimdKernels.SoftmaxRowUnsafe(pInCap + row * axisSz, pOutCap + row * axisSz, axisSz);
                    }
                });
            }
            else
            {
                for (int row = 0; row < outerSize; row++)
                    SimdKernels.SoftmaxRowUnsafe(pIn + row * axisSize, pOut + row * axisSize, axisSize);
            }
        }
    }

    /// <inheritdoc/>
    public Tensor<T> SoftmaxBackward<T>(Tensor<T> gradOutput, Tensor<T> output, int axis = -1)
    {
        if (gradOutput == null) throw new ArgumentNullException(nameof(gradOutput));
        if (output == null) throw new ArgumentNullException(nameof(output));

        int rank = output.Rank;
        if (axis < 0) axis = rank + axis;

        int outerSize = 1, axisSize = output._shape[axis], innerSize = 1;
        for (int i = 0; i < axis; i++) outerSize *= output._shape[i];
        for (int i = axis + 1; i < rank; i++) innerSize *= output._shape[i];

#if NET5_0_OR_GREATER
        // Float SIMD fast path for last-axis softmax backward (innerSize == 1)
        if (typeof(T) == typeof(float) && innerSize == 1
            && gradOutput.GetFlattenedData() is float[] gOutF
            && output.GetFlattenedData() is float[] outF)
        {
            var gInF = new float[outF.Length];
            SoftmaxBackwardFloat(gOutF, outF, gInF, outerSize, axisSize);
            return (Tensor<T>)(object)TensorAllocator.Rent<T>(output._shape, new Vector<T>((T[])(object)gInF));
        }
#endif

        // Generic fallback
        var numOps = MathHelper.GetNumericOperations<T>();
        var gradOutputData = gradOutput.GetFlattenedData();
        var outputData = output.GetFlattenedData();
        var gradInputData = new T[outputData.Length];

        Parallel.For(0, outerSize * innerSize, idx =>
        {
            int outer = idx / innerSize;
            int inner = idx % innerSize;

            T dotProduct = numOps.Zero;
            for (int i = 0; i < axisSize; i++)
            {
                int flatIdx = (outer * axisSize + i) * innerSize + inner;
                dotProduct = numOps.Add(dotProduct, numOps.Multiply(gradOutputData[flatIdx], outputData[flatIdx]));
            }

            for (int i = 0; i < axisSize; i++)
            {
                int flatIdx = (outer * axisSize + i) * innerSize + inner;
                gradInputData[flatIdx] = numOps.Multiply(outputData[flatIdx], numOps.Subtract(gradOutputData[flatIdx], dotProduct));
            }
        });

        return TensorAllocator.Rent<T>(output._shape, new Vector<T>(gradInputData));
    }

#if NET5_0_OR_GREATER
    /// <summary>
    /// SIMD-optimized softmax backward for float with contiguous axis (innerSize == 1).
    /// Per row: dotProduct = sum(gradOut * output), gradIn = output * (gradOut - dotProduct).
    /// </summary>
    private static unsafe void SoftmaxBackwardFloat(float[] gradOut, float[] output, float[] gradIn,
        int outerSize, int axisSize)
    {
        bool useParallel = outerSize >= 4 && outerSize * axisSize >= 32768;

        if (useParallel)
        {
            Parallel.For(0, outerSize, row =>
            {
                SoftmaxBackwardFloatRow(gradOut, output, gradIn, row, axisSize);
            });
        }
        else
        {
            for (int row = 0; row < outerSize; row++)
                SoftmaxBackwardFloatRow(gradOut, output, gradIn, row, axisSize);
        }
    }

    private static unsafe void SoftmaxBackwardFloatRow(float[] gradOut, float[] output, float[] gradIn,
        int row, int axisSize)
    {
        int baseIdx = row * axisSize;
        fixed (float* pGO = gradOut, pO = output, pGI = gradIn)
        {
            float* go = pGO + baseIdx;
            float* o = pO + baseIdx;
            float* gi = pGI + baseIdx;

            // Step 1: dot product = sum(gradOut[i] * output[i])
            float dot = 0f;
            int i = 0;
            if (System.Runtime.Intrinsics.X86.Fma.IsSupported && axisSize >= 32)
            {
                var vdot0 = System.Runtime.Intrinsics.Vector256<float>.Zero;
                var vdot1 = System.Runtime.Intrinsics.Vector256<float>.Zero;
                var vdot2 = System.Runtime.Intrinsics.Vector256<float>.Zero;
                var vdot3 = System.Runtime.Intrinsics.Vector256<float>.Zero;
                int simdLen = axisSize & ~31;
                for (; i < simdLen; i += 32)
                {
                    vdot0 = System.Runtime.Intrinsics.X86.Fma.MultiplyAdd(
                        System.Runtime.Intrinsics.X86.Avx.LoadVector256(go + i),
                        System.Runtime.Intrinsics.X86.Avx.LoadVector256(o + i), vdot0);
                    vdot1 = System.Runtime.Intrinsics.X86.Fma.MultiplyAdd(
                        System.Runtime.Intrinsics.X86.Avx.LoadVector256(go + i + 8),
                        System.Runtime.Intrinsics.X86.Avx.LoadVector256(o + i + 8), vdot1);
                    vdot2 = System.Runtime.Intrinsics.X86.Fma.MultiplyAdd(
                        System.Runtime.Intrinsics.X86.Avx.LoadVector256(go + i + 16),
                        System.Runtime.Intrinsics.X86.Avx.LoadVector256(o + i + 16), vdot2);
                    vdot3 = System.Runtime.Intrinsics.X86.Fma.MultiplyAdd(
                        System.Runtime.Intrinsics.X86.Avx.LoadVector256(go + i + 24),
                        System.Runtime.Intrinsics.X86.Avx.LoadVector256(o + i + 24), vdot3);
                }
                vdot0 = System.Runtime.Intrinsics.X86.Avx.Add(
                    System.Runtime.Intrinsics.X86.Avx.Add(vdot0, vdot1),
                    System.Runtime.Intrinsics.X86.Avx.Add(vdot2, vdot3));
                dot = SimdKernels.HorizontalSum(vdot0);
            }
            for (; i < axisSize; i++)
                dot += go[i] * o[i];

            // Step 2: gradIn[i] = output[i] * (gradOut[i] - dot)
            i = 0;
            if (System.Runtime.Intrinsics.X86.Avx.IsSupported && axisSize >= 32)
            {
                var vdot = System.Runtime.Intrinsics.Vector256.Create(dot);
                int simdLen = axisSize & ~31;
                for (; i < simdLen; i += 32)
                {
                    var go0 = System.Runtime.Intrinsics.X86.Avx.LoadVector256(go + i);
                    var go1 = System.Runtime.Intrinsics.X86.Avx.LoadVector256(go + i + 8);
                    var go2 = System.Runtime.Intrinsics.X86.Avx.LoadVector256(go + i + 16);
                    var go3 = System.Runtime.Intrinsics.X86.Avx.LoadVector256(go + i + 24);
                    var o0 = System.Runtime.Intrinsics.X86.Avx.LoadVector256(o + i);
                    var o1 = System.Runtime.Intrinsics.X86.Avx.LoadVector256(o + i + 8);
                    var o2 = System.Runtime.Intrinsics.X86.Avx.LoadVector256(o + i + 16);
                    var o3 = System.Runtime.Intrinsics.X86.Avx.LoadVector256(o + i + 24);
                    System.Runtime.Intrinsics.X86.Avx.Store(gi + i,
                        System.Runtime.Intrinsics.X86.Avx.Multiply(o0, System.Runtime.Intrinsics.X86.Avx.Subtract(go0, vdot)));
                    System.Runtime.Intrinsics.X86.Avx.Store(gi + i + 8,
                        System.Runtime.Intrinsics.X86.Avx.Multiply(o1, System.Runtime.Intrinsics.X86.Avx.Subtract(go1, vdot)));
                    System.Runtime.Intrinsics.X86.Avx.Store(gi + i + 16,
                        System.Runtime.Intrinsics.X86.Avx.Multiply(o2, System.Runtime.Intrinsics.X86.Avx.Subtract(go2, vdot)));
                    System.Runtime.Intrinsics.X86.Avx.Store(gi + i + 24,
                        System.Runtime.Intrinsics.X86.Avx.Multiply(o3, System.Runtime.Intrinsics.X86.Avx.Subtract(go3, vdot)));
                }
            }
            for (; i < axisSize; i++)
                gi[i] = o[i] * (go[i] - dot);
        }
    }
#endif

    /// <inheritdoc/>
    public Tensor<T> GumbelSoftmax<T>(Tensor<T> input, double temperature = 1.0, bool hard = false, int axis = -1)
    {
        if (input == null) throw new ArgumentNullException(nameof(input));
        if (temperature <= 0)
            throw new ArgumentOutOfRangeException(nameof(temperature), temperature, "Temperature must be positive.");
        if (double.IsNaN(temperature) || double.IsInfinity(temperature))
            throw new ArgumentOutOfRangeException(nameof(temperature), temperature, "Temperature must be a finite number.");

        var numOps = MathHelper.GetNumericOperations<T>();
        int rank = input.Rank;
        if (axis < 0) axis = rank + axis;

        var inputData = input.GetFlattenedData();
        var shape = input._shape;
        const double eps = 1e-10;

        // Add Gumbel noise: -log(-log(U)) where U ~ Uniform(0, 1)
        var random = RandomHelper.ThreadSafeRandom;
        var perturbedData = new T[input.Length];
        for (int i = 0; i < input.Length; i++)
        {
            var u = random.NextDouble();
            u = Math.Max(u, eps);
            u = Math.Min(u, 1 - eps);
            var gumbel = numOps.FromDouble(-Math.Log(-Math.Log(u)));
            var val = numOps.Add(inputData[i], gumbel);
            perturbedData[i] = numOps.Divide(val, numOps.FromDouble(temperature));
        }

        // Apply softmax — wrap in NoGradScope so the inner Softmax doesn't
        // record on the tape. We record the whole GumbelSoftmax as a single
        // unary op below so dL/d(input) flows correctly through the noise
        // injection (the perturbed→softmax bridge above breaks tape chain).
        Tensor<T> softResult;
        using (new NoGradScope<T>())
        {
            var perturbedTensor = TensorAllocator.Rent<T>(shape, new Vector<T>(perturbedData));
            softResult = Softmax(perturbedTensor, axis);
        }

        if (!hard)
        {
            DifferentiableOps.RecordUnary("GumbelSoftmax", softResult, input,
                BackwardFunctions<T>.GumbelSoftmaxBackward, new object[] { temperature, axis });
            return softResult;
        }

        // Hard mode: create one-hot and use straight-through estimator
        var softData = softResult.GetDataArray();
        var hardData = new T[softData.Length];
        int outerSize = 1, axisSize = shape[axis], innerSize = 1;
        for (int i = 0; i < axis; i++) outerSize *= shape[i];
        for (int i = axis + 1; i < rank; i++) innerSize *= shape[i];

        Parallel.For(0, outerSize * innerSize, idx =>
        {
            int outer = idx / innerSize;
            int inner = idx % innerSize;

            // Find argmax
            int maxIdx = 0;
            T maxVal = softData[(outer * axisSize) * innerSize + inner];
            for (int i = 1; i < axisSize; i++)
            {
                int flatIdx = (outer * axisSize + i) * innerSize + inner;
                if (numOps.GreaterThan(softData[flatIdx], maxVal))
                {
                    maxVal = softData[flatIdx];
                    maxIdx = i;
                }
            }

            // Create one-hot
            for (int i = 0; i < axisSize; i++)
            {
                int flatIdx = (outer * axisSize + i) * innerSize + inner;
                hardData[flatIdx] = i == maxIdx ? numOps.One : numOps.Zero;
            }
        });

        // Hard mode straight-through estimator: forward returns the one-hot,
        // backward routes gradient as if forward returned the soft sample.
        // We pass `softResult` (the soft sample) to GumbelSoftmaxBackward via
        // savedState — the engine kernel uses it for the softmax-Jacobian
        // step. inputs[0]=input is what gradient accumulates into.
        var hardResult = TensorAllocator.Rent<T>(shape, new Vector<T>(hardData));
        DifferentiableOps.RecordUnary("GumbelSoftmax", hardResult, input,
            BackwardFunctions<T>.GumbelSoftmaxStraightThroughBackward,
            new object[] { temperature, axis, softResult });
        return hardResult;
    }

    /// <inheritdoc/>
    public Tensor<T> GumbelSoftmaxBackward<T>(Tensor<T> gradOutput, Tensor<T> output, double temperature, int axis = -1)
    {
        if (gradOutput == null) throw new ArgumentNullException(nameof(gradOutput));
        if (output == null) throw new ArgumentNullException(nameof(output));
        var gradOutputOrig = gradOutput;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!gradOutput.IsContiguous) gradOutput = gradOutput.Contiguous();
        if (!output.IsContiguous) throw new InvalidOperationException("Output tensor must be contiguous.");
        if (temperature <= 0)
            throw new ArgumentOutOfRangeException(nameof(temperature), temperature, "Temperature must be positive.");

        // Gradient flows through softmax, scaled by 1/temperature
        var softmaxGrad = SoftmaxBackward(gradOutput, output, axis);
        var numOps = MathHelper.GetNumericOperations<T>();
        var gradData = softmaxGrad.GetDataArray();
        var scale = numOps.FromDouble(1.0 / temperature);

        for (int i = 0; i < gradOutput.Length; i++)
        {
            gradData[i] = numOps.Multiply(gradData[i], scale);
        }

        return TensorAllocator.Rent<T>(output._shape, new Vector<T>(gradData));
    }

    /// <inheritdoc/>
    public Tensor<T> TaylorSoftmax<T>(Tensor<T> input, int order = 2, int axis = -1)
    {
        if (input == null) throw new ArgumentNullException(nameof(input));
        if (order < 1)
            throw new ArgumentOutOfRangeException(nameof(order), order, "Order must be at least 1.");
        if (GraphMode.IsActive) { var scope = GraphMode.Current; if (scope is not null) { var c_input = input; var c_order = order; var c_axis = axis; return scope.RecordUnary(LazyNodeType.Custom, "TaylorSoftmax", input, input._shape, (eng, output) => { var r = eng.TaylorSoftmax(c_input, c_order, c_axis); r.AsSpan().CopyTo(output.AsWritableSpan()); }, BackwardFunctions<T>.SoftmaxBackward); } }
        { var ac = AutoTracer.TryGetCompiledPlan<T>("TaylorSoftmax", input._shape); if (ac is not null) return ac.Execute(); }

        var numOps = MathHelper.GetNumericOperations<T>();
        int rank = input.Rank;
        if (axis < 0) axis = rank + axis;

        var inputData = input.GetFlattenedData();
        var shape = input._shape;
        var outputData = new T[input.Length];

        // Precompute factorials
        var factorials = new double[order + 1];
        factorials[0] = 1;
        for (int i = 1; i <= order; i++)
            factorials[i] = factorials[i - 1] * i;

        int outerSize = 1, axisSize = shape[axis], innerSize = 1;
        for (int i = 0; i < axis; i++) outerSize *= shape[i];
        for (int i = axis + 1; i < rank; i++) innerSize *= shape[i];

        Parallel.For(0, outerSize * innerSize, idx =>
        {
            int outer = idx / innerSize;
            int inner = idx % innerSize;

            // Find max for numerical stability (similar to standard softmax)
            var maxVal = inputData[(outer * axisSize) * innerSize + inner];
            for (int i = 1; i < axisSize; i++)
            {
                int flatIdx = (outer * axisSize + i) * innerSize + inner;
                if (numOps.GreaterThan(inputData[flatIdx], maxVal))
                    maxVal = inputData[flatIdx];
            }

            // Compute Taylor approximation of exp for each position along axis
            var expApprox = new T[axisSize];
            T sumExp = numOps.Zero;

            for (int i = 0; i < axisSize; i++)
            {
                int flatIdx = (outer * axisSize + i) * innerSize + inner;
                // Subtract max for numerical stability
                var x = numOps.Subtract(inputData[flatIdx], maxVal);

                // Taylor: 1 + x + x^2/2! + x^3/3! + ...
                var taylorExp = numOps.One;
                var xPower = numOps.One;
                for (int n = 1; n <= order; n++)
                {
                    xPower = numOps.Multiply(xPower, x);
                    taylorExp = numOps.Add(taylorExp, numOps.Divide(xPower, numOps.FromDouble(factorials[n])));
                }

                // Ensure non-negative for numerical stability
                if (numOps.LessThan(taylorExp, numOps.Zero))
                    taylorExp = numOps.FromDouble(1e-10);

                expApprox[i] = taylorExp;
                sumExp = numOps.Add(sumExp, taylorExp);
            }

            // Guard against zero sum (shouldn't happen with proper max subtraction, but just in case)
            if (numOps.Equals(sumExp, numOps.Zero))
                sumExp = numOps.FromDouble(1e-10);

            // Normalize
            for (int i = 0; i < axisSize; i++)
            {
                int flatIdx = (outer * axisSize + i) * innerSize + inner;
                outputData[flatIdx] = numOps.Divide(expApprox[i], sumExp);
            }
        });

        var taylorResult = TensorAllocator.Rent<T>(shape, new Vector<T>(outputData));
        DifferentiableOps.RecordUnary("TaylorSoftmax", taylorResult, input, BackwardFunctions<T>.TaylorSoftmaxBackward, new object[] { order, axis });
        { var ci = input; var co = order; var ca = axis; AutoTracer.RecordOp("TaylorSoftmax", taylorResult, eng => eng.TaylorSoftmax(ci, co, ca)); }
        return taylorResult;
    }

    /// <inheritdoc/>
    public Tensor<T> TaylorSoftmaxBackward<T>(Tensor<T> gradOutput, Tensor<T> input, Tensor<T> output, int order, int axis = -1)
    {
        if (gradOutput == null) throw new ArgumentNullException(nameof(gradOutput));
        if (input == null) throw new ArgumentNullException(nameof(input));
        if (output == null) throw new ArgumentNullException(nameof(output));
        if (!output.IsContiguous) throw new InvalidOperationException("Output tensor must be contiguous.");
        var inputOrig = input;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!input.IsContiguous) input = input.Contiguous();

        var numOps = MathHelper.GetNumericOperations<T>();
        int rank = output.Rank;
        if (axis < 0) axis = rank + axis;

        var gradOutputData = gradOutput.GetFlattenedData();
        var inputData = input.GetFlattenedData();
        var outputData = output.GetDataArray();
        var shape = output._shape;
        var gradInputData = new T[outputData.Length];

        // Precompute factorials for derivative
        var factorials = new double[order + 1];
        factorials[0] = 1;
        for (int i = 1; i <= order; i++)
            factorials[i] = factorials[i - 1] * i;

        int outerSize = 1, axisSize = shape[axis], innerSize = 1;
        for (int i = 0; i < axis; i++) outerSize *= shape[i];
        for (int i = axis + 1; i < rank; i++) innerSize *= shape[i];

        Parallel.For(0, outerSize * innerSize, idx =>
        {
            int outer = idx / innerSize;
            int inner = idx % innerSize;

            // Compute g(x) and g'(x) for each position
            var gValues = new T[axisSize];
            var gPrimeValues = new T[axisSize];
            T sumG = numOps.Zero;

            for (int i = 0; i < axisSize; i++)
            {
                int flatIdx = (outer * axisSize + i) * innerSize + inner;
                var x = inputData[flatIdx];

                // g(x) = Taylor approximation
                var g = numOps.One;
                var xPower = numOps.One;
                for (int n = 1; n <= order; n++)
                {
                    xPower = numOps.Multiply(xPower, x);
                    g = numOps.Add(g, numOps.Divide(xPower, numOps.FromDouble(factorials[n])));
                }

                // g'(x) = derivative of Taylor = 1 + x + x^2/2! + ... (shifted)
                var gPrime = numOps.One;
                xPower = numOps.One;
                for (int n = 1; n < order; n++)
                {
                    xPower = numOps.Multiply(xPower, x);
                    gPrime = numOps.Add(gPrime, numOps.Divide(xPower, numOps.FromDouble(factorials[n])));
                }

                gValues[i] = g;
                gPrimeValues[i] = gPrime;
                sumG = numOps.Add(sumG, g);
            }

            // Compute gradient using chain rule: grad = softmaxGrad * g'(x) / g(x)
            T dotProduct = numOps.Zero;
            for (int i = 0; i < axisSize; i++)
            {
                int flatIdx = (outer * axisSize + i) * innerSize + inner;
                dotProduct = numOps.Add(dotProduct, numOps.Multiply(gradOutputData[flatIdx], outputData[flatIdx]));
            }

            for (int i = 0; i < axisSize; i++)
            {
                int flatIdx = (outer * axisSize + i) * innerSize + inner;
                var softmaxGrad = numOps.Multiply(outputData[flatIdx], numOps.Subtract(gradOutputData[flatIdx], dotProduct));
                var gPrimeOverG = numOps.Divide(gPrimeValues[i], gValues[i]);
                gradInputData[flatIdx] = numOps.Multiply(softmaxGrad, gPrimeOverG);
            }
        });

        return TensorAllocator.Rent<T>(shape, new Vector<T>(gradInputData));
    }

    /// <inheritdoc/>
    public Tensor<T> Sparsemax<T>(Tensor<T> input, int axis = -1)
    {
        if (input == null) throw new ArgumentNullException(nameof(input));
        if (GraphMode.IsActive) { var scope = GraphMode.Current; if (scope is not null) { var c_input = input; var c_axis = axis; return scope.RecordUnary(LazyNodeType.Custom, "Sparsemax", input, input._shape, (eng, output) => { var r = eng.Sparsemax(c_input, c_axis); r.AsSpan().CopyTo(output.AsWritableSpan()); }, BackwardFunctions<T>.SparsemaxBackward); } }
        { var ac = AutoTracer.TryGetCompiledPlan<T>("Sparsemax", input._shape); if (ac is not null) return ac.Execute(); }

        var numOps = MathHelper.GetNumericOperations<T>();
        int rank = input.Rank;
        if (axis < 0) axis = rank + axis;

        var inputData = input.GetFlattenedData();
        var shape = input._shape;
        var outputData = new T[input.Length];

        int outerSize = 1, axisSize = shape[axis], innerSize = 1;
        for (int i = 0; i < axis; i++) outerSize *= shape[i];
        for (int i = axis + 1; i < rank; i++) innerSize *= shape[i];

        Parallel.For(0, outerSize * innerSize, idx =>
        {
            int outer = idx / innerSize;
            int inner = idx % innerSize;

            // Extract values along axis and sort by value (descending)
            var indexed = new List<(T value, int idx)>();
            for (int i = 0; i < axisSize; i++)
            {
                int flatIdx = (outer * axisSize + i) * innerSize + inner;
                indexed.Add((inputData[flatIdx], i));
            }

            indexed.Sort((a, b) =>
            {
                if (numOps.GreaterThan(a.value, b.value)) return -1;
                if (numOps.LessThan(a.value, b.value)) return 1;
                return 0;
            });

            // Find threshold tau using the sparsemax algorithm
            T cumSum = numOps.Zero;
            int k = 0;
            T threshold = numOps.Zero;

            for (int i = 0; i < axisSize; i++)
            {
                cumSum = numOps.Add(cumSum, indexed[i].value);
                // Check if z[i] > (cumSum - 1) / (i + 1)
                var kPlusOne = numOps.FromDouble(i + 1);
                var testThreshold = numOps.Divide(numOps.Subtract(cumSum, numOps.One), kPlusOne);
                if (numOps.GreaterThan(indexed[i].value, testThreshold))
                {
                    k = i + 1;
                    threshold = testThreshold;
                }
            }

            // Compute output: max(0, z - tau)
            for (int i = 0; i < axisSize; i++)
            {
                int flatIdx = (outer * axisSize + i) * innerSize + inner;
                var val = numOps.Subtract(inputData[flatIdx], threshold);
                outputData[flatIdx] = numOps.GreaterThan(val, numOps.Zero) ? val : numOps.Zero;
            }
        });

        var sparsemaxResult = TensorAllocator.Rent<T>(shape, new Vector<T>(outputData));
        DifferentiableOps.RecordUnary("Sparsemax", sparsemaxResult, input, BackwardFunctions<T>.SparsemaxBackward, new object[] { axis });
        { var ci = input; var ca = axis; AutoTracer.RecordOp("Sparsemax", sparsemaxResult, eng => eng.Sparsemax(ci, ca)); }
        return sparsemaxResult;
    }

    /// <inheritdoc/>
    public Tensor<T> SparsemaxBackward<T>(Tensor<T> gradOutput, Tensor<T> output, int axis = -1)
    {
        if (gradOutput == null) throw new ArgumentNullException(nameof(gradOutput));
        if (output == null) throw new ArgumentNullException(nameof(output));
        if (!output.IsContiguous) throw new InvalidOperationException("Output tensor must be contiguous.");

        var numOps = MathHelper.GetNumericOperations<T>();
        int rank = output.Rank;
        if (axis < 0) axis = rank + axis;

        var gradOutputData = gradOutput.GetFlattenedData();
        var outputData = output.GetDataArray();
        var shape = output._shape;
        var gradInputData = new T[outputData.Length];

        int outerSize = 1, axisSize = shape[axis], innerSize = 1;
        for (int i = 0; i < axis; i++) outerSize *= shape[i];
        for (int i = axis + 1; i < rank; i++) innerSize *= shape[i];

        Parallel.For(0, outerSize * innerSize, idx =>
        {
            int outer = idx / innerSize;
            int inner = idx % innerSize;

            // Find support set (non-zero outputs) and compute mean of gradients in support
            T sumGradSupport = numOps.Zero;
            int supportSize = 0;

            for (int i = 0; i < axisSize; i++)
            {
                int flatIdx = (outer * axisSize + i) * innerSize + inner;
                if (numOps.GreaterThan(outputData[flatIdx], numOps.Zero))
                {
                    sumGradSupport = numOps.Add(sumGradSupport, gradOutputData[flatIdx]);
                    supportSize++;
                }
            }

            T meanGradSupport = supportSize > 0
                ? numOps.Divide(sumGradSupport, numOps.FromDouble(supportSize))
                : numOps.Zero;

            // Gradient: grad_input = grad_output - mean(grad_output[support]) for support, 0 otherwise
            for (int i = 0; i < axisSize; i++)
            {
                int flatIdx = (outer * axisSize + i) * innerSize + inner;
                gradInputData[flatIdx] = numOps.GreaterThan(outputData[flatIdx], numOps.Zero)
                    ? numOps.Subtract(gradOutputData[flatIdx], meanGradSupport)
                    : numOps.Zero;
            }
        });

        return TensorAllocator.Rent<T>(shape, new Vector<T>(gradInputData));
    }

    /// <inheritdoc/>
    public Tensor<T> SphericalSoftmax<T>(Tensor<T> input, int axis = -1)
    {
        if (input == null) throw new ArgumentNullException(nameof(input));

        var numOps = MathHelper.GetNumericOperations<T>();
        int rank = input.Rank;
        if (axis < 0) axis = rank + axis;

        var inputData = input.GetFlattenedData();
        var shape = input._shape;
        var normalizedData = new T[input.Length];

        int outerSize = 1, axisSize = shape[axis], innerSize = 1;
        for (int i = 0; i < axis; i++) outerSize *= shape[i];
        for (int i = axis + 1; i < rank; i++) innerSize *= shape[i];

        Parallel.For(0, outerSize * innerSize, idx =>
        {
            int outer = idx / innerSize;
            int inner = idx % innerSize;

            // Compute L2 norm along axis
            T sumSquares = numOps.Zero;
            for (int i = 0; i < axisSize; i++)
            {
                int flatIdx = (outer * axisSize + i) * innerSize + inner;
                var val = inputData[flatIdx];
                sumSquares = numOps.Add(sumSquares, numOps.Multiply(val, val));
            }
            var norm = numOps.Sqrt(sumSquares);

            // Avoid division by zero
            if (numOps.Equals(norm, numOps.Zero))
                norm = numOps.FromDouble(1e-10);

            // Normalize by L2 norm
            for (int i = 0; i < axisSize; i++)
            {
                int flatIdx = (outer * axisSize + i) * innerSize + inner;
                normalizedData[flatIdx] = numOps.Divide(inputData[flatIdx], norm);
            }
        });

        // Apply softmax to normalized data — wrap in NoGradScope so the
        // inner Softmax doesn't record a (normalized → output) edge that
        // doesn't extend back to `input`. The all-in-one
        // SphericalSoftmaxBackward kernel handles both the L2-normalization
        // Jacobian and the softmax Jacobian as a single composed step.
        Tensor<T> sphResult;
        using (new NoGradScope<T>())
        {
            var normalizedTensor = TensorAllocator.Rent<T>(shape, new Vector<T>(normalizedData));
            sphResult = Softmax(normalizedTensor, axis);
        }
        DifferentiableOps.RecordUnary("SphericalSoftmax", sphResult, input,
            BackwardFunctions<T>.SphericalSoftmaxBackward, new object[] { axis });
        return sphResult;
    }

    /// <inheritdoc/>
    public Tensor<T> SphericalSoftmaxBackward<T>(Tensor<T> gradOutput, Tensor<T> input, Tensor<T> output, int axis = -1)
    {
        if (gradOutput == null) throw new ArgumentNullException(nameof(gradOutput));
        if (input == null) throw new ArgumentNullException(nameof(input));
        if (output == null) throw new ArgumentNullException(nameof(output));
        if (!output.IsContiguous) throw new InvalidOperationException("Output tensor must be contiguous.");
        var inputOrig = input;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!input.IsContiguous) input = input.Contiguous();
        var gradOutputOrig = gradOutput;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!gradOutput.IsContiguous) gradOutput = gradOutput.Contiguous();

        var numOps = MathHelper.GetNumericOperations<T>();
        int rank = input.Rank;
        if (axis < 0) axis = rank + axis;

        var inputData = input.GetFlattenedData();
        var shape = input._shape;

        int outerSize = 1, axisSize = shape[axis], innerSize = 1;
        for (int i = 0; i < axis; i++) outerSize *= shape[i];
        for (int i = axis + 1; i < rank; i++) innerSize *= shape[i];

        // First compute the normalized input
        var normalizedData = new T[input.Length];
        var norms = new T[outerSize * innerSize];

        Parallel.For(0, outerSize * innerSize, idx =>
        {
            int outer = idx / innerSize;
            int inner = idx % innerSize;

            // Compute L2 norm
            T sumSquares = numOps.Zero;
            for (int i = 0; i < axisSize; i++)
            {
                int flatIdx = (outer * axisSize + i) * innerSize + inner;
                var val = inputData[flatIdx];
                sumSquares = numOps.Add(sumSquares, numOps.Multiply(val, val));
            }
            var norm = numOps.Sqrt(sumSquares);
            if (numOps.Equals(norm, numOps.Zero))
                norm = numOps.FromDouble(1e-10);
            norms[idx] = norm;

            // Normalize
            for (int i = 0; i < axisSize; i++)
            {
                int flatIdx = (outer * axisSize + i) * innerSize + inner;
                normalizedData[flatIdx] = numOps.Divide(inputData[flatIdx], norm);
            }
        });

        // Get softmax gradient with respect to normalized input
        var normalizedTensor = TensorAllocator.Rent<T>(shape, new Vector<T>(normalizedData));
        var softmaxGrad = SoftmaxBackward(gradOutput, output, axis);
        var softmaxGradData = softmaxGrad.GetDataArray();

        // Chain rule through L2 normalization
        var gradInputData = new T[input.Length];

        Parallel.For(0, outerSize * innerSize, idx =>
        {
            int outer = idx / innerSize;
            int inner = idx % innerSize;
            var norm = norms[idx];
            var normCubed = numOps.Multiply(norm, numOps.Multiply(norm, norm));

            // Compute dot product of x and grad_normalized
            T dotProduct = numOps.Zero;
            for (int i = 0; i < axisSize; i++)
            {
                int flatIdx = (outer * axisSize + i) * innerSize + inner;
                dotProduct = numOps.Add(dotProduct, numOps.Multiply(inputData[flatIdx], softmaxGradData[flatIdx]));
            }

            // grad_x = (grad_normalized - normalized * dot_product) / norm
            for (int i = 0; i < axisSize; i++)
            {
                int flatIdx = (outer * axisSize + i) * innerSize + inner;
                var term = numOps.Multiply(normalizedData[flatIdx], dotProduct);
                gradInputData[flatIdx] = numOps.Divide(numOps.Subtract(softmaxGradData[flatIdx], term), norm);
            }
        });

        return TensorAllocator.Rent<T>(shape, new Vector<T>(gradInputData));
    }

    /// <inheritdoc/>
    public virtual Tensor<T> BatchNorm<T>(Tensor<T> input, Tensor<T> gamma, Tensor<T> beta, double epsilon, out Tensor<T> mean, out Tensor<T> variance)
    {
        using var _opScope = AiDotNet.Tensors.Engines.Profiling.Profiler.OpScope("BatchNorm");
        if (input == null) throw new ArgumentNullException(nameof(input));
        if (gamma == null) throw new ArgumentNullException(nameof(gamma));
        if (beta == null) throw new ArgumentNullException(nameof(beta));

        // GraphMode: execute eagerly (out params), but record result in graph for compiled plan
        if (GraphMode.IsActive)
        {
            var scope = GraphMode.Current;
            if (scope != null)
            {
                var ci = input; var cg = gamma; var cb = beta; double ce = epsilon;
                // Execute eagerly to fill out params
                var savedScope = GraphMode.Current;
                GraphMode.SetCurrent(null);
                var eagerResult = BatchNorm(ci, cg, cb, ce, out mean, out variance);
                GraphMode.SetCurrent(savedScope);
                // Record in graph so compiled plan captures the dependency
                var lazyResult = scope.RecordVariadic(LazyNodeType.Custom, "BatchNorm",
                    new[] { input, gamma, beta }, eagerResult._shape,
                    (eng, output) => { var r = eng.BatchNorm(ci, cg, cb, ce, out _, out _); r.AsSpan().CopyTo(output.AsWritableSpan()); },
                    BackwardFunctions<T>.BatchNormBackward, new object[] { mean, variance, epsilon });
                // Copy eager data into lazy output
                eagerResult.AsSpan().CopyTo(lazyResult.AsWritableSpan());
                return lazyResult;
            }
        }

        // Preserve original input ref for tape recording (#257) — Contiguous()
        // returns a fresh tensor with no GradFn, breaking the chain back to the
        // upstream parameter when input is a strided view (e.g. from Permute).
        var inputOrig = input;
        if (!input.IsContiguous) input = input.Contiguous();

        var numOps = MathHelper.GetNumericOperations<T>();
        T eps = numOps.FromDouble(epsilon);

        // Handle 1D [features] - treat as single sample [1, features]
        bool was1D = input._shape.Length == 1;
        Tensor<T> workingInput = was1D ? input.Reshape([1, input._shape[0]]) : input;

        // Handle 2D [batch, features], 3D [channels, height, width], and 4D [batch, channels, height, width] tensors
        if (workingInput._shape.Length == 4)
        {
            var result4D = BatchNorm4D(workingInput, gamma, beta, eps, numOps, out mean, out variance);
            var r4 = was1D ? result4D.Reshape([result4D._shape[1]]) : result4D;
            DifferentiableOps.RecordIfActive("BatchNorm", r4, new[] { inputOrig, gamma, beta }, BackwardFunctions<T>.BatchNormBackward, new object[] { mean, variance, epsilon });
            AutoTracer.RecordOp("BatchNorm", r4, eng => r4);
            return r4;
        }

        if (workingInput._shape.Length == 3)
        {
            var result3D = BatchNorm3D(workingInput, gamma, beta, eps, numOps, out mean, out variance);
            var r3 = was1D ? result3D.Reshape([result3D.Length]) : result3D;
            DifferentiableOps.RecordIfActive("BatchNorm", r3, new[] { inputOrig, gamma, beta }, BackwardFunctions<T>.BatchNormBackward, new object[] { mean, variance, epsilon });
            return r3;
        }

        // 2D case: [batch, features]
        int batch = workingInput._shape[0];
        int features = workingInput._shape[1];

        var inputData = workingInput.GetDataArray();
        var gammaData = gamma.GetDataArray();
        var betaData = beta.GetDataArray();

        var meanData = new T[features];
        var varData = new T[features];
        var outputData = new T[batch * features];

        // Compute mean per feature
        for (int f = 0; f < features; f++)
        {
            T sum = numOps.Zero;
            for (int b = 0; b < batch; b++)
            {
                sum = numOps.Add(sum, inputData[b * features + f]);
            }
            meanData[f] = numOps.Divide(sum, numOps.FromDouble(batch));
        }

        // Compute variance per feature
        for (int f = 0; f < features; f++)
        {
            T sumSq = numOps.Zero;
            for (int b = 0; b < batch; b++)
            {
                T diff = numOps.Subtract(inputData[b * features + f], meanData[f]);
                sumSq = numOps.Add(sumSq, numOps.Multiply(diff, diff));
            }
            varData[f] = numOps.Divide(sumSq, numOps.FromDouble(batch));
        }

        // Normalize and scale
        Parallel.For(0, batch, b =>
        {
            for (int f = 0; f < features; f++)
            {
                T normalized = numOps.Divide(
                    numOps.Subtract(inputData[b * features + f], meanData[f]),
                    numOps.Sqrt(numOps.Add(varData[f], eps)));
                outputData[b * features + f] = numOps.Add(numOps.Multiply(gammaData[f], normalized), betaData[f]);
            }
        });

        mean = TensorAllocator.Rent<T>([features], new Vector<T>(meanData));
        variance = TensorAllocator.Rent<T>([features], new Vector<T>(varData));

        // Return with original shape (restore 1D if input was 1D)
        var result = TensorAllocator.Rent<T>(workingInput._shape, new Vector<T>(outputData));
        var bnResult = was1D ? result.Reshape([features]) : result;
        DifferentiableOps.RecordIfActive("BatchNorm", bnResult, new[] { inputOrig, gamma, beta }, BackwardFunctions<T>.BatchNormBackward, new object[] { mean, variance, epsilon });
        return bnResult;
    }

    /// <summary>
    /// Batch normalization for 3D tensors [channels, height, width].
    /// Normalizes per channel across height and width dimensions.
    /// </summary>
    private Tensor<T> BatchNorm3D<T>(Tensor<T> input, Tensor<T> gamma, Tensor<T> beta, T eps, INumericOperations<T> numOps, out Tensor<T> mean, out Tensor<T> variance)
    {
        int channels = input._shape[0];
        int height = input._shape[1];
        int width = input._shape[2];
        int spatialSize = height * width;

        var inputData = input.GetDataArray();
        var gammaData = gamma.GetDataArray();
        var betaData = beta.GetDataArray();

        var meanData = new T[channels];
        var varData = new T[channels];
        var outputData = new T[input.Length];

        // Compute mean per channel (across height, width)
        Parallel.For(0, channels, c =>
        {
            T sum = numOps.Zero;
            int channelOffset = c * spatialSize;
            for (int s = 0; s < spatialSize; s++)
            {
                sum = numOps.Add(sum, inputData[channelOffset + s]);
            }
            meanData[c] = numOps.Divide(sum, numOps.FromDouble(spatialSize));
        });

        // Compute variance per channel
        Parallel.For(0, channels, c =>
        {
            T sumSq = numOps.Zero;
            T channelMean = meanData[c];
            int channelOffset = c * spatialSize;
            for (int s = 0; s < spatialSize; s++)
            {
                T diff = numOps.Subtract(inputData[channelOffset + s], channelMean);
                sumSq = numOps.Add(sumSq, numOps.Multiply(diff, diff));
            }
            varData[c] = numOps.Divide(sumSq, numOps.FromDouble(spatialSize));
        });

        // Normalize and scale
        Parallel.For(0, channels, c =>
        {
            T channelMean = meanData[c];
            T channelStdInv = numOps.Divide(numOps.One, numOps.Sqrt(numOps.Add(varData[c], eps)));
            T gammaVal = gammaData[c];
            T betaVal = betaData[c];
            int channelOffset = c * spatialSize;

            for (int s = 0; s < spatialSize; s++)
            {
                T normalized = numOps.Multiply(numOps.Subtract(inputData[channelOffset + s], channelMean), channelStdInv);
                outputData[channelOffset + s] = numOps.Add(numOps.Multiply(gammaVal, normalized), betaVal);
            }
        });

        mean = TensorAllocator.Rent<T>([channels], new Vector<T>(meanData));
        variance = TensorAllocator.Rent<T>([channels], new Vector<T>(varData));
        return TensorAllocator.Rent<T>(input._shape, new Vector<T>(outputData));
    }


    /// <summary>
    /// Batch normalization for 4D tensors [batch, channels, height, width].
    /// Normalizes per channel across batch, height, and width dimensions.
    /// </summary>
    private Tensor<T> BatchNorm4D<T>(Tensor<T> input, Tensor<T> gamma, Tensor<T> beta, T eps, INumericOperations<T> numOps, out Tensor<T> mean, out Tensor<T> variance)
    {
        int batch = input._shape[0];
        int channels = input._shape[1];
        int height = input._shape[2];
        int width = input._shape[3];
        int spatialSize = height * width;
        int elementsPerChannel = batch * spatialSize;

        var inputData = input.GetDataArray();
        var gammaData = gamma.GetDataArray();
        var betaData = beta.GetDataArray();

        // Float fast path with SIMD
        if (inputData is float[] inF && gammaData is float[] gamF && betaData is float[] betF)
        {
            float epsF = numOps.ToDouble(eps) is double d ? (float)d : 1e-5f;
            var meanF = new float[channels];
            var varF = new float[channels];
#if NET5_0_OR_GREATER
            var outF = GC.AllocateUninitializedArray<float>(inF.Length);
#else
            var outF = new float[inF.Length];
#endif
            BatchNorm4DFloat(inF, gamF, betF, epsF, batch, channels, spatialSize, meanF, varF, outF);
            mean = (Tensor<T>)(object)TensorAllocator.Rent<T>(new[] { channels }, (Vector<T>)(object)Vector<float>.FromMemory(meanF));
            variance = (Tensor<T>)(object)TensorAllocator.Rent<T>(new[] { channels }, (Vector<T>)(object)Vector<float>.FromMemory(varF));
            return (Tensor<T>)(object)TensorAllocator.Rent<T>(input._shape, (Vector<T>)(object)Vector<float>.FromMemory(outF));
        }

        var meanData = new T[channels];
        var varData = new T[channels];
        var outputData = new T[input.Length];

        for (int c = 0; c < channels; c++)
        {
            // Mean
            T sum = numOps.Zero;
            for (int n = 0; n < batch; n++)
            {
                int offset = n * channels * spatialSize + c * spatialSize;
                for (int s = 0; s < spatialSize; s++)
                    sum = numOps.Add(sum, inputData[offset + s]);
            }
            meanData[c] = numOps.Divide(sum, numOps.FromDouble(elementsPerChannel));

            // Variance
            T sumSq = numOps.Zero;
            for (int n = 0; n < batch; n++)
            {
                int offset = n * channels * spatialSize + c * spatialSize;
                for (int s = 0; s < spatialSize; s++)
                {
                    T diff = numOps.Subtract(inputData[offset + s], meanData[c]);
                    sumSq = numOps.Add(sumSq, numOps.Multiply(diff, diff));
                }
            }
            varData[c] = numOps.Divide(sumSq, numOps.FromDouble(elementsPerChannel));

            // Normalize
            T invStd = numOps.Divide(numOps.One, numOps.Sqrt(numOps.Add(varData[c], eps)));
            for (int n = 0; n < batch; n++)
            {
                int offset = n * channels * spatialSize + c * spatialSize;
                for (int s = 0; s < spatialSize; s++)
                {
                    int idx = offset + s;
                    outputData[idx] = numOps.Add(numOps.Multiply(gammaData[c], numOps.Multiply(numOps.Subtract(inputData[idx], meanData[c]), invStd)), betaData[c]);
                }
            }
        }

        mean = TensorAllocator.Rent<T>(new[] { channels }, new Vector<T>(meanData));
        variance = TensorAllocator.Rent<T>(new[] { channels }, new Vector<T>(varData));
        return TensorAllocator.Rent<T>(input._shape, new Vector<T>(outputData));
    }

    private static unsafe void BatchNorm4DFloat(float[] input, float[] gamma, float[] beta, float eps,
        int batch, int channels, int spatialSize, float[] meanOut, float[] varOut, float[] output)
    {
        int elementsPerChannel = batch * spatialSize;
        float invCount = 1f / elementsPerChannel;

        // Parallelize across channels via PersistentParallelExecutor (~5 µs
        // dispatch vs Parallel.For's ~50 µs). At BatchNorm call rates inside
        // training loops this saves ~45 µs per call. #209 close-parity:
        // closes ~3% of the gap to libtorch's MKL-DNN routing.
        Helpers.PersistentParallelExecutor.Instance.Execute(channels, c =>
        {
            BatchNorm4DFloatChannel(input, gamma, beta, eps, batch, channels, spatialSize,
                invCount, c, meanOut, varOut, output);
        });
    }

    private static unsafe void BatchNorm4DFloatChannel(float[] input, float[] gamma, float[] beta, float eps,
        int batch, int channels, int spatialSize, float invCount, int c,
        float[] meanOut, float[] varOut, float[] output)
    {
        {
#if NET5_0_OR_GREATER
            if (System.Runtime.Intrinsics.X86.Fma.IsSupported && spatialSize >= 32)
            {
                // Pin once for all passes — avoids per-pass pinning overhead.
                fixed (float* inp = input, outp = output)
                {
                    // FUSED Pass 1+2: simultaneous sum AND sum-of-squares via
                    //   Var[X] = E[X²] - E[X]²
                    // Cuts input reads from 3× to 2× — saves one full sweep
                    // over the per-channel data (matches the LayerNorm fix).
                    // 4-way unrolled to saturate both FMA ports on Zen 2.
                    float sum = 0f;
                    float sumSq = 0f;
                    var vsum0 = System.Runtime.Intrinsics.Vector256<float>.Zero;
                    var vsum1 = System.Runtime.Intrinsics.Vector256<float>.Zero;
                    var vsum2 = System.Runtime.Intrinsics.Vector256<float>.Zero;
                    var vsum3 = System.Runtime.Intrinsics.Vector256<float>.Zero;
                    var vsq0 = System.Runtime.Intrinsics.Vector256<float>.Zero;
                    var vsq1 = System.Runtime.Intrinsics.Vector256<float>.Zero;
                    var vsq2 = System.Runtime.Intrinsics.Vector256<float>.Zero;
                    var vsq3 = System.Runtime.Intrinsics.Vector256<float>.Zero;
                    for (int n = 0; n < batch; n++)
                    {
                        int offset = n * channels * spatialSize + c * spatialSize;
                        float* ptr = inp + offset;
                        int s = 0;
                        int simdLen = spatialSize & ~31;
                        for (; s < simdLen; s += 32)
                        {
                            var v0 = System.Runtime.Intrinsics.X86.Avx.LoadVector256(ptr + s);
                            var v1 = System.Runtime.Intrinsics.X86.Avx.LoadVector256(ptr + s + 8);
                            var v2v = System.Runtime.Intrinsics.X86.Avx.LoadVector256(ptr + s + 16);
                            var v3 = System.Runtime.Intrinsics.X86.Avx.LoadVector256(ptr + s + 24);
                            vsum0 = System.Runtime.Intrinsics.X86.Avx.Add(vsum0, v0);
                            vsum1 = System.Runtime.Intrinsics.X86.Avx.Add(vsum1, v1);
                            vsum2 = System.Runtime.Intrinsics.X86.Avx.Add(vsum2, v2v);
                            vsum3 = System.Runtime.Intrinsics.X86.Avx.Add(vsum3, v3);
                            vsq0 = System.Runtime.Intrinsics.X86.Fma.MultiplyAdd(v0, v0, vsq0);
                            vsq1 = System.Runtime.Intrinsics.X86.Fma.MultiplyAdd(v1, v1, vsq1);
                            vsq2 = System.Runtime.Intrinsics.X86.Fma.MultiplyAdd(v2v, v2v, vsq2);
                            vsq3 = System.Runtime.Intrinsics.X86.Fma.MultiplyAdd(v3, v3, vsq3);
                        }
                        for (; s < spatialSize; s++)
                        {
                            float x = ptr[s];
                            sum += x;
                            sumSq += x * x;
                        }
                    }
                    vsum0 = System.Runtime.Intrinsics.X86.Avx.Add(System.Runtime.Intrinsics.X86.Avx.Add(vsum0, vsum1), System.Runtime.Intrinsics.X86.Avx.Add(vsum2, vsum3));
                    sum += SimdKernels.HorizontalSum(vsum0);
                    vsq0 = System.Runtime.Intrinsics.X86.Avx.Add(System.Runtime.Intrinsics.X86.Avx.Add(vsq0, vsq1), System.Runtime.Intrinsics.X86.Avx.Add(vsq2, vsq3));
                    sumSq += SimdKernels.HorizontalSum(vsq0);

                    float channelMean = sum * invCount;
                    meanOut[c] = channelMean;
                    var vmean = System.Runtime.Intrinsics.Vector256.Create(channelMean);
                    // Variance via E[X²] - E[X]². Numerical-safety clamp:
                    // catastrophic cancellation can drive this slightly
                    // negative for near-uniform channels — clamp to 0
                    // (matches the LayerNorm clamp; gives invStd → ∞ which
                    // produces zero output for zero-variance channels, the
                    // correct degenerate normalization result).
                    float channelVar = sumSq * invCount - channelMean * channelMean;
                    if (channelVar < 0f) channelVar = 0f;
                    varOut[c] = channelVar;
                    float invStd = 1f / MathF.Sqrt(channelVar + eps);
                    float g = gamma[c];
                    float b = beta[c];

                    // Pass 3: Normalize with 4x unrolled FMA: output = gamma * (x - mean) * invStd + beta
                    var vscale = System.Runtime.Intrinsics.Vector256.Create(g * invStd);
                    var vbias = System.Runtime.Intrinsics.Vector256.Create(b);
                    for (int n = 0; n < batch; n++)
                    {
                        int offset = n * channels * spatialSize + c * spatialSize;
                        float* pi = inp + offset;
                        float* po = outp + offset;
                        int s = 0;
                        int simdLen = spatialSize & ~31;
                        for (; s < simdLen; s += 32)
                        {
                            var d0 = System.Runtime.Intrinsics.X86.Avx.Subtract(System.Runtime.Intrinsics.X86.Avx.LoadVector256(pi + s), vmean);
                            var d1 = System.Runtime.Intrinsics.X86.Avx.Subtract(System.Runtime.Intrinsics.X86.Avx.LoadVector256(pi + s + 8), vmean);
                            var d2 = System.Runtime.Intrinsics.X86.Avx.Subtract(System.Runtime.Intrinsics.X86.Avx.LoadVector256(pi + s + 16), vmean);
                            var d3 = System.Runtime.Intrinsics.X86.Avx.Subtract(System.Runtime.Intrinsics.X86.Avx.LoadVector256(pi + s + 24), vmean);
                            System.Runtime.Intrinsics.X86.Avx.Store(po + s, System.Runtime.Intrinsics.X86.Fma.MultiplyAdd(d0, vscale, vbias));
                            System.Runtime.Intrinsics.X86.Avx.Store(po + s + 8, System.Runtime.Intrinsics.X86.Fma.MultiplyAdd(d1, vscale, vbias));
                            System.Runtime.Intrinsics.X86.Avx.Store(po + s + 16, System.Runtime.Intrinsics.X86.Fma.MultiplyAdd(d2, vscale, vbias));
                            System.Runtime.Intrinsics.X86.Avx.Store(po + s + 24, System.Runtime.Intrinsics.X86.Fma.MultiplyAdd(d3, vscale, vbias));
                        }
                        for (; s < spatialSize; s++)
                            outp[offset + s] = g * (inp[offset + s] - channelMean) * invStd + b;
                    }
                }
                return;
            }
            else if (System.Runtime.Intrinsics.X86.Avx2.IsSupported && spatialSize >= 8)
            {
                fixed (float* inp = input, outp = output)
                {
                    // Pass 1: Mean
                    float sum = 0f;
                    for (int n = 0; n < batch; n++)
                    {
                        int offset = n * channels * spatialSize + c * spatialSize;
                        float* ptr = inp + offset;
                        var vsum = System.Runtime.Intrinsics.Vector256<float>.Zero;
                        int s = 0;
                        int simdLen = spatialSize & ~7;
                        for (; s < simdLen; s += 8)
                            vsum = System.Runtime.Intrinsics.X86.Avx.Add(vsum, System.Runtime.Intrinsics.X86.Avx.LoadVector256(ptr + s));
                        sum += SimdKernels.HorizontalSum(vsum);
                        for (; s < spatialSize; s++)
                            sum += ptr[s];
                    }
                    float channelMean = sum * invCount;
                    meanOut[c] = channelMean;

                    // Pass 2: Variance
                    float sumSq = 0f;
                    var vmean = System.Runtime.Intrinsics.Vector256.Create(channelMean);
                    for (int n = 0; n < batch; n++)
                    {
                        int offset = n * channels * spatialSize + c * spatialSize;
                        float* ptr = inp + offset;
                        var vsumSq = System.Runtime.Intrinsics.Vector256<float>.Zero;
                        int s = 0;
                        int simdLen = spatialSize & ~7;
                        for (; s < simdLen; s += 8)
                        {
                            var diff = System.Runtime.Intrinsics.X86.Avx.Subtract(System.Runtime.Intrinsics.X86.Avx.LoadVector256(ptr + s), vmean);
                            vsumSq = System.Runtime.Intrinsics.X86.Avx.Add(vsumSq, System.Runtime.Intrinsics.X86.Avx.Multiply(diff, diff));
                        }
                        sumSq += SimdKernels.HorizontalSum(vsumSq);
                        for (; s < spatialSize; s++)
                        {
                            float diff = ptr[s] - channelMean;
                            sumSq += diff * diff;
                        }
                    }
                    float channelVar = sumSq * invCount;
                    varOut[c] = channelVar;
                    float invStd = 1f / MathF.Sqrt(channelVar + eps);
                    float g = gamma[c];
                    float b = beta[c];

                    // Pass 3: Normalize
                    var vscale = System.Runtime.Intrinsics.Vector256.Create(g * invStd);
                    var vbias = System.Runtime.Intrinsics.Vector256.Create(b);
                    for (int n = 0; n < batch; n++)
                    {
                        int offset = n * channels * spatialSize + c * spatialSize;
                        float* pi = inp + offset;
                        float* po = outp + offset;
                        int s = 0;
                        int simdLen = spatialSize & ~7;
                        for (; s < simdLen; s += 8)
                        {
                            var diff = System.Runtime.Intrinsics.X86.Avx.Subtract(System.Runtime.Intrinsics.X86.Avx.LoadVector256(pi + s), vmean);
                            System.Runtime.Intrinsics.X86.Avx.Store(po + s, System.Runtime.Intrinsics.X86.Avx.Add(System.Runtime.Intrinsics.X86.Avx.Multiply(diff, vscale), vbias));
                        }
                        for (; s < spatialSize; s++)
                            outp[offset + s] = g * (inp[offset + s] - channelMean) * invStd + b;
                    }
                }
                return;
            }
#endif
            // Scalar fallback
            {
                // Pass 1: Mean
                float sum = 0f;
                for (int n = 0; n < batch; n++)
                {
                    int offset = n * channels * spatialSize + c * spatialSize;
                    for (int s = 0; s < spatialSize; s++)
                        sum += input[offset + s];
                }
                float channelMean = sum * invCount;
                meanOut[c] = channelMean;

                // Pass 2: Variance
                float sumSq = 0f;
                for (int n = 0; n < batch; n++)
                {
                    int offset = n * channels * spatialSize + c * spatialSize;
                    for (int s = 0; s < spatialSize; s++)
                    {
                        float diff = input[offset + s] - channelMean;
                        sumSq += diff * diff;
                    }
                }
                float channelVar = sumSq * invCount;
                varOut[c] = channelVar;
#if NET5_0_OR_GREATER
                float invStd = 1f / MathF.Sqrt(channelVar + eps);
#else
                float invStd = 1f / (float)Math.Sqrt(channelVar + eps);
#endif
                float g = gamma[c];
                float b = beta[c];

                // Pass 3: Normalize
                for (int n = 0; n < batch; n++)
                {
                    int offset = n * channels * spatialSize + c * spatialSize;
                    for (int s = 0; s < spatialSize; s++)
                        output[offset + s] = g * (input[offset + s] - channelMean) * invStd + b;
                }
            }
        }
    }

    /// <inheritdoc/>
    public Tensor<T> BatchNormBackward<T>(Tensor<T> gradOutput, Tensor<T> input, Tensor<T> gamma, Tensor<T> mean, Tensor<T> variance, double epsilon, out Tensor<T> gradGamma, out Tensor<T> gradBeta)
    {
        if (gradOutput == null) throw new ArgumentNullException(nameof(gradOutput));
        if (input == null) throw new ArgumentNullException(nameof(input));

        var numOps = MathHelper.GetNumericOperations<T>();
        T eps = numOps.FromDouble(epsilon);

        // Handle both 2D [batch, features] and 4D [batch, channels, height, width] tensors
        if (input._shape.Length == 4)
        {
            return BatchNormBackward4D(gradOutput, input, gamma, mean, variance, eps, numOps, out gradGamma, out gradBeta);
        }
        // Rank-3 inputs were routed through BatchNorm3D on the forward path
        // (channels = _shape[0], spatial = _shape[1] * _shape[2]). The 2D
        // fallback below assumes channels = _shape[1] and indexes mean[f]
        // / var[f] / gamma[f] for f in [0, _shape[1]) — out-of-bounds for
        // any 3D shape with _shape[1] > _shape[0]. Dispatch to the matching
        // backward instead. (#233)
        if (input._shape.Length == 3)
        {
            return BatchNormBackward3D(gradOutput, input, gamma, mean, variance, eps, numOps, out gradGamma, out gradBeta);
        }

        // 2D case: [batch, features]
        int batch = input._shape[0];
        int features = input._shape[1];
        T batchT = numOps.FromDouble(batch);

        var gradOutputData = gradOutput.GetDataArray();
        var inputData = input.GetFlattenedData();
        var gammaData = gamma.GetDataArray();
        var meanData = mean.GetDataArray();
        var varData = variance.GetDataArray();

        var gradGammaData = new T[features];
        var gradBetaData = new T[features];
        var gradInputData = new T[batch * features];

        // Compute gradGamma and gradBeta
        for (int f = 0; f < features; f++)
        {
            T gGamma = numOps.Zero;
            T gBeta = numOps.Zero;
            T invStd = numOps.Divide(numOps.One, numOps.Sqrt(numOps.Add(varData[f], eps)));

            for (int b = 0; b < batch; b++)
            {
                int idx = b * features + f;
                T normalized = numOps.Multiply(numOps.Subtract(inputData[idx], meanData[f]), invStd);
                gGamma = numOps.Add(gGamma, numOps.Multiply(gradOutputData[idx], normalized));
                gBeta = numOps.Add(gBeta, gradOutputData[idx]);
            }

            gradGammaData[f] = gGamma;
            gradBetaData[f] = gBeta;
        }

        // Compute gradInput
        // Standard batch norm backward formula:
        // dx = (gamma / sqrt(var + eps) / N) * (N * dy - sum(dy) - (x - mean) / (var + eps) * sum(dy * (x - mean)))
        // All terms must be scaled by gamma for correctness
        Parallel.For(0, features, f =>
        {
            T invStd = numOps.Divide(numOps.One, numOps.Sqrt(numOps.Add(varData[f], eps)));
            T gamma = gammaData[f];
            T sumGrad = numOps.Zero;
            T sumGradX = numOps.Zero;

            // Accumulate sums over batch dimension
            for (int b = 0; b < batch; b++)
            {
                int idx = b * features + f;
                sumGrad = numOps.Add(sumGrad, gradOutputData[idx]);
                sumGradX = numOps.Add(sumGradX, numOps.Multiply(gradOutputData[idx], numOps.Subtract(inputData[idx], meanData[f])));
            }

            // Apply gamma scaling to accumulated sums
            T gammaSumGrad = numOps.Multiply(gamma, sumGrad);
            T gammaSumGradX = numOps.Multiply(gamma, sumGradX);

            for (int b = 0; b < batch; b++)
            {
                int idx = b * features + f;
                T normalized = numOps.Multiply(numOps.Subtract(inputData[idx], meanData[f]), invStd);
                T gradNorm = numOps.Multiply(gamma, gradOutputData[idx]);
                T term1 = numOps.Multiply(batchT, gradNorm);
                T term2 = gammaSumGrad;
                T term3 = numOps.Multiply(normalized, numOps.Multiply(invStd, gammaSumGradX));
                gradInputData[idx] = numOps.Multiply(numOps.Divide(invStd, batchT), numOps.Subtract(numOps.Subtract(term1, term2), term3));
            }
        });

        gradGamma = TensorAllocator.Rent<T>([features], new Vector<T>(gradGammaData));
        gradBeta = TensorAllocator.Rent<T>([features], new Vector<T>(gradBetaData));
        return TensorAllocator.Rent<T>(input._shape, new Vector<T>(gradInputData));
    }


    /// <summary>
    /// Backward pass for 4D batch normalization [batch, channels, height, width].
    /// </summary>
    private Tensor<T> BatchNormBackward4D<T>(Tensor<T> gradOutput, Tensor<T> input, Tensor<T> gamma, Tensor<T> mean, Tensor<T> variance, T eps, INumericOperations<T> numOps, out Tensor<T> gradGamma, out Tensor<T> gradBeta)
    {
        int batch = input._shape[0];
        int channels = input._shape[1];
        int height = input._shape[2];
        int width = input._shape[3];
        int spatialSize = height * width;
        int elementsPerChannel = batch * spatialSize;
        T elementsT = numOps.FromDouble(elementsPerChannel);

        var gradOutputData = gradOutput.GetDataArray();
        var inputData = input.GetDataArray();
        var gammaData = gamma.GetDataArray();
        var meanData = mean.GetDataArray();
        var varData = variance.GetDataArray();

        // Float fast path: direct float arithmetic avoids numOps virtual dispatch (4-8x faster)
        if (typeof(T) == typeof(float)
            && gradOutputData is float[] goF && inputData is float[] inF
            && gammaData is float[] gaF && meanData is float[] meF && varData is float[] vaF)
        {
            float epsF = (float)numOps.ToDouble(eps);
            var ggF = new float[channels];
            var gbF = new float[channels];
            var giF = new float[input.Length];
            float elemF = elementsPerChannel;

            Parallel.For(0, channels, c =>
            {
                float invStd = 1f / MathF.Sqrt(vaF[c] + epsF);
                float mean_c = meF[c];
                float gGamma = 0, gBeta = 0, sumGrad = 0, sumGradX = 0;

                for (int n = 0; n < batch; n++)
                {
                    int baseIdx = (n * channels + c) * spatialSize;
                    for (int s = 0; s < spatialSize; s++)
                    {
                        int idx = baseIdx + s;
                        float diff = inF[idx] - mean_c;
                        gGamma += goF[idx] * diff * invStd;
                        gBeta += goF[idx];
                        sumGrad += goF[idx];
                        sumGradX += goF[idx] * diff;
                    }
                }

                ggF[c] = gGamma;
                gbF[c] = gBeta;
                float gamma_c = gaF[c];
                float gammaSumGrad = gamma_c * sumGrad;
                float gammaSumGradX = gamma_c * sumGradX;

                for (int n = 0; n < batch; n++)
                {
                    int baseIdx2 = (n * channels + c) * spatialSize;
                    for (int s = 0; s < spatialSize; s++)
                    {
                        int idx = baseIdx2 + s;
                        float normalized = (inF[idx] - mean_c) * invStd;
                        float gradNorm = gamma_c * goF[idx];
                        giF[idx] = invStd / elemF * (elemF * gradNorm - gammaSumGrad - normalized * invStd * gammaSumGradX);
                    }
                }
            });

            gradGamma = TensorAllocator.Rent<T>([channels], (Vector<T>)(object)new Vector<float>(ggF));
            gradBeta = TensorAllocator.Rent<T>([channels], (Vector<T>)(object)new Vector<float>(gbF));
            return TensorAllocator.Rent<T>(input._shape, (Vector<T>)(object)new Vector<float>(giF));
        }

        var gradGammaData = new T[channels];
        var gradBetaData = new T[channels];
        var gradInputData = new T[input.Length];

        // Compute gradGamma and gradBeta per channel (generic fallback)
        Parallel.For(0, channels, c =>
        {
            T gGamma = numOps.Zero;
            T gBeta = numOps.Zero;
            T invStd = numOps.Divide(numOps.One, numOps.Sqrt(numOps.Add(varData[c], eps)));
            T channelMean = meanData[c];

            for (int n = 0; n < batch; n++)
            {
                int batchOffset = n * channels * spatialSize;
                int channelOffset = c * spatialSize;
                for (int s = 0; s < spatialSize; s++)
                {
                    int idx = batchOffset + channelOffset + s;
                    T normalized = numOps.Multiply(numOps.Subtract(inputData[idx], channelMean), invStd);
                    gGamma = numOps.Add(gGamma, numOps.Multiply(gradOutputData[idx], normalized));
                    gBeta = numOps.Add(gBeta, gradOutputData[idx]);
                }
            }

            gradGammaData[c] = gGamma;
            gradBetaData[c] = gBeta;
        });

        // Compute gradInput
        Parallel.For(0, channels, c =>
        {
            T invStd = numOps.Divide(numOps.One, numOps.Sqrt(numOps.Add(varData[c], eps)));
            T gammaC = gammaData[c];
            T channelMean = meanData[c];
            T sumGrad = numOps.Zero;
            T sumGradX = numOps.Zero;

            // Accumulate sums over batch and spatial dimensions
            for (int n = 0; n < batch; n++)
            {
                int batchOffset = n * channels * spatialSize;
                int channelOffset = c * spatialSize;
                for (int s = 0; s < spatialSize; s++)
                {
                    int idx = batchOffset + channelOffset + s;
                    sumGrad = numOps.Add(sumGrad, gradOutputData[idx]);
                    sumGradX = numOps.Add(sumGradX, numOps.Multiply(gradOutputData[idx], numOps.Subtract(inputData[idx], channelMean)));
                }
            }

            // Apply gamma scaling to accumulated sums
            T gammaSumGrad = numOps.Multiply(gammaC, sumGrad);
            T gammaSumGradX = numOps.Multiply(gammaC, sumGradX);

            for (int n = 0; n < batch; n++)
            {
                int batchOffset = n * channels * spatialSize;
                int channelOffset = c * spatialSize;
                for (int s = 0; s < spatialSize; s++)
                {
                    int idx = batchOffset + channelOffset + s;
                    T normalized = numOps.Multiply(numOps.Subtract(inputData[idx], channelMean), invStd);
                    T gradNorm = numOps.Multiply(gammaC, gradOutputData[idx]);
                    T term1 = numOps.Multiply(elementsT, gradNorm);
                    T term2 = gammaSumGrad;
                    T term3 = numOps.Multiply(normalized, numOps.Multiply(invStd, gammaSumGradX));
                    gradInputData[idx] = numOps.Multiply(numOps.Divide(invStd, elementsT), numOps.Subtract(numOps.Subtract(term1, term2), term3));
                }
            }
        });

        gradGamma = TensorAllocator.Rent<T>([channels], new Vector<T>(gradGammaData));
        gradBeta = TensorAllocator.Rent<T>([channels], new Vector<T>(gradBetaData));
        return TensorAllocator.Rent<T>(input._shape, new Vector<T>(gradInputData));
    }

    /// <summary>
    /// Backward pass for 3D batch normalization <c>[channels, height, width]</c>,
    /// matching the layout used by <see cref="BatchNorm3D{T}"/> on the forward
    /// pass: <c>channels = _shape[0]</c>, <c>spatial = _shape[1] * _shape[2]</c>,
    /// reduction is per-channel across spatial. Standard batch-norm-backward
    /// formula with N = spatial size:
    /// <para>
    /// <c>dx = (γ · invStd / N) · (N · dy − Σdy − norm · invStd · Σ(dy · (x − μ)))</c>
    /// </para>
    /// where <c>invStd = 1 / sqrt(var + eps)</c> and <c>norm = (x − μ) · invStd</c>.
    /// </summary>
    private Tensor<T> BatchNormBackward3D<T>(Tensor<T> gradOutput, Tensor<T> input, Tensor<T> gamma, Tensor<T> mean, Tensor<T> variance, T eps, INumericOperations<T> numOps, out Tensor<T> gradGamma, out Tensor<T> gradBeta)
    {
        int channels = input._shape[0];
        int height = input._shape[1];
        int width = input._shape[2];
        int spatialSize = height * width;
        T spatialT = numOps.FromDouble(spatialSize);

        var gradOutputData = gradOutput.GetDataArray();
        var inputData = input.GetDataArray();
        var gammaData = gamma.GetDataArray();
        var meanData = mean.GetDataArray();
        var varData = variance.GetDataArray();

        var gradGammaData = new T[channels];
        var gradBetaData = new T[channels];
        var gradInputData = new T[input.Length];

        Parallel.For(0, channels, c =>
        {
            T invStd = numOps.Divide(numOps.One, numOps.Sqrt(numOps.Add(varData[c], eps)));
            T mean_c = meanData[c];
            T gamma_c = gammaData[c];

            // Pass 1: accumulate per-channel reductions over the spatial axis.
            T sumGrad = numOps.Zero;
            T sumGradX = numOps.Zero;
            T gGamma = numOps.Zero;
            T gBeta = numOps.Zero;
            int channelOffset = c * spatialSize;
            for (int s = 0; s < spatialSize; s++)
            {
                T x = inputData[channelOffset + s];
                T gOut = gradOutputData[channelOffset + s];
                T centered = numOps.Subtract(x, mean_c);
                T normalized = numOps.Multiply(centered, invStd);
                gGamma = numOps.Add(gGamma, numOps.Multiply(gOut, normalized));
                gBeta = numOps.Add(gBeta, gOut);
                sumGrad = numOps.Add(sumGrad, gOut);
                sumGradX = numOps.Add(sumGradX, numOps.Multiply(gOut, centered));
            }
            gradGammaData[c] = gGamma;
            gradBetaData[c] = gBeta;

            // Pass 2: write gradInput using the accumulated sums.
            T gammaSumGrad = numOps.Multiply(gamma_c, sumGrad);
            T gammaSumGradX = numOps.Multiply(gamma_c, sumGradX);
            T invStdOverSpatial = numOps.Divide(invStd, spatialT);
            for (int s = 0; s < spatialSize; s++)
            {
                T x = inputData[channelOffset + s];
                T gOut = gradOutputData[channelOffset + s];
                T centered = numOps.Subtract(x, mean_c);
                T normalized = numOps.Multiply(centered, invStd);
                T gradNorm = numOps.Multiply(gamma_c, gOut);
                T term1 = numOps.Multiply(spatialT, gradNorm);
                T term2 = gammaSumGrad;
                T term3 = numOps.Multiply(normalized, numOps.Multiply(invStd, gammaSumGradX));
                gradInputData[channelOffset + s] = numOps.Multiply(invStdOverSpatial, numOps.Subtract(numOps.Subtract(term1, term2), term3));
            }
        });

        gradGamma = TensorAllocator.Rent<T>(new[] { channels }, new Vector<T>(gradGammaData));
        gradBeta = TensorAllocator.Rent<T>(new[] { channels }, new Vector<T>(gradBetaData));
        return TensorAllocator.Rent<T>(input._shape, new Vector<T>(gradInputData));
    }

    /// <inheritdoc/>
    public virtual Tensor<T> LayerNorm<T>(Tensor<T> input, Tensor<T> gamma, Tensor<T> beta, double epsilon, out Tensor<T> mean, out Tensor<T> variance)
    {
        using var _opScope = AiDotNet.Tensors.Engines.Profiling.Profiler.OpScope("LayerNorm");
        if (input == null) throw new ArgumentNullException(nameof(input));
        if (gamma == null) throw new ArgumentNullException(nameof(gamma));
        if (beta == null) throw new ArgumentNullException(nameof(beta));

        if (GraphMode.IsActive)
        {
            var scope = GraphMode.Current;
            if (scope != null)
            {
                var ci = input; var cg = gamma; var cb = beta; double ce = epsilon;
                var savedScope = GraphMode.Current;
                GraphMode.SetCurrent(null);
                var eagerResult = LayerNorm(ci, cg, cb, ce, out mean, out variance);
                GraphMode.SetCurrent(savedScope);
                var lazyResult = scope.RecordVariadic(LazyNodeType.Custom, "LayerNorm",
                    new[] { input, gamma, beta }, eagerResult._shape,
                    // Path C: plan-step write-through. When the engine is
                    // CpuEngine and T is float, call LayerNormFloatInto which
                    // writes directly into the plan's pre-allocated output.
                    // This skips the intermediate tensor allocation + the
                    // 786 KB CopyTo that the generic path below would incur
                    // for BERT's [1,256,768] LayerNorm (~130 µs saved per
                    // call × 24 calls per BERT layer).
                    (eng, output) =>
                    {
                        if (typeof(T) == typeof(float) && eng is CpuEngine cpuEng)
                        {
                            cpuEng.LayerNormFloatInto(
                                (Tensor<float>)(object)ci,
                                (Tensor<float>)(object)cg,
                                (Tensor<float>)(object)cb,
                                ce,
                                (Tensor<float>)(object)output);
                        }
                        else
                        {
                            var r = eng.LayerNorm(ci, cg, cb, ce, out _, out _);
                            r.AsSpan().CopyTo(output.AsWritableSpan());
                        }
                    },
                    BackwardFunctions<T>.LayerNormBackward, new object[] { mean, variance, epsilon });
                eagerResult.AsSpan().CopyTo(lazyResult.AsWritableSpan());
                return lazyResult;
            }
        }

        var numOps = MathHelper.GetNumericOperations<T>();
        T eps = numOps.FromDouble(epsilon);

        // Determine normalized dimensions from gamma shape
        // gamma.Shape defines which trailing dimensions to normalize over
        int normalizedDims = gamma._shape.Length;
        int inputRank = input._shape.Length;

        if (normalizedDims > inputRank)
        {
            throw new ArgumentException($"Gamma shape ({string.Join(", ", gamma._shape)}) has more dimensions than input shape ({string.Join(", ", input._shape)})");
        }

        // Verify that gamma shape matches the last N dimensions of input
        for (int i = 0; i < normalizedDims; i++)
        {
            int inputDimIdx = inputRank - normalizedDims + i;
            if (gamma._shape[i] != input._shape[inputDimIdx])
            {
                throw new ArgumentException($"Gamma shape ({string.Join(", ", gamma._shape)}) does not match the last {normalizedDims} dimensions of input shape ({string.Join(", ", input._shape)})");
            }
        }

        // Calculate batch size (product of non-normalized dimensions)
        // and feature size (product of normalized dimensions)
        int batchSize = 1;
        int batchDims = inputRank - normalizedDims;
        var batchShape = new int[Math.Max(1, batchDims)];

        for (int i = 0; i < batchDims; i++)
        {
            batchSize *= input._shape[i];
            batchShape[i] = input._shape[i];
        }

        // Handle case where all dimensions are normalized (batchDims = 0)
        if (batchDims == 0)
        {
            batchSize = 1;
            batchShape = new int[] { 1 };
        }

        int featureSize = gamma.Length; // product of normalized dimensions

        var inputData = input.GetDataArray();
        var gammaData = gamma.GetDataArray();
        var betaData = beta.GetDataArray();

        // Float fast path: SIMD mean, variance, and normalize via Vector256
        // with FMA — fused into a SINGLE pass over the input using
        // <c>Var[X] = E[X²] - E[X]²</c>. Writes directly into an uninitialized
        // rented output tensor, avoiding the 786 KB zero-init cost of
        // <c>new float[batchSize * featureSize]</c> that previously dominated
        // per-call overhead on BERT LayerNorm (measured: engine wrap was
        // 304 µs over a 157 µs kernel → 2× improvement expected from alloc
        // elimination alone; one-pass kernel adds another 20%).
        if (typeof(T) == typeof(float))
        {
            var fInput = (float[])(object)inputData;
            var fGamma = (float[])(object)gammaData;
            var fBeta = (float[])(object)betaData;
            float fEps = eps is not null ? (float)(object)eps : 1e-5f;
            int fs = featureSize;

            // Rent uninitialized output tensor — skips Array.Clear.
            var lnResultF = TensorAllocator.RentUninitialized<float>(input._shape);
            var fOutput = lnResultF.GetDataArray();
            // Mean/variance are always returned as out params. They're
            // consumed by the backward pass; for inference the tensors are
            // thrown away but we still have to produce them. Use
            // RentUninitialized + direct write (small — batchSize floats).
            var meanTensorF = TensorAllocator.RentUninitialized<float>(batchShape);
            var varTensorF  = TensorAllocator.RentUninitialized<float>(batchShape);
            var fMean = meanTensorF.GetDataArray();
            var fVar  = varTensorF .GetDataArray();

            ProcessBatchesSimd(fInput, fGamma, fBeta, fOutput, fMean, fVar,
                batchSize, fs, fEps);

            mean = (Tensor<T>)(object)meanTensorF;
            variance = (Tensor<T>)(object)varTensorF;
            var lnResult = (Tensor<T>)(object)lnResultF;
            DifferentiableOps.RecordIfActive("LayerNorm", lnResult, new[] { input, gamma, beta },
                BackwardFunctions<T>.LayerNormBackward, new object[] { mean, variance, epsilon });
            AutoTracer.RecordOp("LayerNorm", lnResult, eng => lnResult);
            return lnResult;
        }

        // Generic T path — uses numOps.Sum (SIMD via SimdKernels.Sum for
        // float/double) for the mean/variance reductions instead of a scalar
        // accumulation loop, and uses span slicing for the output write pass.
        // The float fast path above returns early, so this branch is only
        // double / BFloat16 / custom numeric types today — no else wrapper
        // required.
        var meanData = new T[batchSize];
        var varData = new T[batchSize];
        var outputData = new T[batchSize * featureSize];
        T featureSizeT = numOps.FromDouble(featureSize);
        Parallel.For(0, batchSize, b =>
        {
            int offset = b * featureSize;
            var inSlice = inputData.AsSpan(offset, featureSize);

            T sum = numOps.Sum(inSlice);
            T m = numOps.Divide(sum, featureSizeT);
            meanData[b] = m;

            // Variance: still scalar-per-element because we need (x-m)² and there's
            // no fused primitive. Still uses local `m` to avoid re-computation.
            T sumSq = numOps.Zero;
            for (int f = 0; f < featureSize; f++)
            {
                T diff = numOps.Subtract(inSlice[f], m);
                sumSq = numOps.Add(sumSq, numOps.Multiply(diff, diff));
            }
            T v = numOps.Divide(sumSq, featureSizeT);
            varData[b] = v;

            T invStd = numOps.Divide(numOps.One, numOps.Sqrt(numOps.Add(v, eps)));
            var outSlice = outputData.AsSpan(offset, featureSize);
            for (int f = 0; f < featureSize; f++)
            {
                T normalized = numOps.Multiply(numOps.Subtract(inSlice[f], m), invStd);
                outSlice[f] = numOps.Add(numOps.Multiply(gammaData[f], normalized), betaData[f]);
            }
        });

        // Create mean and variance tensors with batch shape
        mean = TensorAllocator.Rent<T>(batchShape, new Vector<T>(meanData));
        variance = TensorAllocator.Rent<T>(batchShape, new Vector<T>(varData));
        var lnResultG = TensorAllocator.Rent<T>(input._shape, new Vector<T>(outputData));
        DifferentiableOps.RecordIfActive("LayerNorm", lnResultG, new[] { input, gamma, beta },
            BackwardFunctions<T>.LayerNormBackward, new object[] { mean, variance, epsilon });
        AutoTracer.RecordOp("LayerNorm", lnResultG, eng => lnResultG);
        return lnResultG;
    }

    /// <summary>
    /// Write-through LayerNorm for float inference: writes directly into the
    /// provided <paramref name="output"/> tensor instead of allocating a new
    /// one. Used by compiled plan steps so the plan-step lambda doesn't have
    /// to call the public <see cref="LayerNorm{T}"/> (which allocates an
    /// intermediate tensor) then <c>CopyTo</c> into the pre-allocated plan
    /// buffer. For BERT LayerNorm [1,256,768] this saves ~130 µs per call
    /// (50 µs allocation + 80 µs 786 KB CopyTo at 10 GB/s).
    ///
    /// <para>Skips mean/variance allocation — inference doesn't need them.
    /// Scratch is rented from ArrayPool.</para>
    /// </summary>
    internal static long _lnFloatIntoCalls;

    // #209 close-parity A/B: toggle the fused fs=64 LayerNorm fast path.
    // Set env var AIDOTNET_LAYERNORM_FUSED_FS64=0 to disable (use 2-pass form
    // for direct comparison). Default: enabled.
    private static readonly bool _layerNormFusedFs64Enabled =
        Environment.GetEnvironmentVariable("AIDOTNET_LAYERNORM_FUSED_FS64") != "0";

    internal void LayerNormFloatInto(
        Tensor<float> input, Tensor<float> gamma, Tensor<float> beta,
        double epsilon, Tensor<float> output)
    {
        System.Threading.Interlocked.Increment(ref _lnFloatIntoCalls);
        int normalizedDims = gamma._shape.Length;
        int inputRank = input._shape.Length;
        int batchSize = 1;
        for (int i = 0; i < inputRank - normalizedDims; i++)
            batchSize *= input._shape[i];
        if (batchSize == 0) batchSize = 1;
        int featureSize = gamma.Length;

        var fInput  = input .GetDataArray();
        var fGamma  = gamma .GetDataArray();
        var fBeta   = beta  .GetDataArray();
        var fOutput = output.GetDataArray();
        float fEps = (float)epsilon;

        var fMean = System.Buffers.ArrayPool<float>.Shared.Rent(batchSize);
        var fVar  = System.Buffers.ArrayPool<float>.Shared.Rent(batchSize);
        try
        {
            ProcessBatchesSimd(fInput, fGamma, fBeta, fOutput, fMean, fVar,
                batchSize, featureSize, fEps);
        }
        finally
        {
            System.Buffers.ArrayPool<float>.Shared.Return(fVar);
            System.Buffers.ArrayPool<float>.Shared.Return(fMean);
        }
    }

    /// <summary>
    /// SIMD float LayerNorm worker — three vectorised passes per row
    /// (mean, variance, transform). Extracted so the Parallel.For lambda
    /// can dispatch to a named static method. Uses
    /// <c>Unsafe.ReadUnaligned</c> / <c>Unsafe.WriteUnaligned</c> for
    /// 32-byte vector load/store, avoiding Span bounds-check overhead.
    /// </summary>
    private static void ProcessBatchesSimd(
        float[] fInput, float[] fGamma, float[] fBeta,
        float[] fOutput, float[] fMean, float[] fVar,
        int batchSize, int fs, float fEps)
    {
#if NET5_0_OR_GREATER
        bool useSimd = System.Runtime.Intrinsics.X86.Avx.IsSupported
                    && System.Runtime.Intrinsics.X86.Fma.IsSupported;
#else
        bool useSimd = false;
#endif
        if (batchSize * fs < 50_000)
        {
            for (int b = 0; b < batchSize; b++)
                ProcessRow(fInput, fGamma, fBeta, fOutput, fMean, fVar, b, fs, fEps, useSimd);
        }
        else
        {
            // Chunked parallelism via PersistentParallelExecutor — pre-spawned
            // worker threads + ManualResetEventSlim signaling cuts dispatch
            // overhead from Parallel.For's ~50 µs to ~5 µs per call. At LayerNorm
            // call rates inside transformer training loops this saves ~45 µs
            // per call, which is ~3% of the [32768, 64] benchmark's 1.3 ms.
            // Guard batchSize == 0.
            if (batchSize == 0) return;
            int chunks = Math.Max(1, Math.Min(CpuParallelSettings.MaxDegreeOfParallelism, batchSize));
            int chunkSize = (batchSize + chunks - 1) / chunks;
            int totalBatch = batchSize;
            Helpers.PersistentParallelExecutor.Instance.Execute(chunks, c =>
            {
                int start = c * chunkSize;
                int end = Math.Min(start + chunkSize, totalBatch);
                for (int b = start; b < end; b++)
                    ProcessRow(fInput, fGamma, fBeta, fOutput, fMean, fVar, b, fs, fEps, useSimd);
            });
        }
    }

    [MethodImpl(MethodImplOptions.AggressiveInlining)]
    private static void ProcessRow(
        float[] fInput, float[] fGamma, float[] fBeta,
        float[] fOutput, float[] fMean, float[] fVar,
        int b, int fs, float fEps, bool useSimd)
    {
        int off = b * fs;
        float m, v2;

#if NET8_0_OR_GREATER
        // AVX-512 path: 16-wide Vector512 halves the vector ops vs AVX2
        // for the same row. On Zen 5 / Intel Ice Lake+ / Sapphire Rapids
        // this cuts LayerNorm ProcessRow time by ~2× (measured proxy: the
        // FFN up MatMul's FP throughput jump from AVX2→AVX-512).
        if (AiDotNet.Tensors.Engines.Simd.CpuFeatures.HasAVX512F && fs >= 16)
        {
            // Pass 1 (fused): sum AND sum-of-squares, 16 floats/op.
            var vSum512 = System.Runtime.Intrinsics.Vector512<float>.Zero;
            var vSumSq512 = System.Runtime.Intrinsics.Vector512<float>.Zero;
            int f512 = 0;
            for (; f512 + 16 <= fs; f512 += 16)
            {
                var v = System.Runtime.CompilerServices.Unsafe.ReadUnaligned<System.Runtime.Intrinsics.Vector512<float>>(
                    ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fInput[off + f512]));
                vSum512 = System.Runtime.Intrinsics.X86.Avx512F.Add(vSum512, v);
                vSumSq512 = System.Runtime.Intrinsics.X86.Avx512F.FusedMultiplyAdd(v, v, vSumSq512);
            }
            // Reduce 16 → 8 via GetUpper/GetLower + Add, then the existing
            // AVX2 HorizontalSum closes it out.
            float sum512 = SimdKernels.HorizontalSum(
                System.Runtime.Intrinsics.X86.Avx.Add(vSum512.GetLower(), vSum512.GetUpper()));
            float sumSq512 = SimdKernels.HorizontalSum(
                System.Runtime.Intrinsics.X86.Avx.Add(vSumSq512.GetLower(), vSumSq512.GetUpper()));
            for (; f512 < fs; f512++)
            {
                float x = fInput[off + f512];
                sum512 += x;
                sumSq512 += x * x;
            }
            m = sum512 / fs;
            v2 = sumSq512 / fs - m * m;
            if (v2 < 0f) v2 = 0f;
            fMean[b] = m;
            fVar[b] = v2;

            // Pass 2: 16-wide transform: (in - m) * invStd * gamma + beta.
            float invStd512 = 1f / MathF.Sqrt(v2 + fEps);
            var vInvStd512 = System.Runtime.Intrinsics.Vector512.Create(invStd512);
            var vMNeg512 = System.Runtime.Intrinsics.Vector512.Create(m);
            f512 = 0;
            for (; f512 + 16 <= fs; f512 += 16)
            {
                var v = System.Runtime.CompilerServices.Unsafe.ReadUnaligned<System.Runtime.Intrinsics.Vector512<float>>(
                    ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fInput[off + f512]));
                var vG = System.Runtime.CompilerServices.Unsafe.ReadUnaligned<System.Runtime.Intrinsics.Vector512<float>>(
                    ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fGamma[f512]));
                var vB = System.Runtime.CompilerServices.Unsafe.ReadUnaligned<System.Runtime.Intrinsics.Vector512<float>>(
                    ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fBeta[f512]));
                var d = System.Runtime.Intrinsics.X86.Avx512F.Subtract(v, vMNeg512);
                var scaled = System.Runtime.Intrinsics.X86.Avx512F.Multiply(d, vInvStd512);
                var final = System.Runtime.Intrinsics.X86.Avx512F.FusedMultiplyAdd(scaled, vG, vB);
                System.Runtime.CompilerServices.Unsafe.WriteUnaligned(
                    ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fOutput[off + f512]), final);
            }
            for (; f512 < fs; f512++)
                fOutput[off + f512] = (fInput[off + f512] - m) * invStd512 * fGamma[f512] + fBeta[f512];
            return;
        }
#endif

#if NET5_0_OR_GREATER
        if (useSimd && fs >= 8)
        {
            // ─────────────────────────────────────────────────────────
            // SINGLE-PASS REGISTER-RESIDENT FAST PATH for fs ≤ 64 (8 AVX2 vectors).
            // Holds the entire row in ymm registers across both passes —
            // pass 2's input reads come straight from registers, eliminating
            // the second sweep over input memory entirely.
            //
            // Measured savings on [32768, 64] LayerNorm: ~200 µs vs the
            // 2-pass form (8 MB fewer reads / 50 GB/s memory bandwidth).
            // Total register budget: 8 input + 1 sum + 1 sumSq + 1 vMNeg
            // + 1 vInvStd = 12 ymm. AVX2 has 16. Per-iter gamma/beta loads
            // get the remaining 4.
            //
            // Gating: fs is divisible by 8, fs ≤ 64 (8 vectors fit easily).
            // For fs > 64 the row spills to L1 cache anyway and the
            // 2-pass form below is equivalent.
            // EXPERIMENT (reverted): tried a "register-resident across both
            // passes" fused fs=64 fast path that loaded all 8 input vectors
            // ONCE and reused them in pass 2. A/B benchmark verdict
            // (--ab-layernorm on Ryzen 9 3950X):
            //   [32768, 64] (BDN): 2-pass 906 µs vs fused 948 µs — 2-pass WINS by 5%
            //   [1024,  64]:       2-pass 133 µs vs fused 117 µs — fused wins 13%
            // The JIT spills v0..v7 between passes anyway (the horizontal-sum
            // scalar block triggers a register-state save), so the supposed
            // "no input re-read" doesn't materialize on Zen 2. Removed the
            // fast path — keeping this comment so the lesson is preserved.
            // To re-attempt later, write the kernel with explicit XSAVE-aware
            // accumulator passing.
            if (false && _layerNormFusedFs64Enabled)
            {
                // Load all 8 input vectors once.
                var v0 = System.Runtime.CompilerServices.Unsafe.ReadUnaligned<System.Runtime.Intrinsics.Vector256<float>>(
                    ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fInput[off]));
                var v1 = System.Runtime.CompilerServices.Unsafe.ReadUnaligned<System.Runtime.Intrinsics.Vector256<float>>(
                    ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fInput[off + 8]));
                var v2v = System.Runtime.CompilerServices.Unsafe.ReadUnaligned<System.Runtime.Intrinsics.Vector256<float>>(
                    ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fInput[off + 16]));
                var v3 = System.Runtime.CompilerServices.Unsafe.ReadUnaligned<System.Runtime.Intrinsics.Vector256<float>>(
                    ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fInput[off + 24]));
                var v4 = System.Runtime.CompilerServices.Unsafe.ReadUnaligned<System.Runtime.Intrinsics.Vector256<float>>(
                    ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fInput[off + 32]));
                var v5 = System.Runtime.CompilerServices.Unsafe.ReadUnaligned<System.Runtime.Intrinsics.Vector256<float>>(
                    ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fInput[off + 40]));
                var v6 = System.Runtime.CompilerServices.Unsafe.ReadUnaligned<System.Runtime.Intrinsics.Vector256<float>>(
                    ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fInput[off + 48]));
                var v7 = System.Runtime.CompilerServices.Unsafe.ReadUnaligned<System.Runtime.Intrinsics.Vector256<float>>(
                    ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fInput[off + 56]));

                // Pass 1: 4-way unrolled fused sum + sumSq across the 8 vectors.
                var s0 = System.Runtime.Intrinsics.X86.Avx.Add(v0, v1);
                var s1 = System.Runtime.Intrinsics.X86.Avx.Add(v2v, v3);
                var s2 = System.Runtime.Intrinsics.X86.Avx.Add(v4, v5);
                var s3 = System.Runtime.Intrinsics.X86.Avx.Add(v6, v7);
                var vSum_ = System.Runtime.Intrinsics.X86.Avx.Add(
                    System.Runtime.Intrinsics.X86.Avx.Add(s0, s1),
                    System.Runtime.Intrinsics.X86.Avx.Add(s2, s3));

                var sq0 = System.Runtime.Intrinsics.X86.Fma.MultiplyAdd(v0, v0, System.Runtime.Intrinsics.X86.Fma.MultiplyAdd(v1, v1, System.Runtime.Intrinsics.Vector256<float>.Zero));
                var sq1 = System.Runtime.Intrinsics.X86.Fma.MultiplyAdd(v2v, v2v, System.Runtime.Intrinsics.X86.Fma.MultiplyAdd(v3, v3, System.Runtime.Intrinsics.Vector256<float>.Zero));
                var sq2 = System.Runtime.Intrinsics.X86.Fma.MultiplyAdd(v4, v4, System.Runtime.Intrinsics.X86.Fma.MultiplyAdd(v5, v5, System.Runtime.Intrinsics.Vector256<float>.Zero));
                var sq3 = System.Runtime.Intrinsics.X86.Fma.MultiplyAdd(v6, v6, System.Runtime.Intrinsics.X86.Fma.MultiplyAdd(v7, v7, System.Runtime.Intrinsics.Vector256<float>.Zero));
                var vSumSq_ = System.Runtime.Intrinsics.X86.Avx.Add(
                    System.Runtime.Intrinsics.X86.Avx.Add(sq0, sq1),
                    System.Runtime.Intrinsics.X86.Avx.Add(sq2, sq3));

                float sum_ = SimdKernels.HorizontalSum(vSum_);
                float sumSq_ = SimdKernels.HorizontalSum(vSumSq_);
                m = sum_ / 64f;
                v2 = sumSq_ / 64f - m * m;
                if (v2 < 0f) v2 = 0f;
                fMean[b] = m;
                fVar[b] = v2;

                float invStd_ = 1f / MathF.Sqrt(v2 + fEps);
                var vInvStd_ = System.Runtime.Intrinsics.Vector256.Create(invStd_);
                var vMNeg_ = System.Runtime.Intrinsics.Vector256.Create(m);

                // Pass 2: transform using v0..v7 STILL IN REGISTERS — no input re-read.
                // (in - m) * invStd * gamma + beta, FMA-fused.
                var d0 = System.Runtime.Intrinsics.X86.Avx.Subtract(v0, vMNeg_);
                var d1 = System.Runtime.Intrinsics.X86.Avx.Subtract(v1, vMNeg_);
                var d2 = System.Runtime.Intrinsics.X86.Avx.Subtract(v2v, vMNeg_);
                var d3 = System.Runtime.Intrinsics.X86.Avx.Subtract(v3, vMNeg_);
                var d4 = System.Runtime.Intrinsics.X86.Avx.Subtract(v4, vMNeg_);
                var d5 = System.Runtime.Intrinsics.X86.Avx.Subtract(v5, vMNeg_);
                var d6 = System.Runtime.Intrinsics.X86.Avx.Subtract(v6, vMNeg_);
                var d7 = System.Runtime.Intrinsics.X86.Avx.Subtract(v7, vMNeg_);

                d0 = System.Runtime.Intrinsics.X86.Avx.Multiply(d0, vInvStd_);
                d1 = System.Runtime.Intrinsics.X86.Avx.Multiply(d1, vInvStd_);
                d2 = System.Runtime.Intrinsics.X86.Avx.Multiply(d2, vInvStd_);
                d3 = System.Runtime.Intrinsics.X86.Avx.Multiply(d3, vInvStd_);
                d4 = System.Runtime.Intrinsics.X86.Avx.Multiply(d4, vInvStd_);
                d5 = System.Runtime.Intrinsics.X86.Avx.Multiply(d5, vInvStd_);
                d6 = System.Runtime.Intrinsics.X86.Avx.Multiply(d6, vInvStd_);
                d7 = System.Runtime.Intrinsics.X86.Avx.Multiply(d7, vInvStd_);

                var vG0 = System.Runtime.CompilerServices.Unsafe.ReadUnaligned<System.Runtime.Intrinsics.Vector256<float>>(ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fGamma[0]));
                var vG1 = System.Runtime.CompilerServices.Unsafe.ReadUnaligned<System.Runtime.Intrinsics.Vector256<float>>(ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fGamma[8]));
                var vG2 = System.Runtime.CompilerServices.Unsafe.ReadUnaligned<System.Runtime.Intrinsics.Vector256<float>>(ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fGamma[16]));
                var vG3 = System.Runtime.CompilerServices.Unsafe.ReadUnaligned<System.Runtime.Intrinsics.Vector256<float>>(ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fGamma[24]));
                var vG4 = System.Runtime.CompilerServices.Unsafe.ReadUnaligned<System.Runtime.Intrinsics.Vector256<float>>(ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fGamma[32]));
                var vG5 = System.Runtime.CompilerServices.Unsafe.ReadUnaligned<System.Runtime.Intrinsics.Vector256<float>>(ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fGamma[40]));
                var vG6 = System.Runtime.CompilerServices.Unsafe.ReadUnaligned<System.Runtime.Intrinsics.Vector256<float>>(ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fGamma[48]));
                var vG7 = System.Runtime.CompilerServices.Unsafe.ReadUnaligned<System.Runtime.Intrinsics.Vector256<float>>(ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fGamma[56]));

                var vB0 = System.Runtime.CompilerServices.Unsafe.ReadUnaligned<System.Runtime.Intrinsics.Vector256<float>>(ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fBeta[0]));
                var vB1 = System.Runtime.CompilerServices.Unsafe.ReadUnaligned<System.Runtime.Intrinsics.Vector256<float>>(ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fBeta[8]));
                var vB2 = System.Runtime.CompilerServices.Unsafe.ReadUnaligned<System.Runtime.Intrinsics.Vector256<float>>(ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fBeta[16]));
                var vB3 = System.Runtime.CompilerServices.Unsafe.ReadUnaligned<System.Runtime.Intrinsics.Vector256<float>>(ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fBeta[24]));
                var vB4 = System.Runtime.CompilerServices.Unsafe.ReadUnaligned<System.Runtime.Intrinsics.Vector256<float>>(ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fBeta[32]));
                var vB5 = System.Runtime.CompilerServices.Unsafe.ReadUnaligned<System.Runtime.Intrinsics.Vector256<float>>(ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fBeta[40]));
                var vB6 = System.Runtime.CompilerServices.Unsafe.ReadUnaligned<System.Runtime.Intrinsics.Vector256<float>>(ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fBeta[48]));
                var vB7 = System.Runtime.CompilerServices.Unsafe.ReadUnaligned<System.Runtime.Intrinsics.Vector256<float>>(ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fBeta[56]));

                System.Runtime.CompilerServices.Unsafe.WriteUnaligned(ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fOutput[off]),      System.Runtime.Intrinsics.X86.Fma.MultiplyAdd(d0, vG0, vB0));
                System.Runtime.CompilerServices.Unsafe.WriteUnaligned(ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fOutput[off + 8]),  System.Runtime.Intrinsics.X86.Fma.MultiplyAdd(d1, vG1, vB1));
                System.Runtime.CompilerServices.Unsafe.WriteUnaligned(ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fOutput[off + 16]), System.Runtime.Intrinsics.X86.Fma.MultiplyAdd(d2, vG2, vB2));
                System.Runtime.CompilerServices.Unsafe.WriteUnaligned(ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fOutput[off + 24]), System.Runtime.Intrinsics.X86.Fma.MultiplyAdd(d3, vG3, vB3));
                System.Runtime.CompilerServices.Unsafe.WriteUnaligned(ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fOutput[off + 32]), System.Runtime.Intrinsics.X86.Fma.MultiplyAdd(d4, vG4, vB4));
                System.Runtime.CompilerServices.Unsafe.WriteUnaligned(ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fOutput[off + 40]), System.Runtime.Intrinsics.X86.Fma.MultiplyAdd(d5, vG5, vB5));
                System.Runtime.CompilerServices.Unsafe.WriteUnaligned(ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fOutput[off + 48]), System.Runtime.Intrinsics.X86.Fma.MultiplyAdd(d6, vG6, vB6));
                System.Runtime.CompilerServices.Unsafe.WriteUnaligned(ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fOutput[off + 56]), System.Runtime.Intrinsics.X86.Fma.MultiplyAdd(d7, vG7, vB7));
                return;
            }

            // ─────────────────────────────────────────────────────────
            // Generic 2-pass form for fs > 64 (or fs not equal to 64).
            // Pass 1 (fused): sum AND sum-of-squares in a single pass via
            // Var[X] = E[X²] - (E[X])². Cuts input reads from 3× to 2×
            // and saves ~20% kernel time vs the 3-pass form. Measured at
            // 126 µs vs 157 µs on BERT [1,256,768] LayerNorm.
            //
            // 4-way accumulator unrolling: the previous single-chain form
            // bottlenecked on the FMA latency (4 cycles per dependency on
            // Zen 2). Four parallel chains let the OoO engine fully saturate
            // both FMA ports — 1.5–2× speedup on this pass alone for fs >= 32.
            var vSum0 = System.Runtime.Intrinsics.Vector256<float>.Zero;
            var vSum1 = System.Runtime.Intrinsics.Vector256<float>.Zero;
            var vSum2 = System.Runtime.Intrinsics.Vector256<float>.Zero;
            var vSum3 = System.Runtime.Intrinsics.Vector256<float>.Zero;
            var vSumSq0 = System.Runtime.Intrinsics.Vector256<float>.Zero;
            var vSumSq1 = System.Runtime.Intrinsics.Vector256<float>.Zero;
            var vSumSq2 = System.Runtime.Intrinsics.Vector256<float>.Zero;
            var vSumSq3 = System.Runtime.Intrinsics.Vector256<float>.Zero;
            int f = 0;
            int fs32 = fs & ~31;
            for (; f < fs32; f += 32)
            {
                var v0 = System.Runtime.CompilerServices.Unsafe.ReadUnaligned<System.Runtime.Intrinsics.Vector256<float>>(
                    ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fInput[off + f]));
                var v1 = System.Runtime.CompilerServices.Unsafe.ReadUnaligned<System.Runtime.Intrinsics.Vector256<float>>(
                    ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fInput[off + f + 8]));
                var v2v = System.Runtime.CompilerServices.Unsafe.ReadUnaligned<System.Runtime.Intrinsics.Vector256<float>>(
                    ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fInput[off + f + 16]));
                var v3 = System.Runtime.CompilerServices.Unsafe.ReadUnaligned<System.Runtime.Intrinsics.Vector256<float>>(
                    ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fInput[off + f + 24]));
                vSum0 = System.Runtime.Intrinsics.X86.Avx.Add(vSum0, v0);
                vSum1 = System.Runtime.Intrinsics.X86.Avx.Add(vSum1, v1);
                vSum2 = System.Runtime.Intrinsics.X86.Avx.Add(vSum2, v2v);
                vSum3 = System.Runtime.Intrinsics.X86.Avx.Add(vSum3, v3);
                vSumSq0 = System.Runtime.Intrinsics.X86.Fma.MultiplyAdd(v0, v0, vSumSq0);
                vSumSq1 = System.Runtime.Intrinsics.X86.Fma.MultiplyAdd(v1, v1, vSumSq1);
                vSumSq2 = System.Runtime.Intrinsics.X86.Fma.MultiplyAdd(v2v, v2v, vSumSq2);
                vSumSq3 = System.Runtime.Intrinsics.X86.Fma.MultiplyAdd(v3, v3, vSumSq3);
            }
            // Tail: handle remaining 8-vector chunks with a single accumulator.
            for (; f + 8 <= fs; f += 8)
            {
                var v = System.Runtime.CompilerServices.Unsafe.ReadUnaligned<System.Runtime.Intrinsics.Vector256<float>>(
                    ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fInput[off + f]));
                vSum0 = System.Runtime.Intrinsics.X86.Avx.Add(vSum0, v);
                vSumSq0 = System.Runtime.Intrinsics.X86.Fma.MultiplyAdd(v, v, vSumSq0);
            }
            // Combine the 4 parallel accumulator chains.
            var vSum01 = System.Runtime.Intrinsics.X86.Avx.Add(vSum0, vSum1);
            var vSum23 = System.Runtime.Intrinsics.X86.Avx.Add(vSum2, vSum3);
            var vSum   = System.Runtime.Intrinsics.X86.Avx.Add(vSum01, vSum23);
            var vSumSq01 = System.Runtime.Intrinsics.X86.Avx.Add(vSumSq0, vSumSq1);
            var vSumSq23 = System.Runtime.Intrinsics.X86.Avx.Add(vSumSq2, vSumSq3);
            var vSumSq   = System.Runtime.Intrinsics.X86.Avx.Add(vSumSq01, vSumSq23);
            float sum = SimdKernels.HorizontalSum(vSum);
            float sumSq = SimdKernels.HorizontalSum(vSumSq);
            for (; f < fs; f++)
            {
                float x = fInput[off + f];
                sum += x;
                sumSq += x * x;
            }
            m = sum / fs;
            v2 = sumSq / fs - m * m;
            // Numerical-safety clamp: E[X²] - E[X]² can go slightly negative
            // in float32 for near-uniform rows due to catastrophic
            // cancellation. Clamp to 0 — any invStd > 0 maps such rows to
            // zero output, which is the correct degenerate LayerNorm result.
            if (v2 < 0f) v2 = 0f;
            fMean[b] = m;
            fVar[b] = v2;

            // Pass 2: SIMD transform: out = (in - m) * invStd * gamma + beta.
            // 4-way unrolled for the same OoO-saturation reason as pass 1 —
            // sub→mul→fmadd is an 11-cycle dependency chain; running 4 in
            // parallel hides latency and saturates both FMA ports.
            float invStd = 1f / MathF.Sqrt(v2 + fEps);
            var vInvStd = System.Runtime.Intrinsics.Vector256.Create(invStd);
            var vMNeg = System.Runtime.Intrinsics.Vector256.Create(m);
            f = 0;
            int fs2_32 = fs & ~31;
            for (; f < fs2_32; f += 32)
            {
                var v0 = System.Runtime.CompilerServices.Unsafe.ReadUnaligned<System.Runtime.Intrinsics.Vector256<float>>(
                    ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fInput[off + f]));
                var v1 = System.Runtime.CompilerServices.Unsafe.ReadUnaligned<System.Runtime.Intrinsics.Vector256<float>>(
                    ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fInput[off + f + 8]));
                var v2v = System.Runtime.CompilerServices.Unsafe.ReadUnaligned<System.Runtime.Intrinsics.Vector256<float>>(
                    ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fInput[off + f + 16]));
                var v3 = System.Runtime.CompilerServices.Unsafe.ReadUnaligned<System.Runtime.Intrinsics.Vector256<float>>(
                    ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fInput[off + f + 24]));
                var vG0 = System.Runtime.CompilerServices.Unsafe.ReadUnaligned<System.Runtime.Intrinsics.Vector256<float>>(
                    ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fGamma[f]));
                var vG1 = System.Runtime.CompilerServices.Unsafe.ReadUnaligned<System.Runtime.Intrinsics.Vector256<float>>(
                    ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fGamma[f + 8]));
                var vG2 = System.Runtime.CompilerServices.Unsafe.ReadUnaligned<System.Runtime.Intrinsics.Vector256<float>>(
                    ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fGamma[f + 16]));
                var vG3 = System.Runtime.CompilerServices.Unsafe.ReadUnaligned<System.Runtime.Intrinsics.Vector256<float>>(
                    ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fGamma[f + 24]));
                var vB0 = System.Runtime.CompilerServices.Unsafe.ReadUnaligned<System.Runtime.Intrinsics.Vector256<float>>(
                    ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fBeta[f]));
                var vB1 = System.Runtime.CompilerServices.Unsafe.ReadUnaligned<System.Runtime.Intrinsics.Vector256<float>>(
                    ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fBeta[f + 8]));
                var vB2 = System.Runtime.CompilerServices.Unsafe.ReadUnaligned<System.Runtime.Intrinsics.Vector256<float>>(
                    ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fBeta[f + 16]));
                var vB3 = System.Runtime.CompilerServices.Unsafe.ReadUnaligned<System.Runtime.Intrinsics.Vector256<float>>(
                    ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fBeta[f + 24]));
                var d0 = System.Runtime.Intrinsics.X86.Avx.Subtract(v0, vMNeg);
                var d1 = System.Runtime.Intrinsics.X86.Avx.Subtract(v1, vMNeg);
                var d2 = System.Runtime.Intrinsics.X86.Avx.Subtract(v2v, vMNeg);
                var d3 = System.Runtime.Intrinsics.X86.Avx.Subtract(v3, vMNeg);
                var s0 = System.Runtime.Intrinsics.X86.Avx.Multiply(d0, vInvStd);
                var s1 = System.Runtime.Intrinsics.X86.Avx.Multiply(d1, vInvStd);
                var s2 = System.Runtime.Intrinsics.X86.Avx.Multiply(d2, vInvStd);
                var s3 = System.Runtime.Intrinsics.X86.Avx.Multiply(d3, vInvStd);
                var f0 = System.Runtime.Intrinsics.X86.Fma.MultiplyAdd(s0, vG0, vB0);
                var f1 = System.Runtime.Intrinsics.X86.Fma.MultiplyAdd(s1, vG1, vB1);
                var f2 = System.Runtime.Intrinsics.X86.Fma.MultiplyAdd(s2, vG2, vB2);
                var f3 = System.Runtime.Intrinsics.X86.Fma.MultiplyAdd(s3, vG3, vB3);
                System.Runtime.CompilerServices.Unsafe.WriteUnaligned(
                    ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fOutput[off + f]), f0);
                System.Runtime.CompilerServices.Unsafe.WriteUnaligned(
                    ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fOutput[off + f + 8]), f1);
                System.Runtime.CompilerServices.Unsafe.WriteUnaligned(
                    ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fOutput[off + f + 16]), f2);
                System.Runtime.CompilerServices.Unsafe.WriteUnaligned(
                    ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fOutput[off + f + 24]), f3);
            }
            // Tail: handle remaining 8-vector chunks.
            for (; f + 8 <= fs; f += 8)
            {
                var v = System.Runtime.CompilerServices.Unsafe.ReadUnaligned<System.Runtime.Intrinsics.Vector256<float>>(
                    ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fInput[off + f]));
                var vG = System.Runtime.CompilerServices.Unsafe.ReadUnaligned<System.Runtime.Intrinsics.Vector256<float>>(
                    ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fGamma[f]));
                var vB = System.Runtime.CompilerServices.Unsafe.ReadUnaligned<System.Runtime.Intrinsics.Vector256<float>>(
                    ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fBeta[f]));
                var d = System.Runtime.Intrinsics.X86.Avx.Subtract(v, vMNeg);
                var scaled = System.Runtime.Intrinsics.X86.Avx.Multiply(d, vInvStd);
                var final = System.Runtime.Intrinsics.X86.Fma.MultiplyAdd(scaled, vG, vB);
                System.Runtime.CompilerServices.Unsafe.WriteUnaligned(
                    ref System.Runtime.CompilerServices.Unsafe.As<float, byte>(ref fOutput[off + f]), final);
            }
            for (; f < fs; f++)
                fOutput[off + f] = (fInput[off + f] - m) * invStd * fGamma[f] + fBeta[f];
            return;
        }
#endif

        // Scalar fallback
        {
            float sum = 0f;
            for (int f = 0; f < fs; f++) sum += fInput[off + f];
            m = sum / fs;
            fMean[b] = m;
            float sumSq = 0f;
            for (int f = 0; f < fs; f++)
            {
                float d = fInput[off + f] - m;
                sumSq += d * d;
            }
            v2 = sumSq / fs;
            fVar[b] = v2;
            float invStd = 1f / MathF.Sqrt(v2 + fEps);
            for (int f = 0; f < fs; f++)
                fOutput[off + f] = (fInput[off + f] - m) * invStd * fGamma[f] + fBeta[f];
        }
    }

    /// <inheritdoc/>
    public Tensor<T> LayerNormBackward<T>(Tensor<T> gradOutput, Tensor<T> input, Tensor<T> gamma, Tensor<T> mean, Tensor<T> variance, double epsilon, out Tensor<T> gradGamma, out Tensor<T> gradBeta)
    {
        if (gradOutput == null) throw new ArgumentNullException(nameof(gradOutput));
        if (input == null) throw new ArgumentNullException(nameof(input));

        var numOps = MathHelper.GetNumericOperations<T>();
        T eps = numOps.FromDouble(epsilon);

        // Determine normalized dimensions from gamma shape (same as forward pass)
        int normalizedDims = gamma._shape.Length;
        int inputRank = input._shape.Length;
        int batchDims = inputRank - normalizedDims;

        // Calculate batch size and feature size
        int batchSize = 1;
        for (int i = 0; i < batchDims; i++)
        {
            batchSize *= input._shape[i];
        }
        if (batchDims == 0) batchSize = 1;

        int featureSize = gamma.Length;

        var gradOutputData = gradOutput.GetFlattenedData();
        var inputData = input.GetFlattenedData();
        var gammaData = gamma.GetFlattenedData();
        var meanData = mean.GetDataArray();
        var varData = variance.GetDataArray();

        var gradGammaData = new T[featureSize];
        var gradBetaData = new T[featureSize];
        var gradInputData = new T[batchSize * featureSize];

        // ────────────────────────────────────────────────────────────────────
        // Primitive fast paths: direct array access, no INumericOperations<T>
        // virtual dispatch. Mirror of the LayerNorm forward's primitive
        // branches. Method signature stays generic <T>; non-primitive T
        // (complex, Half, int, etc.) falls through to the scalar path below.
        //
        // Transformer training pays this op's cost on every backward step.
        // Scientific consumers using T = double were on the scalar path — now
        // they get the same dispatch-free treatment as float.
        // ────────────────────────────────────────────────────────────────────
        if (typeof(T) == typeof(float))
        {
            var fGradOut = (float[])(object)gradOutputData;
            var fInput = (float[])(object)inputData;
            var fGamma = (float[])(object)gammaData;
            var fMean = (float[])(object)meanData;
            var fVar = (float[])(object)varData;
            var fGradGamma = (float[])(object)gradGammaData;
            var fGradBeta = (float[])(object)gradBetaData;
            var fGradInput = (float[])(object)gradInputData;
            float fEps = (float)epsilon;
            int fs = featureSize;
            float featureSizeF = fs;
            float invFeatureSizeF = 1f / featureSizeF;

            // gradGamma / gradBeta: sum across batches. Left sequential to avoid
            // cross-thread contention on the [featureSize] accumulators. For
            // typical transformer LN (featureSize ≈ hidden dim ≈ 768–4096 and
            // batchSize × seq ≈ 1k–4k), the sequential pass is memory-bound, not
            // compute-bound, so threading doesn't help.
            for (int b = 0; b < batchSize; b++)
            {
                int off = b * fs;
                float invStd = 1f / MathF.Sqrt(fVar[b] + fEps);
                float m = fMean[b];
                for (int f = 0; f < fs; f++)
                {
                    float go = fGradOut[off + f];
                    float normalized = (fInput[off + f] - m) * invStd;
                    fGradGamma[f] += go * normalized;
                    fGradBeta[f] += go;
                }
            }

            // gradInput: per-batch two-pass (sum reductions, then per-element).
            // Safe to parallelize over batches since each batch writes to a
            // disjoint [b*fs, (b+1)*fs) slice of gradInput.
            void ProcessBatch(int b)
            {
                int off = b * fs;
                float invStd = 1f / MathF.Sqrt(fVar[b] + fEps);
                float m = fMean[b];

                float sumGrad = 0f;
                float sumGradX = 0f;
                for (int f = 0; f < fs; f++)
                {
                    float scaledGrad = fGamma[f] * fGradOut[off + f];
                    sumGrad += scaledGrad;
                    sumGradX += scaledGrad * (fInput[off + f] - m);
                }

                float scale = invStd * invFeatureSizeF;
                for (int f = 0; f < fs; f++)
                {
                    float normalized = (fInput[off + f] - m) * invStd;
                    float gradNorm = fGamma[f] * fGradOut[off + f];
                    float term1 = featureSizeF * gradNorm;
                    float term3 = normalized * invStd * sumGradX;
                    fGradInput[off + f] = scale * (term1 - sumGrad - term3);
                }
            }

            // Same threshold used by the forward: below ~50K total elements the
            // Parallel.For dispatch cost exceeds the work.
            if (batchSize * fs < 50_000)
            {
                for (int b = 0; b < batchSize; b++) ProcessBatch(b);
            }
            else
            {
                Parallel.For(0, batchSize, ProcessBatch);
            }
        }
        else if (typeof(T) == typeof(double))
        {
            var dGradOut = (double[])(object)gradOutputData;
            var dInput = (double[])(object)inputData;
            var dGamma = (double[])(object)gammaData;
            var dMean = (double[])(object)meanData;
            var dVar = (double[])(object)varData;
            var dGradGamma = (double[])(object)gradGammaData;
            var dGradBeta = (double[])(object)gradBetaData;
            var dGradInput = (double[])(object)gradInputData;
            int fs = featureSize;
            double featureSizeD = fs;
            double invFeatureSizeD = 1.0 / featureSizeD;

            for (int b = 0; b < batchSize; b++)
            {
                int off = b * fs;
                double invStd = 1.0 / Math.Sqrt(dVar[b] + epsilon);
                double m = dMean[b];
                for (int f = 0; f < fs; f++)
                {
                    double go = dGradOut[off + f];
                    double normalized = (dInput[off + f] - m) * invStd;
                    dGradGamma[f] += go * normalized;
                    dGradBeta[f] += go;
                }
            }

            void ProcessBatch(int b)
            {
                int off = b * fs;
                double invStd = 1.0 / Math.Sqrt(dVar[b] + epsilon);
                double m = dMean[b];

                double sumGrad = 0.0;
                double sumGradX = 0.0;
                for (int f = 0; f < fs; f++)
                {
                    double scaledGrad = dGamma[f] * dGradOut[off + f];
                    sumGrad += scaledGrad;
                    sumGradX += scaledGrad * (dInput[off + f] - m);
                }

                double scale = invStd * invFeatureSizeD;
                for (int f = 0; f < fs; f++)
                {
                    double normalized = (dInput[off + f] - m) * invStd;
                    double gradNorm = dGamma[f] * dGradOut[off + f];
                    double term1 = featureSizeD * gradNorm;
                    double term3 = normalized * invStd * sumGradX;
                    dGradInput[off + f] = scale * (term1 - sumGrad - term3);
                }
            }

            if (batchSize * fs < 50_000)
            {
                for (int b = 0; b < batchSize; b++) ProcessBatch(b);
            }
            else
            {
                Parallel.For(0, batchSize, ProcessBatch);
            }
        }
        else
        {
            T featureSizeT = numOps.FromDouble(featureSize);

            // Compute gradGamma and gradBeta
            for (int b = 0; b < batchSize; b++)
            {
                T invStd = numOps.Divide(numOps.One, numOps.Sqrt(numOps.Add(varData[b], eps)));
                for (int f = 0; f < featureSize; f++)
                {
                    int idx = b * featureSize + f;
                    T normalized = numOps.Multiply(numOps.Subtract(inputData[idx], meanData[b]), invStd);
                    gradGammaData[f] = numOps.Add(gradGammaData[f], numOps.Multiply(gradOutputData[idx], normalized));
                    gradBetaData[f] = numOps.Add(gradBetaData[f], gradOutputData[idx]);
                }
            }

            // Compute gradInput
            Parallel.For(0, batchSize, b =>
            {
                T invStd = numOps.Divide(numOps.One, numOps.Sqrt(numOps.Add(varData[b], eps)));
                T sumGrad = numOps.Zero;
                T sumGradX = numOps.Zero;

                for (int f = 0; f < featureSize; f++)
                {
                    int idx = b * featureSize + f;
                    T scaledGrad = numOps.Multiply(gammaData[f], gradOutputData[idx]);
                    sumGrad = numOps.Add(sumGrad, scaledGrad);
                    sumGradX = numOps.Add(sumGradX, numOps.Multiply(scaledGrad, numOps.Subtract(inputData[idx], meanData[b])));
                }

                for (int f = 0; f < featureSize; f++)
                {
                    int idx = b * featureSize + f;
                    T normalized = numOps.Multiply(numOps.Subtract(inputData[idx], meanData[b]), invStd);
                    T gradNorm = numOps.Multiply(gammaData[f], gradOutputData[idx]);
                    T term1 = numOps.Multiply(featureSizeT, gradNorm);
                    T term2 = sumGrad;
                    T term3 = numOps.Multiply(normalized, numOps.Multiply(invStd, sumGradX));
                    gradInputData[idx] = numOps.Multiply(numOps.Divide(invStd, featureSizeT), numOps.Subtract(numOps.Subtract(term1, term2), term3));
                }
            });
        }

        gradGamma = TensorAllocator.Rent<T>(gamma._shape, new Vector<T>(gradGammaData));
        gradBeta = TensorAllocator.Rent<T>(gamma._shape, new Vector<T>(gradBetaData));
        return TensorAllocator.Rent<T>(input._shape, new Vector<T>(gradInputData));
    }

    /// <inheritdoc/>
    public virtual Tensor<T> GroupNorm<T>(Tensor<T> input, int numGroups, Tensor<T> gamma, Tensor<T> beta, double epsilon, out Tensor<T> mean, out Tensor<T> variance)
    {
        if (input == null) throw new ArgumentNullException(nameof(input));
        if (gamma == null) throw new ArgumentNullException(nameof(gamma));
        if (beta == null) throw new ArgumentNullException(nameof(beta));

        if (GraphMode.IsActive)
        {
            var scope = GraphMode.Current;
            if (scope != null)
            {
                var ci = input; var cg = gamma; var cb = beta; int cn = numGroups; double ce = epsilon;
                var savedScope = GraphMode.Current;
                GraphMode.SetCurrent(null);
                var eagerResult = GroupNorm(ci, cn, cg, cb, ce, out mean, out variance);
                GraphMode.SetCurrent(savedScope);
                // SavedState order MUST match BackwardFunctions<T>.GroupNormBackward's
                // read order: [numGroups, mean, variance, epsilon]. Previously this was
                // [mean, variance, numGroups, epsilon] causing InvalidCastException in
                // backward (Tensor cast as int at savedState[0]). Fixed per #178.
                var lazyResult = scope.RecordVariadic(LazyNodeType.Custom, "GroupNorm",
                    new[] { input, gamma, beta }, eagerResult._shape,
                    (eng, output) =>
                    {
                        if (eng is CpuEngine cpuEng)
                        {
                            cpuEng.GroupNormInto(output, ci, cn, cg, cb, ce, out _, out _);
                        }
                        else { var r = eng.GroupNorm(ci, cn, cg, cb, ce, out _, out _); r.AsSpan().CopyTo(output.AsWritableSpan()); }
                    },
                    // SavedState order per #178 fix above: numGroups must come first so
                    // GroupNormBackward reads savedState[0] as int (not as Tensor).
                    BackwardFunctions<T>.GroupNormBackward, new object[] { numGroups, mean, variance, epsilon });
                eagerResult.AsSpan().CopyTo(lazyResult.AsWritableSpan());
                return lazyResult;
            }
        }

        // Preserve original input ref for tape recording (#257).
        var inputOrig = input;
        if (!input.IsContiguous) input = input.Contiguous();
        if (numGroups <= 0) throw new ArgumentOutOfRangeException(nameof(numGroups), "Number of groups must be positive.");

        var numOps = MathHelper.GetNumericOperations<T>();
        T eps = numOps.FromDouble(epsilon);

        // Input shape: [batch, channels, ...spatial]
        int batch = input._shape[0];
        int channels = input._shape[1];

        if (channels % numGroups != 0)
        {
            throw new ArgumentException($"Number of channels ({channels}) must be divisible by number of groups ({numGroups}).");
        }

        int channelsPerGroup = channels / numGroups;

        // Compute spatial size (product of all dimensions after batch and channels)
        int spatialSize = 1;
        for (int i = 2; i < input._shape.Length; i++)
        {
            spatialSize *= input._shape[i];
        }

        int groupSize = channelsPerGroup * spatialSize;  // Elements per group

        // Fast float path: Pin() for NativeMemory compatibility
        if (typeof(T) == typeof(float))
        {
            var result = AutoTensorCache.RentOrAllocate<T>(input._shape);
            // Pin all memory to get float* pointers (works with both managed and NativeMemory)
            using var pinIn = input.Data.Pin();
            using var pinOut = result.Data.Pin();
            using var pinGamma = gamma.Data.Pin();
            using var pinBeta = beta.Data.Pin();
            unsafe
            {
                GroupNormFloatPtr(
                    (float*)pinIn.Pointer, (float*)pinOut.Pointer,
                    (float*)pinGamma.Pointer, (float*)pinBeta.Pointer,
                    batch, channels, spatialSize, numGroups, channelsPerGroup,
                    System.Runtime.CompilerServices.Unsafe.As<T, float>(ref eps),
                    out var meanArr, out var varArr);
                mean = TensorAllocator.Rent<T>(new[] { batch, numGroups },
                    new Vector<T>((T[])(object)meanArr));
                variance = TensorAllocator.Rent<T>(new[] { batch, numGroups },
                    new Vector<T>((T[])(object)varArr));
            }
            DifferentiableOps.RecordIfActive("GroupNorm", result, new[] { inputOrig, gamma, beta },
                BackwardFunctions<T>.GroupNormBackward, new object[] { numGroups, mean, variance, epsilon });
            AutoTracer.RecordOp("GroupNorm", result, eng => result);
            return result;
        }

        var inputData = input.GetDataArray();
        var gammaData = gamma.GetDataArray();
        var betaData = beta.GetDataArray();

        // Mean and variance are computed per batch per group
        var meanData = new T[batch * numGroups];
        var varData = new T[batch * numGroups];
        // Allocate output via TensorAllocator to benefit from pooling.
        // Write directly into the tensor's backing array — avoid the Rent().GetDataArray()
        // round-trip which can return an oversized pooled array.
        var output = AutoTensorCache.RentOrAllocate<T>(input._shape);
        var outputData = output.GetDataArray();

        // Fused mean + variance + normalize per batch*group
        Parallel.For(0, batch * numGroups, idx =>
        {
            int b = idx / numGroups;
            int g = idx % numGroups;
            int startChannel = g * channelsPerGroup;
            int batchOffset = b * (channels * spatialSize);
            T groupSizeT = numOps.FromDouble(groupSize);

            // Compute mean
            T sum = numOps.Zero;
            for (int c = 0; c < channelsPerGroup; c++)
            {
                int chanOffset = batchOffset + (startChannel + c) * spatialSize;
                for (int s = 0; s < spatialSize; s++)
                    sum = numOps.Add(sum, inputData[chanOffset + s]);
            }
            T groupMean = numOps.Divide(sum, groupSizeT);
            meanData[b * numGroups + g] = groupMean;

            // Compute variance
            T sumSq = numOps.Zero;
            for (int c = 0; c < channelsPerGroup; c++)
            {
                int chanOffset = batchOffset + (startChannel + c) * spatialSize;
                for (int s = 0; s < spatialSize; s++)
                {
                    T diff = numOps.Subtract(inputData[chanOffset + s], groupMean);
                    sumSq = numOps.Add(sumSq, numOps.Multiply(diff, diff));
                }
            }
            T groupVar = numOps.Divide(sumSq, groupSizeT);
            varData[b * numGroups + g] = groupVar;

            // Normalize and apply scale/shift
            T invStd = numOps.Divide(numOps.One, numOps.Sqrt(numOps.Add(groupVar, eps)));
            for (int c = 0; c < channelsPerGroup; c++)
            {
                int channel = startChannel + c;
                int chanOffset = batchOffset + channel * spatialSize;
                for (int s = 0; s < spatialSize; s++)
                {
                    T normalized = numOps.Multiply(numOps.Subtract(inputData[chanOffset + s], groupMean), invStd);
                    outputData[chanOffset + s] = numOps.Add(numOps.Multiply(gammaData[channel], normalized), betaData[channel]);
                }
            }
        });

        mean = TensorAllocator.Rent<T>([batch, numGroups], Vector<T>.WrapMemory(meanData));
        variance = TensorAllocator.Rent<T>([batch, numGroups], Vector<T>.WrapMemory(varData));
        DifferentiableOps.RecordIfActive("GroupNorm", output, new[] { inputOrig, gamma, beta },
            BackwardFunctions<T>.GroupNormBackward, new object[] { numGroups, mean, variance, epsilon });
        return output;
    }

    /// <inheritdoc/>
    public Tensor<T> GroupNormBackward<T>(Tensor<T> gradOutput, Tensor<T> input, int numGroups, Tensor<T> gamma, Tensor<T> mean, Tensor<T> variance, double epsilon, out Tensor<T> gradGamma, out Tensor<T> gradBeta)
    {
        if (gradOutput == null) throw new ArgumentNullException(nameof(gradOutput));
        if (input == null) throw new ArgumentNullException(nameof(input));
        if (gamma == null) throw new ArgumentNullException(nameof(gamma));
        if (mean == null) throw new ArgumentNullException(nameof(mean));
        if (variance == null) throw new ArgumentNullException(nameof(variance));

        var numOps = MathHelper.GetNumericOperations<T>();
        T eps = numOps.FromDouble(epsilon);

        int batch = input._shape[0];
        int channels = input._shape[1];
        int channelsPerGroup = channels / numGroups;

        // Compute spatial size
        int spatialSize = 1;
        for (int i = 2; i < input._shape.Length; i++)
        {
            spatialSize *= input._shape[i];
        }

        int groupSize = channelsPerGroup * spatialSize;

        var gradOutputData = gradOutput.GetDataArray();
        var inputData = input.GetFlattenedData();
        var gammaData = gamma.GetDataArray();
        var meanData = mean.GetDataArray();
        var varData = variance.GetDataArray();

        var gradGammaData = new T[channels];
        var gradBetaData = new T[channels];
        var gradInputData = new T[input.Length];

        // ────────────────────────────────────────────────────────────────────
        // Primitive fast paths: direct float/double arithmetic, no
        // INumericOperations<T> virtual dispatch. Method signature stays
        // generic <T>; non-primitive T falls through to the scalar path.
        //
        // Diffusion UNet training pays this cost on every backward pass — SD15
        // UNet has ~40 GroupNorm layers and backward runs through all of them
        // per training step. Consumers using T = double get the same treatment.
        // ────────────────────────────────────────────────────────────────────
        if (typeof(T) == typeof(float))
        {
            var fGradOut = (float[])(object)gradOutputData;
            var fInput = (float[])(object)inputData;
            var fGamma = (float[])(object)gammaData;
            var fMean = (float[])(object)meanData;
            var fVar = (float[])(object)varData;
            var fGradGamma = (float[])(object)gradGammaData;
            var fGradBeta = (float[])(object)gradBetaData;
            var fGradInput = (float[])(object)gradInputData;
            float fEps = (float)epsilon;
            float groupSizeF = groupSize;
            float invGroupSizeF = 1f / groupSizeF;

            // gradGamma / gradBeta: sum across (batch, spatial). Sequential
            // across batches to avoid per-channel accumulator contention, but
            // spatial inner loop runs on direct floats. We pre-compute invStd
            // once per (b, g) to avoid recomputing inside the spatial loop.
            for (int b = 0; b < batch; b++)
            {
                for (int g = 0; g < numGroups; g++)
                {
                    float groupMean = fMean[b * numGroups + g];
                    float invStd = 1f / MathF.Sqrt(fVar[b * numGroups + g] + fEps);
                    int startChannel = g * channelsPerGroup;
                    for (int c = 0; c < channelsPerGroup; c++)
                    {
                        int channel = startChannel + c;
                        int chanOffset = b * (channels * spatialSize) + channel * spatialSize;
                        float gammaAcc = 0f;
                        float betaAcc = 0f;
                        for (int s = 0; s < spatialSize; s++)
                        {
                            float go = fGradOut[chanOffset + s];
                            float normalized = (fInput[chanOffset + s] - groupMean) * invStd;
                            gammaAcc += go * normalized;
                            betaAcc += go;
                        }
                        fGradGamma[channel] += gammaAcc;
                        fGradBeta[channel] += betaAcc;
                    }
                }
            }

            // gradInput: parallel over batch. Each batch writes a disjoint
            // [b*channels*spatialSize, (b+1)*channels*spatialSize) slice.
            void ProcessBatch(int b)
            {
                for (int g = 0; g < numGroups; g++)
                {
                    float groupMean = fMean[b * numGroups + g];
                    float invStd = 1f / MathF.Sqrt(fVar[b * numGroups + g] + fEps);
                    int startChannel = g * channelsPerGroup;

                    // Pass 1: sumGrad and sumGradNorm over the group.
                    float sumGrad = 0f;
                    float sumGradNorm = 0f;
                    for (int c = 0; c < channelsPerGroup; c++)
                    {
                        int channel = startChannel + c;
                        int chanOffset = b * (channels * spatialSize) + channel * spatialSize;
                        float gammaC = fGamma[channel];
                        for (int s = 0; s < spatialSize; s++)
                        {
                            float scaledGrad = gammaC * fGradOut[chanOffset + s];
                            float normalized = (fInput[chanOffset + s] - groupMean) * invStd;
                            sumGrad += scaledGrad;
                            sumGradNorm += scaledGrad * normalized;
                        }
                    }

                    // Pass 2: write gradInput.
                    float scale = invStd * invGroupSizeF;
                    for (int c = 0; c < channelsPerGroup; c++)
                    {
                        int channel = startChannel + c;
                        int chanOffset = b * (channels * spatialSize) + channel * spatialSize;
                        float gammaC = fGamma[channel];
                        for (int s = 0; s < spatialSize; s++)
                        {
                            float normalized = (fInput[chanOffset + s] - groupMean) * invStd;
                            float gradNorm = gammaC * fGradOut[chanOffset + s];
                            float term1 = groupSizeF * gradNorm;
                            float term3 = normalized * sumGradNorm;
                            fGradInput[chanOffset + s] = scale * (term1 - sumGrad - term3);
                        }
                    }
                }
            }

            // Batch typically small (1–16) for diffusion training, but each
            // batch's work is large (channels × spatialSize). Always parallel.
            Parallel.For(0, batch, ProcessBatch);
        }
        else if (typeof(T) == typeof(double))
        {
            var dGradOut = (double[])(object)gradOutputData;
            var dInput = (double[])(object)inputData;
            var dGamma = (double[])(object)gammaData;
            var dMean = (double[])(object)meanData;
            var dVar = (double[])(object)varData;
            var dGradGamma = (double[])(object)gradGammaData;
            var dGradBeta = (double[])(object)gradBetaData;
            var dGradInput = (double[])(object)gradInputData;
            double groupSizeD = groupSize;
            double invGroupSizeD = 1.0 / groupSizeD;

            for (int b = 0; b < batch; b++)
            {
                for (int g = 0; g < numGroups; g++)
                {
                    double groupMean = dMean[b * numGroups + g];
                    double invStd = 1.0 / Math.Sqrt(dVar[b * numGroups + g] + epsilon);
                    int startChannel = g * channelsPerGroup;
                    for (int c = 0; c < channelsPerGroup; c++)
                    {
                        int channel = startChannel + c;
                        int chanOffset = b * (channels * spatialSize) + channel * spatialSize;
                        double gammaAcc = 0.0;
                        double betaAcc = 0.0;
                        for (int s = 0; s < spatialSize; s++)
                        {
                            double go = dGradOut[chanOffset + s];
                            double normalized = (dInput[chanOffset + s] - groupMean) * invStd;
                            gammaAcc += go * normalized;
                            betaAcc += go;
                        }
                        dGradGamma[channel] += gammaAcc;
                        dGradBeta[channel] += betaAcc;
                    }
                }
            }

            void ProcessBatchD(int b)
            {
                for (int g = 0; g < numGroups; g++)
                {
                    double groupMean = dMean[b * numGroups + g];
                    double invStd = 1.0 / Math.Sqrt(dVar[b * numGroups + g] + epsilon);
                    int startChannel = g * channelsPerGroup;

                    double sumGrad = 0.0;
                    double sumGradNorm = 0.0;
                    for (int c = 0; c < channelsPerGroup; c++)
                    {
                        int channel = startChannel + c;
                        int chanOffset = b * (channels * spatialSize) + channel * spatialSize;
                        double gammaC = dGamma[channel];
                        for (int s = 0; s < spatialSize; s++)
                        {
                            double scaledGrad = gammaC * dGradOut[chanOffset + s];
                            double normalized = (dInput[chanOffset + s] - groupMean) * invStd;
                            sumGrad += scaledGrad;
                            sumGradNorm += scaledGrad * normalized;
                        }
                    }

                    double scale = invStd * invGroupSizeD;
                    for (int c = 0; c < channelsPerGroup; c++)
                    {
                        int channel = startChannel + c;
                        int chanOffset = b * (channels * spatialSize) + channel * spatialSize;
                        double gammaC = dGamma[channel];
                        for (int s = 0; s < spatialSize; s++)
                        {
                            double normalized = (dInput[chanOffset + s] - groupMean) * invStd;
                            double gradNorm = gammaC * dGradOut[chanOffset + s];
                            double term1 = groupSizeD * gradNorm;
                            double term3 = normalized * sumGradNorm;
                            dGradInput[chanOffset + s] = scale * (term1 - sumGrad - term3);
                        }
                    }
                }
            }

            Parallel.For(0, batch, ProcessBatchD);
        }
        else
        {
            T groupSizeT = numOps.FromDouble(groupSize);

            // Initialize gradGamma and gradBeta to zero
            for (int c = 0; c < channels; c++)
            {
                gradGammaData[c] = numOps.Zero;
                gradBetaData[c] = numOps.Zero;
            }

            // Compute gradGamma and gradBeta (sum across batch and spatial)
            for (int b = 0; b < batch; b++)
            {
                for (int c = 0; c < channels; c++)
                {
                    int g = c / channelsPerGroup;
                    T groupMean = meanData[b * numGroups + g];
                    T groupVar = varData[b * numGroups + g];
                    T invStd = numOps.Divide(numOps.One, numOps.Sqrt(numOps.Add(groupVar, eps)));

                    for (int s = 0; s < spatialSize; s++)
                    {
                        int idx = b * (channels * spatialSize) + c * spatialSize + s;
                        T normalized = numOps.Multiply(numOps.Subtract(inputData[idx], groupMean), invStd);
                        gradGammaData[c] = numOps.Add(gradGammaData[c], numOps.Multiply(gradOutputData[idx], normalized));
                        gradBetaData[c] = numOps.Add(gradBetaData[c], gradOutputData[idx]);
                    }
                }
            }

            // Compute gradInput using the group norm backward formula
            Parallel.For(0, batch, b =>
            {
                for (int g = 0; g < numGroups; g++)
                {
                    T groupMean = meanData[b * numGroups + g];
                    T groupVar = varData[b * numGroups + g];
                    T invStd = numOps.Divide(numOps.One, numOps.Sqrt(numOps.Add(groupVar, eps)));

                    T sumGrad = numOps.Zero;
                    T sumGradNorm = numOps.Zero;

                    int startChannel = g * channelsPerGroup;
                    for (int c = 0; c < channelsPerGroup; c++)
                    {
                        int channel = startChannel + c;
                        for (int s = 0; s < spatialSize; s++)
                        {
                            int idx = b * (channels * spatialSize) + channel * spatialSize + s;
                            T scaledGrad = numOps.Multiply(gammaData[channel], gradOutputData[idx]);
                            T normalized = numOps.Multiply(numOps.Subtract(inputData[idx], groupMean), invStd);
                            sumGrad = numOps.Add(sumGrad, scaledGrad);
                            sumGradNorm = numOps.Add(sumGradNorm, numOps.Multiply(scaledGrad, normalized));
                        }
                    }

                    for (int c = 0; c < channelsPerGroup; c++)
                    {
                        int channel = startChannel + c;
                        for (int s = 0; s < spatialSize; s++)
                        {
                            int idx = b * (channels * spatialSize) + channel * spatialSize + s;
                            T normalized = numOps.Multiply(numOps.Subtract(inputData[idx], groupMean), invStd);
                            T gradNorm = numOps.Multiply(gammaData[channel], gradOutputData[idx]);
                            T term1 = numOps.Multiply(groupSizeT, gradNorm);
                            T term2 = sumGrad;
                            T term3 = numOps.Multiply(normalized, sumGradNorm);
                            gradInputData[idx] = numOps.Multiply(numOps.Divide(invStd, groupSizeT), numOps.Subtract(numOps.Subtract(term1, term2), term3));
                        }
                    }
                }
            });
        }

        gradGamma = TensorAllocator.Rent<T>([channels], new Vector<T>(gradGammaData));
        gradBeta = TensorAllocator.Rent<T>([channels], new Vector<T>(gradBetaData));
        return TensorAllocator.Rent<T>(input._shape, new Vector<T>(gradInputData));
    }


    /// <inheritdoc/>
    public virtual Tensor<T> RMSNorm<T>(Tensor<T> input, Tensor<T> gamma, double epsilon, out Tensor<T> rms)
    {
        if (input == null) throw new ArgumentNullException(nameof(input));
        if (gamma == null) throw new ArgumentNullException(nameof(gamma));

        if (GraphMode.IsActive)
        {
            var scope = GraphMode.Current;
            if (scope != null)
            {
                var ci = input; var cg = gamma; double ce = epsilon;
                var savedScope = GraphMode.Current;
                GraphMode.SetCurrent(null);
                var eagerResult = RMSNorm(ci, cg, ce, out rms);
                GraphMode.SetCurrent(savedScope);
                var lazyResult = scope.RecordBinary(LazyNodeType.Custom, "RMSNorm", input, gamma, eagerResult._shape,
                    (eng, output) => { var r = eng.RMSNorm(ci, cg, ce, out _); r.AsSpan().CopyTo(output.AsWritableSpan()); },
                    BackwardFunctions<T>.RMSNormBackward, new object[] { rms, epsilon });
                eagerResult.AsSpan().CopyTo(lazyResult.AsWritableSpan());
                return lazyResult;
            }
        }

        // Preserve original input ref for tape recording (#257).
        var inputOrig = input;
        if (!input.IsContiguous) input = input.Contiguous();

        var numOps = MathHelper.GetNumericOperations<T>();
        T eps = numOps.FromDouble(epsilon);
        int normalizedDims = gamma._shape.Length;
        int inputRank = input._shape.Length;

        if (normalizedDims > inputRank)
            throw new ArgumentException("Gamma shape has more dimensions than input shape");

        for (int i = 0; i < normalizedDims; i++)
        {
            int inputDimIdx = inputRank - normalizedDims + i;
            if (gamma._shape[i] != input._shape[inputDimIdx])
                throw new ArgumentException("Gamma shape does not match input trailing dimensions");
        }

        int batchSize = 1;
        int batchDims = inputRank - normalizedDims;
        var batchShape = new int[Math.Max(1, batchDims)];
        for (int i = 0; i < batchDims; i++)
        {
            batchSize *= input._shape[i];
            batchShape[i] = input._shape[i];
        }
        if (batchDims == 0) { batchSize = 1; batchShape = [1]; }

        int featureSize = gamma.Length;
        var inputData = input.GetDataArray();
        var gammaData = gamma.GetDataArray();
        var rmsData = new T[batchSize];
        var outputData = new T[batchSize * featureSize];

        Parallel.For(0, batchSize, b =>
        {
            int offset = b * featureSize;
            T featureSizeT = numOps.FromDouble(featureSize);

            // RMS
            T sumSq = numOps.Zero;
            for (int f = 0; f < featureSize; f++)
            {
                T val = inputData[offset + f];
                sumSq = numOps.Add(sumSq, numOps.Multiply(val, val));
            }
            T rmsVal = numOps.Sqrt(numOps.Add(numOps.Divide(sumSq, featureSizeT), eps));
            rmsData[b] = rmsVal;

            // Normalize and scale
            T invRms = numOps.Divide(numOps.One, rmsVal);
            for (int f = 0; f < featureSize; f++)
                outputData[offset + f] = numOps.Multiply(gammaData[f], numOps.Multiply(inputData[offset + f], invRms));
        });

        rms = TensorAllocator.Rent<T>(batchShape, new Vector<T>(rmsData));
        var rmsResult = TensorAllocator.Rent<T>(input._shape, new Vector<T>(outputData));
        DifferentiableOps.RecordIfActive("RMSNorm", rmsResult, new[] { inputOrig, gamma },
            BackwardFunctions<T>.RMSNormBackward, new object[] { rms, epsilon });
        AutoTracer.RecordOp("RMSNorm", rmsResult, eng => rmsResult);
        return rmsResult;
    }

    /// <inheritdoc/>
    public Tensor<T> RMSNormBackward<T>(Tensor<T> gradOutput, Tensor<T> input, Tensor<T> gamma, Tensor<T> rms, double epsilon, out Tensor<T> gradGamma)
    {
        if (gradOutput == null) throw new ArgumentNullException(nameof(gradOutput));
        if (input == null) throw new ArgumentNullException(nameof(input));
        if (gamma == null) throw new ArgumentNullException(nameof(gamma));
        if (rms == null) throw new ArgumentNullException(nameof(rms));

        var numOps = MathHelper.GetNumericOperations<T>();
        int normalizedDims = gamma._shape.Length;
        int inputRank = input._shape.Length;
        int batchDims = inputRank - normalizedDims;
        int batchSize = 1;
        for (int i = 0; i < batchDims; i++) batchSize *= input._shape[i];
        if (batchDims == 0) batchSize = 1;

        int featureSize = gamma.Length;
        var gradOutputData = gradOutput.GetDataArray();
        var inputData = input.GetFlattenedData();
        var gammaData = gamma.GetDataArray();
        var rmsData = rms.GetDataArray();
        var gradGammaData = new T[featureSize];
        var gradInputData = new T[input.Length];

        // ────────────────────────────────────────────────────────────────────
        // Primitive fast paths — method stays generic <T>; float and double
        // bypass INumericOperations<T> virtual dispatch. Used by LLaMA-style
        // transformer training (every block has one RMSNorm).
        // ────────────────────────────────────────────────────────────────────
        if (typeof(T) == typeof(float))
        {
            var fGradOut = (float[])(object)gradOutputData;
            var fInput = (float[])(object)inputData;
            var fGamma = (float[])(object)gammaData;
            var fRms = (float[])(object)rmsData;
            var fGradGamma = (float[])(object)gradGammaData;
            var fGradInput = (float[])(object)gradInputData;
            int fs = featureSize;
            float invFeatureSizeF = 1f / fs;

            for (int b = 0; b < batchSize; b++)
            {
                int off = b * fs;
                float invRms = 1f / fRms[b];
                for (int f = 0; f < fs; f++)
                {
                    float normalized = fInput[off + f] * invRms;
                    fGradGamma[f] += fGradOut[off + f] * normalized;
                }
            }

            Parallel.For(0, batchSize, b =>
            {
                int off = b * fs;
                float invRms = 1f / fRms[b];
                float sumCorrection = 0f;
                for (int f = 0; f < fs; f++)
                {
                    float scaledGrad = fGamma[f] * fGradOut[off + f];
                    float normalized = fInput[off + f] * invRms;
                    sumCorrection += scaledGrad * normalized;
                }
                float meanCorrection = sumCorrection * invFeatureSizeF;
                for (int f = 0; f < fs; f++)
                {
                    float scaledGrad = fGamma[f] * fGradOut[off + f];
                    float normalized = fInput[off + f] * invRms;
                    fGradInput[off + f] = invRms * (scaledGrad - normalized * meanCorrection);
                }
            });
        }
        else if (typeof(T) == typeof(double))
        {
            var dGradOut = (double[])(object)gradOutputData;
            var dInput = (double[])(object)inputData;
            var dGamma = (double[])(object)gammaData;
            var dRms = (double[])(object)rmsData;
            var dGradGamma = (double[])(object)gradGammaData;
            var dGradInput = (double[])(object)gradInputData;
            int fs = featureSize;
            double invFeatureSizeD = 1.0 / fs;

            for (int b = 0; b < batchSize; b++)
            {
                int off = b * fs;
                double invRms = 1.0 / dRms[b];
                for (int f = 0; f < fs; f++)
                {
                    double normalized = dInput[off + f] * invRms;
                    dGradGamma[f] += dGradOut[off + f] * normalized;
                }
            }

            Parallel.For(0, batchSize, b =>
            {
                int off = b * fs;
                double invRms = 1.0 / dRms[b];
                double sumCorrection = 0.0;
                for (int f = 0; f < fs; f++)
                {
                    double scaledGrad = dGamma[f] * dGradOut[off + f];
                    double normalized = dInput[off + f] * invRms;
                    sumCorrection += scaledGrad * normalized;
                }
                double meanCorrection = sumCorrection * invFeatureSizeD;
                for (int f = 0; f < fs; f++)
                {
                    double scaledGrad = dGamma[f] * dGradOut[off + f];
                    double normalized = dInput[off + f] * invRms;
                    dGradInput[off + f] = invRms * (scaledGrad - normalized * meanCorrection);
                }
            });
        }
        else
        {
            for (int f = 0; f < featureSize; f++) gradGammaData[f] = numOps.Zero;

            for (int b = 0; b < batchSize; b++)
            {
                T invRms = numOps.Divide(numOps.One, rmsData[b]);
                for (int f = 0; f < featureSize; f++)
                {
                    T normalized = numOps.Multiply(inputData[b * featureSize + f], invRms);
                    gradGammaData[f] = numOps.Add(gradGammaData[f], numOps.Multiply(gradOutputData[b * featureSize + f], normalized));
                }
            }

            Parallel.For(0, batchSize, b =>
            {
                T invRms = numOps.Divide(numOps.One, rmsData[b]);
                T sumCorrection = numOps.Zero;
                for (int f = 0; f < featureSize; f++)
                {
                    T scaledGrad = numOps.Multiply(gammaData[f], gradOutputData[b * featureSize + f]);
                    T normalized = numOps.Multiply(inputData[b * featureSize + f], invRms);
                    sumCorrection = numOps.Add(sumCorrection, numOps.Multiply(scaledGrad, normalized));
                }
                T meanCorrection = numOps.Divide(sumCorrection, numOps.FromDouble(featureSize));
                for (int f = 0; f < featureSize; f++)
                {
                    T scaledGrad = numOps.Multiply(gammaData[f], gradOutputData[b * featureSize + f]);
                    T normalized = numOps.Multiply(inputData[b * featureSize + f], invRms);
                    gradInputData[b * featureSize + f] = numOps.Multiply(invRms, numOps.Subtract(scaledGrad, numOps.Multiply(normalized, meanCorrection)));
                }
            });
        }

        gradGamma = TensorAllocator.Rent<T>(gamma._shape, new Vector<T>(gradGammaData));
        return TensorAllocator.Rent<T>(input._shape, new Vector<T>(gradInputData));
    }

    #endregion

    #region Attention Operations

    /// <summary>
    /// Computes scaled dot-product attention.
    /// Attention(Q, K, V) = softmax(Q @ K^T / sqrt(d_k)) @ V
    /// From "Attention Is All You Need" (Vaswani et al., 2017)
    /// </summary>
    public Tensor<T> ScaledDotProductAttention<T>(
        Tensor<T> query,
        Tensor<T> key,
        Tensor<T> value,
        Tensor<bool>? mask,
        double? scale,
        out Tensor<T> attentionWeights)
    {
        using var _opScope = AiDotNet.Tensors.Engines.Profiling.Profiler.OpScope("ScaledDotProductAttention");
        if (query == null)
            throw new ArgumentNullException(nameof(query));
        if (key == null)
            throw new ArgumentNullException(nameof(key));
        if (value == null)
            throw new ArgumentNullException(nameof(value));

        // Preserve original Q/K/V refs for tape recording (#257). The
        // .Contiguous() rebinds below would otherwise replace the strided
        // views (typical post-Permute / post-Reshape) with fresh tensors
        // that have no GradFn — backward could no longer chain back to
        // the upstream parameters.
        var queryOrig = query;
        var keyOrig = key;
        var valueOrig = value;
        // Stride-aware: attention QKV often come from reshape+transpose views
        if (!value.IsContiguous) value = value.Contiguous();
        if (!query.IsContiguous) query = query.Contiguous();
        if (!key.IsContiguous) key = key.Contiguous();

        // Expected shapes: [batch, heads, seq, d_k] for Q, K and [batch, heads, seq, d_v] for V
        if (query.Rank != 4 || key.Rank != 4 || value.Rank != 4)
            throw new ArgumentException("Query, Key, and Value must be 4D tensors [batch, heads, seq, d_k/d_v]");

        var numOps = MathHelper.GetNumericOperations<T>();

        int batch = query._shape[0];
        int heads = query._shape[1];
        int seqQ = query._shape[2];
        int d_k = query._shape[3];
        int seqK = key._shape[2];
        int d_v = value._shape[3];

        // Validate shapes
        if (key._shape[0] != batch || key._shape[1] != heads || key._shape[3] != d_k)
            throw new ArgumentException("Key shape mismatch with Query");
        if (value._shape[0] != batch || value._shape[1] != heads || value._shape[2] != seqK)
            throw new ArgumentException("Value shape mismatch with Key");

        // Compute scale factor
        double scaleVal = scale ?? (1.0 / Math.Sqrt(d_k));

        // ────────────────────────────────────────────────────────────────────
        // Fast path for float: BLAS-backed batched GEMM per head.
        //
        // Replaces the scalar virtual-dispatch triple-loop that was dominating
        // DiT-XL forward wall clock (Issue #162). For DiT-XL at B=4, H=16,
        // seq=256, d_k=72, the old path ran ~75M virtual-dispatch FMAs per
        // SDPA call × 28 blocks = tens of seconds per forward; the BLAS path
        // executes the same FMAs as two batched SGEMMs (Q@K^T then P@V) per
        // head, parallel over batch*heads.
        //
        // The float path handles the 99% case. Double and other numeric types
        // fall through to the original scalar code below (preserves exact
        // existing behavior for generic T).
        // ────────────────────────────────────────────────────────────────────
        if (typeof(T) == typeof(float))
        {
            var resultF = ScaledDotProductAttentionFloat(
                (Tensor<float>)(object)query,
                (Tensor<float>)(object)key,
                (Tensor<float>)(object)value,
                mask, scaleVal,
                batch, heads, seqQ, d_k, seqK, d_v,
                out var weightsF);
            attentionWeights = (Tensor<T>)(object)weightsF;
            var resultFCast = (Tensor<T>)(object)resultF;
            DifferentiableOps.RecordIfActive("ScaledDotProductAttention", resultFCast,
                new[] { queryOrig, keyOrig, valueOrig },
                BackwardFunctions<T>.ScaledDotProductAttentionBackward,
                new object[] { attentionWeights, scaleVal });
            return resultFCast;
        }

        // Double-precision fast path mirrors the float version. Uses
        // MatrixMultiplyHelper.MultiplyBlocked as the GEMM kernel — the helper's
        // numOps.MultiplyAdd inner kernel dispatches to SimdKernels'
        // AVX2/FMA Vector256<double> path, so each per-head GEMM runs at SIMD
        // throughput instead of the scalar virtual-dispatch triple-loop the
        // generic-T fallback below would otherwise hit. For Pika21 / DiT-XL at
        // double precision this collapses ~75M scalar virtual FMAs per SDPA
        // call (× 24-28 blocks × 50 inference steps) into batched SIMD GEMMs.
        if (typeof(T) == typeof(double))
        {
            var resultD = ScaledDotProductAttentionDouble(
                (Tensor<double>)(object)query,
                (Tensor<double>)(object)key,
                (Tensor<double>)(object)value,
                mask, scaleVal,
                batch, heads, seqQ, d_k, seqK, d_v,
                out var weightsD);
            attentionWeights = (Tensor<T>)(object)weightsD;
            var resultDCast = (Tensor<T>)(object)resultD;
            DifferentiableOps.RecordIfActive("ScaledDotProductAttention", resultDCast,
                new[] { queryOrig, keyOrig, valueOrig },
                BackwardFunctions<T>.ScaledDotProductAttentionBackward,
                new object[] { attentionWeights, scaleVal });
            return resultDCast;
        }

        T scaleFactor = numOps.FromDouble(scaleVal);

        // Compute attention scores: Q @ K^T -> [batch, heads, seqQ, seqK]
        var scoresData = new T[batch * heads * seqQ * seqK];
        var queryData = query.GetFlattenedData();
        var keyData = key.GetFlattenedData();

        Parallel.For(0, batch * heads, bh =>
        {
            int qOffset = bh * seqQ * d_k;
            int kOffset = bh * seqK * d_k;
            int sOffset = bh * seqQ * seqK;

            for (int i = 0; i < seqQ; i++)
            {
                for (int j = 0; j < seqK; j++)
                {
                    T sum = numOps.Zero;
                    for (int k = 0; k < d_k; k++)
                    {
                        sum = numOps.Add(sum, numOps.Multiply(queryData[qOffset + i * d_k + k], keyData[kOffset + j * d_k + k]));
                    }
                    scoresData[sOffset + i * seqK + j] = numOps.Multiply(sum, scaleFactor);
                }
            }
        });

        // Apply mask (if provided) and softmax
        var weightsData = new T[batch * heads * seqQ * seqK];
        T negInf = numOps.FromDouble(double.NegativeInfinity);

        Parallel.For(0, batch * heads, bh =>
        {
            int b = bh / heads;
            int h = bh % heads;
            int offset = (b * heads + h) * seqQ * seqK;

            for (int i = 0; i < seqQ; i++)
            {
                // Apply mask and find max for numerical stability
                T maxVal = negInf;
                for (int j = 0; j < seqK; j++)
                {
                    int idx = offset + i * seqK + j;
                    if (mask != null && !mask[b, h, i, j])
                    {
                        scoresData[idx] = negInf;
                    }
                    if (numOps.GreaterThan(scoresData[idx], maxVal))
                    {
                        maxVal = scoresData[idx];
                    }
                }

                // Compute exp and sum
                T sumExp = numOps.Zero;
                for (int j = 0; j < seqK; j++)
                {
                    int idx = offset + i * seqK + j;
                    T expVal = numOps.Exp(numOps.Subtract(scoresData[idx], maxVal));
                    weightsData[idx] = expVal;
                    sumExp = numOps.Add(sumExp, expVal);
                }

                // Normalize
                for (int j = 0; j < seqK; j++)
                {
                    int idx = offset + i * seqK + j;
                    weightsData[idx] = numOps.Divide(weightsData[idx], sumExp);
                }
            }
        });

        attentionWeights = TensorAllocator.Rent<T>([batch, heads, seqQ, seqK], new Vector<T>(weightsData));

        // Compute output: weights @ V -> [batch, heads, seqQ, d_v]
        var outputData = new T[batch * heads * seqQ * d_v];
        var valueData = value.GetDataArray();

        Parallel.For(0, batch * heads, bh =>
        {
            int b = bh / heads;
            int h = bh % heads;
            int wOffset = (b * heads + h) * seqQ * seqK;
            int vOffset = (b * heads + h) * seqK * d_v;
            int oOffset = (b * heads + h) * seqQ * d_v;

            for (int i = 0; i < seqQ; i++)
            {
                for (int j = 0; j < d_v; j++)
                {
                    T sum = numOps.Zero;
                    for (int k = 0; k < seqK; k++)
                    {
                        sum = numOps.Add(sum, numOps.Multiply(weightsData[wOffset + i * seqK + k], valueData[vOffset + k * d_v + j]));
                    }
                    outputData[oOffset + i * d_v + j] = sum;
                }
            }
        });

        var resultGen = TensorAllocator.Rent<T>([batch, heads, seqQ, d_v], new Vector<T>(outputData));
        DifferentiableOps.RecordIfActive("ScaledDotProductAttention", resultGen,
            new[] { queryOrig, keyOrig, valueOrig },
            BackwardFunctions<T>.ScaledDotProductAttentionBackward,
            new object[] { attentionWeights, scaleVal });
        return resultGen;
    }

    /// <summary>
    /// BLAS-backed float-precision fast path for <see cref="ScaledDotProductAttention{T}"/>.
    /// Replaces the scalar virtual-dispatch triple-loop with two batched SGEMMs per head
    /// (Q·K^T then P·V), parallelized across batch*heads. Expected to collapse the
    /// DiT-XL SDPA wall clock from tens of seconds to tens of milliseconds per forward
    /// pass (Issue #162).
    /// </summary>
    private Tensor<float> ScaledDotProductAttentionFloat(
        Tensor<float> query,
        Tensor<float> key,
        Tensor<float> value,
        Tensor<bool>? mask,
        double scaleValue,
        int batch, int heads, int seqQ, int d_k, int seqK, int d_v,
        out Tensor<float> attentionWeights)
    {
        int bhCount = batch * heads;
        var qf = query.GetFlattenedData();
        var kf = key.GetFlattenedData();
        var vf = value.GetDataArray();

        // scoresData is internal scratch — reused between the QK^T and softmax
        // steps within each call and never escapes this method. Rent from
        // ArrayPool to amortize the ~16 MB allocation over many calls on the
        // DiT-XL hot path (28 SDPA calls per forward × ~16 MB = 448 MB of raw
        // allocation saved per forward).
        //
        // weightsData and outputData are returned to the caller via
        // attentionWeights + the return tensor, so they must stay independently
        // allocated. Caller owns the array lifetime after this returns.
        int scoresLen = bhCount * seqQ * seqK;
        var scoresData = System.Buffers.ArrayPool<float>.Shared.Rent(scoresLen);
        try
        {
        var weightsData = new float[scoresLen];
        var outputData = new float[bhCount * seqQ * d_v];

        float scaleF  = (float)scaleValue;
        float negInfF = float.NegativeInfinity;

        // Process each batch-head slice in parallel. Each slice is two independent
        // SGEMMs separated by a softmax pass. The individual SGEMMs are sized well
        // above BLAS's 4096-FMA threshold for typical MHA (seqQ*seqK*d_k = 4.7M for
        // DiT-XL per-head), so each head's GEMM hits either MKL or our blocked AVX2
        // kernel — not the scalar fallback.
        Parallel.For(0, bhCount, bh =>
        {
            int b = bh / heads;
            int h = bh % heads;

            int qOff = bh * seqQ * d_k;
            int kOff = bh * seqK * d_k;
            int sOff = bh * seqQ * seqK;

            // ──── Step 1: scores = Q @ K^T, via BLAS TryGemmEx with transB=true.
            // If TryGemmEx is unavailable (deterministic mode, MKL absent), fall back
            // to pre-transposing K and calling SimdGemm.Sgemm.
            bool gemmed = BlasProvider.TryGemmEx(
                m: seqQ, n: seqK, k: d_k,
                a: qf, aOffset: qOff, lda: d_k, transA: false,
                b: kf, bOffset: kOff, ldb: d_k, transB: true,
                c: scoresData, cOffset: sOff, ldc: seqK);
            if (!gemmed)
            {
                // Manual K^T for this head, then SimdGemm (AVX2 blocked).
                var kt = System.Buffers.ArrayPool<float>.Shared.Rent(d_k * seqK);
                try
                {
                    for (int i = 0; i < seqK; i++)
                        for (int j = 0; j < d_k; j++)
                            kt[j * seqK + i] = kf[kOff + i * d_k + j];
                    // SgemmSequential: we're already inside Parallel.For(bhCount), so
                    // forcing the inner SIMD kernel to run sequential avoids
                    // bhCount × maxThreads workers on (maxThreads) cores.
                    Engines.Simd.SimdGemm.SgemmSequential(
                        qf.AsSpan(qOff, seqQ * d_k),
                        kt.AsSpan(0, d_k * seqK),
                        scoresData.AsSpan(sOff, seqQ * seqK),
                        seqQ, d_k, seqK);
                }
                finally { System.Buffers.ArrayPool<float>.Shared.Return(kt); }
            }

            // ──── Step 2: fused scale + mask + numerically-stable softmax,
            // row-wise over the [seqQ, seqK] scores matrix for this head.
            for (int i = 0; i < seqQ; i++)
            {
                int rowOff = sOff + i * seqK;
                // First pass: scale in-place, mask, and find row max.
                float maxVal = negInfF;
                for (int j = 0; j < seqK; j++)
                {
                    float v = scoresData[rowOff + j] * scaleF;
                    if (mask != null && !mask[b, h, i, j]) v = negInfF;
                    if (v > maxVal) maxVal = v;
                    scoresData[rowOff + j] = v;
                }
                // Second pass: exp(v - max), sum.
                // Edge case: if the entire row was masked out, maxVal is still -Infinity.
                // (scores - (-Inf)) == +Inf; MathF.Exp(+Inf) == +Inf; normalizing produces
                // NaN. Detect that case up front and emit an all-zero softmax row, which
                // is the sensible behavior (no attention anywhere → no value flows).
                if (float.IsNegativeInfinity(maxVal))
                {
                    for (int j = 0; j < seqK; j++)
                        weightsData[rowOff + j] = 0f;
                    continue;
                }

                float sumExp = 0f;
                for (int j = 0; j < seqK; j++)
                {
                    float e = MathF.Exp(scoresData[rowOff + j] - maxVal);
                    weightsData[rowOff + j] = e;
                    sumExp += e;
                }
                // Third pass: normalize. Use 1/sumExp to turn N divides into N muls.
                float inv = sumExp != 0f ? 1f / sumExp : 0f;
                for (int j = 0; j < seqK; j++)
                    weightsData[rowOff + j] *= inv;
            }

            // ──── Step 3: output = weights @ V, via BLAS (no transpose).
            int wOff = bh * seqQ * seqK;
            int vOff = bh * seqK * d_v;
            int oOff = bh * seqQ * d_v;
            bool gemmed2 = BlasProvider.TryGemmEx(
                m: seqQ, n: d_v, k: seqK,
                a: weightsData, aOffset: wOff, lda: seqK, transA: false,
                b: vf, bOffset: vOff, ldb: d_v, transB: false,
                c: outputData, cOffset: oOff, ldc: d_v);
            if (!gemmed2)
            {
                Engines.Simd.SimdGemm.SgemmSequential(
                    weightsData.AsSpan(wOff, seqQ * seqK),
                    vf.AsSpan(vOff, seqK * d_v),
                    outputData.AsSpan(oOff, seqQ * d_v),
                    seqQ, seqK, d_v);
            }
        });

        // Return strongly typed Tensor<float> (no generic cast). Caller bridges
        // to the outer Tensor<T> via a single (Tensor<T>)(object) cast at the
        // call site, keeping this method's contract explicit about the fact
        // that it's float-only.
        attentionWeights = TensorAllocator.Rent<float>(
            new[] { batch, heads, seqQ, seqK },
            new Vector<float>(weightsData));
        return TensorAllocator.Rent<float>(
            new[] { batch, heads, seqQ, d_v },
            new Vector<float>(outputData));
        }
        finally
        {
            // scoresData was rented from ArrayPool — return it regardless of success.
            // clearArray:false because the scratch doesn't leak data (we overwrite
            // every slot in the next rental) and clearing a 16 MB buffer would
            // undo the allocation savings.
            System.Buffers.ArrayPool<float>.Shared.Return(scoresData, clearArray: false);
        }
    }

    /// <summary>
    /// SIMD-backed double-precision fast path for <see cref="ScaledDotProductAttention{T}"/>.
    /// Replaces the scalar virtual-dispatch triple-loop with two SIMD-blocked DGEMMs per head
    /// (Q·K^T then P·V), parallelized across batch*heads. Uses
    /// <see cref="MatrixMultiplyHelper.MultiplyBlocked"/> as the kernel because BlasProvider
    /// is disabled and SimdGemm only ships an Sgemm path; MultiplyBlocked's inner
    /// numOps.MultiplyAdd dispatches to SimdKernels' AVX2/FMA Vector256&lt;double&gt; kernel.
    /// <para>
    /// Mirrors the structure of <see cref="ScaledDotProductAttentionFloat"/> exactly so the
    /// two paths stay easy to keep in sync. The K^T transpose is materialized into a per-head
    /// scratch buffer because MultiplyBlocked has no transposed-B variant.
    /// </para>
    /// </summary>
    private Tensor<double> ScaledDotProductAttentionDouble(
        Tensor<double> query,
        Tensor<double> key,
        Tensor<double> value,
        Tensor<bool>? mask,
        double scaleValue,
        int batch, int heads, int seqQ, int d_k, int seqK, int d_v,
        out Tensor<double> attentionWeights)
    {
        int bhCount = batch * heads;
        // Use the stride-aware accessor on all three operands for consistency.
        // Contiguous() was already called on the public entry point, so the
        // three calls return identical data today — but keeping them on the
        // same accessor guards against divergence if the contract ever changes
        // or a future caller forgets the contiguity contract.
        var qd = query.GetFlattenedData();
        var kd = key.GetFlattenedData();
        var vd = value.GetFlattenedData();
        var doubleOps = MathHelper.GetNumericOperations<double>();

        // scoresData is internal scratch — rent from ArrayPool to amortize the
        // per-call allocation across the SDPA hot path (24-28 calls per DiT
        // forward × 50 inference steps).
        int scoresLen = bhCount * seqQ * seqK;
        var scoresData = System.Buffers.ArrayPool<double>.Shared.Rent(scoresLen);
        try
        {
            var weightsData = new double[scoresLen];
            var outputData = new double[bhCount * seqQ * d_v];
            double negInfD = double.NegativeInfinity;

            Parallel.For(0, bhCount, bh =>
            {
                int b = bh / heads;
                int h = bh % heads;
                int qOff = bh * seqQ * d_k;
                int kOff = bh * seqK * d_k;
                int sOff = bh * seqQ * seqK;

                // ──── Step 1: scores = Q @ K^T.
                // MultiplyBlocked has no transposed-B variant, so materialize K^T
                // into a per-head scratch buffer rented from ArrayPool. allowParallel:
                // false because we're already inside Parallel.For(bhCount).
                var kt = System.Buffers.ArrayPool<double>.Shared.Rent(d_k * seqK);
                try
                {
                    for (int i = 0; i < seqK; i++)
                        for (int j = 0; j < d_k; j++)
                            kt[j * seqK + i] = kd[kOff + i * d_k + j];

                    var scoresSlice = new Memory<double>(scoresData, sOff, seqQ * seqK);
                    scoresSlice.Span.Clear();
                    MatrixMultiplyHelper.MultiplyBlocked(
                        doubleOps,
                        new ReadOnlyMemory<double>(qd, qOff, seqQ * d_k),
                        new ReadOnlyMemory<double>(kt, 0, d_k * seqK),
                        scoresSlice,
                        seqQ, d_k, seqK,
                        d_k, seqK, seqK,
                        allowParallel: false);
                }
                finally { System.Buffers.ArrayPool<double>.Shared.Return(kt, clearArray: false); }

                // ──── Step 2: fused scale + mask + numerically-stable softmax.
                for (int i = 0; i < seqQ; i++)
                {
                    int rowOff = sOff + i * seqK;
                    double maxVal = negInfD;
                    for (int j = 0; j < seqK; j++)
                    {
                        double v = scoresData[rowOff + j] * scaleValue;
                        if (mask != null && !mask[b, h, i, j]) v = negInfD;
                        if (v > maxVal) maxVal = v;
                        scoresData[rowOff + j] = v;
                    }
                    if (double.IsNegativeInfinity(maxVal))
                    {
                        for (int j = 0; j < seqK; j++)
                            weightsData[rowOff + j] = 0d;
                        continue;
                    }
                    double sumExp = 0d;
                    for (int j = 0; j < seqK; j++)
                    {
                        double e = Math.Exp(scoresData[rowOff + j] - maxVal);
                        weightsData[rowOff + j] = e;
                        sumExp += e;
                    }
                    double inv = sumExp != 0d ? 1d / sumExp : 0d;
                    for (int j = 0; j < seqK; j++)
                        weightsData[rowOff + j] *= inv;
                }

                // ──── Step 3: output = weights @ V (no transpose).
                int wOff = bh * seqQ * seqK;
                int vOff = bh * seqK * d_v;
                int oOff = bh * seqQ * d_v;
                var outSlice = new Memory<double>(outputData, oOff, seqQ * d_v);
                outSlice.Span.Clear();
                MatrixMultiplyHelper.MultiplyBlocked(
                    doubleOps,
                    new ReadOnlyMemory<double>(weightsData, wOff, seqQ * seqK),
                    new ReadOnlyMemory<double>(vd, vOff, seqK * d_v),
                    outSlice,
                    seqQ, seqK, d_v,
                    seqK, d_v, d_v,
                    allowParallel: false);
            });

            attentionWeights = TensorAllocator.Rent<double>(
                new[] { batch, heads, seqQ, seqK },
                new Vector<double>(weightsData));
            return TensorAllocator.Rent<double>(
                new[] { batch, heads, seqQ, d_v },
                new Vector<double>(outputData));
        }
        finally
        {
            System.Buffers.ArrayPool<double>.Shared.Return(scoresData, clearArray: false);
        }
    }

    /// <summary>
    /// Computes the backward pass for scaled dot-product attention.
    /// </summary>
    public Tensor<T> ScaledDotProductAttentionBackward<T>(
        Tensor<T> gradOutput,
        Tensor<T> query,
        Tensor<T> key,
        Tensor<T> value,
        Tensor<T> attentionWeights,
        double scale,
        out Tensor<T> gradQuery,
        out Tensor<T> gradKey,
        out Tensor<T> gradValue)
    {
        if (gradOutput == null)
            throw new ArgumentNullException(nameof(gradOutput));
        if (query == null)
            throw new ArgumentNullException(nameof(query));
        if (key == null)
            throw new ArgumentNullException(nameof(key));
        if (value == null)
            throw new ArgumentNullException(nameof(value));
        if (attentionWeights == null)
            throw new ArgumentNullException(nameof(attentionWeights));

        var numOps = MathHelper.GetNumericOperations<T>();

        int batch = query._shape[0];
        int heads = query._shape[1];
        int seqQ = query._shape[2];
        int d_k = query._shape[3];
        int seqK = key._shape[2];
        int d_v = value._shape[3];

        // ────────────────────────────────────────────────────────────────────
        // Fast path for float: BLAS-backed batched GEMMs, mirror of the SDPA
        // forward fix (commit cd954be, Issue #162).
        //
        // The four matmul-shaped steps (gradV = W^T·gradOut, gradW = gradOut·V^T,
        // gradQ = gradScores·K, gradK = gradScores^T·Q) are individually sized
        // well above BLAS's 4096-FMA threshold for typical MHA, so each head
        // runs through either MKL or our blocked AVX2 kernel. The softmax
        // backward (gradScores = W·(gradW − row_dot)) stays in managed float
        // arithmetic — it's a row-wise elementwise pass with trivial arithmetic
        // intensity, no BLAS.
        //
        // Expected speedup matches the forward fix (~3.7× at DiT-XL shapes).
        // Non-primitive T (complex, Half, int, etc.) continues through the
        // original scalar path below. float and double both get primitive-typed
        // fast paths that skip INumericOperations<T>'s virtual dispatch.
        // ────────────────────────────────────────────────────────────────────
        if (typeof(T) == typeof(float))
        {
            var gradOutF = (Tensor<float>)(object)gradOutput;
            var gradQF = ScaledDotProductAttentionBackwardFloat(
                gradOutF,
                (Tensor<float>)(object)query,
                (Tensor<float>)(object)key,
                (Tensor<float>)(object)value,
                (Tensor<float>)(object)attentionWeights,
                scale,
                batch, heads, seqQ, d_k, seqK, d_v,
                out var gradKF, out var gradVF);
            gradQuery = (Tensor<T>)(object)gradQF;
            gradKey = (Tensor<T>)(object)gradKF;
            gradValue = (Tensor<T>)(object)gradVF;
            return gradOutput;
        }
        if (typeof(T) == typeof(double))
        {
            var gradOutD = (Tensor<double>)(object)gradOutput;
            var gradQD = ScaledDotProductAttentionBackwardDouble(
                gradOutD,
                (Tensor<double>)(object)query,
                (Tensor<double>)(object)key,
                (Tensor<double>)(object)value,
                (Tensor<double>)(object)attentionWeights,
                scale,
                batch, heads, seqQ, d_k, seqK, d_v,
                out var gradKD, out var gradVD);
            gradQuery = (Tensor<T>)(object)gradQD;
            gradKey = (Tensor<T>)(object)gradKD;
            gradValue = (Tensor<T>)(object)gradVD;
            return gradOutput;
        }

        T scaleFactor = numOps.FromDouble(scale);

        var gradOutData = gradOutput.GetFlattenedData();
        var queryData = query.GetFlattenedData();
        var keyData = key.GetFlattenedData();
        var valueData = value.GetFlattenedData();
        var weightsData = attentionWeights.GetDataArray();

        var gradVData = new T[batch * heads * seqK * d_v];
        var gradQData = new T[batch * heads * seqQ * d_k];
        var gradKData = new T[batch * heads * seqK * d_k];

        Parallel.For(0, batch * heads, bh =>
        {
            int b = bh / heads;
            int h = bh % heads;
            int wOffset = (b * heads + h) * seqQ * seqK;
            int gOffset = (b * heads + h) * seqQ * d_v;
            int vOffset = (b * heads + h) * seqK * d_v;
            int qOffset = (b * heads + h) * seqQ * d_k;
            int kOffset = (b * heads + h) * seqK * d_k;

            // Gradient w.r.t. V: weights^T @ gradOutput
            for (int i = 0; i < seqK; i++)
            {
                for (int j = 0; j < d_v; j++)
                {
                    T sum = numOps.Zero;
                    for (int k = 0; k < seqQ; k++)
                    {
                        sum = numOps.Add(sum, numOps.Multiply(weightsData[wOffset + k * seqK + i], gradOutData[gOffset + k * d_v + j]));
                    }
                    gradVData[vOffset + i * d_v + j] = sum;
                }
            }

            // Gradient w.r.t. attention weights: gradOutput @ V^T
            var gradWeights = new T[seqQ * seqK];
            for (int i = 0; i < seqQ; i++)
            {
                for (int j = 0; j < seqK; j++)
                {
                    T sum = numOps.Zero;
                    for (int k = 0; k < d_v; k++)
                    {
                        sum = numOps.Add(sum, numOps.Multiply(gradOutData[gOffset + i * d_v + k], valueData[vOffset + j * d_v + k]));
                    }
                    gradWeights[i * seqK + j] = sum;
                }
            }

            // Softmax backward: gradScores = weights * (gradWeights - sum(weights * gradWeights))
            var gradScores = new T[seqQ * seqK];
            for (int i = 0; i < seqQ; i++)
            {
                T dotProduct = numOps.Zero;
                for (int j = 0; j < seqK; j++)
                {
                    dotProduct = numOps.Add(dotProduct, numOps.Multiply(weightsData[wOffset + i * seqK + j], gradWeights[i * seqK + j]));
                }
                for (int j = 0; j < seqK; j++)
                {
                    T w = weightsData[wOffset + i * seqK + j];
                    gradScores[i * seqK + j] = numOps.Multiply(w, numOps.Subtract(gradWeights[i * seqK + j], dotProduct));
                }
            }

            // Gradient w.r.t. Q: gradScores @ K * scale
            for (int i = 0; i < seqQ; i++)
            {
                for (int j = 0; j < d_k; j++)
                {
                    T sum = numOps.Zero;
                    for (int k = 0; k < seqK; k++)
                    {
                        sum = numOps.Add(sum, numOps.Multiply(gradScores[i * seqK + k], keyData[kOffset + k * d_k + j]));
                    }
                    gradQData[qOffset + i * d_k + j] = numOps.Multiply(sum, scaleFactor);
                }
            }

            // Gradient w.r.t. K: gradScores^T @ Q * scale
            for (int i = 0; i < seqK; i++)
            {
                for (int j = 0; j < d_k; j++)
                {
                    T sum = numOps.Zero;
                    for (int k = 0; k < seqQ; k++)
                    {
                        sum = numOps.Add(sum, numOps.Multiply(gradScores[k * seqK + i], queryData[qOffset + k * d_k + j]));
                    }
                    gradKData[kOffset + i * d_k + j] = numOps.Multiply(sum, scaleFactor);
                }
            }
        });

        gradQuery = TensorAllocator.Rent<T>(query._shape, new Vector<T>(gradQData));
        gradKey = TensorAllocator.Rent<T>(key._shape, new Vector<T>(gradKData));
        gradValue = TensorAllocator.Rent<T>(value._shape, new Vector<T>(gradVData));

        return gradOutput;
    }

    /// <summary>
    /// Float-only fast path for <see cref="ScaledDotProductAttentionBackward{T}"/>.
    /// Counterpart to <see cref="ScaledDotProductAttentionFloat"/> — replaces the
    /// generic method's scalar INumericOperations-dispatch triple-loops with four
    /// BLAS SGEMMs per head plus a row-wise softmax-backward pass in managed float.
    /// </summary>
    /// <remarks>
    /// <para><b>Layout:</b> Q/K/V/gradOut/weights are in row-major [B, H, seq, d] layout.
    /// Within each (b, h) slice the helper issues four GEMMs plus one elementwise
    /// softmax-backward pass.</para>
    /// <para><b>Why separate from the forward helper:</b> the forward goes
    /// Q·K^T → softmax → P·V (two GEMMs + softmax). The backward goes
    /// gradV = W^T·gradOut, gradW = gradOut·V^T, softmax-bwd, gradQ = gradScores·K,
    /// gradK = gradScores^T·Q — four GEMMs with different transpose combos. Keeping
    /// them in one method would hide which step does what.</para>
    /// <para><b>Scale application:</b> the forward bakes sqrt(d_k) into the scores
    /// before softmax; for backward, the scale propagates through softmax to gradQ
    /// and gradK (but NOT through gradV — V's gradient doesn't see the scale).
    /// We multiply gradScores by scaleF before the gradQ/gradK GEMMs. One broadcast
    /// scale per head is negligible compared to the GEMMs.</para>
    /// </remarks>
    private Tensor<float> ScaledDotProductAttentionBackwardFloat(
        Tensor<float> gradOutput,
        Tensor<float> query,
        Tensor<float> key,
        Tensor<float> value,
        Tensor<float> attentionWeights,
        double scaleValue,
        int batch, int heads, int seqQ, int d_k, int seqK, int d_v,
        out Tensor<float> gradKey,
        out Tensor<float> gradValue)
    {
        int bhCount = batch * heads;
        var gradOutF = gradOutput.GetFlattenedData();
        var qF = query.GetFlattenedData();
        var kF = key.GetFlattenedData();
        var vF = value.GetFlattenedData();
        var wF = attentionWeights.GetDataArray();

        var gradQData = new float[batch * heads * seqQ * d_k];
        var gradKData = new float[batch * heads * seqK * d_k];
        var gradVData = new float[batch * heads * seqK * d_v];

        float scaleF = (float)scaleValue;

        // Per-head scratch for gradWeights (seqQ × seqK). Rent from the pool —
        // the upper bound is ~1 MB per head at DiT-XL shapes; renting keeps
        // Parallel.For from churning the GC for each of bhCount workers.
        int scratchLen = seqQ * seqK;

        Parallel.For(0, bhCount, bh =>
        {
            int wOff = bh * seqQ * seqK;
            int gOff = bh * seqQ * d_v;
            int qOff = bh * seqQ * d_k;
            int kOff = bh * seqK * d_k;
            int vOff = bh * seqK * d_v;

            // Step 1: gradV[seqK, d_v] = W^T[seqK, seqQ] @ gradOut[seqQ, d_v]
            // Row-major Gemm: m=seqK, n=d_v, k=seqQ. A = weights viewed as
            // [seqQ, seqK] with transA=true (so effectively [seqK, seqQ]).
            // lda is the *original* row stride of A (seqK, since weights is
            // stored row-major [seqQ, seqK]).
            bool gemmedV = BlasProvider.TryGemmEx(
                m: seqK, n: d_v, k: seqQ,
                a: wF, aOffset: wOff, lda: seqK, transA: true,
                b: gradOutF, bOffset: gOff, ldb: d_v, transB: false,
                c: gradVData, cOffset: vOff, ldc: d_v);
            if (!gemmedV)
            {
                // SimdGemm has no built-in transA support — transpose weights
                // into scratch, then regular SGEMM.
                var wT = System.Buffers.ArrayPool<float>.Shared.Rent(seqK * seqQ);
                try
                {
                    for (int i = 0; i < seqQ; i++)
                        for (int j = 0; j < seqK; j++)
                            wT[j * seqQ + i] = wF[wOff + i * seqK + j];
                    Engines.Simd.SimdGemm.SgemmSequential(
                        wT.AsSpan(0, seqK * seqQ),
                        gradOutF.AsSpan(gOff, seqQ * d_v),
                        gradVData.AsSpan(vOff, seqK * d_v),
                        seqK, seqQ, d_v);
                }
                finally { System.Buffers.ArrayPool<float>.Shared.Return(wT); }
            }

            // Step 2: gradWeights[seqQ, seqK] = gradOut[seqQ, d_v] @ V^T[d_v, seqK]
            // m=seqQ, n=seqK, k=d_v. B = value with transB=true; ldb is value's
            // original row stride (d_v).
            var gradWeights = System.Buffers.ArrayPool<float>.Shared.Rent(scratchLen);
            try
            {
                bool gemmedW = BlasProvider.TryGemmEx(
                    m: seqQ, n: seqK, k: d_v,
                    a: gradOutF, aOffset: gOff, lda: d_v, transA: false,
                    b: vF, bOffset: vOff, ldb: d_v, transB: true,
                    c: gradWeights, cOffset: 0, ldc: seqK);
                if (!gemmedW)
                {
                    var vT = System.Buffers.ArrayPool<float>.Shared.Rent(d_v * seqK);
                    try
                    {
                        for (int i = 0; i < seqK; i++)
                            for (int j = 0; j < d_v; j++)
                                vT[j * seqK + i] = vF[vOff + i * d_v + j];
                        Engines.Simd.SimdGemm.SgemmSequential(
                            gradOutF.AsSpan(gOff, seqQ * d_v),
                            vT.AsSpan(0, d_v * seqK),
                            gradWeights.AsSpan(0, seqQ * seqK),
                            seqQ, d_v, seqK);
                    }
                    finally { System.Buffers.ArrayPool<float>.Shared.Return(vT); }
                }

                // Step 3: softmax backward — row-wise. gradScores = W * (gradW - dot),
                // where dot = sum_j(W[i,j] * gradW[i,j]) is the per-row inner product.
                // We write gradScores in-place into gradWeights then premultiply by
                // scaleF since both gradQ and gradK use gradScores·scale. Scaling
                // once here avoids two elementwise passes after the GEMMs.
                for (int i = 0; i < seqQ; i++)
                {
                    int rowOff = i * seqK;
                    int wRow = wOff + rowOff;
                    float dotProduct = 0f;
                    for (int j = 0; j < seqK; j++)
                        dotProduct += wF[wRow + j] * gradWeights[rowOff + j];
                    for (int j = 0; j < seqK; j++)
                    {
                        float w = wF[wRow + j];
                        gradWeights[rowOff + j] = scaleF * w * (gradWeights[rowOff + j] - dotProduct);
                    }
                }

                // Step 4: gradQ[seqQ, d_k] = gradScores[seqQ, seqK] @ K[seqK, d_k]
                // (scale already folded into gradScores).
                bool gemmedQ = BlasProvider.TryGemmEx(
                    m: seqQ, n: d_k, k: seqK,
                    a: gradWeights, aOffset: 0, lda: seqK, transA: false,
                    b: kF, bOffset: kOff, ldb: d_k, transB: false,
                    c: gradQData, cOffset: qOff, ldc: d_k);
                if (!gemmedQ)
                {
                    Engines.Simd.SimdGemm.SgemmSequential(
                        gradWeights.AsSpan(0, seqQ * seqK),
                        kF.AsSpan(kOff, seqK * d_k),
                        gradQData.AsSpan(qOff, seqQ * d_k),
                        seqQ, seqK, d_k);
                }

                // Step 5: gradK[seqK, d_k] = gradScores^T[seqK, seqQ] @ Q[seqQ, d_k]
                bool gemmedK = BlasProvider.TryGemmEx(
                    m: seqK, n: d_k, k: seqQ,
                    a: gradWeights, aOffset: 0, lda: seqK, transA: true,
                    b: qF, bOffset: qOff, ldb: d_k, transB: false,
                    c: gradKData, cOffset: kOff, ldc: d_k);
                if (!gemmedK)
                {
                    var sT = System.Buffers.ArrayPool<float>.Shared.Rent(seqK * seqQ);
                    try
                    {
                        for (int i = 0; i < seqQ; i++)
                            for (int j = 0; j < seqK; j++)
                                sT[j * seqQ + i] = gradWeights[i * seqK + j];
                        Engines.Simd.SimdGemm.SgemmSequential(
                            sT.AsSpan(0, seqK * seqQ),
                            qF.AsSpan(qOff, seqQ * d_k),
                            gradKData.AsSpan(kOff, seqK * d_k),
                            seqK, seqQ, d_k);
                    }
                    finally { System.Buffers.ArrayPool<float>.Shared.Return(sT); }
                }
            }
            finally { System.Buffers.ArrayPool<float>.Shared.Return(gradWeights, clearArray: false); }
        });

        gradValue = TensorAllocator.Rent<float>(value._shape, new Vector<float>(gradVData));
        gradKey = TensorAllocator.Rent<float>(key._shape, new Vector<float>(gradKData));
        return TensorAllocator.Rent<float>(query._shape, new Vector<float>(gradQData));
    }

    /// <summary>
    /// Double-only fast path for <see cref="ScaledDotProductAttentionBackward{T}"/>.
    /// Same structure as <see cref="ScaledDotProductAttentionBackwardFloat"/>, but
    /// uses <see cref="Im2ColHelper.MultiplyMatrixBlockedDouble"/> instead of
    /// <see cref="Simd.SimdGemm.SgemmSequential"/> for the four matmul steps.
    /// Direct double arithmetic in the softmax-backward pass replaces the
    /// <see cref="INumericOperations{T}"/> virtual dispatch.
    /// </summary>
    /// <remarks>
    /// <para>Double-precision consumers (scientific workloads, any code that
    /// constructs tensors with <c>T = double</c>) were on the scalar path
    /// before this — every SDPA backward call walked 4 triple-nested loops
    /// via virtual dispatch. Now the dispatch cost is paid once per op
    /// and the inner arithmetic goes direct-double, which the JIT can
    /// auto-vectorize for the softmax-backward row sweep.</para>
    /// <para>No double equivalent of <c>BlasProvider.TryGemmEx</c> exists,
    /// so the transposed GEMMs always pre-transpose into scratch and call
    /// the blocked kernel. That matches what the float path does when
    /// <c>TryGemmEx</c> returns false.</para>
    /// </remarks>
    private Tensor<double> ScaledDotProductAttentionBackwardDouble(
        Tensor<double> gradOutput,
        Tensor<double> query,
        Tensor<double> key,
        Tensor<double> value,
        Tensor<double> attentionWeights,
        double scaleValue,
        int batch, int heads, int seqQ, int d_k, int seqK, int d_v,
        out Tensor<double> gradKey,
        out Tensor<double> gradValue)
    {
        int bhCount = batch * heads;
        var gradOutD = gradOutput.GetFlattenedData();
        var qD = query.GetFlattenedData();
        var kD = key.GetFlattenedData();
        var vD = value.GetFlattenedData();
        var wD = attentionWeights.GetDataArray();

        var gradQData = new double[batch * heads * seqQ * d_k];
        var gradKData = new double[batch * heads * seqK * d_k];
        var gradVData = new double[batch * heads * seqK * d_v];

        int scratchLen = seqQ * seqK;

        Parallel.For(0, bhCount, bh =>
        {
            int wOff = bh * seqQ * seqK;
            int gOff = bh * seqQ * d_v;
            int qOff = bh * seqQ * d_k;
            int kOff = bh * seqK * d_k;
            int vOff = bh * seqK * d_v;

            // Step 1: gradV[seqK, d_v] = W^T[seqK, seqQ] @ gradOut[seqQ, d_v]
            // MultiplyMatrixBlockedDouble doesn't support transA, so transpose W
            // into scratch first. Same fallback pattern the float path takes
            // when TryGemmEx is unavailable.
            var wT = System.Buffers.ArrayPool<double>.Shared.Rent(seqK * seqQ);
            try
            {
                for (int i = 0; i < seqQ; i++)
                    for (int j = 0; j < seqK; j++)
                        wT[j * seqQ + i] = wD[wOff + i * seqK + j];
                Helpers.Im2ColHelper.MultiplyMatrixBlockedDouble(
                    wT.AsSpan(0, seqK * seqQ),
                    gradOutD.AsSpan(gOff, seqQ * d_v),
                    gradVData.AsSpan(vOff, seqK * d_v),
                    seqK, seqQ, d_v);
            }
            finally { System.Buffers.ArrayPool<double>.Shared.Return(wT); }

            var gradWeights = System.Buffers.ArrayPool<double>.Shared.Rent(scratchLen);
            try
            {
                // Defensive zero of the rented region. MultiplyMatrixBlockedDouble
                // today clears its `c` span internally, but an explicit clear here
                // keeps this site correct if the helper ever gains accumulate-mode
                // semantics (e.g. a beta-style BLAS variant). Cheap: O(seqQ*seqK).
                gradWeights.AsSpan(0, scratchLen).Clear();

                // Step 2: gradWeights[seqQ, seqK] = gradOut[seqQ, d_v] @ V^T[d_v, seqK]
                var vT = System.Buffers.ArrayPool<double>.Shared.Rent(d_v * seqK);
                try
                {
                    for (int i = 0; i < seqK; i++)
                        for (int j = 0; j < d_v; j++)
                            vT[j * seqK + i] = vD[vOff + i * d_v + j];
                    Helpers.Im2ColHelper.MultiplyMatrixBlockedDouble(
                        gradOutD.AsSpan(gOff, seqQ * d_v),
                        vT.AsSpan(0, d_v * seqK),
                        gradWeights.AsSpan(0, seqQ * seqK),
                        seqQ, d_v, seqK);
                }
                finally { System.Buffers.ArrayPool<double>.Shared.Return(vT); }

                // Step 3: softmax backward row-wise, scale folded in (same as float path).
                for (int i = 0; i < seqQ; i++)
                {
                    int rowOff = i * seqK;
                    int wRow = wOff + rowOff;
                    double dotProduct = 0.0;
                    for (int j = 0; j < seqK; j++)
                        dotProduct += wD[wRow + j] * gradWeights[rowOff + j];
                    for (int j = 0; j < seqK; j++)
                    {
                        double w = wD[wRow + j];
                        gradWeights[rowOff + j] = scaleValue * w * (gradWeights[rowOff + j] - dotProduct);
                    }
                }

                // Step 4: gradQ[seqQ, d_k] = gradScores[seqQ, seqK] @ K[seqK, d_k]
                Helpers.Im2ColHelper.MultiplyMatrixBlockedDouble(
                    gradWeights.AsSpan(0, seqQ * seqK),
                    kD.AsSpan(kOff, seqK * d_k),
                    gradQData.AsSpan(qOff, seqQ * d_k),
                    seqQ, seqK, d_k);

                // Step 5: gradK[seqK, d_k] = gradScores^T[seqK, seqQ] @ Q[seqQ, d_k]
                var sT = System.Buffers.ArrayPool<double>.Shared.Rent(seqK * seqQ);
                try
                {
                    for (int i = 0; i < seqQ; i++)
                        for (int j = 0; j < seqK; j++)
                            sT[j * seqQ + i] = gradWeights[i * seqK + j];
                    Helpers.Im2ColHelper.MultiplyMatrixBlockedDouble(
                        sT.AsSpan(0, seqK * seqQ),
                        qD.AsSpan(qOff, seqQ * d_k),
                        gradKData.AsSpan(kOff, seqK * d_k),
                        seqK, seqQ, d_k);
                }
                finally { System.Buffers.ArrayPool<double>.Shared.Return(sT); }
            }
            finally { System.Buffers.ArrayPool<double>.Shared.Return(gradWeights, clearArray: false); }
        });

        gradValue = TensorAllocator.Rent<double>(value._shape, new Vector<double>(gradVData));
        gradKey = TensorAllocator.Rent<double>(key._shape, new Vector<double>(gradKData));
        return TensorAllocator.Rent<double>(query._shape, new Vector<double>(gradQData));
    }

    /// <summary>
    /// Computes memory-efficient attention using the FlashAttention algorithm.
    /// </summary>
    /// <remarks>
    /// This is a CPU implementation of FlashAttention that uses tiling and online softmax
    /// to achieve O(N) memory complexity instead of O(N²) for standard attention.
    /// While the CPU version doesn't benefit as much from the memory hierarchy optimizations
    /// as GPU, it still provides memory savings for long sequences.
    /// </remarks>
    public Tensor<T> FlashAttention<T>(
        Tensor<T> query,
        Tensor<T> key,
        Tensor<T> value,
        double? scale,
        bool isCausal,
        out Tensor<T> softmaxStats,
        Tensor<T>? attentionBias = null)
    {
        if (query == null) throw new ArgumentNullException(nameof(query));
        if (key == null) throw new ArgumentNullException(nameof(key));
        if (value == null) throw new ArgumentNullException(nameof(value));

        var numOps = MathHelper.GetNumericOperations<T>();

        int batch = query._shape[0];
        int heads = query._shape[1];
        int seqQ = query._shape[2];
        int headDim = query._shape[3];
        int seqK = key._shape[2];

        // Validate bias shape *before* the float fast-path branch below. The
        // fast path (FlashAttentionFloat) trusts its caller to hand it a
        // correctly-shaped bias, so the rank/dimension check has to run here
        // or we silently accept malformed bias tensors on the float path.
        // (Regression exposed by FlashAttention_InvalidBiasRank_Throws +
        // FlashAttention_Mismatched{3D,}BiasDimensions_Throws after the fast
        // path was added.)
        bool biasBroadcastBatch = false;
        if (attentionBias is not null)
        {
            int biasRank = attentionBias._shape.Length;
            if (biasRank == 4)
            {
                if (attentionBias._shape[0] != batch || attentionBias._shape[1] != heads ||
                    attentionBias._shape[2] != seqQ || attentionBias._shape[3] != seqK)
                    throw new ArgumentException(
                        $"4D attention bias shape [{string.Join(",", attentionBias._shape)}] must match [batch={batch}, heads={heads}, seqQ={seqQ}, seqK={seqK}].",
                        nameof(attentionBias));
                biasBroadcastBatch = false;
            }
            else if (biasRank == 3)
            {
                if (attentionBias._shape[0] != heads || attentionBias._shape[1] != seqQ || attentionBias._shape[2] != seqK)
                    throw new ArgumentException(
                        $"3D attention bias shape [{string.Join(",", attentionBias._shape)}] must match [heads={heads}, seqQ={seqQ}, seqK={seqK}].",
                        nameof(attentionBias));
                biasBroadcastBatch = true;
            }
            else
            {
                throw new ArgumentException(
                    $"Attention bias must be rank 3 [heads, seqQ, seqK] or rank 4 [batch, heads, seqQ, seqK], got rank {biasRank}.",
                    nameof(attentionBias));
            }
        }

        // ────────────────────────────────────────────────────────────────────
        // Fast path for float: materialized-softmax with SimdGemm, same pattern
        // as the SDPA fix (Issue #162). Replaces the scalar virtual-dispatch
        // triple-loop below which was dominated by INumericOperations<T>.Multiply
        // / .Add calls per FMA.
        //
        // The tiled online-softmax approach of the scalar path is memory-efficient
        // for very long sequences (O(N) memory), but at DiT-XL's N=256 the
        // materialized [N,N] scores matrix is only 256 KB per head — fits in L2
        // comfortably. For that regime, materializing + batched SGEMMs is
        // substantially faster than the tiled scalar loop.
        //
        // Non-float T continues through the existing scalar path below.
        // ────────────────────────────────────────────────────────────────────
        if (typeof(T) == typeof(float))
        {
            double scaleValF = scale ?? 1.0 / Math.Sqrt(headDim);
            var resultF = FlashAttentionFloat(
                (Tensor<float>)(object)query,
                (Tensor<float>)(object)key,
                (Tensor<float>)(object)value,
                attentionBias is null ? null : (Tensor<float>)(object)attentionBias,
                scaleValF, isCausal,
                batch, heads, seqQ, headDim, seqK,
                out var statsF);
            softmaxStats = (Tensor<T>)(object)statsF;
            var resultFCast = (Tensor<T>)(object)resultF;
            // attentionBias is nullable; encode as variable-length savedState
            // (3 entries when null, 4 when present). The SavedStateSerializer's
            // default branch throws NotSupportedException for unknown types, so
            // we can't pack DBNull.Value or any other sentinel — only a missing
            // entry is portable across the tape's checkpoint/replay surface.
            var savedF = attentionBias is null
                ? new object[] { softmaxStats, scaleValF, isCausal }
                : new object[] { softmaxStats, scaleValF, isCausal, attentionBias };
            DifferentiableOps.RecordIfActive("FlashAttention", resultFCast,
                new[] { query, key, value },
                BackwardFunctions<T>.FlashAttentionBackward,
                savedF);
            return resultFCast;
        }

        // Extract bias data for the scalar path (shape already validated above).
        T[]? biasData = null;
        bool hasBias = false;
        if (attentionBias is not null)
        {
            biasData = attentionBias.GetDataArray();
            hasBias = true;
        }

        // Compute scale if not provided
        double scaleValue = scale ?? 1.0 / Math.Sqrt(headDim);
        T scaleFactor = numOps.FromDouble(scaleValue);

        // Block sizes for tiling (tuned for CPU cache)
        const int BLOCK_Q = 64;
        const int BLOCK_KV = 64;

        var queryData = query.GetDataArray();
        var keyData = key.GetDataArray();
        var valueData = value.GetDataArray();

        // Output and statistics
        var outputData = new T[batch * heads * seqQ * headDim];
        var statsData = new T[batch * heads * seqQ]; // log-sum-exp statistics

        // Initialize output to zero and stats to negative infinity
        T negInf = numOps.FromDouble(double.NegativeInfinity);
        numOps.Fill(outputData.AsSpan(), numOps.Zero);
        numOps.Fill(statsData.AsSpan(), negInf);

        Parallel.For(0, batch * heads, bh =>
        {
            int b = bh / heads;
            int h = bh % heads;
            int qOffset = (b * heads + h) * seqQ * headDim;
            int kOffset = (b * heads + h) * seqK * headDim;
            int vOffset = (b * heads + h) * seqK * headDim;
            int oOffset = (b * heads + h) * seqQ * headDim;
            int sOffset = (b * heads + h) * seqQ;

            // Local accumulators per query position
            var rowMax = new T[seqQ];
            var rowSum = new T[seqQ];
            numOps.Fill(rowMax.AsSpan(), negInf);
            numOps.Fill(rowSum.AsSpan(), numOps.Zero);

            // Process KV blocks
            for (int kvBlockStart = 0; kvBlockStart < seqK; kvBlockStart += BLOCK_KV)
            {
                int kvBlockEnd = Math.Min(kvBlockStart + BLOCK_KV, seqK);

                // Process Q blocks
                for (int qBlockStart = 0; qBlockStart < seqQ; qBlockStart += BLOCK_Q)
                {
                    int qBlockEnd = Math.Min(qBlockStart + BLOCK_Q, seqQ);

                    // Compute attention scores for this tile
                    for (int qi = qBlockStart; qi < qBlockEnd; qi++)
                    {
                        // Causal: skip if all keys in block are after query
                        if (isCausal && kvBlockStart > qi)
                            continue;

                        T localMax = rowMax[qi];
                        T localSum = rowSum[qi];

                        // Temporary storage for this row's scores in the block
                        var blockScores = new T[kvBlockEnd - kvBlockStart];
                        var blockMaxScore = negInf;

                        // Compute scores: Q @ K^T * scale
                        for (int ki = kvBlockStart; ki < kvBlockEnd; ki++)
                        {
                            // Causal mask
                            if (isCausal && ki > qi)
                            {
                                blockScores[ki - kvBlockStart] = negInf;
                                continue;
                            }

                            T score = numOps.Zero;
                            for (int d = 0; d < headDim; d++)
                            {
                                score = numOps.Add(score, numOps.Multiply(
                                    queryData[qOffset + qi * headDim + d],
                                    keyData[kOffset + ki * headDim + d]));
                            }
                            score = numOps.Multiply(score, scaleFactor);

                            // Add attention bias if provided (applied after QK^T * scale, before softmax)
                            if (hasBias && biasData is not null)
                            {
                                int biasIdx = biasBroadcastBatch
                                    ? (h * seqQ * seqK + qi * seqK + ki)
                                    : (b * heads * seqQ * seqK + h * seqQ * seqK + qi * seqK + ki);
                                score = numOps.Add(score, biasData[biasIdx]);
                            }

                            blockScores[ki - kvBlockStart] = score;

                            if (numOps.ToDouble(score) > numOps.ToDouble(blockMaxScore))
                                blockMaxScore = score;
                        }

                        // Online softmax: compute new max
                        T newMax = numOps.ToDouble(blockMaxScore) > numOps.ToDouble(localMax) ? blockMaxScore : localMax;

                        // Rescale previous accumulator
                        T scale1 = numOps.Exp(numOps.Subtract(localMax, newMax));
                        T newSum = numOps.Multiply(localSum, scale1);

                        // Add new contributions
                        for (int ki = kvBlockStart; ki < kvBlockEnd; ki++)
                        {
                            if (isCausal && ki > qi)
                                continue;

                            T expScore = numOps.Exp(numOps.Subtract(blockScores[ki - kvBlockStart], newMax));
                            newSum = numOps.Add(newSum, expScore);

                            // Update output: O = O * scale1 + exp(score - newMax) * V
                            for (int d = 0; d < headDim; d++)
                            {
                                T vVal = valueData[vOffset + ki * headDim + d];
                                T oVal = outputData[oOffset + qi * headDim + d];

                                // First time rescaling for this block
                                if (ki == kvBlockStart)
                                    oVal = numOps.Multiply(oVal, scale1);

                                outputData[oOffset + qi * headDim + d] = numOps.Add(oVal, numOps.Multiply(expScore, vVal));
                            }
                        }

                        rowMax[qi] = newMax;
                        rowSum[qi] = newSum;
                    }
                }
            }

            // Final normalization: O = O / rowSum
            for (int qi = 0; qi < seqQ; qi++)
            {
                T invSum = numOps.Divide(numOps.One, rowSum[qi]);
                for (int d = 0; d < headDim; d++)
                {
                    outputData[oOffset + qi * headDim + d] = numOps.Multiply(
                        outputData[oOffset + qi * headDim + d], invSum);
                }
                // Store log-sum-exp: logsumexp = max + log(sum)
                statsData[sOffset + qi] = numOps.Add(rowMax[qi], numOps.Log(rowSum[qi]));
            }
        });

        softmaxStats = TensorAllocator.Rent<T>([batch, heads, seqQ], new Vector<T>(statsData));
        var resultGen = TensorAllocator.Rent<T>([batch, heads, seqQ, headDim], new Vector<T>(outputData));
        // Tape registration — variable-length savedState encodes optional
        // attentionBias (3 entries when null, 4 when present). See
        // FlashAttentionBackward and SavedStateSerializer for why DBNull /
        // null entries can't be used in their place.
        double scaleValGen = scale ?? 1.0 / Math.Sqrt(headDim);
        var savedGen = attentionBias is null
            ? new object[] { softmaxStats, scaleValGen, isCausal }
            : new object[] { softmaxStats, scaleValGen, isCausal, attentionBias };
        DifferentiableOps.RecordIfActive("FlashAttention", resultGen,
            new[] { query, key, value },
            BackwardFunctions<T>.FlashAttentionBackward,
            savedGen);
        return resultGen;
    }

    /// <summary>
    /// SimdGemm-backed float fast path for <see cref="FlashAttention{T}"/>.
    /// Uses materialized softmax (not tiled online-softmax): computes
    /// scores = Q·K^T via batched SimdGemm, applies scale + optional bias + optional
    /// causal mask, numerically-stable softmax per row, then output = softmax · V
    /// via batched SimdGemm. Also computes the log-sum-exp statistics the backward
    /// pass needs.
    ///
    /// For DiT-XL-scale attention (N=256, headDim=72), this is substantially faster
    /// than the scalar online-softmax path. For very long sequences (N ≥ ~2K), the
    /// materialized [N,N] scores matrix starts to matter — the scalar path's tiled
    /// approach has O(N) memory vs our O(N²). Callers that know they need very-long-
    /// sequence semantics should still be able to hit the scalar path by using a
    /// non-float tensor type, or we can add a tile-threshold check later if the need
    /// arises.
    /// </summary>
    private Tensor<float> FlashAttentionFloat(
        Tensor<float> query,
        Tensor<float> key,
        Tensor<float> value,
        Tensor<float>? attentionBias,
        double scaleValue,
        bool isCausal,
        int batch, int heads, int seqQ, int headDim, int seqK,
        out Tensor<float> softmaxStats)
    {
        int bhCount = batch * heads;
        int d_v = headDim; // FlashAttention takes headDim for both Q/K and V

        var queryOrig = query;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!query.IsContiguous) query = query.Contiguous();
        var keyOrig = key;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!key.IsContiguous) key = key.Contiguous();
        var valueOrig = value;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!value.IsContiguous) value = value.Contiguous();

        var qf = query.GetFlattenedData();
        var kf = key.GetFlattenedData();
        var vf = value.GetDataArray();
        float[]? biasData = null;
        bool biasBroadcastBatch = false;
        if (attentionBias is not null)
        {
            var attentionBiasOrig = attentionBias;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
            if (!attentionBias.IsContiguous) attentionBias = attentionBias.Contiguous();
            biasData = attentionBias.GetDataArray();
            biasBroadcastBatch = attentionBias.Rank == 3;
        }

        // scoresData is internal scratch pooled from ArrayPool. weightsData and
        // outputData are returned to the caller (via the tensor pair + softmaxStats).
        int scoresLen = bhCount * seqQ * seqK;
        var scoresData = System.Buffers.ArrayPool<float>.Shared.Rent(scoresLen);
        try
        {
            var weightsData = new float[scoresLen];
            var outputData = new float[bhCount * seqQ * d_v];
            var statsData = new float[bhCount * seqQ];

            float scaleF  = (float)scaleValue;
            float negInfF = float.NegativeInfinity;

            Parallel.For(0, bhCount, bh =>
            {
                int b = bh / heads;
                int h = bh % heads;

                int qOff = bh * seqQ * headDim;
                int kOff = bh * seqK * headDim;
                int sOff = bh * seqQ * seqK;

                // Step 1: scores = Q · K^T. Same pattern as SDPA fast path —
                // pre-transpose this head's K slice into a pooled scratch buffer
                // (SimdGemm has no transB support) then call SgemmSequential.
                var kt = System.Buffers.ArrayPool<float>.Shared.Rent(headDim * seqK);
                try
                {
                    for (int i = 0; i < seqK; i++)
                        for (int j = 0; j < headDim; j++)
                            kt[j * seqK + i] = kf[kOff + i * headDim + j];
                    Engines.Simd.SimdGemm.SgemmSequential(
                        qf.AsSpan(qOff, seqQ * headDim),
                        kt.AsSpan(0, headDim * seqK),
                        scoresData.AsSpan(sOff, seqQ * seqK),
                        seqQ, headDim, seqK);
                }
                finally { System.Buffers.ArrayPool<float>.Shared.Return(kt); }

                // Step 2: fused scale + causal-mask + bias + stable softmax per row.
                for (int i = 0; i < seqQ; i++)
                {
                    int rowOff = sOff + i * seqK;
                    float maxVal = negInfF;
                    for (int j = 0; j < seqK; j++)
                    {
                        float v = scoresData[rowOff + j] * scaleF;
                        // Additive attention bias (3D [heads,seqQ,seqK] or 4D [B,H,seqQ,seqK])
                        if (biasData is not null)
                        {
                            int biasIdx = biasBroadcastBatch
                                ? (h * seqQ * seqK + i * seqK + j)
                                : (b * heads * seqQ * seqK + h * seqQ * seqK + i * seqK + j);
                            v += biasData[biasIdx];
                        }
                        // Causal mask: positions j > i don't attend
                        if (isCausal && j > i) v = negInfF;
                        if (v > maxVal) maxVal = v;
                        scoresData[rowOff + j] = v;
                    }

                    // Fully-masked row guard (SDPA fix pattern): if every position
                    // was masked out, the exp(x - (-Inf)) = +Inf trick produces NaN.
                    // Emit all-zero softmax + log-sum-exp = -Inf for that row.
                    if (float.IsNegativeInfinity(maxVal))
                    {
                        for (int j = 0; j < seqK; j++)
                            weightsData[rowOff + j] = 0f;
                        statsData[bh * seqQ + i] = negInfF;
                        continue;
                    }

                    float sumExp = 0f;
                    for (int j = 0; j < seqK; j++)
                    {
                        float e = MathF.Exp(scoresData[rowOff + j] - maxVal);
                        weightsData[rowOff + j] = e;
                        sumExp += e;
                    }
                    float inv = sumExp != 0f ? 1f / sumExp : 0f;
                    for (int j = 0; j < seqK; j++)
                        weightsData[rowOff + j] *= inv;

                    // logsumexp = max + log(sum) — the backward pass needs this.
                    statsData[bh * seqQ + i] = maxVal + MathF.Log(sumExp);
                }

                // Step 3: output = softmax · V via SimdGemm (no transpose).
                int wOff = bh * seqQ * seqK;
                int vOff = bh * seqK * d_v;
                int oOff = bh * seqQ * d_v;
                Engines.Simd.SimdGemm.SgemmSequential(
                    weightsData.AsSpan(wOff, seqQ * seqK),
                    vf.AsSpan(vOff, seqK * d_v),
                    outputData.AsSpan(oOff, seqQ * d_v),
                    seqQ, seqK, d_v);
            });

            softmaxStats = TensorAllocator.Rent<float>(
                new[] { batch, heads, seqQ },
                new Vector<float>(statsData));
            return TensorAllocator.Rent<float>(
                new[] { batch, heads, seqQ, headDim },
                new Vector<float>(outputData));
        }
        finally
        {
            System.Buffers.ArrayPool<float>.Shared.Return(scoresData, clearArray: false);
        }
    }

    /// <summary>
    /// Computes the backward pass for FlashAttention.
    /// </summary>
    public Tensor<T> FlashAttentionBackward<T>(
        Tensor<T> gradOutput,
        Tensor<T> query,
        Tensor<T> key,
        Tensor<T> value,
        Tensor<T> output,
        Tensor<T> softmaxStats,
        double scale,
        bool isCausal,
        out Tensor<T> gradQuery,
        out Tensor<T> gradKey,
        out Tensor<T> gradValue,
        Tensor<T>? attentionBias = null)
    {
        if (gradOutput == null) throw new ArgumentNullException(nameof(gradOutput));
        if (query == null) throw new ArgumentNullException(nameof(query));
        if (key == null) throw new ArgumentNullException(nameof(key));
        if (value == null) throw new ArgumentNullException(nameof(value));
        if (output == null) throw new ArgumentNullException(nameof(output));
        if (softmaxStats == null) throw new ArgumentNullException(nameof(softmaxStats));

        if (query._shape.Length != 4)
            throw new ArgumentException($"query must be rank-4 [batch, heads, seqQ, headDim], got rank {query._shape.Length}.", nameof(query));
        if (key._shape.Length != 4)
            throw new ArgumentException($"key must be rank-4 [batch, heads, seqK, headDim], got rank {key._shape.Length}.", nameof(key));
        if (value._shape.Length != 4)
            throw new ArgumentException($"value must be rank-4 [batch, heads, seqK, headDim], got rank {value._shape.Length}.", nameof(value));
        if (output._shape.Length != 4)
            throw new ArgumentException($"output must be rank-4 [batch, heads, seqQ, headDim], got rank {output._shape.Length}.", nameof(output));
        if (gradOutput._shape.Length != 4)
            throw new ArgumentException($"gradOutput must be rank-4 [batch, heads, seqQ, headDim], got rank {gradOutput._shape.Length}.", nameof(gradOutput));
        if (softmaxStats._shape.Length != 3)
            throw new ArgumentException($"softmaxStats must be rank-3 [batch, heads, seqQ], got rank {softmaxStats._shape.Length}.", nameof(softmaxStats));

        var numOps = MathHelper.GetNumericOperations<T>();

        int batch = query._shape[0];
        int heads = query._shape[1];
        int seqQ = query._shape[2];
        int headDim = query._shape[3];
        int seqK = key._shape[2];

        if (key._shape[0] != batch || key._shape[1] != heads || key._shape[3] != headDim)
            throw new ArgumentException(
                $"key shape [{string.Join(",", key._shape)}] must be [batch={batch}, heads={heads}, seqK, headDim={headDim}].",
                nameof(key));
        if (value._shape[0] != batch || value._shape[1] != heads || value._shape[2] != seqK || value._shape[3] != headDim)
            throw new ArgumentException(
                $"value shape [{string.Join(",", value._shape)}] must be [batch={batch}, heads={heads}, seqK={seqK}, headDim={headDim}].",
                nameof(value));
        if (output._shape[0] != batch || output._shape[1] != heads || output._shape[2] != seqQ || output._shape[3] != headDim)
            throw new ArgumentException(
                $"output shape [{string.Join(",", output._shape)}] must be [batch={batch}, heads={heads}, seqQ={seqQ}, headDim={headDim}].",
                nameof(output));
        if (gradOutput._shape[0] != batch || gradOutput._shape[1] != heads || gradOutput._shape[2] != seqQ || gradOutput._shape[3] != headDim)
            throw new ArgumentException(
                $"gradOutput shape [{string.Join(",", gradOutput._shape)}] must be [batch={batch}, heads={heads}, seqQ={seqQ}, headDim={headDim}].",
                nameof(gradOutput));
        if (softmaxStats._shape[0] != batch || softmaxStats._shape[1] != heads || softmaxStats._shape[2] != seqQ)
            throw new ArgumentException(
                $"softmaxStats shape [{string.Join(",", softmaxStats._shape)}] must be [batch={batch}, heads={heads}, seqQ={seqQ}].",
                nameof(softmaxStats));

        T scaleFactor = numOps.FromDouble(scale);

        const int BLOCK_Q = 64;
        const int BLOCK_KV = 64;

        var queryData = query.GetDataArray();
        var keyData = key.GetDataArray();
        var valueData = value.GetDataArray();
        var outputData = output.GetDataArray();
        var gradOutData = gradOutput.GetDataArray();
        var statsData = softmaxStats.GetDataArray();

        var gradQData = new T[batch * heads * seqQ * headDim];
        var gradKData = new T[batch * heads * seqK * headDim];
        var gradVData = new T[batch * heads * seqK * headDim];

        // Extract and validate bias data if provided (same validation as forward pass)
        T[]? biasData = null;
        bool hasBias = false;
        bool biasBroadcastBatch = false;
        if (attentionBias is not null)
        {
            int biasRank = attentionBias._shape.Length;
            if (biasRank == 4)
            {
                if (attentionBias._shape[0] != batch || attentionBias._shape[1] != heads ||
                    attentionBias._shape[2] != seqQ || attentionBias._shape[3] != seqK)
                    throw new ArgumentException(
                        $"4D attention bias shape [{string.Join(",", attentionBias._shape)}] must match [batch={batch}, heads={heads}, seqQ={seqQ}, seqK={seqK}].",
                        nameof(attentionBias));
                biasBroadcastBatch = false;
            }
            else if (biasRank == 3)
            {
                if (attentionBias._shape[0] != heads || attentionBias._shape[1] != seqQ || attentionBias._shape[2] != seqK)
                    throw new ArgumentException(
                        $"3D attention bias shape [{string.Join(",", attentionBias._shape)}] must match [heads={heads}, seqQ={seqQ}, seqK={seqK}].",
                        nameof(attentionBias));
                biasBroadcastBatch = true;
            }
            else
            {
                throw new ArgumentException(
                    $"Attention bias must be rank 3 [heads, seqQ, seqK] or rank 4 [batch, heads, seqQ, seqK], got rank {biasRank}.",
                    nameof(attentionBias));
            }
            biasData = attentionBias.GetDataArray();
            hasBias = true;
        }

        T negInf = numOps.FromDouble(double.NegativeInfinity);

        // ────────────────────────────────────────────────────────────────────
        // Primitive fast paths: direct float/double arithmetic, no virtual
        // dispatch. Method signature stays generic <T>; non-primitive T falls
        // through to the original scalar path below.
        //
        // Note on locks: the generic scalar path uses `lock (gradVData)` and
        // `lock (gradKData)` inside the ki loop. The locks are unnecessary —
        // each Parallel.For worker (one per batch*head) writes to a disjoint
        // [seqK*headDim]-sized slice of gradVData/gradKData selected by its
        // unique vOffset/kOffset. The primitive paths drop the locks, which
        // also un-serializes the nominally-parallel outer loop (the locks
        // reference the shared array object, so all workers were contending
        // on the same monitor — effectively sequentializing the op).
        // ────────────────────────────────────────────────────────────────────
        if (typeof(T) == typeof(float))
        {
            FlashAttentionBackwardFloat(
                (float[])(object)queryData, (float[])(object)keyData,
                (float[])(object)valueData, (float[])(object)outputData,
                (float[])(object)gradOutData, (float[])(object)statsData,
                (float[])(object)gradQData, (float[])(object)gradKData,
                (float[])(object)gradVData,
                biasData is null ? null : (float[])(object)biasData,
                biasBroadcastBatch, (float)scale, isCausal,
                batch, heads, seqQ, headDim, seqK, BLOCK_Q, BLOCK_KV);
        }
        else if (typeof(T) == typeof(double))
        {
            FlashAttentionBackwardDouble(
                (double[])(object)queryData, (double[])(object)keyData,
                (double[])(object)valueData, (double[])(object)outputData,
                (double[])(object)gradOutData, (double[])(object)statsData,
                (double[])(object)gradQData, (double[])(object)gradKData,
                (double[])(object)gradVData,
                biasData is null ? null : (double[])(object)biasData,
                biasBroadcastBatch, scale, isCausal,
                batch, heads, seqQ, headDim, seqK, BLOCK_Q, BLOCK_KV);
        }
        else
        {
            Parallel.For(0, batch * heads, bh =>
            {
                int b = bh / heads;
                int h = bh % heads;
                int qOffset = (b * heads + h) * seqQ * headDim;
                int kOffset = (b * heads + h) * seqK * headDim;
                int vOffset = (b * heads + h) * seqK * headDim;
                int oOffset = (b * heads + h) * seqQ * headDim;
                int sOffset = (b * heads + h) * seqQ;

                // Process in blocks (similar to forward, but recomputing attention)
                for (int kvBlockStart = 0; kvBlockStart < seqK; kvBlockStart += BLOCK_KV)
                {
                    int kvBlockEnd = Math.Min(kvBlockStart + BLOCK_KV, seqK);

                    for (int qBlockStart = 0; qBlockStart < seqQ; qBlockStart += BLOCK_Q)
                    {
                        int qBlockEnd = Math.Min(qBlockStart + BLOCK_Q, seqQ);

                        for (int qi = qBlockStart; qi < qBlockEnd; qi++)
                        {
                            if (isCausal && kvBlockStart > qi)
                                continue;

                            T logsumexp = statsData[sOffset + qi];

                            // Recompute attention weights for this row segment
                            for (int ki = kvBlockStart; ki < kvBlockEnd; ki++)
                            {
                                if (isCausal && ki > qi)
                                    continue;

                                // Recompute score
                                T score = numOps.Zero;
                                for (int d = 0; d < headDim; d++)
                                {
                                    score = numOps.Add(score, numOps.Multiply(
                                        queryData[qOffset + qi * headDim + d],
                                        keyData[kOffset + ki * headDim + d]));
                                }
                                score = numOps.Multiply(score, scaleFactor);

                                // Add attention bias if provided (must match forward pass)
                                if (hasBias && biasData is not null)
                                {
                                    int biasIdx = biasBroadcastBatch
                                        ? (h * seqQ * seqK + qi * seqK + ki)
                                        : (b * heads * seqQ * seqK + h * seqQ * seqK + qi * seqK + ki);
                                    score = numOps.Add(score, biasData[biasIdx]);
                                }

                                // Recompute attention weight: exp(score - logsumexp)
                                T attnWeight = numOps.Exp(numOps.Subtract(score, logsumexp));

                                // Gradient w.r.t. V: attnWeight * gradOutput
                                for (int d = 0; d < headDim; d++)
                                {
                                    T gradO = gradOutData[oOffset + qi * headDim + d];
                                    int vIdx = vOffset + ki * headDim + d;
                                    lock (gradVData) // Thread safety for accumulation
                                    {
                                        gradVData[vIdx] = numOps.Add(gradVData[vIdx], numOps.Multiply(attnWeight, gradO));
                                    }
                                }

                                // Compute dS = attnWeight * (dO @ V - sum(attnWeight * dO @ V))
                                // First compute dO @ v for this position
                                T doV = numOps.Zero;
                                for (int d = 0; d < headDim; d++)
                                {
                                    doV = numOps.Add(doV, numOps.Multiply(
                                        gradOutData[oOffset + qi * headDim + d],
                                        valueData[vOffset + ki * headDim + d]));
                                }

                                // Compute dO @ O for the full row (dot product with output)
                                T doO = numOps.Zero;
                                for (int d = 0; d < headDim; d++)
                                {
                                    doO = numOps.Add(doO, numOps.Multiply(
                                        gradOutData[oOffset + qi * headDim + d],
                                        outputData[oOffset + qi * headDim + d]));
                                }

                                // dS = attnWeight * (doV - doO)
                                T dS = numOps.Multiply(attnWeight, numOps.Subtract(doV, doO));
                                dS = numOps.Multiply(dS, scaleFactor);

                                // Gradient w.r.t. Q: dS * K
                                for (int d = 0; d < headDim; d++)
                                {
                                    int qIdx = qOffset + qi * headDim + d;
                                    gradQData[qIdx] = numOps.Add(gradQData[qIdx],
                                        numOps.Multiply(dS, keyData[kOffset + ki * headDim + d]));
                                }

                                // Gradient w.r.t. K: dS * Q
                                for (int d = 0; d < headDim; d++)
                                {
                                    int kIdx = kOffset + ki * headDim + d;
                                    lock (gradKData) // Thread safety for accumulation
                                    {
                                        gradKData[kIdx] = numOps.Add(gradKData[kIdx],
                                            numOps.Multiply(dS, queryData[qOffset + qi * headDim + d]));
                                    }
                                }
                            }
                        }
                    }
                }
            });
        }

        gradQuery = TensorAllocator.Rent<T>(query._shape, new Vector<T>(gradQData));
        gradKey = TensorAllocator.Rent<T>(key._shape, new Vector<T>(gradKData));
        gradValue = TensorAllocator.Rent<T>(value._shape, new Vector<T>(gradVData));

        return gradOutput;
    }

    /// <summary>
    /// Float fast path for <see cref="FlashAttentionBackward{T}"/>. Direct
    /// float arithmetic; no virtual dispatch; writes to disjoint per-(b, h)
    /// slices so no locks are needed.
    /// </summary>
    private static void FlashAttentionBackwardFloat(
        float[] queryData, float[] keyData, float[] valueData, float[] outputData,
        float[] gradOutData, float[] statsData,
        float[] gradQData, float[] gradKData, float[] gradVData,
        float[]? biasData, bool biasBroadcastBatch, float scaleFactor, bool isCausal,
        int batch, int heads, int seqQ, int headDim, int seqK,
        int BLOCK_Q, int BLOCK_KV)
    {
        Parallel.For(0, batch * heads, bh =>
        {
            int b = bh / heads;
            int h = bh % heads;
            int qOffset = (b * heads + h) * seqQ * headDim;
            int kOffset = (b * heads + h) * seqK * headDim;
            int vOffset = (b * heads + h) * seqK * headDim;
            int oOffset = (b * heads + h) * seqQ * headDim;
            int sOffset = (b * heads + h) * seqQ;

            for (int kvBlockStart = 0; kvBlockStart < seqK; kvBlockStart += BLOCK_KV)
            {
                int kvBlockEnd = Math.Min(kvBlockStart + BLOCK_KV, seqK);
                for (int qBlockStart = 0; qBlockStart < seqQ; qBlockStart += BLOCK_Q)
                {
                    int qBlockEnd = Math.Min(qBlockStart + BLOCK_Q, seqQ);
                    for (int qi = qBlockStart; qi < qBlockEnd; qi++)
                    {
                        if (isCausal && kvBlockStart > qi) continue;

                        float logsumexp = statsData[sOffset + qi];
                        int qRowOff = qOffset + qi * headDim;
                        int oRowOff = oOffset + qi * headDim;

                        // doO is independent of ki — hoist it out of the ki loop.
                        // (The generic path recomputes it per ki; correctness-neutral
                        // hoist that was already safe there too.)
                        float doO = 0f;
                        for (int d = 0; d < headDim; d++)
                            doO += gradOutData[oRowOff + d] * outputData[oRowOff + d];

                        for (int ki = kvBlockStart; ki < kvBlockEnd; ki++)
                        {
                            if (isCausal && ki > qi) continue;

                            int kRowOff = kOffset + ki * headDim;
                            int vRowOff = vOffset + ki * headDim;

                            float score = 0f;
                            for (int d = 0; d < headDim; d++)
                                score += queryData[qRowOff + d] * keyData[kRowOff + d];
                            score *= scaleFactor;

                            if (biasData is not null)
                            {
                                int biasIdx = biasBroadcastBatch
                                    ? (h * seqQ * seqK + qi * seqK + ki)
                                    : (b * heads * seqQ * seqK + h * seqQ * seqK + qi * seqK + ki);
                                score += biasData[biasIdx];
                            }

                            float attnWeight = MathF.Exp(score - logsumexp);

                            float doV = 0f;
                            for (int d = 0; d < headDim; d++)
                                doV += gradOutData[oRowOff + d] * valueData[vRowOff + d];

                            float dS = attnWeight * (doV - doO) * scaleFactor;

                            // gradV += attnWeight * gradOutput — disjoint per (b, h), no lock.
                            for (int d = 0; d < headDim; d++)
                                gradVData[vRowOff + d] += attnWeight * gradOutData[oRowOff + d];

                            // gradQ += dS * K (this worker owns the full gradQ slice for its qi row).
                            for (int d = 0; d < headDim; d++)
                                gradQData[qRowOff + d] += dS * keyData[kRowOff + d];

                            // gradK += dS * Q — also disjoint per (b, h).
                            for (int d = 0; d < headDim; d++)
                                gradKData[kRowOff + d] += dS * queryData[qRowOff + d];
                        }
                    }
                }
            }
        });
    }

    /// <summary>Double fast path for <see cref="FlashAttentionBackward{T}"/>. Mirror of the float version.</summary>
    private static void FlashAttentionBackwardDouble(
        double[] queryData, double[] keyData, double[] valueData, double[] outputData,
        double[] gradOutData, double[] statsData,
        double[] gradQData, double[] gradKData, double[] gradVData,
        double[]? biasData, bool biasBroadcastBatch, double scaleFactor, bool isCausal,
        int batch, int heads, int seqQ, int headDim, int seqK,
        int BLOCK_Q, int BLOCK_KV)
    {
        Parallel.For(0, batch * heads, bh =>
        {
            int b = bh / heads;
            int h = bh % heads;
            int qOffset = (b * heads + h) * seqQ * headDim;
            int kOffset = (b * heads + h) * seqK * headDim;
            int vOffset = (b * heads + h) * seqK * headDim;
            int oOffset = (b * heads + h) * seqQ * headDim;
            int sOffset = (b * heads + h) * seqQ;

            for (int kvBlockStart = 0; kvBlockStart < seqK; kvBlockStart += BLOCK_KV)
            {
                int kvBlockEnd = Math.Min(kvBlockStart + BLOCK_KV, seqK);
                for (int qBlockStart = 0; qBlockStart < seqQ; qBlockStart += BLOCK_Q)
                {
                    int qBlockEnd = Math.Min(qBlockStart + BLOCK_Q, seqQ);
                    for (int qi = qBlockStart; qi < qBlockEnd; qi++)
                    {
                        if (isCausal && kvBlockStart > qi) continue;

                        double logsumexp = statsData[sOffset + qi];
                        int qRowOff = qOffset + qi * headDim;
                        int oRowOff = oOffset + qi * headDim;

                        double doO = 0.0;
                        for (int d = 0; d < headDim; d++)
                            doO += gradOutData[oRowOff + d] * outputData[oRowOff + d];

                        for (int ki = kvBlockStart; ki < kvBlockEnd; ki++)
                        {
                            if (isCausal && ki > qi) continue;

                            int kRowOff = kOffset + ki * headDim;
                            int vRowOff = vOffset + ki * headDim;

                            double score = 0.0;
                            for (int d = 0; d < headDim; d++)
                                score += queryData[qRowOff + d] * keyData[kRowOff + d];
                            score *= scaleFactor;

                            if (biasData is not null)
                            {
                                int biasIdx = biasBroadcastBatch
                                    ? (h * seqQ * seqK + qi * seqK + ki)
                                    : (b * heads * seqQ * seqK + h * seqQ * seqK + qi * seqK + ki);
                                score += biasData[biasIdx];
                            }

                            double attnWeight = Math.Exp(score - logsumexp);

                            double doV = 0.0;
                            for (int d = 0; d < headDim; d++)
                                doV += gradOutData[oRowOff + d] * valueData[vRowOff + d];

                            double dS = attnWeight * (doV - doO) * scaleFactor;

                            for (int d = 0; d < headDim; d++)
                                gradVData[vRowOff + d] += attnWeight * gradOutData[oRowOff + d];

                            for (int d = 0; d < headDim; d++)
                                gradQData[qRowOff + d] += dS * keyData[kRowOff + d];

                            for (int d = 0; d < headDim; d++)
                                gradKData[kRowOff + d] += dS * queryData[qRowOff + d];
                        }
                    }
                }
            }
        });
    }

    /// <summary>
    /// Computes Grouped Query Attention (GQA) for efficient inference.
    /// </summary>
    /// <remarks>
    /// GQA allows multiple query heads to share the same key-value head,
    /// reducing memory bandwidth and KV-cache size during inference.
    /// </remarks>
    public Tensor<T> GroupedQueryAttention<T>(
        Tensor<T> query,
        Tensor<T> key,
        Tensor<T> value,
        int numQueriesPerKV,
        double? scale,
        bool isCausal,
        out Tensor<T> attentionWeights)
    {
        if (query == null) throw new ArgumentNullException(nameof(query));
        if (key == null) throw new ArgumentNullException(nameof(key));
        if (value == null) throw new ArgumentNullException(nameof(value));
        if (numQueriesPerKV <= 0) throw new ArgumentOutOfRangeException(nameof(numQueriesPerKV));

        var numOps = MathHelper.GetNumericOperations<T>();

        int batch = query._shape[0];
        int numQHeads = query._shape[1];
        int seqQ = query._shape[2];
        int headDim = query._shape[3];
        int numKVHeads = key._shape[1];
        int seqK = key._shape[2];

        if (numQHeads != numKVHeads * numQueriesPerKV)
            throw new ArgumentException($"Query heads ({numQHeads}) must equal KV heads ({numKVHeads}) * numQueriesPerKV ({numQueriesPerKV})");

        // Compute scale
        double scaleValue = scale ?? 1.0 / Math.Sqrt(headDim);
        T scaleFactor = numOps.FromDouble(scaleValue);
        T negInf = numOps.FromDouble(double.NegativeInfinity);

        var queryData = query.GetDataArray();
        var keyData = key.GetDataArray();
        var valueData = value.GetDataArray();

        var outputData = new T[batch * numQHeads * seqQ * headDim];
        var weightsData = new T[batch * numQHeads * seqQ * seqK];

        Parallel.For(0, batch * numQHeads, bqh =>
        {
            int b = bqh / numQHeads;
            int qh = bqh % numQHeads;
            int kvh = qh / numQueriesPerKV; // Which KV head this query head uses

            int qOffset = (b * numQHeads + qh) * seqQ * headDim;
            int kOffset = (b * numKVHeads + kvh) * seqK * headDim;
            int vOffset = (b * numKVHeads + kvh) * seqK * headDim;
            int oOffset = (b * numQHeads + qh) * seqQ * headDim;
            int wOffset = (b * numQHeads + qh) * seqQ * seqK;

            for (int qi = 0; qi < seqQ; qi++)
            {
                // Compute attention scores: Q @ K^T * scale
                var scores = new T[seqK];
                T maxScore = negInf;

                for (int ki = 0; ki < seqK; ki++)
                {
                    // Causal mask
                    if (isCausal && ki > qi)
                    {
                        scores[ki] = negInf;
                        continue;
                    }

                    T score = numOps.Zero;
                    for (int d = 0; d < headDim; d++)
                    {
                        score = numOps.Add(score, numOps.Multiply(
                            queryData[qOffset + qi * headDim + d],
                            keyData[kOffset + ki * headDim + d]));
                    }
                    score = numOps.Multiply(score, scaleFactor);
                    scores[ki] = score;

                    if (numOps.ToDouble(score) > numOps.ToDouble(maxScore))
                        maxScore = score;
                }

                // Softmax
                T sumExp = numOps.Zero;
                for (int ki = 0; ki < seqK; ki++)
                {
                    if (isCausal && ki > qi)
                    {
                        weightsData[wOffset + qi * seqK + ki] = numOps.Zero;
                        continue;
                    }
                    T expScore = numOps.Exp(numOps.Subtract(scores[ki], maxScore));
                    weightsData[wOffset + qi * seqK + ki] = expScore;
                    sumExp = numOps.Add(sumExp, expScore);
                }

                // Normalize
                T invSum = numOps.Divide(numOps.One, sumExp);
                for (int ki = 0; ki < seqK; ki++)
                {
                    weightsData[wOffset + qi * seqK + ki] = numOps.Multiply(
                        weightsData[wOffset + qi * seqK + ki], invSum);
                }

                // Compute output: weights @ V
                for (int d = 0; d < headDim; d++)
                {
                    T val = numOps.Zero;
                    for (int ki = 0; ki < seqK; ki++)
                    {
                        val = numOps.Add(val, numOps.Multiply(
                            weightsData[wOffset + qi * seqK + ki],
                            valueData[vOffset + ki * headDim + d]));
                    }
                    outputData[oOffset + qi * headDim + d] = val;
                }
            }
        });

        attentionWeights = TensorAllocator.Rent<T>([batch, numQHeads, seqQ, seqK], new Vector<T>(weightsData));
        var gqaResult = TensorAllocator.Rent<T>([batch, numQHeads, seqQ, headDim], new Vector<T>(outputData));
        double gqaScale = scale ?? (1.0 / Math.Sqrt(headDim));
        DifferentiableOps.RecordIfActive("GroupedQueryAttention", gqaResult,
            new[] { query, key, value },
            BackwardFunctions<T>.GroupedQueryAttentionBackward,
            new object[] { attentionWeights, numQueriesPerKV, gqaScale });
        return gqaResult;
    }

    /// <summary>
    /// Computes the backward pass for Grouped Query Attention.
    /// </summary>
    public Tensor<T> GroupedQueryAttentionBackward<T>(
        Tensor<T> gradOutput,
        Tensor<T> query,
        Tensor<T> key,
        Tensor<T> value,
        Tensor<T> attentionWeights,
        int numQueriesPerKV,
        double scale,
        out Tensor<T> gradQuery,
        out Tensor<T> gradKey,
        out Tensor<T> gradValue)
    {
        if (gradOutput == null) throw new ArgumentNullException(nameof(gradOutput));
        if (query == null) throw new ArgumentNullException(nameof(query));
        if (key == null) throw new ArgumentNullException(nameof(key));
        if (value == null) throw new ArgumentNullException(nameof(value));
        if (attentionWeights == null) throw new ArgumentNullException(nameof(attentionWeights));

        var numOps = MathHelper.GetNumericOperations<T>();

        int batch = query._shape[0];
        int numQHeads = query._shape[1];
        int seqQ = query._shape[2];
        int headDim = query._shape[3];
        int numKVHeads = key._shape[1];
        int seqK = key._shape[2];

        T scaleFactor = numOps.FromDouble(scale);

        var queryData = query.GetDataArray();
        var keyData = key.GetDataArray();
        var valueData = value.GetDataArray();
        var weightsData = attentionWeights.GetDataArray();
        var gradOutData = gradOutput.GetDataArray();

        var gradQData = new T[batch * numQHeads * seqQ * headDim];
        var gradKData = new T[batch * numKVHeads * seqK * headDim];
        var gradVData = new T[batch * numKVHeads * seqK * headDim];

        // Lock objects for thread-safe accumulation of gradK and gradV
        var gradKLocks = new object[batch * numKVHeads * seqK];
        var gradVLocks = new object[batch * numKVHeads * seqK];
        for (int i = 0; i < gradKLocks.Length; i++)
        {
            gradKLocks[i] = new object();
            gradVLocks[i] = new object();
        }

        Parallel.For(0, batch * numQHeads, bqh =>
        {
            int b = bqh / numQHeads;
            int qh = bqh % numQHeads;
            int kvh = qh / numQueriesPerKV;

            int qOffset = (b * numQHeads + qh) * seqQ * headDim;
            int kOffset = (b * numKVHeads + kvh) * seqK * headDim;
            int vOffset = (b * numKVHeads + kvh) * seqK * headDim;
            int gOffset = (b * numQHeads + qh) * seqQ * headDim;
            int wOffset = (b * numQHeads + qh) * seqQ * seqK;

            for (int qi = 0; qi < seqQ; qi++)
            {
                // Gradient w.r.t. V: weights^T @ gradOutput
                for (int ki = 0; ki < seqK; ki++)
                {
                    T weight = weightsData[wOffset + qi * seqK + ki];
                    int lockIdx = (b * numKVHeads + kvh) * seqK + ki;

                    for (int d = 0; d < headDim; d++)
                    {
                        T gradV = numOps.Multiply(weight, gradOutData[gOffset + qi * headDim + d]);
                        lock (gradVLocks[lockIdx])
                        {
                            gradVData[vOffset + ki * headDim + d] = numOps.Add(
                                gradVData[vOffset + ki * headDim + d], gradV);
                        }
                    }
                }

                // Gradient w.r.t. attention weights: gradOutput @ V^T
                var gradWeights = new T[seqK];
                for (int ki = 0; ki < seqK; ki++)
                {
                    T sum = numOps.Zero;
                    for (int d = 0; d < headDim; d++)
                    {
                        sum = numOps.Add(sum, numOps.Multiply(
                            gradOutData[gOffset + qi * headDim + d],
                            valueData[vOffset + ki * headDim + d]));
                    }
                    gradWeights[ki] = sum;
                }

                // Softmax backward: gradScores = weights * (gradWeights - sum(weights * gradWeights))
                T dotProduct = numOps.Zero;
                for (int ki = 0; ki < seqK; ki++)
                {
                    dotProduct = numOps.Add(dotProduct, numOps.Multiply(
                        weightsData[wOffset + qi * seqK + ki], gradWeights[ki]));
                }

                var gradScores = new T[seqK];
                for (int ki = 0; ki < seqK; ki++)
                {
                    T w = weightsData[wOffset + qi * seqK + ki];
                    gradScores[ki] = numOps.Multiply(w, numOps.Subtract(gradWeights[ki], dotProduct));
                    gradScores[ki] = numOps.Multiply(gradScores[ki], scaleFactor);
                }

                // Gradient w.r.t. Q: gradScores @ K
                for (int d = 0; d < headDim; d++)
                {
                    T sum = numOps.Zero;
                    for (int ki = 0; ki < seqK; ki++)
                    {
                        sum = numOps.Add(sum, numOps.Multiply(gradScores[ki], keyData[kOffset + ki * headDim + d]));
                    }
                    gradQData[qOffset + qi * headDim + d] = sum;
                }

                // Gradient w.r.t. K: gradScores^T @ Q (accumulated across query heads sharing this KV)
                for (int ki = 0; ki < seqK; ki++)
                {
                    int lockIdx = (b * numKVHeads + kvh) * seqK + ki;
                    for (int d = 0; d < headDim; d++)
                    {
                        T gradK = numOps.Multiply(gradScores[ki], queryData[qOffset + qi * headDim + d]);
                        lock (gradKLocks[lockIdx])
                        {
                            gradKData[kOffset + ki * headDim + d] = numOps.Add(
                                gradKData[kOffset + ki * headDim + d], gradK);
                        }
                    }
                }
            }
        });

        gradQuery = TensorAllocator.Rent<T>(query._shape, new Vector<T>(gradQData));
        gradKey = TensorAllocator.Rent<T>(key._shape, new Vector<T>(gradKData));
        gradValue = TensorAllocator.Rent<T>(value._shape, new Vector<T>(gradVData));

        return gradOutput;
    }

    /// <summary>
    /// Computes Graph Attention Network (GAT) style attention over graph nodes.
    /// </summary>
    public Tensor<T> GraphAttention<T>(
        Tensor<T> nodeFeatures,
        Tensor<int> edgeSourceIndices,
        Tensor<int> edgeTargetIndices,
        Tensor<T> attentionWeightSource,
        Tensor<T> attentionWeightTarget,
        double leakyReluAlpha,
        out Tensor<T> attentionCoeffs)
    {
        var numOps = MathHelper.GetNumericOperations<T>();

        int batchSize = nodeFeatures._shape[0];
        int numNodes = nodeFeatures._shape[1];
        int features = nodeFeatures._shape[2];
        int numEdges = edgeSourceIndices._shape[0];

        var nodeData = nodeFeatures.AsSpan();
        var srcIndices = edgeSourceIndices.AsSpan();
        var tgtIndices = edgeTargetIndices.AsSpan();
        var attnSrcData = attentionWeightSource.AsSpan();
        var attnTgtData = attentionWeightTarget.AsSpan();

        // Output tensors
        var outputData = new T[batchSize * numNodes * features];
        var coeffsData = new T[batchSize * numEdges];

        T alpha = numOps.FromDouble(leakyReluAlpha);

        for (int b = 0; b < batchSize; b++)
        {
            int batchOffset = b * numNodes * features;

            // Step 1: Compute attention scores for each edge
            var edgeScores = new T[numEdges];
            for (int e = 0; e < numEdges; e++)
            {
                int src = srcIndices[e];
                int tgt = tgtIndices[e];

                // Compute a_src^T @ h_src + a_tgt^T @ h_tgt
                T score = numOps.Zero;
                for (int f = 0; f < features; f++)
                {
                    T srcFeature = nodeData[batchOffset + src * features + f];
                    T tgtFeature = nodeData[batchOffset + tgt * features + f];
                    score = numOps.Add(score, numOps.Multiply(attnSrcData[f], srcFeature));
                    score = numOps.Add(score, numOps.Multiply(attnTgtData[f], tgtFeature));
                }

                // Apply LeakyReLU
                if (numOps.ToDouble(score) < 0)
                {
                    score = numOps.Multiply(alpha, score);
                }
                edgeScores[e] = score;
            }

            // Step 2: Compute softmax per target node (normalize over incoming edges)
            // First, group edges by target node
            var targetEdges = new System.Collections.Generic.Dictionary<int, System.Collections.Generic.List<int>>();
            for (int e = 0; e < numEdges; e++)
            {
                int tgt = tgtIndices[e];
                if (!targetEdges.ContainsKey(tgt))
                    targetEdges[tgt] = new System.Collections.Generic.List<int>();
                targetEdges[tgt].Add(e);
            }

            // Softmax per target node
            var attentionWeights = new T[numEdges];
            foreach (var kvp in targetEdges)
            {
                var edges = kvp.Value;

                // Find max for numerical stability
                double maxScore = double.MinValue;
                foreach (int e in edges)
                {
                    double s = numOps.ToDouble(edgeScores[e]);
                    if (s > maxScore) maxScore = s;
                }

                // Compute exp and sum
                double expSum = 0.0;
                var expScores = new double[edges.Count];
                for (int i = 0; i < edges.Count; i++)
                {
                    expScores[i] = Math.Exp(numOps.ToDouble(edgeScores[edges[i]]) - maxScore);
                    expSum += expScores[i];
                }

                // Normalize
                for (int i = 0; i < edges.Count; i++)
                {
                    attentionWeights[edges[i]] = numOps.FromDouble(expScores[i] / expSum);
                }
            }

            // Store attention coefficients
            for (int e = 0; e < numEdges; e++)
            {
                coeffsData[b * numEdges + e] = attentionWeights[e];
            }

            // Step 3: Aggregate features using attention weights
            // h'_i = sum_j alpha_ij * h_j (where j are neighbors of i)
            for (int e = 0; e < numEdges; e++)
            {
                int src = srcIndices[e];
                int tgt = tgtIndices[e];
                T weight = attentionWeights[e];

                for (int f = 0; f < features; f++)
                {
                    T srcFeature = nodeData[batchOffset + src * features + f];
                    T contribution = numOps.Multiply(weight, srcFeature);
                    outputData[batchOffset + tgt * features + f] = numOps.Add(
                        outputData[batchOffset + tgt * features + f], contribution);
                }
            }
        }

        attentionCoeffs = TensorAllocator.Rent<T>(new[] { batchSize, numEdges }, new Vector<T>(coeffsData));
        var gatResult = TensorAllocator.Rent<T>(nodeFeatures._shape, new Vector<T>(outputData));
        // Snapshot the edge-index tensors as portable int[] data + int[] shape
        // pairs so the savedState round-trips through SavedStateSerializer.
        // Saving Tensor<int> directly would throw at checkpoint time when the
        // tape's T is float/double — the serializer only matches Tensor<T>
        // for the tape's own T. attentionCoeffs is a freshly-allocated
        // Tensor<T> — safe to share. leakyReluAlpha is a value type.
        if (DifferentiableOps.IsTapeActiveForThread<T>())
        {
            var srcArr = edgeSourceIndices.GetFlattenedData();
            var tgtArr = edgeTargetIndices.GetFlattenedData();
            var srcSnap = new int[srcArr.Length];
            var tgtSnap = new int[tgtArr.Length];
            Array.Copy(srcArr, srcSnap, srcArr.Length);
            Array.Copy(tgtArr, tgtSnap, tgtArr.Length);
            var srcShape = (int[])edgeSourceIndices._shape.Clone();
            var tgtShape = (int[])edgeTargetIndices._shape.Clone();
            DifferentiableOps.RecordIfActive("GraphAttention", gatResult,
                new[] { nodeFeatures, attentionWeightSource, attentionWeightTarget },
                BackwardFunctions<T>.GraphAttentionBackward,
                new object[] { srcSnap, srcShape, tgtSnap, tgtShape, attentionCoeffs, leakyReluAlpha });
        }
        return gatResult;
    }

    /// <summary>
    /// Computes the backward pass for Graph Attention Network attention.
    /// </summary>
    public Tensor<T> GraphAttentionBackward<T>(
        Tensor<T> gradOutput,
        Tensor<T> nodeFeatures,
        Tensor<int> edgeSourceIndices,
        Tensor<int> edgeTargetIndices,
        Tensor<T> attentionWeightSource,
        Tensor<T> attentionWeightTarget,
        Tensor<T> attentionCoeffs,
        double leakyReluAlpha,
        out Tensor<T> gradNodeFeatures,
        out Tensor<T> gradAttentionWeightSource,
        out Tensor<T> gradAttentionWeightTarget)
    {
        var numOps = MathHelper.GetNumericOperations<T>();

        int batchSize = nodeFeatures._shape[0];
        int numNodes = nodeFeatures._shape[1];
        int features = nodeFeatures._shape[2];
        int numEdges = edgeSourceIndices._shape[0];

        var nodeData = nodeFeatures.AsSpan();
        var gradOutData = gradOutput.AsSpan();
        var srcIndices = edgeSourceIndices.AsSpan();
        var tgtIndices = edgeTargetIndices.AsSpan();
        var attnSrcData = attentionWeightSource.AsSpan();
        var attnTgtData = attentionWeightTarget.AsSpan();
        var coeffsData = attentionCoeffs.AsSpan();

        T alpha = numOps.FromDouble(leakyReluAlpha);

        var gradNodeData = new T[batchSize * numNodes * features];
        var gradAttnSrc = new T[features];
        var gradAttnTgt = new T[features];

        for (int b = 0; b < batchSize; b++)
        {
            int batchOffset = b * numNodes * features;
            int coeffsOffset = b * numEdges;

            // Group edges by target for softmax backward
            var targetEdges = new System.Collections.Generic.Dictionary<int, System.Collections.Generic.List<int>>();
            for (int e = 0; e < numEdges; e++)
            {
                int tgt = tgtIndices[e];
                if (!targetEdges.ContainsKey(tgt))
                    targetEdges[tgt] = new System.Collections.Generic.List<int>();
                targetEdges[tgt].Add(e);
            }

            // Compute gradients for each edge
            var gradCoeffs = new T[numEdges];

            // Gradient w.r.t. attention coefficients from aggregation
            // dL/d_alpha_ij = dL/d_h'_tgt @ h_src
            for (int e = 0; e < numEdges; e++)
            {
                int src = srcIndices[e];
                int tgt = tgtIndices[e];

                T gradCoeff = numOps.Zero;
                for (int f = 0; f < features; f++)
                {
                    T gradOutTgt = gradOutData[batchOffset + tgt * features + f];
                    T srcFeature = nodeData[batchOffset + src * features + f];
                    gradCoeff = numOps.Add(gradCoeff, numOps.Multiply(gradOutTgt, srcFeature));
                }
                gradCoeffs[e] = gradCoeff;
            }

            // Gradient w.r.t. node features from aggregation
            // dL/d_h_src += alpha_ij * dL/d_h'_tgt
            for (int e = 0; e < numEdges; e++)
            {
                int src = srcIndices[e];
                int tgt = tgtIndices[e];
                T coeff = coeffsData[coeffsOffset + e];

                for (int f = 0; f < features; f++)
                {
                    T gradOutTgt = gradOutData[batchOffset + tgt * features + f];
                    T contribution = numOps.Multiply(coeff, gradOutTgt);
                    gradNodeData[batchOffset + src * features + f] = numOps.Add(
                        gradNodeData[batchOffset + src * features + f], contribution);
                }
            }

            // Backprop through softmax per target node
            foreach (var kvp in targetEdges)
            {
                var edges = kvp.Value;

                // Softmax backward: dL/d_score_i = sum_j (alpha_i * (delta_ij - alpha_j)) * dL/d_alpha_j
                for (int i = 0; i < edges.Count; i++)
                {
                    int ei = edges[i];
                    T alphaI = coeffsData[coeffsOffset + ei];
                    T gradScore = numOps.Zero;

                    for (int j = 0; j < edges.Count; j++)
                    {
                        int ej = edges[j];
                        T alphaJ = coeffsData[coeffsOffset + ej];
                        T gradAlphaJ = gradCoeffs[ej];

                        T jacobian = i == j
                            ? numOps.Multiply(alphaI, numOps.Subtract(numOps.One, alphaJ))
                            : numOps.Negate(numOps.Multiply(alphaI, alphaJ));

                        gradScore = numOps.Add(gradScore, numOps.Multiply(jacobian, gradAlphaJ));
                    }

                    // Backprop through LeakyReLU
                    // Recompute score to check sign
                    int src = srcIndices[ei];
                    int tgt = tgtIndices[ei];
                    T score = numOps.Zero;
                    for (int f = 0; f < features; f++)
                    {
                        T srcFeature = nodeData[batchOffset + src * features + f];
                        T tgtFeature = nodeData[batchOffset + tgt * features + f];
                        score = numOps.Add(score, numOps.Multiply(attnSrcData[f], srcFeature));
                        score = numOps.Add(score, numOps.Multiply(attnTgtData[f], tgtFeature));
                    }

                    T leakyGrad = numOps.ToDouble(score) < 0 ? alpha : numOps.One;
                    gradScore = numOps.Multiply(gradScore, leakyGrad);

                    // Gradient w.r.t. attention weights
                    // dL/d_a_src += dL/d_score * h_src
                    // dL/d_a_tgt += dL/d_score * h_tgt
                    for (int f = 0; f < features; f++)
                    {
                        T srcFeature = nodeData[batchOffset + src * features + f];
                        T tgtFeature = nodeData[batchOffset + tgt * features + f];

                        gradAttnSrc[f] = numOps.Add(gradAttnSrc[f], numOps.Multiply(gradScore, srcFeature));
                        gradAttnTgt[f] = numOps.Add(gradAttnTgt[f], numOps.Multiply(gradScore, tgtFeature));

                        // Gradient w.r.t. node features through attention
                        T gradSrcFromAttn = numOps.Multiply(gradScore, attnSrcData[f]);
                        T gradTgtFromAttn = numOps.Multiply(gradScore, attnTgtData[f]);

                        gradNodeData[batchOffset + src * features + f] = numOps.Add(
                            gradNodeData[batchOffset + src * features + f], gradSrcFromAttn);
                        gradNodeData[batchOffset + tgt * features + f] = numOps.Add(
                            gradNodeData[batchOffset + tgt * features + f], gradTgtFromAttn);
                    }
                }
            }
        }

        gradNodeFeatures = TensorAllocator.Rent<T>(nodeFeatures._shape, new Vector<T>(gradNodeData));
        gradAttentionWeightSource = TensorAllocator.Rent<T>(attentionWeightSource._shape, new Vector<T>(gradAttnSrc));
        gradAttentionWeightTarget = TensorAllocator.Rent<T>(attentionWeightTarget._shape, new Vector<T>(gradAttnTgt));

        return gradOutput;
    }

    /// <summary>
    /// Computes multi-head Graph Attention with concatenation or averaging of heads.
    /// </summary>
    public Tensor<T> MultiHeadGraphAttention<T>(
        Tensor<T> nodeFeatures,
        Tensor<int> edgeSourceIndices,
        Tensor<int> edgeTargetIndices,
        Tensor<T> headWeights,
        Tensor<T> attentionWeightsSource,
        Tensor<T> attentionWeightsTarget,
        double leakyReluAlpha,
        bool concatenate,
        out Tensor<T> attentionCoeffs)
    {
        var numOps = MathHelper.GetNumericOperations<T>();

        int batchSize = nodeFeatures._shape[0];
        int numNodes = nodeFeatures._shape[1];
        int inFeatures = nodeFeatures._shape[2];
        int numHeads = headWeights._shape[0];
        int headDim = headWeights._shape[2];
        int numEdges = edgeSourceIndices._shape[0];

        var nodeData = nodeFeatures.AsSpan();
        var weightData = headWeights.AsSpan();
        var attnSrcData = attentionWeightsSource.AsSpan();
        var attnTgtData = attentionWeightsTarget.AsSpan();

        int outFeatures = concatenate ? numHeads * headDim : headDim;
        var outputData = new T[batchSize * numNodes * outFeatures];
        var allCoeffsData = new T[batchSize * numHeads * numEdges];

        for (int h = 0; h < numHeads; h++)
        {
            // Transform node features for this head: [batch, nodes, in_features] @ W_h -> [batch, nodes, head_dim]
            var transformedData = new T[batchSize * numNodes * headDim];

            for (int b = 0; b < batchSize; b++)
            {
                for (int n = 0; n < numNodes; n++)
                {
                    for (int d = 0; d < headDim; d++)
                    {
                        T sum = numOps.Zero;
                        for (int f = 0; f < inFeatures; f++)
                        {
                            int nodeIdx = b * numNodes * inFeatures + n * inFeatures + f;
                            int weightIdx = h * inFeatures * headDim + f * headDim + d;
                            sum = numOps.Add(sum, numOps.Multiply(nodeData[nodeIdx], weightData[weightIdx]));
                        }
                        transformedData[b * numNodes * headDim + n * headDim + d] = sum;
                    }
                }
            }

            // Extract attention weights for this head
            var headAttnSrc = new T[headDim];
            var headAttnTgt = new T[headDim];
            for (int d = 0; d < headDim; d++)
            {
                headAttnSrc[d] = attnSrcData[h * headDim + d];
                headAttnTgt[d] = attnTgtData[h * headDim + d];
            }

            // Create transformed tensor for this head
            var transformedTensor = TensorAllocator.Rent<T>(new[] { batchSize, numNodes, headDim }, new Vector<T>(transformedData));
            var headAttnSrcTensor = TensorAllocator.Rent<T>(new[] { headDim }, new Vector<T>(headAttnSrc));
            var headAttnTgtTensor = TensorAllocator.Rent<T>(new[] { headDim }, new Vector<T>(headAttnTgt));

            // Apply single-head GAT
            var headOutput = GraphAttention(
                transformedTensor,
                edgeSourceIndices,
                edgeTargetIndices,
                headAttnSrcTensor,
                headAttnTgtTensor,
                leakyReluAlpha,
                out var headCoeffs);

            var headOutputData = headOutput.AsSpan();
            var headCoeffsData = headCoeffs.AsSpan();

            // Store coefficients
            for (int b = 0; b < batchSize; b++)
            {
                for (int e = 0; e < numEdges; e++)
                {
                    allCoeffsData[b * numHeads * numEdges + h * numEdges + e] = headCoeffsData[b * numEdges + e];
                }
            }

            // Combine head outputs
            if (concatenate)
            {
                // Concatenate: place head output at appropriate offset
                for (int b = 0; b < batchSize; b++)
                {
                    for (int n = 0; n < numNodes; n++)
                    {
                        for (int d = 0; d < headDim; d++)
                        {
                            int srcIdx = b * numNodes * headDim + n * headDim + d;
                            int dstIdx = b * numNodes * outFeatures + n * outFeatures + h * headDim + d;
                            outputData[dstIdx] = headOutputData[srcIdx];
                        }
                    }
                }
            }
            else
            {
                // Average: accumulate and divide later
                for (int b = 0; b < batchSize; b++)
                {
                    for (int n = 0; n < numNodes; n++)
                    {
                        for (int d = 0; d < headDim; d++)
                        {
                            int idx = b * numNodes * headDim + n * headDim + d;
                            outputData[idx] = numOps.Add(outputData[idx], headOutputData[idx]);
                        }
                    }
                }
            }
        }

        // If averaging, divide by number of heads
        if (!concatenate)
        {
            T divisor = numOps.FromDouble(numHeads);
            for (int i = 0; i < outputData.Length; i++)
            {
                outputData[i] = numOps.Divide(outputData[i], divisor);
            }
        }

        attentionCoeffs = TensorAllocator.Rent<T>(new[] { batchSize, numHeads, numEdges }, new Vector<T>(allCoeffsData));
        return TensorAllocator.Rent<T>(new[] { batchSize, numNodes, outFeatures }, new Vector<T>(outputData));
    }


    #endregion

    #region Scatter Operations (Graph Neural Networks)

    /// <summary>
    /// Scatter add: Aggregates source values at indices using addition.
    /// Used in GNN message passing for sum aggregation.
    /// </summary>
    public Tensor<T> ScatterAdd<T>(Tensor<T> source, Tensor<int> indices, int dim = 0, int? outputSize = null)
    {
        if (source == null)
            throw new ArgumentNullException(nameof(source));
        if (indices == null)
            throw new ArgumentNullException(nameof(indices));
        if (GraphMode.IsActive) { var scope = GraphMode.Current; if (scope is not null) { var c_source = source; var c_indices = indices; var c_dim = dim; var c_outputSize = outputSize; return scope.RecordUnary(LazyNodeType.Custom, "ScatterAdd", source, source._shape, (eng, output) => { var r = eng.ScatterAdd(c_source, c_indices, c_dim, c_outputSize); r.AsSpan().CopyTo(output.AsWritableSpan()); }, BackwardFunctions<T>.ScatterAddBackward); } }
        { var ac = AutoTracer.TryGetCompiledPlan<T>("ScatterAdd", source._shape); if (ac is not null) return ac.Execute(); }

        var numOps = MathHelper.GetNumericOperations<T>();

        // Handle negative dimension
        int actualDim = dim < 0 ? source.Rank + dim : dim;
        if (actualDim < 0 || actualDim >= source.Rank)
            throw new ArgumentException($"Invalid dimension {dim} for tensor with rank {source.Rank}");

        // Determine output size along scatter dimension
        var indicesData = indices.GetFlattenedData();
        int maxIndex = 0;
        for (int i = 0; i < indicesData.Length; i++)
        {
            if (indicesData[i] > maxIndex) maxIndex = indicesData[i];
        }
        int outDimSize = outputSize ?? (maxIndex + 1);

        // Build output shape
        var outputShape = source.Shape.ToArray();
        outputShape[actualDim] = outDimSize;

        var sourceData = source.GetFlattenedData();
        var outputData = new T[outputShape.Aggregate(1, (a, b) => a * b)];

        // Initialize to zero
        for (int i = 0; i < outputData.Length; i++)
            outputData[i] = numOps.Zero;

        // Calculate strides
        int innerSize = 1;
        for (int i = actualDim + 1; i < source.Rank; i++)
            innerSize *= source._shape[i];

        int outerSize = 1;
        for (int i = 0; i < actualDim; i++)
            outerSize *= source._shape[i];

        int srcDimSize = source._shape[actualDim];

        // Scatter add
        for (int outer = 0; outer < outerSize; outer++)
        {
            for (int d = 0; d < srcDimSize; d++)
            {
                int targetIdx = indicesData[d % indicesData.Length];
                if (targetIdx < 0 || targetIdx >= outDimSize) continue;

                for (int inner = 0; inner < innerSize; inner++)
                {
                    int srcIdx = outer * srcDimSize * innerSize + d * innerSize + inner;
                    int dstIdx = outer * outDimSize * innerSize + targetIdx * innerSize + inner;
                    outputData[dstIdx] = numOps.Add(outputData[dstIdx], sourceData[srcIdx]);
                }
            }
        }

        var scatterAddResult = TensorAllocator.Rent<T>(outputShape, new Vector<T>(outputData));
        DifferentiableOps.RecordUnary("ScatterAdd", scatterAddResult, source, BackwardFunctions<T>.ScatterAddBackward, new object[] { indices, actualDim });
        { var cs = source; var ci = indices; var cd = dim; var co = outputSize; AutoTracer.RecordOp("ScatterAdd", scatterAddResult, eng => eng.ScatterAdd(cs, ci, cd, co)); }
        return scatterAddResult;
    }

    /// <summary>
    /// Backward pass for scatter add.
    /// </summary>
    public Tensor<T> ScatterAddBackward<T>(Tensor<T> gradOutput, Tensor<int> indices, int[] sourceShape, int dim = 0)
    {
        if (gradOutput == null)
            throw new ArgumentNullException(nameof(gradOutput));
        if (indices == null)
            throw new ArgumentNullException(nameof(indices));
        var indicesOrig = indices;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!indices.IsContiguous) indices = indices.Contiguous();

        var numOps = MathHelper.GetNumericOperations<T>();

        int actualDim = dim < 0 ? sourceShape.Length + dim : dim;

        var gradOutData = gradOutput.GetFlattenedData();
        var indicesData = indices.GetFlattenedData();
        var gradInputData = new T[sourceShape.Aggregate(1, (a, b) => a * b)];

        int innerSize = 1;
        for (int i = actualDim + 1; i < sourceShape.Length; i++)
            innerSize *= sourceShape[i];

        int outerSize = 1;
        for (int i = 0; i < actualDim; i++)
            outerSize *= sourceShape[i];

        int srcDimSize = sourceShape[actualDim];
        int outDimSize = gradOutput._shape[actualDim];

        // Gather gradients back
        for (int outer = 0; outer < outerSize; outer++)
        {
            for (int d = 0; d < srcDimSize; d++)
            {
                int targetIdx = indicesData[d % indicesData.Length];
                if (targetIdx < 0 || targetIdx >= outDimSize) continue;

                for (int inner = 0; inner < innerSize; inner++)
                {
                    int srcIdx = outer * srcDimSize * innerSize + d * innerSize + inner;
                    int dstIdx = outer * outDimSize * innerSize + targetIdx * innerSize + inner;
                    gradInputData[srcIdx] = gradOutData[dstIdx];
                }
            }
        }

        return TensorAllocator.Rent<T>(sourceShape, new Vector<T>(gradInputData));
    }

    /// <summary>
    /// Scatter mean: Aggregates source values at indices using mean.
    /// </summary>
    public virtual Tensor<T> ScatterMean<T>(Tensor<T> source, Tensor<int> indices, out Tensor<int>? counts, int dim = 0, int? outputSize = null)
    {
        if (source == null)
            throw new ArgumentNullException(nameof(source));
        if (indices == null)
            throw new ArgumentNullException(nameof(indices));

        if (GraphMode.IsActive)
        {
            var scope = GraphMode.Current;
            if (scope != null)
            {
                var cs = source; var ci = indices; int cd = dim; int? co = outputSize;
                var savedScope = GraphMode.Current;
                GraphMode.SetCurrent(null);
                var eagerResult = ScatterMean(cs, ci, out counts, cd, co);
                GraphMode.SetCurrent(savedScope);
                var lazyResult = scope.RecordUnary(LazyNodeType.Custom, "ScatterMean", source, eagerResult._shape,
                    (eng, output) => { var r = eng.ScatterMean(cs, ci, out _, cd, co); r.AsSpan().CopyTo(output.AsWritableSpan()); },
                    BackwardFunctions<T>.ScatterMeanBackward, new object[] { indices, dim });
                eagerResult.AsSpan().CopyTo(lazyResult.AsWritableSpan());
                return lazyResult;
            }
        }

        var numOps = MathHelper.GetNumericOperations<T>();

        int actualDim = dim < 0 ? source.Rank + dim : dim;

        var indicesData = indices.GetFlattenedData();
        int maxIndex = 0;
        for (int i = 0; i < indicesData.Length; i++)
        {
            if (indicesData[i] > maxIndex) maxIndex = indicesData[i];
        }
        int outDimSize = outputSize ?? (maxIndex + 1);

        var outputShape = source.Shape.ToArray();
        outputShape[actualDim] = outDimSize;

        var sourceData = source.GetFlattenedData();
        var outputData = new T[outputShape.Aggregate(1, (a, b) => a * b)];
        var countData = new int[outDimSize];

        int innerSize = 1;
        for (int i = actualDim + 1; i < source.Rank; i++)
            innerSize *= source._shape[i];

        int outerSize = 1;
        for (int i = 0; i < actualDim; i++)
            outerSize *= source._shape[i];

        int srcDimSize = source._shape[actualDim];

        if (typeof(T) == typeof(float))
        {
            var fSource = (float[])(object)sourceData;
            var fOutput = (float[])(object)outputData;
            Array.Clear(fOutput, 0, fOutput.Length);

            for (int outer = 0; outer < outerSize; outer++)
            {
                for (int d = 0; d < srcDimSize; d++)
                {
                    int targetIdx = indicesData[d % indicesData.Length];
                    if (targetIdx < 0 || targetIdx >= outDimSize) continue;
                    if (outer == 0) countData[targetIdx]++;
                    int srcBase = outer * srcDimSize * innerSize + d * innerSize;
                    int dstBase = outer * outDimSize * innerSize + targetIdx * innerSize;
                    for (int inner = 0; inner < innerSize; inner++)
                        fOutput[dstBase + inner] += fSource[srcBase + inner];
                }
            }

            for (int outer = 0; outer < outerSize; outer++)
            {
                for (int d = 0; d < outDimSize; d++)
                {
                    if (countData[d] > 0)
                    {
                        float invDivisor = 1f / countData[d];
                        int baseIdx = outer * outDimSize * innerSize + d * innerSize;
                        for (int inner = 0; inner < innerSize; inner++)
                            fOutput[baseIdx + inner] *= invDivisor;
                    }
                }
            }
        }
        else if (typeof(T) == typeof(double))
        {
            var dSource = (double[])(object)sourceData;
            var dOutput = (double[])(object)outputData;
            Array.Clear(dOutput, 0, dOutput.Length);

            for (int outer = 0; outer < outerSize; outer++)
            {
                for (int d = 0; d < srcDimSize; d++)
                {
                    int targetIdx = indicesData[d % indicesData.Length];
                    if (targetIdx < 0 || targetIdx >= outDimSize) continue;
                    if (outer == 0) countData[targetIdx]++;
                    int srcBase = outer * srcDimSize * innerSize + d * innerSize;
                    int dstBase = outer * outDimSize * innerSize + targetIdx * innerSize;
                    for (int inner = 0; inner < innerSize; inner++)
                        dOutput[dstBase + inner] += dSource[srcBase + inner];
                }
            }

            for (int outer = 0; outer < outerSize; outer++)
            {
                for (int d = 0; d < outDimSize; d++)
                {
                    if (countData[d] > 0)
                    {
                        double invDivisor = 1.0 / countData[d];
                        int baseIdx = outer * outDimSize * innerSize + d * innerSize;
                        for (int inner = 0; inner < innerSize; inner++)
                            dOutput[baseIdx + inner] *= invDivisor;
                    }
                }
            }
        }
        else
        {
            // Initialize
            for (int i = 0; i < outputData.Length; i++)
                outputData[i] = numOps.Zero;

            // Sum and count
            for (int outer = 0; outer < outerSize; outer++)
            {
                for (int d = 0; d < srcDimSize; d++)
                {
                    int targetIdx = indicesData[d % indicesData.Length];
                    if (targetIdx < 0 || targetIdx >= outDimSize) continue;

                    if (outer == 0) countData[targetIdx]++;

                    for (int inner = 0; inner < innerSize; inner++)
                    {
                        int srcIdx = outer * srcDimSize * innerSize + d * innerSize + inner;
                        int dstIdx = outer * outDimSize * innerSize + targetIdx * innerSize + inner;
                        outputData[dstIdx] = numOps.Add(outputData[dstIdx], sourceData[srcIdx]);
                    }
                }
            }

            // Divide by counts
            for (int outer = 0; outer < outerSize; outer++)
            {
                for (int d = 0; d < outDimSize; d++)
                {
                    if (countData[d] > 0)
                    {
                        T divisor = numOps.FromDouble(countData[d]);
                        for (int inner = 0; inner < innerSize; inner++)
                        {
                            int idx = outer * outDimSize * innerSize + d * innerSize + inner;
                            outputData[idx] = numOps.Divide(outputData[idx], divisor);
                        }
                    }
                }
            }
        }

        counts = new Tensor<int>([outDimSize], new Vector<int>(countData));
        var scatterMeanResult = TensorAllocator.Rent<T>(outputShape, new Vector<T>(outputData));
        DifferentiableOps.RecordUnary("ScatterMean", scatterMeanResult, source, BackwardFunctions<T>.ScatterMeanBackward, new object[] { indices, counts });
        { var cs = source; var ci = indices; var cd = dim; var co = outputSize; AutoTracer.RecordOp("ScatterMean", scatterMeanResult, eng => { eng.ScatterMean(cs, ci, out _, cd, co); return scatterMeanResult; }); }
        return scatterMeanResult;
    }

    /// <summary>
    /// Backward pass for scatter mean.
    /// </summary>
    public Tensor<T> ScatterMeanBackward<T>(Tensor<T> gradOutput, Tensor<int> indices, Tensor<int> counts, int[] sourceShape, int dim = 0)
    {
        if (gradOutput == null)
            throw new ArgumentNullException(nameof(gradOutput));
        if (indices == null)
            throw new ArgumentNullException(nameof(indices));
        if (counts == null)
            throw new ArgumentNullException(nameof(counts));
        var indicesOrig = indices;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!indices.IsContiguous) indices = indices.Contiguous();

        var numOps = MathHelper.GetNumericOperations<T>();

        int actualDim = dim < 0 ? sourceShape.Length + dim : dim;

        var gradOutData = gradOutput.GetFlattenedData();
        var indicesData = indices.GetFlattenedData();
        var countsData = counts.GetFlattenedData();
        var gradInputData = new T[sourceShape.Aggregate(1, (a, b) => a * b)];

        int innerSize = 1;
        for (int i = actualDim + 1; i < sourceShape.Length; i++)
            innerSize *= sourceShape[i];

        int outerSize = 1;
        for (int i = 0; i < actualDim; i++)
            outerSize *= sourceShape[i];

        int srcDimSize = sourceShape[actualDim];
        int outDimSize = gradOutput._shape[actualDim];

        for (int outer = 0; outer < outerSize; outer++)
        {
            for (int d = 0; d < srcDimSize; d++)
            {
                int targetIdx = indicesData[d % indicesData.Length];
                if (targetIdx < 0 || targetIdx >= outDimSize) continue;

                int count = countsData[targetIdx];
                T divisor = count > 0 ? numOps.FromDouble(count) : numOps.One;

                for (int inner = 0; inner < innerSize; inner++)
                {
                    int srcIdx = outer * srcDimSize * innerSize + d * innerSize + inner;
                    int dstIdx = outer * outDimSize * innerSize + targetIdx * innerSize + inner;
                    gradInputData[srcIdx] = numOps.Divide(gradOutData[dstIdx], divisor);
                }
            }
        }

        return TensorAllocator.Rent<T>(sourceShape, new Vector<T>(gradInputData));
    }

    /// <summary>
    /// Scatter max: Aggregates source values at indices using maximum.
    /// </summary>
    public Tensor<T> ScatterMax<T>(Tensor<T> source, Tensor<int> indices, out Tensor<int>? argmax, int dim = 0, int? outputSize = null)
    {
        if (source == null)
            throw new ArgumentNullException(nameof(source));
        if (indices == null)
            throw new ArgumentNullException(nameof(indices));

        var numOps = MathHelper.GetNumericOperations<T>();

        int actualDim = dim < 0 ? source.Rank + dim : dim;

        var indicesData = indices.GetFlattenedData();
        int maxIndex = 0;
        for (int i = 0; i < indicesData.Length; i++)
        {
            if (indicesData[i] > maxIndex) maxIndex = indicesData[i];
        }
        int outDimSize = outputSize ?? (maxIndex + 1);

        var outputShape = source.Shape.ToArray();
        outputShape[actualDim] = outDimSize;

        var sourceData = source.GetFlattenedData();
        int outputLength = outputShape.Aggregate(1, (a, b) => a * b);
        var outputData = new T[outputLength];
        var argmaxData = new int[outputLength];

        // Initialize to negative infinity and -1
        T negInf = numOps.FromDouble(double.NegativeInfinity);
        for (int i = 0; i < outputData.Length; i++)
        {
            outputData[i] = negInf;
            argmaxData[i] = -1;
        }

        int innerSize = 1;
        for (int i = actualDim + 1; i < source.Rank; i++)
            innerSize *= source._shape[i];

        int outerSize = 1;
        for (int i = 0; i < actualDim; i++)
            outerSize *= source._shape[i];

        int srcDimSize = source._shape[actualDim];

        // Find max
        for (int outer = 0; outer < outerSize; outer++)
        {
            for (int d = 0; d < srcDimSize; d++)
            {
                int targetIdx = indicesData[d % indicesData.Length];
                if (targetIdx < 0 || targetIdx >= outDimSize) continue;

                for (int inner = 0; inner < innerSize; inner++)
                {
                    int srcIdx = outer * srcDimSize * innerSize + d * innerSize + inner;
                    int dstIdx = outer * outDimSize * innerSize + targetIdx * innerSize + inner;

                    if (numOps.GreaterThan(sourceData[srcIdx], outputData[dstIdx]))
                    {
                        outputData[dstIdx] = sourceData[srcIdx];
                        argmaxData[dstIdx] = d;
                    }
                }
            }
        }

        argmax = new Tensor<int>(outputShape, new Vector<int>(argmaxData));
        var scatterMaxResult = TensorAllocator.Rent<T>(outputShape, new Vector<T>(outputData));
        DifferentiableOps.RecordUnary("ScatterMax", scatterMaxResult, source, BackwardFunctions<T>.ScatterMaxBackward, new object[] { indices, argmax });
        { var cs = source; var ci = indices; var cd = dim; var co = outputSize; AutoTracer.RecordOp("ScatterMax", scatterMaxResult, eng => { eng.ScatterMax(cs, ci, out _, cd, co); return scatterMaxResult; }); }
        return scatterMaxResult;
    }

    /// <summary>
    /// Backward pass for scatter max.
    /// </summary>
    public Tensor<T> ScatterMaxBackward<T>(Tensor<T> gradOutput, Tensor<int> argmax, int[] sourceShape, int dim = 0)
    {
        if (gradOutput == null)
            throw new ArgumentNullException(nameof(gradOutput));
        if (argmax == null)
            throw new ArgumentNullException(nameof(argmax));

        var numOps = MathHelper.GetNumericOperations<T>();

        int actualDim = dim < 0 ? sourceShape.Length + dim : dim;

        var gradOutData = gradOutput.GetFlattenedData();
        var argmaxData = argmax.GetFlattenedData();
        var gradInputData = new T[sourceShape.Aggregate(1, (a, b) => a * b)];

        // Initialize to zero
        for (int i = 0; i < gradInputData.Length; i++)
            gradInputData[i] = numOps.Zero;

        int innerSize = 1;
        for (int i = actualDim + 1; i < sourceShape.Length; i++)
            innerSize *= sourceShape[i];

        int outerSize = 1;
        for (int i = 0; i < actualDim; i++)
            outerSize *= sourceShape[i];

        int srcDimSize = sourceShape[actualDim];
        int outDimSize = gradOutput._shape[actualDim];

        // Route gradients to argmax positions
        for (int outer = 0; outer < outerSize; outer++)
        {
            for (int d = 0; d < outDimSize; d++)
            {
                for (int inner = 0; inner < innerSize; inner++)
                {
                    int dstIdx = outer * outDimSize * innerSize + d * innerSize + inner;
                    int srcD = argmaxData[dstIdx];
                    if (srcD >= 0 && srcD < srcDimSize)
                    {
                        int srcIdx = outer * srcDimSize * innerSize + srcD * innerSize + inner;
                        gradInputData[srcIdx] = gradOutData[dstIdx];
                    }
                }
            }
        }

        return TensorAllocator.Rent<T>(sourceShape, new Vector<T>(gradInputData));
    }

    /// <summary>
    /// Scatter softmax: Applies softmax within each group defined by indices.
    /// </summary>
    public Tensor<T> ScatterSoftmax<T>(Tensor<T> source, Tensor<int> indices, int dim = 0, int? outputSize = null)
    {
        if (source == null)
            throw new ArgumentNullException(nameof(source));
        if (indices == null)
            throw new ArgumentNullException(nameof(indices));

        if (GraphMode.IsActive) { var scope = GraphMode.Current; if (scope is not null) { var cs = source; var ci = indices; var cd = dim; var co = outputSize; return scope.RecordUnary(LazyNodeType.Custom, "ScatterSoftmax", source, source._shape, (eng, output) => { var r = eng.ScatterSoftmax(cs, ci, cd, co); r.AsSpan().CopyTo(output.AsWritableSpan()); }, BackwardFunctions<T>.ScatterSoftmaxBackward); } }

        { var ac = AutoTracer.TryGetCompiledPlan<T>("ScatterSoftmax", source._shape); if (ac is not null) return ac.Execute(); }

        var numOps = MathHelper.GetNumericOperations<T>();

        int actualDim = dim < 0 ? source.Rank + dim : dim;

        var indicesData = indices.GetFlattenedData();
        int maxIndex = 0;
        for (int i = 0; i < indicesData.Length; i++)
        {
            if (indicesData[i] > maxIndex) maxIndex = indicesData[i];
        }
        int numGroups = outputSize ?? (maxIndex + 1);

        var sourceData = source.GetFlattenedData();
        var outputData = new T[source.Length];

        int innerSize = 1;
        for (int i = actualDim + 1; i < source.Rank; i++)
            innerSize *= source._shape[i];

        int outerSize = 1;
        for (int i = 0; i < actualDim; i++)
            outerSize *= source._shape[i];

        int srcDimSize = source._shape[actualDim];

        // For each outer/inner position, compute softmax per group
        for (int outer = 0; outer < outerSize; outer++)
        {
            for (int inner = 0; inner < innerSize; inner++)
            {
                // Find max per group for numerical stability
                var maxPerGroup = new T[numGroups];
                T negInf = numOps.FromDouble(double.NegativeInfinity);
                for (int g = 0; g < numGroups; g++) maxPerGroup[g] = negInf;

                for (int d = 0; d < srcDimSize; d++)
                {
                    int idx = outer * srcDimSize * innerSize + d * innerSize + inner;
                    int group = indicesData[d % indicesData.Length];
                    if (group >= 0 && group < numGroups && numOps.GreaterThan(sourceData[idx], maxPerGroup[group]))
                    {
                        maxPerGroup[group] = sourceData[idx];
                    }
                }

                // Compute exp and sum per group
                var sumPerGroup = new T[numGroups];
                for (int g = 0; g < numGroups; g++) sumPerGroup[g] = numOps.Zero;

                for (int d = 0; d < srcDimSize; d++)
                {
                    int idx = outer * srcDimSize * innerSize + d * innerSize + inner;
                    int group = indicesData[d % indicesData.Length];
                    if (group >= 0 && group < numGroups)
                    {
                        T expVal = numOps.Exp(numOps.Subtract(sourceData[idx], maxPerGroup[group]));
                        outputData[idx] = expVal;
                        sumPerGroup[group] = numOps.Add(sumPerGroup[group], expVal);
                    }
                }

                // Normalize
                for (int d = 0; d < srcDimSize; d++)
                {
                    int idx = outer * srcDimSize * innerSize + d * innerSize + inner;
                    int group = indicesData[d % indicesData.Length];
                    if (group >= 0 && group < numGroups && !numOps.Equals(sumPerGroup[group], numOps.Zero))
                    {
                        outputData[idx] = numOps.Divide(outputData[idx], sumPerGroup[group]);
                    }
                }
            }
        }

        var scatterSmResult = TensorAllocator.Rent<T>(source._shape, new Vector<T>(outputData));
        DifferentiableOps.RecordUnary("ScatterSoftmax", scatterSmResult, source, BackwardFunctions<T>.ScatterSoftmaxBackward, new object[] { indices });
        { var cs2 = source; var ci2 = indices; AutoTracer.RecordOp("ScatterSoftmax", scatterSmResult, eng => eng.ScatterSoftmax(cs2, ci2, dim, outputSize)); }
        return scatterSmResult;
    }

    /// <summary>
    /// Backward pass for scatter softmax.
    /// </summary>
    public Tensor<T> ScatterSoftmaxBackward<T>(Tensor<T> gradOutput, Tensor<T> output, Tensor<int> indices, int dim = 0)
    {
        if (gradOutput == null)
            throw new ArgumentNullException(nameof(gradOutput));
        if (output == null)
            throw new ArgumentNullException(nameof(output));
        if (indices == null)
            throw new ArgumentNullException(nameof(indices));
        if (!output.IsContiguous) throw new InvalidOperationException("Output tensor must be contiguous.");

        var numOps = MathHelper.GetNumericOperations<T>();

        int actualDim = dim < 0 ? output.Rank + dim : dim;

        var indicesData = indices.GetFlattenedData();
        int maxIndex = 0;
        for (int i = 0; i < indicesData.Length; i++)
        {
            if (indicesData[i] > maxIndex) maxIndex = indicesData[i];
        }
        int numGroups = maxIndex + 1;

        var gradOutData = gradOutput.GetFlattenedData();
        var outData = output.GetDataArray();
        var gradInputData = new T[gradOutData.Length];

        int innerSize = 1;
        for (int i = actualDim + 1; i < output.Rank; i++)
            innerSize *= output._shape[i];

        int outerSize = 1;
        for (int i = 0; i < actualDim; i++)
            outerSize *= output._shape[i];

        int srcDimSize = output._shape[actualDim];

        // Softmax backward: grad_input = output * (grad_output - sum(output * grad_output))
        for (int outer = 0; outer < outerSize; outer++)
        {
            for (int inner = 0; inner < innerSize; inner++)
            {
                // Compute sum(output * grad_output) per group
                var sumPerGroup = new T[numGroups];
                for (int g = 0; g < numGroups; g++) sumPerGroup[g] = numOps.Zero;

                for (int d = 0; d < srcDimSize; d++)
                {
                    int idx = outer * srcDimSize * innerSize + d * innerSize + inner;
                    int group = indicesData[d % indicesData.Length];
                    if (group >= 0 && group < numGroups)
                    {
                        sumPerGroup[group] = numOps.Add(sumPerGroup[group], numOps.Multiply(outData[idx], gradOutData[idx]));
                    }
                }

                // Compute gradient
                for (int d = 0; d < srcDimSize; d++)
                {
                    int idx = outer * srcDimSize * innerSize + d * innerSize + inner;
                    int group = indicesData[d % indicesData.Length];
                    if (group >= 0 && group < numGroups)
                    {
                        gradInputData[idx] = numOps.Multiply(outData[idx], numOps.Subtract(gradOutData[idx], sumPerGroup[group]));
                    }
                }
            }
        }

        return TensorAllocator.Rent<T>(output._shape, new Vector<T>(gradInputData));
    }

    #endregion


    #region Tensor Reduction Operations

    /// <summary>
    /// Validates and normalizes reduction axes.
    /// </summary>
    /// <param name="axes">The axes to validate</param>
    /// <param name="rank">The tensor rank</param>
    /// <returns>Normalized, validated, and sorted unique axes</returns>
    private static int[] ValidateAndNormalizeAxes(int[] axes, int rank)
    {
        if (axes == null)
            throw new ArgumentNullException(nameof(axes), "Axes cannot be null");

        if (axes.Length == 0)
            throw new ArgumentException("Axes array cannot be empty", nameof(axes));

        var normalizedAxes = new int[axes.Length];
        for (int i = 0; i < axes.Length; i++)
        {
            int axis = axes[i];
            // Normalize negative indices
            int normalized = axis < 0 ? rank + axis : axis;

            if (normalized < 0 || normalized >= rank)
                throw new ArgumentOutOfRangeException(nameof(axes), $"Axis {axis} is out of range for tensor with rank {rank}. Valid range is [{-rank}, {rank - 1}].");

            normalizedAxes[i] = normalized;
        }

        // Check for duplicates
        var uniqueAxes = normalizedAxes.Distinct().ToArray();
        if (uniqueAxes.Length != axes.Length)
            throw new ArgumentException("Duplicate axes are not allowed", nameof(axes));

        return uniqueAxes.OrderBy(a => a).ToArray();
    }

    /// <inheritdoc/>
    public Tensor<T> ReduceMax<T>(Tensor<T> input, int[] axes, bool keepDims, out int[] maxIndices)
    {
        // GraphMode: record lazy node for compiled plan
        if (GraphMode.IsActive)
        {
            var scope = GraphMode.Current;
            if (scope != null)
            {
                // Compute output shape
                var effectiveAxes = axes ?? Enumerable.Range(0, input.Rank).ToArray();
                var normAxes = new HashSet<int>(effectiveAxes.Select(a => a < 0 ? input.Rank + a : a));
                var outShapeList = new List<int>();
                for (int d = 0; d < input.Rank; d++)
                {
                    if (normAxes.Contains(d)) { if (keepDims) outShapeList.Add(1); }
                    else outShapeList.Add(input._shape[d]);
                }
                var outShape = outShapeList.Count > 0 ? outShapeList.ToArray() : new[] { 1 };

                var capturedInput = input;
                var capturedAxes = axes;
                bool capturedKeepDims = keepDims;
                // For backward, we need maxIndices. Compute via the execute delegate
                // at replay time (avoids recursive call during GraphMode recording).
                maxIndices = Array.Empty<int>();
                var capturedEffectiveAxes = effectiveAxes.ToArray();
                // savedState[0] will be populated with maxIndices at execute time.
                // The execute delegate must bypass GraphMode to avoid infinite recursion.
                var savedStateArr = new object[] { Array.Empty<int>() };
                var capturedSelf = this;
                return scope.RecordUnary(LazyNodeType.Custom, "ReduceMax", input, outShape,
                    (eng, output) =>
                    {
                        // Call ReduceMax on captured 'this' after GraphMode check has already
                        // been handled — the lazy node's execute runs outside scope.Current.
                        // Use the eager path by materializing input first.
                        var materializedInput = capturedInput.IsContiguous ? capturedInput : capturedInput.Contiguous();
                        var numOps = MathHelper.GetNumericOperations<T>();
                        var inputData = materializedInput.GetFlattenedData();
                        T maxVal = inputData[0];
                        int maxIdx = 0;
                        for (int k = 1; k < inputData.Length; k++)
                        {
                            if (numOps.ToDouble(inputData[k]) > numOps.ToDouble(maxVal))
                            {
                                maxVal = inputData[k];
                                maxIdx = k;
                            }
                        }
                        output.GetDataArray()[0] = maxVal;
                        savedStateArr[0] = new[] { maxIdx };
                    },
                    BackwardFunctions<T>.ReduceMaxBackward,
                    savedStateArr);
            }
        }

        // Stride-aware single-axis max
        if (!input.IsContiguous && axes.Length == 1)
        {
            var ops = MathHelper.GetNumericOperations<T>();
            int axis = axes[0] < 0 ? input.Rank + axes[0] : axes[0];
            if (axis < 0 || axis >= input.Rank) throw new ArgumentOutOfRangeException(nameof(axes), $"Axis {axes[0]} out of range for rank {input.Rank}");
            var (outerSize, axisSize, innerSize) = input.GetReductionDims(axis);
            var outShape = new List<int>();
            for (int d = 0; d < input.Rank; d++) { if (d == axis) { if (keepDims) outShape.Add(1); } else outShape.Add(input._shape[d]); }
            var result = AutoTensorCache.RentOrAllocate<T>(outShape.ToArray());
            var rArr = result.GetDataArray(); var srcArr = input._storage.GetDataArray();
            maxIndices = new int[outerSize * innerSize];
            for (int o = 0; o < outerSize; o++)
                for (int inner = 0; inner < innerSize; inner++)
                {
                    T best = srcArr[input.ReductionStorageIndex(o, 0, inner, axis)]; int bestIdx = 0;
                    for (int a = 1; a < axisSize; a++) { T v = srcArr[input.ReductionStorageIndex(o, a, inner, axis)]; if (ops.GreaterThan(v, best)) { best = v; bestIdx = a; } }
                    rArr[o * innerSize + inner] = best;
                    maxIndices[o * innerSize + inner] = bestIdx;
                }
            return result;
        }
        var numOps = MathHelper.GetNumericOperations<T>();
        var inputShape = input._shape;

        // Fast path: 1D full reduction
        if (input.Rank == 1 && axes.Length == 1 && (axes[0] == 0 || axes[0] == -1))
        {
            if (typeof(T) == typeof(float) && input.IsContiguous)
            {
                var fData = (float[])(object)input.GetDataArray();
                float maxVal = float.MinValue;
                int maxIdx = 0;
                for (int i = 0; i < fData.Length; i++)
                    if (fData[i] > maxVal) { maxVal = fData[i]; maxIdx = i; }
                maxIndices = new[] { maxIdx };
                float fMax = maxVal;
                return TensorAllocator.Rent<T>(keepDims ? new[] { 1 } : new[] { 1 },
                    new Vector<T>(new[] { Unsafe.As<float, T>(ref fMax) }));
            }
        }

        var inputData = input.GetFlattenedData();

        // Validate and normalize axes
        var normalizedAxes = ValidateAndNormalizeAxes(axes, inputShape.Length);

        // Compute output shape
        var outputShapeList = new List<int>();
        for (int i = 0; i < inputShape.Length; i++)
        {
            if (normalizedAxes.Contains(i))
            {
                if (keepDims) outputShapeList.Add(1);
            }
            else
            {
                outputShapeList.Add(inputShape[i]);
            }
        }
        var outputShape = outputShapeList.Count > 0 ? outputShapeList.ToArray() : [1];

        int outputSize = outputShape.Aggregate(1, (a, b) => a * b);
        var outputData = new T[outputSize];
        maxIndices = new int[outputSize];

        // Initialize with minimum values
        T minVal = numOps.MinValue;
        for (int i = 0; i < outputSize; i++)
        {
            outputData[i] = minVal;
            maxIndices[i] = -1;
        }

        var inputStrides = ComputeStrides(inputShape);
        var outputStrides = ComputeStrides(outputShape);

        for (int i = 0; i < input.Length; i++)
        {
            var multiIndex = FlatToMultiIndex(i, inputShape, inputStrides);

            var outputMultiIndex = new List<int>();
            for (int d = 0; d < inputShape.Length; d++)
            {
                if (normalizedAxes.Contains(d))
                {
                    if (keepDims) outputMultiIndex.Add(0);
                }
                else
                {
                    outputMultiIndex.Add(multiIndex[d]);
                }
            }
            if (outputMultiIndex.Count == 0) outputMultiIndex.Add(0);

            int outputIdx = MultiToFlatIndex([.. outputMultiIndex], outputShape, outputStrides);

            if (numOps.GreaterThan(inputData[i], outputData[outputIdx]))
            {
                outputData[outputIdx] = inputData[i];
                maxIndices[outputIdx] = i;
            }
        }

        var reduceMaxResult = TensorAllocator.Rent<T>(outputShape, new Vector<T>(outputData));
        DifferentiableOps.RecordUnary("ReduceMax", reduceMaxResult, input, BackwardFunctions<T>.ReduceMaxBackward, new object[] { maxIndices });
        { var ci = input; var ca = axes; var ck = keepDims; AutoTracer.RecordOp("ReduceMax", reduceMaxResult, eng => { eng.ReduceMax(ci, ca, ck, out _); return reduceMaxResult; }); }
        return reduceMaxResult;
    }

    /// <inheritdoc/>
    public Tensor<T> ReduceMaxBackward<T>(Tensor<T> gradOutput, int[] maxIndices, int[] inputShape)
    {
        var numOps = MathHelper.GetNumericOperations<T>();
        int inputSize = inputShape.Aggregate(1, (a, b) => a * b);
        var gradInputData = new T[inputSize];

        for (int i = 0; i < inputSize; i++)
            gradInputData[i] = numOps.Zero;

        var gradOutputData = gradOutput.GetFlattenedData();

        for (int i = 0; i < maxIndices.Length; i++)
        {
            if (maxIndices[i] >= 0 && maxIndices[i] < inputSize)
            {
                gradInputData[maxIndices[i]] = numOps.Add(gradInputData[maxIndices[i]], gradOutputData[i]);
            }
        }

        return TensorAllocator.Rent<T>(inputShape, new Vector<T>(gradInputData));
    }

    /// <inheritdoc/>
    public virtual Tensor<T> ReduceMean<T>(Tensor<T> input, int[] axes, bool keepDims)
    {
        if (GraphMode.IsActive)
        {
            var scope = GraphMode.Current;
            if (scope != null)
            {
                var captured = input;
                var capturedAxes = axes;
                bool capturedKeepDims = keepDims;
                // Compute output shape same as ReduceSum
                var shapeList = new System.Collections.Generic.List<int>();
                var axisSet = new System.Collections.Generic.HashSet<int>();
                foreach (int a in axes) axisSet.Add(a < 0 ? input.Rank + a : a);
                for (int i = 0; i < input.Rank; i++)
                {
                    if (axisSet.Contains(i)) { if (keepDims) shapeList.Add(1); }
                    else shapeList.Add(input._shape[i]);
                }
                var outShape = shapeList.Count > 0 ? shapeList.ToArray() : new[] { 1 };
                return scope.RecordUnary(LazyNodeType.ReduceMean, "ReduceMean", input, outShape,
                    (eng, output) => { var r = eng.ReduceMean(captured, capturedAxes, capturedKeepDims); r.AsSpan().CopyTo(output.AsWritableSpan()); },
                    BackwardFunctions<T>.ReduceMeanBackward, new object[] { axes, keepDims });
            }
        }

        { var ac = AutoTracer.TryGetCompiledPlan<T>("ReduceMean", input._shape); if (ac is not null) return ac.Execute(); }

        // Stride-aware single-axis mean
        if (!input.IsContiguous && axes.Length == 1)
        {
            var ops = MathHelper.GetNumericOperations<T>();
            int axis = axes[0] < 0 ? input.Rank + axes[0] : axes[0];
            if (axis < 0 || axis >= input.Rank) throw new ArgumentOutOfRangeException(nameof(axes), $"Axis {axes[0]} out of range for rank {input.Rank}");
            var (outerSize, axisSize, innerSize) = input.GetReductionDims(axis);
            var outShape = new List<int>();
            for (int d = 0; d < input.Rank; d++) { if (d == axis) { if (keepDims) outShape.Add(1); } else outShape.Add(input._shape[d]); }
            var earlyResult = AutoTensorCache.RentOrAllocate<T>(outShape.ToArray());
            var rArr = earlyResult.GetDataArray(); var srcArr = input._storage.GetDataArray();
            T divisor = ops.FromDouble(axisSize);
            for (int o = 0; o < outerSize; o++)
                for (int inner = 0; inner < innerSize; inner++)
                {
                    T sum = ops.Zero;
                    for (int a = 0; a < axisSize; a++) sum = ops.Add(sum, srcArr[input.ReductionStorageIndex(o, a, inner, axis)]);
                    rArr[o * innerSize + inner] = ops.Divide(sum, divisor);
                }
            DifferentiableOps.RecordUnary("ReduceMean", earlyResult, input,
                BackwardFunctions<T>.ReduceMeanBackward,
                savedState: new object[] { new[] { axis } });
            AutoTracer.RecordOp("ReduceMean", earlyResult, eng => earlyResult);
            return earlyResult;
        }
        // Fast path: reduce all axes — just sum/count
        // Also catches 1D tensors with axes=[0] since that's equivalent to full reduction
        bool isFullReduction = axes == null || axes.Length == 0;
        if (!isFullReduction && input.IsContiguous && axes is not null)
        {
            var axisSet = new HashSet<int>();
            foreach (int a in axes) axisSet.Add(a < 0 ? input.Rank + a : a);
            isFullReduction = axisSet.Count == input.Rank;
        }
        if (isFullReduction && input.IsContiguous)
        {
            if (typeof(T) == typeof(float))
            {
                unsafe
                {
                    var mem = AsFloatMemory(input.Data);
                    using var pin = mem.Pin();
                    float fSum = SimdKernels.SumUnsafe((float*)pin.Pointer, input.Length);
                    float fMean = fSum / input.Length;
                    var scalarResult = AutoTensorCache.RentOrAllocate<T>(new[] { 1 });
                    ((float[])(object)scalarResult.GetDataArray())[0] = fMean;
                    DifferentiableOps.RecordUnary("ReduceMean", scalarResult, input,
                        BackwardFunctions<T>.ReduceMeanBackward,
                        savedState: new object[] { Enumerable.Range(0, input.Rank).ToArray() });
                    AutoTracer.RecordOp("ReduceMean", scalarResult, eng => scalarResult);
                    return scalarResult;
                }
            }
        }

        var numOps = MathHelper.GetNumericOperations<T>();
        var inputShape = input._shape;
        var inputData = input.GetFlattenedData();

        // Validate and normalize axes (handle null = reduce all)
        var effectiveAxes = axes ?? Enumerable.Range(0, inputShape.Length).ToArray();
        var normalizedAxes = ValidateAndNormalizeAxes(effectiveAxes, inputShape.Length);

        var outputShapeList = new List<int>();
        for (int i = 0; i < inputShape.Length; i++)
        {
            if (normalizedAxes.Contains(i))
            {
                if (keepDims) outputShapeList.Add(1);
            }
            else
            {
                outputShapeList.Add(inputShape[i]);
            }
        }
        var outputShape = outputShapeList.Count > 0 ? outputShapeList.ToArray() : [1];

        int outputSize = outputShape.Aggregate(1, (a, b) => a * b);
        var outputData = new T[outputSize];
        var counts = new int[outputSize];

        for (int i = 0; i < outputSize; i++)
        {
            outputData[i] = numOps.Zero;
            counts[i] = 0;
        }

        var inputStrides = ComputeStrides(inputShape);
        var outputStrides = ComputeStrides(outputShape);

        for (int i = 0; i < input.Length; i++)
        {
            var multiIndex = FlatToMultiIndex(i, inputShape, inputStrides);

            var outputMultiIndex = new List<int>();
            for (int d = 0; d < inputShape.Length; d++)
            {
                if (normalizedAxes.Contains(d))
                {
                    if (keepDims) outputMultiIndex.Add(0);
                }
                else
                {
                    outputMultiIndex.Add(multiIndex[d]);
                }
            }
            if (outputMultiIndex.Count == 0) outputMultiIndex.Add(0);

            int outputIdx = MultiToFlatIndex([.. outputMultiIndex], outputShape, outputStrides);
            outputData[outputIdx] = numOps.Add(outputData[outputIdx], inputData[i]);
            counts[outputIdx]++;
        }

        for (int i = 0; i < outputSize; i++)
        {
            if (counts[i] > 0)
            {
                outputData[i] = numOps.Divide(outputData[i], numOps.FromDouble(counts[i]));
            }
        }

        var result = TensorAllocator.Rent<T>(outputShape, new Vector<T>(outputData));
        DifferentiableOps.RecordUnary("ReduceMean", result, input,
            BackwardFunctions<T>.ReduceMeanBackward,
            savedState: new object[] { normalizedAxes.ToArray() });
        AutoTracer.RecordOp("ReduceMean", result, eng => result);
        return result;
    }

    /// <inheritdoc/>
    public Tensor<T> ReduceMeanBackward<T>(Tensor<T> gradOutput, int[] inputShape, int[] axes)
    {
        if (inputShape == null || inputShape.Length == 0)
            throw new ArgumentNullException(nameof(inputShape), "inputShape cannot be null or empty");

        var numOps = MathHelper.GetNumericOperations<T>();
        int inputSize = inputShape.Aggregate(1, (a, b) => a * b);
        var gradInputData = new T[inputSize];

        // Validate and normalize axes
        var normalizedAxes = ValidateAndNormalizeAxes(axes, inputShape.Length);

        int reduceCount = 1;
        foreach (var ax in normalizedAxes)
        {
            reduceCount *= inputShape[ax];
        }
        T scale = numOps.Divide(numOps.One, numOps.FromDouble(reduceCount));

        var gradOutputData = gradOutput.GetFlattenedData();
        var gradOutputShape = gradOutput._shape;
        var inputStrides = ComputeStrides(inputShape);
        var outputStrides = ComputeStrides(gradOutputShape);

        for (int i = 0; i < inputSize; i++)
        {
            var multiIndex = FlatToMultiIndex(i, inputShape, inputStrides);

            var outputMultiIndex = new List<int>();
            int d2 = 0;
            for (int d = 0; d < inputShape.Length; d++)
            {
                if (normalizedAxes.Contains(d))
                {
                    if (d2 < gradOutputShape.Length && gradOutputShape[d2] == 1)
                    {
                        outputMultiIndex.Add(0);
                        d2++;
                    }
                }
                else
                {
                    if (d2 < gradOutputShape.Length)
                    {
                        outputMultiIndex.Add(multiIndex[d]);
                        d2++;
                    }
                }
            }
            if (outputMultiIndex.Count == 0) outputMultiIndex.Add(0);

            while (outputMultiIndex.Count < gradOutputShape.Length)
                outputMultiIndex.Add(0);
            while (outputMultiIndex.Count > gradOutputShape.Length)
                outputMultiIndex.RemoveAt(outputMultiIndex.Count - 1);

            int outputIdx = MultiToFlatIndex([.. outputMultiIndex], gradOutputShape, outputStrides);
            if (outputIdx < 0 || outputIdx >= gradOutputData.Length)
                throw new InvalidOperationException($"Output index {outputIdx} out of range [0, {gradOutputData.Length}). This indicates a shape mismatch between gradOutput and the expected shape.");
            gradInputData[i] = numOps.Multiply(gradOutputData[outputIdx], scale);
        }

        return TensorAllocator.Rent<T>(inputShape, new Vector<T>(gradInputData));
    }

    /// <inheritdoc/>
    public Tensor<T> ReduceVariance<T>(Tensor<T> input, int[] axes, bool keepDims)
    {
        // Tape-aware path: take the slow path that explicitly allocates a
        // `mean` Tensor<T> we can save in savedState for backward. The fast
        // paths below inline the mean and would need extra alloc + bookkeeping
        // to expose it, so they're bypassed when a tape is active. This only
        // hits during training; inference goes through the fast paths.
        if (DifferentiableOps.IsTapeActiveForThread<T>())
        {
            return ReduceVarianceTapeAware(input, axes, keepDims);
        }

        // Stride-aware: compute mean then variance with stride math
        if (!input.IsContiguous && axes.Length == 1)
        {
            var ops = MathHelper.GetNumericOperations<T>();
            int axis = axes[0] < 0 ? input.Rank + axes[0] : axes[0];
            if (axis < 0 || axis >= input.Rank) throw new ArgumentOutOfRangeException(nameof(axes), $"Axis {axes[0]} out of range for rank {input.Rank}");
            var (outerSize, axisSize, innerSize) = input.GetReductionDims(axis);
            var outShape = new List<int>();
            for (int d = 0; d < input.Rank; d++) { if (d == axis) { if (keepDims) outShape.Add(1); } else outShape.Add(input._shape[d]); }
            var result = AutoTensorCache.RentOrAllocate<T>(outShape.ToArray());
            var rArr = result.GetDataArray(); var srcArr = input._storage.GetDataArray();
            T divisor = ops.FromDouble(axisSize);
            for (int o = 0; o < outerSize; o++)
                for (int inner = 0; inner < innerSize; inner++)
                {
                    // Mean
                    T sum = ops.Zero;
                    for (int a = 0; a < axisSize; a++) sum = ops.Add(sum, srcArr[input.ReductionStorageIndex(o, a, inner, axis)]);
                    T meanVal = ops.Divide(sum, divisor);
                    // Variance
                    T varSum = ops.Zero;
                    for (int a = 0; a < axisSize; a++) { T diff = ops.Subtract(srcArr[input.ReductionStorageIndex(o, a, inner, axis)], meanVal); varSum = ops.Add(varSum, ops.Multiply(diff, diff)); }
                    rArr[o * innerSize + inner] = ops.Divide(varSum, divisor);
                }
            return result;
        }
        if (input == null)
            throw new ArgumentNullException(nameof(input));

        // Float fast path for 2D single-axis variance
        if (typeof(T) == typeof(float) && input.IsContiguous && axes.Length == 1 && input.Rank == 2)
        {
            int axis = axes[0] < 0 ? input.Rank + axes[0] : axes[0];
            var fData = (float[])(object)input.GetDataArray();
            int rows = input._shape[0], cols = input._shape[1];

            if (axis == 1) // variance along columns (per-row)
            {
                var outShape = keepDims ? new[] { rows, 1 } : new[] { rows };
                var result = AutoTensorCache.RentOrAllocate<T>(outShape);
                var fOut = (float[])(object)result.GetDataArray();
                for (int r = 0; r < rows; r++)
                {
                    int off = r * cols;
                    float rowSum = 0f;
                    for (int c = 0; c < cols; c++) rowSum += fData[off + c];
                    float rowMean = rowSum / cols;
                    float varSum = 0f;
                    for (int c = 0; c < cols; c++) { float d = fData[off + c] - rowMean; varSum += d * d; }
                    fOut[r] = varSum / cols;
                }
                return result;
            }
            else if (axis == 0) // variance along rows (per-column)
            {
                var outShape = keepDims ? new[] { 1, cols } : new[] { cols };
                var result = AutoTensorCache.RentOrAllocate<T>(outShape);
                var fOut = (float[])(object)result.GetDataArray();
                // First compute means
                var means = new float[cols];
                for (int r = 0; r < rows; r++)
                    for (int c = 0; c < cols; c++) means[c] += fData[r * cols + c];
                for (int c = 0; c < cols; c++) means[c] /= rows;
                // Then compute variance
                for (int r = 0; r < rows; r++)
                    for (int c = 0; c < cols; c++) { float d = fData[r * cols + c] - means[c]; fOut[c] += d * d; }
                for (int c = 0; c < cols; c++) fOut[c] /= rows;
                return result;
            }
        }

        var numOps = MathHelper.GetNumericOperations<T>();
        var inputData = input.GetFlattenedData();
        var inputShape = input._shape;

        // First compute the mean
        var mean = ReduceMean(input, axes, keepDims: true);
        var meanData = mean.GetDataArray();
        var meanShape = mean._shape;

        // Normalize axes
        var normalizedAxes = ValidateAndNormalizeAxes(axes, inputShape.Length);

        // Compute output shape
        var outputShapeList = new List<int>();
        for (int d = 0; d < inputShape.Length; d++)
        {
            if (normalizedAxes.Contains(d))
            {
                if (keepDims) outputShapeList.Add(1);
            }
            else
            {
                outputShapeList.Add(inputShape[d]);
            }
        }
        if (outputShapeList.Count == 0) outputShapeList.Add(1);
        var outputShape = outputShapeList.ToArray();

        int outputSize = outputShape.Aggregate(1, (a, b) => a * b);
        var outputData = new T[outputSize];

        // Compute reduction count (number of elements being reduced)
        int reduceCount = 1;
        foreach (var ax in normalizedAxes)
        {
            reduceCount *= inputShape[ax];
        }
        T scale = numOps.Divide(numOps.One, numOps.FromDouble(reduceCount));

        var inputStrides = ComputeStrides(inputShape);
        var outputStrides = ComputeStrides(outputShape);
        var meanStrides = ComputeStrides(meanShape);

        // Accumulate squared differences from mean
        int inputSize = input.Length;
        for (int i = 0; i < inputSize; i++)
        {
            var multiIndex = FlatToMultiIndex(i, inputShape, inputStrides);

            var outputMultiIndex = new List<int>();
            for (int d = 0; d < inputShape.Length; d++)
            {
                if (normalizedAxes.Contains(d))
                {
                    if (keepDims) outputMultiIndex.Add(0);
                }
                else
                {
                    outputMultiIndex.Add(multiIndex[d]);
                }
            }
            if (outputMultiIndex.Count == 0) outputMultiIndex.Add(0);

            int outputIdx = MultiToFlatIndex([.. outputMultiIndex], outputShape, outputStrides);

            // Get mean value (mean tensor has keepDims=true shape)
            var meanMultiIndex = new List<int>();
            for (int d = 0; d < inputShape.Length; d++)
            {
                if (normalizedAxes.Contains(d))
                    meanMultiIndex.Add(0);
                else
                    meanMultiIndex.Add(multiIndex[d]);
            }
            int meanIdx = MultiToFlatIndex([.. meanMultiIndex], meanShape, meanStrides);

            T diff = numOps.Subtract(inputData[i], meanData[meanIdx]);
            T squaredDiff = numOps.Multiply(diff, diff);
            outputData[outputIdx] = numOps.Add(outputData[outputIdx], squaredDiff);
        }

        // Divide by count to get variance
        for (int i = 0; i < outputSize; i++)
        {
            outputData[i] = numOps.Multiply(outputData[i], scale);
        }

        return TensorAllocator.Rent<T>(outputShape, new Vector<T>(outputData));
    }

    /// <summary>
    /// Tape-aware ReduceVariance: forces the slow path so we can capture
    /// the intermediate mean tensor for backward, then records the op.
    /// Backward = engine.ReduceVarianceBackward(gradOutput, input, mean, axes).
    /// </summary>
    private Tensor<T> ReduceVarianceTapeAware<T>(Tensor<T> input, int[] axes, bool keepDims)
    {
        if (input == null) throw new ArgumentNullException(nameof(input));
        var numOps = MathHelper.GetNumericOperations<T>();
        // Preserve the caller's original tensor reference so the recorded
        // GradFn keys to the tensor the caller will look up gradients for.
        // The contiguous copy below is for the math kernels only.
        var originalInput = input;
        var inputOrig = input;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!input.IsContiguous) input = input.Contiguous();

        var inputData = input.GetFlattenedData();
        var inputShape = input._shape;

        var mean = ReduceMean(input, axes, keepDims: true);
        var meanData = mean.GetDataArray();
        var meanShape = mean._shape;
        var normalizedAxes = ValidateAndNormalizeAxes(axes, inputShape.Length);

        var outputShapeList = new List<int>();
        for (int d = 0; d < inputShape.Length; d++)
        {
            if (normalizedAxes.Contains(d)) { if (keepDims) outputShapeList.Add(1); }
            else outputShapeList.Add(inputShape[d]);
        }
        if (outputShapeList.Count == 0) outputShapeList.Add(1);
        var outputShape = outputShapeList.ToArray();
        int outputSize = outputShape.Aggregate(1, (a, b) => a * b);
        var outputData = new T[outputSize];

        int reduceCount = 1;
        foreach (var ax in normalizedAxes) reduceCount *= inputShape[ax];
        T scale = numOps.Divide(numOps.One, numOps.FromDouble(reduceCount));

        var inputStrides = ComputeStrides(inputShape);
        var outputStrides = ComputeStrides(outputShape);
        var meanStrides = ComputeStrides(meanShape);

        int inputSize = input.Length;
        for (int i = 0; i < inputSize; i++)
        {
            var multiIndex = FlatToMultiIndex(i, inputShape, inputStrides);
            var outputMultiIndex = new List<int>();
            for (int d = 0; d < inputShape.Length; d++)
            {
                if (normalizedAxes.Contains(d)) { if (keepDims) outputMultiIndex.Add(0); }
                else outputMultiIndex.Add(multiIndex[d]);
            }
            if (outputMultiIndex.Count == 0) outputMultiIndex.Add(0);
            int outputIdx = MultiToFlatIndex([.. outputMultiIndex], outputShape, outputStrides);

            var meanMultiIndex = new List<int>();
            for (int d = 0; d < inputShape.Length; d++)
            {
                if (normalizedAxes.Contains(d)) meanMultiIndex.Add(0);
                else meanMultiIndex.Add(multiIndex[d]);
            }
            int meanIdx = MultiToFlatIndex([.. meanMultiIndex], meanShape, meanStrides);

            T diff = numOps.Subtract(inputData[i], meanData[meanIdx]);
            outputData[outputIdx] = numOps.Add(outputData[outputIdx], numOps.Multiply(diff, diff));
        }
        for (int i = 0; i < outputSize; i++) outputData[i] = numOps.Multiply(outputData[i], scale);

        var result = TensorAllocator.Rent<T>(outputShape, new Vector<T>(outputData));
        // savedState order matches existing BackwardFunctions<T>.ReduceVarianceBackward: [axes, mean].
        // Snapshot axes (caller-owned int[]) and key the recorded op against the
        // ORIGINAL input reference, not the contiguous copy used by the math.
        DifferentiableOps.RecordUnary("ReduceVariance", result, originalInput,
            BackwardFunctions<T>.ReduceVarianceBackward, new object[] { (int[])axes.Clone(), mean });
        return result;
    }

    /// <inheritdoc/>
    public Tensor<T> ReduceVarianceBackward<T>(Tensor<T> gradOutput, Tensor<T> input, Tensor<T> mean, int[] axes)
    {
        if (gradOutput == null)
            throw new ArgumentNullException(nameof(gradOutput));
        if (input == null)
            throw new ArgumentNullException(nameof(input));
        if (mean == null)
            throw new ArgumentNullException(nameof(mean));

        var numOps = MathHelper.GetNumericOperations<T>();
        var inputData = input.GetFlattenedData();
        var inputShape = input._shape;
        var meanData = mean.GetDataArray();
        var meanShape = mean._shape;
        var gradOutputData = gradOutput.GetFlattenedData();
        var gradOutputShape = gradOutput._shape;

        int inputSize = input.Length;
        var gradInputData = new T[inputSize];

        var normalizedAxes = ValidateAndNormalizeAxes(axes, inputShape.Length);

        int reduceCount = 1;
        foreach (var ax in normalizedAxes)
        {
            reduceCount *= inputShape[ax];
        }
        T scale = numOps.Divide(numOps.FromDouble(2.0), numOps.FromDouble(reduceCount));

        var inputStrides = ComputeStrides(inputShape);
        var outputStrides = ComputeStrides(gradOutputShape);
        var meanStrides = ComputeStrides(meanShape);

        for (int i = 0; i < inputSize; i++)
        {
            var multiIndex = FlatToMultiIndex(i, inputShape, inputStrides);

            // Map to output and mean indices using helper methods
            int outputIdx = MapToReducedIndex(multiIndex, inputShape, gradOutputShape, normalizedAxes, outputStrides);
            int meanIdx = MapToMeanIndex(multiIndex, inputShape, meanShape, normalizedAxes, meanStrides);

            // gradient = 2 * (x - mean) * gradOutput / N
            T diff = numOps.Subtract(inputData[i], meanData[meanIdx]);
            gradInputData[i] = numOps.Multiply(numOps.Multiply(diff, scale), gradOutputData[outputIdx]);
        }

        return TensorAllocator.Rent<T>(inputShape, new Vector<T>(gradInputData));
    }

    /// <inheritdoc/>
    public Tensor<T> ReduceLogVariance<T>(Tensor<T> input, int[] axes, bool keepDims, double epsilon = 1e-8)
    {
        if (input == null)
            throw new ArgumentNullException(nameof(input));
        if (GraphMode.IsActive) { var scope = GraphMode.Current; if (scope is not null) { var c_input = input; var c_axes = axes; var c_keepDims = keepDims; var c_epsilon = epsilon; return scope.RecordUnary(LazyNodeType.Custom, "ReduceLogVariance", input, input._shape, (eng, output) => { var r = eng.ReduceLogVariance(c_input, c_axes, c_keepDims, c_epsilon); r.AsSpan().CopyTo(output.AsWritableSpan()); }, BackwardFunctions<T>.ReduceLogVarianceBackward); } }
        { var ac = AutoTracer.TryGetCompiledPlan<T>("ReduceLogVariance", input._shape); if (ac is not null) return ac.Execute(); }

        var inputOrig = input;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!input.IsContiguous) input = input.Contiguous();

        var numOps = MathHelper.GetNumericOperations<T>();

        // Compute variance first
        var variance = ReduceVariance(input, axes, keepDims);
        var varianceData = variance.GetDataArray();

        // Apply log(variance + epsilon)
        T eps = numOps.FromDouble(epsilon);
        for (int i = 0; i < varianceData.Length; i++)
        {
            varianceData[i] = numOps.Log(numOps.Add(varianceData[i], eps));
        }

        var logVarResult = TensorAllocator.Rent<T>(variance._shape, new Vector<T>(varianceData));
        // Compute mean inside NoGradScope to avoid adding disconnected tape entries
        Tensor<T> mean;
        using (new NoGradScope<T>())
        {
            mean = ReduceMean(input, axes, keepDims);
        }
        DifferentiableOps.RecordUnary("ReduceLogVariance", logVarResult, inputOrig, BackwardFunctions<T>.ReduceLogVarianceBackward, new object[] { axes, mean, variance });
        { var ci = input; var ca = axes; var ck = keepDims; var ce = epsilon; AutoTracer.RecordOp("ReduceLogVariance", logVarResult, eng => eng.ReduceLogVariance(ci, ca, ck, ce)); }
        return logVarResult;
    }

    /// <inheritdoc/>
    public Tensor<T> ReduceLogVarianceBackward<T>(Tensor<T> gradOutput, Tensor<T> input, Tensor<T> mean, Tensor<T> variance, int[] axes)
    {
        if (gradOutput == null)
            throw new ArgumentNullException(nameof(gradOutput));
        if (input == null)
            throw new ArgumentNullException(nameof(input));
        if (mean == null)
            throw new ArgumentNullException(nameof(mean));
        if (variance == null)
            throw new ArgumentNullException(nameof(variance));
        var gradOutputOrig = gradOutput;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!gradOutput.IsContiguous) gradOutput = gradOutput.Contiguous();
        var inputOrig = input;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!input.IsContiguous) input = input.Contiguous();

        var numOps = MathHelper.GetNumericOperations<T>();
        var inputData = input.GetFlattenedData();
        var inputShape = input._shape;
        var meanData = mean.GetDataArray();
        var meanShape = mean._shape;
        var varianceData = variance.GetDataArray();
        var varianceShape = variance._shape;
        var gradOutputData = gradOutput.GetFlattenedData();
        var gradOutputShape = gradOutput._shape;

        int inputSize = input.Length;
        var gradInputData = new T[inputSize];

        var normalizedAxes = ValidateAndNormalizeAxes(axes, inputShape.Length);

        int reduceCount = 1;
        foreach (var ax in normalizedAxes)
        {
            reduceCount *= inputShape[ax];
        }
        T scale = numOps.Divide(numOps.FromDouble(2.0), numOps.FromDouble(reduceCount));

        var inputStrides = ComputeStrides(inputShape);
        var outputStrides = ComputeStrides(gradOutputShape);
        var meanStrides = ComputeStrides(meanShape);
        var varianceStrides = ComputeStrides(varianceShape);

        for (int i = 0; i < inputSize; i++)
        {
            var multiIndex = FlatToMultiIndex(i, inputShape, inputStrides);

            // Map to output/variance index
            var outputMultiIndex = new List<int>();
            int d2 = 0;
            for (int d = 0; d < inputShape.Length; d++)
            {
                if (normalizedAxes.Contains(d))
                {
                    if (d2 < gradOutputShape.Length && gradOutputShape[d2] == 1)
                    {
                        outputMultiIndex.Add(0);
                        d2++;
                    }
                }
                else
                {
                    if (d2 < gradOutputShape.Length)
                    {
                        outputMultiIndex.Add(multiIndex[d]);
                        d2++;
                    }
                }
            }
            if (outputMultiIndex.Count == 0) outputMultiIndex.Add(0);
            while (outputMultiIndex.Count < gradOutputShape.Length) outputMultiIndex.Add(0);
            while (outputMultiIndex.Count > gradOutputShape.Length) outputMultiIndex.RemoveAt(outputMultiIndex.Count - 1);

            int outputIdx = MultiToFlatIndex([.. outputMultiIndex], gradOutputShape, outputStrides);

            // Map to mean index
            var meanMultiIndex = new List<int>();
            for (int d = 0; d < inputShape.Length; d++)
            {
                if (normalizedAxes.Contains(d))
                    meanMultiIndex.Add(0);
                else
                    meanMultiIndex.Add(multiIndex[d]);
            }
            int meanIdx = MultiToFlatIndex([.. meanMultiIndex], meanShape, meanStrides);
            int varianceIdx = MultiToFlatIndex([.. outputMultiIndex], varianceShape, varianceStrides);

            // gradient = 2 * (x - mean) / (N * variance) * gradOutput
            // = (x - mean) * scale / variance * gradOutput
            T diff = numOps.Subtract(inputData[i], meanData[meanIdx]);
            T varianceVal = varianceData[varianceIdx];
            // Avoid division by zero
            if (numOps.LessThanOrEquals(varianceVal, numOps.Zero))
                varianceVal = numOps.FromDouble(1e-8);
            T gradScale = numOps.Divide(scale, varianceVal);
            gradInputData[i] = numOps.Multiply(numOps.Multiply(diff, gradScale), gradOutputData[outputIdx]);
        }

        return TensorAllocator.Rent<T>(inputShape, new Vector<T>(gradInputData));
    }

    // Helper methods for reduction operations
    private static int[] ComputeStrides(int[] shape)
    {
        var strides = new int[shape.Length];
        int stride = 1;
        for (int i = shape.Length - 1; i >= 0; i--)
        {
            strides[i] = stride;
            stride *= shape[i];
        }
        return strides;
    }

    private static int[] FlatToMultiIndex(int flatIndex, int[] shape, int[] strides)
    {
        var multiIndex = new int[shape.Length];
        for (int i = 0; i < shape.Length; i++)
        {
            multiIndex[i] = flatIndex / strides[i];
            flatIndex %= strides[i];
        }
        return multiIndex;
    }

    private static int MultiToFlatIndex(int[] multiIndex, int[] shape, int[] strides)
    {
        int flatIndex = 0;
        for (int i = 0; i < multiIndex.Length; i++)
        {
            flatIndex += multiIndex[i] * strides[i];
        }
        return flatIndex;
    }

    /// <summary>
    /// Maps a multi-index from input space to reduced output space for variance backward pass.
    /// </summary>
    private static int MapToReducedIndex(int[] multiIndex, int[] inputShape, int[] outputShape, int[] normalizedAxes, int[] outputStrides)
    {
        var outputMultiIndex = new List<int>();
        int d2 = 0;
        for (int d = 0; d < inputShape.Length; d++)
        {
            if (Array.IndexOf(normalizedAxes, d) >= 0)
            {
                if (d2 < outputShape.Length && outputShape[d2] == 1)
                {
                    outputMultiIndex.Add(0);
                    d2++;
                }
            }
            else
            {
                if (d2 < outputShape.Length)
                {
                    outputMultiIndex.Add(multiIndex[d]);
                    d2++;
                }
            }
        }
        if (outputMultiIndex.Count == 0) outputMultiIndex.Add(0);
        while (outputMultiIndex.Count < outputShape.Length) outputMultiIndex.Add(0);
        while (outputMultiIndex.Count > outputShape.Length) outputMultiIndex.RemoveAt(outputMultiIndex.Count - 1);

        return MultiToFlatIndex([.. outputMultiIndex], outputShape, outputStrides);
    }

    /// <summary>
    /// Maps a multi-index from input space to mean tensor space for variance backward pass.
    /// </summary>
    private static int MapToMeanIndex(int[] multiIndex, int[] inputShape, int[] meanShape, int[] normalizedAxes, int[] meanStrides)
    {
        var meanMultiIndex = new List<int>();
        for (int d = 0; d < inputShape.Length; d++)
        {
            if (Array.IndexOf(normalizedAxes, d) >= 0)
                meanMultiIndex.Add(0);
            else
                meanMultiIndex.Add(multiIndex[d]);
        }
        return MultiToFlatIndex([.. meanMultiIndex], meanShape, meanStrides);
    }

    #endregion

    #region Spatial Operations

    /// <summary>
    /// Write-through nearest-neighbour upsample. Mirrors the kernel used by
    /// <see cref="Upsample{T}(Tensor{T}, int, int)"/> but writes into the
    /// provided output tensor. Used by U-Net decoders, FPN top-down passes,
    /// and image super-resolution heads — these typically do 4-5 upsamples
    /// per inference.
    /// </summary>
    public void UpsampleInto<T>(Tensor<T> output, Tensor<T> input, int scaleH, int scaleW)
    {
        if (output == null) throw new ArgumentNullException(nameof(output));
        if (input == null) throw new ArgumentNullException(nameof(input));
        var shape = input._shape;
        if (shape.Length < 2)
            throw new ArgumentException("UpsampleInto requires tensor with at least 2 dimensions for height and width.");

        int heightIdx = shape.Length - 2;
        int widthIdx = shape.Length - 1;
        int height = shape[heightIdx];
        int width = shape[widthIdx];
        int flatBatch = 1;
        for (int i = 0; i < shape.Length - 2; i++) flatBatch *= shape[i];
        int newHeight = height * scaleH;
        int newWidth = width * scaleW;

        if (typeof(T) == typeof(float)
            && input.GetDataArray() is float[] inArr
            && output.GetDataArray() is float[] outArr)
        {
            int h = height, w = width, sH = scaleH, sW = scaleW, nH = newHeight, nW = newWidth;
            Action<int> kernel = fb =>
            {
                int inBase = fb * h * w;
                int outBase = fb * nH * nW;
                for (int oh = 0; oh < nH; oh++)
                {
                    int ih = oh / sH;
                    int rowOut = outBase + oh * nW;
                    int rowIn  = inBase  + ih * w;
                    for (int ow = 0; ow < nW; ow++)
                    {
                        outArr[rowOut + ow] = inArr[rowIn + ow / sW];
                    }
                }
            };
            if (flatBatch > 8) Parallel.For(0, flatBatch, kernel);
            else for (int fb = 0; fb < flatBatch; fb++) kernel(fb);
            return;
        }

        var inputData = input.GetFlattenedData();
        var outputData = output.GetDataArray();
        Parallel.For(0, flatBatch, fb =>
        {
            for (int oh = 0; oh < newHeight; oh++)
            {
                int ih = oh / scaleH;
                for (int ow = 0; ow < newWidth; ow++)
                {
                    int iw = ow / scaleW;
                    int inputIdx = (fb * height + ih) * width + iw;
                    int outputIdx = (fb * newHeight + oh) * newWidth + ow;
                    outputData[outputIdx] = inputData[inputIdx];
                }
            }
        });
    }

    /// <inheritdoc/>
    public virtual Tensor<T> Upsample<T>(Tensor<T> input, int scaleH, int scaleW)
    {
        var shape = input._shape;
        if (shape.Length < 2)
            throw new ArgumentException("Upsample requires tensor with at least 2 dimensions for height and width.");

        if (GraphMode.IsActive)
        {
            var scope = GraphMode.Current;
            if (scope != null)
            {
                var captured = input;
                int capScaleH = scaleH, capScaleW = scaleW;
                var outShape = (int[])shape.Clone();
                outShape[shape.Length - 2] *= scaleH;
                outShape[shape.Length - 1] *= scaleW;
                return scope.RecordUnary(LazyNodeType.Custom, "Upsample", input, outShape,
                    (eng, output) =>
                    {
                        if (eng is CpuEngine cpuEng) cpuEng.UpsampleInto(output, captured, capScaleH, capScaleW);
                        else { var r = eng.Upsample(captured, capScaleH, capScaleW); r.AsSpan().CopyTo(output.AsWritableSpan()); }
                    },
                    BackwardFunctions<T>.UpsampleBackward, new object[] { capScaleH, capScaleW });
            }
        }

        { var ac = AutoTracer.TryGetCompiledPlan<T>("Upsample", input._shape); if (ac is not null) return ac.Execute(); }

        // Industry-standard: last two dimensions are height and width
        int heightIdx = shape.Length - 2;
        int widthIdx = shape.Length - 1;
        int height = shape[heightIdx];
        int width = shape[widthIdx];

        // Flatten all leading dimensions into a single "batch" dimension
        int flatBatch = 1;
        for (int i = 0; i < shape.Length - 2; i++)
        {
            flatBatch *= shape[i];
        }

        int newHeight = height * scaleH;
        int newWidth = width * scaleW;

        var inputData = input.GetFlattenedData();
        var outputData = new T[flatBatch * newHeight * newWidth];

        // Primitive fast paths — avoid the generic T[] array covariance check
        // and let JIT generate specialized code for float/double. Even though
        // Upsample is a pure copy with no arithmetic, the generic path still
        // incurs a per-element type check for the array store.
        if (typeof(T) == typeof(float))
        {
            var fIn = (float[])(object)inputData;
            var fOut = (float[])(object)outputData;
            Parallel.For(0, flatBatch, fb =>
            {
                for (int oh = 0; oh < newHeight; oh++)
                {
                    int ih = oh / scaleH;
                    for (int ow = 0; ow < newWidth; ow++)
                    {
                        int iw = ow / scaleW;
                        fOut[(fb * newHeight + oh) * newWidth + ow] = fIn[(fb * height + ih) * width + iw];
                    }
                }
            });
        }
        else if (typeof(T) == typeof(double))
        {
            var dIn = (double[])(object)inputData;
            var dOut = (double[])(object)outputData;
            Parallel.For(0, flatBatch, fb =>
            {
                for (int oh = 0; oh < newHeight; oh++)
                {
                    int ih = oh / scaleH;
                    for (int ow = 0; ow < newWidth; ow++)
                    {
                        int iw = ow / scaleW;
                        dOut[(fb * newHeight + oh) * newWidth + ow] = dIn[(fb * height + ih) * width + iw];
                    }
                }
            });
        }
        else
        {
            Parallel.For(0, flatBatch, fb =>
            {
                for (int oh = 0; oh < newHeight; oh++)
                {
                    int ih = oh / scaleH;
                    for (int ow = 0; ow < newWidth; ow++)
                    {
                        int iw = ow / scaleW;
                        int inputIdx = (fb * height + ih) * width + iw;
                        int outputIdx = (fb * newHeight + oh) * newWidth + ow;
                        outputData[outputIdx] = inputData[inputIdx];
                    }
                }
            });
        }

        // Create output shape preserving all leading dimensions
        var outputShape = new int[shape.Length];
        for (int i = 0; i < shape.Length - 2; i++)
        {
            outputShape[i] = shape[i];
        }
        outputShape[heightIdx] = newHeight;
        outputShape[widthIdx] = newWidth;

        var upsampleResult = TensorAllocator.Rent<T>(outputShape, new Vector<T>(outputData));
        DifferentiableOps.RecordUnary("Upsample", upsampleResult, input,
            BackwardFunctions<T>.UpsampleBackward,
            savedState: new object[] { scaleH, scaleW });
        AutoTracer.RecordOp("Upsample", upsampleResult, eng => upsampleResult);
        return upsampleResult;
    }

    /// <inheritdoc/>
    public Tensor<T> UpsampleBackward<T>(Tensor<T> gradOutput, int[] inputShape, int scaleH, int scaleW)
    {
        if (inputShape.Length < 2)
            throw new ArgumentException("UpsampleBackward requires inputShape with at least 2 dimensions for height and width.");

        var numOps = MathHelper.GetNumericOperations<T>();

        // Industry-standard: last two dimensions are height and width
        int heightIdx = inputShape.Length - 2;
        int widthIdx = inputShape.Length - 1;
        int height = inputShape[heightIdx];
        int width = inputShape[widthIdx];

        // Flatten all leading dimensions into a single "batch" dimension
        int flatBatch = 1;
        int totalInput = 1;
        for (int i = 0; i < inputShape.Length; i++)
        {
            totalInput *= inputShape[i];
            if (i < inputShape.Length - 2)
            {
                flatBatch *= inputShape[i];
            }
        }

        int newHeight = height * scaleH;
        int newWidth = width * scaleW;

        var gradOutputData = gradOutput.GetFlattenedData();
        var gradInputData = new T[totalInput];

        for (int i = 0; i < gradInputData.Length; i++)
            gradInputData[i] = numOps.Zero;

        Parallel.For(0, flatBatch, fb =>
        {
            for (int oh = 0; oh < newHeight; oh++)
            {
                int ih = oh / scaleH;
                for (int ow = 0; ow < newWidth; ow++)
                {
                    int iw = ow / scaleW;
                    int gradOutputIdx = (fb * newHeight + oh) * newWidth + ow;
                    int gradInputIdx = (fb * height + ih) * width + iw;
                    // No lock needed - each flatBatch partition owns disjoint gradInput slices
                    gradInputData[gradInputIdx] = numOps.Add(gradInputData[gradInputIdx], gradOutputData[gradOutputIdx]);
                }
            }
        });

        return TensorAllocator.Rent<T>(inputShape, new Vector<T>(gradInputData));
    }

    /// <summary>
    /// Write-through PixelShuffle (sub-pixel upscaling). Used by super-
    /// resolution heads (ESPCN, EDSR, SRResNet) and YOLO neck/head blocks.
    /// Inverts the loop nest from output-major (with div/mod per inner pixel)
    /// to input-major so the inner ow loop becomes linear indexing.
    /// </summary>
    public void PixelShuffleInto<T>(Tensor<T> output, Tensor<T> input, int upscaleFactor)
    {
        if (output == null) throw new ArgumentNullException(nameof(output));
        if (input == null) throw new ArgumentNullException(nameof(input));
        var shape = input._shape;
        if (shape.Length != 4)
            throw new ArgumentException("PixelShuffleInto expects 4D tensor [batch, channels, height, width]");

        int batch = shape[0];
        int channels = shape[1];
        int height = shape[2];
        int width = shape[3];
        int r = upscaleFactor;
        if (channels % (r * r) != 0)
            throw new ArgumentException($"Number of channels ({channels}) must be divisible by r^2 ({r * r})");

        int newChannels = channels / (r * r);
        int newHeight = height * r;
        int newWidth = width * r;

        if (typeof(T) == typeof(float)
            && input.GetDataArray() is float[] inArr
            && output.GetDataArray() is float[] outArr)
        {
            int totalBOC = batch * newChannels;
            int hh = height, ww = width, oH = newHeight, oW = newWidth, rr = r, ch = channels;
            Action<int> kernel = boc =>
            {
                int b = boc / newChannels;
                int oc = boc % newChannels;
                int ocBase = oc * rr * rr;
                int outBcBase = boc * oH * oW;
                int inBatchBase = b * ch * hh * ww;
                for (int subH = 0; subH < rr; subH++)
                {
                    for (int subW = 0; subW < rr; subW++)
                    {
                        int ic = ocBase + subH * rr + subW;
                        int inChanBase = inBatchBase + ic * hh * ww;
                        for (int ih = 0; ih < hh; ih++)
                        {
                            int oh = ih * rr + subH;
                            int rowOut = outBcBase + oh * oW + subW;
                            int rowIn = inChanBase + ih * ww;
                            // Stride-rr write into the output row.
                            for (int iw = 0; iw < ww; iw++)
                            {
                                outArr[rowOut + iw * rr] = inArr[rowIn + iw];
                            }
                        }
                    }
                }
            };
            if (totalBOC > 4) Parallel.For(0, totalBOC, kernel);
            else for (int boc = 0; boc < totalBOC; boc++) kernel(boc);
            return;
        }

        var inputData = input.GetFlattenedData();
        var outputData = output.GetDataArray();
        Parallel.For(0, batch * newChannels, boc =>
        {
            int b = boc / newChannels;
            int oc = boc % newChannels;
            int ocBase = oc * r * r;
            int outBcBase = boc * newHeight * newWidth;
            int inBatchBase = b * channels * height * width;
            for (int subH = 0; subH < r; subH++)
            {
                for (int subW = 0; subW < r; subW++)
                {
                    int ic = ocBase + subH * r + subW;
                    int inChanBase = inBatchBase + ic * height * width;
                    for (int ih = 0; ih < height; ih++)
                    {
                        int oh = ih * r + subH;
                        int rowOut = outBcBase + oh * newWidth + subW;
                        int rowIn = inChanBase + ih * width;
                        for (int iw = 0; iw < width; iw++)
                        {
                            outputData[rowOut + iw * r] = inputData[rowIn + iw];
                        }
                    }
                }
            }
        });
    }

    /// <inheritdoc/>
    public Tensor<T> PixelShuffle<T>(Tensor<T> input, int upscaleFactor)
    {
        var shape = input._shape;
        if (shape.Length != 4)
            throw new ArgumentException("PixelShuffle expects 4D tensor [batch, channels, height, width]");
        if (GraphMode.IsActive)
        {
            var scope = GraphMode.Current;
            if (scope is not null)
            {
                var c_input = input;
                int c_upscaleFactor = upscaleFactor;
                int rr = upscaleFactor;
                if (shape[1] % (rr * rr) != 0)
                    throw new ArgumentException($"Number of channels ({shape[1]}) must be divisible by r^2 ({rr * rr})");
                // FIX: previous code passed input._shape, leaving the output buffer
                // sized for the pre-shuffle layout — element count matched but the
                // shape metadata was wrong for downstream shape-aware ops.
                var outShape = new[] { shape[0], shape[1] / (rr * rr), shape[2] * rr, shape[3] * rr };
                return scope.RecordUnary(LazyNodeType.Custom, "PixelShuffle", input, outShape,
                    (eng, output) =>
                    {
                        if (eng is CpuEngine cpuEng) cpuEng.PixelShuffleInto(output, c_input, c_upscaleFactor);
                        else { var r = eng.PixelShuffle(c_input, c_upscaleFactor); r.AsSpan().CopyTo(output.AsWritableSpan()); }
                    },
                    BackwardFunctions<T>.PixelShuffleBackward, new object[] { c_upscaleFactor });
            }
        }
        { var ac = AutoTracer.TryGetCompiledPlan<T>("PixelShuffle", input._shape); if (ac is not null) return ac.Execute(); }

        int batch = shape[0];
        int channels = shape[1];
        int height = shape[2];
        int width = shape[3];

        int r = upscaleFactor;
        if (channels % (r * r) != 0)
            throw new ArgumentException($"Number of channels ({channels}) must be divisible by r^2 ({r * r})");

        int newChannels = channels / (r * r);
        int newHeight = height * r;
        int newWidth = width * r;

        var psResult = TensorAllocator.Rent<T>([batch, newChannels, newHeight, newWidth]);
        PixelShuffleInto(psResult, input, upscaleFactor);
        DifferentiableOps.RecordUnary("PixelShuffle", psResult, input, BackwardFunctions<T>.PixelShuffleBackward, new object[] { upscaleFactor });
        { var ci = input; var cu = upscaleFactor; AutoTracer.RecordOp("PixelShuffle", psResult, eng => eng.PixelShuffle(ci, cu)); }
        return psResult;
    }

    /// <inheritdoc/>
    public Tensor<T> PixelShuffleBackward<T>(Tensor<T> gradOutput, int[] inputShape, int upscaleFactor)
    {
        int batch = inputShape[0];
        int channels = inputShape[1];
        int height = inputShape[2];
        int width = inputShape[3];

        int r = upscaleFactor;
        int newChannels = channels / (r * r);
        int newHeight = height * r;
        int newWidth = width * r;

        var gradOutputData = gradOutput.GetFlattenedData();
        var gradInputData = new T[batch * channels * height * width];

        Parallel.For(0, batch, b =>
        {
            for (int oc = 0; oc < newChannels; oc++)
            {
                for (int oh = 0; oh < newHeight; oh++)
                {
                    for (int ow = 0; ow < newWidth; ow++)
                    {
                        int ih = oh / r;
                        int iw = ow / r;
                        int subH = oh % r;
                        int subW = ow % r;
                        int ic = oc * r * r + subH * r + subW;

                        int gradInputIdx = ((b * channels + ic) * height + ih) * width + iw;
                        int gradOutputIdx = ((b * newChannels + oc) * newHeight + oh) * newWidth + ow;
                        gradInputData[gradInputIdx] = gradOutputData[gradOutputIdx];
                    }
                }
            }
        });

        return TensorAllocator.Rent<T>(inputShape, new Vector<T>(gradInputData));
    }

    public Tensor<T> AffineGrid<T>(Tensor<T> theta, int outputHeight, int outputWidth)
    {
        if (theta == null) throw new ArgumentNullException(nameof(theta));
        if (theta._shape.Length != 3 || theta._shape[1] != 2 || theta._shape[2] != 3)
            throw new ArgumentException("AffineGrid expects theta shape [batch, 2, 3]");

        int batchSize = theta._shape[0];
        var grid = TensorAllocator.Rent<T>([batchSize, outputHeight, outputWidth, 2]);
        var numOps = MathHelper.GetNumericOperations<T>();

        for (int b = 0; b < batchSize; b++)
        {
            for (int h = 0; h < outputHeight; h++)
            {
                T yNorm = outputHeight == 1
                    ? numOps.Zero
                    : numOps.FromDouble((double)h / (outputHeight - 1) * 2.0 - 1.0);

                for (int w = 0; w < outputWidth; w++)
                {
                    T xNorm = outputWidth == 1
                        ? numOps.Zero
                        : numOps.FromDouble((double)w / (outputWidth - 1) * 2.0 - 1.0);

                    T xPrime = numOps.Add(
                        numOps.Add(
                            numOps.Multiply(theta[b, 0, 0], xNorm),
                            numOps.Multiply(theta[b, 0, 1], yNorm)),
                        theta[b, 0, 2]);

                    T yPrime = numOps.Add(
                        numOps.Add(
                            numOps.Multiply(theta[b, 1, 0], xNorm),
                            numOps.Multiply(theta[b, 1, 1], yNorm)),
                        theta[b, 1, 2]);

                    grid[b, h, w, 0] = xPrime;
                    grid[b, h, w, 1] = yPrime;
                }
            }
        }

        return grid;
    }

    public virtual Tensor<T> GridSample<T>(Tensor<T> input, Tensor<T> grid)
    {
        if (input == null) throw new ArgumentNullException(nameof(input));
        if (grid == null) throw new ArgumentNullException(nameof(grid));

        if (GraphMode.IsActive)
        {
            var scope = GraphMode.Current;
            if (scope != null)
            {
                var ci = input; var cg = grid;
                var outShape = new[] { input._shape[0], grid._shape[1], grid._shape[2], input._shape[3] };
                return scope.RecordBinary(LazyNodeType.Custom, "GridSample", input, grid, outShape,
                    (eng, output) => { var r = eng.GridSample(ci, cg); r.AsSpan().CopyTo(output.AsWritableSpan()); });
            }
        }

        { var ac = AutoTracer.TryGetCompiledPlan<T>("GridSample", input._shape); if (ac is not null) return ac.Execute(); }

        if (input._shape.Length != 4)
            throw new ArgumentException("GridSample expects input shape [batch, height, width, channels]");
        if (grid._shape.Length != 4 || grid._shape[3] != 2)
            throw new ArgumentException("GridSample expects grid shape [batch, outH, outW, 2]");
        if (input._shape[0] != grid._shape[0])
            throw new ArgumentException("GridSample batch size mismatch between input and grid");

        var numOps = MathHelper.GetNumericOperations<T>();
        int batch = input._shape[0];
        int inH = input._shape[1];
        int inW = input._shape[2];
        int channels = input._shape[3];
        int outH = grid._shape[1];
        int outW = grid._shape[2];

        var output = TensorAllocator.Rent<T>([batch, outH, outW, channels]);

        T heightScale = numOps.FromDouble((inH - 1) / 2.0);
        T widthScale = numOps.FromDouble((inW - 1) / 2.0);

        for (int b = 0; b < batch; b++)
        {
            for (int h = 0; h < outH; h++)
            {
                for (int w = 0; w < outW; w++)
                {
                    T gridX = grid[b, h, w, 0];
                    T gridY = grid[b, h, w, 1];

                    T srcX = numOps.Multiply(numOps.Add(gridX, numOps.One), widthScale);
                    T srcY = numOps.Multiply(numOps.Add(gridY, numOps.One), heightScale);

                    double srcXDouble = Convert.ToDouble(srcX);
                    double srcYDouble = Convert.ToDouble(srcY);
                    int x0 = Math.Max(0, Math.Min((int)Math.Floor(srcXDouble), inW - 1));
                    int x1 = Math.Max(0, Math.Min(x0 + 1, inW - 1));
                    int y0 = Math.Max(0, Math.Min((int)Math.Floor(srcYDouble), inH - 1));
                    int y1 = Math.Max(0, Math.Min(y0 + 1, inH - 1));

                    T wx1 = numOps.Subtract(srcX, numOps.FromDouble(x0));
                    T wx0 = numOps.Subtract(numOps.One, wx1);
                    T wy1 = numOps.Subtract(srcY, numOps.FromDouble(y0));
                    T wy0 = numOps.Subtract(numOps.One, wy1);

                    for (int c = 0; c < channels; c++)
                    {
                        T v00 = input[b, y0, x0, c];
                        T v01 = input[b, y0, x1, c];
                        T v10 = input[b, y1, x0, c];
                        T v11 = input[b, y1, x1, c];

                        T interp = numOps.Add(
                            numOps.Add(
                                numOps.Multiply(numOps.Multiply(v00, wx0), wy0),
                                numOps.Multiply(numOps.Multiply(v01, wx1), wy0)),
                            numOps.Add(
                                numOps.Multiply(numOps.Multiply(v10, wx0), wy1),
                                numOps.Multiply(numOps.Multiply(v11, wx1), wy1)));

                        output[b, h, w, c] = interp;
                    }
                }
            }
        }

        DifferentiableOps.RecordBinary("GridSample", output, input, grid, BackwardFunctions<T>.GridSampleBackward);
        AutoTracer.RecordOp("GridSample", output, eng => output);
        return output;
    }

    /// <summary>
    /// Extracts sliding local blocks (im2col) from a batched input tensor.
    /// Input: [batch, channels, height, width] -> Output: [batch, channels * kH * kW, L]
    /// </summary>
    public virtual Tensor<T> Unfold<T>(Tensor<T> input, int[] kernelSize, int[] stride, int[] padding)
    {
        if (input == null) throw new ArgumentNullException(nameof(input));

        if (GraphMode.IsActive)
        {
            var scope = GraphMode.Current;
            if (scope != null)
            {
                var ci = input; var ck = kernelSize; var cs = stride; var cp = padding;
                int lkH = kernelSize[0], lkW = kernelSize[1];
                int lsH = stride[0], lsW = stride[1];
                int lpH = padding[0], lpW = padding[1];
                int oH = (input._shape[2] + 2 * lpH - lkH) / lsH + 1;
                int oW = (input._shape[3] + 2 * lpW - lkW) / lsW + 1;
                var outShape = new[] { input._shape[0], input._shape[1] * lkH * lkW, oH * oW };
                return scope.RecordUnary(LazyNodeType.Custom, "Unfold", input, outShape,
                    (eng, output) => { var r = eng.Unfold(ci, ck, cs, cp); r.AsSpan().CopyTo(output.AsWritableSpan()); });
            }
        }
        { var ac = AutoTracer.TryGetCompiledPlan<T>("Unfold", input._shape); if (ac is not null) return ac.Execute(); }

        if (kernelSize == null || kernelSize.Length < 2) throw new ArgumentException("kernelSize must have at least 2 elements.", nameof(kernelSize));
        if (stride == null || stride.Length < 2) throw new ArgumentException("stride must have at least 2 elements.", nameof(stride));
        if (padding == null || padding.Length < 2) throw new ArgumentException("padding must have at least 2 elements.", nameof(padding));
        if (input.Rank != 4) throw new ArgumentException($"Unfold requires 4D input [batch, channels, height, width]. Got rank {input.Rank}.");
        if (kernelSize[0] <= 0 || kernelSize[1] <= 0) throw new ArgumentException("Kernel size elements must be positive.", nameof(kernelSize));
        if (stride[0] <= 0 || stride[1] <= 0) throw new ArgumentException("Stride elements must be positive.", nameof(stride));
        if (padding[0] < 0 || padding[1] < 0) throw new ArgumentException("Padding elements must be non-negative.", nameof(padding));

        // Save original input for tape before potential Contiguous() replacement
        var originalUnfoldInput = input;
        var inputOrig = input;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!input.IsContiguous) input = input.Contiguous();

        var numOps = MathHelper.GetNumericOperations<T>();
        int batch = input._shape[0];
        int channels = input._shape[1];
        int height = input._shape[2];
        int width = input._shape[3];
        int kH = kernelSize[0], kW = kernelSize[1];
        int sH = stride[0], sW = stride[1];
        int pH = padding[0], pW = padding[1];

        int outH = (int)Math.Floor((height + 2.0 * pH - kH) / sH) + 1;
        int outW = (int)Math.Floor((width + 2.0 * pW - kW) / sW) + 1;
        if (outH <= 0 || outW <= 0)
            throw new ArgumentException($"Invalid Unfold dimensions: output would be {outH}x{outW}. Check kernel, stride, and padding.");
        int colLength = outH * outW;
        int colChannels = channels * kH * kW;

        var result = TensorAllocator.Rent<T>(new[] { batch, colChannels, colLength });
        var inputData = input.GetDataArray();
        var resultData = result.GetDataArray();

        for (int b = 0; b < batch; b++)
        {
            int batchInputOffset = b * channels * height * width;
            int batchOutputOffset = b * colChannels * colLength;

            for (int c = 0; c < channels; c++)
            {
                for (int ki = 0; ki < kH; ki++)
                {
                    for (int kj = 0; kj < kW; kj++)
                    {
                        int colRow = (c * kH + ki) * kW + kj;
                        for (int oh = 0; oh < outH; oh++)
                        {
                            int ih = oh * sH + ki - pH;
                            for (int ow = 0; ow < outW; ow++)
                            {
                                int iw = ow * sW + kj - pW;
                                int colIdx = batchOutputOffset + colRow * colLength + oh * outW + ow;
                                if (ih >= 0 && ih < height && iw >= 0 && iw < width)
                                    resultData[colIdx] = inputData[batchInputOffset + c * height * width + ih * width + iw];
                                else
                                    resultData[colIdx] = numOps.Zero;
                            }
                        }
                    }
                }
            }
        }

        if (GradientTape<T>.Current is not null)
            DifferentiableOps.RecordUnary("Unfold", result, originalUnfoldInput, BackwardFunctions<T>.UnfoldBackward,
                new object[] { (int[])kernelSize.Clone(), (int[])stride.Clone(), (int[])padding.Clone() });
        AutoTracer.RecordOp("Unfold", result, eng => result);
        return result;
    }

    /// <summary>
    /// Combines sliding local blocks back into a full tensor (col2im).
    /// Input: [batch, channels * kH * kW, L] -> Output: [batch, channels, outputH, outputW]
    /// </summary>
    public virtual Tensor<T> Fold<T>(Tensor<T> input, int[] outputSize, int[] kernelSize, int[] stride, int[] padding)
    {
        if (input == null) throw new ArgumentNullException(nameof(input));

        if (GraphMode.IsActive)
        {
            var scope = GraphMode.Current;
            if (scope != null)
            {
                var ci = input; var co = outputSize; var ck = kernelSize; var cs = stride; var cp = padding;
                int lBatch = input._shape[0];
                int lkH = kernelSize[0], lkW = kernelSize[1];
                int lCh = input._shape[1] / (lkH * lkW);
                var outShape = new[] { lBatch, lCh, outputSize[0], outputSize[1] };
                return scope.RecordUnary(LazyNodeType.Custom, "Fold", input, outShape,
                    (eng, output) => { var r = eng.Fold(ci, co, ck, cs, cp); r.AsSpan().CopyTo(output.AsWritableSpan()); });
            }
        }
        { var ac = AutoTracer.TryGetCompiledPlan<T>("Fold", input._shape); if (ac is not null) return ac.Execute(); }

        if (outputSize == null || outputSize.Length < 2) throw new ArgumentException("outputSize must have at least 2 elements.", nameof(outputSize));
        if (kernelSize == null || kernelSize.Length < 2) throw new ArgumentException("kernelSize must have at least 2 elements.", nameof(kernelSize));
        if (stride == null || stride.Length < 2) throw new ArgumentException("stride must have at least 2 elements.", nameof(stride));
        if (padding == null || padding.Length < 2) throw new ArgumentException("padding must have at least 2 elements.", nameof(padding));
        if (input.Rank != 3) throw new ArgumentException($"Fold requires 3D input [batch, C*kH*kW, L]. Got rank {input.Rank}.");
        if (kernelSize[0] <= 0 || kernelSize[1] <= 0) throw new ArgumentException("Kernel size elements must be positive.", nameof(kernelSize));
        if (stride[0] <= 0 || stride[1] <= 0) throw new ArgumentException("Stride elements must be positive.", nameof(stride));
        if (padding[0] < 0 || padding[1] < 0) throw new ArgumentException("Padding elements must be non-negative.", nameof(padding));

        var originalFoldInput = input;
        var inputOrig = input;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!input.IsContiguous) input = input.Contiguous();

        var numOps = MathHelper.GetNumericOperations<T>();
        int batch = input._shape[0];
        int kH = kernelSize[0], kW = kernelSize[1];
        int sH = stride[0], sW = stride[1];
        int pH = padding[0], pW = padding[1];
        int outH = outputSize[0], outW = outputSize[1];
        int colChannels = input._shape[1];
        int kernelElements = kH * kW;
        if (kernelElements == 0 || colChannels % kernelElements != 0)
            throw new ArgumentException($"Input channels ({colChannels}) must be divisible by kernel elements ({kernelElements}).");
        int channels = colChannels / kernelElements;
        int colLength = input._shape[2];
        int unfoldH = (int)Math.Floor((outH + 2.0 * pH - kH) / sH) + 1;
        int unfoldW = (int)Math.Floor((outW + 2.0 * pW - kW) / sW) + 1;
        int expectedColLength = unfoldH * unfoldW;
        if (colLength != expectedColLength)
            throw new ArgumentException($"Column length {colLength} doesn't match expected {expectedColLength} for output {outH}x{outW} with kernel {kH}x{kW}, stride {sH}x{sW}, pad {pH}x{pW}.");

        var result = TensorAllocator.Rent<T>(new[] { batch, channels, outH, outW });
        var inputData = input.GetDataArray();
        var resultData = result.GetDataArray();

        // Initialize to zero
        for (int i = 0; i < resultData.Length; i++)
            resultData[i] = numOps.Zero;

        for (int b = 0; b < batch; b++)
        {
            int batchInputOffset = b * colChannels * colLength;
            int batchOutputOffset = b * channels * outH * outW;

            for (int c = 0; c < channels; c++)
            {
                for (int ki = 0; ki < kH; ki++)
                {
                    for (int kj = 0; kj < kW; kj++)
                    {
                        int colRow = (c * kH + ki) * kW + kj;
                        for (int oh = 0; oh < unfoldH; oh++)
                        {
                            int ih = oh * sH + ki - pH;
                            for (int ow = 0; ow < unfoldW; ow++)
                            {
                                int iw = ow * sW + kj - pW;
                                if (ih >= 0 && ih < outH && iw >= 0 && iw < outW)
                                {
                                    int colIdx = batchInputOffset + colRow * colLength + oh * unfoldW + ow;
                                    int outIdx = batchOutputOffset + c * outH * outW + ih * outW + iw;
                                    resultData[outIdx] = numOps.Add(resultData[outIdx], inputData[colIdx]);
                                }
                            }
                        }
                    }
                }
            }
        }

        if (GradientTape<T>.Current is not null)
            DifferentiableOps.RecordUnary("Fold", result, originalFoldInput, BackwardFunctions<T>.FoldBackward,
                new object[] { (int[])kernelSize.Clone(), (int[])stride.Clone(), (int[])padding.Clone() });
        AutoTracer.RecordOp("Fold", result, eng => result);
        return result;
    }

    public (Tensor<T> real, Tensor<T> imag) ComplexMatMul<T>(Tensor<T> aReal, Tensor<T> aImag, Tensor<T> bReal, Tensor<T> bImag)
    {
        if (aReal == null || aImag == null || bReal == null || bImag == null)
            throw new ArgumentNullException("ComplexMatMul inputs cannot be null");
        var aShape = aReal._shape;
        var bShape = bReal._shape;
        if (aShape.Length != 2 || bShape.Length != 2 || aShape[1] != bShape[0])
            throw new ArgumentException("ComplexMatMul expects shapes [M,K] x [K,N]");

        int m = aShape[0];
        int k = aShape[1];
        int n = bShape[1];

        var realOut = TensorAllocator.Rent<T>([m, n]);
        var imagOut = TensorAllocator.Rent<T>([m, n]);

        var numOps = MathHelper.GetNumericOperations<T>();

        for (int i = 0; i < m; i++)
        {
            for (int j = 0; j < n; j++)
            {
                T realSum = numOps.Zero;
                T imagSum = numOps.Zero;
                for (int kk = 0; kk < k; kk++)
                {
                    var ar = aReal[i, kk];
                    var ai = aImag[i, kk];
                    var br = bReal[kk, j];
                    var bi = bImag[kk, j];
                    // (ar + i ai) * (br + i bi) = (ar*br - ai*bi) + i(ar*bi + ai*br)
                    realSum = numOps.Add(realSum, numOps.Subtract(numOps.Multiply(ar, br), numOps.Multiply(ai, bi)));
                    imagSum = numOps.Add(imagSum, numOps.Add(numOps.Multiply(ar, bi), numOps.Multiply(ai, br)));
                }
                realOut[i, j] = realSum;
                imagOut[i, j] = imagSum;
            }
        }

        return (realOut, imagOut);
    }

    public Tensor<T> ComplexMagnitudeSquared<T>(Tensor<T> real, Tensor<T> imag)
    {
        if (real == null || imag == null)
            throw new ArgumentNullException("ComplexMagnitudeSquared inputs cannot be null");
        if (GraphMode.IsActive) { var scope = GraphMode.Current; if (scope is not null) { var c_real = real; var c_imag = imag; return scope.RecordBinary(LazyNodeType.Custom, "ComplexMagnitudeSquared", real, imag, real._shape, (eng, output) => { var r = eng.ComplexMagnitudeSquared(c_real, c_imag); r.AsSpan().CopyTo(output.AsWritableSpan()); }, BackwardFunctions<T>.ComplexMagnitudeSquaredBackward); } }
        { var ac = AutoTracer.TryGetCompiledPlan<T>("ComplexMagnitudeSquared", real._shape); if (ac is not null) return ac.Execute(); }

        if (!real._shape.SequenceEqual(imag._shape))
            throw new ArgumentException("Real and imaginary parts must have the same shape");

        var numOps = MathHelper.GetNumericOperations<T>();
        var output = AutoTensorCache.RentOrAllocate<T>(real._shape);
        for (int idx = 0; idx < real.Length; idx++)
        {
            var r = real[idx];
            var i = imag[idx];
            output[idx] = numOps.Add(numOps.Multiply(r, r), numOps.Multiply(i, i));
        }
        DifferentiableOps.RecordBinary("ComplexMagnitudeSquared", output, real, imag, BackwardFunctions<T>.ComplexMagnitudeSquaredBackward);
        { var cr = real; var ci2 = imag; AutoTracer.RecordOp("ComplexMagnitudeSquared", output, eng => eng.ComplexMagnitudeSquared(cr, ci2)); }
        return output;
    }

    public (Tensor<T> real, Tensor<T> imag) ComplexNormalize<T>(Tensor<T> real, Tensor<T> imag)
    {
        var magSq = ComplexMagnitudeSquared(real, imag);
        var total = TensorSum(magSq);
        var numOps = MathHelper.GetNumericOperations<T>();
        if (numOps.Equals(total, numOps.Zero))
            return (real.Clone(), imag.Clone());
        var denom = numOps.Sqrt(total);
        var denomTensor = AutoTensorCache.RentOrAllocate<T>(magSq._shape);
        denomTensor.Fill(denom);
        var realNorm = TensorDivide(real, denomTensor);
        var imagNorm = TensorDivide(imag, denomTensor);
        return (realNorm, imagNorm);
    }

    /// <summary>
    /// Write-through 4D-NCHW crop. Mirrors <see cref="Crop{T}"/> but writes
    /// into the supplied output buffer with row-contiguous BlockCopy/Array
    /// .Copy. Used by detection postprocessing and ROI-based pipelines.
    /// </summary>
    public void CropInto<T>(Tensor<T> output, Tensor<T> input, int top, int left, int height, int width)
    {
        if (output == null) throw new ArgumentNullException(nameof(output));
        if (input == null) throw new ArgumentNullException(nameof(input));
        var shape = input._shape;
        if (shape.Length != 4)
            throw new ArgumentException("CropInto expects 4D tensor [batch, channels, height, width]");

        int batch = shape[0];
        int channels = shape[1];
        int inputHeight = shape[2];
        int inputWidth = shape[3];

        if (top < 0 || left < 0 || top + height > inputHeight || left + width > inputWidth)
            throw new ArgumentException("Crop region is out of bounds");

        if (typeof(T) == typeof(float)
            && input.GetDataArray() is float[] inArr
            && output.GetDataArray() is float[] outArr)
        {
            int totalBC = batch * channels;
            int iH = inputHeight, iW = inputWidth, oH = height, oW = width;
            int t = top, l = left;
            Action<int> kernel = bc =>
            {
                int inBase = bc * iH * iW + t * iW + l;
                int outBase = bc * oH * oW;
                for (int oh = 0; oh < oH; oh++)
                {
                    Buffer.BlockCopy(inArr, (inBase + oh * iW) * sizeof(float),
                                     outArr, (outBase + oh * oW) * sizeof(float),
                                     oW * sizeof(float));
                }
            };
            if (totalBC > 8) Parallel.For(0, totalBC, kernel);
            else for (int bc = 0; bc < totalBC; bc++) kernel(bc);
            return;
        }

        var inputData = input.GetFlattenedData();
        var outputData = output.GetDataArray();
        Parallel.For(0, batch * channels, bc =>
        {
            int inBase = bc * inputHeight * inputWidth + top * inputWidth + left;
            int outBase = bc * height * width;
            for (int oh = 0; oh < height; oh++)
            {
                Array.Copy(inputData, inBase + oh * inputWidth,
                           outputData, outBase + oh * width, width);
            }
        });
    }

    /// <inheritdoc/>
    public Tensor<T> Crop<T>(Tensor<T> input, int top, int left, int height, int width)
    {
        var shape = input._shape;
        if (shape.Length != 4)
            throw new ArgumentException("Crop expects 4D tensor [batch, channels, height, width]");
        if (GraphMode.IsActive)
        {
            var scope = GraphMode.Current;
            if (scope is not null)
            {
                var c_input = input;
                int c_top = top, c_left = left, c_height = height, c_width = width;
                // FIX: previous code passed input._shape, leaving the output buffer
                // sized for the un-cropped input — only the leading bytes were
                // overwritten, downstream ops saw stale data after the crop.
                var outShape = new[] { shape[0], shape[1], height, width };
                return scope.RecordUnary(LazyNodeType.Custom, "Crop", input, outShape,
                    (eng, output) =>
                    {
                        if (eng is CpuEngine cpuEng) cpuEng.CropInto(output, c_input, c_top, c_left, c_height, c_width);
                        else { var r = eng.Crop(c_input, c_top, c_left, c_height, c_width); r.AsSpan().CopyTo(output.AsWritableSpan()); }
                    },
                    BackwardFunctions<T>.CropBackward, new object[] { c_top, c_left });
            }
        }
        { var ac = AutoTracer.TryGetCompiledPlan<T>("Crop", input._shape); if (ac is not null) return ac.Execute(); }

        int batch = shape[0];
        int channels = shape[1];
        int inputHeight = shape[2];
        int inputWidth = shape[3];

        if (top < 0 || left < 0 || top + height > inputHeight || left + width > inputWidth)
            throw new ArgumentException("Crop region is out of bounds");

        var cropResult = TensorAllocator.Rent<T>([batch, channels, height, width]);
        CropInto(cropResult, input, top, left, height, width);
        DifferentiableOps.RecordUnary("Crop", cropResult, input, BackwardFunctions<T>.CropBackward, new object[] { top, left });
        { var ci = input; var ct = top; var cl = left; var ch = height; var cw = width; AutoTracer.RecordOp("Crop", cropResult, eng => eng.Crop(ci, ct, cl, ch, cw)); }
        return cropResult;
    }

    /// <inheritdoc/>
    public Tensor<T> CropBackward<T>(Tensor<T> gradOutput, int[] inputShape, int top, int left)
    {
        var numOps = MathHelper.GetNumericOperations<T>();

        int batch = inputShape[0];
        int channels = inputShape[1];
        int inputHeight = inputShape[2];
        int inputWidth = inputShape[3];

        var gradOutputShape = gradOutput._shape;
        int cropHeight = gradOutputShape[2];
        int cropWidth = gradOutputShape[3];

        var gradOutputData = gradOutput.GetFlattenedData();
        var gradInputData = new T[batch * channels * inputHeight * inputWidth];

        for (int i = 0; i < gradInputData.Length; i++)
            gradInputData[i] = numOps.Zero;

        Parallel.For(0, batch * channels, bc =>
        {
            int b = bc / channels;
            int c = bc % channels;

            for (int oh = 0; oh < cropHeight; oh++)
            {
                int ih = top + oh;
                for (int ow = 0; ow < cropWidth; ow++)
                {
                    int iw = left + ow;
                    int gradOutputIdx = ((b * channels + c) * cropHeight + oh) * cropWidth + ow;
                    int gradInputIdx = ((b * channels + c) * inputHeight + ih) * inputWidth + iw;
                    gradInputData[gradInputIdx] = gradOutputData[gradOutputIdx];
                }
            }
        });

        return TensorAllocator.Rent<T>(inputShape, new Vector<T>(gradInputData));
    }

    /// <summary>
    /// Write-through 2D-spatial pad. Mirrors <see cref="Pad{T}"/> but writes
    /// into the supplied output. The eager path was per-element fill + per-
    /// element copy (O(NHW) memory bandwidth twice). This implementation
    /// uses Array.Clear for zero-pad and Buffer.MemoryCopy per row, cutting
    /// the inner copy from 4 ops/element to a single memcpy. Hot whenever
    /// an ONNX model uses an explicit Pad op before Conv (asymmetric pads,
    /// non-zero pad value, or padding modes Conv2D doesn't support natively).
    /// </summary>
    public void PadInto<T>(Tensor<T> output, Tensor<T> input, int padTop, int padBottom, int padLeft, int padRight, T padValue)
    {
        if (output == null) throw new ArgumentNullException(nameof(output));
        if (input == null) throw new ArgumentNullException(nameof(input));
        var inputOrig = input;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!input.IsContiguous) input = input.Contiguous();
        var shape = input._shape;
        if (shape.Length < 2) throw new ArgumentException("PadInto expects at least 2D tensor");

        int rank = shape.Length;
        int height = shape[rank - 2];
        int width = shape[rank - 1];
        int newHeight = height + padTop + padBottom;
        int newWidth = width + padLeft + padRight;
        int batchSize = 1;
        for (int i = 0; i < rank - 2; i++) batchSize *= shape[i];

        if (typeof(T) == typeof(float)
            && input.GetDataArray() is float[] inArr
            && output.GetDataArray() is float[] outArr)
        {
            float padF = padValue is float fv ? fv : 0f;
            // Fast fill: Array.Clear if zero pad, scalar fill otherwise.
            if (padF == 0f)
            {
                Array.Clear(outArr, 0, outArr.Length);
            }
            else
            {
                outArr.AsSpan().Fill(padF);
            }
            int h = height, w = width, nH = newHeight, nW = newWidth;
            int pt = padTop, pl = padLeft;
            Action<int> kernel = b =>
            {
                int inBase = b * h * w;
                int outBase = b * nH * nW + pt * nW + pl;
                for (int ih = 0; ih < h; ih++)
                {
                    Buffer.BlockCopy(inArr, (inBase + ih * w) * sizeof(float),
                                     outArr, (outBase + ih * nW) * sizeof(float),
                                     w * sizeof(float));
                }
            };
            if (batchSize > 4) Parallel.For(0, batchSize, kernel);
            else for (int b = 0; b < batchSize; b++) kernel(b);
            return;
        }

        var inputData = input.GetFlattenedData();
        var outputData = output.GetDataArray();
        // Single fill of the whole output with padValue (Span<T>.Fill is
        // available across all target frameworks via System.Memory).
        outputData.AsSpan().Fill(padValue);
        Parallel.For(0, batchSize, b =>
        {
            int inBase = b * height * width;
            int outBase = b * newHeight * newWidth + padTop * newWidth + padLeft;
            // Per-row contiguous copy.
            for (int ih = 0; ih < height; ih++)
            {
                Array.Copy(inputData, inBase + ih * width,
                           outputData, outBase + ih * newWidth, width);
            }
        });
    }

    /// <inheritdoc/>
    public Tensor<T> Pad<T>(Tensor<T> input, int padTop, int padBottom, int padLeft, int padRight, T padValue)
    {
        var inputOrig = input;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!input.IsContiguous) input = input.Contiguous();
        var shape = input._shape;
        if (shape.Length < 2)
            throw new ArgumentException("Pad expects at least 2D tensor");

        if (GraphMode.IsActive)
        {
            var scope = GraphMode.Current;
            if (scope != null)
            {
                var captured = input;
                int capTop = padTop, capBottom = padBottom, capLeft = padLeft, capRight = padRight;
                T capValue = padValue;
                int capRank = shape.Length;
                var outShape = (int[])shape.Clone();
                outShape[capRank - 2] += padTop + padBottom;
                outShape[capRank - 1] += padLeft + padRight;
                return scope.RecordUnary(LazyNodeType.Custom, "Pad", input, outShape,
                    (eng, output) =>
                    {
                        if (eng is CpuEngine cpuEng) cpuEng.PadInto(output, captured, capTop, capBottom, capLeft, capRight, capValue);
                        else { var r = eng.Pad(captured, capTop, capBottom, capLeft, capRight, capValue); r.AsSpan().CopyTo(output.AsWritableSpan()); }
                    },
                    BackwardFunctions<T>.PadBackward, new object[] { capTop, capLeft });
            }
        }

        int rank = shape.Length;
        int height = shape[rank - 2];
        int width = shape[rank - 1];

        int newHeight = height + padTop + padBottom;
        int newWidth = width + padLeft + padRight;

        var newShape = (int[])shape.Clone();
        newShape[rank - 2] = newHeight;
        newShape[rank - 1] = newWidth;

        var padResult = TensorAllocator.Rent<T>(newShape);
        PadInto(padResult, input, padTop, padBottom, padLeft, padRight, padValue);
        DifferentiableOps.RecordUnary("Pad", padResult, inputOrig, BackwardFunctions<T>.PadBackward, new object[] { padTop, padLeft });
        { var ci = input; var cpt = padTop; var cpb = padBottom; var cpl = padLeft; var cpr = padRight; var cpv = padValue; AutoTracer.RecordOp("Pad", padResult, eng => eng.Pad(ci, cpt, cpb, cpl, cpr, cpv)); }
        return padResult;
    }

    /// <inheritdoc/>
    public Tensor<T> PadBackward<T>(Tensor<T> gradOutput, int padTop, int padLeft, int[] inputShape)
    {
        int rank = inputShape.Length;
        int height = inputShape[rank - 2];
        int width = inputShape[rank - 1];

        int batchSize = 1;
        for (int i = 0; i < rank - 2; i++)
            batchSize *= inputShape[i];

        var gradOutputShape = gradOutput._shape;
        int paddedHeight = gradOutputShape[rank - 2];
        int paddedWidth = gradOutputShape[rank - 1];

        var gradOutputData = gradOutput.GetFlattenedData();
        var gradInputData = new T[batchSize * height * width];

        Parallel.For(0, batchSize, b =>
        {
            for (int ih = 0; ih < height; ih++)
            {
                int oh = ih + padTop;
                for (int iw = 0; iw < width; iw++)
                {
                    int ow = iw + padLeft;
                    int gradOutputIdx = b * paddedHeight * paddedWidth + oh * paddedWidth + ow;
                    int gradInputIdx = b * height * width + ih * width + iw;
                    gradInputData[gradInputIdx] = gradOutputData[gradOutputIdx];
                }
            }
        });

        return TensorAllocator.Rent<T>(inputShape, new Vector<T>(gradInputData));
    }

    /// <inheritdoc/>
    public Tensor<T> Concat<T>(IReadOnlyList<Tensor<T>> tensors, int axis)
    {
        if (tensors == null || tensors.Count == 0)
            throw new ArgumentException("At least one tensor required for concatenation");

        if (GraphMode.IsActive)
        {
            var scope = GraphMode.Current;
            if (scope != null)
            {
                var captured = tensors.ToArray();
                int capturedAxis = axis < 0 ? tensors[0]._shape.Length + axis : axis;
                var outShape = (int[])tensors[0]._shape.Clone();
                int totalAxis = 0;
                foreach (var t in tensors) totalAxis += t._shape[capturedAxis];
                outShape[capturedAxis] = totalAxis;
                return scope.RecordVariadic(LazyNodeType.Custom, "Concat", captured, outShape,
                    (eng, output) =>
                    {
                        if (eng is CpuEngine cpuEng) cpuEng.ConcatInto(output, captured, capturedAxis);
                        else { var r = eng.Concat(captured, capturedAxis); r.AsSpan().CopyTo(output.AsWritableSpan()); }
                    },
                    BackwardFunctions<T>.ConcatenateBackward, new object[] { capturedAxis });
            }
        }

        var firstShape = tensors[0]._shape;
        int rank = firstShape.Length;

        if (axis < 0) axis = rank + axis;
        if (axis < 0 || axis >= rank)
            throw new ArgumentException($"Invalid axis {axis} for tensor with {rank} dimensions");

        int totalAxisSize = 0;
        foreach (var tensor in tensors)
        {
            if (tensor._shape.Length != rank)
                throw new ArgumentException("All tensors must have the same number of dimensions");

            for (int i = 0; i < rank; i++)
            {
                if (i != axis && tensor._shape[i] != firstShape[i])
                    throw new ArgumentException($"All tensors must have the same shape except along axis {axis}");
            }

            totalAxisSize += tensor._shape[axis];
        }

        var outputShape = (int[])firstShape.Clone();
        outputShape[axis] = totalAxisSize;

        int outputSize = outputShape.Aggregate(1, (a, b) => a * b);
        var outputData = new T[outputSize];

        // NCHWc8 fast path: channel-axis concat where every input is
        // NCHWc8 and each C is divisible by the cBlock. Physical layout is
        // [N, cg, H, W, 8], so concat along cg is contiguous-block memcpy
        // per-batch — no index math per element.
        bool nchwcChannelConcat =
            typeof(T) == typeof(float) &&
            axis == 1 &&
            rank == 4 &&
            tensors.All(t => t.Layout == LinearAlgebra.TensorLayout.Nchwc8 &&
                             t._shape[1] % Simd.NchwcPool.CBlock == 0);
        if (nchwcChannelConcat)
        {
            int cb = Simd.NchwcPool.CBlock;
            int N = firstShape[0], H = firstShape[2], W = firstShape[3];
            int cgOut = totalAxisSize / cb;
            int outImageStride = cgOut * H * W * cb; // floats per batch image
            var outF = (T[])(object)outputData;
            int dstCgOffset = 0;
            foreach (var t in tensors)
            {
                int cgIn = t._shape[1] / cb;
                int inImageStride = cgIn * H * W * cb;
                var srcF = (Tensor<float>)(object)t;
                var srcData = srcF.GetDataArray();
                int copyPerImage = cgIn * H * W * cb;
                for (int n = 0; n < N; n++)
                {
                    int dstBase = n * outImageStride + dstCgOffset * H * W * cb;
                    int srcBase = n * inImageStride;
                    Array.Copy(srcData, srcBase, (float[])(object)outF, dstBase, copyPerImage);
                }
                dstCgOffset += cgIn;
            }
            var packedResult = TensorAllocator.Rent<T>(outputShape, new Vector<T>(outputData));
            packedResult.Layout = LinearAlgebra.TensorLayout.Nchwc8;
            return packedResult;
        }

        var outputStrides = ComputeStrides(outputShape);

        int axisOffset = 0;
        foreach (var tensor in tensors)
        {
            var tensorData = tensor.GetDataArray();
            var tensorShape = tensor._shape;
            var tensorStrides = ComputeStrides(tensorShape);

            for (int i = 0; i < tensor.Length; i++)
            {
                var multiIndex = FlatToMultiIndex(i, tensorShape, tensorStrides);
                multiIndex[axis] += axisOffset;
                int outputIdx = MultiToFlatIndex(multiIndex, outputShape, outputStrides);
                outputData[outputIdx] = tensorData[i];
            }

            axisOffset += tensor._shape[axis];
        }

        var result = TensorAllocator.Rent<T>(outputShape, new Vector<T>(outputData));
        if (GradientTape<T>.Current is not null)
        {
            DifferentiableOps.RecordIfActive("Concat", result, tensors.ToArray(),
                BackwardFunctions<T>.ConcatenateBackward, new object[] { axis });
        }
        { var ct = tensors; var ca = axis; AutoTracer.RecordOp("Concat", result, eng => eng.Concat(ct, ca)); }
        return result;
    }

    /// <inheritdoc/>
    public unsafe T TensorSumOfSquares<T>(Tensor<T> tensor)
    {
        if (tensor == null) throw new ArgumentNullException(nameof(tensor));

#if NET5_0_OR_GREATER
        if (typeof(T) == typeof(float))
        {
            T[] arr = tensor.GetFlattenedData();
            float[] fArr = Unsafe.As<T[], float[]>(ref arr);
            int length = tensor.Length;
            float result;

            fixed (float* ptr = fArr)
            {
                result = SumOfSquaresUnsafe(ptr, length);
            }
            return Unsafe.As<float, T>(ref result);
        }
#endif

        var numOps = MathHelper.GetNumericOperations<T>();
        return numOps.Dot(tensor.AsSpan(), tensor.AsSpan());
    }

#if NET5_0_OR_GREATER
    /// <summary>
    /// SIMD sum of squares: sum(x[i] * x[i]) with 4x unrolled FMA accumulation.
    /// </summary>
    private static unsafe float SumOfSquaresUnsafe(float* data, int length)
    {
        int i = 0;
        float result = 0f;

        if (System.Runtime.Intrinsics.X86.Fma.IsSupported && length >= 32)
        {
            var vsum0 = System.Runtime.Intrinsics.Vector256<float>.Zero;
            var vsum1 = vsum0; var vsum2 = vsum0; var vsum3 = vsum0;
            int simdLen = length & ~31;
            for (; i < simdLen; i += 32)
            {
                var v0 = System.Runtime.Intrinsics.X86.Avx.LoadVector256(data + i);
                var v1 = System.Runtime.Intrinsics.X86.Avx.LoadVector256(data + i + 8);
                var v2 = System.Runtime.Intrinsics.X86.Avx.LoadVector256(data + i + 16);
                var v3 = System.Runtime.Intrinsics.X86.Avx.LoadVector256(data + i + 24);
                vsum0 = System.Runtime.Intrinsics.X86.Fma.MultiplyAdd(v0, v0, vsum0);
                vsum1 = System.Runtime.Intrinsics.X86.Fma.MultiplyAdd(v1, v1, vsum1);
                vsum2 = System.Runtime.Intrinsics.X86.Fma.MultiplyAdd(v2, v2, vsum2);
                vsum3 = System.Runtime.Intrinsics.X86.Fma.MultiplyAdd(v3, v3, vsum3);
            }
            vsum0 = System.Runtime.Intrinsics.X86.Avx.Add(
                System.Runtime.Intrinsics.X86.Avx.Add(vsum0, vsum1),
                System.Runtime.Intrinsics.X86.Avx.Add(vsum2, vsum3));
            // Horizontal sum
            var hi = System.Runtime.Intrinsics.X86.Avx.ExtractVector128(vsum0, 1);
            var lo = System.Runtime.Intrinsics.X86.Avx.ExtractVector128(vsum0, 0);
            var s128 = System.Runtime.Intrinsics.X86.Sse.Add(lo, hi);
            var shuf = System.Runtime.Intrinsics.X86.Sse.Shuffle(s128, s128, 0b_01_00_11_10);
            s128 = System.Runtime.Intrinsics.X86.Sse.Add(s128, shuf);
            shuf = System.Runtime.Intrinsics.X86.Sse.Shuffle(s128, s128, 0b_10_11_00_01);
            s128 = System.Runtime.Intrinsics.X86.Sse.Add(s128, shuf);
            float tmp;
            System.Runtime.Intrinsics.X86.Sse.StoreScalar(&tmp, s128);
            result = tmp;
        }

        for (; i < length; i++)
            result += data[i] * data[i];
        return result;
    }
#endif

    /// <inheritdoc/>
    public Tensor<TValue> TensorEmbeddingLookup<TValue, TIndex>(Tensor<TValue> embeddings, Tensor<TIndex> indices)
        where TIndex : unmanaged
    {
        if (embeddings == null) throw new ArgumentNullException(nameof(embeddings));
        if (indices == null) throw new ArgumentNullException(nameof(indices));
        if (embeddings.Rank != 2)
            throw new ArgumentException($"Embeddings must be a 2D tensor [vocab_size, embedding_dim]. Got rank {embeddings.Rank}.");

        int vocabSize = embeddings._shape[0];
        int embeddingDim = embeddings._shape[1];
        int numIndices = indices.Length;

        // Output shape is [*indices.shape, embedding_dim]
        var outputShape = new int[indices.Rank + 1];
        for (int i = 0; i < indices.Rank; i++)
        {
            outputShape[i] = indices._shape[i];
        }
        outputShape[indices.Rank] = embeddingDim;

        var result = new Tensor<TValue>(outputShape);
        var embData = embeddings.GetDataArray();
        var resultData = result.GetDataArray();
        var idxData = indices.GetDataArray();

        // For each index, copy the entire embedding row
        for (int i = 0; i < numIndices; i++)
        {
            int tokenIdx = Convert.ToInt32(idxData[i]);

            // Bounds check for index
            if (tokenIdx < 0 || tokenIdx >= vocabSize)
                throw new ArgumentOutOfRangeException(nameof(indices),
                    $"Index {tokenIdx} at position {i} is out of bounds for embedding table with vocabulary size {vocabSize}.");

            int srcOffset = tokenIdx * embeddingDim;
            int dstOffset = i * embeddingDim;

            // Direct array copy of embedding row
            Array.Copy(embData, srcOffset, resultData, dstOffset, embeddingDim);
        }

        // Tape registration. Without this, dL/dE was silently dropped — see #255.
        // Indices are non-trainable; only the embedding table receives gradient.
        // Snapshot the indices as a portable int[] (widening from long if
        // necessary) so the savedState round-trips through SavedStateSerializer:
        // it supports null/int/int[]/double/float/bool/string/byte[]/Tensor<T>/Enum,
        // but not Tensor<TIndex> for TIndex != T.
        if (DifferentiableOps.IsTapeActiveForThread<TValue>())
        {
            var indicesSnap = new int[numIndices];
            for (int i = 0; i < numIndices; i++) indicesSnap[i] = Convert.ToInt32(idxData[i]);
            var indicesShapeSnap = (int[])indices._shape.Clone();
            DifferentiableOps.RecordUnary(
                "TensorEmbeddingLookup",
                result,
                embeddings,
                BackwardFunctions<TValue>.TensorEmbeddingLookupBackward,
                new object[] { indicesSnap, indicesShapeSnap, vocabSize, embeddingDim });
        }

        return result;
    }

    /// <inheritdoc/>
    public Tensor<TValue> TensorEmbeddingLookupBackward<TValue, TIndex>(Tensor<TValue> gradOutput, Tensor<TIndex> indices, int vocabSize, int embeddingDim)
        where TIndex : unmanaged
    {
        if (gradOutput == null) throw new ArgumentNullException(nameof(gradOutput));
        if (indices == null) throw new ArgumentNullException(nameof(indices));
        if (vocabSize <= 0)
            throw new ArgumentOutOfRangeException(nameof(vocabSize), "Vocabulary size must be positive.");
        if (embeddingDim <= 0)
            throw new ArgumentOutOfRangeException(nameof(embeddingDim), "Embedding dimension must be positive.");

        var numOps = MathHelper.GetNumericOperations<TValue>();
        var gradEmbeddings = new Tensor<TValue>(new[] { vocabSize, embeddingDim });
        var gradEmbData = gradEmbeddings.GetDataArray();

        var gradData = gradOutput.GetDataArray();
        var idxData = indices.GetDataArray();
        int numIndices = indices.Length;

        // Scatter-add: for each index, accumulate gradients to the embedding row
        for (int i = 0; i < numIndices; i++)
        {
            int tokenIdx = Convert.ToInt32(idxData[i]);

            // Bounds check for index
            if (tokenIdx < 0 || tokenIdx >= vocabSize)
                throw new ArgumentOutOfRangeException(nameof(indices),
                    $"Index {tokenIdx} at position {i} is out of bounds for vocabulary size {vocabSize}.");

            int srcOffset = i * embeddingDim;
            int dstOffset = tokenIdx * embeddingDim;

            // Accumulate gradient for this embedding row - direct array access
            for (int d = 0; d < embeddingDim; d++)
            {
                gradEmbData[dstOffset + d] = numOps.Add(gradEmbData[dstOffset + d], gradData[srcOffset + d]);
            }
        }

        return gradEmbeddings;
    }

    /// <inheritdoc/>
    public Tensor<T> RBFKernel<T>(Tensor<T> input, Tensor<T> centers, Tensor<T> epsilons)
    {
        if (input == null) throw new ArgumentNullException(nameof(input));
        if (centers == null) throw new ArgumentNullException(nameof(centers));
        if (epsilons == null) throw new ArgumentNullException(nameof(epsilons));
        if (GraphMode.IsActive) { var scope = GraphMode.Current; if (scope is not null) { var c_input = input; var c_centers = centers; var c_epsilons = epsilons; return scope.RecordVariadic(LazyNodeType.Custom, "RBFKernel", new[] { input, centers, epsilons }, input._shape, (eng, output) => { var r = eng.RBFKernel(c_input, c_centers, c_epsilons); r.AsSpan().CopyTo(output.AsWritableSpan()); }, BackwardFunctions<T>.RBFKernelBackward); } }
        { var ac = AutoTracer.TryGetCompiledPlan<T>("RBFKernel", input._shape); if (ac is not null) return ac.Execute(); }

        if (input.Rank != 2)
            throw new ArgumentException($"input must be 2D [batch, features], got rank {input.Rank}", nameof(input));
        if (centers.Rank != 2)
            throw new ArgumentException($"centers must be 2D [numCenters, features], got rank {centers.Rank}", nameof(centers));
        if (epsilons.Rank != 1)
            throw new ArgumentException($"epsilons must be 1D [numCenters], got rank {epsilons.Rank}", nameof(epsilons));

        var numOps = MathHelper.GetNumericOperations<T>();
        int batchSize = input._shape[0];
        int features = input._shape[1];
        int numCenters = centers._shape[0];

        if (centers._shape[1] != features)
            throw new ArgumentException($"centers features dimension ({centers._shape[1]}) must match input features ({features})", nameof(centers));
        if (epsilons._shape[0] != numCenters)
            throw new ArgumentException($"epsilons length ({epsilons._shape[0]}) must match number of centers ({numCenters})", nameof(epsilons));

        var output = TensorAllocator.Rent<T>([batchSize, numCenters]);
        var inputData = input.GetFlattenedData();
        var centersData = centers.GetFlattenedData();
        var epsilonsData = epsilons.GetFlattenedData();

        // Compute exp(-epsilon * ||x - center||Ã‚Â²) for each (sample, center) pair
        for (int b = 0; b < batchSize; b++)
        {
            int inputOffset = b * features;
            for (int c = 0; c < numCenters; c++)
            {
                int centerOffset = c * features;
                T distSquared = numOps.Zero;

                // Compute ||x - center||Ã‚Â²
                for (int f = 0; f < features; f++)
                {
                    T diff = numOps.Subtract(inputData[inputOffset + f], centersData[centerOffset + f]);
                    distSquared = numOps.Add(distSquared, numOps.Multiply(diff, diff));
                }

                // Compute exp(-epsilon * distSquared)
                T negEpsDist = numOps.Negate(numOps.Multiply(epsilonsData[c], distSquared));
                output[b, c] = numOps.Exp(negEpsDist);
            }
        }

        DifferentiableOps.RecordIfActive("RBFKernel", output, new[] { input, centers, epsilons }, BackwardFunctions<T>.RBFKernelBackward, epsilonsData.Length > 0 ? new object[] { numOps.ToDouble(epsilonsData[0]) } : Array.Empty<object>());
        { var ci = input; var cc = centers; var ce = epsilons; AutoTracer.RecordOp("RBFKernel", output, eng => eng.RBFKernel(ci, cc, ce)); }
        return output;
    }

    /// <inheritdoc/>
    public (Tensor<T> gradInput, Tensor<T> gradCenters, Tensor<T> gradEpsilons) RBFKernelBackward<T>(
        Tensor<T> gradOutput, Tensor<T> input, Tensor<T> centers, Tensor<T> epsilons, Tensor<T> output)
    {
        if (gradOutput == null) throw new ArgumentNullException(nameof(gradOutput));
        if (input == null) throw new ArgumentNullException(nameof(input));
        if (centers == null) throw new ArgumentNullException(nameof(centers));
        if (epsilons == null) throw new ArgumentNullException(nameof(epsilons));
        if (output == null) throw new ArgumentNullException(nameof(output));

        if (input.Rank != 2)
            throw new ArgumentException($"input must be 2D [batch, features], got rank {input.Rank}", nameof(input));
        if (centers.Rank != 2)
            throw new ArgumentException($"centers must be 2D [numCenters, features], got rank {centers.Rank}", nameof(centers));
        if (epsilons.Rank != 1)
            throw new ArgumentException($"epsilons must be 1D [numCenters], got rank {epsilons.Rank}", nameof(epsilons));
        if (gradOutput.Rank != 2)
            throw new ArgumentException($"gradOutput must be 2D [batch, numCenters], got rank {gradOutput.Rank}", nameof(gradOutput));
        if (output.Rank != 2)
            throw new ArgumentException($"output must be 2D [batch, numCenters], got rank {output.Rank}", nameof(output));

        var numOps = MathHelper.GetNumericOperations<T>();
        int batchSize = input._shape[0];
        int features = input._shape[1];
        int numCenters = centers._shape[0];

        if (centers._shape[1] != features)
            throw new ArgumentException($"centers features dimension ({centers._shape[1]}) must match input features ({features})", nameof(centers));
        if (epsilons._shape[0] != numCenters)
            throw new ArgumentException($"epsilons length ({epsilons._shape[0]}) must match number of centers ({numCenters})", nameof(epsilons));
        if (gradOutput._shape[0] != batchSize || gradOutput._shape[1] != numCenters)
            throw new ArgumentException($"gradOutput shape [{gradOutput._shape[0]}, {gradOutput._shape[1]}] must be [{batchSize}, {numCenters}]", nameof(gradOutput));
        if (output._shape[0] != batchSize || output._shape[1] != numCenters)
            throw new ArgumentException($"output shape [{output._shape[0]}, {output._shape[1]}] must be [{batchSize}, {numCenters}]", nameof(output));

        var gradInput = AutoTensorCache.RentOrAllocate<T>(input._shape);
        var gradCenters = AutoTensorCache.RentOrAllocate<T>(centers._shape);
        var gradEpsilons = AutoTensorCache.RentOrAllocate<T>(epsilons._shape);
        // Zero pooled buffers — RentOrAllocate can return stale data from the cache
        gradInput.AsWritableSpan().Clear();
        gradCenters.AsWritableSpan().Clear();
        gradEpsilons.AsWritableSpan().Clear();

        var inputData = input.GetFlattenedData();
        var centersData = centers.GetFlattenedData();
        var epsilonsData = epsilons.GetFlattenedData();
        var outputData = output.GetDataArray();
        var gradOutputData = gradOutput.GetDataArray();
        var gradInputData = gradInput.GetDataArray();
        var gradCentersData = gradCenters.GetDataArray();

        // For RBF: K = exp(-epsilon * ||x - c||Ã‚Â²)
        // dK/dx = K * (-epsilon) * 2 * (x - c) = -2 * epsilon * K * (x - c)
        // dK/dc = K * (-epsilon) * (-2) * (x - c) = 2 * epsilon * K * (x - c) = -dK/dx
        // dK/depsilon = K * (-||x - c||Ã‚Â²)

        for (int b = 0; b < batchSize; b++)
        {
            int inputOffset = b * features;
            for (int c = 0; c < numCenters; c++)
            {
                int centerOffset = c * features;
                int outIdx = b * numCenters + c;
                T K = outputData[outIdx];
                T eps = epsilonsData[c];
                T dL_dK = gradOutputData[outIdx];

                // Compute ||x - c||Ã‚Â² for epsilon gradient
                T distSquared = numOps.Zero;
                for (int f = 0; f < features; f++)
                {
                    T diff = numOps.Subtract(inputData[inputOffset + f], centersData[centerOffset + f]);
                    distSquared = numOps.Add(distSquared, numOps.Multiply(diff, diff));
                }

                // dL/depsilon += dL/dK * dK/depsilon = dL/dK * K * (-distSquared)
                T gradEps = numOps.Multiply(dL_dK, numOps.Multiply(K, numOps.Negate(distSquared)));
                gradEpsilons[c] = numOps.Add(gradEpsilons[c], gradEps);

                // Common factor: -2 * epsilon * K * dL/dK
                T commonFactor = numOps.Multiply(
                    numOps.Multiply(numOps.FromDouble(-2.0), eps),
                    numOps.Multiply(K, dL_dK));

                for (int f = 0; f < features; f++)
                {
                    T diff = numOps.Subtract(inputData[inputOffset + f], centersData[centerOffset + f]);
                    T grad = numOps.Multiply(commonFactor, diff);

                    // dL/dx = commonFactor * (x - c)
                    int inputIdx = b * features + f;
                    gradInputData[inputIdx] = numOps.Add(gradInputData[inputIdx], grad);

                    // dL/dc = -dL/dx = -commonFactor * (x - c)
                    int centerIdx = c * features + f;
                    gradCentersData[centerIdx] = numOps.Subtract(gradCentersData[centerIdx], grad);
                }
            }
        }

        return (gradInput, gradCenters, gradEpsilons);
    }

    #endregion

    #region Tensor Shape Operations

    /// <inheritdoc/>
    public Tensor<T> TensorRepeatElements<T>(Tensor<T> tensor, int repeats, int axis = 0)
    {
        if (tensor == null) throw new ArgumentNullException(nameof(tensor));
        if (repeats < 1) throw new ArgumentOutOfRangeException(nameof(repeats), "Repeats must be at least 1");
        if (axis < 0 || axis >= tensor._shape.Length)
            throw new ArgumentOutOfRangeException(nameof(axis), $"Axis {axis} out of range for tensor with {tensor._shape.Length} dimensions");
        if (GraphMode.IsActive) { var scope = GraphMode.Current; if (scope is not null) { var c_tensor = tensor; var c_repeats = repeats; var c_axis = axis; return scope.RecordUnary(LazyNodeType.Custom, "TensorRepeatElements", tensor, tensor._shape, (eng, output) => { var r = eng.TensorRepeatElements(c_tensor, c_repeats, c_axis); r.AsSpan().CopyTo(output.AsWritableSpan()); }, BackwardFunctions<T>.RepeatElementsBackward); } }


        // Calculate output shape
        var outputShape = new int[tensor._shape.Length];
        Array.Copy(tensor._shape, outputShape, tensor._shape.Length);
        outputShape[axis] *= repeats;

        var result = AutoTensorCache.RentOrAllocate<T>(outputShape);

        // Calculate strides for the tensor
        int outerSize = 1;
        for (int i = 0; i < axis; i++)
            outerSize *= tensor._shape[i];

        int axisSize = tensor._shape[axis];
        int innerSize = 1;
        for (int i = axis + 1; i < tensor._shape.Length; i++)
            innerSize *= tensor._shape[i];

        var tensorData = tensor.GetFlattenedData();
        var resultData = result.GetDataArray();

        // Perform the repeat operation
        Parallel.For(0, outerSize, outer =>
        {
            for (int a = 0; a < axisSize; a++)
            {
                int srcBase = (outer * axisSize + a) * innerSize;
                int dstBase = (outer * axisSize * repeats + a * repeats) * innerSize;

                for (int r = 0; r < repeats; r++)
                {
                    int dstOffset = dstBase + r * innerSize;
                    Array.Copy(tensorData, srcBase, resultData, dstOffset, innerSize);
                }
            }
        });

        DifferentiableOps.RecordUnary("TensorRepeatElements", result, tensor, BackwardFunctions<T>.RepeatElementsBackward, new object[] { repeats, axis });
        { var ct = tensor; var cr = repeats; var ca = axis; AutoTracer.RecordOp("TensorRepeatElements", result, eng => eng.TensorRepeatElements(ct, cr, ca)); }
        return result;
    }

    /// <inheritdoc/>
    public virtual Tensor<T> TensorTile<T>(Tensor<T> tensor, int[] multiples)
    {
        if (tensor == null) throw new ArgumentNullException(nameof(tensor));
        if (multiples == null) throw new ArgumentNullException(nameof(multiples));
        var tensorOrig = tensor;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!tensor.IsContiguous) tensor = tensor.Contiguous();
        if (multiples.Length != tensor._shape.Length)
            throw new ArgumentException($"Multiples length ({multiples.Length}) must match tensor dimensions ({tensor._shape.Length})");

        if (GraphMode.IsActive)
        {
            var scope = GraphMode.Current;
            if (scope != null)
            {
                var captured = tensor;
                var capMultiples = (int[])multiples.Clone();
                var outShape = new int[tensor._shape.Length];
                for (int i = 0; i < tensor._shape.Length; i++)
                    outShape[i] = tensor._shape[i] * multiples[i];
                return scope.RecordUnary(LazyNodeType.Custom, "Tile", tensor, outShape,
                    (eng, output) => { var r = eng.TensorTile(captured, capMultiples); r.AsSpan().CopyTo(output.AsWritableSpan()); },
                    BackwardFunctions<T>.TileBackward);
            }
        }

        { var ac = AutoTracer.TryGetCompiledPlan<T>("Tile", tensor._shape); if (ac is not null) return ac.Execute(); }

        // Calculate output shape
        var outputShape = new int[tensor._shape.Length];
        for (int i = 0; i < tensor._shape.Length; i++)
        {
            if (multiples[i] < 1)
                throw new ArgumentOutOfRangeException(nameof(multiples), $"Multiple at index {i} must be at least 1");
            outputShape[i] = tensor._shape[i] * multiples[i];
        }

        var result = AutoTensorCache.RentOrAllocate<T>(outputShape);
        var tensorData = tensor.GetDataArray();
        var resultData = result.GetDataArray();
        int srcLen = tensor.Length;

        // Fast path: only tiling along axis 0 (other axes multiply=1)
        bool onlyAxis0 = true;
        for (int i = 1; i < multiples.Length; i++)
            if (multiples[i] != 1) { onlyAxis0 = false; break; }

        if (onlyAxis0)
        {
            // Just copy the source data `multiples[0]` times
            for (int m = 0; m < multiples[0]; m++)
                Array.Copy(tensorData, 0, resultData, m * srcLen, srcLen);
        }
        else
        {
            // General tiling via per-element index mapping
            int totalElements = result.Length;
            Parallel.For(0, totalElements, flatIdx =>
            {
                int remaining = flatIdx;
                int inputFlat = 0;
                int inStride = 1;
                for (int d = outputShape.Length - 1; d >= 0; d--)
                {
                    int outIdx = remaining % outputShape[d];
                    remaining /= outputShape[d];
                    inputFlat += (outIdx % tensor._shape[d]) * inStride;
                    inStride *= tensor._shape[d];
                }
                resultData[flatIdx] = tensorData[inputFlat];
            });
        }

        DifferentiableOps.RecordUnary("Tile", result, tensorOrig,
            BackwardFunctions<T>.TileBackward);
        AutoTracer.RecordOp("Tile", result, eng => result);
        return result;
    }

    /// <inheritdoc/>
    public virtual Tensor<T> TensorSlice<T>(Tensor<T> tensor, int[] start, int[] length)
    {
        if (tensor == null) throw new ArgumentNullException(nameof(tensor));
        if (start == null) throw new ArgumentNullException(nameof(start));
        if (length == null) throw new ArgumentNullException(nameof(length));
        if (start.Length != tensor._shape.Length)
            throw new ArgumentException($"Start length ({start.Length}) must match tensor dimensions ({tensor._shape.Length})");
        if (length.Length != tensor._shape.Length)
            throw new ArgumentException($"Length length ({length.Length}) must match tensor dimensions ({tensor._shape.Length})");

        if (GraphMode.IsActive)
        {
            var scope = GraphMode.Current;
            if (scope != null)
            {
                var captured = tensor;
                var capStart = (int[])start.Clone();
                var capLength = (int[])length.Clone();
                return scope.RecordUnary(LazyNodeType.Custom, "TensorSlice", tensor, capLength,
                    (eng, output) => { var r = eng.TensorSlice(captured, capStart, capLength); r.AsSpan().CopyTo(output.AsWritableSpan()); },
                    BackwardFunctions<T>.SliceBackward, new object[] { capStart });
            }
        }

        { var ac = AutoTracer.TryGetCompiledPlan<T>("TensorSlice", tensor._shape); if (ac is not null) return ac.Execute(); }

        // Validate bounds
        for (int i = 0; i < tensor._shape.Length; i++)
        {
            if (start[i] < 0 || start[i] >= tensor._shape[i])
                throw new ArgumentOutOfRangeException(nameof(start), $"Start index {start[i]} out of range for axis {i} with size {tensor._shape[i]}");
            if (length[i] < 1 || start[i] + length[i] > tensor._shape[i])
                throw new ArgumentOutOfRangeException(nameof(length), $"Slice length {length[i]} starting at {start[i]} exceeds axis {i} size {tensor._shape[i]}");
        }

        var result = AutoTensorCache.RentOrAllocate<T>(length);
        int totalElements = length.Aggregate(1, (a, b) => a * b);
        var tensorData = tensor.GetFlattenedData();
        var resultData = result.GetDataArray();

        // For each output element, find the corresponding input element
        Parallel.For(0, totalElements, flatIdx =>
        {
            // Convert flat index to output indices and map to input flat index
            int remaining = flatIdx;
            int inputFlat = 0;
            int stride = 1;
            for (int d = tensor._shape.Length - 1; d >= 0; d--)
            {
                int outputIdx = remaining % length[d];
                remaining /= length[d];
                inputFlat += (start[d] + outputIdx) * stride;
                stride *= tensor._shape[d];
            }

            resultData[flatIdx] = tensorData[inputFlat];
        });

        DifferentiableOps.RecordUnary("TensorSlice", result, tensor, BackwardFunctions<T>.SliceBackward, new object[] { start });
        AutoTracer.RecordOp("TensorSlice", result, eng => result);
        return result;
    }

    /// <inheritdoc/>
    public Tensor<T> TensorSetSlice<T>(Tensor<T> destination, Tensor<T> source, int[] start)
    {
        if (destination == null) throw new ArgumentNullException(nameof(destination));
        if (source == null) throw new ArgumentNullException(nameof(source));
        if (start == null) throw new ArgumentNullException(nameof(start));
        if (!destination.IsContiguous) throw new InvalidOperationException("Output tensor must be contiguous.");
        if (start.Length != destination._shape.Length)
            throw new ArgumentException($"Start length ({start.Length}) must match destination dimensions ({destination._shape.Length})");
        if (source._shape.Length != destination._shape.Length)
            throw new ArgumentException($"Source dimensions ({source._shape.Length}) must match destination dimensions ({destination._shape.Length})");

        // Validate bounds
        for (int i = 0; i < destination._shape.Length; i++)
        {
            if (start[i] < 0 || start[i] + source._shape[i] > destination._shape[i])
                throw new ArgumentOutOfRangeException(nameof(start), $"Slice starting at {start[i]} with size {source._shape[i]} exceeds destination axis {i} size {destination._shape[i]}");
        }

        // Create a copy of destination to avoid modifying the original
        var result = AutoTensorCache.RentOrAllocate<T>(destination._shape);
        var destData = destination.GetDataArray();
        var resultData = result.GetDataArray();
        Array.Copy(destData, resultData, destData.Length);

        int sourceTotal = source._shape.Aggregate(1, (a, b) => a * b);
        var sourceData = source.GetFlattenedData();

        // Set the slice values
        Parallel.For(0, sourceTotal, flatIdx =>
        {
            // Convert flat index to source indices and map to dest flat index
            int remaining = flatIdx;
            int destFlat = 0;
            int stride = 1;
            for (int d = destination._shape.Length - 1; d >= 0; d--)
            {
                int srcIdx = remaining % source._shape[d];
                remaining /= source._shape[d];
                destFlat += (start[d] + srcIdx) * stride;
                stride *= destination._shape[d];
            }

            resultData[destFlat] = sourceData[flatIdx];
        });

        return result;
    }

    /// <inheritdoc/>
    public virtual Tensor<T> TensorWhere<T>(Tensor<T> condition, Tensor<T> x, Tensor<T> y)
    {
        if (condition == null) throw new ArgumentNullException(nameof(condition));
        if (x == null) throw new ArgumentNullException(nameof(x));

        if (GraphMode.IsActive)
        {
            var scope = GraphMode.Current;
            if (scope != null)
            {
                var cc = condition; var cx = x; var cy = y;
                return scope.RecordVariadic(LazyNodeType.Custom, "TensorWhere",
                    new[] { condition, x, y }, x._shape,
                    (eng, output) => { var r = eng.TensorWhere(cc, cx, cy); r.AsSpan().CopyTo(output.AsWritableSpan()); });
            }
        }
        if (y == null) throw new ArgumentNullException(nameof(y));
        var yOrig = y;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!y.IsContiguous) y = y.Contiguous();
        var xOrig = x;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!x.IsContiguous) x = x.Contiguous();
        var conditionOrig = condition;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!condition.IsContiguous) condition = condition.Contiguous();

        // All tensors must have the same shape (or be broadcastable, but we'll require same shape for simplicity)
        if (!condition._shape.SequenceEqual(x._shape) || !condition._shape.SequenceEqual(y._shape))
            throw new ArgumentException("All tensors must have the same shape");

        var numOps = MathHelper.GetNumericOperations<T>();
        var result = AutoTensorCache.RentOrAllocate<T>(condition._shape);
        var condSpan = condition.AsSpan();
        var xSpan = x.AsSpan();
        var ySpan = y.AsSpan();
        var dest = result.AsWritableSpan();

        for (int i = 0; i < condSpan.Length; i++)
        {
            bool isTrue = !numOps.Equals(condSpan[i], numOps.Zero);
            dest[i] = isTrue ? xSpan[i] : ySpan[i];
        }

        return result;
    }

    #endregion

    #region Loop Elimination Operations

    /// <inheritdoc/>
    public void TensorCopy<T>(Tensor<T> source, Tensor<T> destination)
    {
        if (source == null) throw new ArgumentNullException(nameof(source));
        if (destination == null) throw new ArgumentNullException(nameof(destination));
        var sourceOrig = source;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!source.IsContiguous) source = source.Contiguous();
        if (!destination.IsContiguous) throw new InvalidOperationException("Output tensor must be contiguous.");
        if (source.Length != destination.Length)
            throw new ArgumentException($"Tensor lengths must match. Got {source.Length} and {destination.Length}");

        // Copy exactly source.Length elements — NOT sourceArray.Length.
        // GetFlattenedData / GetDataArray can return the underlying storage
        // array directly when the tensor is contiguous (zero-copy fast
        // path), and that array may be over-allocated past the logical
        // Length (e.g. arrays grown for capacity headroom). Copying
        // sourceArray.Length would then attempt to write past
        // destination's logical length and throw "Destination array was
        // not long enough", even though the logical Length values agree.
        var sourceArray = source.GetFlattenedData();
        var destArray = destination.GetDataArray();
        Array.Copy(sourceArray, destArray, source.Length);
    }

    /// <inheritdoc/>
    public void TensorFill<T>(Tensor<T> tensor, T value)
    {
        if (tensor == null) throw new ArgumentNullException(nameof(tensor));
        var tensorOrig = tensor;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!tensor.IsContiguous) tensor = tensor.Contiguous();
        tensor.Fill(value);
    }

    /// <inheritdoc/>
    public Tensor<T> TensorOuterProduct<T>(Tensor<T> a, Tensor<T> b)
    {
        if (a == null) throw new ArgumentNullException(nameof(a));
        if (b == null) throw new ArgumentNullException(nameof(b));
        if (GraphMode.IsActive) { var scope = GraphMode.Current; if (scope is not null) { var c_a = a; var c_b = b; return scope.RecordBinary(LazyNodeType.Custom, "TensorOuterProduct", a, b, a._shape, (eng, output) => { var r = eng.TensorOuterProduct(c_a, c_b); r.AsSpan().CopyTo(output.AsWritableSpan()); }, BackwardFunctions<T>.OuterProductBackward); } }


        // Flatten both tensors to 1D
        int n = a.Length;
        int m = b.Length;
        var result = TensorAllocator.Rent<T>([n, m]);
        var numOps = MathHelper.GetNumericOperations<T>();

        var aData = a.GetFlattenedData();
        var bData = b.GetFlattenedData();
        var rData = result.GetDataArray();

        Parallel.For(0, n, i =>
        {
            T ai = aData[i];
            int rowOffset = i * m;
            for (int j = 0; j < m; j++)
            {
                rData[rowOffset + j] = numOps.Multiply(ai, bData[j]);
            }
        });

        DifferentiableOps.RecordBinary("TensorOuterProduct", result, a, b, BackwardFunctions<T>.OuterProductBackward);
        { var ca = a; var cb = b; AutoTracer.RecordOp("TensorOuterProduct", result, eng => eng.TensorOuterProduct(ca, cb)); }
        return result;
    }

    /// <inheritdoc/>
    public Tensor<T> TensorBatchOuterProduct<T>(Tensor<T> a, Tensor<T> b)
    {
        if (a == null) throw new ArgumentNullException(nameof(a));
        if (b == null) throw new ArgumentNullException(nameof(b));
        if (a._shape.Length != 2 || b._shape.Length != 2)
            throw new ArgumentException("Both tensors must be 2D [batch, features]");
        if (a._shape[0] != b._shape[0])
            throw new ArgumentException("Batch sizes must match");
        if (GraphMode.IsActive) { var scope = GraphMode.Current; if (scope is not null) { var c_a = a; var c_b = b; return scope.RecordBinary(LazyNodeType.Custom, "TensorBatchOuterProduct", a, b, a._shape, (eng, output) => { var r = eng.TensorBatchOuterProduct(c_a, c_b); r.AsSpan().CopyTo(output.AsWritableSpan()); }, BackwardFunctions<T>.OuterProductBackward); } }


        int batch = a._shape[0];
        int n = a._shape[1];
        int m = b._shape[1];
        var result = TensorAllocator.Rent<T>([batch, n, m]);
        var numOps = MathHelper.GetNumericOperations<T>();

        Parallel.For(0, batch, bIdx =>
        {
            for (int i = 0; i < n; i++)
            {
                T ai = a[bIdx, i];
                for (int j = 0; j < m; j++)
                {
                    result[bIdx, i, j] = numOps.Multiply(ai, b[bIdx, j]);
                }
            }
        });

        DifferentiableOps.RecordBinary("TensorBatchOuterProduct", result, a, b, BackwardFunctions<T>.OuterProductBackward);
        { var ca = a; var cb = b; AutoTracer.RecordOp("TensorBatchOuterProduct", result, eng => eng.TensorBatchOuterProduct(ca, cb)); }
        return result;
    }

    /// <inheritdoc/>
    public virtual Tensor<T> TensorPermute<T>(Tensor<T> tensor, int[] axes)
    {
        if (tensor == null) throw new ArgumentNullException(nameof(tensor));
        if (axes == null) throw new ArgumentNullException(nameof(axes));
        if (axes.Length != tensor._shape.Length)
            throw new ArgumentException("Axes length must match tensor rank");

        if (GraphMode.IsActive)
        {
            var scope = GraphMode.Current;
            if (scope != null)
            {
                var captured = tensor;
                var capturedAxes = axes;
                // Compute permuted output shape
                var outShape = new int[axes.Length];
                for (int i = 0; i < axes.Length; i++) outShape[i] = tensor._shape[axes[i]];
                return scope.RecordUnary(LazyNodeType.Custom, "TensorPermute", tensor, outShape,
                    // Permute's eager path returns a strided view; .Contiguous()
                    // materializes it into row-major memory so AsSpan doesn't
                    // throw "non-contiguous" when copying into the pre-allocated
                    // output. O(n) materialization cost, paid once per Execute.
                    (eng, output) => { var r = eng.TensorPermute(captured, capturedAxes).Contiguous(); r.AsSpan().CopyTo(output.AsWritableSpan()); },
                    BackwardFunctions<T>.PermuteBackward, new object[] { capturedAxes });
            }
        }

        { var ac = AutoTracer.TryGetCompiledPlan<T>("TensorPermute", tensor._shape); if (ac is not null) return ac.Execute(); }

        // Use tensor's built-in Transpose method
        var result = tensor.Transpose(axes);
        DifferentiableOps.RecordUnary("TensorPermute", result, tensor, BackwardFunctions<T>.PermuteBackward, new object[] { axes });
        AutoTracer.RecordOp("TensorPermute", result, eng => result);
        return result;
    }

    /// <inheritdoc/>
    public virtual Tensor<T> TensorExpandDims<T>(Tensor<T> tensor, int axis)
    {
        if (tensor == null) throw new ArgumentNullException(nameof(tensor));

        // Normalize negative axis
        int rank = tensor._shape.Length;
        if (axis < 0) axis = rank + 1 + axis;
        if (axis < 0 || axis > rank)
            throw new ArgumentOutOfRangeException(nameof(axis), "Axis out of range");

        if (GraphMode.IsActive)
        {
            var scope = GraphMode.Current;
            if (scope != null)
            {
                var captured = tensor;
                var capturedAxis = axis;
                // Build output shape with 1 inserted at axis
                var outShape = new int[rank + 1];
                for (int i = 0; i < capturedAxis; i++) outShape[i] = tensor._shape[i];
                outShape[capturedAxis] = 1;
                for (int i = capturedAxis; i < rank; i++) outShape[i + 1] = tensor._shape[i];
                return scope.RecordUnary(LazyNodeType.Custom, "TensorExpandDims", tensor, outShape,
                    (eng, output) => { var r = eng.TensorExpandDims(captured, capturedAxis); r.AsSpan().CopyTo(output.AsWritableSpan()); },
                    BackwardFunctions<T>.ExpandDimsBackward, new object[] { capturedAxis });
            }
        }

        { var ac = AutoTracer.TryGetCompiledPlan<T>("TensorExpandDims", tensor._shape); if (ac is not null) return ac.Execute(); }

        // Build new shape with 1 inserted at axis
        var newShape = new int[rank + 1];
        for (int i = 0; i < axis; i++)
            newShape[i] = tensor._shape[i];
        newShape[axis] = 1;
        for (int i = axis; i < rank; i++)
            newShape[i + 1] = tensor._shape[i];

        var result = tensor.Reshape(newShape);
        DifferentiableOps.RecordUnary("TensorExpandDims", result, tensor, BackwardFunctions<T>.ExpandDimsBackward, new object[] { axis });
        AutoTracer.RecordOp("TensorExpandDims", result, eng => result);
        return result;
    }

    /// <inheritdoc/>
    public virtual Tensor<T> TensorSqueeze<T>(Tensor<T> tensor, int axis = -1)
    {
        if (tensor == null) throw new ArgumentNullException(nameof(tensor));

        if (GraphMode.IsActive)
        {
            var scope = GraphMode.Current;
            if (scope != null)
            {
                var captured = tensor;
                var capturedAxis = axis;
                // Compute squeezed output shape
                var shapeList = tensor._shape.ToList();
                if (capturedAxis == -1) { shapeList = shapeList.Where(s => s != 1).ToList(); if (shapeList.Count == 0) shapeList.Add(1); }
                else { int normAxis = capturedAxis < 0 ? shapeList.Count + capturedAxis : capturedAxis; shapeList.RemoveAt(normAxis); if (shapeList.Count == 0) shapeList.Add(1); }
                return scope.RecordUnary(LazyNodeType.Custom, "TensorSqueeze", tensor, shapeList.ToArray(),
                    (eng, output) => { var r = eng.TensorSqueeze(captured, capturedAxis); r.AsSpan().CopyTo(output.AsWritableSpan()); },
                    BackwardFunctions<T>.SqueezeBackward, new object[] { capturedAxis });
            }
        }

        { var ac = AutoTracer.TryGetCompiledPlan<T>("TensorSqueeze", tensor._shape); if (ac is not null) return ac.Execute(); }

        var shape = tensor._shape.ToList();

        if (axis == -1)
        {
            // Remove all singleton dimensions
            shape = shape.Where(s => s != 1).ToList();
            if (shape.Count == 0) shape.Add(1); // Keep at least one dimension
        }
        else
        {
            // Normalize axis
            if (axis < 0) axis = shape.Count + axis;
            if (axis < 0 || axis >= shape.Count)
                throw new ArgumentOutOfRangeException(nameof(axis));
            if (shape[axis] != 1)
                throw new ArgumentException($"Cannot squeeze axis {axis} with size {shape[axis]} (must be 1)");
            shape.RemoveAt(axis);
            if (shape.Count == 0) shape.Add(1);
        }

        var squeezeResult = tensor.Reshape(shape.ToArray());
        DifferentiableOps.RecordUnary("TensorSqueeze", squeezeResult, tensor, BackwardFunctions<T>.SqueezeBackward, new object[] { axis });
        AutoTracer.RecordOp("TensorSqueeze", squeezeResult, eng => squeezeResult);
        return squeezeResult;
    }

    /// <inheritdoc/>
    public virtual Tensor<T> TensorScatterAdd<T>(Tensor<T> destination, Tensor<int> indices, Tensor<T> updates, int axis = 0)
    {
        if (destination == null) throw new ArgumentNullException(nameof(destination));
        if (indices == null) throw new ArgumentNullException(nameof(indices));
        if (updates == null) throw new ArgumentNullException(nameof(updates));
        if (GraphMode.IsActive) { var scope = GraphMode.Current; if (scope is not null) { var c_destination = destination; var c_indices = indices; var c_updates = updates; var c_axis = axis; return scope.RecordBinary(LazyNodeType.Custom, "TensorScatterAdd", destination, updates, destination._shape, (eng, output) => { var r = eng.TensorScatterAdd(c_destination, c_indices, c_updates, c_axis); r.AsSpan().CopyTo(output.AsWritableSpan()); }, BackwardFunctions<T>.ScatterAddBackward); } }

        if (!destination.IsContiguous) throw new InvalidOperationException("Output tensor must be contiguous.");

        var numOps = MathHelper.GetNumericOperations<T>();
        var result = AutoTensorCache.RentOrAllocate<T>(destination._shape);
        TensorCopy(destination, result);

        // index_add semantics — torch.Tensor.index_add_(dim, index, src):
        //   for i in 0..index.Length:
        //     result[..., index[i] at axis, ...] += updates[..., i at axis, ...]
        // index is 1D; updates has the same rank as destination with
        // updates.shape[axis] == index.Length and every other dim equal
        // to destination.shape. Decomposes into outer × axis × inner so
        // arbitrary rank and axis collapse to a triple-loop with a
        // contiguous inner copy.
        int rank = destination._shape.Length;
        if (axis < 0) axis += rank;
        if (axis < 0 || axis >= rank)
            throw new ArgumentOutOfRangeException(nameof(axis),
                $"axis {axis} out of range for destination of rank {rank}.");
        if (indices.Shape.Length != 1)
            throw new ArgumentException(
                $"indices must be 1-D for index_add semantics; got rank {indices.Shape.Length}.",
                nameof(indices));
        if (updates._shape.Length != rank)
            throw new ArgumentException(
                $"updates rank {updates._shape.Length} must equal destination rank {rank}.",
                nameof(updates));
        for (int d = 0; d < rank; d++)
        {
            int expected = d == axis ? indices.Length : destination._shape[d];
            if (updates._shape[d] != expected)
                throw new ArgumentException(
                    $"updates.shape[{d}] {updates._shape[d]} must be {expected} (axis={axis}, indices.Length={indices.Length}).",
                    nameof(updates));
        }

        int outerSize = 1;
        for (int d = 0; d < axis; d++) outerSize *= destination._shape[d];
        int innerSize = 1;
        for (int d = axis + 1; d < rank; d++) innerSize *= destination._shape[d];
        int dstAxisLen = destination._shape[axis];
        int srcAxisLen = indices.Length;

        var indicesData = indices.GetFlattenedData();
        var resultData = result.GetDataArray();
        var updatesData = updates.GetFlattenedData();

        for (int outer = 0; outer < outerSize; outer++)
        {
            int outerDstStride = outer * dstAxisLen * innerSize;
            int outerSrcStride = outer * srcAxisLen * innerSize;
            for (int i = 0; i < srcAxisLen; i++)
            {
                int idx = indicesData[i];
                // PyTorch's index_add_ throws "index out of range" rather than
                // silently dropping; matching that here so callers see real bugs
                // instead of mysteriously-zero update slots.
                if ((uint)idx >= (uint)dstAxisLen)
                    throw new ArgumentOutOfRangeException(
                        nameof(indices),
                        $"indices[{i}]={idx} is out of range for axis length {dstAxisLen}.");
                int dstOffset = outerDstStride + idx * innerSize;
                int srcOffset = outerSrcStride + i * innerSize;
                for (int k = 0; k < innerSize; k++)
                    resultData[dstOffset + k] = numOps.Add(resultData[dstOffset + k], updatesData[srcOffset + k]);
            }
        }

        DifferentiableOps.RecordIfActive("TensorScatterAdd", result, new[] { destination, updates },
            BackwardFunctions<T>.ScatterAddBackward, new object[] { indices, axis });
        { var cd = destination; var ci = indices; var cu = updates; var ca = axis; AutoTracer.RecordOp("TensorScatterAdd", result, eng => eng.TensorScatterAdd(cd, ci, cu, ca)); }
        return result;
    }

    /// <inheritdoc/>
    public virtual Tensor<T> TensorGather<T>(Tensor<T> source, Tensor<int> indices, int axis = 0)
    {
        if (source == null) throw new ArgumentNullException(nameof(source));
        if (indices == null) throw new ArgumentNullException(nameof(indices));
        var indicesOrig = indices;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!indices.IsContiguous) indices = indices.Contiguous();

        int normalizedAxis = axis < 0 ? source._shape.Length + axis : axis;
        if (normalizedAxis < 0 || normalizedAxis >= source._shape.Length)
            throw new ArgumentOutOfRangeException(nameof(axis), $"Axis {axis} out of range for tensor with {source._shape.Length} dimensions");

        if (GraphMode.IsActive)
        {
            var scope = GraphMode.Current;
            if (scope is not null)
            {
                var captured = source;
                var capIndices = indices;
                var capAxis = normalizedAxis;
                // Compute output shape: replace source._shape[axis] with indices shape
                var outShape = ComputeGatherOutputShape(source._shape, indices._shape, capAxis);
                return scope.RecordUnary(LazyNodeType.Custom, "TensorGather", source, outShape,
                    (eng, output) => { var r = eng.TensorGather(captured, capIndices, capAxis); r.AsSpan().CopyTo(output.AsWritableSpan()); },
                    BackwardFunctions<T>.GatherBackward, new object[] { capIndices, capAxis });
            }
        }

        { var ac = AutoTracer.TryGetCompiledPlan<T>("TensorGather", source._shape); if (ac is not null) return ac.Execute(); }

        var sourceData = source.GetFlattenedData();
        var indicesData = indices.GetFlattenedData();

        // Fast path: axis=0, 2D source — embedding lookup
        if (normalizedAxis == 0 && source._shape.Length == 2)
        {
            int embeddingDim = source._shape[1];
            int numIndices = indices.Length;
            var result = TensorAllocator.Rent<T>([numIndices, embeddingDim]);
            var resultData = result.GetDataArray();
            Parallel.For(0, numIndices, i =>
            {
                int idx = indicesData[i];
                if (idx >= 0 && idx < source._shape[0])
                {
                    Array.Copy(sourceData, idx * embeddingDim, resultData, i * embeddingDim, embeddingDim);
                }
            });

            DifferentiableOps.RecordUnary("TensorGather", result, source, BackwardFunctions<T>.GatherBackward, new object[] { indicesOrig, normalizedAxis });
            { var cs = source; var ci = indices; var ca = normalizedAxis; AutoTracer.RecordOp("TensorGather", result, eng => eng.TensorGather(cs, ci, ca)); }
            return result;
        }

        // General path: gather along any axis for any-rank tensor
        {
            // Output shape: for each dimension d, if d == axis then use indices shape, else source shape
            var outShape = ComputeGatherOutputShape(source._shape, indices._shape, normalizedAxis);
            int totalOutput = 1;
            for (int d = 0; d < outShape.Length; d++) totalOutput *= outShape[d];
            var resultData = new T[totalOutput];

            // Compute strides for source
            int outerSize = 1;
            for (int d = 0; d < normalizedAxis; d++) outerSize *= source._shape[d];
            int axisSize = source._shape[normalizedAxis];
            int innerSize = 1;
            for (int d = normalizedAxis + 1; d < source._shape.Length; d++) innerSize *= source._shape[d];

            // For indices that are 1D or match the source shape at the gather dimension
            Parallel.For(0, outerSize, outer =>
            {
                for (int idxPos = 0; idxPos < indices.Length; idxPos++)
                {
                    int idx = indicesData[idxPos];
                    if (idx < 0 || idx >= axisSize) continue;

                    int srcBase = (outer * axisSize + idx) * innerSize;
                    int dstBase = (outer * indices.Length + idxPos) * innerSize;
                    Array.Copy(sourceData, srcBase, resultData, dstBase, innerSize);
                }
            });

            var result = TensorAllocator.Rent<T>(outShape, new Vector<T>(resultData));
            DifferentiableOps.RecordUnary("TensorGather", result, source, BackwardFunctions<T>.GatherBackward, new object[] { indicesOrig, normalizedAxis });
            { var cs = source; var ci = indices; var ca = normalizedAxis; AutoTracer.RecordOp("TensorGather", result, eng => eng.TensorGather(cs, ci, ca)); }
            return result;
        }
    }

    private static int[] ComputeGatherOutputShape(int[] sourceShape, int[] indicesShape, int axis)
    {
        // For 1D indices gathering from ND source:
        // output shape = sourceShape with sourceShape[axis] replaced by indices total length
        var outShape = (int[])sourceShape.Clone();
        int indicesTotal = 1;
        for (int d = 0; d < indicesShape.Length; d++) indicesTotal *= indicesShape[d];
        outShape[axis] = indicesTotal;
        return outShape;
    }

    /// <inheritdoc/>
    public virtual Tensor<T> TensorCumSum<T>(Tensor<T> tensor, int axis)
    {
        if (tensor == null) throw new ArgumentNullException(nameof(tensor));

        if (GraphMode.IsActive)
        { var ac = AutoTracer.TryGetCompiledPlan<T>("TensorCumSum", tensor._shape); if (ac is not null) return ac.Execute(); }

        {
            var scope = GraphMode.Current;
            if (scope != null)
            {
                var captured = tensor;
                var capturedAxis = axis;
                return scope.RecordUnary(LazyNodeType.Custom, "TensorCumSum", tensor, tensor._shape,
                    (eng, output) => { var r = eng.TensorCumSum(captured, capturedAxis); r.AsSpan().CopyTo(output.AsWritableSpan()); },
                    BackwardFunctions<T>.CumSumBackward, new object[] { capturedAxis });
            }
        }

        var tensorOrig = tensor;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!tensor.IsContiguous) tensor = tensor.Contiguous();
        var result = AutoTensorCache.RentOrAllocate<T>(tensor._shape);

        // Normalize axis
        if (axis < 0) axis = tensor._shape.Length + axis;

        int outerSize = 1;
        for (int i = 0; i < axis; i++) outerSize *= tensor._shape[i];

        int axisSize = tensor._shape[axis];

        int innerSize = 1;
        for (int i = axis + 1; i < tensor._shape.Length; i++) innerSize *= tensor._shape[i];

        // Float fast path for 1D (common case). Uses the SIMD Sklansky
        // prefix-sum from Simd.ScanKernels when AVX2 is available, 8x the
        // scalar throughput on bandwidth-limited 1-D cumsum.
        if (typeof(T) == typeof(float) && tensor.Rank == 1)
        {
            var src = (float[])(object)tensor.GetDataArray();
            var dst = (float[])(object)result.GetDataArray();
            Simd.ScanKernels.PrefixSumFloat(src, dst);
            DifferentiableOps.RecordUnary("TensorCumSum", result, tensorOrig, BackwardFunctions<T>.CumSumBackward, new object[] { axis });
            AutoTracer.RecordOp("TensorCumSum", result, eng => result);
            return result;
        }

        // Fp32 contiguous inner-most axis: run the SIMD scan per line.
        if (typeof(T) == typeof(float) && innerSize == 1)
        {
            var src = (float[])(object)tensor.GetDataArray();
            var dst = (float[])(object)result.GetDataArray();
            for (int outer = 0; outer < outerSize; outer++)
            {
                int start = outer * axisSize;
                Simd.ScanKernels.PrefixSumFloat(
                    new ReadOnlySpan<float>(src, start, axisSize),
                    new Span<float>(dst, start, axisSize));
            }
            DifferentiableOps.RecordUnary("TensorCumSum", result, tensorOrig, BackwardFunctions<T>.CumSumBackward, new object[] { axis });
            AutoTracer.RecordOp("TensorCumSum", result, eng => result);
            return result;
        }

        var numOps = MathHelper.GetNumericOperations<T>();
        var tensorData = tensor.GetDataArray();
        var resultData = result.GetDataArray();

        int totalWork = outerSize * innerSize;
        if (totalWork > 1)
        {
            Parallel.For(0, totalWork, flatIdx =>
            {
                int outer = flatIdx / innerSize;
                int inner = flatIdx % innerSize;
                T cumSum = numOps.Zero;
                for (int a = 0; a < axisSize; a++)
                {
                    int srcIdx = (outer * axisSize + a) * innerSize + inner;
                    cumSum = numOps.Add(cumSum, tensorData[srcIdx]);
                    resultData[srcIdx] = cumSum;
                }
            });
        }
        else
        {
            T cumSum = numOps.Zero;
            for (int a = 0; a < axisSize; a++)
            {
                cumSum = numOps.Add(cumSum, tensorData[a]);
                resultData[a] = cumSum;
            }
        }

        DifferentiableOps.RecordUnary("TensorCumSum", result, tensorOrig, BackwardFunctions<T>.CumSumBackward, new object[] { axis });
        AutoTracer.RecordOp("TensorCumSum", result, eng => result);
        return result;
    }

    /// <inheritdoc/>
    public virtual Tensor<T> TensorLogSumExp<T>(Tensor<T> tensor, int axis, bool keepDims = false)
    {
        if (tensor == null) throw new ArgumentNullException(nameof(tensor));

        if (GraphMode.IsActive)
        {
            var scope = GraphMode.Current;
            if (scope != null)
            {
                var captured = tensor;
                int capAxis = axis < 0 ? tensor._shape.Length + axis : axis;
                bool capKeepDims = keepDims;
                // Compute output shape after reduction
                var outShape = new List<int>();
                for (int d = 0; d < tensor._shape.Length; d++)
                {
                    if (d == capAxis) { if (keepDims) outShape.Add(1); }
                    else outShape.Add(tensor._shape[d]);
                }
                if (outShape.Count == 0) outShape.Add(1);
                return scope.RecordUnary(LazyNodeType.Custom, "LogSumExp", tensor, outShape.ToArray(),
                    (eng, output) => { var r = eng.TensorLogSumExp(captured, capAxis, capKeepDims); r.AsSpan().CopyTo(output.AsWritableSpan()); },
                    BackwardFunctions<T>.LogSumExpBackward, new object[] { capAxis });
            }
        }

        var numOps = MathHelper.GetNumericOperations<T>();

        // Normalize axis
        if (axis < 0) axis = tensor._shape.Length + axis;

        // Compute max along axis for numerical stability
        var maxVals = ReduceMax(tensor, new[] { axis }, keepDims: true, out _);

        // Compute exp(x - max)
        var shifted = TensorBroadcastSubtract(tensor, maxVals);
        var expShifted = TensorExp(shifted);

        // Sum along axis
        var sumExp = ReduceSum(expShifted, new[] { axis }, keepDims: keepDims);

        // log(sum) + max
        var logSum = TensorLog(sumExp);

        if (keepDims)
        {
            return TensorAdd(logSum, maxVals);
        }
        else
        {
            var maxSqueezed = TensorSqueeze(maxVals, axis);
            return TensorAdd(logSum, maxSqueezed);
        }
    }

    /// <inheritdoc/>
    public Tensor<T> TensorRandomUniform<T>(int[] shape)
    {
        if (shape == null) throw new ArgumentNullException(nameof(shape));
        var tensor = new Tensor<T>(shape);
        var rng = new Helpers.SimdRandom();
        rng.FillUniform(tensor.DataVector.AsWritableSpan());
        return tensor;
    }

    /// <inheritdoc/>
    public Tensor<T> TensorRandomNormal<T>(int[] shape, T mean, T stddev)
    {
        if (shape == null) throw new ArgumentNullException(nameof(shape));

        var numOps = MathHelper.GetNumericOperations<T>();
        var random = RandomHelper.ThreadSafeRandom;
        var result = AutoTensorCache.RentOrAllocate<T>(shape);
        int totalElements = shape.Aggregate(1, (a, b) => a * b);

        var resultData = result.GetDataArray();
        double meanD = numOps.ToDouble(mean);
        double stdD = numOps.ToDouble(stddev);

        // Box-Muller transform for normal distribution
        for (int i = 0; i < totalElements; i += 2)
        {
            double u1 = random.NextDouble();
            double u2 = random.NextDouble();

            // Guard against log(0) which produces -Infinity and then NaN
            u1 = Math.Max(u1, double.Epsilon);

            double mag = Math.Sqrt(-2.0 * Math.Log(u1));
            double z0 = mag * Math.Cos(2.0 * Math.PI * u2);
            double z1 = mag * Math.Sin(2.0 * Math.PI * u2);

            resultData[i] = numOps.FromDouble(z0 * stdD + meanD);
            if (i + 1 < totalElements)
                resultData[i + 1] = numOps.FromDouble(z1 * stdD + meanD);
        }

        return result;
    }

    /// <inheritdoc/>
    public Tensor<T> TensorRandomUniformRange<T>(int[] shape, T min, T max, int? seed = null)
    {
        if (shape == null) throw new ArgumentNullException(nameof(shape));

        var numOps = MathHelper.GetNumericOperations<T>();
        var random = seed.HasValue ? RandomHelper.CreateSeededRandom(seed.Value) : RandomHelper.ThreadSafeRandom;
        var result = AutoTensorCache.RentOrAllocate<T>(shape);
        int totalElements = shape.Aggregate(1, (a, b) => a * b);

        double minD = numOps.ToDouble(min);
        double maxD = numOps.ToDouble(max);
        double range = maxD - minD;

        var resultData = result.GetDataArray();

        if (totalElements > 10000)
        {
            // For seeded random with parallelism, we need thread-local randoms
            if (seed.HasValue)
            {
                var baseRandom = RandomHelper.CreateSeededRandom(seed.Value);
                var seeds = new int[CpuParallelSettings.MaxDegreeOfParallelism];
                for (int i = 0; i < seeds.Length; i++)
                    seeds[i] = baseRandom.Next();

                Parallel.For(0, totalElements, () => RandomHelper.CreateSeededRandom(seeds[Thread.CurrentThread.ManagedThreadId % seeds.Length]),
                    (i, state, localRandom) =>
                    {
                        resultData[i] = numOps.FromDouble(localRandom.NextDouble() * range + minD);
                        return localRandom;
                    },
                    _ => { });
            }
            else
            {
                Parallel.For(0, totalElements, i =>
                {
                    resultData[i] = numOps.FromDouble(RandomHelper.ThreadSafeRandom.NextDouble() * range + minD);
                });
            }
        }
        else
        {
            for (int i = 0; i < totalElements; i++)
            {
                resultData[i] = numOps.FromDouble(random.NextDouble() * range + minD);
            }
        }

        return result;
    }

    /// <inheritdoc/>
    public Tensor<T> TensorDropoutMask<T>(int[] shape, T dropoutRate, T scale, int? seed = null)
    {
        if (shape == null) throw new ArgumentNullException(nameof(shape));

        var numOps = MathHelper.GetNumericOperations<T>();
        var random = seed.HasValue ? RandomHelper.CreateSeededRandom(seed.Value) : RandomHelper.ThreadSafeRandom;
        var result = AutoTensorCache.RentOrAllocate<T>(shape);
        int totalElements = shape.Aggregate(1, (a, b) => a * b);

        double dropoutRateD = numOps.ToDouble(dropoutRate);
        T zero = numOps.Zero;

        var resultData = result.GetDataArray();

        if (totalElements > 10000)
        {
            // For seeded random with parallelism, we need thread-local randoms
            if (seed.HasValue)
            {
                var baseRandom = RandomHelper.CreateSeededRandom(seed.Value);
                var seeds = new int[CpuParallelSettings.MaxDegreeOfParallelism];
                for (int i = 0; i < seeds.Length; i++)
                    seeds[i] = baseRandom.Next();

                Parallel.For(0, totalElements, () => RandomHelper.CreateSeededRandom(seeds[Thread.CurrentThread.ManagedThreadId % seeds.Length]),
                    (i, state, localRandom) =>
                    {
                        resultData[i] = localRandom.NextDouble() < dropoutRateD ? zero : scale;
                        return localRandom;
                    },
                    _ => { });
            }
            else
            {
                Parallel.For(0, totalElements, i =>
                {
                    resultData[i] = RandomHelper.ThreadSafeRandom.NextDouble() < dropoutRateD ? zero : scale;
                });
            }
        }
        else
        {
            for (int i = 0; i < totalElements; i++)
            {
                resultData[i] = random.NextDouble() < dropoutRateD ? zero : scale;
            }
        }

        return result;
    }

    /// <inheritdoc/>
    public Tensor<T> ScalarMinusTensor<T>(T scalar, Tensor<T> tensor)
    {
        if (tensor == null) throw new ArgumentNullException(nameof(tensor));
        if (GraphMode.IsActive) { var scope = GraphMode.Current; if (scope is not null) { var c_scalar = scalar; var c_tensor = tensor; return scope.RecordUnary(LazyNodeType.Custom, "ScalarMinusTensor", tensor, tensor._shape, (eng, output) => { var r = eng.ScalarMinusTensor(c_scalar, c_tensor); r.AsSpan().CopyTo(output.AsWritableSpan()); }, BackwardFunctions<T>.NegateBackward); } }

        var tensorOrig = tensor;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!tensor.IsContiguous) tensor = tensor.Contiguous();

        var numOps = MathHelper.GetNumericOperations<T>();
        var result = AutoTensorCache.RentOrAllocate<T>(tensor._shape);

        // scalar - tensor = -(tensor - scalar) = negate(tensor) + scalar
        numOps.Negate(tensor.AsSpan(), result.AsWritableSpan());
        numOps.AddScalar(result.AsSpan(), scalar, result.AsWritableSpan());

        // d(scalar - x)/dx = -1, so gradient is negated
        DifferentiableOps.RecordUnary("ScalarMinusTensor", result, tensorOrig, BackwardFunctions<T>.NegateBackward);
        { var cs = scalar; var ct = tensor; AutoTracer.RecordOp("ScalarMinusTensor", result, eng => eng.ScalarMinusTensor(cs, ct)); }
        return result;
    }

    /// <inheritdoc/>
    public Tensor<T> TensorEye<T>(int size)
    {
        if (size <= 0) throw new ArgumentException("Size must be positive", nameof(size));

        var numOps = MathHelper.GetNumericOperations<T>();
        var result = TensorAllocator.Rent<T>([size, size]);
        result.Fill(numOps.Zero);

        for (int i = 0; i < size; i++)
        {
            result[i, i] = numOps.One;
        }

        return result;
    }

    /// <inheritdoc/>
    public Tensor<T> TensorDiag<T>(Tensor<T> diagonal)
    {
        if (diagonal == null) throw new ArgumentNullException(nameof(diagonal));

        var numOps = MathHelper.GetNumericOperations<T>();
        int n = diagonal.Length;
        var result = TensorAllocator.Rent<T>([n, n]);
        result.Fill(numOps.Zero);

        var diagData = diagonal.GetFlattenedData();
        var resultData = result.GetDataArray();

        for (int i = 0; i < n; i++)
        {
            resultData[i * n + i] = diagData[i];
        }

        return result;
    }

    /// <inheritdoc/>
    public Tensor<T> TensorDiagonal<T>(Tensor<T> tensor)
    {
        if (tensor == null) throw new ArgumentNullException(nameof(tensor));
        if (tensor._shape.Length != 2)
            throw new ArgumentException("Tensor must be 2D");
        if (GraphMode.IsActive) { var scope = GraphMode.Current; if (scope is not null) { var c_tensor = tensor; return scope.RecordUnary(LazyNodeType.Custom, "TensorDiagonal", tensor, tensor._shape, (eng, output) => { var r = eng.TensorDiagonal(c_tensor); r.AsSpan().CopyTo(output.AsWritableSpan()); }, BackwardFunctions<T>.DiagonalBackward); } }


        int n = Math.Min(tensor._shape[0], tensor._shape[1]);
        var result = AutoTensorCache.RentOrAllocate<T>([n]);

        for (int i = 0; i < n; i++)
        {
            result[i] = tensor[i, i];
        }

        DifferentiableOps.RecordUnary("TensorDiagonal", result, tensor, BackwardFunctions<T>.DiagonalBackward);
        { var ct = tensor; AutoTracer.RecordOp("TensorDiagonal", result, eng => eng.TensorDiagonal(ct)); }
        return result;
    }

    /// <inheritdoc/>
    public Tensor<T> TensorEinsum<T>(string subscripts, params Tensor<T>[] tensors)
    {
        if (subscripts == null) throw new ArgumentNullException(nameof(subscripts));
        if (tensors == null || tensors.Length == 0) throw new ArgumentNullException(nameof(tensors));

        var numOps = MathHelper.GetNumericOperations<T>();

        // Fast-paths for common patterns that already have tuned kernels.
        // Strip whitespace only for pattern-matching; the generic parser
        // handles whitespace itself.
        var normalized = subscripts.Replace(" ", "");
        if (tensors.Length == 2)
        {
            // Batched matrix multiplication: bij,bjk->bik
            if (normalized == "bij,bjk->bik")
            {
                return BatchMatMul(tensors[0], tensors[1]);
            }
            // Matrix multiplication: ij,jk->ik
            if (normalized == "ij,jk->ik")
            {
                return TensorMatMul(tensors[0], tensors[1]);
            }
            // Batched outer product: bi,bj->bij
            if (normalized == "bi,bj->bij")
            {
                return TensorBatchOuterProduct(tensors[0], tensors[1]);
            }
            // Outer product: i,j->ij
            if (normalized == "i,j->ij")
            {
                return TensorOuterProduct(tensors[0], tensors[1]);
            }
            // Batched dot: bi,bi->b
            if (normalized == "bi,bi->b")
            {
                int batch = tensors[0]._shape[0];
                int n = tensors[0]._shape[1];
                var result = AutoTensorCache.RentOrAllocate<T>([batch]);
                Parallel.For(0, batch, b =>
                {
                    T sum = numOps.Zero;
                    for (int i = 0; i < n; i++)
                    {
                        sum = numOps.Add(sum, numOps.Multiply(tensors[0][b, i], tensors[1][b, i]));
                    }
                    result[b] = sum;
                });
                return result;
            }
        }

        // General path: parse -> bind shapes -> choose contraction order ->
        // execute. The hardcoded fast-paths above still win on speed since
        // they route to our tuned GEMM/BatchMatMul kernels; the generic path
        // is the correctness floor for every other equation.
        var equation = Engines.Einsum.EinsumEquation.Parse(subscripts);
        var shapes = new int[tensors.Length][];
        for (int i = 0; i < tensors.Length; i++) shapes[i] = tensors[i].Shape.ToArray();
        var binding = Engines.Einsum.EinsumShapeBinding.Bind(equation, shapes);
        var path = Engines.Einsum.EinsumPathOptimizer.Optimize(binding);
        var einsumResult = Engines.Einsum.EinsumExecutor.Execute(binding, path, tensors);

        // Record autograd for every operand count (including 1-operand
        // transpose / reduction einsums).  The only case we leave unrecorded
        // is a within-operand diagonal (e.g. "ii->i") — the backward for
        // those reduces an entire axis to a single element, which is
        // gather-into-diagonal, not a standard einsum contraction.
        if (DifferentiableOps.IsRecording<T>()
            && !HasDiagonalOperand(equation))
        {
            DifferentiableOps.RecordIfActive(
                "TensorEinsum",
                einsumResult,
                tensors,
                Engines.Autodiff.BackwardFunctions<T>.EinsumBackward,
                savedState: new object[] { subscripts });
        }

        return einsumResult;
    }

    private static bool HasDiagonalOperand(Engines.Einsum.EinsumEquation eq)
    {
        foreach (var op in eq.Operands)
        {
            var seen = new HashSet<char>();
            foreach (var c in op.Labels)
                if (!seen.Add(c)) return true;
        }
        return false;
    }

    /// <inheritdoc/>
    public virtual Tensor<T> TensorAddScalar<T>(Tensor<T> tensor, T scalar)
    {
        if (tensor == null) throw new ArgumentNullException(nameof(tensor));

        if (GraphMode.IsActive)
        { var ac = AutoTracer.TryGetCompiledPlan<T>("TensorAddScalar", tensor._shape); if (ac is not null) return ac.Execute(); }

        {
            var scope = GraphMode.Current;
            if (scope != null)
            {
                var captured = tensor;
                var capturedScalar = scalar;
                return scope.RecordUnary(LazyNodeType.AddScalar, "TensorAddScalar", tensor, tensor._shape,
                    (eng, output) => { var r = eng.TensorAddScalar(captured, capturedScalar); r.AsSpan().CopyTo(output.AsWritableSpan()); },
                    BackwardFunctions<T>.AddScalarBackward);
            }
        }

        var numOps = MathHelper.GetNumericOperations<T>();
        var result = AutoTensorCache.RentOrAllocate<T>(tensor._shape);
        if (tensor.IsContiguous) { numOps.AddScalar(tensor.AsSpan(), scalar, result.AsWritableSpan()); }
        else { var src = tensor._storage.GetDataArray(); var dst = result.GetDataArray(); for (int i = 0; i < tensor.Length; i++) dst[i] = numOps.Add(src[tensor.LogicalToStorageIndex(i)], scalar); }

        DifferentiableOps.RecordUnary("TensorAddScalar", result, tensor, BackwardFunctions<T>.AddScalarBackward);
        AutoTracer.RecordOp("TensorAddScalar", result, eng => result);
        return result;
    }

    /// <inheritdoc/>
    public virtual Tensor<T> TensorSubtractScalar<T>(Tensor<T> tensor, T scalar)
    {
        if (tensor == null) throw new ArgumentNullException(nameof(tensor));

        if (GraphMode.IsActive)
        { var ac = AutoTracer.TryGetCompiledPlan<T>("TensorSubtractScalar", tensor._shape); if (ac is not null) return ac.Execute(); }

        {
            var scope = GraphMode.Current;
            if (scope != null)
            {
                var captured = tensor;
                var capturedScalar = scalar;
                return scope.RecordUnary(LazyNodeType.Custom, "TensorSubtractScalar", tensor, tensor._shape,
                    (eng, output) => { var r = eng.TensorSubtractScalar(captured, capturedScalar); r.AsSpan().CopyTo(output.AsWritableSpan()); },
                    BackwardFunctions<T>.SubtractScalarBackward);
            }
        }

        var numOps = MathHelper.GetNumericOperations<T>();
        var result = AutoTensorCache.RentOrAllocate<T>(tensor._shape);
        if (tensor.IsContiguous) { numOps.SubtractScalar(tensor.AsSpan(), scalar, result.AsWritableSpan()); }
        else { var src = tensor._storage.GetDataArray(); var dst = result.GetDataArray(); for (int i = 0; i < tensor.Length; i++) dst[i] = numOps.Subtract(src[tensor.LogicalToStorageIndex(i)], scalar); }

        DifferentiableOps.RecordUnary("TensorSubtractScalar", result, tensor, BackwardFunctions<T>.SubtractScalarBackward);
        AutoTracer.RecordOp("TensorSubtractScalar", result, eng => result);
        return result;
    }

    /// <inheritdoc/>
    public virtual Tensor<T> TensorDivideScalar<T>(Tensor<T> tensor, T scalar)
    {
        if (tensor == null) throw new ArgumentNullException(nameof(tensor));

        if (GraphMode.IsActive)
        { var ac = AutoTracer.TryGetCompiledPlan<T>("TensorDivideScalar", tensor._shape); if (ac is not null) return ac.Execute(); }

        {
            var scope = GraphMode.Current;
            if (scope != null)
            {
                var captured = tensor;
                var capturedScalar = scalar;
                return scope.RecordUnary(LazyNodeType.DivideScalar, "TensorDivideScalar", tensor, tensor._shape,
                    (eng, output) => { var r = eng.TensorDivideScalar(captured, capturedScalar); r.AsSpan().CopyTo(output.AsWritableSpan()); },
                    BackwardFunctions<T>.DivideScalarBackward, scalar != null ? new object[] { scalar } : Array.Empty<object>());
            }
        }

        var numOps = MathHelper.GetNumericOperations<T>();
        var result = AutoTensorCache.RentOrAllocate<T>(tensor._shape);
        if (tensor.IsContiguous) { numOps.DivideScalar(tensor.AsSpan(), scalar, result.AsWritableSpan()); }
        else { var src = tensor._storage.GetDataArray(); var dst = result.GetDataArray(); for (int i = 0; i < tensor.Length; i++) dst[i] = numOps.Divide(src[tensor.LogicalToStorageIndex(i)], scalar); }

        if (scalar is not null)
            DifferentiableOps.RecordUnary("TensorDivideScalar", result, tensor, BackwardFunctions<T>.DivideScalarBackward, new object[] { scalar });
        AutoTracer.RecordOp("TensorDivideScalar", result, eng => result);
        return result;
    }

    /// <inheritdoc/>
    public Tensor<T> TanhDerivative<T>(Tensor<T> tanhOutput)
    {
        if (tanhOutput == null) throw new ArgumentNullException(nameof(tanhOutput));
        var tanhOutputOrig = tanhOutput;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!tanhOutput.IsContiguous) tanhOutput = tanhOutput.Contiguous();

        var numOps = MathHelper.GetNumericOperations<T>();
        var result = AutoTensorCache.RentOrAllocate<T>(tanhOutput._shape);

        // d/dx tanh(x) = 1 - tanh(x)^2: compute y*y then subtract from 1
        // Use span-based: result = 1 - y*y
        var y = tanhOutput.AsSpan();
        var dest = result.AsWritableSpan();
        numOps.Multiply(y, y, dest);       // dest = y^2
        numOps.Negate(dest, dest);          // dest = -y^2
        numOps.AddScalar(dest, numOps.One, dest); // dest = 1 - y^2

        return result;
    }

    /// <inheritdoc/>
    public Tensor<T> SigmoidDerivative<T>(Tensor<T> sigmoidOutput)
    {
        if (sigmoidOutput == null) throw new ArgumentNullException(nameof(sigmoidOutput));
        var sigmoidOutputOrig = sigmoidOutput;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!sigmoidOutput.IsContiguous) sigmoidOutput = sigmoidOutput.Contiguous();

        var numOps = MathHelper.GetNumericOperations<T>();
        var result = AutoTensorCache.RentOrAllocate<T>(sigmoidOutput._shape);
        var temp = AutoTensorCache.RentOrAllocate<T>(sigmoidOutput._shape);

        // d/dx sigmoid(x) = sigmoid(x) * (1 - sigmoid(x))
        var y = sigmoidOutput.AsSpan();
        var oneMinusY = temp.AsWritableSpan();
        numOps.Negate(y, oneMinusY);                     // oneMinusY = -y
        numOps.AddScalar(oneMinusY, numOps.One, oneMinusY); // oneMinusY = 1 - y
        numOps.Multiply(y, oneMinusY, result.AsWritableSpan()); // result = y * (1-y)

        return result;
    }

    /// <inheritdoc/>
    public Tensor<T> ReLUDerivative<T>(Tensor<T> input)
    {
        if (input == null) throw new ArgumentNullException(nameof(input));
        var inputOrig = input;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!input.IsContiguous) input = input.Contiguous();

        var numOps = MathHelper.GetNumericOperations<T>();
        var result = AutoTensorCache.RentOrAllocate<T>(input._shape);
        int totalElements = input.Length;

        // ReLU derivative: 1 if x > 0, else 0
        var src = input.AsSpan();
        var dest = result.AsWritableSpan();
        for (int i = 0; i < totalElements; i++)
        {
            dest[i] = numOps.ToDouble(src[i]) > 0 ? numOps.One : numOps.Zero;
        }

        return result;
    }

    /// <inheritdoc/>
    public Tensor<T> TensorTriangularMask<T>(int size, bool upper = false, int diagonal = 0)
    {
        if (size <= 0) throw new ArgumentException("Size must be positive", nameof(size));

        var numOps = MathHelper.GetNumericOperations<T>();
        var result = TensorAllocator.Rent<T>([size, size]);

        for (int i = 0; i < size; i++)
        {
            for (int j = 0; j < size; j++)
            {
                bool inMask = upper ? (j >= i + diagonal) : (j <= i + diagonal);
                result[i, j] = inMask ? numOps.One : numOps.Zero;
            }
        }

        return result;
    }

    /// <inheritdoc/>
    public Tensor<T> TensorSquash<T>(Tensor<T> tensor, int axis = -1)
    {
        if (tensor == null) throw new ArgumentNullException(nameof(tensor));

        var numOps = MathHelper.GetNumericOperations<T>();

        // Normalize axis
        if (axis < 0) axis = tensor._shape.Length + axis;

        // Compute squared norm along axis
        var squared = TensorMultiply(tensor, tensor);
        var normSquared = ReduceSum(squared, new[] { axis }, keepDims: true);

        // Compute scale factor: ||v||^2 / (1 + ||v||^2)
        var one = AutoTensorCache.RentOrAllocate<T>(normSquared._shape);
        one.Fill(numOps.One);
        var denom = TensorAdd(one, normSquared);
        var scale = TensorDivide(normSquared, denom);

        // Compute ||v||
        var norm = TensorSqrt(normSquared);
        var epsilon = AutoTensorCache.RentOrAllocate<T>(norm._shape);
        epsilon.Fill(numOps.FromDouble(1e-8));
        norm = TensorAdd(norm, epsilon);

        // Normalize: v / ||v||
        var normalized = TensorBroadcastDivide(tensor, norm);

        // Apply scale
        return TensorMultiply(scale, normalized);
    }

    /// <inheritdoc/>
    public Tensor<T> TensorSquashBackward<T>(Tensor<T> gradOutput, Tensor<T> input, Tensor<T> output, int axis = -1)
    {
        if (gradOutput == null) throw new ArgumentNullException(nameof(gradOutput));
        if (input == null) throw new ArgumentNullException(nameof(input));
        if (output == null) throw new ArgumentNullException(nameof(output));

        var numOps = MathHelper.GetNumericOperations<T>();

        // Normalize axis
        if (axis < 0) axis = input._shape.Length + axis;

        // This is a simplified gradient - full implementation would require proper Jacobian
        // For now, approximate with element-wise gradient scaling
        var squared = TensorMultiply(input, input);
        var normSquared = ReduceSum(squared, new[] { axis }, keepDims: true);
        var one = AutoTensorCache.RentOrAllocate<T>(normSquared._shape);
        one.Fill(numOps.One);
        var denom = TensorAdd(one, normSquared);
        var scale = TensorDivide(one, denom);

        return TensorMultiply(gradOutput, scale);
    }

    /// <inheritdoc/>
    public Tensor<T> TensorNorm<T>(Tensor<T> tensor, int axis, bool keepDims = false)
    {
        if (tensor == null) throw new ArgumentNullException(nameof(tensor));

        if (GraphMode.IsActive)
        {
            var scope = GraphMode.Current;
            if (scope != null)
            {
                var captured = tensor;
                int capAxis = axis < 0 ? tensor._shape.Length + axis : axis;
                bool capKeepDims = keepDims;
                var outShape = new List<int>();
                for (int d = 0; d < tensor._shape.Length; d++)
                {
                    if (d == capAxis) { if (keepDims) outShape.Add(1); }
                    else outShape.Add(tensor._shape[d]);
                }
                if (outShape.Count == 0) outShape.Add(1);
                return scope.RecordUnary(LazyNodeType.Custom, "Norm", tensor, outShape.ToArray(),
                    (eng, output) => { var r = eng.TensorNorm(captured, capAxis, capKeepDims); r.AsSpan().CopyTo(output.AsWritableSpan()); },
                    BackwardFunctions<T>.NormBackward, new object[] { capAxis });
            }
        }

        // Float fast path for 2D L2 norm along axis: fused sum(x²) + sqrt per row/col
        if (typeof(T) == typeof(float) && tensor.Rank == 2 && tensor.IsContiguous)
        {
            int normAxis = axis < 0 ? tensor.Rank + axis : axis;
            int rows = tensor._shape[0], cols = tensor._shape[1];
            var fSrc = (float[])(object)tensor.GetDataArray();

            if (normAxis == 1)
            {
                // Norm along cols → output [rows] or [rows,1]
                var outShape = keepDims ? new[] { rows, 1 } : new[] { rows };
                var normResult = AutoTensorCache.RentOrAllocate<T>(outShape);
                var fDst = (float[])(object)normResult.GetDataArray();
                for (int r = 0; r < rows; r++)
                {
                    float sumSq = 0f;
                    int off = r * cols;
                    for (int c = 0; c < cols; c++)
                        sumSq += fSrc[off + c] * fSrc[off + c];
                    fDst[r] = MathF.Sqrt(sumSq);
                }
                DifferentiableOps.RecordUnary("Norm", normResult, tensor, BackwardFunctions<T>.NormBackward, new object[] { normAxis });
                AutoTracer.RecordOp("Norm", normResult, eng => normResult);
                return normResult;
            }
            else if (normAxis == 0)
            {
                // Norm along rows → output [cols] or [1,cols]
                var outShape = keepDims ? new[] { 1, cols } : new[] { cols };
                var normResult = AutoTensorCache.RentOrAllocate<T>(outShape);
                var fDst = (float[])(object)normResult.GetDataArray();
                Array.Clear(fDst, 0, cols);
                for (int r = 0; r < rows; r++)
                {
                    int off = r * cols;
                    for (int c = 0; c < cols; c++)
                        fDst[c] += fSrc[off + c] * fSrc[off + c];
                }
                for (int c = 0; c < cols; c++)
                    fDst[c] = MathF.Sqrt(fDst[c]);
                DifferentiableOps.RecordUnary("Norm", normResult, tensor, BackwardFunctions<T>.NormBackward, new object[] { normAxis });
                AutoTracer.RecordOp("Norm", normResult, eng => normResult);
                return normResult;
            }
        }

        // Generic fallback: 3-op chain
        var squared = TensorMultiply(tensor, tensor);
        var sumSquared = ReduceSum(squared, new[] { axis }, keepDims: keepDims);
        return TensorSqrt(sumSquared);
    }

    /// <inheritdoc/>
    public Tensor<T> TensorNormalize<T>(Tensor<T> tensor, int axis, T epsilon)
    {
        if (tensor == null) throw new ArgumentNullException(nameof(tensor));

        // Compute norm
        var norm = TensorNorm(tensor, axis, keepDims: true);

        // Add epsilon for numerical stability
        var epsArray = AutoTensorCache.RentOrAllocate<T>(norm._shape);
        epsArray.Fill(epsilon);
        norm = TensorAdd(norm, epsArray);

        // Divide
        return TensorBroadcastDivide(tensor, norm);
    }

    /// <inheritdoc/>
    public Tensor<T> TensorClip<T>(Tensor<T> tensor, T minValue, T maxValue)
    {
        if (tensor == null) throw new ArgumentNullException(nameof(tensor));

        var tensorOrig = tensor;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!tensor.IsContiguous) tensor = tensor.Contiguous();
        return TensorClamp(tensor, minValue, maxValue);
    }

    /// <inheritdoc/>
    public virtual Tensor<T> TensorConcatenate<T>(Tensor<T>[] tensors, int axis = 0)
    {
        if (tensors == null || tensors.Length == 0)
            throw new ArgumentNullException(nameof(tensors));

        if (GraphMode.IsActive)
        {
            var scope = GraphMode.Current;
            if (scope != null)
            {
                var captured = (Tensor<T>[])tensors.Clone();
                int capturedAxis = axis;
                // Compute output shape: same as first tensor except along concat axis
                var firstShape = tensors[0]._shape;
                int rank = firstShape.Length;
                int normAxis = axis < 0 ? rank + axis : axis;
                var outShape = (int[])firstShape.Clone();
                int totalAxis = 0;
                foreach (var t in tensors) totalAxis += t._shape[normAxis];
                outShape[normAxis] = totalAxis;
                return scope.RecordVariadic(LazyNodeType.Custom, "Concatenate", captured, outShape,
                    (eng, output) => { var r = eng.TensorConcatenate(captured, capturedAxis); r.AsSpan().CopyTo(output.AsWritableSpan()); },
                    BackwardFunctions<T>.ConcatenateBackward, new object[] { capturedAxis });
            }
        }

        // Fast path for axis=0 contiguous tensors: direct Array.Copy (any rank)
        Tensor<T> result;
        if (axis == 0 && tensors.All(t => t.IsContiguous))
        {
            // Compute output shape first
            var outShape = (int[])tensors[0]._shape.Clone();
            int totalAxis0 = 0;
            foreach (var t in tensors) totalAxis0 += t._shape[0];
            outShape[0] = totalAxis0;

            result = AutoTensorCache.RentOrAllocate<T>(outShape);
            var data = result.GetDataArray();
            int offset = 0;
            foreach (var t in tensors)
            {
                var src = t.GetDataArray();
                Array.Copy(src, 0, data, offset, t.Length);
                offset += t.Length;
            }
        }
        else
        {
            result = Tensor<T>.Concatenate(tensors, axis);
        }
        DifferentiableOps.RecordIfActive("Concatenate", result, (Tensor<T>[])tensors.Clone(),
            BackwardFunctions<T>.ConcatenateBackward,
            savedState: new object[] { axis });
        { var ct = tensors; var ca = axis; AutoTracer.RecordOp("Concatenate", result, eng => eng.TensorConcatenate(ct, ca)); }
        return result;
    }

    /// <inheritdoc/>
    public virtual Tensor<T>[] TensorSplit<T>(Tensor<T> tensor, int numSplits, int axis = 0)
    {
        if (tensor == null) throw new ArgumentNullException(nameof(tensor));
        if (numSplits <= 0) throw new ArgumentException("Number of splits must be positive", nameof(numSplits));

        // GraphMode: record each split result as its own lazy node. We must
        // NOT perform the eager split here — that would force AsSpan on the
        // input tensor, which triggers Realize on its entire upstream lazy
        // chain. For ONNX import specifically, that chain may include ops
        // that read from graph-input placeholders; realizing them before the
        // caller has filled those placeholders bakes placeholder=0 data into
        // those nodes' IsRealized state, which the later plan replay cannot
        // undo (AsSpan subsequently returns whatever the upstream step wrote,
        // which IS correct — but ONLY because the plan's step delegate
        // overwrites the buffer; meanwhile any op whose closure captured a
        // pre-realize snapshot of the data — e.g. a specialization that pins
        // inputA.GetDataArray() during compile — now holds a stale array).
        // Shape is all we need at record time, and that comes from
        // tensor._shape directly.
        if (GraphMode.IsActive)
        {
            var scope = GraphMode.Current;
            if (scope != null)
            {
                if (axis < 0) axis = tensor._shape.Length + axis;
                int axisSizeLazy = tensor._shape[axis];
                if (axisSizeLazy % numSplits != 0)
                    throw new ArgumentException(
                        $"Cannot split axis of size {axisSizeLazy} into {numSplits} equal parts");
                int splitSizeLazy = axisSizeLazy / numSplits;

                var ct = tensor; int cn = numSplits; int ca = axis;
                var lazyResults = new Tensor<T>[numSplits];
                for (int s = 0; s < numSplits; s++)
                {
                    int splitIdx = s;
                    var outShape = (int[])tensor._shape.Clone();
                    outShape[ca] = splitSizeLazy;
                    lazyResults[s] = scope.RecordUnary(LazyNodeType.Custom, "TensorSplit", tensor, outShape,
                        (eng, output) => { var r = eng.TensorSplit(ct, cn, ca)[splitIdx]; r.AsSpan().CopyTo(output.AsWritableSpan()); },
                        BackwardFunctions<T>.SplitBackward, new object[] { numSplits, axis, s });
                }
                return lazyResults;
            }
        }

        // Normalize axis
        if (axis < 0) axis = tensor._shape.Length + axis;

        int axisSize = tensor._shape[axis];
        if (axisSize % numSplits != 0)
            throw new ArgumentException($"Cannot split axis of size {axisSize} into {numSplits} equal parts");

        int splitSize = axisSize / numSplits;

        // NCHWc8 fast path: channel-axis split on a packed tensor. Slicing
        // logical axis=1 on the raw Tensor does the wrong thing (physical
        // layout is [N, cg, H, W, 8]), so we cut per-channel-group with
        // direct memcpy when splitSize is a multiple of the cBlock.
        if (typeof(T) == typeof(float)
            && tensor.Layout == LinearAlgebra.TensorLayout.Nchwc8
            && tensor.Rank == 4
            && axis == 1
            && splitSize % Simd.NchwcPool.CBlock == 0)
        {
            int cb = Simd.NchwcPool.CBlock;
            int N = tensor._shape[0], H = tensor._shape[2], W = tensor._shape[3];
            int cgTotal = axisSize / cb;
            int cgPerSplit = splitSize / cb;
            int inImageStride = cgTotal * H * W * cb;
            int outImageStride = cgPerSplit * H * W * cb;
            int copyPerImage = outImageStride;
            var srcF = (Tensor<float>)(object)tensor;
            var srcData = srcF.GetDataArray();
            var packedResults = new Tensor<T>[numSplits];
            for (int i = 0; i < numSplits; i++)
            {
                var splitShape = (int[])tensor._shape.Clone();
                splitShape[1] = splitSize;
                var dst = new Tensor<float>(splitShape) { Layout = LinearAlgebra.TensorLayout.Nchwc8 };
                var dstData = dst.GetDataArray();
                int srcCgStart = i * cgPerSplit;
                for (int n = 0; n < N; n++)
                {
                    int srcBase = n * inImageStride + srcCgStart * H * W * cb;
                    int dstBase = n * outImageStride;
                    Array.Copy(srcData, srcBase, dstData, dstBase, copyPerImage);
                }
                packedResults[i] = (Tensor<T>)(object)dst;
            }
            return packedResults;
        }

        var results = new Tensor<T>[numSplits];

        for (int i = 0; i < numSplits; i++)
        {
            int start = i * splitSize;
            results[i] = tensor.Slice(axis, start, start + splitSize);
            DifferentiableOps.RecordUnary("Split", results[i], tensor,
                BackwardFunctions<T>.SplitBackward,
                savedState: new object[] { axis, start, tensor._shape.ToArray() });
        }

        return results;
    }

    /// <inheritdoc/>
    public Tensor<T> TensorOneHot<T>(Tensor<int> indices, int depth)
    {
        if (indices == null) throw new ArgumentNullException(nameof(indices));
        if (depth <= 0) throw new ArgumentException("Depth must be positive", nameof(depth));

        var numOps = MathHelper.GetNumericOperations<T>();
        int numIndices = indices.Length;
        var result = TensorAllocator.Rent<T>([numIndices, depth]);
        result.Fill(numOps.Zero);

        var idxData = indices.GetFlattenedData();
        var resultData = result.GetDataArray();

        for (int i = 0; i < numIndices; i++)
        {
            int idx = idxData[i];
            if (idx >= 0 && idx < depth)
            {
                resultData[i * depth + idx] = numOps.One;
            }
        }

        return result;
    }

    /// <inheritdoc/>
    public Tensor<int> TensorArgMax<T>(Tensor<T> tensor, int axis)
    {
        if (tensor == null) throw new ArgumentNullException(nameof(tensor));

        var numOps = MathHelper.GetNumericOperations<T>();

        // Normalize axis
        if (axis < 0) axis = tensor._shape.Length + axis;

        // Build output shape (remove axis dimension)
        var outputShape = tensor._shape.Where((_, i) => i != axis).ToArray();
        if (outputShape.Length == 0) outputShape = new[] { 1 };
        var result = new Tensor<int>(outputShape);

        int outerSize = 1;
        for (int i = 0; i < axis; i++) outerSize *= tensor._shape[i];

        int axisSize = tensor._shape[axis];

        int innerSize = 1;
        for (int i = axis + 1; i < tensor._shape.Length; i++) innerSize *= tensor._shape[i];

        var tensorData = tensor.GetFlattenedData();
        var resultData = result.GetDataArray();

        Parallel.For(0, outerSize * innerSize, flatIdx =>
        {
            int outer = flatIdx / innerSize;
            int inner = flatIdx % innerSize;

            T maxVal = tensorData[(outer * axisSize) * innerSize + inner];
            int maxIdx = 0;

            for (int a = 1; a < axisSize; a++)
            {
                int srcIdx = (outer * axisSize + a) * innerSize + inner;
                T val = tensorData[srcIdx];
                if (numOps.ToDouble(val) > numOps.ToDouble(maxVal))
                {
                    maxVal = val;
                    maxIdx = a;
                }
            }

            resultData[flatIdx] = maxIdx;
        });

        return result;
    }

    /// <inheritdoc/>
    public Tensor<int> TensorArgMin<T>(Tensor<T> tensor, int axis)
    {
        if (tensor == null) throw new ArgumentNullException(nameof(tensor));
        var tensorOrig = tensor;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!tensor.IsContiguous) tensor = tensor.Contiguous();

        var numOps = MathHelper.GetNumericOperations<T>();

        // Normalize axis
        if (axis < 0) axis = tensor._shape.Length + axis;

        // Build output shape (remove axis dimension)
        var outputShape = tensor._shape.Where((_, i) => i != axis).ToArray();
        if (outputShape.Length == 0) outputShape = new[] { 1 };
        var result = new Tensor<int>(outputShape);

        int outerSize = 1;
        for (int i = 0; i < axis; i++) outerSize *= tensor._shape[i];

        int axisSize = tensor._shape[axis];

        int innerSize = 1;
        for (int i = axis + 1; i < tensor._shape.Length; i++) innerSize *= tensor._shape[i];

        var tensorData = tensor.GetFlattenedData();
        var resultData = result.GetDataArray();

        Parallel.For(0, outerSize * innerSize, flatIdx =>
        {
            int outer = flatIdx / innerSize;
            int inner = flatIdx % innerSize;

            T minVal = tensorData[(outer * axisSize) * innerSize + inner];
            int minIdx = 0;

            for (int a = 1; a < axisSize; a++)
            {
                int srcIdx = (outer * axisSize + a) * innerSize + inner;
                T val = tensorData[srcIdx];
                if (numOps.ToDouble(val) < numOps.ToDouble(minVal))
                {
                    minVal = val;
                    minIdx = a;
                }
            }

            resultData[flatIdx] = minIdx;
        });

        return result;
    }

    /// <inheritdoc/>
    public Tensor<T> TensorBinaryCrossEntropy<T>(Tensor<T> predictions, Tensor<T> targets, T epsilon)
    {
        if (predictions == null) throw new ArgumentNullException(nameof(predictions));
        if (targets == null) throw new ArgumentNullException(nameof(targets));

        if (GraphMode.IsActive)
        {
            var scope = GraphMode.Current;
            if (scope is not null)
            {
                var cp = predictions; var ct = targets; var ce = epsilon;
                return scope.RecordBinary(LazyNodeType.Custom, "TensorBinaryCrossEntropy", predictions, targets, predictions._shape,
                    (eng, output) => { var r = ((CpuEngine)eng).TensorBinaryCrossEntropy(cp, ct, ce); r.AsSpan().CopyTo(output.AsWritableSpan()); },
                    BackwardFunctions<T>.BinaryCrossEntropyBackward, new object[] { (object)epsilon! });
            }
        }

        var predictionsOrig = predictions;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!predictions.IsContiguous) predictions = predictions.Contiguous();
        var targetsOrig = targets;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!targets.IsContiguous) targets = targets.Contiguous();

        var numOps = MathHelper.GetNumericOperations<T>();
        var result = AutoTensorCache.RentOrAllocate<T>(predictions._shape);
        var predSpan = predictions.AsSpan();
        var targetSpan = targets.AsSpan();
        var dest = result.AsWritableSpan();
        T upperBound = numOps.Subtract(numOps.One, epsilon);
        double upperVal = numOps.ToDouble(upperBound);
        double epsVal = numOps.ToDouble(epsilon);

        for (int i = 0; i < predSpan.Length; i++)
        {
            T p = predSpan[i];
            T t = targetSpan[i];

            // Clip for numerical stability
            double pVal = numOps.ToDouble(p);
            T clippedUpper = pVal < upperVal ? p : upperBound;
            double clippedUpperVal = numOps.ToDouble(clippedUpper);
            T pClipped = clippedUpperVal > epsVal ? clippedUpper : epsilon;

            // -[t * log(p) + (1-t) * log(1-p)]
            T logP = numOps.Log(pClipped);
            T log1MinusP = numOps.Log(numOps.Subtract(numOps.One, pClipped));
            T oneMinusT = numOps.Subtract(numOps.One, t);

            dest[i] = numOps.Negate(numOps.Add(
                numOps.Multiply(t, logP),
                numOps.Multiply(oneMinusT, log1MinusP)));
        }

        DifferentiableOps.RecordBinary("TensorBinaryCrossEntropy", result, predictionsOrig, targetsOrig, BackwardFunctions<T>.BinaryCrossEntropyBackward, new object[] { numOps.ToDouble(epsilon) });
        { var cp = predictions; var ct = targets; var ce = epsilon; AutoTracer.RecordOp("TensorBinaryCrossEntropy", result, eng => eng.TensorBinaryCrossEntropy(cp, ct, ce)); }
        return result;
    }

    /// <inheritdoc/>
    public Tensor<T> TensorBinaryCrossEntropyBackward<T>(Tensor<T> predictions, Tensor<T> targets, T epsilon)
    {
        if (predictions == null) throw new ArgumentNullException(nameof(predictions));
        if (targets == null) throw new ArgumentNullException(nameof(targets));
        var predictionsOrig = predictions;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!predictions.IsContiguous) predictions = predictions.Contiguous();
        var targetsOrig = targets;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!targets.IsContiguous) targets = targets.Contiguous();

        var numOps = MathHelper.GetNumericOperations<T>();
        var result = AutoTensorCache.RentOrAllocate<T>(predictions._shape);
        var predSpan = predictions.AsSpan();
        var targetSpan = targets.AsSpan();
        var dest = result.AsWritableSpan();
        T upperBound = numOps.Subtract(numOps.One, epsilon);
        double upperVal = numOps.ToDouble(upperBound);
        double epsVal = numOps.ToDouble(epsilon);

        for (int i = 0; i < predSpan.Length; i++)
        {
            T p = predSpan[i];
            T t = targetSpan[i];

            // Clip for numerical stability
            double pVal = numOps.ToDouble(p);
            T clippedUpper = pVal < upperVal ? p : upperBound;
            double clippedUpperVal = numOps.ToDouble(clippedUpper);
            T pClipped = clippedUpperVal > epsVal ? clippedUpper : epsilon;

            // Gradient: -t/p + (1-t)/(1-p)
            T termA = numOps.Divide(t, pClipped);
            T oneMinusP = numOps.Subtract(numOps.One, pClipped);
            T oneMinusT = numOps.Subtract(numOps.One, t);
            T termB = numOps.Divide(oneMinusT, oneMinusP);

            dest[i] = numOps.Subtract(termB, termA);
        }

        return result;
    }

    /// <inheritdoc/>
    public (Tensor<T> X, Tensor<T> Y) TensorMeshgrid<T>(Tensor<T> x, Tensor<T> y)
    {
        if (x == null) throw new ArgumentNullException(nameof(x));
        if (y == null) throw new ArgumentNullException(nameof(y));

        int width = x.Length;
        int height = y.Length;

        var X = TensorAllocator.Rent<T>([height, width]);
        var Y = TensorAllocator.Rent<T>([height, width]);
        var xData = x.GetDataArray();
        var yData = y.GetDataArray();
        var XData = X.GetDataArray();
        var YData = Y.GetDataArray();

        Parallel.For(0, height, row =>
        {
            T yVal = yData[row];
            int rowOffset = row * width;
            Array.Copy(xData, 0, XData, rowOffset, width);
            for (int col = 0; col < width; col++)
            {
                YData[rowOffset + col] = yVal;
            }
        });

        return (X, Y);
    }

    /// <inheritdoc/>
    public Tensor<T> TensorSliceAxis<T>(Tensor<T> tensor, int axis, int index)
    {
        if (tensor == null) throw new ArgumentNullException(nameof(tensor));
        if (tensor.Rank < 1) throw new ArgumentException("Cannot slice a scalar tensor.", nameof(tensor));
        if (axis < 0 || axis >= tensor.Rank)
            throw new ArgumentOutOfRangeException(nameof(axis), $"Axis {axis} is out of range for tensor of rank {tensor.Rank}.");
        if (index < 0 || index >= tensor._shape[axis])
            throw new ArgumentOutOfRangeException(nameof(index), $"Index {index} is out of range for axis {axis} with size {tensor._shape[axis]}.");

        // Output shape: original shape with shape[axis] removed
        var outShape = new int[tensor.Rank - 1];
        for (int d = 0, j = 0; d < tensor.Rank; d++)
            if (d != axis) outShape[j++] = tensor._shape[d];

        if (GraphMode.IsActive)
        {
            var scope = GraphMode.Current;
            if (scope != null)
            {
                var captured = tensor;
                int capAxis = axis, capIndex = index;
                return scope.RecordUnary(LazyNodeType.Custom, "TensorSliceAxis", tensor, outShape,
                    (eng, output) => { var r = eng.TensorSliceAxis(captured, capAxis, capIndex); r.AsSpan().CopyTo(output.AsWritableSpan()); },
                    BackwardFunctions<T>.SliceAxisBackward, new object[] { axis, index });
            }
        }

        { var ac = AutoTracer.TryGetCompiledPlan<T>("TensorSliceAxis", tensor._shape); if (ac is not null) return ac.Execute(); }

        // Save original for autodiff — Contiguous() creates a clone for non-contiguous views
        var originalTensor = tensor;
        var tensorOrig = tensor;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!tensor.IsContiguous) tensor = tensor.Contiguous();
        var tensorData = tensor.GetDataArray();

        // Generic N-D slice: select index along axis, producing rank-1 output.
        // stride = product(shape[axis+1:]) — contiguous elements per index along axis
        // outerCount = product(shape[:axis]) — number of outer blocks
        int stride = 1;
        for (int d = axis + 1; d < tensor.Rank; d++)
            stride *= tensor._shape[d];

        int outerCount = 1;
        for (int d = 0; d < axis; d++)
            outerCount *= tensor._shape[d];

        int axisSize = tensor._shape[axis];

        var result = TensorAllocator.Rent<T>(outShape);
        var resultData = result.GetDataArray();

        if (outerCount > 64)
        {
            Parallel.For(0, outerCount, outer =>
            {
                int srcOffset = outer * axisSize * stride + index * stride;
                int dstOffset = outer * stride;
                Array.Copy(tensorData, srcOffset, resultData, dstOffset, stride);
            });
        }
        else
        {
            for (int outer = 0; outer < outerCount; outer++)
            {
                int srcOffset = outer * axisSize * stride + index * stride;
                int dstOffset = outer * stride;
                Array.Copy(tensorData, srcOffset, resultData, dstOffset, stride);
            }
        }

        DifferentiableOps.RecordUnary("TensorSliceAxis", result, originalTensor, BackwardFunctions<T>.SliceAxisBackward, new object[] { axis, index });
        AutoTracer.RecordOp("TensorSliceAxis", result, eng => result);
        return result;
    }

    /// <inheritdoc/>
    public Tensor<T> TensorLinspace<T>(T start, T end, int count)
    {
        if (count < 2) throw new ArgumentException("Count must be at least 2.", nameof(count));

        var numOps = MathHelper.GetNumericOperations<T>();
        var result = AutoTensorCache.RentOrAllocate<T>([count]);

        T range = numOps.Subtract(end, start);
        T divisor = numOps.FromDouble(count - 1);
        T step = numOps.Divide(range, divisor);

        var resultData = result.GetDataArray();
        Parallel.For(0, count, i =>
        {
            T value = numOps.Add(start, numOps.Multiply(numOps.FromDouble(i), step));
            resultData[i] = value;
        });

        return result;
    }

    /// <inheritdoc/>
    public Tensor<T> TensorBatchMatMul<T>(Tensor<T> a, Tensor<T> b)
    {
        if (a == null) throw new ArgumentNullException(nameof(a));
        if (b == null) throw new ArgumentNullException(nameof(b));

        // Preserve the caller's references for tape recording (#257) — see
        // TensorMatMul note. .Contiguous() returns a fresh tensor without the
        // user's GradFn chain, breaking topo walk back to the parameter.
        var aOrig = a;
        var bOrig = b;
        // Stride-aware: only materialize views that aren't simple transposes
        // Simple transposes can be handled by GEMM transA/transB flags (zero-copy)
        if (!a.IsContiguous && !a.IsSimpleTranspose) a = a.Contiguous();
        if (!b.IsContiguous && !b.IsSimpleTranspose) b = b.Contiguous();

        // If both tensors are 3D, delegate to BatchMatMul (which records under
        // its own name). Pass the originals so its tape recording also keys
        // against the caller's references rather than the contiguous copies.
        if (a.Rank == 3 && b.Rank == 3)
        {
            return BatchMatMul(aOrig, bOrig);
        }

        // Handle broadcasting case where b is 2D [K, N]
        if (a.Rank != 3 || b.Rank != 2)
        {
            throw new ArgumentException(
                $"TensorBatchMatMul requires a to be 3D and b to be 2D or 3D. Got ranks {a.Rank} and {b.Rank}.");
        }

        if (GraphMode.IsActive) { var scope = GraphMode.Current; if (scope is not null) { var ca = a; var cb = b; var outShape = new[] { a._shape[0], a._shape[1], b._shape[1] }; return scope.RecordBinary(LazyNodeType.Custom, "TensorBatchMatMul", a, b, outShape, (eng, output) => { var r = eng.TensorBatchMatMul(ca, cb); r.AsSpan().CopyTo(output.AsWritableSpan()); }, BackwardFunctions<T>.BatchMatMulBackward); } }
        { var ac = AutoTracer.TryGetCompiledPlan<T>("TensorBatchMatMul", a._shape); if (ac is not null) return ac.Execute(); }

        var numOps = MathHelper.GetNumericOperations<T>();

        // a: [batch, M, K], b: [K, N]
        int batch = a._shape[0];
        int M = a._shape[1];
        int K = a._shape[2];
        int N = b._shape[1];

        if (b._shape[0] != K)
        {
            throw new ArgumentException(
                $"Matrix dimensions incompatible. a has shape [{batch}, {M}, {K}], b has shape [{b._shape[0]}, {N}]. Inner dimensions must match.");
        }

        var result = TensorAllocator.Rent<T>([batch, M, N]);
        var aData = a.GetDataArray();
        var bData = b.GetDataArray();
        var resultData = result.GetDataArray();

        Parallel.For(0, batch, batchIdx =>
        {
            int aBase = batchIdx * M * K;
            int rBase = batchIdx * M * N;
            for (int i = 0; i < M; i++)
            {
                for (int j = 0; j < N; j++)
                {
                    T sum = numOps.Zero;
                    for (int k = 0; k < K; k++)
                    {
                        sum = numOps.Add(sum, numOps.Multiply(aData[aBase + i * K + k], bData[k * N + j]));
                    }
                    resultData[rBase + i * N + j] = sum;
                }
            }
        });

        DifferentiableOps.RecordBinary("BatchMatMul", result, aOrig, bOrig,
            BackwardFunctions<T>.BatchMatMulBackward);
        { var ca = a; var cb = b; AutoTracer.RecordOp("BatchMatMul", result, eng => eng.BatchMatMul(ca, cb)); }
        return result;
    }

    /// <inheritdoc/>
    public void TensorSetSliceAxis<T>(Tensor<T> destination, Tensor<T> source, int axis, int index)
    {
        if (destination == null) throw new ArgumentNullException(nameof(destination));
        if (source == null) throw new ArgumentNullException(nameof(source));
        if (axis < 0 || axis >= destination.Rank)
            throw new ArgumentOutOfRangeException(nameof(axis), $"Axis {axis} is out of range for tensor of rank {destination.Rank}.");
        if (index < 0 || index >= destination._shape[axis])
            throw new ArgumentOutOfRangeException(nameof(index), $"Index {index} is out of range for axis {axis} with size {destination._shape[axis]}.");

        if (!destination.IsContiguous) throw new InvalidOperationException("TensorSetSliceAxis requires contiguous destination tensor.");
        var sourceOrig = source;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!source.IsContiguous) source = source.Contiguous();

        var dstData = destination.GetDataArray();
        var srcData = source.GetDataArray();

        // Generic N-D set-slice: write source into destination at [... , index, ...] along axis.
        // Same stride/outerCount algorithm as TensorSliceAxis but reversed (src→dst).
        int stride = 1;
        for (int d = axis + 1; d < destination.Rank; d++)
            stride *= destination._shape[d];

        int outerCount = 1;
        for (int d = 0; d < axis; d++)
            outerCount *= destination._shape[d];

        int axisSize = destination._shape[axis];

        if (outerCount > 64)
        {
            Parallel.For(0, outerCount, outer =>
            {
                int dstOffset = outer * axisSize * stride + index * stride;
                int srcOffset = outer * stride;
                Array.Copy(srcData, srcOffset, dstData, dstOffset, stride);
            });
        }
        else
        {
            for (int outer = 0; outer < outerCount; outer++)
            {
                int dstOffset = outer * axisSize * stride + index * stride;
                int srcOffset = outer * stride;
                Array.Copy(srcData, srcOffset, dstData, dstOffset, stride);
            }
        }
    }

    /// <inheritdoc/>
    public Tensor<T> TensorSoftmax<T>(Tensor<T> tensor, int axis)
    {
        var tensorOrig = tensor;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!tensor.IsContiguous) tensor = tensor.Contiguous();
        // Delegate to Softmax which has the same functionality
        return Softmax(tensor, axis);
    }

    /// <inheritdoc/>
    public Tensor<T> TensorSoftmaxBackward<T>(Tensor<T> softmaxOutput, Tensor<T> outputGradient, int axis)
    {
        var softmaxOutputOrig = softmaxOutput;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!softmaxOutput.IsContiguous) softmaxOutput = softmaxOutput.Contiguous();
        var outputGradientOrig = outputGradient;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!outputGradient.IsContiguous) outputGradient = outputGradient.Contiguous();
        // Delegate to SoftmaxBackward with reordered parameters (grad first, then output)
        return SoftmaxBackward(outputGradient, softmaxOutput, axis);
    }

    /// <inheritdoc/>
    public virtual unsafe Tensor<T> TensorLogSoftmax<T>(Tensor<T> tensor, int axis)
    {
        if (tensor == null) throw new ArgumentNullException(nameof(tensor));

        int rank = tensor.Rank;
        if (axis < 0) axis = rank + axis;
        if (axis < 0 || axis >= rank)
            throw new ArgumentException($"Invalid axis {axis} for tensor with {rank} dimensions");

        if (GraphMode.IsActive)
        { var ac = AutoTracer.TryGetCompiledPlan<T>("LogSoftmax", tensor._shape); if (ac is not null) return ac.Execute(); }

        {
            var scope = GraphMode.Current;
            if (scope != null)
            {
                var captured = tensor;
                var capturedAxis = axis;
                return scope.RecordUnary(LazyNodeType.Custom, "LogSoftmax", tensor, tensor._shape,
                    (eng, output) => { var r = eng.TensorLogSoftmax(captured, capturedAxis); r.AsSpan().CopyTo(output.AsWritableSpan()); },
                    BackwardFunctions<T>.LogSoftmaxBackward);
            }
        }

        // Compute outer and inner sizes relative to the axis
        int outerSize = 1, axisSize = tensor._shape[axis], innerSize = 1;
        for (int i = 0; i < axis; i++) outerSize *= tensor._shape[i];
        for (int i = axis + 1; i < rank; i++) innerSize *= tensor._shape[i];

        // Fast SIMD path for float when log_softmax is on the last axis (innerSize==1)
        if (typeof(T) == typeof(float) && innerSize == 1)
        {
            // Use Pin() for NativeMemory compatibility
            var result = AutoTensorCache.RentOrAllocate<T>(tensor._shape);
            using var pinIn = tensor.Data.Pin();
            using var pinOut = result.Data.Pin();
            unsafe
            {
                LogSoftmaxFloatFastPtr((float*)pinIn.Pointer, (float*)pinOut.Pointer, outerSize, axisSize);
            }
            DifferentiableOps.RecordUnary("LogSoftmax", result, tensor,
                BackwardFunctions<T>.LogSoftmaxBackward);
            AutoTracer.RecordOp("LogSoftmax", result, eng => result);
            return result;
        }

        // Generic scalar fallback
        var numOps = MathHelper.GetNumericOperations<T>();
        var inputData = tensor.GetFlattenedData();
        var outputData = new T[tensor.Length];

        Parallel.For(0, outerSize * innerSize, idx =>
        {
            int outer = idx / innerSize;
            int inner = idx % innerSize;

            // Find max for numerical stability
            T maxVal = numOps.MinValue;
            for (int i = 0; i < axisSize; i++)
            {
                int flatIdx = (outer * axisSize + i) * innerSize + inner;
                if (numOps.GreaterThan(inputData[flatIdx], maxVal))
                    maxVal = inputData[flatIdx];
            }

            // Compute exp(x - max) and sum
            T sumExp = numOps.Zero;
            for (int i = 0; i < axisSize; i++)
            {
                int flatIdx = (outer * axisSize + i) * innerSize + inner;
                T shifted = numOps.Subtract(inputData[flatIdx], maxVal);
                sumExp = numOps.Add(sumExp, numOps.Exp(shifted));
            }

            // log_softmax = (x - max) - log(sum(exp(x - max)))
            T logSumExp = numOps.Log(sumExp);
            for (int i = 0; i < axisSize; i++)
            {
                int flatIdx = (outer * axisSize + i) * innerSize + inner;
                T shifted = numOps.Subtract(inputData[flatIdx], maxVal);
                outputData[flatIdx] = numOps.Subtract(shifted, logSumExp);
            }
        });

        var logSoftmaxResult = TensorAllocator.Rent<T>(tensor._shape, new Vector<T>(outputData));
        DifferentiableOps.RecordUnary("LogSoftmax", logSoftmaxResult, tensor,
            BackwardFunctions<T>.LogSoftmaxBackward);
        AutoTracer.RecordOp("LogSoftmax", logSoftmaxResult, eng => logSoftmaxResult);
        return logSoftmaxResult;
    }

    /// <summary>
    /// Fast SIMD log_softmax for float arrays on last axis.
    /// log_softmax(x) = (x - max) - log(sum(exp(x - max)))
    /// </summary>
    /// <summary>Pointer-based log-softmax — works with both managed and NativeMemory.</summary>
    private static unsafe void LogSoftmaxFloatFastPtr(float* pIn, float* pOut, int outerSize, int axisSize)
    {
        int maxThreads = CpuParallelSettings.MaxDegreeOfParallelism;
        bool useParallel = outerSize >= 4 && outerSize * axisSize >= 32768;

        if (useParallel)
        {
            float* pInCap = pIn;
            float* pOutCap = pOut;
            int axisSz = axisSize;
            int outerSz = outerSize;
            int numChunks = Math.Min(maxThreads, outerSize);
            int rowsPerChunk = (outerSize + numChunks - 1) / numChunks;

            PersistentParallelExecutor.Instance.Execute(numChunks, chunk =>
            {
                int startRow = chunk * rowsPerChunk;
                int endRow = Math.Min(startRow + rowsPerChunk, outerSz);
                for (int row = startRow; row < endRow; row++)
                {
                    SimdKernels.LogSoftmaxRowUnsafe(pInCap + row * axisSz, pOutCap + row * axisSz, axisSz);
                }
            });
        }
        else
        {
            for (int row = 0; row < outerSize; row++)
                SimdKernels.LogSoftmaxRowUnsafe(pIn + row * axisSize, pOut + row * axisSize, axisSize);
        }
    }

    /// <inheritdoc/>
    public Tensor<T> TensorTopK<T>(Tensor<T> tensor, int k, int axis, out Tensor<int> indices)
    {
        if (tensor == null) throw new ArgumentNullException(nameof(tensor));
        if (k <= 0) throw new ArgumentException("k must be positive.", nameof(k));

        var numOps = MathHelper.GetNumericOperations<T>();
        if (axis < 0) axis = tensor.Rank + axis;

        // For simplicity, handle 2D case: [batch, features]
        if (tensor.Rank == 2 && axis == 1)
        {
            int batch = tensor._shape[0];
            int features = tensor._shape[1];
            k = Math.Min(k, features);

            var resultValues = TensorAllocator.Rent<T>([batch, k]);
            var indicesResult = new Tensor<int>([batch, k]);

            Parallel.For(0, batch, b =>
            {
                // Extract row and sort with indices
                var rowWithIndices = new (T value, int index)[features];
                for (int i = 0; i < features; i++)
                {
                    rowWithIndices[i] = (tensor[b, i], i);
                }

                // Sort descending by value using GreaterThan
                Array.Sort(rowWithIndices, (a, x) =>
                {
                    if (numOps.GreaterThan(x.value, a.value)) return 1;
                    if (numOps.LessThan(x.value, a.value)) return -1;
                    return 0;
                });

                // Take top-k
                for (int i = 0; i < k; i++)
                {
                    resultValues[b, i] = rowWithIndices[i].value;
                    indicesResult[b, i] = rowWithIndices[i].index;
                }
            });

            indices = indicesResult;
            return resultValues;
        }
        else
        {
            throw new NotSupportedException("TensorTopK currently only supports 2D tensors with axis=1.");
        }
    }

    /// <inheritdoc/>
    public Tensor<T> TensorScatter<T>(Tensor<T> destination, Tensor<int> indices, Tensor<T> source, int axis)
    {
        if (destination == null) throw new ArgumentNullException(nameof(destination));
        if (indices == null) throw new ArgumentNullException(nameof(indices));
        if (source == null) throw new ArgumentNullException(nameof(source));

        var result = destination.Clone();

        // For 2D with axis=1: result[b, indices[b, i]] = source[b, i]
        if (result.Rank == 2 && axis == 1)
        {
            int batch = result._shape[0];
            int numIndices = indices._shape[1];

            Parallel.For(0, batch, b =>
            {
                for (int i = 0; i < numIndices; i++)
                {
                    int idx = indices[b, i];
                    result[b, idx] = source[b, i];
                }
            });
        }
        else
        {
            throw new NotSupportedException("TensorScatter currently only supports 2D tensors with axis=1.");
        }

        return result;
    }

    /// <inheritdoc/>
    public virtual Tensor<T> TensorIndexSelect<T>(Tensor<T> tensor, Tensor<int> indices, int axis)
    {
        if (tensor == null) throw new ArgumentNullException(nameof(tensor));
        if (indices == null) throw new ArgumentNullException(nameof(indices));

        if (axis < 0) axis = tensor.Rank + axis;

        if (GraphMode.IsActive)
        {
            var scope = GraphMode.Current;
            if (scope != null && tensor.Rank == 2)
            {
                var captured = tensor;
                var capIndices = indices;
                int capAxis = axis;
                var outShape = (int[])tensor._shape.Clone();
                outShape[axis] = indices.Length;
                return scope.RecordUnary(LazyNodeType.Custom, "TensorIndexSelect", tensor, outShape,
                    (eng, output) => { var r = eng.TensorIndexSelect(captured, capIndices, capAxis); r.AsSpan().CopyTo(output.AsWritableSpan()); },
                    BackwardFunctions<T>.IndexSelectBackward, new object[] { capIndices, capAxis });
            }
        }

        { var ac = AutoTracer.TryGetCompiledPlan<T>("TensorIndexSelect", tensor._shape); if (ac is not null) return ac.Execute(); }

        // For 2D tensor with axis=0: select rows
        if (tensor.Rank == 2 && axis == 0)
        {
            int numIndices = indices.Length;
            int cols = tensor._shape[1];
            var result = TensorAllocator.Rent<T>([numIndices, cols]);

            var indicesData = indices.GetFlattenedData();
            var tensorData = tensor.GetFlattenedData();
            var resultData = result.GetDataArray();
            Parallel.For(0, numIndices, i =>
            {
                int idx = indicesData[i];
                Array.Copy(tensorData, idx * cols, resultData, i * cols, cols);
            });

            DifferentiableOps.RecordUnary("TensorIndexSelect", result, tensor,
                BackwardFunctions<T>.IndexSelectBackward, new object[] { indices, axis });
            AutoTracer.RecordOp("TensorIndexSelect", result, eng => result);
            return result;
        }
        else if (tensor.Rank == 2 && axis == 1)
        {
            int rows = tensor._shape[0];
            int numIndices = indices.Length;
            var result = TensorAllocator.Rent<T>([rows, numIndices]);
            var indicesData = indices.GetFlattenedData();
            var tensorData = tensor.GetFlattenedData();
            var resultData = result.GetDataArray();

            Parallel.For(0, rows, i =>
            {
                int rowOffset = i * numIndices;
                int tensorRowOffset = i * tensor._shape[1];
                for (int j = 0; j < numIndices; j++)
                {
                    resultData[rowOffset + j] = tensorData[tensorRowOffset + indicesData[j]];
                }
            });

            DifferentiableOps.RecordUnary("TensorIndexSelect", result, tensor,
                BackwardFunctions<T>.IndexSelectBackward, new object[] { indices, axis });
            AutoTracer.RecordOp("TensorIndexSelect", result, eng => result);
            return result;
        }
        else
        {
            throw new NotSupportedException("TensorIndexSelect currently only supports 2D tensors.");
        }
    }

    /// <inheritdoc/>
    public virtual Tensor<T> TensorStack<T>(Tensor<T>[] tensors, int axis)
    {
        if (tensors == null || tensors.Length == 0)
            throw new ArgumentException("Tensors array must not be empty.", nameof(tensors));

        int numTensors = tensors.Length;
        var firstShape = tensors[0]._shape;

        // Validate all tensors have same shape
        for (int i = 1; i < numTensors; i++)
        {
            if (!tensors[i]._shape.SequenceEqual(firstShape))
                throw new ArgumentException("All tensors must have the same shape.");
        }

        if (axis < 0) axis = firstShape.Length + 1 + axis;

        if (GraphMode.IsActive)
        {
            var scope = GraphMode.Current;
            if (scope != null)
            {
                var captured = (Tensor<T>[])tensors.Clone();
                int capAxis = axis;
                // New shape: insert numTensors at axis position
                var outShape = new int[firstShape.Length + 1];
                for (int i = 0; i < axis; i++) outShape[i] = firstShape[i];
                outShape[axis] = numTensors;
                for (int i = axis; i < firstShape.Length; i++) outShape[i + 1] = firstShape[i];
                return scope.RecordVariadic(LazyNodeType.Custom, "TensorStack", captured, outShape,
                    (eng, output) => { var r = eng.TensorStack(captured, capAxis); r.AsSpan().CopyTo(output.AsWritableSpan()); },
                    BackwardFunctions<T>.StackBackward, new object[] { capAxis });
            }
        }

        // New shape: insert numTensors at axis position
        var newShape = new int[firstShape.Length + 1];
        for (int i = 0; i < axis; i++) newShape[i] = firstShape[i];
        newShape[axis] = numTensors;
        for (int i = axis; i < firstShape.Length; i++) newShape[i + 1] = firstShape[i];

        var result = AutoTensorCache.RentOrAllocate<T>(newShape);
        var resultData = result.GetDataArray();

        // Fast path: axis=0 with contiguous tensors — just Array.Copy sequentially
        if (axis == 0 && tensors.All(t => t.IsContiguous))
        {
            int elementsPerTensor = tensors[0].Length;
            for (int t = 0; t < numTensors; t++)
            {
                var srcArr = tensors[t].GetDataArray();
                Array.Copy(srcArr, 0, resultData, t * elementsPerTensor, elementsPerTensor);
            }
            DifferentiableOps.RecordIfActive("TensorStack", result, (Tensor<T>[])tensors.Clone(),
                BackwardFunctions<T>.StackBackward, savedState: new object[] { axis });
            { var ct = tensors; var ca = axis; AutoTracer.RecordOp("TensorStack", result, eng => eng.TensorStack(ct, ca)); }
            return result;
        }

        // General path: copy each tensor with index mapping
        Parallel.For(0, numTensors, t =>
        {
            var tensor = tensors[t];
            var tensorData = tensor.IsContiguous ? tensor.GetDataArray() : tensor.GetFlattenedData();
            int sliceSize = 1;
            for (int i = axis + 1; i < newShape.Length; i++) sliceSize *= newShape[i];

            int outerSize = 1;
            for (int i = 0; i < axis; i++) outerSize *= newShape[i];

            for (int outer = 0; outer < outerSize; outer++)
            {
                int srcOffset = outer * sliceSize;
                int dstOffset = (outer * numTensors + t) * sliceSize;
                Array.Copy(tensorData, srcOffset, resultData, dstOffset, sliceSize);
            }
        });

        DifferentiableOps.RecordIfActive("TensorStack", result, tensors,
            BackwardFunctions<T>.StackBackward, new object[] { axis });
        { var ct = tensors; var ca = axis; AutoTracer.RecordOp("TensorStack", result, eng => eng.TensorStack(ct, ca)); }
        return result;
    }

    /// <inheritdoc/>
    public Tensor<T>[] TensorUnstack<T>(Tensor<T> tensor, int axis)
    {
        if (tensor == null) throw new ArgumentNullException(nameof(tensor));

        if (axis < 0) axis = tensor.Rank + axis;

        int numSlices = tensor._shape[axis];
        var result = new Tensor<T>[numSlices];

        // New shape: remove the axis dimension
        var newShape = new int[tensor.Rank - 1];
        for (int i = 0, j = 0; i < tensor.Rank; i++)
        {
            if (i != axis) newShape[j++] = tensor._shape[i];
        }

        Parallel.For(0, numSlices, i =>
        {
            result[i] = TensorSliceAxis(tensor, axis, i);
        });

        return result;
    }

    /// <inheritdoc/>
    public Tensor<T> TensorMap<T>(Tensor<T> tensor, Func<T, T> func)
    {
        if (tensor == null) throw new ArgumentNullException(nameof(tensor));
        if (func == null) throw new ArgumentNullException(nameof(func));

        var result = AutoTensorCache.RentOrAllocate<T>(tensor._shape);
        try
        {
            var src = tensor.GetFlattenedData();
            var dest = result.GetDataArray();

            for (int i = 0; i < tensor.Length; i++)
                dest[i] = func(src[i]);

            return result;
        }
        catch
        {
            TensorAllocator.Return(result);
            throw;
        }
    }

    /// <inheritdoc/>
    public virtual Tensor<T> TensorMaskedFill<T>(Tensor<T> tensor, Tensor<bool> mask, T value)
    {
        if (tensor == null) throw new ArgumentNullException(nameof(tensor));

        if (GraphMode.IsActive)
        {
            var scope = GraphMode.Current;
            if (scope != null)
            {
                var ct = tensor; var cm = mask; var cv = value;
                return scope.RecordUnary(LazyNodeType.Custom, "TensorMaskedFill", tensor, tensor._shape,
                    (eng, output) => { var r = eng.TensorMaskedFill(ct, cm, cv); r.AsSpan().CopyTo(output.AsWritableSpan()); },
                    BackwardFunctions<T>.MaskedFillBackward, new object[] { mask });
            }
        }
        { var ac = AutoTracer.TryGetCompiledPlan<T>("TensorMaskedFill", tensor._shape); if (ac is not null) return ac.Execute(); }

        if (mask == null) throw new ArgumentNullException(nameof(mask));
        var tensorOrig = tensor;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!tensor.IsContiguous) tensor = tensor.Contiguous();

        var result = tensor.Clone();
        var maskSpan = mask.AsSpan();
        var dest = result.AsWritableSpan();

        for (int i = 0; i < maskSpan.Length; i++)
        {
            if (maskSpan[i])
                dest[i] = value;
        }

        DifferentiableOps.RecordUnary("TensorMaskedFill", result, tensorOrig,
            BackwardFunctions<T>.MaskedFillBackward, new object[] { mask });
        AutoTracer.RecordOp("TensorMaskedFill", result, eng => result);
        return result;
    }

    /// <inheritdoc/>
    public Tensor<T> TensorMaskedFill<T>(Tensor<T> tensor, Tensor<Bit> mask, T value)
    {
        if (tensor == null) throw new ArgumentNullException(nameof(tensor));
        if (mask == null) throw new ArgumentNullException(nameof(mask));
        var tensorOrig = tensor;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!tensor.IsContiguous) tensor = tensor.Contiguous();
        if (!tensor._shape.SequenceEqual(mask._shape))
            throw new ArgumentException($"Tensor shape [{string.Join(", ", tensor._shape)}] must match mask shape [{string.Join(", ", mask._shape)}].");

        if (GraphMode.IsActive) { var scope = GraphMode.Current; if (scope is not null) { var ct = tensor; var cm = mask; var cv = value; return scope.RecordUnary(LazyNodeType.Custom, "MaskedFill", tensor, tensor._shape, (eng, output) => { var r = eng.TensorMaskedFill(ct, cm, cv); r.AsSpan().CopyTo(output.AsWritableSpan()); }, BackwardFunctions<T>.MaskedFillBackward); } }

        { var ac = AutoTracer.TryGetCompiledPlan<T>("MaskedFill", tensor._shape); if (ac is not null) return ac.Execute(); }

        var result = tensor.Clone();
        var maskSpan = mask.AsSpan();
        var dest = result.AsWritableSpan();

        for (int i = 0; i < maskSpan.Length; i++)
        {
            if ((bool)maskSpan[i])
                dest[i] = value;
        }

        { var ct = tensor; var cm = mask; var cv = value; AutoTracer.RecordOp("MaskedFill", result, eng => eng.TensorMaskedFill(ct, cm, cv)); }
        return result;
    }

    /// <inheritdoc/>
    public virtual Tensor<T> TensorMaskedSelect<T>(Tensor<T> tensor, Tensor<Bit> mask)
    {
        if (tensor == null) throw new ArgumentNullException(nameof(tensor));
        if (mask == null) throw new ArgumentNullException(nameof(mask));
        if (!tensor._shape.SequenceEqual(mask._shape))
            throw new ArgumentException(
                $"MaskedSelect requires mask shape [{string.Join(", ", mask._shape)}] " +
                $"to match tensor shape [{string.Join(", ", tensor._shape)}].");

        // Preserve the original tensor/mask for autograd binding so gradients
        // flow back to the caller's input, not to transient contiguous copies.
        var inputTensor = tensor;
        var computeTensor = tensor.IsContiguous ? tensor : tensor.Contiguous();
        var computeMask = mask.IsContiguous ? mask : mask.Contiguous();

        var src = computeTensor.AsSpan();
        var maskSpan = computeMask.AsSpan();
        // First pass: count true entries.
        int n = 0;
        for (int i = 0; i < maskSpan.Length; i++) if ((bool)maskSpan[i]) n++;

        var result = new Tensor<T>(new[] { n });
        var dest = result.AsWritableSpan();
        // Second pass: copy selected elements in order.
        int w = 0;
        for (int i = 0; i < maskSpan.Length; i++)
        {
            if ((bool)maskSpan[i]) dest[w++] = src[i];
        }

        DifferentiableOps.RecordUnary(
            "TensorMaskedSelect", result, inputTensor,
            BackwardFunctions<T>.MaskedSelectBackward,
            savedState: new object[] { computeMask, (int[])inputTensor._shape.Clone() });
        return result;
    }

    /// <inheritdoc/>
    public Tensor<T> TensorWhere<T>(Tensor<bool> condition, Tensor<T> x, Tensor<T> y)
    {
        if (condition == null) throw new ArgumentNullException(nameof(condition));
        if (x == null) throw new ArgumentNullException(nameof(x));
        if (y == null) throw new ArgumentNullException(nameof(y));

        var result = AutoTensorCache.RentOrAllocate<T>(x._shape);
        var condData = condition.GetFlattenedData();
        var xData = x.GetFlattenedData();
        var yData = y.GetFlattenedData();
        var rData = result.GetDataArray();

        Parallel.For(0, x.Length, i =>
        {
            rData[i] = condData[i] ? xData[i] : yData[i];
        });

        // Tape registration — condition is non-trainable; gradient routes
        // through x where condition is true and through y otherwise (#255 audit).
        // Save the mask as byte[] (0/1-encoded) rather than bool[] because
        // SavedStateSerializer doesn't support bool[] — would throw on
        // checkpointing. byte[] is supported and is the same wire size.
        var condBytes = new byte[condData.Length];
        for (int i = 0; i < condData.Length; i++) condBytes[i] = condData[i] ? (byte)1 : (byte)0;
        DifferentiableOps.RecordBinary("TensorWhere", result, x, y,
            BackwardFunctions<T>.WhereBackward, new object[] { condBytes });
        return result;
    }

    /// <inheritdoc/>
    public Tensor<T> TensorWhere<T>(Tensor<Bit> condition, Tensor<T> x, Tensor<T> y)
    {
        if (condition == null) throw new ArgumentNullException(nameof(condition));
        if (x == null) throw new ArgumentNullException(nameof(x));
        if (y == null) throw new ArgumentNullException(nameof(y));
        var yOrig = y;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!y.IsContiguous) y = y.Contiguous();
        var xOrig = x;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!x.IsContiguous) x = x.Contiguous();
        var conditionOrig = condition;  // #257: preserve user-facing ref before .Contiguous() discards GradFn.
        if (!condition.IsContiguous) condition = condition.Contiguous();
        if (x.Length != y.Length || x.Length != condition.Length)
            throw new ArgumentException("All tensors must have the same length.");

        var result = AutoTensorCache.RentOrAllocate<T>(x._shape);
        var condData = condition.GetFlattenedData();
        var xData = x.GetFlattenedData();
        var yData = y.GetFlattenedData();
        var rData = result.GetDataArray();

        Parallel.For(0, x.Length, i =>
        {
            rData[i] = (bool)condData[i] ? xData[i] : yData[i];
        });

        // Tape registration — see Tensor<bool> overload above. Save as byte[]
        // for SavedStateSerializer compatibility (bool[] would throw on
        // checkpointing).
        var condBytesBit = new byte[condData.Length];
        for (int i = 0; i < condData.Length; i++) condBytesBit[i] = (bool)condData[i] ? (byte)1 : (byte)0;
        DifferentiableOps.RecordBinary("TensorWhere", result, xOrig, yOrig,
            BackwardFunctions<T>.WhereBackward, new object[] { condBytesBit });
        return result;
    }

