    /// <inheritdoc />
    public virtual Tensor<T> OctonionMatMulTensor<T>(Tensor<T> input, Tensor<T> weight)
    {
        if (input.Rank != 3 || input._shape[2] != 8)
            throw new ArgumentException($"Input must be rank-3 with last dim 8, got shape [{string.Join(", ", input._shape)}].", nameof(input));
        if (weight.Rank != 3 || weight._shape[2] != 8)
            throw new ArgumentException($"Weight must be rank-3 with last dim 8, got shape [{string.Join(", ", weight._shape)}].", nameof(weight));
        if (input._shape[1] != weight._shape[1])
            throw new ArgumentException($"Input features ({input._shape[1]}) must match weight input dimension ({weight._shape[1]}).");
        var outputShape = new[] { input._shape[0], weight._shape[0], 8 };
        if (GraphMode.IsActive) { var scope = GraphMode.Current; if (scope is not null) { var c_input = input; var c_weight = weight; return scope.RecordBinary(LazyNodeType.Custom, "OctonionMatMulTensor", input, weight, outputShape, (eng, output) => { var r = eng.OctonionMatMulTensor(c_input, c_weight); r.AsSpan().CopyTo(output.AsWritableSpan()); }, BackwardFunctions<T>.OctonionMatMulBackward); } }
        { var ac = AutoTracer.TryGetCompiledPlan<T>("OctonionMatMulTensor", outputShape); if (ac is not null) return ac.Execute(); }

        var numOps = MathHelper.GetNumericOperations<T>();

        // input: [batch, inputFeatures, 8], weight: [outputFeatures, inputFeatures, 8]
        int batch = input._shape[0];
        int inputFeatures = input._shape[1];
        int outputFeatures = weight._shape[0];

        var output = new Tensor<T>(new[] { batch, outputFeatures, 8 });

        // Pre-allocate reusable buffers outside inner loops to avoid GC pressure.
        // OctonionMultiply writes into prod; a/w are loaded per iteration.
        var accum = new T[8];
        var a = new T[8];
        var w = new T[8];
        var prod = new T[8];

        for (int b = 0; b < batch; b++)
        {
            for (int o = 0; o < outputFeatures; o++)
            {
                for (int c = 0; c < 8; c++) accum[c] = default!;

                for (int i = 0; i < inputFeatures; i++)
                {
                    for (int c = 0; c < 8; c++)
                    {
                        a[c] = input[b, i, c];
                        w[c] = weight[o, i, c];
                    }

                    // Octonion multiplication (Cayley-Dickson): result = w * a
                    // Matches CpuAdvancedAlgebraEngine.OctonionMatMul which uses weight * input.
                    // Octonion multiply is non-commutative, so order matters.
                    OctonionMultiplyInPlace(w, a, prod, numOps);

                    for (int c = 0; c < 8; c++)
                        accum[c] = numOps.Add(accum[c], prod[c]);
                }

                for (int c = 0; c < 8; c++)
                    output[b, o, c] = accum[c];
            }
        }

        DifferentiableOps.RecordBinary("OctonionMatMulTensor", output, input, weight, BackwardFunctions<T>.OctonionMatMulBackward);
        { var ci = input; var cw = weight; AutoTracer.RecordOp("OctonionMatMulTensor", output, eng => eng.OctonionMatMulTensor(ci, cw)); }
        return output;
    }

    /// <inheritdoc />
    public Tensor<T> OctonionAddTensor<T>(Tensor<T> a, Tensor<T> b)
    {
        // Element-wise addition — last dimension is 8 (octonion components)
        return TensorAdd(a, b);
    }

    /// <summary>
    /// Multiplies two octonions represented as T[8] arrays using the Cayley-Dickson construction.
    /// </summary>
    private static T[] OctonionMultiply<T>(T[] a, T[] b, INumericOperations<T> ops)
    {
        // Cayley-Dickson: split each octonion into two quaternion halves
        // a = (a0..a3, a4..a7) = (p, q)
        // b = (b0..b3, b4..b7) = (r, s)
        // a*b = (p*r - conj(s)*q, s*p + q*conj(r))

        // Quaternion multiply helper
        static T[] QuatMul(T[] x, T[] y, INumericOperations<T> o)
        {
            return new T[]
            {
                o.Subtract(o.Subtract(o.Subtract(o.Multiply(x[0], y[0]), o.Multiply(x[1], y[1])), o.Multiply(x[2], y[2])), o.Multiply(x[3], y[3])),
                o.Add(o.Subtract(o.Add(o.Multiply(x[0], y[1]), o.Multiply(x[1], y[0])), o.Multiply(x[2], y[3])), o.Multiply(x[3], y[2])),
                o.Add(o.Add(o.Subtract(o.Multiply(x[0], y[2]), o.Multiply(x[1], y[3])), o.Multiply(x[2], y[0])), o.Multiply(x[3], y[1])),
                o.Subtract(o.Add(o.Add(o.Multiply(x[0], y[3]), o.Multiply(x[1], y[2])), o.Multiply(x[3], y[0])), o.Multiply(x[2], y[1]))
            };
        }

        static T[] QuatConj(T[] x, INumericOperations<T> o)
        {
            return new T[] { x[0], o.Negate(x[1]), o.Negate(x[2]), o.Negate(x[3]) };
        }

        static T[] QuatSub(T[] x, T[] y, INumericOperations<T> o)
        {
            return new T[] { o.Subtract(x[0], y[0]), o.Subtract(x[1], y[1]), o.Subtract(x[2], y[2]), o.Subtract(x[3], y[3]) };
        }

        static T[] QuatAdd(T[] x, T[] y, INumericOperations<T> o)
        {
            return new T[] { o.Add(x[0], y[0]), o.Add(x[1], y[1]), o.Add(x[2], y[2]), o.Add(x[3], y[3]) };
        }

        var p = new T[] { a[0], a[1], a[2], a[3] };
        var q = new T[] { a[4], a[5], a[6], a[7] };
        var r = new T[] { b[0], b[1], b[2], b[3] };
        var s = new T[] { b[4], b[5], b[6], b[7] };

        // a*b = (p*r - conj(s)*q, s*p + q*conj(r))
        var pr = QuatMul(p, r, ops);
        var conjS_q = QuatMul(QuatConj(s, ops), q, ops);
        var sp = QuatMul(s, p, ops);
        var q_conjR = QuatMul(q, QuatConj(r, ops), ops);

        var first = QuatSub(pr, conjS_q, ops);
        var second = QuatAdd(sp, q_conjR, ops);

        return new T[] { first[0], first[1], first[2], first[3], second[0], second[1], second[2], second[3] };
    }

    /// <summary>
    /// Zero-allocation octonion multiply using the standard Cayley-Dickson table.
    /// Matches the CUDA kernels in CudaOctonionKernels.cs and the backward
    /// Jacobian tables in BackwardFunctions.OctonionJacobianA/B. Uses static
    /// sign/index lookup tables and a simple accumulation loop — no nested
    /// ops.Add/Subtract chains that were prone to sign errors.
    /// </summary>
    // Standard Cayley-Dickson octonion multiplication sign table.
    // signs[component][term]: +1 or -1 for the a[term]*b[bIdx[term]] product.
    private static readonly int[][] OctonionSigns = {
        new[]{ 1,-1,-1,-1,-1,-1,-1,-1}, // e0
        new[]{ 1, 1, 1,-1, 1,-1,-1, 1}, // e1
        new[]{ 1,-1, 1, 1, 1, 1,-1,-1}, // e2
        new[]{ 1, 1,-1, 1, 1,-1, 1,-1}, // e3
        new[]{ 1,-1,-1,-1, 1, 1, 1, 1}, // e4
        new[]{ 1, 1,-1, 1,-1, 1,-1, 1}, // e5
        new[]{ 1, 1, 1,-1,-1, 1, 1,-1}, // e6
        new[]{ 1,-1, 1, 1,-1,-1, 1, 1}, // e7
    };

    // b-index table: bIdx[component][term] gives which b[j] multiplies a[term].
    private static readonly int[][] OctonionBIdx = {
        new[]{0,1,2,3,4,5,6,7}, // e0
        new[]{1,0,3,2,5,4,7,6}, // e1
        new[]{2,3,0,1,6,7,4,5}, // e2
        new[]{3,2,1,0,7,6,5,4}, // e3
        new[]{4,5,6,7,0,1,2,3}, // e4
        new[]{5,4,7,6,1,0,3,2}, // e5
        new[]{6,7,4,5,2,3,0,1}, // e6
        new[]{7,6,5,4,3,2,1,0}, // e7
    };

    private static void OctonionMultiplyInPlace<T>(T[] a, T[] b, T[] result, INumericOperations<T> ops)
    {
        for (int comp = 0; comp < 8; comp++)
        {
            T sum = ops.Zero;
            var signs = OctonionSigns[comp];
            var bIdx = OctonionBIdx[comp];
            for (int term = 0; term < 8; term++)
            {
                T product = ops.Multiply(a[term], b[bIdx[term]]);
                sum = signs[term] > 0 ? ops.Add(sum, product) : ops.Subtract(sum, product);
            }
            result[comp] = sum;
        }
    }

    #endregion

    #region Complex Tensor Operations

    /// <inheritdoc />
    public Tensor<T> TensorComplexMultiply<T>(Tensor<T> a, Tensor<T> b)
    {
        if (a.Length != b.Length)
            throw new ArgumentException($"Tensor lengths must match: {a.Length} vs {b.Length}");
        if (a.Length % 2 != 0 || (a.Rank > 0 && a._shape[a.Rank - 1] % 2 != 0))
            throw new ArgumentException("Complex tensors must have even length with the last axis divisible by 2 (interleaved re/im).");
        if (GraphMode.IsActive) { var scope = GraphMode.Current; if (scope is not null) { var c_a = a; var c_b = b; return scope.RecordBinary(LazyNodeType.Custom, "ComplexMultiply", a, b, a._shape, (eng, output) => { var r = eng.TensorComplexMultiply(c_a, c_b); r.AsSpan().CopyTo(output.AsWritableSpan()); }, BackwardFunctions<T>.ComplexMultiplyBackward); } }


        var ops = MathHelper.GetNumericOperations<T>();
        var result = new Tensor<T>(a._shape);
        int pairs = a.Length / 2;

        for (int i = 0; i < pairs; i++)
        {
            int idx = i * 2;
            T aRe = a.GetFlat(idx), aIm = a.GetFlat(idx + 1);
            T bRe = b.GetFlat(idx), bIm = b.GetFlat(idx + 1);
            // (aRe + aIm*i) * (bRe + bIm*i) = (aRe*bRe - aIm*bIm) + (aRe*bIm + aIm*bRe)*i
            result.SetFlat(idx, ops.Subtract(ops.Multiply(aRe, bRe), ops.Multiply(aIm, bIm)));
            result.SetFlat(idx + 1, ops.Add(ops.Multiply(aRe, bIm), ops.Multiply(aIm, bRe)));
        }

        Autodiff.DifferentiableOps.RecordIfActive("ComplexMultiply", result,
            new[] { a, b }, Autodiff.BackwardFunctions<T>.ComplexMultiplyBackward);
        { var ca = a; var cb = b; AutoTracer.RecordOp("ComplexMultiply", result, eng => eng.TensorComplexMultiply(ca, cb)); }
        return result;
    }

    /// <inheritdoc />
    public Tensor<T> TensorComplexConjugate<T>(Tensor<T> a)
    {
        if (a.Length % 2 != 0)
            throw new ArgumentException("Complex tensors must have even length (interleaved re/im).");
        if (GraphMode.IsActive) { var scope = GraphMode.Current; if (scope is not null) { var c_a = a; return scope.RecordUnary(LazyNodeType.Custom, "ComplexConjugate", a, a._shape, (eng, output) => { var r = eng.TensorComplexConjugate(c_a); r.AsSpan().CopyTo(output.AsWritableSpan()); }, BackwardFunctions<T>.ComplexConjugateBackward); } }


        var ops = MathHelper.GetNumericOperations<T>();
        var result = new Tensor<T>(a._shape);

        for (int i = 0; i < a.Length; i++)
        {
            result.SetFlat(i, (i % 2 == 1) ? ops.Negate(a.GetFlat(i)) : a.GetFlat(i));
        }

        Autodiff.DifferentiableOps.RecordIfActive("ComplexConjugate", result,
            new[] { a }, Autodiff.BackwardFunctions<T>.ComplexConjugateBackward);
        { var ca = a; AutoTracer.RecordOp("ComplexConjugate", result, eng => eng.TensorComplexConjugate(ca)); }
        return result;
    }

    /// <inheritdoc />
    public Tensor<T> TensorComplexMagnitude<T>(Tensor<T> a)
    {
        if (a.Length % 2 != 0)
            throw new ArgumentException("Complex tensors must have even length (interleaved re/im).");
        if (GraphMode.IsActive) { var scope = GraphMode.Current; if (scope is not null) { var c = a; return scope.RecordUnary(LazyNodeType.Custom, "ComplexMagnitude", a, a._shape, (eng, output) => { var r = eng.TensorComplexMagnitude(c); r.AsSpan().CopyTo(output.AsWritableSpan()); }, BackwardFunctions<T>.ComplexMagnitudeBackward); } }


        var ops = MathHelper.GetNumericOperations<T>();
        int pairs = a.Length / 2;
        var result = new Tensor<T>(new[] { pairs });

        for (int i = 0; i < pairs; i++)
        {
            int idx = i * 2;
            T re = a.GetFlat(idx), im = a.GetFlat(idx + 1);
            T magSq = ops.Add(ops.Multiply(re, re), ops.Multiply(im, im));
            result.SetFlat(i, ops.Sqrt(magSq));
        }

        Autodiff.DifferentiableOps.RecordIfActive("ComplexMagnitude", result,
            new[] { a }, Autodiff.BackwardFunctions<T>.ComplexMagnitudeBackward,
            new object[] { a });
        { var ca = a; AutoTracer.RecordOp("ComplexMagnitude", result, eng => eng.TensorComplexMagnitude(ca)); }
        return result;
    }

    // --- Native Complex<T> Tensor Operations ---

    private static void ValidatePowerOfTwo(int n, string paramName)
    {
        if (n <= 0 || (n & (n - 1)) != 0)
            throw new ArgumentException(
                $"FFT requires input length to be a power of 2, got {n}.", paramName);
    }

    /// <summary>Decompose Complex tensor to split float arrays for SIMD processing.</summary>
    private static (float[] real, float[] imag) DecomposeToFloat<T>(Tensor<Complex<T>> tensor)
    {
        var ops = MathHelper.GetNumericOperations<T>();
        int n = tensor.Length;
        var real = new float[n];
        var imag = new float[n];
        for (int i = 0; i < n; i++)
        {
            real[i] = (float)ops.ToDouble(tensor[i].Real);
            imag[i] = (float)ops.ToDouble(tensor[i].Imaginary);
        }
        return (real, imag);
    }

    /// <summary>Recompose float arrays back to Complex tensor.</summary>
    private static Tensor<Complex<T>> RecomposeFromFloat<T>(float[] real, float[] imag, int[] shape)
    {
        var ops = MathHelper.GetNumericOperations<T>();
        int n = real.Length;
        var result = new Tensor<Complex<T>>(shape);
        for (int i = 0; i < n; i++)
            result[i] = new Complex<T>(ops.FromDouble(real[i]), ops.FromDouble(imag[i]));
        return result;
    }

    /// <summary>Recompose float array to real Tensor.</summary>
    private static Tensor<T> RecomposeRealFromFloat<T>(float[] data, int[] shape)
    {
        var ops = MathHelper.GetNumericOperations<T>();
        int n = data.Length;
        var result = new Tensor<T>(shape);
        for (int i = 0; i < n; i++) result[i] = ops.FromDouble(data[i]);
        return result;
    }

    /// <summary>
    /// Computes batch count and last-axis size for batched FFT.
    /// For 1D: batch=1, fftSize=length. For multi-D: batch=product of leading dims, fftSize=last dim.
    /// </summary>
    private static (int batchCount, int fftSize) GetBatchedFFTDims(int[] shape)
    {
        int fftSize = shape[^1]; // Last axis
        int batchCount = 1;
        for (int i = 0; i < shape.Length - 1; i++)
            batchCount *= shape[i];
        return (batchCount, fftSize);
    }

    /// <inheritdoc />
    public virtual Tensor<Complex<T>> NativeComplexFFT<T>(Tensor<T> input)
    {
        if (input is null) throw new ArgumentNullException(nameof(input));
        var (batchCount, fftSize) = GetBatchedFFTDims(input._shape);
        ValidatePowerOfTwo(fftSize, nameof(input));

        if (GraphMode.IsActive) { var scope = GraphMode.Current; if (scope is not null) { var ci = input; return scope.RecordCrossType<T, Complex<T>>(LazyNodeType.Custom, "NativeComplexFFT", input, input._shape, (eng, output) => { var r = eng.NativeComplexFFT(ci); r.AsSpan().CopyTo(output.AsWritableSpan()); }); } }
        { var ac = AutoTracer.TryGetCompiledPlan<Complex<T>>("NativeComplexFFT", input._shape); if (ac is not null) return ac.Execute(); }

        var ops = MathHelper.GetNumericOperations<T>();
        var result = new Tensor<Complex<T>>(input._shape);

        // Transform along last axis, batch over leading dimensions
        var slice = new Complex<T>[fftSize];
        for (int b = 0; b < batchCount; b++)
        {
            int offset = b * fftSize;
            for (int i = 0; i < fftSize; i++)
                slice[i] = new Complex<T>(input[offset + i], ops.Zero);

            NativeFFTInPlace(slice, false, ops);

            for (int i = 0; i < fftSize; i++)
                result[offset + i] = slice[i];
        }

        { var ci = input; AutoTracer.RecordOp("NativeComplexFFT", result, eng => eng.NativeComplexFFT(ci)); }
        return result;
    }

    /// <inheritdoc />
    public virtual void NativeComplexFFTSpan<T>(ReadOnlySpan<T> input, Span<Complex<T>> output)
    {
        if (input.Length != output.Length)
            throw new ArgumentException($"Input length ({input.Length}) must equal output length ({output.Length}).");
        ValidatePowerOfTwo(input.Length, nameof(input));

        int n = input.Length;
#if NET5_0_OR_GREATER
        if (typeof(T) == typeof(double))
        {
            // Reinterpret caller's output span as Span<Complex<double>> (layout-identical when T=double).
            // Fill output directly with (input[i], 0), then run the in-place butterflies on it.
            // Zero extra allocations, single write pass before FFT.
            ref Complex<T> outHead = ref System.Runtime.InteropServices.MemoryMarshal.GetReference(output);
            var outD = System.Runtime.InteropServices.MemoryMarshal.CreateSpan(
                ref System.Runtime.CompilerServices.Unsafe.As<Complex<T>, Complex<double>>(ref outHead), n);
            for (int i = 0; i < n; i++)
            {
                ref T src = ref System.Runtime.CompilerServices.Unsafe.AsRef(in input[i]);
                outD[i] = new Complex<double>(System.Runtime.CompilerServices.Unsafe.As<T, double>(ref src), 0.0);
            }
            NativeFFTInPlaceDoubleSpan(outD, inverse: false);
            return;
        }
        if (typeof(T) == typeof(float))
        {
            ref Complex<T> outHead = ref System.Runtime.InteropServices.MemoryMarshal.GetReference(output);
            var outF = System.Runtime.InteropServices.MemoryMarshal.CreateSpan(
                ref System.Runtime.CompilerServices.Unsafe.As<Complex<T>, Complex<float>>(ref outHead), n);
            for (int i = 0; i < n; i++)
            {
                ref T src = ref System.Runtime.CompilerServices.Unsafe.AsRef(in input[i]);
                outF[i] = new Complex<float>(System.Runtime.CompilerServices.Unsafe.As<T, float>(ref src), 0f);
            }
            NativeFFTInPlaceFloatSpan(outF, inverse: false);
            return;
        }
#else
        // net471 fallback: no MemoryMarshal.CreateSpan — use a scratch buffer.
        if (typeof(T) == typeof(double))
        {
            var buf = new Complex<double>[n];
            for (int i = 0; i < n; i++)
            {
                ref T src = ref System.Runtime.CompilerServices.Unsafe.AsRef(in input[i]);
                buf[i] = new Complex<double>(System.Runtime.CompilerServices.Unsafe.As<T, double>(ref src), 0.0);
            }
            NativeFFTInPlaceDoubleSpan(buf, inverse: false);
            for (int i = 0; i < n; i++)
                output[i] = System.Runtime.CompilerServices.Unsafe.As<Complex<double>, Complex<T>>(ref buf[i]);
            return;
        }
        if (typeof(T) == typeof(float))
        {
            var buf = new Complex<float>[n];
            for (int i = 0; i < n; i++)
            {
                ref T src = ref System.Runtime.CompilerServices.Unsafe.AsRef(in input[i]);
                buf[i] = new Complex<float>(System.Runtime.CompilerServices.Unsafe.As<T, float>(ref src), 0f);
            }
            NativeFFTInPlaceFloatSpan(buf, inverse: false);
            for (int i = 0; i < n; i++)
                output[i] = System.Runtime.CompilerServices.Unsafe.As<Complex<float>, Complex<T>>(ref buf[i]);
            return;
        }
#endif

        // Generic fallback
        var ops = MathHelper.GetNumericOperations<T>();
        var arr = new Complex<T>[n];
        for (int i = 0; i < n; i++) arr[i] = new Complex<T>(input[i], ops.Zero);
        NativeFFTInPlace(arr, false, ops);
        for (int i = 0; i < n; i++) output[i] = arr[i];
    }

    /// <inheritdoc />
    public virtual void NativeComplexIFFTSpan<T>(ReadOnlySpan<Complex<T>> input, Span<Complex<T>> output)
    {
        if (input.Length != output.Length)
            throw new ArgumentException($"Input length ({input.Length}) must equal output length ({output.Length}).");
        ValidatePowerOfTwo(input.Length, nameof(input));

        int n = input.Length;
#if NET5_0_OR_GREATER
        if (typeof(T) == typeof(double))
        {
            // Copy input into output (reinterpret as Complex<double>) then IFFT + scale in place.
            ref Complex<T> head = ref System.Runtime.InteropServices.MemoryMarshal.GetReference(output);
            var outD = System.Runtime.InteropServices.MemoryMarshal.CreateSpan(
                ref System.Runtime.CompilerServices.Unsafe.As<Complex<T>, Complex<double>>(ref head), n);
            for (int i = 0; i < n; i++)
            {
                ref Complex<T> src = ref System.Runtime.CompilerServices.Unsafe.AsRef(in input[i]);
                outD[i] = System.Runtime.CompilerServices.Unsafe.As<Complex<T>, Complex<double>>(ref src);
            }
            NativeFFTInPlaceDoubleSpan(outD, inverse: true);
            double scale = 1.0 / n;
            for (int i = 0; i < n; i++)
                outD[i] = new Complex<double>(outD[i].Real * scale, outD[i].Imaginary * scale);
            return;
        }
        if (typeof(T) == typeof(float))
        {
            ref Complex<T> head = ref System.Runtime.InteropServices.MemoryMarshal.GetReference(output);
            var outF = System.Runtime.InteropServices.MemoryMarshal.CreateSpan(
