                var xr = x[i].Real; var xi = x[i].Imaginary;
                var yr = y[i].Real; var yi = y[i].Imaginary;
                result[i] = new Complex<T>(
                    ops.Add(ops.Multiply(xr, yr), ops.Multiply(xi, yi)),
                    ops.Subtract(ops.Multiply(xi, yr), ops.Multiply(xr, yi)));
            }
        }

        { var cx2 = x; var cy2 = y; AutoTracer.RecordOp("NativeComplexCrossSpectral", result, eng => eng.NativeComplexCrossSpectral(cx2, cy2)); }
        return result;
    }

    /// <inheritdoc />
    public virtual Tensor<Complex<T>> NativeComplexFFT2D<T>(Tensor<T> input)
    {
        if (input is null) throw new ArgumentNullException(nameof(input));
        if (input.Rank < 2)
            throw new ArgumentException("NativeComplexFFT2D requires at least a 2D tensor.", nameof(input));

        if (GraphMode.IsActive) { var scope = GraphMode.Current; if (scope is not null) { var c = input; return scope.RecordCrossType<T, Complex<T>>(LazyNodeType.Custom, "NativeComplexFFT2D", input, input._shape, (eng, output) => { var r = eng.NativeComplexFFT2D(c); r.AsSpan().CopyTo(output.AsWritableSpan()); }); } }
        { var ac = AutoTracer.TryGetCompiledPlan<Complex<T>>("NativeComplexFFT2D", input._shape); if (ac is not null) return ac.Execute(); }

        int h = input._shape[^2];
        int w = input._shape[^1];
        if ((h & (h - 1)) != 0 || h <= 0)
            throw new ArgumentException($"Height {h} must be a positive power of 2.", nameof(input));
        if ((w & (w - 1)) != 0 || w <= 0)
            throw new ArgumentException($"Width {w} must be a positive power of 2.", nameof(input));

        // Step 1: FFT along last axis (rows) — NativeComplexFFT already batches this
        var afterRows = NativeComplexFFT(input);

        // Step 2: Transpose last two axes so columns become the last axis
        var transposed = TransposeLastTwoAxes(afterRows);

        // Step 3: FFT along (now-last) column axis
        var afterCols = NativeComplexFFTComplex(transposed);

        // Step 4: Transpose back
        var result = TransposeLastTwoAxes(afterCols);
        { var ci = input; AutoTracer.RecordOp("NativeComplexFFT2D", result, eng => eng.NativeComplexFFT2D(ci)); }
        return result;
    }

    /// <inheritdoc />
    public virtual Tensor<T> NativeComplexIFFT2DReal<T>(Tensor<Complex<T>> input)
    {
        if (input is null) throw new ArgumentNullException(nameof(input));
        if (input.Rank < 2)
            throw new ArgumentException("NativeComplexIFFT2DReal requires at least a 2D tensor.", nameof(input));

        int ih = input._shape[^2];
        int iw = input._shape[^1];
        if ((ih & (ih - 1)) != 0 || ih <= 0)
            throw new ArgumentException($"Height {ih} must be a positive power of 2.", nameof(input));
        if ((iw & (iw - 1)) != 0 || iw <= 0)
            throw new ArgumentException($"Width {iw} must be a positive power of 2.", nameof(input));

        if (GraphMode.IsActive) { var scope = GraphMode.Current; if (scope is not null) { var c = input; return scope.RecordCrossType<Complex<T>, T>(LazyNodeType.Custom, "NativeComplexIFFT2DReal", input, input._shape, (eng, output) => { var r = eng.NativeComplexIFFT2DReal(c); r.AsSpan().CopyTo(output.AsWritableSpan()); }); } }
        { var ac = AutoTracer.TryGetCompiledPlan<T>("NativeComplexIFFT2DReal", input._shape); if (ac is not null) return ac.Execute(); }

        // Step 1: Transpose so columns are last axis
        var transposed = TransposeLastTwoAxes(input);

        // Step 2: IFFT along columns (now last axis)
        var afterCols = NativeComplexIFFT(transposed);

        // Step 3: Transpose back so rows are last axis
        var afterColsT = TransposeLastTwoAxes(afterCols);

        // Step 4: IFFT along rows and return real
        var result = NativeComplexIFFTReal(afterColsT);
        { var ci = input; AutoTracer.RecordOp("NativeComplexIFFT2DReal", result, eng => eng.NativeComplexIFFT2DReal(ci)); }
        return result;
    }

    /// <inheritdoc />
    public virtual Tensor<Complex<T>> NativeComplexFFTND<T>(Tensor<T> input, int[] axes)
    {
        if (input is null) throw new ArgumentNullException(nameof(input));
        if (axes is null || axes.Length == 0) throw new ArgumentException("axes must be non-empty.", nameof(axes));

        // Derive a paramHash from axes so that different axis sets on the same shape
        // don't collide in the AutoTracer cache.
        long axesHash = 0;
        for (int i = 0; i < axes.Length; i++)
            axesHash = axesHash * 31 + axes[i];

        if (GraphMode.IsActive) { var scope = GraphMode.Current; if (scope is not null) { var c = input; var ca = axes; return scope.RecordCrossType<T, Complex<T>>(LazyNodeType.Custom, "NativeComplexFFTND", input, input._shape, (eng, output) => { var r = eng.NativeComplexFFTND(c, ca); r.AsSpan().CopyTo(output.AsWritableSpan()); }); } }
        { var ac = AutoTracer.TryGetCompiledPlan<Complex<T>>("NativeComplexFFTND", input._shape, paramHash: axesHash); if (ac is not null) return ac.Execute(); }

        // Normalize negative axes and reject duplicates (matches NumPy/PyTorch behavior)
        int rank = input.Rank;
        var normalizedAxes = new int[axes.Length];
        var seen = new HashSet<int>();
        for (int i = 0; i < axes.Length; i++)
        {
            int ax = axes[i] < 0 ? rank + axes[i] : axes[i];
            if (ax < 0 || ax >= rank)
                throw new ArgumentException($"Axis {axes[i]} is out of range for rank-{rank} tensor.");
            if (!seen.Add(ax))
                throw new ArgumentException($"Duplicate axis {axes[i]} (normalized: {ax}).");
            normalizedAxes[i] = ax;
        }

        // First axis: real-to-complex FFT via MoveAxisToLast + NativeComplexFFT + MoveAxisBack
        var result = FFTAlongAxis(input, normalizedAxes[0]);

        // Subsequent axes: complex-to-complex FFT
        for (int i = 1; i < normalizedAxes.Length; i++)
            result = FFTComplexAlongAxis(result, normalizedAxes[i]);

        { var ci = input; var ca = axes; AutoTracer.RecordOp("NativeComplexFFTND", result, eng => eng.NativeComplexFFTND(ci, ca), paramHash: axesHash); }
        return result;
    }

    /// <inheritdoc />
    public virtual Tensor<T> NativeComplexIFFTNDReal<T>(Tensor<Complex<T>> input, int[] axes)
    {
        if (input is null) throw new ArgumentNullException(nameof(input));
        if (axes is null || axes.Length == 0) throw new ArgumentException("axes must be non-empty.", nameof(axes));

        long axesHash = 0;
        for (int i = 0; i < axes.Length; i++)
            axesHash = axesHash * 31 + axes[i];

        if (GraphMode.IsActive) { var scope = GraphMode.Current; if (scope is not null) { var c = input; var ca = axes; return scope.RecordCrossType<Complex<T>, T>(LazyNodeType.Custom, "NativeComplexIFFTNDReal", input, input._shape, (eng, output) => { var r = eng.NativeComplexIFFTNDReal(c, ca); r.AsSpan().CopyTo(output.AsWritableSpan()); }); } }
        { var ac = AutoTracer.TryGetCompiledPlan<T>("NativeComplexIFFTNDReal", input._shape, paramHash: axesHash); if (ac is not null) return ac.Execute(); }

        int rank = input.Rank;
        var normalizedAxes = new int[axes.Length];
        var seen = new HashSet<int>();
        for (int i = 0; i < axes.Length; i++)
        {
            int ax = axes[i] < 0 ? rank + axes[i] : axes[i];
            if (ax < 0 || ax >= rank)
                throw new ArgumentException($"Axis {axes[i]} is out of range for rank-{rank} tensor.");
            if (!seen.Add(ax))
                throw new ArgumentException($"Duplicate axis {axes[i]} (normalized: {ax}).");
            normalizedAxes[i] = ax;
        }

        // IFFT in reverse axis order. All but the last axis: complex-to-complex IFFT.
        var current = input;
        for (int i = normalizedAxes.Length - 1; i >= 1; i--)
            current = IFFTComplexAlongAxis(current, normalizedAxes[i]);

        // Last axis: complex-to-real IFFT
        var result = IFFTRealAlongAxis(current, normalizedAxes[0]);
        { var ci = input; var ca = axes; AutoTracer.RecordOp("NativeComplexIFFTNDReal", result, eng => eng.NativeComplexIFFTNDReal(ci, ca), paramHash: axesHash); }
        return result;
    }

    /// <inheritdoc />
    public virtual Tensor<T> NativeSpectralFilter<T>(Tensor<T> input, Tensor<Complex<T>> filter)
    {
        if (input is null) throw new ArgumentNullException(nameof(input));
        if (filter is null) throw new ArgumentNullException(nameof(filter));
        if (input.Rank < 2)
            throw new ArgumentException("NativeSpectralFilter requires at least a 2D input tensor.", nameof(input));
        if (filter.Rank < 2)
            throw new ArgumentException("NativeSpectralFilter requires at least a 2D filter tensor.", nameof(filter));

        int h = input._shape[^2];
        int w = input._shape[^1];
        if (filter._shape[^2] != h || filter._shape[^1] != w)
            throw new ArgumentException(
                $"Filter spatial dims [{filter._shape[^2]},{filter._shape[^1]}] must match input [{h},{w}].",
                nameof(filter));
        if (filter.Length > input.Length)
            throw new ArgumentException(
                $"Filter length ({filter.Length}) cannot exceed input length ({input.Length}).",
                nameof(filter));

        // Fused: FFT2D → pointwise multiply with broadcast → IFFT2D
        var spectrum = NativeComplexFFT2D(input);

        // Multiply spectrum by filter using modular broadcast on filter.Length.
        // This naturally handles any rank: [H,W] wraps every H*W, [C,H,W] wraps every C*H*W, etc.
        int filterLen = filter.Length;
        if (filterLen <= 0)
            throw new ArgumentException("Filter length must be a positive multiple of spatial slice size.", nameof(filter));
        int sliceSize = h * w;
        if (sliceSize > 0 && filterLen % sliceSize != 0)
            throw new ArgumentException(
                $"Filter length ({filterLen}) must be a positive multiple of spatial slice size ({sliceSize}).",
                nameof(filter));
        var ops = MathHelper.GetNumericOperations<T>();
        var filtered = new Tensor<Complex<T>>(spectrum._shape);
        for (int i = 0; i < spectrum.Length; i++)
        {
            int fi = i % filterLen;
            var sr = spectrum[i].Real; var si = spectrum[i].Imaginary;
            var fr = filter[fi].Real; var fi2 = filter[fi].Imaginary;
            filtered[i] = new Complex<T>(
                ops.Subtract(ops.Multiply(sr, fr), ops.Multiply(si, fi2)),
                ops.Add(ops.Multiply(sr, fi2), ops.Multiply(si, fr)));
        }

        return NativeComplexIFFT2DReal(filtered);
    }

    /// <inheritdoc />
    public virtual Tensor<T> NativeSpectralFilterBatch<T>(Tensor<T> input, Tensor<Complex<T>> filter)
    {
        if (input is null) throw new ArgumentNullException(nameof(input));
        if (filter is null) throw new ArgumentNullException(nameof(filter));
        if (input.Rank != 4)
            throw new ArgumentException(
                $"NativeSpectralFilterBatch requires 4D input [B,C,H,W]. Got rank {input.Rank}.",
                nameof(input));
        if (filter.Rank < 2)
            throw new ArgumentException("Filter must be at least 2D.", nameof(filter));

        int h = input._shape[2];
        int w = input._shape[3];
        if (filter._shape[^2] != h || filter._shape[^1] != w)
            throw new ArgumentException(
                $"Filter spatial dims [{filter._shape[^2]},{filter._shape[^1]}] must match input [{h},{w}].",
                nameof(filter));
        if (filter.Length > input.Length)
            throw new ArgumentException(
                $"Filter length ({filter.Length}) cannot exceed input length ({input.Length}).",
                nameof(filter));

        // FFT2D the entire [B,C,H,W] input — the FFT2D already batches over leading dims
        var spectrum = NativeComplexFFT2D(input);

        // Multiply spectrum by filter using modular broadcast on filter.Length.
        // [H,W] wraps every H*W, [C,H,W] wraps every C*H*W, [B,C,H,W] is direct.
        int filterLen = filter.Length;
        var ops = MathHelper.GetNumericOperations<T>();
        var filtered = new Tensor<Complex<T>>(spectrum._shape);
        for (int i = 0; i < spectrum.Length; i++)
        {
            int fi = i % filterLen;
            var sr = spectrum[i].Real; var si = spectrum[i].Imaginary;
            var fr = filter[fi].Real; var fi2 = filter[fi].Imaginary;
            filtered[i] = new Complex<T>(
                ops.Subtract(ops.Multiply(sr, fr), ops.Multiply(si, fi2)),
                ops.Add(ops.Multiply(sr, fi2), ops.Multiply(si, fr)));
        }

        return NativeComplexIFFT2DReal(filtered);
    }

    /// <summary>
    /// Transpose the last two axes of a complex tensor using a specialized nested loop.
    /// For shape [..., H, W] → [..., W, H], iterates batch × H × W with direct index
    /// arithmetic instead of per-element multi-index decomposition.
    /// </summary>
    private static Tensor<Complex<T>> TransposeLastTwoAxes<T>(Tensor<Complex<T>> input)
    {
        int rank = input.Rank;
        int h = input._shape[rank - 2];
        int w = input._shape[rank - 1];
        int batchSize = input.Length / (h * w);

        var newShape = (int[])input._shape.Clone();
        newShape[rank - 2] = w;
        newShape[rank - 1] = h;

        var result = new Tensor<Complex<T>>(newShape);
        var srcArr = input.GetDataArray();
        var dstArr = result.GetDataArray();

        for (int b = 0; b < batchSize; b++)
        {
            int srcBase = b * h * w;
            int dstBase = b * w * h;
            for (int r = 0; r < h; r++)
                for (int c = 0; c < w; c++)
                    dstArr[dstBase + c * h + r] = srcArr[srcBase + r * w + c];
        }

        return result;
    }

    /// <summary>FFT along a specific axis (real-to-complex). Moves axis to last, FFTs, moves back.</summary>
    private Tensor<Complex<T>> FFTAlongAxis<T>(Tensor<T> input, int axis)
    {
        if (axis == input.Rank - 1)
            return NativeComplexFFT(input);

        // Move target axis to last position
        var permuted = MoveAxisToLast(input, axis);
        var result = NativeComplexFFT(permuted);
        return MoveAxisFromLast(result, axis);
    }

    /// <summary>Complex-to-complex FFT along a specific axis.</summary>
    private Tensor<Complex<T>> FFTComplexAlongAxis<T>(Tensor<Complex<T>> input, int axis)
    {
        if (axis == input.Rank - 1)
            return NativeComplexFFTComplex(input);

        var permuted = MoveAxisToLast(input, axis);
        var result = NativeComplexFFTComplex(permuted);
        return MoveAxisFromLast(result, axis);
    }

    /// <summary>Complex-to-complex IFFT along a specific axis.</summary>
    private Tensor<Complex<T>> IFFTComplexAlongAxis<T>(Tensor<Complex<T>> input, int axis)
    {
        if (axis == input.Rank - 1)
            return NativeComplexIFFT(input);

        var permuted = MoveAxisToLast(input, axis);
        var result = NativeComplexIFFT(permuted);
        return MoveAxisFromLast(result, axis);
    }

    /// <summary>Complex-to-real IFFT along a specific axis.</summary>
    private Tensor<T> IFFTRealAlongAxis<T>(Tensor<Complex<T>> input, int axis)
    {
        if (axis == input.Rank - 1)
            return NativeComplexIFFTReal(input);

        var permuted = MoveAxisToLast(input, axis);
        var result = NativeComplexIFFTReal(permuted);
        return MoveAxisFromLastReal(result, axis);
    }

    /// <summary>Move a given axis to the last position via permute.</summary>
    private static Tensor<Complex<T>> MoveAxisToLast<T>(Tensor<Complex<T>> input, int axis)
    {
        int rank = input.Rank;
        var perm = new int[rank];
        int p = 0;
        for (int i = 0; i < rank; i++)
            if (i != axis) perm[p++] = i;
        perm[rank - 1] = axis;
        return PermuteComplex(input, perm);
    }

    /// <summary>Move axis to last position via data copy. Does NOT record to tape/GraphMode.</summary>
    private static Tensor<T> MoveAxisToLast<T>(Tensor<T> input, int axis)
    {
        int rank = input.Rank;
        var perm = new int[rank];
        int p = 0;
        for (int i = 0; i < rank; i++)
            if (i != axis) perm[p++] = i;
        perm[rank - 1] = axis;
        return PermuteReal(input, perm);
    }

    /// <summary>Move the last axis back to the original position.</summary>
    private static Tensor<Complex<T>> MoveAxisFromLast<T>(Tensor<Complex<T>> input, int axis)
    {
        int rank = input.Rank;
        var perm = new int[rank];
        for (int i = 0; i < rank; i++)
        {
            if (i < axis) perm[i] = i;
            else if (i == axis) perm[i] = rank - 1;
            else perm[i] = i - 1;
        }
        return PermuteComplex(input, perm);
    }

    /// <summary>Move last axis back to original position via data copy. Does NOT record to tape.</summary>
    private static Tensor<T> MoveAxisFromLastReal<T>(Tensor<T> input, int axis)
    {
        int rank = input.Rank;
        var perm = new int[rank];
        for (int i = 0; i < rank; i++)
        {
            if (i < axis) perm[i] = i;
            else if (i == axis) perm[i] = rank - 1;
            else perm[i] = i - 1;
        }
        return PermuteReal(input, perm);
    }

    /// <summary>Permute a real tensor (data copy, no tape recording).</summary>
    private static Tensor<T> PermuteReal<T>(Tensor<T> input, int[] perm)
    {
        int rank = input.Rank;
        var newShape = new int[rank];
        for (int i = 0; i < rank; i++)
            newShape[i] = input._shape[perm[i]];

        var result = new Tensor<T>(newShape);
        var srcArr = input.GetDataArray();
        var dstArr = result.GetDataArray();

        var srcStrides = new int[rank];
        srcStrides[rank - 1] = 1;
        for (int i = rank - 2; i >= 0; i--)
            srcStrides[i] = srcStrides[i + 1] * input._shape[i + 1];

        var dstStrides = new int[rank];
        dstStrides[rank - 1] = 1;
        for (int i = rank - 2; i >= 0; i--)
            dstStrides[i] = dstStrides[i + 1] * newShape[i + 1];

        var indices = new int[rank];
        for (int flat = 0; flat < input.Length; flat++)
        {
            int remaining = flat;
            for (int d = 0; d < rank; d++)
            {
                indices[d] = remaining / srcStrides[d];
                remaining %= srcStrides[d];
            }

            int dstFlat = 0;
            for (int d = 0; d < rank; d++)
                dstFlat += indices[perm[d]] * dstStrides[d];

            dstArr[dstFlat] = srcArr[flat];
        }

        return result;
    }

    /// <summary>Permute a complex tensor (data copy, no tape recording).</summary>
    private static Tensor<Complex<T>> PermuteComplex<T>(Tensor<Complex<T>> input, int[] perm)
    {
        int rank = input.Rank;
        var newShape = new int[rank];
        for (int i = 0; i < rank; i++)
            newShape[i] = input._shape[perm[i]];

        var result = new Tensor<Complex<T>>(newShape);
        var srcArr = input.GetDataArray();
        var dstArr = result.GetDataArray();

        var srcStrides = new int[rank];
        srcStrides[rank - 1] = 1;
        for (int i = rank - 2; i >= 0; i--)
            srcStrides[i] = srcStrides[i + 1] * input._shape[i + 1];

        var dstStrides = new int[rank];
        dstStrides[rank - 1] = 1;
        for (int i = rank - 2; i >= 0; i--)
            dstStrides[i] = dstStrides[i + 1] * newShape[i + 1];

        var indices = new int[rank];
        for (int flat = 0; flat < input.Length; flat++)
        {
            int remaining = flat;
            for (int d = 0; d < rank; d++)
            {
                indices[d] = remaining / srcStrides[d];
                remaining %= srcStrides[d];
            }

            int dstFlat = 0;
            for (int d = 0; d < rank; d++)
                dstFlat += indices[perm[d]] * dstStrides[d];

            dstArr[dstFlat] = srcArr[flat];
        }

        return result;
    }

    /// <inheritdoc />
    public virtual Tensor<Complex<T>> NativeComplexAdd<T>(Tensor<Complex<T>> a, Tensor<Complex<T>> b)
    {
        if (a is null) throw new ArgumentNullException(nameof(a));
        if (b is null) throw new ArgumentNullException(nameof(b));
        if (a.Length != b.Length)
            throw new ArgumentException($"Tensor lengths must match: {a.Length} vs {b.Length}");

        if (GraphMode.IsActive) { var scope = GraphMode.Current; if (scope is not null) { var ca = a; var cb = b; return scope.RecordBinary(LazyNodeType.Custom, "NativeComplexAdd", a, b, a._shape, (eng, output) => { var r = eng.NativeComplexAdd(ca, cb); r.AsSpan().CopyTo(output.AsWritableSpan()); }, null); } }
        { var ac = AutoTracer.TryGetCompiledPlan<Complex<T>>("NativeComplexAdd", a._shape); if (ac is not null) return ac.Execute(); }

        var ops = MathHelper.GetNumericOperations<T>();
        int n = a.Length;
        var result = new Tensor<Complex<T>>(a._shape);

        if (typeof(T) == typeof(float))
        {
            var (aR, aI) = DecomposeToFloat(a);
            var (bR, bI) = DecomposeToFloat(b);
            var oR = new float[n]; var oI = new float[n];
            Simd.SimdComplexKernels.ComplexAdd(aR, aI, bR, bI, oR, oI);
            result = RecomposeFromFloat<T>(oR, oI, a._shape);
        }
        else
        {
            for (int i = 0; i < n; i++)
                result[i] = new Complex<T>(
                    ops.Add(a[i].Real, b[i].Real),
                    ops.Add(a[i].Imaginary, b[i].Imaginary));
        }

        { var ca2 = a; var cb2 = b; AutoTracer.RecordOp("NativeComplexAdd", result, eng => eng.NativeComplexAdd(ca2, cb2)); }
        return result;
    }

    /// <summary>
    /// In-place iterative Cooley-Tukey FFT on a Complex&lt;T&gt; array.
    /// Input length must be a power of 2 (validated by callers).
    /// </summary>
    // Cache twiddle factors across FFT calls — key is (n, inverse)
    [ThreadStatic] private static Dictionary<(int n, bool inverse), Complex<double>[]>? _twiddleCache;

    private static void NativeFFTInPlace<T>(Complex<T>[] data, bool inverse,
        INumericOperations<T> ops)
    {
        if (typeof(T) == typeof(float))
        {
            NativeFFTInPlaceFloatSpan(
                System.Runtime.CompilerServices.Unsafe.As<Complex<T>[], Complex<float>[]>(ref data),
                inverse);
            return;
        }

        if (typeof(T) == typeof(double))
        {
            NativeFFTInPlaceDoubleSpan(
                System.Runtime.CompilerServices.Unsafe.As<Complex<T>[], Complex<double>[]>(ref data),
                inverse);
            return;
        }

        int n = data.Length;
        int bits = 0;
        for (int tmp = n >> 1; tmp > 0; tmp >>= 1) bits++;

        // Bit-reversal permutation
        for (int i = 0; i < n; i++)
        {
            int j = BitReverse(i, bits);
            if (j > i)
                (data[i], data[j]) = (data[j], data[i]);
        }

        // Get or create cached twiddle table for this (n, inverse) pair
        _twiddleCache ??= new Dictionary<(int, bool), Complex<double>[]>();
        var cacheKey = (n, inverse);
        if (!_twiddleCache.TryGetValue(cacheKey, out var cachedTwiddles))
        {
            // Precompute all twiddle factors for all stages at once
            // Total count = 1 + 2 + 4 + ... + n/2 = n - 1
            cachedTwiddles = new Complex<double>[n - 1];
            int idx = 0;
            for (int size = 2; size <= n; size *= 2)
            {
                int halfSize = size / 2;
                double baseAngle = (inverse ? 2.0 : -2.0) * Math.PI / size;
                for (int k = 0; k < halfSize; k++)
                    cachedTwiddles[idx++] = new Complex<double>(Math.Cos(baseAngle * k), Math.Sin(baseAngle * k));
            }
            _twiddleCache[cacheKey] = cachedTwiddles;
        }

        // Butterfly stages using cached twiddle factors — zero allocations
        int twiddleIdx = 0;
        for (int size = 2; size <= n; size *= 2)
        {
            int halfSize = size / 2;

            for (int start = 0; start < n; start += size)
            {
                for (int k = 0; k < halfSize; k++)
                {
                    var tw = cachedTwiddles[twiddleIdx + k];
                    // Inline complex multiply to avoid Complex<T> construction per iteration:
                    // twiddle * data[bot] = (tw.re*d.re - tw.im*d.im, tw.re*d.im + tw.im*d.re)
                    var d = data[start + k + halfSize];
                    var twRe = ops.FromDouble(tw.Real);
                    var twIm = ops.FromDouble(tw.Imaginary);
                    var tRe = ops.Subtract(ops.Multiply(twRe, d.Real), ops.Multiply(twIm, d.Imaginary));
                    var tIm = ops.Add(ops.Multiply(twRe, d.Imaginary), ops.Multiply(twIm, d.Real));
                    var u = data[start + k];
                    data[start + k] = new Complex<T>(ops.Add(u.Real, tRe), ops.Add(u.Imaginary, tIm));
                    data[start + k + halfSize] = new Complex<T>(ops.Subtract(u.Real, tRe), ops.Subtract(u.Imaginary, tIm));
                }
            }
            twiddleIdx += halfSize;
        }
    }

    // Span-based overload — zero-copy entry point used by NativeComplexFFTSpan hot paths.
    private static void NativeFFTInPlaceDoubleSpan(Span<Complex<double>> data, bool inverse)
    {
        int n = data.Length;
        int bits = 0;
        for (int tmp = n >> 1; tmp > 0; tmp >>= 1) bits++;

        for (int i = 0; i < n; i++)
        {
            int j = BitReverse(i, bits);
            if (j > i)
                (data[i], data[j]) = (data[j], data[i]);
        }

        _twiddleCache ??= new Dictionary<(int, bool), Complex<double>[]>();
        var cacheKey = (n, inverse);
        if (!_twiddleCache.TryGetValue(cacheKey, out var cachedTwiddles))
        {
            cachedTwiddles = new Complex<double>[n - 1];
            int idx = 0;
            for (int size = 2; size <= n; size *= 2)
            {
                int halfSize = size / 2;
                double baseAngle = (inverse ? 2.0 : -2.0) * Math.PI / size;
                for (int k = 0; k < halfSize; k++)
                    cachedTwiddles[idx++] = new Complex<double>(Math.Cos(baseAngle * k), Math.Sin(baseAngle * k));
            }
            _twiddleCache[cacheKey] = cachedTwiddles;
        }

        int twiddleIdx = 0;
        for (int size = 2; size <= n; size *= 2)
        {
            int halfSize = size / 2;
            for (int start = 0; start < n; start += size)
            {
                for (int k = 0; k < halfSize; k++)
                {
                    double twRe = cachedTwiddles[twiddleIdx + k].Real;
                    double twIm = cachedTwiddles[twiddleIdx + k].Imaginary;
                    double dRe = data[start + k + halfSize].Real;
                    double dIm = data[start + k + halfSize].Imaginary;
                    double tRe = twRe * dRe - twIm * dIm;
                    double tIm = twRe * dIm + twIm * dRe;
                    double uRe = data[start + k].Real;
                    double uIm = data[start + k].Imaginary;
                    data[start + k] = new Complex<double>(uRe + tRe, uIm + tIm);
                    data[start + k + halfSize] = new Complex<double>(uRe - tRe, uIm - tIm);
                }
            }
            twiddleIdx += halfSize;
        }
    }

    [ThreadStatic] private static Dictionary<(int n, bool inverse), Complex<float>[]>? _twiddleCacheFloat;

    private static void NativeFFTInPlaceFloatSpan(Span<Complex<float>> data, bool inverse)
    {
        int n = data.Length;
        int bits = 0;
        for (int tmp = n >> 1; tmp > 0; tmp >>= 1) bits++;

        for (int i = 0; i < n; i++)
        {
            int j = BitReverse(i, bits);
            if (j > i)
                (data[i], data[j]) = (data[j], data[i]);
        }

        _twiddleCacheFloat ??= new Dictionary<(int, bool), Complex<float>[]>();
        var cacheKey = (n, inverse);
        if (!_twiddleCacheFloat.TryGetValue(cacheKey, out var cachedTwiddles))
        {
            cachedTwiddles = new Complex<float>[n - 1];
            int idx = 0;
            for (int size = 2; size <= n; size *= 2)
            {
                int halfSize = size / 2;
                double baseAngle = (inverse ? 2.0 : -2.0) * Math.PI / size;
                for (int k = 0; k < halfSize; k++)
                    cachedTwiddles[idx++] = new Complex<float>((float)Math.Cos(baseAngle * k), (float)Math.Sin(baseAngle * k));
            }
            _twiddleCacheFloat[cacheKey] = cachedTwiddles;
        }

        int twiddleIdx = 0;
        for (int size = 2; size <= n; size *= 2)
        {
            int halfSize = size / 2;
            for (int start = 0; start < n; start += size)
            {
                for (int k = 0; k < halfSize; k++)
                {
                    float twRe = cachedTwiddles[twiddleIdx + k].Real;
                    float twIm = cachedTwiddles[twiddleIdx + k].Imaginary;
                    float dRe = data[start + k + halfSize].Real;
                    float dIm = data[start + k + halfSize].Imaginary;
                    float tRe = twRe * dRe - twIm * dIm;
                    float tIm = twRe * dIm + twIm * dRe;
                    float uRe = data[start + k].Real;
                    float uIm = data[start + k].Imaginary;
                    data[start + k] = new Complex<float>(uRe + tRe, uIm + tIm);
                    data[start + k + halfSize] = new Complex<float>(uRe - tRe, uIm - tIm);
                }
            }
            twiddleIdx += halfSize;
        }
    }

    #endregion

    #region CTC Loss

    /// <inheritdoc />
    public Tensor<T> TensorCTCLoss<T>(Tensor<T> logProbs, Tensor<int> targets, int[] inputLengths, int[] targetLengths, int blank = 0)
    {
        if (logProbs.Rank != 3)
            throw new ArgumentException("logProbs must be 3D [T, N, C].");

        if (GraphMode.IsActive) { var scope = GraphMode.Current; if (scope is not null) { var clp = logProbs; var ct = targets; var cil = inputLengths; var ctl = targetLengths; var cb = blank; var outShape = new[] { logProbs._shape[1] }; return scope.RecordUnary(LazyNodeType.Custom, "CTCLoss", logProbs, outShape, (eng, output) => { var r = eng.TensorCTCLoss(clp, ct, cil, ctl, cb); r.AsSpan().CopyTo(output.AsWritableSpan()); }, BackwardFunctions<T>.CTCLossBackward); } }

        var ops = MathHelper.GetNumericOperations<T>();
        int maxT = logProbs._shape[0];
        int batchSize = logProbs._shape[1];
        int numClasses = logProbs._shape[2];

        if (inputLengths.Length != batchSize || targetLengths.Length != batchSize)
            throw new ArgumentException("inputLengths and targetLengths must have length == batchSize.");

        if (blank < 0 || blank >= numClasses)
            throw new ArgumentOutOfRangeException(nameof(blank), $"Blank index {blank} must be in [0, {numClasses}).");

        // Validate target bounds
        int totalTargets = 0;
        for (int n = 0; n < batchSize; n++)
            totalTargets += targetLengths[n];
        if (totalTargets > targets.Length)
            throw new ArgumentException($"Sum of targetLengths ({totalTargets}) exceeds targets length ({targets.Length}).");

        var losses = new Tensor<T>(new[] { batchSize });

        // Forward-backward algorithm per batch element
        int targetOffset = 0;
        for (int n = 0; n < batchSize; n++)
        {
            int T_n = inputLengths[n];
            int U_n = targetLengths[n];

            if (T_n < 0 || T_n > maxT)
                throw new ArgumentOutOfRangeException(nameof(inputLengths), $"inputLengths[{n}]={T_n} must be in [0, {maxT}].");
            if (U_n < 0)
                throw new ArgumentOutOfRangeException(nameof(targetLengths), $"targetLengths[{n}]={U_n} must be non-negative.");

            int S = 2 * U_n + 1; // expanded label length with blanks

            // Build expanded label sequence: blank, l1, blank, l2, blank, ...
            var expandedLabels = new int[S];
            for (int s = 0; s < S; s++)
            {
                int label = (s % 2 == 0) ? blank : targets.GetFlat(targetOffset + s / 2);
                if (label < 0 || label >= numClasses)
                    throw new ArgumentOutOfRangeException(nameof(targets), $"Target label {label} must be in [0, {numClasses}).");
                expandedLabels[s] = label;
            }

            // Alpha (forward) pass — log domain for numerical stability
            var alpha = new double[T_n, S];
            double negInf = double.NegativeInfinity;
            for (int t = 0; t < T_n; t++)
                for (int s = 0; s < S; s++)
                    alpha[t, s] = negInf;

            // Initialize
            alpha[0, 0] = ops.ToDouble(logProbs[0, n, expandedLabels[0]]);
            if (S > 1)
                alpha[0, 1] = ops.ToDouble(logProbs[0, n, expandedLabels[1]]);

            // Forward recursion
            for (int t = 1; t < T_n; t++)
            {
                for (int s = 0; s < S; s++)
                {
                    double logProbTS = ops.ToDouble(logProbs[t, n, expandedLabels[s]]);
                    double prevSum = alpha[t - 1, s];
                    if (s >= 1)
                        prevSum = LogSumExp(prevSum, alpha[t - 1, s - 1]);
                    if (s >= 2 && expandedLabels[s] != blank && expandedLabels[s] != expandedLabels[s - 2])
                        prevSum = LogSumExp(prevSum, alpha[t - 1, s - 2]);
                    alpha[t, s] = prevSum + logProbTS;
                }
            }

            // Total log-probability
            double logProb = alpha[T_n - 1, S - 1];
            if (S >= 2)
                logProb = LogSumExp(logProb, alpha[T_n - 1, S - 2]);

            // CTC loss = -log P(labels | input)
            losses.SetFlat(n, ops.FromDouble(-logProb));
            targetOffset += U_n;
        }

        Autodiff.DifferentiableOps.RecordIfActive("CTCLoss", losses,
            new[] { logProbs }, Autodiff.BackwardFunctions<T>.CTCLossBackward,
            new object[] { logProbs, targets, inputLengths, targetLengths, blank });
        { var clp2 = logProbs; var ct2 = targets; var cil2 = inputLengths; var ctl2 = targetLengths; var cb2 = blank; AutoTracer.RecordOp("CTCLoss", losses, eng => eng.TensorCTCLoss(clp2, ct2, cil2, ctl2, cb2)); }
        return losses;
    }

    private static double LogSumExp(double a, double b)
    {
        if (double.IsNegativeInfinity(a)) return b;
        if (double.IsNegativeInfinity(b)) return a;
        double max = Math.Max(a, b);
        return max + Math.Log(Math.Exp(a - max) + Math.Exp(b - max));
    }

    #endregion
}
